UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  const service = new NotificationService();

  // Register standard channels assuming these classes are implemented by the user
  // based on the starter code and problem requirements.
  try {
    service.registerChannel(new EmailChannel());
  } catch (e) {
    // If EmailChannel is not implemented, the test will fail here.
    // In a competitive programming context, this signals an incomplete solution.
    // console.error("Error registering EmailChannel:", e);
  }
  try {
    service.registerChannel(new SMSChannel());
  } catch (e) {
    // console.error("Error registering SMSChannel:", e);
  }
  try {
    service.registerChannel(new PushChannel());
  } catch (e) {
    // console.error("Error registering PushChannel:", e);
  }

  for (const line of lines) {
    const parts = line.split(' ');
    const command = parts[0];

    if (command === 'subscribe') {
      if (parts.length < 3) {
        console.log("Error: 'subscribe' command requires user and channel (e.g., subscribe alice email).");
        continue;
      }
      const user = parts[1];
      const channelName = parts[2];
      const result = service.subscribe(user, channelName);
      console.log(result);
    } else if (command === 'send') {
      if (parts.length < 4) { // e.g., 'send email user=alice subject=Hello' -> 4 parts
        console.log("Error: 'send' command requires channel, user, and content (e.g., send email user=alice subject=Hello).");
        continue;
      }
      const channelName = parts[1];
      let user: string | undefined;
      const payload: Record<string, string> = {};

      // Parse remaining parts for user and message/subject
      for (let i = 2; i < parts.length; i++) {
        const param = parts[i];
        if (param.startsWith('user=')) {
          user = param.substring(5);
        } else if (param.startsWith('subject=')) {
          payload.subject = param.substring(8);
        } else if (param.startsWith('message=')) {
          payload.message = param.substring(8);
        }
      }

      if (!user) {
        console.log("Error: 'send' command requires a user (e.g., user=alice).");
        continue;
      }

      const result = service.sendNotification(channelName, user, payload);
      console.log(result);
    } else {
      console.log(`Unknown command: ${command}`);
    }
  }
});$harness$,
