-- dp_002: Plugin System
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // Map of plugin names to their constructors.
  // This allows the harness to dynamically instantiate user-defined plugins.
  // The harness assumes the user will provide implementations for these classes.
  const pluginConstructors: Record<string, new () => Plugin> = {
    "LogPlugin": LogPlugin,
    "MetricsPlugin": MetricsPlugin,
    // Extend this map with other plugin classes as needed for future tests
  };

  const registry = new PluginRegistry();

  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    const parts = line.split(' ');
    const command = parts[0];

    try {
      if (command === 'register') {
        const pluginName = parts[1];
        if (!pluginName) {
          console.log("Error: Missing plugin name for register command.");
          continue;
        }

        const PluginClass = pluginConstructors[pluginName];
        if (!PluginClass) {
          console.log(`Error: Unknown plugin type '${pluginName}' for registration. Check if the class is defined.`);
          continue;
        }

        // Instantiate the plugin and register it
        const pluginInstance = new PluginClass();
        registry.register(pluginInstance); // This method is expected to print output
      } else if (command === 'execute') {
        const pluginName = parts[1];
        if (!pluginName) {
          console.log("Error: Missing plugin name for execute command.");
          continue;
        }

        const plugin = registry.get(pluginName);
        if (!plugin) {
          console.log(`Plugin not found: ${pluginName}`);
          continue;
        }

        let context: Record<string, unknown> = {};
        const contextStringMatch = line.match(/context=(.*)/);
        if (contextStringMatch) {
          const jsonString = contextStringMatch[1];
          try {
            context = JSON.parse(jsonString);
          } catch (e: any) {
            console.log(`Error: Invalid context JSON for ${pluginName}: ${e.message}`);
            continue;
          }
        }
        
        // Execute the plugin with the parsed context
        plugin.execute(context); // This method is expected to print output
      } else {
        console.log(`Error: Unknown command '${command}'`);
      }
    } catch (e: any) {
      // Catch any unexpected errors from user's plugin or registry logic during command processing
      console.log(`Error during command '${command}' for line "${line}": ${e.message}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "register LogPlugin", "description": "Register a plugin by name", "expected_output": "LogPlugin registered"}, {"input": "register LogPlugin\nregister LogPlugin", "description": "Duplicate registration triggers warning", "expected_output": "LogPlugin registered\nWarning: LogPlugin already registered"}, {"input": "register LogPlugin\nexecute LogPlugin context={}", "description": "Execute a registered plugin with empty context", "expected_output": "LogPlugin registered\nLogPlugin executed"}, {"input": "execute UnknownPlugin", "description": "Executing unregistered plugin returns error", "expected_output": "Plugin not found: UnknownPlugin"}, {"input": "register MetricsPlugin\nexecute MetricsPlugin context={\"req\":1,\"user\":\"test\"}", "description": "Register and execute a second plugin with context", "expected_output": "MetricsPlugin registered\nMetricsPlugin executed"}, {"input": "register LogPlugin\nexecute LogPlugin context={\"level\":\"debug\",\"message\":\"Hello\"}\nregister MetricsPlugin\nexecute MetricsPlugin context={\"requestCount\":10}", "description": "Multiple operations including different contexts", "expected_output": "LogPlugin registered\nLogPlugin executed\nMetricsPlugin registered\nMetricsPlugin executed"}, {"input": "register LogPlugin\nexecute LogPlugin context=invalidjson", "description": "Executing with invalid context JSON", "expected_output": "LogPlugin registered\nError: Invalid context JSON for LogPlugin: Unexpected token ''i'', \"invalidjson\" is not valid JSON"}, {"input": "register NonExistentPlugin", "description": "Registering a plugin class not known to the harness", "expected_output": "Error: Unknown plugin type ''NonExistentPlugin'' for registration. Check if the class is defined."}, {"input": "execute", "description": "Execute command with missing plugin name", "expected_output": "Error: Missing plugin name for execute command."}, {"input": "register", "description": "Register command with missing plugin name", "expected_output": "Error: Missing plugin name for register command."}]'::jsonb
