-- dp_003: Document Builder
UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;

class Main {
    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        // DocumentDirector is instantiated once per test run, maintaining potential internal state.
        DocumentDirector director = new DocumentDirector(); 

        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            try {
                String[] parts = line.split(" ", 2);
                String command = parts[0];
                String argsString = parts.length > 1 ? parts[1] : "";

                if ("build".equals(command)) {
                    DocumentBuilder builder = new DocumentBuilder();
                    
                    // Parse key-value pairs
                    String[] params = argsString.split(" ");
                    for (String param : params) {
                        if (param.isEmpty()) continue;
                        
                        // Special handling for 'no_body=true' to simulate not setting body
                        if ("no_body=true".equals(param)) {
                            continue; // Skip setting body, letting the builder.build() enforce the requirement
                        }

                        String[] kv = param.split("=", 2);
                        if (kv.length != 2) {
                            throw new IllegalArgumentException("Malformed parameter for build command: " + param);
                        }
                        String key = kv[0];
                        String value = kv[1];

                        switch (key) {
                            case "title":
                                builder.withTitle(value);
                                break;
                            case "body":
                                builder.withBody(value);
                                break;
                            case "header":
                                builder.withHeader(value);
                                break;
                            case "footer":
                                builder.withFooter(value);
                                break;
                            case "metadata":
                                // Assuming metadata is a single String field based on example outputs
                                builder.withMetadata(value); 
                                break;
                            default:
                                throw new IllegalArgumentException("Unknown build parameter: " + key);
                        }
                    }

                    Document doc = builder.build();
                    System.out.println(doc.toString());

                } else if ("director".equals(command)) {
                    String[] params = argsString.split("=", 2);
                    if (params.length != 2 || !"template".equals(params[0])) {
                        throw new IllegalArgumentException("Malformed director command: " + argsString);
                    }
                    String templateName = params[1];
                    // Assumes DocumentDirector has a createTemplate(String) method that returns a Document
                    Document doc = director.createTemplate(templateName); 
                    System.out.println(doc.toString());

                } else {
                    System.out.println("Unknown command: " + command);
                }
            } catch (IllegalStateException e) {
                System.out.println("IllegalStateException: " + e.getMessage());
            } catch (IllegalArgumentException e) {
                System.out.println("IllegalArgumentException: " + e.getMessage());
            } catch (Exception e) {
                // Catch any other unexpected exceptions to provide a consistent error output format
                System.out.println("Error: " + e.getClass().getName() + ": " + e.getMessage());
            }
        }
        sc.close();
    }
