-- dp_004: Event Bus
UPDATE challenges SET
  test_harness = $harness$import sys
import json
from typing import Callable, Any

# These classes (EventBus, Publisher, Subscriber) are expected to be provided by the user's solution.
# The harness will dynamically interact with them.

# --- Global State for the Harness ---
event_bus: Any = None # Will hold the EventBus instance
publishers: dict[str, Any] = {} # Stores Publisher instances by name
subscribers: dict[str, Any] = {} # Stores Subscriber instances by name
handler_funcs: dict[str, Callable[[Any], None]] = {} # Stores named handler callables

# --- Helper for creating named handler functions ---
def create_printing_handler(handler_name: str) -> Callable[[Any], None]:
    def handler(payload: Any):
        # If payload is an empty dict or None, print just the handler name.
        # Otherwise, print with the payload's string representation.
        if (isinstance(payload, dict) and not payload) or payload is None:
            print(f"{handler_name} called")
        else:
            print(f"{handler_name} called with {payload}")
    return handler

# --- Main Harness Logic ---
def run_harness():
    global event_bus, publishers, subscribers, handler_funcs

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        parts = line.split(" ", 1)
        command = parts[0]
        args = parts[1] if len(parts) > 1 else ""

        try:
            if command == "CREATE_BUS":
                event_bus = EventBus()
                
            elif command == "CREATE_PUBLISHER":
                name = args
                if event_bus is None:
                    print("Harness Error: EventBus not created. Use CREATE_BUS first.")
                    continue
                publishers[name] = Publisher(event_bus)

            elif command == "CREATE_SUBSCRIBER":
                name = args
                if event_bus is None:
                    print("Harness Error: EventBus not created. Use CREATE_BUS first.")
                    continue
                subscribers[name] = Subscriber(event_bus)
                
            elif command == "DEFINE_HANDLER":
                handler_name = args
                handler_funcs[handler_name] = create_printing_handler(handler_name)
                
            elif command == "SUBSCRIBE":
                parts = args.split(" ", 2) # Split into subscriber_name, event_type, handler_name
                if len(parts) != 3:
                    print(f"Harness Error: Invalid SUBSCRIBE command format: '{line}'")
                    continue
                subscriber_name, event_type, handler_name = parts

                if subscriber_name not in subscribers:
                    print(f"Harness Error: Subscriber '{subscriber_name}' not found.")
                    continue
                if handler_name not in handler_funcs:
                    print(f"Harness Error: Handler '{handler_name}' not found.")
                    continue

                subscribers[subscriber_name].subscribe(event_type, handler_funcs[handler_name])
                print(f"{handler_name} subscribed to {event_type}")

            elif command == "UNSUBSCRIBE":
                parts = args.split(" ", 2) # Split into subscriber_name, event_type, handler_name
                if len(parts) != 3:
                    print(f"Harness Error: Invalid UNSUBSCRIBE command format: '{line}'")
                    continue
                subscriber_name, event_type, handler_name = parts

                if subscriber_name not in subscribers:
                    print(f"Harness Error: Subscriber '{subscriber_name}' not found.")
                    continue
                if handler_name not in handler_funcs:
                    print(f"Harness Error: Handler '{handler_name}' not found.")
                    continue

                subscribers[subscriber_name].unsubscribe(event_type, handler_funcs[handler_name])

            elif command == "EMIT":
                # EMIT publisher_name event_type [payload={"key":"value"}]
                parts = args.split(" ", 1) # Split into publisher_name and rest of args
                if len(parts) < 1:
                    print(f"Harness Error: Invalid EMIT command format: '{line}'")
                    continue
                
                publisher_name = parts[0]
                remaining_args = parts[1] if len(parts) > 1 else ""

                event_type_payload_parts = remaining_args.split(" payload=", 1)
                
                if not event_type_payload_parts[0]: # event_type is mandatory
                    print(f"Harness Error: Event type missing for EMIT command: '{line}'")
                    continue
                
                event_type = event_type_payload_parts[0]
                payload_str = event_type_payload_parts[1] if len(event_type_payload_parts) > 1 else "{}"

                payload = json.loads(payload_str) # Parse payload as JSON

                if publisher_name not in publishers:
                    print(f"Harness Error: Publisher '{publisher_name}' not found.")
                    continue
                
                publishers[publisher_name].emit(event_type, payload)

            else:
                print(f"Harness Error: Unknown command: {command}")
        except json.JSONDecodeError as jde:
            print(f"Harness Error: Invalid JSON payload in command '{line}': {jde}")
        except KeyError as ke:
            print(f"Harness Error: Missing expected key/object in command '{line}': {ke}")
        except Exception as e:
            # Catch any other exceptions, likely originating from user code
            print(f"Harness Error processing command '{command} {args}': {type(e).__name__}: {e}")

# Call the harness function at module level as the sole entry point
run_harness()$harness$,
  test_cases   = '[{"input": "CREATE_BUS\nCREATE_SUBSCRIBER sub1\nDEFINE_HANDLER handler_a\nSUBSCRIBE sub1 user_created handler_a", "description": "Subscribe handler to event", "expected_output": "handler_a subscribed to user_created"}, {"input": "CREATE_BUS\nCREATE_PUBLISHER pub1\nCREATE_SUBSCRIBER sub1\nDEFINE_HANDLER handler_a\nSUBSCRIBE sub1 user_created handler_a\nEMIT pub1 user_created payload={\"id\":1}", "description": "Emit event calls subscriber", "expected_output": "handler_a subscribed to user_created\nhandler_a called with {''id'': 1}"}, {"input": "CREATE_BUS\nCREATE_PUBLISHER pub1\nEMIT pub1 no_subscribers_event payload={}", "description": "Emit with no subscribers is a no-op", "expected_output": ""}, {"input": "CREATE_BUS\nCREATE_PUBLISHER pub1\nCREATE_SUBSCRIBER sub1\nDEFINE_HANDLER handler_b\nDEFINE_HANDLER handler_c\nSUBSCRIBE sub1 order_placed handler_b\nSUBSCRIBE sub1 order_placed handler_c\nEMIT pub1 order_placed payload={}", "description": "Multiple handlers called in subscription order", "expected_output": "handler_b subscribed to order_placed\nhandler_c subscribed to order_placed\nhandler_b called\nhandler_c called"}, {"input": "CREATE_BUS\nCREATE_PUBLISHER pub1\nCREATE_SUBSCRIBER sub1\nDEFINE_HANDLER handler_d\nSUBSCRIBE sub1 click handler_d\nUNSUBSCRIBE sub1 click handler_d\nEMIT pub1 click payload={}", "description": "Unsubscribed handler is not called", "expected_output": "handler_d subscribed to click"}]'::jsonb
