-- dp_005: Payment Strategy Engine
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', () => {
  // The user's classes (Strategy, Context, and concrete strategy implementations)
  // are available in this scope due to concatenation.

  // Initialize the stateful Context object
  const context = new Context();

  // Map strategy type strings to their constructors. 
  // The user is expected to implement these specific concrete strategy classes 
  // (e.g., CreditCardStrategy, PaypalStrategy, etc.) implementing the Strategy interface.
  const strategyConstructors: { [key: string]: new () => Strategy } = {
    "CreditCard": CreditCardStrategy,
    "Paypal": PaypalStrategy,
    "Crypto": CryptoStrategy,
    "BankTransfer": BankTransferStrategy,
  };

  for (const line of lines) {
    const [command, typeOrAmountStr] = line.split(' ');

    switch (command) {
      case 'SET_STRATEGY':
        const strategyType = typeOrAmountStr;
        const StrategyClass = strategyConstructors[strategyType];
        if (StrategyClass) {
          context.setStrategy(new StrategyClass());
        }
        // If StrategyClass is undefined, context.setStrategy() will likely be called
        // with an invalid argument or new StrategyClass() will throw, leading to test failure.
        break;

      case 'PROCESS_PAYMENT':
        const amount = parseFloat(typeOrAmountStr);
        if (!isNaN(amount)) {
          // Assume Context's processPayment method takes an object like { amount: number }
          // and delegates to the currently set Strategy's execute method.
          context.processPayment({ amount: amount });
        }
        // If amount is NaN, context.processPayment() will be called with an invalid value,
        // or the strategy's execute method might receive an unexpected type, leading to test failure.
        break;

      default:
        // Unknown commands are ignored, letting the test fail if it leads to incorrect behavior.
        break;
    }
  }
});$harness$,
  test_cases   = '[{"input": "SET_STRATEGY CreditCard\nPROCESS_PAYMENT 100", "description": "Credit card payment", "expected_output": "Charged $100.00 via Credit Card"}, {"input": "SET_STRATEGY Paypal\nPROCESS_PAYMENT 50", "description": "PayPal payment", "expected_output": "Charged $50.00 via PayPal"}, {"input": "SET_STRATEGY Crypto\nPROCESS_PAYMENT 200", "description": "Crypto payment", "expected_output": "Charged $200.00 via Crypto"}, {"input": "SET_STRATEGY BankTransfer\nPROCESS_PAYMENT 1000", "description": "Bank transfer payment", "expected_output": "Charged $1000.00 via Bank Transfer"}]'::jsonb
WHERE id = 'dp_005';
-- dp_006: Chat Observer System
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', () => {
  // The user is expected to have implemented:
  //   - interface Strategy { execute(context: Context, data: Record<string, string>): string; }
  //   - class Context { // Should implement: setStrategy, executeStrategy, subscribeUserToChannel, unsubscribeUserFromChannel, getUsersInChannel }
  //   - Specific strategy classes like SubscribeStrategy, PublishStrategy, UnsubscribeStrategy, 
  //     each implementing the 'Strategy' interface.

  // Instantiate user's Context and Strategy implementations
  const chatContext = new Context();
  const subscribeStrategy = new SubscribeStrategy();
  const publishStrategy = new PublishStrategy();
  const unsubscribeStrategy = new UnsubscribeStrategy();

  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    const parts = line.split(' ');
    const commandType = parts[0];
    const paramsString = parts.slice(1).join(' ').trim(); // Get the rest of the line as parameter string

    const params: Record<string, string> = {};
    if (paramsString) {
      paramsString.split(',').forEach(pair => { // Split by comma to get individual param=value pairs
        const trimmedPair = pair.trim();
        const [key, value] = trimmedPair.split('='); // Split each pair by '='
        if (key && value) {
          params[key.trim()] = value.trim(); // Store trimmed key-value pairs
        }
      });
    }

    let currentStrategy: Strategy | undefined;
    switch (commandType) {
      case 'subscribe':
        currentStrategy = subscribeStrategy;
        break;
      case 'publish':
        currentStrategy = publishStrategy;
        break;
      case 'unsubscribe':
        currentStrategy = unsubscribeStrategy;
        break;
      default:
        console.log(`Error: Unknown command type '${commandType}'`);
        continue; // Skip to next line if command type is unknown
    }

    if (currentStrategy) {
      chatContext.setStrategy(currentStrategy);
      try {
        const output = chatContext.executeStrategy(params);
        console.log(output);
      } catch (e: any) {
        console.log(`Error during command execution: ${e.message}`);
      }
    }
  }
});$harness$,
  test_cases   = '[{"input": "subscribe user=alice, channel=news", "description": "User subscribes to channel", "expected_output": "alice subscribed to news"}, {"input": "subscribe user=alice, channel=news\npublish channel=news, message=Breaking news!", "description": "Message delivered to subscriber", "expected_output": "alice subscribed to news\nalice received: Breaking news!"}, {"input": "subscribe user=alice, channel=news\nunsubscribe user=alice, channel=news", "description": "User unsubscribes", "expected_output": "alice subscribed to news\nalice unsubscribed from news"}, {"input": "subscribe user=alice, channel=news\nunsubscribe user=alice, channel=news\npublish channel=news, message=Update", "description": "No delivery after unsubscribe", "expected_output": "alice subscribed to news\nalice unsubscribed from news\nNo subscribers notified"}, {"input": "publish channel=general, message=Hello world", "description": "Publish to an empty channel", "expected_output": "No subscribers notified"}, {"input": "subscribe user=alice, channel=general\nsubscribe user=bob, channel=general\npublish channel=general, message=Meeting today!", "description": "Multiple users subscribe to same channel and receive message (order by subscription)", "expected_output": "alice subscribed to general\nbob subscribed to general\nalice received: Meeting today!\nbob received: Meeting today!"}, {"input": "subscribe user=charlie, channel=updates\nsubscribe user=diana, channel=updates\nunsubscribe user=charlie, channel=updates\npublish channel=updates, message=New feature released", "description": "One of multiple users unsubscribes, others still receive message", "expected_output": "charlie subscribed to updates\ndiana subscribed to updates\ncharlie unsubscribed from updates\ndiana received: New feature released"}, {"input": "subscribe user=eve, channel=tech\npublish channel=tech, message=Latest gadgets\nsubscribe user=frank, channel=tech\npublish channel=tech, message=New programming language", "description": "User subscribes mid-session and receives subsequent messages", "expected_output": "eve subscribed to tech\neve received: Latest gadgets\nfrank subscribed to tech\neve received: New programming language\nfrank received: New programming language"}]'::jsonb
