-- dp_007: Vehicle Factory Assembly
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

// The harness will use the user's implementations of Strategy, Context, and concrete strategies
// when concatenated with their code. These declarations are included within the harness
// for type-checking the harness itself during compilation and to provide a blueprint
// for the expected user implementation based on the challenge description and outputs.

/**
 * Assumed interface for concrete strategy classes.
 * Users are expected to modify the starter `execute` method to return a string
 * representing the vehicle description, rather than `void`.
 */
interface Strategy {
  execute(): string;
}

/**
 * Assumed implementation for the Context class.
 * Users are expected to implement methods to hold and execute a strategy.
 */
class Context {
  private strategy: Strategy | null = null;

  setStrategy(strategy: Strategy): void {
    this.strategy = strategy;
  }

  executeStrategy(): string {
    if (!this.strategy) {
      throw new Error("Context strategy not set. Cannot execute.");
    }
    return this.strategy.execute();
  }
}

