-- dp_011: Configuration Singleton Registry
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
    // The user is expected to implement a 'ConfigurationManager' class
    // with a static getInstance() method, and instance methods set(key, value) and get(key).
    // The getInstance() method should print "Singleton instance created" on first call
    // and "Returning existing instance" on subsequent calls.
    // The set() method should print "Config <key> set to <value>".
    // The get() method should return the stored value or undefined if not found.

    let configManager: any = null; // Use 'any' to interact with the user's class dynamically

    for (const line of lines) {
        if (!line) {
            continue; // Skip empty lines
        }

        const parts = line.split(/\s+/); // Split by one or more spaces
        const command = parts[0];

        try {
            switch (command) {
                case 'get_instance':
                    configManager = ConfigurationManager.getInstance();
                    // User's getInstance() method is expected to print its own messages.
                    break;
                case 'SET':
                    if (!configManager) {
                        console.log("Error: ConfigurationManager not initialized. Call get_instance first.");
                        break;
                    }
                    if (parts.length < 3) {
                        console.log("Error: SET command requires key and value. Usage: SET <key> <value>");
                        break;
                    }
                    const setKey = parts[1];
                    const setValue = parts.slice(2).join(' '); // Join remaining parts for value to handle spaces
                    configManager.set(setKey, setValue);
                    // User's set() method is expected to print its own messages.
                    break;
                case 'GET':
                    if (!configManager) {
                        console.log("Error: ConfigurationManager not initialized. Call get_instance first.");
                        break;
                    }
                    if (parts.length < 2) {
                        console.log("Error: GET command requires key. Usage: GET <key>");
                        break;
                    }
                    const getKey = parts[1];
                    const value = configManager.get(getKey);
                    // Output "null" for undefined values, otherwise the value itself.
                    console.log(value === undefined ? "null" : value);
                    break;
                default:
                    console.log(`Unknown command: ${line}`);
                    break;
            }
        } catch (error: any) {
            console.log(`Runtime Error: ${error.message}`);
        }
    }
});$harness$,
