  // We assume the user will adapt the provided `Context` class to be the Aggregate (Playlist)
  // and the `Strategy` interface/`ConcreteStrategy` class to be the Iterator interface/implementation.
  // The expected structure for user-implemented classes within the challenge would be:
  //
  //   interface Strategy { // User modifies this interface for Iterator methods
  //     hasNext(): boolean;
  //     next(): string | undefined; // Or string | null, or throw an error when no more elements
  //   }
  //
  //   class Context { // User adapts this class to be the Playlist (Aggregate)
  //     private songs: string[];
  //
  //     constructor(initialSongs: string[]) { /* ... */ }
  //
  //     // This method creates and returns an iterator (a 'Strategy' instance)
  //     public createIterator(): Strategy { /* ... */ }
  //   }
  //
  //   class ConcreteStrategy implements Strategy { // User implements this as the ConcreteIterator
  //     private items: string[];
  //     private position: number = 0;
  //
  //     constructor(items: string[]) { /* ... */ }
  //     hasNext(): boolean { /* ... */ }
  //     next(): string | undefined { /* ... */ }
  //   }

  let currentContext: Context | null = null;
  let currentIterator: Strategy | null = null;

  for (const line of lines) {
    const [command, ...args] = line.split(' ');

    try {
      switch (command) {
        case 'CREATE_PLAYLIST':
          // Expected input format: CREATE_PLAYLIST [song1,song2,...]
          let playlistItems: string[] = [];
          if (args.length > 0) {
            const rawList = args[0].substring(1, args[0].length - 1); // Remove square brackets
            if (rawList.length > 0) {
              playlistItems = rawList.split(',').map(item => item.trim());
            }
          }
          currentContext = new Context(playlistItems);
          break;

        case 'GET_ITERATOR':
          if (!currentContext) {
            console.log('Error: Playlist not created. Use CREATE_PLAYLIST first.');
            continue;
          }
          currentIterator = currentContext.createIterator();
          break;

        case 'NEXT':
          if (!currentIterator) {
            console.log('Error: Iterator not obtained. Use GET_ITERATOR first.');
            continue;
          }
          const nextItem = currentIterator.next();
          // User's next() is expected to return string, undefined, or null. If it throws, the catch block handles it.
          if (nextItem !== undefined && nextItem !== null) {
            console.log(nextItem);
          } else {
            // If next() returns undefined or null when called past the end, print 'undefined' for consistent testing.
            console.log('undefined'); 
          }
          break;

        case 'HAS_NEXT':
          if (!currentIterator) {
            console.log('Error: Iterator not obtained. Use GET_ITERATOR first.');
            continue;
          }
          console.log(currentIterator.hasNext());
          break;

        default:
          console.log(`Error: Unknown command - ${command}`);
          break;
      }
    } catch (e: any) {
      // Catch any runtime errors thrown by the user's implementation (e.g., next() throwing an error).
      console.log(`Runtime Error: ${e.message || e}`);
    }
  }
});$harness$,
