-- dp_016: Media Player Adapter Bridge
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {
  // User's classes (Strategy, Context, ConcreteStrategy) are available here.
  // We assume the user implements Context with a `setStrategy(strategy: Strategy)`
  // and a `run(data: unknown)` method that delegates to the current strategy's `execute`.
  // We also assume ConcreteStrategy can be initialized with a player name to differentiate behaviors.

  const playerContext = new Context();

  // Instantiate concrete strategy implementations for known players.
  // This uses the single ConcreteStrategy class with a constructor parameter
  // to make the harness robust to whether the user defines multiple classes
  // or parameterizes the given ConcreteStrategy.
  const vlcStrategy = new ConcreteStrategy("VLC");
  const quickTimeStrategy = new ConcreteStrategy("QuickTime");
  const winAmpStrategy = new ConcreteStrategy("WinAmp");

  const availableStrategies: { [key: string]: Strategy } = {
    "VLC": vlcStrategy,
    "QuickTime": quickTimeStrategy,
    "WinAmp": winAmpStrategy,
  };

  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    const parts = line.split(' ');
    const command = parts[0];
    const arg = parts.slice(1).join(' '); // Rejoin for arguments that might contain spaces

    switch (command) {
      case 'SET_PLAYER':
        const playerName = arg;
        const strategy = availableStrategies[playerName];
        if (strategy) {
          playerContext.setStrategy(strategy);
        } else {
          console.log(`Error: Unknown player "${playerName}"`);
        }
        break;
      case 'PLAY':
        const mediaType = arg;
        playerContext.run(mediaType);
        break;
      default:
        console.log(`Error: Unknown command "${command}"`);
        break;
    }
  }
});$harness$,
