-- dp_017: Report Template Generator
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {
  // User's classes (Context, ConcreteStrategy, etc.) are available here due to concatenation.

  // --- Start Harness Logic ---

  // Map logical strategy names (used in test inputs) to the user's expected class names.
  // The user is expected to implement these specific classes, each adhering to the Strategy interface.
  const strategyClassNames: { [key: string]: string } = {
    'sales_report': 'SalesReportStrategy',
    'expense_report': 'ExpenseReportStrategy',
    'summary_report': 'SummaryReportStrategy',
    'pdf_export': 'PdfExportStrategy', // For the 'export_format=pdf' case, assuming a dedicated strategy
  };

  // Instantiate the Context object. This object will maintain state across commands.
  let context: Context;
  try {
    // The user MUST implement the `Context` class.
    // We assume its constructor can be called without arguments initially.
    context = new Context();
  } catch (e: any) {
    console.log(`Error: Could not instantiate Context class. Make sure 'class Context' is defined and accessible. Details: ${e.message}`);
    return; // Stop execution if Context cannot be created.
  }

  // Process each command line from stdin.
  for (const line of lines) {
    // Split the command from its arguments. Use a regex to split only on the first space.
    const parts = line.split(/ (.+)/);
    const command = parts[0];
    const args = parts[1] || ''; // Arguments string, or empty if no arguments.

    switch (command) {
      case 'SET_STRATEGY': {
        const strategyIdentifier = args; // e.g., 'sales_report'
        const userClassName = strategyClassNames[strategyIdentifier];

        if (!userClassName) {
          console.log(`Error: Unknown strategy identifier provided: "${strategyIdentifier}".`);
          continue;
        }

        try {
          // Dynamically obtain the constructor for the user's strategy class from the global scope.
          // This relies on the user defining classes with the expected names.
          const StrategyConstructor = (globalThis as any)[userClassName];

          if (typeof StrategyConstructor !== 'function') {
            console.log(`Error: Strategy class "${userClassName}" not found or is not a constructor.`);
            continue;
          }

          // Create an instance of the user's concrete strategy.
          const strategyInstance: Strategy = new StrategyConstructor();
          
          // The user's `Context` class MUST have a `setStrategy` method.
          if (typeof (context as any).setStrategy !== 'function') {
             console.log(`Error: Context class must implement a 'setStrategy(strategy: Strategy)' method.`);
             continue;
          }
          context.setStrategy(strategyInstance);
          // No output is expected for commands that set state.
        } catch (e: any) {
          console.log(`Error instantiating strategy "${userClassName}": ${e.message}`);
        }
        break;
      }

      case 'EXECUTE': {
        let data: unknown = {};
        if (args) {
          try {
            // Attempt to parse the arguments as a JSON object.
            data = JSON.parse(args);
          } catch (e: any) {
            console.log(`Error: Invalid JSON data for EXECUTE command. Details: ${e.message}. Raw input: "${args}"`);
            continue;
          }
        }
        
        try {
          // The user's `Context` class MUST have an `executeStrategy` method.
          if (typeof (context as any).executeStrategy !== 'function') {
             console.log(`Error: Context class must implement an 'executeStrategy(data: unknown)' method.`);
             continue;
          }
          // Delegate the execution to the currently set strategy via the context.
          context.executeStrategy(data);
        } catch (e: any) {
          console.log(`Error during strategy execution: ${e.message}`);
        }
        break;
      }

      default:
        console.log(`Error: Unknown command received: "${command}".`);
    }
  }

  // --- End Harness Logic ---
});$harness$,
  test_cases   = '[{"input": "SET_STRATEGY sales_report\nEXECUTE {\"revenue\": 5000}", "description": "Generate sales report", "expected_output": "Sales Report generated with revenue $5000"}, {"input": "SET_STRATEGY expense_report\nEXECUTE {\"total\": 1200}", "description": "Generate expense report", "expected_output": "Expense Report generated with total $1200"}, {"input": "SET_STRATEGY summary_report\nEXECUTE {\"items\": 3}", "description": "Generate summary report", "expected_output": "Summary Report generated with 3 items"}, {"input": "SET_STRATEGY pdf_export\nEXECUTE {}", "description": "Export report as PDF", "expected_output": "Report exported as PDF"}, {"input": "SET_STRATEGY sales_report\nEXECUTE {\"revenue\": 7500}\nSET_STRATEGY expense_report\nEXECUTE {\"total\": 1500}\nSET_STRATEGY summary_report\nEXECUTE {\"items\": 5}", "description": "Generate multiple reports in sequence (stateful)", "expected_output": "Sales Report generated with revenue $7500\nExpense Report generated with total $1500\nSummary Report generated with 5 items"}, {"input": "EXECUTE {}", "description": "Execute without strategy set (should handle gracefully)", "expected_output": "Error during strategy execution: No strategy set."}]'::jsonb
WHERE id = 'dp_017';
-- dp_018: Support Ticket Chain Handler
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // Store the original console.log to restore it later
  const originalConsoleLog = console.log;

  // Variables to capture console.log output
  let capturedOutput: string[] = [];
  const captureConsoleLog = (...args: any[]) => {
    capturedOutput.push(args.map(arg => String(arg)).join(' '));
  };

  try {
    // Instantiate the chain of strategies.
    // We assume the user implements concrete strategy classes with these specific names:
    // ManagerHandlerStrategy, Level3HandlerStrategy, Level2HandlerStrategy, Level1HandlerStrategy.
    // Each handler (except the last) is expected to take the next handler in its constructor.
    // The Strategy interface's execute method is assumed to be `execute(data: unknown): void`
    // and is expected to use `console.log` for its output.

    const managerStrategy: Strategy = new ManagerHandlerStrategy();
    const level3Strategy: Strategy = new Level3HandlerStrategy(managerStrategy);
    const level2Strategy: Strategy = new Level2HandlerStrategy(level3Strategy);
    const level1Strategy: Strategy = new Level1HandlerStrategy(level2Strategy);

    // Initialize the Context with the head of the chain (Level1HandlerStrategy).
    // We assume the Context class has a constructor that accepts an initial Strategy.
    const context = new Context(level1Strategy);

    // Process each command from stdin
    for (const line of lines) {
      if (!line) continue;

      const parts = line.split(' ');
      const command = parts[0];
      const payload = parts.slice(1).join(' '); // The ticket priority string

      if (command === 'HANDLE_TICKET') {
        capturedOutput = []; // Clear output for the current command
        console.log = captureConsoleLog; // Redirect console.log to capture output
        
        // The Context's execute method is called, passing a data object.
        // User's strategy implementations should cast `data: unknown` to the expected type
        // (e.g., `{ priority: string }`).
        const ticketData = { priority: payload };
        context.execute(ticketData);

        // Restore console.log and print the captured output for this command.
        console.log = originalConsoleLog;
        originalConsoleLog(capturedOutput.join('\n'));
      } else {
        originalConsoleLog(`Unknown command: ${command}`);
      }
    }
  } catch (error: any) {
    // Log any errors during the harness execution or user code interaction.
    originalConsoleLog(`Error during test harness execution: ${error.message}`);
    if (error.stack) {
      originalConsoleLog(error.stack);
    }
  } finally {
    // Ensure console.log is always restored to its original state.
    console.log = originalConsoleLog;
  }
});$harness$,
  test_cases   = '[{"input": "HANDLE_TICKET low_priority", "description": "Low priority handled at level 1", "expected_output": "Level 1 handler resolved ticket"}, {"input": "HANDLE_TICKET medium_priority", "description": "Medium escalated to level 2", "expected_output": "Level 1 passed to Level 2\nLevel 2 resolved ticket"}, {"input": "HANDLE_TICKET critical", "description": "Critical escalated to level 3", "expected_output": "Level 1 passed to Level 2\nLevel 2 passed to Level 3\nLevel 3 resolved ticket"}, {"input": "HANDLE_TICKET unknown_type", "description": "Unhandled ticket type", "expected_output": "Level 1 passed to Level 2\nLevel 2 passed to Level 3\nLevel 3 passed to Manager\nTicket unhandled, escalated to manager"}]'::jsonb
WHERE id = 'dp_018';
-- dp_019: Trading Floor Mediator
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  function parseCommand(line: string): { command: string, args: Record<string, string | number> } {
    const parts = line.split(' ');
    const command = parts[0];
    const args: Record<string, string | number> = {};

    if (parts.length > 1) {
      const paramsString = parts.slice(1).join(' ');
      const paramPairs = paramsString.split(',').map(p => p.trim()).filter(p => p.includes('='));
      for (const pair of paramPairs) {
        const [key, value] = pair.split('=').map(s => s.trim());
        args[key] = isNaN(Number(value)) ? value : Number(value);
      }
    }
    return { command, args };
  }

  // The user's Context class is assumed to act as the Mediator and hold state.
  // The user's ConcreteStrategy is assumed to be a generic strategy that takes
  // a command type and parameters, delegating to the Context.
  const tradingFloor = new Context(); 

  for (const line of lines) {
    if (!line) continue;

    const { command, args } = parseCommand(line);
    let output: string | null = null;
    let strategy: Strategy | null = null;

    switch (command) {
      case 'place_order':
        if (typeof args.trader === 'string' && typeof args.stock === 'string' && typeof args.qty === 'number') {
          strategy = new ConcreteStrategy('place_order', { trader: args.trader, stock: args.stock, qty: args.qty, type: 'buy' });
        } else {
          output = `Error: Invalid arguments for place_order: ${line}`;
        }
        break;
      case 'place_sell_order': // Added for comprehensive matching tests
        if (typeof args.trader === 'string' && typeof args.stock === 'string' && typeof args.qty === 'number') {
          strategy = new ConcreteStrategy('place_sell_order', { trader: args.trader, stock: args.stock, qty: args.qty, type: 'sell' });
        } else {
          output = `Error: Invalid arguments for place_sell_order: ${line}`;
        }
        break;
      case 'match_orders':
        if (typeof args.stock === 'string') {
          strategy = new ConcreteStrategy('match_orders', { stock: args.stock });
        } else {
          output = `Error: Invalid arguments for match_orders: ${line}`;
        }
        break;
      case 'cancel_order':
        if (typeof args.trader === 'string' && typeof args.order_id === 'number') {
          strategy = new ConcreteStrategy('cancel_order', { trader: args.trader, order_id: args.order_id });
        } else {
          output = `Error: Invalid arguments for cancel_order: ${line}`;
        }
        break;
      case 'get_price':
        if (typeof args.stock === 'string') {
          strategy = new ConcreteStrategy('get_price', { stock: args.stock });
        } else {
          output = `Error: Invalid arguments for get_price: ${line}`;
        }
        break;
      default:
        output = `Unknown command: ${command}`;
        break;
    }

    if (strategy) {
      try {
        output = tradingFloor.executeStrategy(strategy);
      } catch (e: any) {
        output = `Error executing strategy: ${e.message || e}`;
      }
    }
    if (output !== null) {
      console.log(output);
    }
  }
});$harness$,
  test_cases   = '[{"input": "place_order trader=alice, stock=AAPL, qty=100", "description": "Place buy order", "expected_output": "Order placed: alice buys 100 AAPL"}, {"input": "place_order trader=alice, stock=AAPL, qty=100\nplace_sell_order trader=bob, stock=AAPL, qty=50\nmatch_orders stock=AAPL", "description": "Match buy and sell orders", "expected_output": "Order placed: alice buys 100 AAPL\nOrder placed: bob sells 50 AAPL\nOrders matched for AAPL"}, {"input": "place_order trader=alice, stock=AAPL, qty=100\ncancel_order trader=alice, order_id=1\nplace_order trader=alice, stock=GOOG, qty=50\ncancel_order trader=bob, order_id=2", "description": "Cancel order", "expected_output": "Order placed: alice buys 100 AAPL\nOrder 1 cancelled for alice\nOrder placed: alice buys 50 GOOG\nOrder 2 not found or not cancellable for bob"}, {"input": "get_price stock=AAPL\nget_price stock=GOOG\nget_price stock=MSFT", "description": "Get stock price", "expected_output": "AAPL current price: $150.00\nGOOG current price: $2000.00\nPrice not available for MSFT"}, {"input": "place_order trader=charlie, stock=MSFT, qty=200\nplace_sell_order trader=diana, stock=MSFT, qty=100\nmatch_orders stock=MSFT\ncancel_order trader=charlie, order_id=1\nget_price stock=MSFT", "description": "Full trading flow: place, match, cancel, get price", "expected_output": "Order placed: charlie buys 200 MSFT\nOrder placed: diana sells 100 MSFT\nOrders matched for MSFT\nOrder 1 cancelled for charlie\nPrice not available for MSFT"}]'::jsonb
WHERE id = 'dp_019';
-- dp_020: Game Save Memento System
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // This harness assumes the user has adapted the provided 'Context' class
  // to act as the 'Originator' (the Game whose state is saved) and
  // 'ConcreteStrategy' class to act as the 'Memento' (the saved state snapshot).
  // The harness itself plays the role of the 'Caretaker'.
  //
  // Expected User Implementation Structure:
  //
  // interface Strategy {
  //   execute(data: unknown): void; // This method can be a no-op for a Memento
  //   getState(): { level: number; health: number; score: number }; // Added for Memento functionality
  // }
  //
  // class Context { // Originator
  //   private state: { level: number; health: number; score: number };
  //   constructor(initialLevel: number = 1, initialHealth: number = 100, initialScore: number = 0) { ... }
  //   public updateState(level: number, health: number, score: number): void { ... }
  //   public save(): Strategy { /* Returns a new ConcreteStrategy instance */ }
  //   public restore(memento: Strategy): void { /* Sets internal state from memento.getState() */ }
  //   public getCurrentStateString(): string { /* Returns 'level X, health Y, score Z' */ }
  // }
  //
  // class ConcreteStrategy implements Strategy { // Memento
  //   private mementoState: { level: number; health: number; score: number };
  //   constructor(level: number, health: number, score: number) { ... }
  //   execute(data: unknown): void { /* No-op or debug print */ }
  //   getState(): { level: number; health: number; score: number } { /* Returns a copy of mementoState */ }
  // }

  // Initialize the game Originator. The harness expects Context's constructor
  // to be callable without arguments and to provide sensible default initial state.
  const game = new Context(); 

  // This variable acts as the Caretaker's storage for the single Memento (game save).
  let savedGameMemento: Strategy | null = null;

  for (const line of lines) {
    if (line.startsWith("save_state")) {
      // Parse the game state parameters from the input line.
      const params = line.substring("save_state ".length).split(', ').map(s => s.trim());
      let level = 1; // Default values, will be overwritten by input if present
      let health = 100;
      let score = 0;

      for (const param of params) {
        const [key, value] = param.split('=');
        const numValue = parseInt(value, 10);
        if (key === 'level') level = numValue;
        else if (key === 'health') health = numValue;
        else if (key === 'score') score = numValue;
      }

      // Update the Originator's (game's) current state before saving.
      game.updateState(level, health, score);
      
      // Instruct the Originator to create a Memento (ConcreteStrategy instance)
      // and store it in the Caretaker's storage.
      savedGameMemento = game.save();
      
      // Output the current state after saving.
      console.log(`Game state saved: ${game.getCurrentStateString()}`);

    } else if (line === "restore_state") {
      if (savedGameMemento) {
        // If a Memento exists, instruct the Originator to restore its state from it.
        game.restore(savedGameMemento);
        
        // Output the current state after restoring.
        console.log(`Game restored: ${game.getCurrentStateString()}`);
      } else {
        // Handle the case where no Memento has been saved yet.
        console.log("No saved state found");
      }
    }
  }
});$harness$,
  test_cases   = '[{"input": "save_state level=5, health=80, score=1200", "description": "Save initial game state", "expected_output": "Game state saved: level 5, health 80, score 1200"}, {"input": "save_state level=5, health=80, score=1200\nrestore_state", "description": "Save and then restore the game state", "expected_output": "Game state saved: level 5, health 80, score 1200\nGame restored: level 5, health 80, score 1200"}, {"input": "save_state level=10, health=50, score=2000\nsave_state level=7, health=40, score=2500\nrestore_state", "description": "Overwrite save state and restore the latest", "expected_output": "Game state saved: level 10, health 50, score 2000\nGame state saved: level 7, health 40, score 2500\nGame restored: level 7, health 40, score 2500"}, {"input": "restore_state", "description": "Attempt to restore with no prior save", "expected_output": "No saved state found"}, {"input": "save_state level=1, health=100, score=0\nrestore_state\nsave_state level=2, health=90, score=500\nrestore_state", "description": "Multiple save/restore cycles", "expected_output": "Game state saved: level 1, health 100, score 0\nGame restored: level 1, health 100, score 0\nGame state saved: level 2, health 90, score 500\nGame restored: level 2, health 90, score 500"}, {"input": "restore_state\nsave_state level=15, health=75, score=3000\nrestore_state\nrestore_state", "description": "Restore before save, then save and restore twice", "expected_output": "No saved state found\nGame state saved: level 15, health 75, score 3000\nGame restored: level 15, health 75, score 3000\nGame restored: level 15, health 75, score 3000"}]'::jsonb
WHERE id = 'dp_020';
-- dp_021: Traffic Light State Machine
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {
  // User's classes (Strategy, Context, RedStateStrategy, GreenStateStrategy, YellowStateStrategy)
  // are expected to be available here, prepended to this harness.
  // The harness assumes the user has implemented:
  // - interface Strategy { getName(): string; execute(event: string): string | null; }
  // - class Context { constructor(initialStrategy: Strategy, availableStrategies: Map<string, Strategy>); setStrategyByName(strategyName: string): void; request(event: string): void; activateEmergency(): void; deactivateEmergency(): void; getCurrentState(): string; }
  // - class RedStateStrategy implements Strategy { ... }
  // - class GreenStateStrategy implements Strategy { ... }
  // - class YellowStateStrategy implements Strategy { ... }

  try {
    // 1. Instantiate all concrete strategies (assuming user implements these classes)
    const redState = new RedStateStrategy();
    const greenState = new GreenStateStrategy();
    const yellowState = new YellowStateStrategy();

    // 2. Create a map of available strategies for the Context to manage transitions
    const availableStrategies = new Map<string, Strategy>();
    availableStrategies.set('RED', redState);
    availableStrategies.set('GREEN', greenState);
    availableStrategies.set('YELLOW', yellowState);

    let trafficLight: Context;
    let firstCommandProcessed = false;

    for (const line of lines) {
      if (!line) continue; // Skip empty lines

      const [command, arg] = line.split('=');

      if (!firstCommandProcessed) {
        // Initialize the traffic light context with an initial state
        if (command === 'INITIAL_STATE' && arg) {
          const initialState = availableStrategies.get(arg);
          if (initialState) {
            trafficLight = new Context(initialState, availableStrategies);
          } else {
            console.log(`Warning: Invalid initial state '${arg}'. Defaulting to RED.`);
            trafficLight = new Context(redState, availableStrategies);
          }
        } else {
          // If the first command is not INITIAL_STATE, use default initial state (RED)
          trafficLight = new Context(redState, availableStrategies);
          // The current line will be processed as a regular command after this block.
        }
        firstCommandProcessed = true;
      }

      // Process commands on the initialized trafficLight
      // Skip INITIAL_STATE if it was the very first command (already handled initialization)
      if (command === 'INITIAL_STATE' && firstCommandProcessed && line === lines[0]) {
          continue;
      }

      switch (command) {
        case 'HANDLE_EVENT':
          if (arg) {
            trafficLight.request(arg);
          } else {
            console.log('Error: HANDLE_EVENT command requires an event argument.');
          }
          break;
        case 'ACTIVATE_EMERGENCY':
          trafficLight.activateEmergency();
          break;
        case 'DEACTIVATE_EMERGENCY':
          trafficLight.deactivateEmergency();
          break;
        case 'GET_CURRENT_STATE': // For debugging/testing current state explicitly
          console.log(`Current State: ${trafficLight.getCurrentState()}`);
          break;
        case 'INITIAL_STATE': // If it's not the first command, log a warning (or ignore silently)
          console.log(`Warning: INITIAL_STATE command ignored as light is already initialized.`);
          break;
        default:
          console.log(`Error: Unknown command '${command}'.`);
          break;
      }
    }
  } catch (error: any) {
    console.error(`Runtime Error: ${error.message}`);
  }
});$harness$,
  test_cases   = '[{"input": "INITIAL_STATE=RED\nHANDLE_EVENT=timer_expired", "description": "Red to green transition", "expected_output": "Initial state: RED\nTransition: RED -> GREEN"}, {"input": "INITIAL_STATE=GREEN\nHANDLE_EVENT=timer_expired", "description": "Green to yellow transition", "expected_output": "Initial state: GREEN\nTransition: GREEN -> YELLOW"}, {"input": "INITIAL_STATE=YELLOW\nHANDLE_EVENT=timer_expired", "description": "Yellow to red transition", "expected_output": "Initial state: YELLOW\nTransition: YELLOW -> RED"}, {"input": "INITIAL_STATE=RED\nHANDLE_EVENT=emergency", "description": "Emergency mode activation from RED (already RED)", "expected_output": "Initial state: RED\nAll lights RED, emergency mode activated."}, {"input": "INITIAL_STATE=GREEN\nHANDLE_EVENT=emergency", "description": "Emergency mode activation from GREEN", "expected_output": "Initial state: GREEN\nAll lights RED, emergency mode activated.\nTransition: GREEN -> RED"}, {"input": "INITIAL_STATE=GREEN\nHANDLE_EVENT=emergency\nHANDLE_EVENT=deactivate_emergency", "description": "Activate then deactivate emergency mode", "expected_output": "Initial state: GREEN\nAll lights RED, emergency mode activated.\nTransition: GREEN -> RED\nEmergency mode deactivated."}, {"input": "INITIAL_STATE=GREEN\nHANDLE_EVENT=emergency\nHANDLE_EVENT=timer_expired", "description": "Timer expired during emergency (from RED)", "expected_output": "Initial state: GREEN\nAll lights RED, emergency mode activated.\nTransition: GREEN -> RED\nCannot transition to GREEN during emergency; must remain RED."}, {"input": "INITIAL_STATE=GREEN\nHANDLE_EVENT=emergency\nHANDLE_EVENT=deactivate_emergency\nHANDLE_EVENT=timer_expired", "description": "Deactivate emergency, then normal transition", "expected_output": "Initial state: GREEN\nAll lights RED, emergency mode activated.\nTransition: GREEN -> RED\nEmergency mode deactivated.\nTransition: RED -> GREEN"}, {"input": "INITIAL_STATE=YELLOW\nHANDLE_EVENT=unknown_event", "description": "Unknown event in YELLOW state", "expected_output": "Initial state: YELLOW\nEvent ''unknown_event'' ignored in YELLOW state."}]'::jsonb
WHERE id = 'dp_021';
-- dp_022: Tax Calculation Visitor
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // Define TaxData interface for clarity for the harness, assuming strategies expect this.
  // Users' Strategy implementations will likely cast the `unknown` data to this type.
  interface TaxData {
    item: string;
    price: number;
    region: string;
  }

  // Map of strategy class names to their constructors.
  // This harness expects the user to implement specific Strategy classes,
  // e.g., USTaxStrategy, EUTaxStrategy, CATaxStrategy.
  const strategyConstructors: Map<string, new () => Strategy> = new Map();

  // Dynamically register user-defined strategy classes if they exist in the global scope.
  // This relies on the user creating classes with these specific names.
  // The `(global as any)` cast is used to access globally defined classes in Node.js environments.
  if (typeof (global as any).USTaxStrategy !== 'undefined') {
    strategyConstructors.set("USTaxStrategy", (global as any).USTaxStrategy);
  }
  if (typeof (global as any).EUTaxStrategy !== 'undefined') {
    strategyConstructors.set("EUTaxStrategy", (global as any).EUTaxStrategy);
  }
  if (typeof (global as any).CATaxStrategy !== 'undefined') {
    strategyConstructors.set("CATaxStrategy", (global as any).CATaxStrategy);
  }
  if (typeof (global as any).FoodExemptStrategy !== 'undefined') {
    // In case user creates a specific strategy for food exemption
    strategyConstructors.set("FoodExemptStrategy", (global as any).FoodExemptStrategy);
  }
  // Register the provided ConcreteStrategy in case user uses it for a generic or default case
  if (typeof (global as any).ConcreteStrategy !== 'undefined') {
    strategyConstructors.set("ConcreteStrategy", (global as any).ConcreteStrategy);
  }

  // Instantiate the Context object once, maintaining its state across commands.
  const context = new Context();

  for (const line of lines) {
    const parts = line.split(' ');
    const command = parts[0];

    if (command === 'SET_STRATEGY') {
      const strategyName = parts[1];
      const StrategyClass = strategyConstructors.get(strategyName);

      if (StrategyClass) {
        context.setStrategy(new StrategyClass());
      } else {
        // This error will be printed if a strategy class isn't found.
        // For passing tests, this should not occur as test cases will use valid names.
        console.error(`Error: Unknown strategy class '${strategyName}' or class not found.`);
      }
    } else if (command === 'CALCULATE') {
      const dataString = parts.slice(1).join(' '); // e.g., "item=a, price=b, region=c"
      const data: TaxData = { item: '', price: 0, region: '' };

      // Parse the key-value pairs from the data string
      dataString.split(',').forEach(part => {
        const [key, value] = part.split('=').map(s => s.trim());
        if (key === 'item') {
          data.item = value;
        } else if (key === 'price') {
          data.price = parseFloat(value);
        } else if (key === 'region') {
          data.region = value;
        }
      });

      // Execute the currently set strategy with the parsed data.
      // The user's strategy will expect `data` to conform to TaxData structure.
      context.runStrategy(data);
    } else {
      console.error(`Error: Unknown command '${command}'`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "SET_STRATEGY USTaxStrategy\nCALCULATE item=electronics, price=1000, region=US", "description": "Electronics US tax", "expected_output": "Tax: $80.00 (8% electronics US)"}, {"input": "SET_STRATEGY USTaxStrategy\nCALCULATE item=food, price=50, region=US", "description": "Food tax exempt", "expected_output": "Tax: $0.00 (food exempt)"}, {"input": "SET_STRATEGY EUTaxStrategy\nCALCULATE item=clothing, price=200, region=EU", "description": "EU clothing VAT", "expected_output": "Tax: $40.00 (20% VAT EU)"}, {"input": "SET_STRATEGY CATaxStrategy\nCALCULATE item=electronics, price=500, region=CA", "description": "Canada electronics tax", "expected_output": "Tax: $65.00 (13% HST CA)"}]'::jsonb
WHERE id = 'dp_022';
