const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', () => {
  // Instantiate the user's GlyphFactory class.
  // This will throw a ReferenceError if GlyphFactory is not defined by the user.
  const glyphFactory = new GlyphFactory(); 

