        // Call the user's GlyphFactory method to get the current pool size
        const size = glyphFactory.getPoolSize();
        console.log(`Pool contains ${size} unique glyphs.`);
      } catch (e: any) {
        console.log(`Error processing POOL_SIZE command: ${e.message}`);
      }
    } else {
      console.log(`Error: Unknown command: ${line}`);
    }
  }
});$harness$,
