-- dp_024: Cross-Platform UI Bridge
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  let currentStrategy: Strategy | null = null;

  for (const line of lines) {
    const parts = line.split(' ');
    const command = parts[0];
    const arg = parts[1];

    switch (command) {
      case 'SET_RENDERER':
        const platform = arg;
        if (!platform) {
            console.log('Error: SET_RENDERER command requires a platform argument.');
            currentStrategy = null; // Ensure strategy is reset if command is malformed
            continue;
        }
        try {
            switch (platform) {
                case 'Windows':
                    // User is expected to define `class WindowsRenderer implements Strategy { ... }`
                    currentStrategy = new (globalThis as any).WindowsRenderer();
                    break;
                case 'Mac':
                    // User is expected to define `class MacRenderer implements Strategy { ... }`
                    currentStrategy = new (globalThis as any).MacRenderer();
                    break;
                case 'Linux':
                    // User is expected to define `class LinuxRenderer implements Strategy { ... }`
                    currentStrategy = new (globalThis as any).LinuxRenderer();
                    break;
                default:
                    console.log(`Error: Unknown platform renderer: ${platform}.`);
                    currentStrategy = null; // Reset current strategy for unknown platform
                    continue;
            }
            console.log(`Renderer set to ${platform}.`);
        } catch (e: any) {
            console.log(`Error instantiating renderer for ${platform}: ${e.message || e}`);
            currentStrategy = null; // Ensure strategy is null on instantiation error
        }
        break;

      case 'RENDER':
        const widgetType = arg;
        if (!widgetType) {
            console.log('Error: RENDER command requires a widget type argument.');
            continue;
        }
        if (!currentStrategy) {
          console.log('Error: Renderer not set. Use SET_RENDERER first.');
          continue;
        }
        try {
            // User is expected to implement `Context` class constructor as `constructor(strategy: Strategy, widgetType: string)`
            // and to have a method like `render(): string` that delegates to the strategy.
            const context = new (globalThis as any).Context(currentStrategy, widgetType);
            console.log(context.render());
        } catch (e: any) {
            console.log(`Error rendering widget ${widgetType}: ${e.message || e}`);
        }
        break;

      default:
        console.log(`Error: Unknown command: ${command}.`);
        break;
    }
  }
});$harness$,
  test_cases   = '[{"input": "SET_RENDERER Windows\nRENDER Button", "description": "Windows button", "expected_output": "Renderer set to Windows.\nWindows Button rendered"}, {"input": "SET_RENDERER Mac\nRENDER Button", "description": "Mac button", "expected_output": "Renderer set to Mac.\nMac Button rendered"}, {"input": "SET_RENDERER Linux\nRENDER Checkbox", "description": "Linux checkbox", "expected_output": "Renderer set to Linux.\nLinux Checkbox rendered"}, {"input": "SET_RENDERER Windows\nRENDER TextField", "description": "Windows text field", "expected_output": "Renderer set to Windows.\nWindows TextField rendered"}, {"input": "SET_RENDERER Mac\nRENDER Button\nRENDER TextField\nRENDER Checkbox", "description": "Multiple widgets on same platform", "expected_output": "Renderer set to Mac.\nMac Button rendered\nMac TextField rendered\nMac Checkbox rendered"}, {"input": "SET_RENDERER Windows\nRENDER Button\nSET_RENDERER Linux\nRENDER Checkbox\nSET_RENDERER Mac\nRENDER TextField", "description": "Switching platforms", "expected_output": "Renderer set to Windows.\nWindows Button rendered\nRenderer set to Linux.\nLinux Checkbox rendered\nRenderer set to Mac.\nMac TextField rendered"}, {"input": "RENDER Button\nSET_RENDERER Windows\nRENDER Button", "description": "Render before setting platform", "expected_output": "Error: Renderer not set. Use SET_RENDERER first.\nRenderer set to Windows.\nWindows Button rendered"}, {"input": "SET_RENDERER InvalidPlatform\nRENDER Button", "description": "Invalid platform setting", "expected_output": "Error: Unknown platform renderer: InvalidPlatform.\nError: Renderer not set. Use SET_RENDERER first."}, {"input": "SET_RENDERER Windows\nRENDER", "description": "Render command missing widget type", "expected_output": "Renderer set to Windows.\nError: RENDER command requires a widget type argument."}, {"input": "SET_RENDERER\nRENDER Button", "description": "Set renderer command missing platform", "expected_output": "Error: SET_RENDERER command requires a platform argument.\nError: Renderer not set. Use SET_RENDERER first."}]'::jsonb
