-- dp_025: Animal Kingdom Abstract Factory
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', () => {
  const factories: Map<string, any> = new Map(); // Stores instances of AnimalFactory implementations

  for (const line of lines) {
    if (line === '') continue; // Skip empty lines

    const parts = line.split(' ');
    const command = parts[0];

    try {
      switch (command) {
        case 'CREATE_FACTORY': {
          const factoryName = parts[1];
          let factoryInstance: any;

          // User is expected to have defined these factory classes globally or as part of the module.
          // Using (global as any) to access classes defined in the user's code scope.
          if (factoryName === 'Africa') {
            factoryInstance = new (global as any).AfricaFactory();
          } else if (factoryName === 'Arctic') {
            factoryInstance = new (global as any).ArcticFactory();
          } else if (factoryName === 'Ocean') {
            factoryInstance = new (global as any).OceanFactory();
          } else {
            console.log(`Error: Unknown factory type '${factoryName}'`);
            continue;
          }
          factories.set(factoryName, factoryInstance);
          console.log(`Factory '${factoryName}' created.`);
          break;
        }

        case 'GET_ANIMAL': {
          const factoryName = parts[1];
          // The animalProductType here refers to the abstract product type (e.g., "herbivore", "carnivore")
          // and maps to the corresponding creation method on the factory (e.g., createHerbivore(), createCarnivore()).
          const animalProductType = parts[2]; 

          const factory = factories.get(factoryName);
          if (!factory) {
            console.log(`Error: Factory '${factoryName}' not found. Create it first.`);
            continue;
          }

          let animal: any;
          if (animalProductType === 'herbivore') {
            // Assumes the user's factory has a createHerbivore method.
            animal = factory.createHerbivore();
          } else if (animalProductType === 'carnivore' || animalProductType === 'predator') {
            // Assumes the user's factory has a createCarnivore method which returns the appropriate product.
            // For example, OceanFactory.createCarnivore() should return a Shark instance.
            animal = factory.createCarnivore();
          } else {
            console.log(`Error: Unknown animal product type '${animalProductType}'`);
            continue;
          }

          // Assumes the animal product object (e.g., Elephant, Lion, Shark) has a getDescription() method
          // that returns the formatted string like "Elephant (African herbivore)".
          if (animal && typeof animal.getDescription === 'function') {
            console.log(`Created: ${animal.getDescription()}`);
          } else if (animal) {
            console.log(`Error: Animal product missing getDescription() method or returned unexpected type.`);
            console.log(`Created (raw): ${JSON.stringify(animal)}`); // Fallback for debugging
          } else {
            console.log(`Error: Failed to create animal of type '${animalProductType}' from factory '${factoryName}'.`);
          }
          break;
        }

        default: {
          console.log(`Error: Unknown command '${command}'`);
        }
      }
    } catch (e: any) {
      // Catch and log any runtime errors from user code or harness logic.
      console.log(`Runtime Error processing command '${line}': ${e.message || e}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "CREATE_FACTORY Africa\nGET_ANIMAL Africa herbivore", "description": "African herbivore", "expected_output": "Factory ''Africa'' created.\nCreated: Elephant (African herbivore)"}, {"input": "CREATE_FACTORY Africa\nGET_ANIMAL Africa carnivore", "description": "African carnivore", "expected_output": "Factory ''Africa'' created.\nCreated: Lion (African carnivore)"}, {"input": "CREATE_FACTORY Arctic\nGET_ANIMAL Arctic carnivore", "description": "Arctic carnivore", "expected_output": "Factory ''Arctic'' created.\nCreated: Polar Bear (Arctic carnivore)"}, {"input": "CREATE_FACTORY Ocean\nGET_ANIMAL Ocean predator", "description": "Ocean predator", "expected_output": "Factory ''Ocean'' created.\nCreated: Shark (Ocean predator)"}]'::jsonb
WHERE id = 'dp_025';
-- dp_026: Document Clone Prototype
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

// Assumed user-implemented classes based on challenge description and starter code:
// 1. interface Strategy { execute(data: unknown): void; }
//    (The user is expected to implement concrete strategies that interact with Context and print output.)
// 2. class Context { /* user implements: holds strategy, original/clone documents, provides getters/setters */ }
//    - Expected Context methods: constructor(), setStrategy(strategy: Strategy), executeStrategy(data: unknown)
//    - Expected Context state: private original: Document | null, private clone: Document | null
//    - Expected Context state interaction methods for strategies: getOriginal(), setOriginal(doc), getClone(), setClone(doc)
// 3. class Document { /* user implements: properties, clone() for deep copy, equals() for deep comparison */ }
//    - Expected Document properties: public title: string, public author: string, public sections: { name: string; content: string }[]
//    - Expected Document methods: clone(): Document (performs deep copy), equals(other: Document): boolean (performs deep comparison)
// 4. Concrete Strategy implementations (e.g., ConcreteCloneDocumentStrategy, ConcreteModifyCloneStrategy, ConcreteCompareDocumentsStrategy)
//    - These strategies are expected to be instantiated with a reference to the Context in their constructor.
//    - They perform operations on the Context's documents and print results using console.log().
//    - For the 'clone' command, ConcreteCloneDocumentStrategy should instantiate 'Document' based on the name (e.g., 'contract_template' or 'invoice_template')
//      and set it as the original, then clone it and set as the clone in the Context.
//    - For 'modify clone', ConcreteModifyCloneStrategy should modify the clone's properties (e.g., 'title', 'author', 'section.0.content')
//      and ensure the original is unchanged.
//    - For 'compare original clone', ConcreteCompareDocumentsStrategy should compare the original and clone documents for deep equality and referential inequality.

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {
  // Helper to parse key-value pairs from a string (e.g., 'field=title, value=New Contract')
  const parseParams = (paramString: string): Record<string, string> => {
    const params: Record<string, string> = {};
    paramString.split(',').forEach(part => {
      const [key, value] = part.split('=').map(s => s.trim());
      if (key && value) {
        params[key] = value;
      }
    });
    return params;
  };

  // Instantiate Context (user's implementation). 
  // Expected to be instantiable without arguments and manage document state.
  const appCtx = new Context();

  // Instantiate concrete strategy implementations, passing the Context instance to them.
  // This allows strategies to interact with the Context's document state.
  // Assumes user creates these specific named classes extending/implementing Strategy.
  const cloneStrategy = new ConcreteCloneDocumentStrategy(appCtx);
  const modifyStrategy = new ConcreteModifyCloneStrategy(appCtx);
  const compareStrategy = new ConcreteCompareDocumentsStrategy(appCtx);

  for (const line of lines) {
    if (line.length === 0) continue;

    const parts = line.split(' ');
    const command = parts[0];
    const args = parts.slice(1).join(' '); // Remaining part as argument string

    try {
      if (command === "clone") {
        const params = parseParams(args);
        const documentName = params['document'];
        if (documentName) {
          appCtx.setStrategy(cloneStrategy);
          // Pass document name as data to the strategy
          appCtx.executeStrategy(documentName);
        } else {
          console.log("Error: 'clone' command missing 'document' parameter.");
        }
      } else if (command === "modify") {
        const params = parseParams(args);
        const target = parts[1]; // Expected to be 'clone'
        const field = params['field'];
        const value = params['value'];

        if (target === 'clone' && field && value) {
          appCtx.setStrategy(modifyStrategy);
          // Pass an object with field and value for modification
          appCtx.executeStrategy({ field, value });
        } else {
          console.log("Error: 'modify clone' command missing 'field' or 'value' parameters, or wrong target.");
        }
      } else if (command === "compare") {
        const target1 = parts[1]; // Expected to be 'original'
        const target2 = parts[2]; // Expected to be 'clone'
        if (target1 === 'original' && target2 === 'clone') {
          appCtx.setStrategy(compareStrategy);
          // No specific data needed for compare command
          appCtx.executeStrategy(null);
        } else {
          console.log("Error: 'compare' command requires 'original clone'.");
        }
      } else {
        console.log(`Unknown command: ${command}`);
      }
    } catch (e: any) {
      // Catch and log any runtime errors from user code or harness logic
      console.log(`Runtime Error: ${e.message}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "clone document=contract_template\nmodify clone field=title, value=New Contract Title\ncompare original clone", "description": "Clone a document and modify its title, ensuring the original is unaffected, and verify the clone has a different reference.", "expected_output": "Deep clone of contract_template created\nClone title updated to New Contract Title, original unchanged\nClone matches original structure, different reference"}, {"input": "clone document=invoice_template\nmodify clone field=section.0.content, value=Updated Invoice Details\ncompare original clone", "description": "Clone a document and modify a nested property (section content), ensuring the original''s nested property is unaffected, and verify the deep copy.", "expected_output": "Deep clone of invoice_template created\nClone section.0.content updated to Updated Invoice Details, original unchanged\nClone matches original structure, different reference"}, {"input": "modify clone field=title, value=Error Case", "description": "Attempt to modify a clone before any document has been cloned.", "expected_output": "No document cloned yet to modify."}, {"input": "unknown_command param=value", "description": "Attempt an unknown command.", "expected_output": "Unknown command: unknown_command"}]'::jsonb
