-- dp_027: Shipping Cost Strategy Selector
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // Instantiate the Context, which will hold the current strategy.
  // This assumes the user has properly implemented the 'Context' class.
  const context = new Context();

  // A mapping from strategy names used in commands to their expected class constructors.
  // This relies on user-defined strategy classes (e.g., StandardShippingStrategy) 
  // being available in the global scope after concatenation.
  // The starter code includes 'ConcreteStrategy', but for a Strategy pattern implementation,
  // users are expected to create multiple named concrete strategies.
  const strategyMap: { [key: string]: new () => Strategy } = {
    'standard': (globalThis as any).StandardShippingStrategy,
    'express': (globalThis as any).ExpressShippingStrategy,
    'economy': (globalThis as any).EconomyShippingStrategy,
    'overnight': (globalThis as any).OvernightShippingStrategy,
  };

  for (const line of lines) {
    if (line.startsWith('SELECT_STRATEGY:')) {
      // Command to select and set a new shipping strategy.
      const strategyName = line.substring('SELECT_STRATEGY:'.length);
      const StrategyClass = strategyMap[strategyName];

      if (!StrategyClass) {
        console.log(`Error: Unknown strategy '${strategyName}' or its class not found.`);
        continue;
      }

      try {
        const strategyInstance = new StrategyClass();
        context.setStrategy(strategyInstance);
      } catch (e: any) {
        console.log(`Error creating instance for strategy '${strategyName}': ${e.message}`);
      }

    } else if (line.startsWith('CALCULATE:')) {
      // Command to calculate shipping cost using the currently selected strategy.
      const parts = line.substring('CALCULATE:'.length).split(',');
      if (parts.length !== 2) {
        console.log(`Error: Invalid CALCULATE command format: ${line}. Expected 'CALCULATE:weight_kg,destination'.`);
        continue;
      }

      const weightKg = parseFloat(parts[0]);
      const destination = parts[1];

      if (isNaN(weightKg)) {
        console.log(`Error: Invalid weight value '${parts[0]}' in CALCULATE command.`);
        continue;
      }
      
      // The Context's calculateShippingCost method is expected to delegate to the current strategy
      // and print the shipping cost to stdout in the specified format.
      try {
        context.calculateShippingCost(weightKg, destination);
      } catch (e: any) {
        console.log(`Error during shipping calculation: ${e.message}`);
      }

    } else {
      console.log(`Error: Unrecognized command '${line}'.`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "SELECT_STRATEGY:standard\nCALCULATE:5,local", "description": "Standard local shipping", "expected_output": "Shipping cost: $5.00 (standard local)"}, {"input": "SELECT_STRATEGY:express\nCALCULATE:5,international", "description": "Express international shipping", "expected_output": "Shipping cost: $45.00 (express international)"}, {"input": "SELECT_STRATEGY:economy\nCALCULATE:20,local", "description": "Economy local shipping", "expected_output": "Shipping cost: $12.00 (economy local)"}, {"input": "SELECT_STRATEGY:overnight\nCALCULATE:2,local", "description": "Overnight shipping", "expected_output": "Shipping cost: $25.00 (overnight)"}]'::jsonb
WHERE id = 'dp_027';
-- dp_028: Stock Price Observer Ticker
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', () => {
  // This harness assumes the user will adapt the provided `interface Strategy`, `class Context`,
  // and `class ConcreteStrategy` to implement the Observer pattern for stock price updates.
  //
  // Expected roles:
  // - `Context`: Acts as the Subject (the Stock Ticker) that manages observers.
  //   It should expose methods like `addStrategy`, `removeStrategy`, and `updateStockPrice`.
  // - `Strategy`: Acts as the Observer interface.
  //   It should require a `getName(): string` method (for observer identification) and the `execute(stock: string, price: number): void` method (for receiving updates).
  // - `ConcreteStrategy`: Acts as a concrete Observer (e.g., a Dashboard Observer).
  //   Its constructor is expected to accept a name (e.g., `new ConcreteStrategy('dashboard')`).

  // Holds instances of ConcreteStrategy (observers) by their logical name (e.g., 'dashboard', 'anotherdash')
  const activeStrategies = new Map<string, any>(); 

  // Factory function to get or create a ConcreteStrategy instance.
  // This assumes `ConcreteStrategy` is a globally available class and its constructor
  // accepts a single string argument for the observer's name.
  function getOrCreateStrategy(name: string): any {
    if (!activeStrategies.has(name)) {
      if (typeof (global as any).ConcreteStrategy === 'function') {
        const strategyInstance = new (global as any).ConcreteStrategy(name);
        activeStrategies.set(name, strategyInstance);
      } else {
        console.error(`Runtime Error: ConcreteStrategy class not found or not a constructor. Ensure 'ConcreteStrategy' is correctly defined with a constructor that accepts a name string.`);
        return null; // Critical error: cannot proceed without this class
      }
    }
    return activeStrategies.get(name);
  }

  // Instantiate the main Context (Subject/StockTicker).
  // This assumes `Context` is a globally available class.
  let context: any;
  if (typeof (global as any).Context === 'function') {
    context = new (global as any).Context();
  } else {
    console.error('Runtime Error: Context class not found or not a constructor. Ensure 'Context' is correctly defined.');
    return; // Critical error: cannot proceed without this class
  }

  // Helper to parse key-value arguments from command strings
  const parseArgs = (argString: string): { [key: string]: string } => {
    const result: { [key: string]: string } = {};
    argString.split(',').forEach(arg => {
      const [key, value] = arg.trim().split('=');
      if (key && value) {
        result[key.trim()] = value.trim();
      }
    });
    return result;
  };

  // Process each command line read from stdin
  for (const line of lines) {
    const parts = line.split(' ');
    const command = parts[0];
    const args = parts.slice(1).join(' '); // Rejoin to handle potential spaces in argument values

    const parsedArgs = parseArgs(args);

    switch (command) {
      case 'subscribe': {
        const observerName = parsedArgs['observer'];
        const stockSymbol = parsedArgs['stock'];
        if (observerName && stockSymbol) {
          const strategy = getOrCreateStrategy(observerName);
          if (strategy) {
            // Expect `Context` to have an `addStrategy` method (acting as subscribe)
            if (typeof context.addStrategy === 'function') {
              context.addStrategy(strategy, stockSymbol);
            } else {
              console.error(`Runtime Error: Context.addStrategy method not found. Implement 'addStrategy(observer: Strategy, stock: string)' on your Context class to handle subscriptions.`);
            }
          }
        } else {
          console.error(`Invalid subscribe command format: '${line}'. Expected 'subscribe observer=<name>, stock=<symbol>'`);
        }
        break;
      }
      case 'update': {
        const stockSymbol = parsedArgs['stock'];
        const priceStr = parsedArgs['price'];
        if (stockSymbol && priceStr) {
          const price = parseFloat(priceStr);
          if (!isNaN(price)) {
            // Expect `Context` to have an `updateStockPrice` method (acting as notify)
            if (typeof context.updateStockPrice === 'function') {
              context.updateStockPrice(stockSymbol, price);
            } else {
              console.error(`Runtime Error: Context.updateStockPrice method not found. Implement 'updateStockPrice(stock: string, price: number)' on your Context class to trigger notifications.`);
            }
          } else {
            console.error(`Invalid price value in update command: '${line}'. Price must be a number.`);
          }
        } else {
          console.error(`Invalid update command format: '${line}'. Expected 'update stock=<symbol>, price=<value>'`);
        }
        break;
      }
      case 'unsubscribe': {
        const observerName = parsedArgs['observer'];
        const stockSymbol = parsedArgs['stock'];
        if (observerName && stockSymbol) {
          // Expect `Context` to have a `removeStrategy` method (acting as unsubscribe)
          if (typeof context.removeStrategy === 'function') {
            context.removeStrategy(observerName, stockSymbol);
          } else {
            console.error(`Runtime Error: Context.removeStrategy method not found. Implement 'removeStrategy(observerName: string, stock: string)' on your Context class to handle unsubscriptions.`);
          }
        } else {
          console.error(`Invalid unsubscribe command format: '${line}'. Expected 'unsubscribe observer=<name>, stock=<symbol>'`);
        }
        break;
      }
      default: {
        console.error(`Unknown command: '${command}'.`);
        break;
      }
    }
  }
});$harness$,
  test_cases   = '[{"input": "subscribe observer=dashboard, stock=AAPL", "description": "Subscribe to a stock", "expected_output": "dashboard subscribed to AAPL"}, {"input": "subscribe observer=dashboard, stock=AAPL\nupdate stock=AAPL, price=152.50", "description": "Price update notification for a subscribed observer", "expected_output": "dashboard subscribed to AAPL\ndashboard notified: AAPL = $152.50"}, {"input": "subscribe observer=dashboard, stock=AAPL\nunsubscribe observer=dashboard, stock=AAPL", "description": "Unsubscribe from a stock", "expected_output": "dashboard subscribed to AAPL\ndashboard unsubscribed from AAPL"}, {"input": "subscribe observer=dashboard, stock=AAPL\nunsubscribe observer=dashboard, stock=AAPL\nupdate stock=AAPL, price=153.00", "description": "No notification after unsubscribe", "expected_output": "dashboard subscribed to AAPL\ndashboard unsubscribed from AAPL\nNo observers notified for AAPL"}, {"input": "update stock=GOOG, price=2000.00", "description": "Update a stock with no active observers", "expected_output": "No observers notified for GOOG"}, {"input": "subscribe observer=dashboard, stock=AAPL\nunsubscribe observer=dashboard, stock=GOOG", "description": "Attempt to unsubscribe a non-existent subscription", "expected_output": "dashboard subscribed to AAPL\ndashboard was not subscribed to GOOG"}, {"input": "subscribe observer=dashboard, stock=IBM\nsubscribe observer=anotherdash, stock=IBM\nupdate stock=IBM, price=140.00", "description": "Multiple observers for the same stock receive updates", "expected_output": "dashboard subscribed to IBM\nanotherdash subscribed to IBM\ndashboard notified: IBM = $140.00\nanotherdash notified: IBM = $140.00"}, {"input": "subscribe observer=dashboard, stock=MSFT\nupdate stock=MSFT, price=300.00\nunsubscribe observer=dashboard, stock=MSFT\nsubscribe observer=dashboard, stock=MSFT\nupdate stock=MSFT, price=301.50", "description": "Subscribe, unsubscribe, then re-subscribe and update", "expected_output": "dashboard subscribed to MSFT\ndashboard notified: MSFT = $300.00\ndashboard unsubscribed from MSFT\ndashboard subscribed to MSFT\ndashboard notified: MSFT = $301.50"}]'::jsonb
WHERE id = 'dp_028';
-- dp_029: Cloud Storage Provider Factory
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // Assumes the user has implemented the following:
  // 1. A refined 'interface Strategy' with `execute(action: string, data?: string): string;`
  //    (The starter `execute(data: unknown): void;` is too generic for this problem
  //    and is expected to be adapted by the user to specific actions and return values).
  // 2. The 'class Context' with `setStrategy(strategy: Strategy): void;` and
  //    `performAction(action: string, data?: string): string;` methods.
  // 3. Concrete strategy classes like `AwsS3Strategy`, `GcpStorageStrategy`, `AzureBlobStrategy`
  //    that implement the refined `Strategy` interface and manage their internal state (e.g., list of files).

  // Initialize strategy instances. These are stateful and need to persist across commands.
  // The harness acts as a simple factory for these concrete strategy instances.
  let awsS3Strategy: Strategy; // User must define AwsS3Strategy
  let gcpStorageStrategy: Strategy; // User must define GcpStorageStrategy
  let azureBlobStrategy: Strategy; // User must define AzureBlobStrategy

  try {
    awsS3Strategy = new AwsS3Strategy();
    gcpStorageStrategy = new GcpStorageStrategy();
    azureBlobStrategy = new AzureBlobStrategy();
  } catch (e) {
    console.error(`Error initializing strategies: ${e.message}. Make sure AwsS3Strategy, GcpStorageStrategy, and AzureBlobStrategy classes are defined.`);
    return;
  }

  const providerStrategies: { [key: string]: Strategy } = {
    'aws': awsS3Strategy,
    'gcp': gcpStorageStrategy,
    'azure': azureBlobStrategy,
  };

  // Initialize the Context. User must define Context class.
  let context: Context;
  try {
    context = new Context();
  } catch (e) {
    console.error(`Error initializing Context: ${e.message}. Make sure the Context class is defined.`);
    return;
  }

  // Process each command line
  for (const line of lines) {
    if (!line) continue;

    let provider: string | undefined;
    let action: string | undefined;
    let fileData: string | undefined; // Used for 'upload' action

    const parts = line.split(',').map(p => p.trim());
    for (const part of parts) {
      if (part.startsWith('provider=')) {
        provider = part.substring('provider='.length).toLowerCase();
      } else if (part.startsWith('file=')) {
        action = 'upload';
        fileData = part.substring('file='.length);
      } else if (part === 'list_files') {
        action = 'list_files';
      }
      // Add more actions here if needed for future tests
    }

    if (!provider) {
      console.log("Error: No storage provider specified.");
      continue;
    }

    const currentStrategy = providerStrategies[provider];
    if (!currentStrategy) {
      console.log(`Error: Unknown storage provider: ${provider}`);
      continue;
    }

    if (!action) {
      console.log(`Error: No action specified for provider ${provider}.`);
      continue;
    }

    // Set the chosen strategy on the context
    context.setStrategy(currentStrategy);

    // Perform the action via the context, which delegates to the strategy
    const result = context.performAction(action, fileData);
    console.log(result);
  }
});$harness$,
  test_cases   = '[{"input": "provider=AWS, file=data.csv", "description": "Upload a single file to AWS", "expected_output": "data.csv uploaded to AWS S3"}, {"input": "provider=GCP, file=image.png", "description": "Upload a single file to GCP", "expected_output": "image.png uploaded to GCP Storage"}, {"input": "provider=Azure, file=report.pdf", "description": "Upload a single file to Azure", "expected_output": "report.pdf uploaded to Azure Blob"}, {"input": "provider=AWS, file=doc1.txt\nprovider=AWS, file=doc2.pdf\nprovider=AWS, list_files", "description": "Upload multiple files to AWS and then list them", "expected_output": "doc1.txt uploaded to AWS S3\ndoc2.pdf uploaded to AWS S3\nFiles in AWS S3: [doc1.txt, doc2.pdf]"}, {"input": "provider=GCP, file=vid.mp4\nprovider=GCP, list_files", "description": "Upload a file to GCP and then list it", "expected_output": "vid.mp4 uploaded to GCP Storage\nFiles in GCP Storage: [vid.mp4]"}, {"input": "provider=Azure, file=log.zip\nprovider=Azure, file=archive.tar\nprovider=Azure, list_files", "description": "Upload multiple files to Azure and then list them", "expected_output": "log.zip uploaded to Azure Blob\narchive.tar uploaded to Azure Blob\nFiles in Azure Blob: [log.zip, archive.tar]"}, {"input": "provider=AWS, file=server_logs.log\nprovider=GCP, file=user_profiles.json\nprovider=AWS, list_files\nprovider=GCP, list_files\nprovider=Azure, list_files", "description": "Verify independent state between different storage providers (AWS, GCP, Azure)", "expected_output": "server_logs.log uploaded to AWS S3\nuser_profiles.json uploaded to GCP Storage\nFiles in AWS S3: [server_logs.log]\nFiles in GCP Storage: [user_profiles.json]\nFiles in Azure Blob: []"}, {"input": "provider=Invalid, file=test.txt", "description": "Handle an unknown storage provider gracefully", "expected_output": "Error: Unknown storage provider: invalid"}, {"input": "provider=AWS, unknown_command", "description": "Handle an unknown command for a specific provider", "expected_output": "Unknown command for AWS: unknown_command"}, {"input": "file=data.csv", "description": "Handle command with no provider specified", "expected_output": "Error: No storage provider specified."}]'::jsonb
WHERE id = 'dp_029';
-- dp_030: SQL Query Builder Fluent
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {

    // Helper function to preprocess input line arguments
    // It identifies arguments within parentheses and wraps non-numeric/non-boolean/non-quoted arguments in double quotes.
    // Handles single arguments like 'users ON orders.user_id = users.id' and multiple like 'name, email'.
    function preprocessInputLine(line: string): string {
        return line.replace(/\(([^)]*)\)/g, (matchInner, argsString) => {
            if (!argsString.trim()) {
                return '()'; // Empty parentheses, keep as is
            }

            let processedArgs: string[];

            // Heuristic: If argsString contains a comma, assume multiple arguments (e.g., 'name, email').
            // Otherwise, assume a single argument (e.g., 'users', 'age > 18', '10').
            if (argsString.includes(',')) {
                // Split by comma for multiple arguments
                processedArgs = argsString.split(',').map(arg => {
                    arg = arg.trim();
                    if (arg === '') return ''; // Should not happen with well-formed input
                    // Keep numbers, booleans, null, or already quoted strings as is
                    if (/^-?\d+(\.\d+)?$|^true$|^false$|^\".*\"$|^'.*'$|null/i.test(arg)) {
                        return arg;
                    }
                    return `"${arg}"`; // Quote other identifiers
                });
            } else {
                // Single argument
                const arg = argsString.trim();
                if (arg === '') {
                    processedArgs = ['']; // Empty argument (covered by !argsString.trim() above but for safety)
                } else if (/^-?\d+(\.\d+)?$|^true$|^false$|^\".*\"$|^'.*'$|null/i.test(arg)) {
                    processedArgs = [arg]; // Keep numbers, booleans, null, or already quoted strings as is
                } else {
                    processedArgs = [`"${arg}"`]; // Quote everything else (e.g., 'users', 'age > 18')
                }
            }
            return `(${processedArgs.join(', ')})`;
        });
    }

    let builder: Context | null = null; // The user's Context class is expected to be the SQL builder

    for (const line of lines) {
        if (line.trim() === '') {
            continue;
        }

        if (!builder) {
            // Instantiate the builder for the first command of a test case.
            // This creates a fresh builder for each test's stdin input.
            builder = new Context();
        }

        // Preprocess arguments in the current line for safe evaluation
        const preprocessedLine = preprocessInputLine(line);
        // Construct the full JavaScript expression to evaluate
        // We prepend 'builder.' because the input lines are method calls like 'SELECT()', not 'new Context().SELECT()'
        // User's fluent methods are expected to return 'this' (the builder instance).
        const fullEvalString = `builder.${preprocessedLine}`;

        let output: unknown; // Use unknown to capture any return type before toString()
        try {
            // Execute the fluent method chain. The result of `eval` should be the builder instance itself.
            const chainResult = eval(fullEvalString);
            // After each command, print the current state of the query by calling builder.toString().
            // This assumes the Context class has a toString method that renders the current query.
            if (builder && typeof builder.toString === 'function') {
                output = builder.toString();
            } else if (typeof chainResult === 'string' || typeof chainResult === 'number' || typeof chainResult === 'boolean') {
                // Fallback if toString is not available or if a method directly returned a primitive
                output = chainResult;
            } else {
                output = `[object Object]`; // Generic output for unstringifiable objects
            }
        } catch (e: any) {
            output = `Error: ${e.message}`;
        }
        console.log(output);
    }
});$harness$,
  test_cases   = '[{"input": "SELECT()\nFROM(users)\nWHERE(age > 18)", "description": "Basic SELECT with WHERE", "expected_output": "SELECT *\nSELECT * FROM users\nSELECT * FROM users WHERE age > 18"}, {"input": "SELECT(name, email)\nFROM(users)\nLIMIT(10)", "description": "SELECT specific columns", "expected_output": "SELECT name, email\nSELECT name, email FROM users\nSELECT name, email FROM users LIMIT 10"}, {"input": "SELECT()\nFROM(orders)\nJOIN(users ON orders.user_id = users.id)", "description": "SELECT with JOIN", "expected_output": "SELECT *\nSELECT * FROM orders\nSELECT * FROM orders JOIN users ON orders.user_id = users.id"}, {"input": "SELECT()\nFROM(products)\nORDER_BY(price DESC)", "description": "SELECT with ORDER BY", "expected_output": "SELECT *\nSELECT * FROM products\nSELECT * FROM products ORDER BY price DESC"}, {"input": "SELECT(id, title)\nFROM(books)\nWHERE(author = ''Jane Doe'' AND published_year > 2000)\nORDER_BY(published_year ASC)\nLIMIT(5)", "description": "Complex query with multiple clauses", "expected_output": "SELECT id, title\nSELECT id, title FROM books\nSELECT id, title FROM books WHERE author = ''Jane Doe'' AND published_year > 2000\nSELECT id, title FROM books WHERE author = ''Jane Doe'' AND published_year > 2000 ORDER BY published_year ASC\nSELECT id, title FROM books WHERE author = ''Jane Doe'' AND published_year > 2000 ORDER BY published_year ASC LIMIT 5"}, {"input": "SELECT(category, COUNT(*))\nFROM(items)\nGROUP_BY(category)", "description": "SELECT with GROUP BY", "expected_output": "SELECT category, COUNT(*)\nSELECT category, COUNT(*) FROM items\nSELECT category, COUNT(*) FROM items GROUP BY category"}]'::jsonb
