-- dp_031: HTTP Request Decorator Chain
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // This harness assumes the user has implemented the following structure for an HTTP Request Decorator Chain:
  // - An interface for the base component, e.g., `interface RequestHandler { handle(request: HttpRequestData): string; }`
  // - A concrete component class, e.g., `class BasicHttpRequest implements RequestHandler { /* ... */ }`
  // - An abstract base decorator class, e.g., `abstract class RequestDecorator implements RequestHandler { protected wrappedHandler: RequestHandler; constructor(handler: RequestHandler) { ... } abstract handle(request: HttpRequestData): string; }`
  // - Concrete decorator classes that extend `RequestDecorator`, e.g., `AuthDecorator`, `LogDecorator`, `CacheDecorator`, `ValidateDecorator`.
  // - `AuthDecorator` must have a static method `setAuthSuccess(success: boolean): void`.
  // - `CacheDecorator` must have static methods `setCacheState(url: string, data: string | null): void` and `clearCache(): void`.
  // - An interface for request data, e.g., `interface HttpRequestData { method: string; url: string; /* optional: body?: unknown; */ }`
  // The starter code's `Strategy` and `Context` are considered generic placeholders not specific to this challenge's pattern.

  // Using 'any' for type safety bypass due to dynamic nature and user-defined types
  // that are not known at harness compile time but are available at runtime after concatenation.

  const getDecoratorInstance = (name: string, wrappedHandler: any): any => {
    switch (name.toLowerCase()) {
      case 'auth':
        // @ts-ignore - AuthDecorator assumed to be user-defined and compatible
        return new AuthDecorator(wrappedHandler);
      case 'log':
        // @ts-ignore - LogDecorator assumed to be user-defined and compatible
        return new LogDecorator(wrappedHandler);
      case 'cache':
        // @ts-ignore - CacheDecorator assumed to be user-defined and compatible
        return new CacheDecorator(wrappedHandler);
      case 'validate':
        // @ts-ignore - ValidateDecorator assumed to be user-defined and compatible
        return new ValidateDecorator(wrappedHandler);
      default:
        throw new Error(`Unknown decorator: ${name}`);
    }
  };

  for (const line of lines) {
    const parts = line.split(' ');
    const command = parts[0].toUpperCase();

    switch (command) {
      case 'SET_AUTH_SUCCESS':
        const success = parts[1] === 'true';
        // @ts-ignore - AuthDecorator assumed to be user-defined
        AuthDecorator.setAuthSuccess(success);
        console.log(`Auth success set to ${success}`);
        break;

      case 'SET_CACHE':
        const url = parts[1];
        let cacheDataString = parts.slice(2).join(' ');

        // If data is empty or 'null', interpret as clearing specific entry
        if (cacheDataString.toLowerCase() === 'null' || cacheDataString === '') {
          cacheDataString = ''; // Signal to clear or leave empty
        }
        
        // Remove surrounding quotes if present
        if (cacheDataString.startsWith('"') && cacheDataString.endsWith('"')) {
          cacheDataString = cacheDataString.substring(1, cacheDataString.length - 1);
        }

        // Pass null to clear an entry, otherwise pass the string data
        // @ts-ignore - CacheDecorator assumed to be user-defined
        CacheDecorator.setCacheState(url, cacheDataString === '' ? null : cacheDataString);
        console.log(`Cache for ${url} set to "${cacheDataString}"`);
        break;

      case 'CLEAR_CACHE':
        // @ts-ignore - CacheDecorator assumed to be user-defined
        CacheDecorator.clearCache();
        console.log('Cache cleared');
        break;

      case 'REQUEST':
        const method = parts[1];
        const requestUrl = parts[2];
        const decoratorsStartIndex = parts.indexOf('DECORATORS');
        const decoratorNames = decoratorsStartIndex !== -1 ? parts.slice(decoratorsStartIndex + 1) : [];

        // The HttpRequestData type is assumed to be defined by the user
        // We'll construct a plain object matching the expected shape
        const requestData: any = { method, url: requestUrl };

        // @ts-ignore - BasicHttpRequest assumed to be user-defined and compatible with RequestHandler
        let handler: any = new BasicHttpRequest();

        // Apply decorators in reverse order of how they are listed in the command line
        // This ensures the chain is built correctly (e.g., for `auth log cache`, `auth` is outermost).
        for (let i = decoratorNames.length - 1; i >= 0; i--) {
          handler = getDecoratorInstance(decoratorNames[i], handler);
        }

        const result = handler.handle(requestData);
        console.log(result);
        break;

      default:
        console.error(`Unknown command: ${command}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "SET_AUTH_SUCCESS true\nSET_CACHE /api/data \"Response returned\"\nREQUEST GET /api/data DECORATORS auth log cache", "description": "Decorated GET request (cache hit)", "expected_output": "Auth success set to true\nCache for /api/data set to \"Response returned\"\nAuth checked -> Logged -> Cache hit -> Response returned"}, {"input": "SET_AUTH_SUCCESS true\nREQUEST POST /api/data DECORATORS auth log validate", "description": "Decorated POST request", "expected_output": "Auth success set to true\nAuth checked -> Logged -> Validated -> Data saved"}, {"input": "SET_AUTH_SUCCESS true\nCLEAR_CACHE\nREQUEST GET /api/data DECORATORS auth log cache", "description": "Cache miss path", "expected_output": "Auth success set to true\nCache cleared\nAuth checked -> Logged -> Cache miss -> Fetched from DB"}, {"input": "SET_AUTH_SUCCESS false\nREQUEST DELETE /api/data DECORATORS auth", "description": "Auth failure", "expected_output": "Auth success set to false\nAuth failed -> 401 Unauthorized"}]'::jsonb
WHERE id = 'dp_031';
-- dp_032: Virtual DOM Proxy Cache
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', async () => {
  // Simulate an "origin" data source (e.g., a real API or Virtual DOM elements)
  const _originData = new Map<string, any>();
  _originData.set('/api/users', { id: 1, name: 'Alice', email: 'alice@example.com' });
  _originData.set('/api/products/1', { id: 1, name: 'Laptop', price: 1200 });
  _originData.set('/api/posts/101', { id: 101, title: 'My First Post', author: 'Bob' });

  // This function simulates fetching data from the origin (e.g., network request, DOM access)
  // It's asynchronous to mimic real-world fetching delays.
  const harnessOriginFetcher = async (key: string): Promise<any> => {
    // Simulate a brief network/DOM access delay
    await new Promise(resolve => setTimeout(resolve, 50));
    if (_originData.has(key)) {
      // Return a deep copy to prevent direct modification of origin data through cached references
      return JSON.parse(JSON.stringify(_originData.get(key)));
    }
    throw new Error(`Resource not found at ${key}`);
  };

  // Instantiate the user's ConcreteStrategy and Context classes.
  // We assume:
  // 1. The ConcreteStrategy implements the `Strategy` interface and manages the actual cache state.
  // 2. The Context constructor accepts an instance of `Strategy` and an `originFetcher` function.
  // 3. The Context provides `fetch(key)` and `invalidate(key)` methods.
  // 4. The `Strategy.execute(data: unknown)` method in `ConcreteStrategy` is designed to interpret
  //    `data` as an object `{ command: string, key: string, originFetcher?: Function }`
  //    and performs side effects (like updating its internal cache and printing to console).
  const concreteStrategy = new ConcreteStrategy();
  const context = new Context(concreteStrategy, harnessOriginFetcher);

  // Process each command line-by-line
  for (const line of lines) {
    const parts = line.split(' ');
    const command = parts[0];
    const key = parts[1];

    if (command === 'fetch') {
      try {
        await context.fetch(key); // Await for async operations within the context
      } catch (error: any) {
        console.log(`Error fetching ${key}: ${error.message}`);
      }
    } else if (command === 'invalidate') {
      context.invalidate(key);
    } else {
      console.log(`Unknown command: ${line}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "fetch /api/users", "description": "First fetch populates cache for a key", "expected_output": "Cache miss, fetched from origin, cached result: {\"id\":1,\"name\":\"Alice\",\"email\":\"alice@example.com\"}"}, {"input": "fetch /api/users\nfetch /api/users", "description": "Subsequent fetch for the same key uses cache", "expected_output": "Cache miss, fetched from origin, cached result: {\"id\":1,\"name\":\"Alice\",\"email\":\"alice@example.com\"}\nCache hit, returned cached result: {\"id\":1,\"name\":\"Alice\",\"email\":\"alice@example.com\"}"}, {"input": "fetch /api/users\ninvalidate /api/users", "description": "Invalidate a specific cache entry", "expected_output": "Cache miss, fetched from origin, cached result: {\"id\":1,\"name\":\"Alice\",\"email\":\"alice@example.com\"}\nCache invalidated for /api/users"}, {"input": "fetch /api/users\ninvalidate /api/users\nfetch /api/users", "description": "Fetch after invalidation results in a cache miss", "expected_output": "Cache miss, fetched from origin, cached result: {\"id\":1,\"name\":\"Alice\",\"email\":\"alice@example.com\"}\nCache invalidated for /api/users\nCache miss, fetched from origin, cached result: {\"id\":1,\"name\":\"Alice\",\"email\":\"alice@example.com\"}"}, {"input": "fetch /api/products/1\nfetch /api/users\nfetch /api/products/1", "description": "Fetching different keys operates independently, then subsequent fetch for same key hits cache", "expected_output": "Cache miss, fetched from origin, cached result: {\"id\":1,\"name\":\"Laptop\",\"price\":1200}\nCache miss, fetched from origin, cached result: {\"id\":1,\"name\":\"Alice\",\"email\":\"alice@example.com\"}\nCache hit, returned cached result: {\"id\":1,\"name\":\"Laptop\",\"price\":1200}"}, {"input": "fetch /api/posts/101\ninvalidate /api/products/1\nfetch /api/posts/101", "description": "Invalidating one key does not affect other cached entries", "expected_output": "Cache miss, fetched from origin, cached result: {\"id\":101,\"title\":\"My First Post\",\"author\":\"Bob\"}\nCache invalidated for /api/products/1\nCache hit, returned cached result: {\"id\":101,\"title\":\"My First Post\",\"author\":\"Bob\"}"}, {"input": "fetch /api/nonexistent", "description": "Fetching a non-existent key should indicate an error or resource not found", "expected_output": "Error fetching /api/nonexistent: Resource not found at /api/nonexistent"}]'::jsonb
