-- dp_033: Theme Manager Singleton
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // User's ThemeManager class is expected to be available here.
  // It should implement the Singleton pattern with methods like:
  // - static getInstance(): ThemeManager
  // - getTheme(): string
  // - setTheme(theme: string): void

  // Get the singleton instance of the ThemeManager.
  // All subsequent calls to ThemeManager.getInstance() are expected to return this same instance.
  const themeManagerInstance = ThemeManager.getInstance();

  let isFirstGetThemeOutput = true; // Flag to distinguish between "(singleton instance)" and "(same singleton)"

  for (const line of lines) {
    const parts = line.split(' ');
    const command = parts[0];

    if (command === 'get_theme') {
      const currentTheme = themeManagerInstance.getTheme();
      if (isFirstGetThemeOutput) {
        console.log(`Current theme: ${currentTheme} (singleton instance)`);
        isFirstGetThemeOutput = false;
      } else {
        console.log(`Current theme: ${currentTheme} (same singleton)`);
      }
    } else if (command === 'set_theme') {
      if (parts.length < 2) {
        // Error: set_theme command requires a theme name. Not expected based on test cases.
        continue;
      }
      const newTheme = parts[1];
      themeManagerInstance.setTheme(newTheme);
      console.log(`Theme changed to ${newTheme}`);
    }
    // Unknown commands or empty lines are silently ignored as per typical challenge setup.
  }
});$harness$,
