-- dp_034: Smart Home Command Remote
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout,
  terminal: false // Not interacting with a terminal directly
});

const lines: string[] = [];

// Read all lines from stdin and store them, trimmed.
// This part of the harness adheres to the provided starter template.
rl.on('line', (line) => {
  lines.push(line.trim());
});

// Process all commands after stdin has been fully read.
rl.on('close', () => {
  // Instantiate the user's Context class. This 'Context' is expected to manage
  // strategies and command execution as per the Strategy design pattern.
  // It should be stateful across command executions.
  const smartHomeRemote = new Context();

  // Iterate through each command line received from stdin.
  for (const line of lines) {
    if (!line) {
      continue; // Skip empty lines that might result from trimming or empty input.
    }

    // Call the Context's primary method to handle the command.
    // This method is responsible for parsing the command, selecting the appropriate
    // ConcreteStrategy, executing it, and returning any string result.
    // The Context should encapsulate the logic of the Strategy design pattern
    // and ensure all interaction with ConcreteStrategy instances happens within it.
    // It's assumed that the Context.executeCommand method returns a string for commands
    // that produce output, and undefined/null/empty string for commands that don't.
    const output = smartHomeRemote.executeCommand(line);

    // If the command produced a string output, print it to stdout.
    // The harness is responsible for all console.log() output.
    if (typeof output === 'string' && output.length > 0) {
      console.log(output);
    }
  }
});$harness$,
  test_cases   = '[{"input": "command=turn_on, device=lights", "description": "Turn on lights", "expected_output": "Lights turned ON"}, {"input": "command=turn_off, device=thermostat", "description": "Turn off thermostat", "expected_output": "Thermostat turned OFF"}, {"input": "command=turn_on, device=lights\ncommand=turn_off, device=thermostat\nundo_last_command", "description": "Undo last command after multiple operations", "expected_output": "Lights turned ON\nThermostat turned OFF\nUndone: Thermostat turned ON"}, {"input": "macro=[turn_on lights, set_temp 22, lock_door]", "description": "Execute macro command", "expected_output": "Macro executed: 3 commands run"}, {"input": "command=set_temp, device=thermostat, value=22", "description": "Set thermostat temperature", "expected_output": "Thermostat temperature set to 22"}, {"input": "command=lock_door, device=front_door", "description": "Lock a door", "expected_output": "Front_door locked"}, {"input": "command=turn_on, device=lights\ncommand=set_temp, device=thermostat, value=22\ncommand=lock_door, device=front_door\nundo_last_command\nundo_last_command", "description": "Chained commands and multiple undo operations", "expected_output": "Lights turned ON\nThermostat temperature set to 22\nFront_door locked\nUndone: Front_door unlocked\nUndone: Thermostat temperature restored"}, {"input": "undo_last_command", "description": "Attempt to undo with no commands in history", "expected_output": "No command to undo"}, {"input": "macro=[turn_on fan, set_brightness 50, unlock_door]\nundo_last_command", "description": "Execute macro and then undo it (if macro is undoable)", "expected_output": "Macro executed: 3 commands run\nUndone: Macro: 3 commands reversed"}]'::jsonb
