-- dp_035: Binary Tree Iterator Traversal
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

// The following interfaces and classes are part of the user's starter code:
// interface Strategy {
//   execute(data: unknown): void;
// }

// class Context {
//   // TODO: hold strategy and run it
// }

// class ConcreteStrategy implements Strategy {
//   // TODO: implement
// }

// The user is also expected to define a 'TreeNode' class (e.g., class TreeNode { val: number; left: TreeNode | null; right: TreeNode | null; ... }) 
// and specific concrete strategy classes (e.g., InOrderTraversalStrategy) that implement the 'Strategy' interface.

// --- Start Cr4ck Test Harness --- 

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {

  // Helper function to build a binary tree from a level-order array representation.
  // It assumes the user has defined a `TreeNode` class with `val`, `left`, `right` properties.
  // Example: `[1,2,3,null,5]` represents:
  //      1
  //     / \
  //    2   3
  //   / \ 
  //  null 5
  function buildTree(nodes: (number | null)[]): TreeNode | null {
    if (!nodes || nodes.length === 0 || nodes[0] === null) {
      return null;
    }

    // `TreeNode` is expected to be defined by the user. The harness directly uses it.
    const root = new TreeNode(nodes[0]); 
    const queue: (TreeNode | null)[] = [root];
    let i = 1;

    while (queue.length > 0 && i < nodes.length) {
      const current = queue.shift();

      if (current === null) {
        continue; // Skip null placeholders in the queue if they somehow get there
      }

      // Left child
      if (i < nodes.length) {
        const leftVal = nodes[i];
        if (leftVal !== null) {
          current.left = new TreeNode(leftVal);
          queue.push(current.left);
        } else {
          current.left = null; // Explicitly set to null
        }
        i++;
      }

      // Right child
      if (i < nodes.length) {
        const rightVal = nodes[i];
        if (rightVal !== null) {
          current.right = new TreeNode(rightVal);
          queue.push(current.right);
        } else {
          current.right = null; // Explicitly set to null
        }
        i++;
      }
    }
    return root;
  }

  // Initialize the user's Context instance.
  // Assumes the user's Context class has a constructor that can be called without arguments
  // and methods `setStrategy(strategy: Strategy)` and `executeStrategy(data: unknown)`. 
  const context = new Context();
  let currentRoot: TreeNode | null = null; // Stateful variable to hold the current binary tree root

  // Map to store instances of concrete strategies.
  // Assumes user defines 'InOrderTraversalStrategy', 'PreOrderTraversalStrategy', 'PostOrderTraversalStrategy'
  // and that they implement the 'Strategy' interface.
  const strategyMap = new Map<string, Strategy>();
  try {
    strategyMap.set('inorder', new InOrderTraversalStrategy());
    strategyMap.set('preorder', new PreOrderTraversalStrategy());
    strategyMap.set('postorder', new PostOrderTraversalStrategy());
  } catch (e: any) {
    // This error indicates the user likely hasn't defined the required strategy classes.
    console.error(`Harness Error: Failed to initialize strategy instances. Please ensure 'InOrderTraversalStrategy', 'PreOrderTraversalStrategy', and 'PostOrderTraversalStrategy' classes are correctly defined and implement the 'Strategy' interface. Details: ${e.message}`);
    // The program might not function correctly if strategies aren't initialized, but we continue processing commands 
    // to report all possible errors.
  }

  // Process each command line from stdin
  for (const line of lines) {
    const parts = line.split(' ');
    const command = parts[0];
    const args = parts.slice(1).join(' ');

    switch (command) {
      case 'BUILD_TREE':
        // Command: BUILD_TREE [1,2,3,null,5]
        // Parses the JSON array string and builds a tree, storing its root in `currentRoot`.
        try {
          const nodeVals = JSON.parse(args) as (number | null)[];
          currentRoot = buildTree(nodeVals);
        } catch (e: any) {
          console.error(`Harness Error: BUILD_TREE command failed to parse argument or build tree. Argument: '${args}'. Details: ${e.message}`);
          currentRoot = null; // Reset tree on error to prevent cascading issues
        }
        break;
      case 'SET_STRATEGY':
        // Command: SET_STRATEGY inorder
        // Sets the appropriate concrete strategy on the Context.
        const strategyName = args.toLowerCase();
        const selectedStrategy = strategyMap.get(strategyName);
        if (selectedStrategy) {
          context.setStrategy(selectedStrategy);
        } else {
          console.error(`Harness Error: Unknown strategy '${strategyName}'. Please ensure the strategy name is correct and its instance is mapped.`);
        }
        break;
      case 'EXECUTE_TRAVERSAL':
        // Command: EXECUTE_TRAVERSAL
        // Executes the currently set strategy using the `currentRoot`.
        // The Context's executeStrategy method is expected to delegate to the current strategy,
        // which in turn should perform the traversal and print the result to console.log.
        context.executeStrategy(currentRoot);
        break;
      default:
        console.error(`Harness Error: Unknown command '${command}'.`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "BUILD_TREE [1,2,3,4,5]\nSET_STRATEGY inorder\nEXECUTE_TRAVERSAL", "description": "In-order traversal", "expected_output": "4, 2, 5, 1, 3"}, {"input": "BUILD_TREE [1,2,3,4,5]\nSET_STRATEGY preorder\nEXECUTE_TRAVERSAL", "description": "Pre-order traversal", "expected_output": "1, 2, 4, 5, 3"}, {"input": "BUILD_TREE [1,2,3,4,5]\nSET_STRATEGY postorder\nEXECUTE_TRAVERSAL", "description": "Post-order traversal", "expected_output": "4, 5, 2, 3, 1"}, {"input": "BUILD_TREE []\nSET_STRATEGY inorder\nEXECUTE_TRAVERSAL", "description": "Empty tree traversal (in-order)", "expected_output": ""}, {"input": "BUILD_TREE [1,null,2,null,null,3]\nSET_STRATEGY inorder\nEXECUTE_TRAVERSAL", "description": "In-order traversal with sparse tree", "expected_output": "1, 3, 2"}, {"input": "BUILD_TREE [1,null,2,null,null,3]\nSET_STRATEGY preorder\nEXECUTE_TRAVERSAL", "description": "Pre-order traversal with sparse tree", "expected_output": "1, 2, 3"}, {"input": "BUILD_TREE [1,null,2,null,null,3]\nSET_STRATEGY postorder\nEXECUTE_TRAVERSAL", "description": "Post-order traversal with sparse tree", "expected_output": "3, 2, 1"}, {"input": "BUILD_TREE [10,5,15,null,null,12,20]\nSET_STRATEGY inorder\nEXECUTE_TRAVERSAL", "description": "In-order traversal with another tree structure", "expected_output": "5, 10, 12, 15, 20"}, {"input": "BUILD_TREE [10,5,15,null,null,12,20]\nSET_STRATEGY preorder\nEXECUTE_TRAVERSAL", "description": "Pre-order traversal with another tree structure", "expected_output": "10, 5, 15, 12, 20"}, {"input": "BUILD_TREE [10,5,15,null,null,12,20]\nSET_STRATEGY postorder\nEXECUTE_TRAVERSAL", "description": "Post-order traversal with another tree structure", "expected_output": "5, 12, 20, 15, 10"}]'::jsonb
WHERE id = 'dp_035';
-- dp_036: UI Component Composite Renderer
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';
const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

// Capture console.log output
const originalConsoleLog = console.log;
let outputBuffer: string[] = [];
console.log = (...args: any[]) => {
    outputBuffer.push(args.map(String).join(' '));
};

rl.on('close', () => {
    const componentRegistry = new Map<string, any>(); // Stores component instances by name

    // Helper function to determine component class name from instance name
    // This heuristic assumes component instance names contain keywords indicative of their class.
    const getComponentTypeNameFromInstanceName = (instanceName: string): string => {
        // Order matters for specific types like "SubPanel" before general "Panel"
        if (instanceName.toLowerCase().includes('subpanel')) return 'SubPanel';
        if (instanceName.toLowerCase().includes('panel')) return 'Panel';
        if (instanceName.toLowerCase().includes('button')) return 'Button';
        // Assuming 'Header' and 'Footer' are also leaf components like 'Button' for these tests.
        if (instanceName.toLowerCase().includes('header')) return 'Button';
        if (instanceName.toLowerCase().includes('footer')) return 'Button';
        return 'UnknownComponentType'; 
    };

    // Helper function to get or create a component instance.
    // Assumes user's component classes (e.g., Panel, Button) are globally accessible
