  lines.push(line.trim());
});

rl.on('close', () => {
  // Mock file system for strategies to access
  // Assumes "rows parsed" refers to data rows (excluding header).
  // For "100 rows parsed", it means 100 data rows after the header.
  const mockFileSystem: { [key: string]: string[] } = {
    "data.csv": [
      "name,age,email", // Header
      ...Array(100).fill("dummy_name,25,dummy@example.com") // 100 data rows
    ],
    // Malformed line is on physical line 3 (index 2), which is the 2nd data row.
    // If the error message refers to the physical line number, "row 3" is correct.
