      "name,age,email",         // Line 1 (header)
      "Good,20,good@example.com", // Line 2 (data row 1)
      "Alice,30",               // Line 3 (data row 2, malformed)
      "Bob,24,bob@example.com"  // Line 4 (data row 3)
    ],
    "empty.csv": [
      "name,age,email" // Header only, 0 data rows
    ]
  };

  // Instantiate the user's Context class. User's Context, Strategy, 
  // ImportCsvStrategy, and ConvertRowStrategy are expected to be available.
  const context = new Context();

  for (const line of lines) {
    let output: string = "";
    try {
      if (line.startsWith("import file=")) {
