          output = `Error: file not found: ${filename}`;
        } else {
          // The harness assumes the user has implemented an 'ImportCsvStrategy' class.
          // It also assumes user's Strategy interface and Context class are adapted 
          // to return strings and pass the context object to execute.
          if (typeof ImportCsvStrategy === 'function') {
            const importStrategy = new ImportCsvStrategy();
            context.setStrategy(importStrategy);
            // Pass relevant data and the context object to the strategy.
            output = context.executeStrategy({ filename: filename, content: fileContent });
          } else {
            output = `Error: ImportCsvStrategy class not found.`;
          }
        }
      } else if (line.startsWith("convert row=")) {
        const rowDataString = line.substring("convert row=".length);
        // The harness assumes the user has implemented a 'ConvertRowStrategy' class.
        if (typeof ConvertRowStrategy === 'function') {
          const convertStrategy = new ConvertRowStrategy();
          context.setStrategy(convertStrategy);
          // Pass relevant data and the context object to the strategy.
          output = context.executeStrategy({ rowString: rowDataString });
        } else {
          output = `Error: ConvertRowStrategy class not found.`;
        }
      } else {
        output = `Error: Unknown command "${line}"`;
      }
    } catch (e: any) {
      // Catch errors originating from the user's code/strategies
      output = `Error: ${e.message || 'An unknown error occurred during command execution.'}`;
    }
    if (output) {
      console.log(output);
    }
  }
});$harness$,
