-- dp_039: Email Digest Template Builder
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout,
  terminal: false
});

const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', () => {
  // Parser function to interpret commands from stdin
  // It extracts the command type and associated data/arguments.
  function parseCommand(line: string): { type: string; data: Record<string, any> } {
    const parts = line.split(' ');
    let type = parts[0]; // e.g., "add_section", "send"
    let dataStr = parts.slice(1).join(' ').trim(); // remaining args string

    // Special handling for the 'build_digest' command which starts with key=value pair
    if (type.includes('=')) {
      type = 'build_digest';
      dataStr = line;
    }

    const data: Record<string, any> = {};
    // Parse key=value pairs separated by commas
    dataStr.split(',').forEach(part => {
      const [key, value] = part.split('=').map(s => s.trim());
      if (key && value) {
        // Attempt to convert value to a number if possible, otherwise keep as string
        data[key] = isNaN(Number(value)) ? value : Number(value);
      }
    });

    return { type, data };
  }

  // Instantiate the Context class, which will manage the state of the email digest.
  // The user is expected to extend the provided Context class to hold strategy and digest state.
  const context = new Context();

  // Process each command line by line
  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    const { type, data } = parseCommand(line);

    let strategy: Strategy;

    // Based on the command type, instantiate the appropriate ConcreteStrategy.
    // The user is expected to define these ConcreteStrategy classes (e.g., BuildDigestStrategy, AddSectionStrategy, SendEmailStrategy)
    // and ensure their constructors accept a reference to the Context instance.
    switch (type) {
      case 'build_digest':
        // @ts-ignore - User-defined classes like 'BuildDigestStrategy' are available at runtime
        strategy = new BuildDigestStrategy(context);
        break;
      case 'add_section':
        // @ts-ignore
        strategy = new AddSectionStrategy(context);
        break;
      case 'send_email':
        // @ts-ignore
        strategy = new SendEmailStrategy(context);
        break;
      default:
        console.error(`Error: Unknown command type "${type}"`);
        continue;
    }

    // Set the chosen strategy on the context and execute it with the parsed data.
    // The strategy's execute method is expected to interact with the context's state
    // and print results using console.log().
    context.setStrategy(strategy);
    context.executeStrategy(data);
  }
});$harness$,
  test_cases   = '[{"input": "template=weekly_digest, user=alice@example.com", "description": "Build weekly digest", "expected_output": "Email digest built for alice@example.com with weekly template"}, {"input": "template=weekly_digest, user=alice@example.com\nadd_section type=featured_articles, count=3", "description": "Add articles section", "expected_output": "Email digest built for alice@example.com with weekly template\nFeatured articles section added with 3 articles"}, {"input": "template=weekly_digest, user=alice@example.com\nadd_section type=featured_articles, count=3\nadd_section type=promotions, discount=20%", "description": "Add promotions section", "expected_output": "Email digest built for alice@example.com with weekly template\nFeatured articles section added with 3 articles\nPromotions section added with 20% discount"}, {"input": "template=weekly_digest, user=alice@example.com\nadd_section type=featured_articles, count=3\nadd_section type=promotions, discount=20%\nsend email=built", "description": "Send built digest", "expected_output": "Email digest built for alice@example.com with weekly template\nFeatured articles added with 3 articles\nPromotions section added with 20% discount\nDigest email sent successfully"}]'::jsonb
WHERE id = 'dp_039';
-- dp_040: Approval Workflow Chain
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout,
  terminal: false
});

const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', () => {
  // User's `Strategy` interface, `Context`, and `ConcreteStrategy` classes are available here.
  // It is assumed the user will define multiple concrete strategy classes (e.g., ManagerApprovalStrategy, etc.)
  // and that the `Strategy.execute` method signature will be updated to `execute(request: ApprovalRequest): string;`

  // Internal interface for parsing input. This should mirror what user's Strategy expects.
  interface ApprovalRequest {
    type: string;
    amount: number;
    // 'approver' from input is considered a hint and not directly part of the core request object
  }

  // Helper function to parse input lines into an ApprovalRequest object
  function parseInput(inputLine: string): ApprovalRequest {
    const parts = inputLine.split(', ').map(p => p.trim());
    const request: Partial<ApprovalRequest> = {};

    for (const part of parts) {
      const [key, value] = part.split('=');
      switch (key) {
        case 'request':
          request.type = value;
          break;
        case 'amount':
          // Remove any non-numeric characters (like 'days', '$') before parsing to float
          request.amount = parseFloat(value.replace(/[^0-9.]/g, ''));
          break;
        // 'approver' is an input hint, not a core data field for the approval logic itself.
        // User's strategies should route based on type and amount.
      }
    }

    if (request.type === undefined || request.amount === undefined) {
      throw new Error(`Invalid input format: "${inputLine}" - missing request type or amount.`);
    }
    return request as ApprovalRequest;
  }

  try {
    // Instantiate user's concrete strategy classes and chain them together.
    // This setup assumes the user has created distinct classes for each approval level
    // (e.g., CEOApprovalStrategy, VPApprovalStrategy) and that these classes implement
    // a constructor that allows chaining (e.g., `constructor(successor?: Strategy)`).
    // The chain is typically built from the highest authority down to the lowest.

    // Using `any` for constructors to allow for user-defined class names that are not directly available in TS scope
    // outside of their definitions. This will cause runtime errors if classes aren't defined by user.
    const ceoStrategy: Strategy = new (globalThis as any).CEOApprovalStrategy();
    const vpStrategy: Strategy = new (globalThis as any).VPApprovalStrategy(ceoStrategy);
    const directorStrategy: Strategy = new (globalThis as any).DirectorApprovalStrategy(vpStrategy);
    const managerStrategy: Strategy = new (globalThis as any).ManagerApprovalStrategy(directorStrategy);

    // Instantiate the user's Context class with the entry point strategy (Manager).
    // The Context's constructor is assumed to take an initial Strategy.
    const context: Context = new (globalThis as any).Context(managerStrategy);

    // Process each line from stdin as a separate approval request
    for (const line of lines) {
      if (!line) continue; // Skip empty lines

      try {
        const request = parseInput(line);
        // Assumes user's Context has a method like `processRequest` that delegates to its current strategy.
        // Also assumes `Strategy.execute` returns the final approval message string.
        const result = context.processRequest(request);
        console.log(result);
      } catch (error: any) {
        console.error(`Error processing request "${line}": ${error.message}`);
      }
    }
  } catch (e: any) {
    console.error(`Harness setup error: ${e.message}. \n\nEnsure your custom Strategy implementations (e.g., ManagerApprovalStrategy, CEOApprovalStrategy) and Context class are correctly defined, implement the Strategy interface, and have appropriate constructors for chaining.`);
  }
});$harness$,
  test_cases   = '[{"input": "request=leave, amount=3days, approver=manager", "description": "Manager approves short leave", "expected_output": "Manager approved 3-day leave"}, {"input": "request=budget, amount=5000, approver=manager", "description": "Budget escalated to director", "expected_output": "Manager passed to Director, Director approved $5000"}, {"input": "request=capital_expense, amount=50000", "description": "Large expense approved by VP", "expected_output": "Escalated to VP, VP approved $50000"}, {"input": "request=acquisition, amount=1000000", "description": "Acquisition approved by CEO", "expected_output": "Escalated to CEO, CEO approved"}]'::jsonb
