-- dp_041: Airport Control Tower Mediator
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

const lines: string[] = [];
rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', () => {
  // The `Context` class is interpreted as the Mediator (Air Traffic Control Tower).
  // It manages the state (e.g., occupied runways, flights in holding patterns)
  // and coordinates interactions between `Strategy` implementations (which act as commands/colleagues).
  const airTrafficControlTower = new Context();

  // Instantiate all concrete strategies, passing the tower (Mediator) instance to them.
  // This allows strategies to interact with the tower's state and methods.
  const takeoffStrategy = new TakeoffClearanceStrategy(airTrafficControlTower);
  const landingStrategy = new LandingClearanceStrategy(airTrafficControlTower);
  const emergencyStrategy = new EmergencyClearanceStrategy(airTrafficControlTower);
  
  // Map of request types to their corresponding strategy.
  // The harness dispatches commands to the appropriate strategy.
  const strategyMap: { [key: string]: Strategy } = {
    'takeoff_clearance': takeoffStrategy,
    'landing': landingStrategy,
    'emergency': emergencyStrategy,
  };

  for (const line of lines) {
    if (!line) continue;

    // Parse the command line: COMMAND_TYPE:param1=value1,param2=value2
    const parts = line.split(':');
    const commandType = parts[0];
    const rawParams = parts.length > 1 ? parts[1] : '';

    const params: Record<string, string> = {};
    rawParams.split(',').forEach(param => {
      const [key, value] = param.split('=');
      if (key && value) {
        params[key.trim()] = value.trim();
      }
    });

    try {
      if (commandType === 'REQUEST_CLEARANCE') {
        // Handle standard flight clearance requests
        const requestType = params['request'];
        const strategy = strategyMap[requestType];
        if (strategy) {
          strategy.execute(params); // Execute the strategy with parsed parameters
        } else {
          console.log(`Error: Unknown request type - ${requestType}`);
        }
      } else if (commandType === 'EMERGENCY') {
        // Handle emergency requests
        const strategy = strategyMap['emergency'];
        if (strategy) {
            strategy.execute(params);
        } else {
          console.log("Error: Emergency strategy not found.");
        }
      } else if (commandType === 'SETUP_RUNWAY') { 
        // Internal harness command to pre-configure airport state (e.g., occupy a runway)
        const runwayId = params['id'];
        if (runwayId) {
          airTrafficControlTower.occupyRunway(runwayId);
        }
      } else if (commandType === 'FREE_RUNWAY') { 
        // Internal harness command to pre-configure airport state (e.g., free a runway)
        const runwayId = params['id'];
        if (runwayId) {
          airTrafficControlTower.freeRunway(runwayId);
        }
      }
       else {
        console.log(`Error: Unknown command - ${commandType}`);
      }
    } catch (e: any) {
      console.log(`Error processing command "${line}": ${e.message}`);
    }
  }
});$harness$,
