-- dp_042: Browser History Memento
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {
  // User's classes (expected to be globally available after concatenation)
  // The user is expected to implement:
  //   interface BrowserMemento { /* ... */ }
  //   class Browser { /* ... */ }
  //   class SessionCareTaker { /* ... */ }
  // The provided Strategy/Context classes are generic and not directly used by this Memento-specific harness.

  const browser = new Browser();
  const careTaker = new SessionCareTaker();

  for (const line of lines) {
    if (line.startsWith('navigate url=')) {
      const url = line.substring('navigate url='.length);
      const navigatedUrl = browser.navigate(url);
      console.log(`Navigated to ${navigatedUrl}, history saved`);
    } else if (line === 'back') {
      const prevUrl = browser.back();
      if (prevUrl) {
        console.log(`Navigated back to ${prevUrl}`);
      } else {
        console.log('Cannot go back further');
      }
    } else if (line === 'forward') {
      const nextUrl = browser.forward();
      if (nextUrl) {
        console.log(`Navigated forward to ${nextUrl}`);
      } else {
        console.log('Cannot go forward further');
      }
    } else if (line === 'save_session') {
      const memento = browser.saveState();
      careTaker.addMemento(memento);
      console.log('Session state saved.');
    } else if (line === 'restore_session') {
      const memento = careTaker.getLastMemento();
      if (memento) {
        browser.restoreState(memento);
        console.log(`Session restored with ${browser.getHistoryEntryCount()} history entries, current URL: ${browser.getCurrentUrl()}`);
      } else {
        console.log('No session state to restore.');
      }
    } else {
      console.log(`Unknown command: ${line}`);
    }
  }
});$harness$,
