-- dp_043: Vending Machine State Controller
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // User's `Strategy` and `Context` definitions are expected to be available.
  // The harness assumes the user will adapt the `Strategy` interface and `Context` class
  // to implement the State design pattern.
  // Specifically, `Strategy.execute` is expected to take `(context: Context, event: string)`
  // and `Context` should have `transitionTo(state: Strategy)` and `logMessage(message: string)`.
  
  // Accessing user-defined classes from the global scope after concatenation.
  const InitialStateClass = (global as any)['IdleState'];
  const UserContextClass = (global as any)['Context'];

  if (!UserContextClass || typeof UserContextClass !== 'function') {
    console.error("Error: User's 'Context' class not found or not a valid class. Ensure it's defined and accessible.");
    process.exit(1);
  }
  if (!InitialStateClass || typeof InitialStateClass !== 'function') {
    console.error("Error: Initial state class 'IdleState' not found or not a valid class. Ensure it's defined and accessible.");
    process.exit(1);
  }

  // Instantiate the vending machine controller with its initial state.
  const vendingMachine = new UserContextClass(new InitialStateClass());

  for (const line of lines) {
    if (line) {
      // Each line from stdin is treated as an event for the vending machine.
      const output = vendingMachine.request(line);
      if (output) {
        console.log(output);
      }
    }
  }
});$harness$,
  test_cases   = '[{"input": "insert_coin", "description": "Insert coin", "expected_output": "Transition: IDLE -> HAS_MONEY"}, {"input": "insert_coin\nselect_item", "description": "Select item", "expected_output": "Transition: IDLE -> HAS_MONEY\nTransition: HAS_MONEY -> DISPENSING"}, {"input": "insert_coin\nselect_item\ndispense_complete", "description": "Item dispensed", "expected_output": "Transition: IDLE -> HAS_MONEY\nTransition: HAS_MONEY -> DISPENSING\nTransition: DISPENSING -> IDLE, item dispensed"}, {"input": "select_item", "description": "Select without coin", "expected_output": "Invalid: no coin inserted"}, {"input": "insert_coin\ninsert_coin", "description": "Insert coin when already has money", "expected_output": "Transition: IDLE -> HAS_MONEY\nInvalid: already has money."}, {"input": "insert_coin\nrefund_request", "description": "Request refund", "expected_output": "Transition: IDLE -> HAS_MONEY\nTransition: HAS_MONEY -> IDLE, refund issued"}, {"input": "insert_coin\nselect_item\ninsert_coin", "description": "Insert coin while dispensing", "expected_output": "Transition: IDLE -> HAS_MONEY\nTransition: HAS_MONEY -> DISPENSING\nInvalid: machine is dispensing."}, {"input": "refund_request", "description": "Request refund when idle", "expected_output": "Invalid: no money to refund"}]'::jsonb
