-- dp_044: Shopping Cart Discount Visitor
UPDATE challenges SET
  test_harness = $harness$class CartItem {
  constructor(public item: string, public price: number) {}
}

import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin
});

const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', () => {
  // The user's 'Context' class is expected to be adapted to function as a ShoppingCart.
  // It should have methods like addItem, clear, setStrategy, and executeCurrentStrategy.
  const shoppingCart = new Context();

  for (const line of lines) {
    const [command, ...args] = line.split(' ');

    switch (command) {
      case 'ADD_ITEM':
        if (args.length === 2) {
          const itemName = args[0];
          const itemPrice = parseFloat(args[1]);
          if (!isNaN(itemPrice)) {
            shoppingCart.addItem(new CartItem(itemName, itemPrice));
          } else {
            console.error(`Invalid price for ADD_ITEM: ${args[1]}`);
          }
        } else {
          console.error(`Invalid ADD_ITEM command: ${line}`);
        }
        break;

      case 'SET_VISITOR':
        if (args.length === 1) {
          const visitorType = args[0];
          let visitor: Strategy | null = null; // Expects user's 'Strategy' interface to be adapted for Visitor

          // Instantiate the appropriate user-defined ConcreteStrategy (Visitor)
          // based on the visitorType string. These classes are expected to implement
          // the 'Strategy' interface and be named e.g., 'DiscountStrategy', 'TaxStrategy'.
          switch (visitorType) {
            case 'discount_10':
              visitor = new (global as any).DiscountStrategy();
              break;
            case 'tax_calculator':
              visitor = new (global as any).TaxStrategy();
              break;
            case 'shipping':
              visitor = new (global as any).ShippingStrategy();
              break;
            default:
              console.error(`Unknown visitor type: ${visitorType}`);
              break;
          }

          if (visitor) {
            // User's Context.setStrategy is expected to hold the visitor
            shoppingCart.setStrategy(visitor);
          }
        } else {
          console.error(`Invalid SET_VISITOR command: ${line}`);
        }
        break;

      case 'APPLY_VISITOR':
        // User's Context.executeCurrentStrategy is expected to apply the held visitor
        shoppingCart.executeCurrentStrategy();
        break;

      case 'CLEAR_CART':
        // User's Context.clear is expected to reset the shopping cart's items
        shoppingCart.clear();
        break;

      default:
        console.error(`Unknown command: ${command}`);
        break;
    }
  }
});$harness$,
  test_cases   = '[{"input": "ADD_ITEM laptop 1000\nSET_VISITOR discount_10\nAPPLY_VISITOR", "description": "10% discount visitor", "expected_output": "Discount applied: $100.00 off, total $900.00"}, {"input": "CLEAR_CART\nADD_ITEM book 50\nSET_VISITOR tax_calculator\nAPPLY_VISITOR", "description": "Tax calculation visitor", "expected_output": "Tax calculated: $4.00, total $54.00"}, {"input": "CLEAR_CART\nADD_ITEM laptop 1000\nADD_ITEM book 50\nSET_VISITOR shipping\nAPPLY_VISITOR", "description": "Shipping cost visitor", "expected_output": "Shipping cost calculated: $15.00"}, {"input": "CLEAR_CART\nSET_VISITOR discount_10\nAPPLY_VISITOR", "description": "Empty cart visitor", "expected_output": "Empty cart, no discount applied"}, {"input": "CLEAR_CART\nADD_ITEM gadget 250\nAPPLY_VISITOR", "description": "Apply visitor without setting one", "expected_output": "No visitor set."}, {"input": "CLEAR_CART\nADD_ITEM mouse 25\nADD_ITEM keyboard 75\nSET_VISITOR tax_calculator\nAPPLY_VISITOR\nSET_VISITOR shipping\nAPPLY_VISITOR", "description": "Multiple visitors on same cart", "expected_output": "Tax calculated: $8.00, total $108.00\nShipping cost calculated: $15.00"}]'::jsonb
WHERE id = 'dp_044';
-- dp_045: Particle System Flyweight Renderer
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // The user is expected to adapt the provided `Context` class
  // to implement the Flyweight pattern for a particle system renderer.
  // This `Context` class should internally manage a FlyweightFactory
  // and expose the following methods for the harness to interact with:
  // 1. `renderParticles(type: string, count: number, extrinsicStateDescription?: string): string`
  //    - Renders a batch of particles and returns a summary string.
  //      `extrinsicStateDescription` is optional, used for particles with varying extrinsic state.
  // 2. `getFlyweightPoolInfo(): string`
  //    - Returns a string describing the current state of the flyweight pool (e.g., count and types).
  const renderer = new Context(); // Instantiate the user's Context class

  for (const line of lines) {
    if (line.startsWith('particle_type=')) {
      const parts = line.split(',').map(p => p.trim());
      let type: string | undefined;
      let count: number | undefined;
      let extrinsicStateDescription: string | undefined;

      for (const part of parts) {
        if (part.startsWith('particle_type=')) {
          type = part.substring('particle_type='.length);
        } else if (part.startsWith('count=')) {
          count = parseInt(part.substring('count='.length), 10);
        } else if (part.startsWith('position=')) { // Handle specific extrinsic state type
          extrinsicStateDescription = part.substring('position='.length);
        }
        // More extrinsic state parsing logic could be added here if needed
      }

      if (type && typeof count === 'number' && !isNaN(count)) {
        try {
          // Cast to `any` to allow calling methods dynamically on the user's potentially modified Context class
          const result = (renderer as any).renderParticles(type, count, extrinsicStateDescription);
          console.log(result);
        } catch (e: any) {
          console.error(`Runtime Error in renderParticles: ${e.message}`);
          // Provide a fallback output for a clearer test failure message if the method is missing or errors
          console.log(`Error: Failed to render particles of type '${type}'`);
        }
      } else {
        console.log(`Error: Invalid 'particle_type' command format: ${line}`);
      }
    } else if (line === 'pool_size') {
      try {
        const result = (renderer as any).getFlyweightPoolInfo();
        console.log(result);
      } catch (e: any) {
        console.error(`Runtime Error in getFlyweightPoolInfo: ${e.message}`);
        console.log(`Error: Failed to retrieve flyweight pool information`);
      }
    } else {
      console.log(`Error: Unknown command: ${line}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "particle_type=fire, count=1000", "description": "Render fire particles", "expected_output": "1000 fire particles rendered using 1 shared flyweight"}, {"input": "particle_type=fire, count=1000\nparticle_type=smoke, count=500\npool_size", "description": "Render smoke particles and verify flyweight pool size and types.", "expected_output": "1000 fire particles rendered using 1 shared flyweight\n500 smoke particles rendered using 1 shared flyweight\nFlyweight pool: 2 types (fire, smoke)"}, {"input": "particle_type=rain, count=2000, position=varies", "description": "Rain particles with extrinsic state", "expected_output": "2000 rain particles rendered, extrinsic state varies"}, {"input": "particle_type=fire, count=100\nparticle_type=smoke, count=200\nparticle_type=rain, count=300, position=random\npool_size\nparticle_type=fire, count=500\npool_size", "description": "Render multiple particle types, including one with extrinsic state, and check the flyweight pool at various points to confirm sharing.", "expected_output": "100 fire particles rendered using 1 shared flyweight\n200 smoke particles rendered using 1 shared flyweight\n300 rain particles rendered, extrinsic state random\nFlyweight pool: 3 types (fire, smoke, rain)\n500 fire particles rendered using 1 shared flyweight\nFlyweight pool: 3 types (fire, smoke, rain)"}]'::jsonb
WHERE id = 'dp_045';
-- dp_046: Drawing Tool Abstraction Bridge
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', () => {
  // Map platform names to Strategy instances.
  // We assume the user implements specific concrete strategy classes
  // that adhere to the 'Strategy' interface and represent the Bridge's 'Implementation' hierarchy.
  // The harness expects these classes to be named `RasterDrawingImplementation` and `VectorDrawingImplementation`.

  // Using `global as any` to access potentially user-defined classes in the global scope.
  const strategyImplementations: { [key: string]: Strategy | null } = {
    "raster": (global as any).RasterDrawingImplementation ? new (global as any).RasterDrawingImplementation() : null,
    "vector": (global as any).VectorDrawingImplementation ? new (global as any).VectorDrawingImplementation() : null,
  };

  // The Context class represents the 'Abstraction' hierarchy for the Bridge pattern.
  // We assume the user implements the `Context` class to hold and delegate to a `Strategy`.
  let drawingToolContext: Context | null = null; 

  for (const line of lines) {
    const parts = line.split(' ');
    const command = parts[0];
    const args = parts.slice(1);

    switch (command) {
      case 'SET_PLATFORM': {
        const platformType = args[0];
        const strategyInstance = strategyImplementations[platformType];

        if (!strategyInstance) {
          console.log(`Error: Concrete strategy for platform '${platformType}' not found. Please ensure 'RasterDrawingImplementation' and 'VectorDrawingImplementation' are defined.`);
          continue;
        }

        if (!(global as any).Context) {
             console.log("Error: Context class not found. Please define the 'Context' class.");
             continue;
        }

        if (!drawingToolContext) {
          // Initialize the Context (Abstraction) with the chosen Implementation (Strategy)
          drawingToolContext = new (global as any).Context(strategyInstance);
        } else {
          // Change the Implementation (Strategy) for the existing Abstraction (Context)
          // We assume Context has a `setStrategy` method to change its underlying implementation.
          drawingToolContext.setStrategy(strategyInstance);
        }
        break;
      }
      case 'DRAW': {
        if (!drawingToolContext) {
          console.log('Error: Drawing platform not set. Use SET_PLATFORM first.');
          continue;
        }
        const toolType = args[0];
        // The Context's `performAction` method delegates to its current Strategy's `execute` method.
        // We assume `Context.performAction` takes the tool type.
        // The strategy's `execute` method is expected to print the output directly (due to `void` return type).
        drawingToolContext.performAction(toolType);
        break;
      }
      default:
        console.log(`Error: Unknown command: ${command}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "SET_PLATFORM raster\nDRAW pencil", "description": "Pencil on raster", "expected_output": "Pencil tool drawing on raster canvas"}, {"input": "SET_PLATFORM vector\nDRAW pencil", "description": "Pencil on vector", "expected_output": "Pencil tool drawing on vector canvas"}, {"input": "SET_PLATFORM raster\nDRAW brush", "description": "Brush on raster", "expected_output": "Brush tool drawing on raster canvas"}, {"input": "SET_PLATFORM vector\nDRAW eraser", "description": "Eraser on vector", "expected_output": "Eraser tool on vector canvas"}]'::jsonb
WHERE id = 'dp_046';
-- dp_047: GUI Widget Abstract Factory
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

// Define interfaces the harness expects from user's implementation
// The user's concrete widget classes must implement these interfaces and have a 'render' method.
interface IButton {
    render(): string;
}

interface ICheckbox {
    render(): string;
}

interface ITextField {
    render(): string;
}

interface ISlider {
    render(): string;
}

// Define the Abstract Factory interface that the user's concrete factories must implement.
interface IGUIFactory {
    createButton(): IButton;
    createCheckbox(): ICheckbox;
    createTextField(): ITextField;
    createSlider(): ISlider;
}

// Declare Concrete Factory classes that the user must implement.
// These declarations inform TypeScript that these classes will exist at runtime
// and implement the IGUIFactory interface. The harness will instantiate them.
declare class WindowsFactory implements IGUIFactory {
    createButton(): IButton;
    createCheckbox(): ICheckbox;
    createTextField(): ITextField;
    createSlider(): ISlider;
}

declare class MacFactory implements IGUIFactory {
    createButton(): IButton;
    createCheckbox(): ICheckbox;
    createTextField(): ITextField;
    createSlider(): ISlider;
}

declare class WebFactory implements IGUIFactory {
    createButton(): IButton;
    createCheckbox(): ICheckbox;
    createTextField(): ITextField;
    createSlider(): ISlider;
}

declare class MobileFactory implements IGUIFactory {
    createButton(): IButton;
    createCheckbox(): ICheckbox;
    createTextField(): ITextField;
    createSlider(): ISlider;
}


const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {
  // This variable will hold the currently selected factory, maintaining state across commands.
  let currentFactory: IGUIFactory | null = null;

  for (const line of lines) {
    const parts = line.split('=');
    const command = parts[0];
    const value = parts[1];

    switch (command) {
      case 'SET_FACTORY':
        // Command to select and instantiate a concrete GUI factory.
        switch (value) {
          case 'Windows':
            currentFactory = new WindowsFactory();
            console.log(`Windows GUI factory selected.`);
            break;
          case 'Mac':
            currentFactory = new MacFactory();
            console.log(`Mac GUI factory selected.`);
            break;
          case 'Web':
            currentFactory = new WebFactory();
            console.log(`Web GUI factory selected.`);
            break;
          case 'Mobile':
            currentFactory = new MobileFactory();
            console.log(`Mobile GUI factory selected.`);
            break;
          default:
            console.log(`Error: Unknown factory type: ${value}`);
            currentFactory = null; // Clear factory on error
        }
        break;

      case 'CREATE_WIDGET':
        // Command to create a specific widget using the currently selected factory.
        if (!currentFactory) {
          console.log('Error: No factory selected. Use SET_FACTORY first.');
          break;
        }
        let widget: IButton | ICheckbox | ITextField | ISlider | null = null;
        switch (value) {
          case 'Button':
            widget = currentFactory.createButton();
            break;
          case 'Checkbox':
            widget = currentFactory.createCheckbox();
            break;
          case 'TextField':
            widget = currentFactory.createTextField();
            break;
          case 'Slider':
            widget = currentFactory.createSlider();
            break;
          default:
            console.log(`Error: Unknown widget type: ${value}`);
            break;
        }
        // If a widget was successfully created, call its render method and print the result.
        if (widget) {
          console.log(widget.render());
        }
        break;

      default:
        console.log(`Error: Unknown command: ${line}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "SET_FACTORY=Windows\nCREATE_WIDGET=Button", "description": "Windows button widget", "expected_output": "Windows GUI factory selected.\nWindows Button created"}, {"input": "SET_FACTORY=Mac\nCREATE_WIDGET=Checkbox", "description": "Mac checkbox widget", "expected_output": "Mac GUI factory selected.\nMac Checkbox created"}, {"input": "SET_FACTORY=Web\nCREATE_WIDGET=TextField", "description": "Web text field widget", "expected_output": "Web GUI factory selected.\nWeb TextField created"}, {"input": "SET_FACTORY=Mobile\nCREATE_WIDGET=Slider", "description": "Mobile slider widget", "expected_output": "Mobile GUI factory selected.\nMobile Slider created"}, {"input": "SET_FACTORY=Windows\nCREATE_WIDGET=Button\nCREATE_WIDGET=Checkbox", "description": "Multiple widgets from the same Windows factory", "expected_output": "Windows GUI factory selected.\nWindows Button created\nWindows Checkbox created"}, {"input": "SET_FACTORY=Mac\nCREATE_WIDGET=TextField\nSET_FACTORY=Mobile\nCREATE_WIDGET=Slider", "description": "Switch factory and create widgets", "expected_output": "Mac GUI factory selected.\nMac TextField created\nMobile GUI factory selected.\nMobile Slider created"}, {"input": "CREATE_WIDGET=Button", "description": "Create widget before setting factory", "expected_output": "Error: No factory selected. Use SET_FACTORY first."}, {"input": "SET_FACTORY=InvalidFactory\nCREATE_WIDGET=Button", "description": "Set invalid factory", "expected_output": "Error: Unknown factory type: InvalidFactory\nError: No factory selected. Use SET_FACTORY first."}, {"input": "SET_FACTORY=Windows\nCREATE_WIDGET=InvalidWidget", "description": "Create invalid widget type", "expected_output": "Windows GUI factory selected.\nError: Unknown widget type: InvalidWidget"}]'::jsonb
WHERE id = 'dp_047';
