const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {
  // ALL user-defined classes (Packet, Strategy, Context, ConcreteStrategy implementations)
  // are available in this scope, as the harness code is appended to user code.

  // To make the tests pass, the user is expected to implement:
  // 1. A 'Packet' class that acts as the prototype, with methods like clone(), setDst(), and toString().
  //    Its constructor should support arguments like (type, src?, dst?, payload?).
  // 2. The 'Context' class, extended from the starter, to hold a 'currentPrototype' Packet
  //    and provide methods like setStrategy(), execute(), setPrototype(Packet | null), and getPrototype(): Packet | null.
  // 3. Concrete Strategy implementations for specific actions: CreatePacketStrategy, ModifyCloneStrategy, BatchCloneStrategy.
  //    Each strategy's execute method should take the Context instance and data specific to the command.

  // Initialize strategy instances. These will be reused by the Context.
  // We assume the user creates these concrete strategy classes.
  const createPacketStrategy = new CreatePacketStrategy();
  const modifyCloneStrategy = new ModifyCloneStrategy();
  const batchCloneStrategy = new BatchCloneStrategy();

  // Instantiate the Context. It will orchestrate operations and maintain the 'current' prototype Packet.
  const context = new Context(); // Assumes Context has a no-arg constructor or can be initialized with a default strategy.

  lines.forEach((line) => {
    try {
      if (line.startsWith('clone packet=')) {
        // Example: clone packet={type: HTTP, src: 192.168.1.1, dst: 10.0.0.1}
        const packetDataString = line.substring('clone packet='.length);
        const cleanedString = packetDataString.replace(/[{}]/g, ''); // Remove braces for easier parsing
        const parts = cleanedString.split(',').map(s => s.trim());
        const packetData: { [key: string]: string } = {};
        parts.forEach(part => {
          const [key, value] = part.split('=').map(s => s.trim());
          if (key && value) { // Ensure both key and value exist
            packetData[key] = value;
          }
        });
        context.setStrategy(createPacketStrategy);
        context.execute(packetData);
      } else if (line.startsWith('modify clone ')) {
        // Example: modify clone dst=10.0.0.2
        const modificationString = line.substring('modify clone '.length);
        const [field, value] = modificationString.split('=').map(s => s.trim());
        if (field && value) { // Ensure both field and value exist
          context.setStrategy(modifyCloneStrategy);
          context.execute({ field, value });
        } else {
          console.log("Invalid modify command format.");
        }
      } else if (line.startsWith('batch_clone ')) {
        // Example: batch_clone count=5 template={type: ICMP}
        const parts = line.substring('batch_clone '.length).split('template=');
        const countPart = parts[0].trim(); // e.g., "count=5"
        // Remove braces from template string and trim
        const templateDataString = parts[1] ? parts[1].replace(/[{}]/g, '').trim() : '';

        const countMatch = countPart.match(/count=(\d+)/);
        const count = countMatch ? parseInt(countMatch[1]) : 0;

        const templateParts = templateDataString.split(',').map(s => s.trim());
        const templateData: { [key: string]: string } = {};
        templateParts.forEach(part => {
          // Note: template uses ':', other commands use '='
          const [key, value] = part.split(':').map(s => s.trim());
          if (key && value) { // Ensure both key and value exist
            templateData[key] = value;
          }
        });

        if (count > 0 && templateData.type) { // Ensure count is positive and template has at least a type
          context.setStrategy(batchCloneStrategy);
          context.execute({ count, ...templateData });
        } else {
          console.log("Invalid batch_clone command format or missing template type.");
        }
      } else {
        console.log(`Unknown command: ${line}`);
      }
    } catch (e: any) {
      // Catch errors during command processing to prevent test harness from crashing
      console.log(`Error processing command '${line}': ${e.message}`);
    }
  });
});$harness$,
  test_cases   = '[{"input": "clone packet={type: HTTP, src: 192.168.1.1, dst: 10.0.0.1}", "description": "Clone HTTP packet and set as prototype", "expected_output": "Packet cloned: HTTP from 192.168.1.1 to 10.0.0.1"}, {"input": "clone packet={type: HTTP, src: 192.168.1.1, dst: 10.0.0.1}\nmodify clone dst=10.0.0.2", "description": "Modify a clone of the current prototype", "expected_output": "Packet cloned: HTTP from 192.168.1.1 to 10.0.0.1\nClone dst updated to 10.0.0.2, original unchanged"}, {"input": "clone packet={type: DNS, payload=query}", "description": "Clone DNS packet and set as new prototype", "expected_output": "Packet cloned: DNS with query payload"}, {"input": "batch_clone count=5 template={type: ICMP}", "description": "Batch clone multiple packets from a template", "expected_output": "5 ICMP packets cloned"}, {"input": "modify clone dst=10.0.0.2", "description": "Attempt to modify a clone when no prototype is set", "expected_output": "Error: No prototype packet to modify."}, {"input": "clone packet={type: FTP, src: 192.168.1.2, dst: 10.0.0.2}\nclone packet={type: TCP, src: 172.16.0.1, dst: 192.168.1.5, payload=SYN}", "description": "Clone multiple packets consecutively, updating the current prototype each time", "expected_output": "Packet cloned: FTP from 192.168.1.2 to 10.0.0.2\nPacket cloned: TCP from 172.16.0.1 to 192.168.1.5 with SYN payload"}, {"input": "batch_clone count=3 template={type: UDP, src: 1.1.1.1}\nclone packet={type: HTTPS, src: 192.168.1.100, dst: 10.0.0.100}\nmodify clone dst=10.0.0.101", "description": "Combined batch clone, then clone new prototype, then modify its clone", "expected_output": "3 UDP packets cloned\nPacket cloned: HTTPS from 192.168.1.100 to 10.0.0.100\nClone dst updated to 10.0.0.101, original unchanged"}]'::jsonb
