-- dp_049: Compression Algorithm Strategy
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // Assume user's Strategy interface, Context class, and concrete strategy classes (RLEStrategy, HuffmanStrategy, LZWStrategy) are available.
  // The harness expects:
  //   interface Strategy { execute(data: unknown): void; }
  //   class Context { setStrategy(strategy: Strategy): void; executeStrategy(data: unknown): void; }
  //   Concrete strategy classes like RLEStrategy, HuffmanStrategy, LZWStrategy implement Strategy and handle console.log() for output.

  const context = new Context();

  // A map to instantiate strategy objects based on their names.
  // We assume these concrete strategy classes are defined by the user and implement the Strategy interface.
  const strategyMap: { [key: string]: Strategy } = {
    'RLE': new RLEStrategy(),
    'huffman': new HuffmanStrategy(),
    'LZW': new LZWStrategy(),
  };

  for (const line of lines) {
    const parts = line.split(' ');
    const command = parts[0];

    switch (command) {
      case 'SET_STRATEGY':
        const strategyName = parts[1];
        const strategyInstance = strategyMap[strategyName];
        if (strategyInstance) {
          context.setStrategy(strategyInstance);
          console.log(`Strategy switched to ${strategyName}`);
        } else {
          console.log(`Error: Unknown strategy '${strategyName}'. Available: ${Object.keys(strategyMap).join(', ')}`);
        }
        break;
      case 'COMPRESS':
        // The data to compress might contain spaces, so join remaining parts.
        // The 'unknown' type in Strategy.execute allows for flexibility, passing string is compatible.
        const dataToCompress: string = parts.slice(1).join(' ');
        try {
          if (context) {
            context.executeStrategy(dataToCompress);
          } else {
            console.log("Error: Context not initialized. This should not happen.");
          }
        } catch (e: any) {
          console.log(`Error during compression: ${e.message}`);
        }
        break;
      default:
        console.log(`Error: Unknown command '${command}'`);
        break;
    }
  }
});$harness$,
  test_cases   = '[{"input": "SET_STRATEGY RLE\nCOMPRESS AABBBCCCC", "description": "RLE compression", "expected_output": "Strategy switched to RLE\nCompressed: A2B3C4 (50% reduction)"}, {"input": "SET_STRATEGY huffman\nCOMPRESS hello world", "description": "Huffman compression", "expected_output": "Strategy switched to huffman\nCompressed with Huffman encoding, 40% reduction"}, {"input": "SET_STRATEGY RLE\nCOMPRESS already_optimal", "description": "Incompressible data", "expected_output": "Strategy switched to RLE\nCompressed: same size (0% reduction)"}, {"input": "SET_STRATEGY LZW", "description": "Switch compression strategy", "expected_output": "Strategy switched to LZW"}]'::jsonb
