-- dp_050: Weather Station Observer Dashboard
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

// Assume user has implemented these classes based on the challenge description
// and test cases (Observer pattern).
// These interfaces/classes are used for type-checking the harness and for the harness
// to instantiate and interact with the user's code.

interface Observer {
  update(data: { station: string, temp?: string, humidity?: string }): string;
  getDisplayType(): string; // e.g., "Screen", "Mobile"
  onSubscribe(stationName: string): string; // Returns the subscription message
}

// User's WeatherStation class (Subject)
// The harness will expect a class named 'WeatherStation'
declare class WeatherStation {
  constructor(name: string);
  subscribe(observer: Observer): void;
  unsubscribe(observer: Observer): void; // Not directly used by tests, but common
  notifyObservers(data: { station: string, temp?: string, humidity?: string }): string[];
}

// User's ScreenDisplay class (Concrete Observer)
// The harness will expect a class named 'ScreenDisplay'
declare class ScreenDisplay implements Observer {
  constructor();
  update(data: { station: string, temp?: string, humidity?: string }): string;
  getDisplayType(): string;
  onSubscribe(stationName: string): string;
}

// User's MobileDisplay class (Concrete Observer)
// The harness will expect a class named 'MobileDisplay'
declare class MobileDisplay implements Observer {
  constructor();
  update(data: { station: string, temp?: string, humidity?: string }): string;
  getDisplayType(): string;
  onSubscribe(stationName: string): string;
}


// --- Test Harness Logic ---
const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {
  const weatherStations = new Map<string, WeatherStation>();
  const displays = new Map<string, Observer>(); // Store displays by type (screen, mobile)

  function parseCommand(line: string): { command: string, args: Record<string, string | undefined> } {
    const parts = line.split(' ');
    const command = parts[0];
    const argString = parts.slice(1).join(' ');
    const args: Record<string, string | undefined> = {};

    argString.split(',').forEach(arg => {
      const [key, value] = arg.trim().split('=');
      if (key && value) {
        args[key.trim()] = value.trim();
      }
    });
    return { command, args };
  }

  for (const line of lines) {
    if (!line) continue;

    const { command, args } = parseCommand(line);

    if (command === 'subscribe') {
      const displayType = args.display?.toLowerCase();
      const stationName = args.station;

      if (!displayType || !stationName) {
        console.error(`Error: Missing display type or station name for subscribe command: ${line}`);
        continue;
      }

      let station = weatherStations.get(stationName);
      if (!station) {
        // Assuming WeatherStation class is provided by the user
        station = new WeatherStation(stationName);
        weatherStations.set(stationName, station);
      }

      let display = displays.get(displayType);
      if (!display) {
        // Assuming ScreenDisplay and MobileDisplay classes are provided by the user
        if (displayType === 'screen') {
          display = new ScreenDisplay();
        } else if (displayType === 'mobile') {
          display = new MobileDisplay();
        } else {
          console.error(`Error: Unknown display type '${displayType}' for subscribe command: ${line}`);
          continue;
        }
        displays.set(displayType, display);
      }
      
      // Subscribe the display to the station
      station.subscribe(display);
      // The subscription message is generated by the display itself
      console.log(display.onSubscribe(stationName));

    } else if (command === 'update') {
      const stationName = args.station;
      const temp = args.temp;
      const humidity = args.humidity;

      if (!stationName) {
        console.error(`Error: Missing station name for update command: ${line}`);
        continue;
      }

      const station = weatherStations.get(stationName);
      if (!station) {
        console.error(`Error: Station '${stationName}' not found for update command: ${line}`);
        continue;
      }

      const notificationMessages = station.notifyObservers({ station: stationName, temp, humidity });
      if (notificationMessages.length > 0) {
        console.log(notificationMessages.join(' | '));
      }

    } else {
      console.error(`Error: Unknown command: ${command}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "subscribe display=screen, station=NYC", "description": "Subscribe display", "expected_output": "Screen display subscribed to NYC station"}, {"input": "subscribe display=screen, station=NYC\nupdate station=NYC, temp=22C, humidity=65%", "description": "Weather update notification", "expected_output": "Screen display subscribed to NYC station\nScreen notified: NYC temp=22C, humidity=65%"}, {"input": "subscribe display=screen, station=NYC\nsubscribe display=mobile, station=NYC", "description": "Subscribe mobile display", "expected_output": "Screen display subscribed to NYC station\nMobile display subscribed to NYC station"}, {"input": "subscribe display=screen, station=NYC\nsubscribe display=mobile, station=NYC\nupdate station=NYC, temp=24C", "description": "Multiple observers notified", "expected_output": "Screen display subscribed to NYC station\nMobile display subscribed to NYC station\nScreen notified: 24C | Mobile notified: 24C"}]'::jsonb
WHERE id = 'dp_050';
-- dp_051: Pizza Topping Factory Kitchen
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', () => {
  // User-defined classes (Context, ConcreteStrategy, etc.) are available in the global scope.

  // We assume the user's Context class can be instantiated without arguments
  // and has a `setStrategy(strategy: Strategy)` method and a `runStrategy(data: unknown)` method.
  // The Strategy interface's `execute` method is assumed to return `void` (as per starter code)
  // and will typically print its output using `console.log()` directly.
  const context: Context = new Context();

  for (const line of lines) {
    if (line.startsWith('USE_STRATEGY')) {
      const strategyClassName = line.substring('USE_STRATEGY '.length).trim();
      try {
        // Dynamically access the class constructor from the global scope.
        const StrategyClass = (globalThis as any)[strategyClassName];

        if (typeof StrategyClass !== 'function' || !StrategyClass.prototype || !('execute' in StrategyClass.prototype)) {
          console.error(`Error: Strategy class '${strategyClassName}' not found or does not conform to the Strategy interface.`);
          break; // Stop processing further commands
        }
        if (typeof StrategyClass.prototype.execute !== 'function') {
            console.error(`Error: Strategy class '${strategyClassName}' has a non-function 'execute' method.`);
            break; // Stop processing further commands
        }

        // Instantiate and set the strategy in the context.
        const strategyInstance: Strategy = new StrategyClass();
        context.setStrategy(strategyInstance);
        // No direct output from the harness for this command; it's a setup step.
      } catch (error: any) {
        console.error(`Harness error setting strategy '${strategyClassName}': ${error.message}`);
        break; // Stop processing further commands
      }
    } else if (line.startsWith('EXECUTE')) {
      const jsonString = line.substring('EXECUTE '.length).trim();
      try {
        const data: unknown = JSON.parse(jsonString);
        // Execute the current strategy. The strategy itself is expected to print output.
        context.runStrategy(data);
      } catch (error: any) {
        if (error.message && error.message.includes("No strategy has been set")) {
            console.error(`Harness error: No strategy set before EXECUTE. Make sure to use USE_STRATEGY first.`);
        } else if (error instanceof SyntaxError) {
            console.error(`Harness error parsing JSON data: ${error.message}. Input was: ${jsonString}`);
        } else {
            console.error(`Harness error executing strategy: ${error.message}`);
        }
        break; // Stop processing if execution fails
      }
    } else if (line === "") {
        // Ignore empty lines
    } else {
      console.error(`Harness error: Unknown command '${line}'.`);
      break; // Stop processing for unknown commands
    }
  }
});$harness$,
  test_cases   = '[{"input": "USE_STRATEGY MargheritaStrategy\nEXECUTE {\"pizza\":\"margherita\", \"toppings\":[\"cheese\", \"tomato\"]}", "description": "Create margherita", "expected_output": "Margherita pizza with cheese, tomato created"}, {"input": "USE_STRATEGY PepperoniStrategy\nEXECUTE {\"pizza\":\"pepperoni\", \"toppings\":[\"cheese\", \"pepperoni\", \"olives\"]}", "description": "Create pepperoni pizza", "expected_output": "Pepperoni pizza with cheese, pepperoni, olives created"}, {"input": "USE_STRATEGY ItalianFactoryStrategy\nEXECUTE {\"factory\":\"italian\", \"pizza\":\"calzone\"}", "description": "Italian factory calzone", "expected_output": "Italian-style calzone created"}, {"input": "USE_STRATEGY AmericanFactoryStrategy\nEXECUTE {\"factory\":\"american\", \"pizza\":\"deep_dish\"}", "description": "American factory deep dish", "expected_output": "American-style deep dish created"}, {"input": "EXECUTE {\"pizza\":\"invalid\"}", "description": "Execute without setting strategy", "expected_output": "Harness error: No strategy set before EXECUTE. Make sure to use USE_STRATEGY first."}, {"input": "USE_STRATEGY NonExistentStrategy\nEXECUTE {\"pizza\":\"test\"}", "description": "Attempt to use a non-existent strategy", "expected_output": "Harness error setting strategy ''NonExistentStrategy'': Strategy class ''NonExistentStrategy'' not found or does not conform to the Strategy interface."}, {"input": "USE_STRATEGY MargheritaStrategy\nEXECUTE {\"pizza\":\"margherita\", \"toppings\":[\"cheese\", \"tomato\"}\nEXECUTE {\"pizza\":\"margherita\"}", "description": "Execute with invalid JSON", "expected_output": "Margherita pizza with cheese, tomato created\nHarness error parsing JSON data: Expected ''}'' after property list in JSON at position 47. Input was: {\"pizza\":\"margherita\", \"toppings\":[\"cheese\", \"tomato\"}"}]'::jsonb
