-- dp_052: Character Sheet Builder RPG
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', () => {
  // The Context class and ConcreteStrategy classes are expected to be implemented by the user
  // based on the starter code and the Strategy design pattern principles.

  // The harness expects the user's Context class to have:
  // 1. A constructor: `constructor(initialData: any)` that accepts an object to initialize the character sheet state.
  // 2. A method: `setStrategy(strategy: Strategy): void` to set the currently active strategy.
  // 3. A method: `executeStrategy(): void` which internally calls `this.currentStrategy.execute(this.characterData);`

  // The harness expects the user to implement specific Concrete Strategy classes:
  // - `ConcreteSetNameClassStrategy(name: string, charClass: string)` for `set name=X, class=Y` commands.
  // - `ConcreteSetStatsStrategy(strength: number, dexterity: number, intelligence: number)` for `set strength=X, dexterity=Y, intelligence=Z` commands.
  // - `ConcreteAddSkillStrategy(skillName: string, skillLevel: number)` for `add skill=X, level=Y` commands.
  // - `ConcreteBuildSheetStrategy()` for `build_sheet` commands.
  // Each strategy's `execute(characterData: any)` method should modify the passed `characterData` object in-place
  // and print its output directly using `console.log()`.

  const initialCharacterSheetState: any = {
    name: 'Unnamed',
    charClass: 'Adventurer',
    strength: 0,
    dexterity: 0,
    intelligence: 0,
    skills: new Map<string, number>() // Using Map to store skills for easy update/retrieval
  };

  // Instantiate the user's Context class with the initial character sheet state.
  const characterContext = new Context(initialCharacterSheetState);

  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    const [commandType, ...rest] = line.split(' ');
    const paramsString = rest.join(' ');

    let strategy: Strategy | null = null;

    try {
      if (commandType === 'set') {
        if (paramsString.includes('name=') && paramsString.includes('class=')) {
          const nameMatch = paramsString.match(/name=([^,]+)/);
          const classMatch = paramsString.match(/class=([^,]+)/);
          if (nameMatch && classMatch) {
            strategy = new ConcreteSetNameClassStrategy(nameMatch[1].trim(), classMatch[1].trim());
          } else {
            console.log(`Error: Invalid 'set name/class' command format: ${line}`);
          }
        } else if (paramsString.includes('strength=') && paramsString.includes('dexterity=') && paramsString.includes('intelligence=')) {
          const strMatch = paramsString.match(/strength=(\d+)/);
          const dexMatch = paramsString.match(/dexterity=(\d+)/);
          const intMatch = paramsString.match(/intelligence=(\d+)/);
          if (strMatch && dexMatch && intMatch) {
            strategy = new ConcreteSetStatsStrategy(
              parseInt(strMatch[1]),
              parseInt(dexMatch[1]),
              parseInt(intMatch[1])
            );
          } else {
            console.log(`Error: Invalid 'set stats' command format: ${line}`);
          }
        } else {
          console.log(`Error: Unknown 'set' command type or format: ${line}`);
        }
      } else if (commandType === 'add') {
        if (paramsString.includes('skill=')) {
          const skillMatch = paramsString.match(/skill=([^,]+)/);
          const levelMatch = paramsString.match(/level=(\d+)/);
          if (skillMatch && levelMatch) {
            strategy = new ConcreteAddSkillStrategy(skillMatch[1].trim(), parseInt(levelMatch[1]));
          } else {
            console.log(`Error: Invalid 'add skill' command format: ${line}`);
          }
        } else {
          console.log(`Error: Unknown 'add' command type or format: ${line}`);
        }
      } else if (commandType === 'build_sheet') {
        strategy = new ConcreteBuildSheetStrategy();
      } else {
        console.log(`Error: Unknown command "${commandType}"`);
      }

      if (strategy) {
        characterContext.setStrategy(strategy);
        characterContext.executeStrategy(); // Context executes the currently set strategy
      }
    } catch (e: any) {
      // Catch and report errors during strategy execution to provide feedback.
      console.log(`Execution Error for command "${line}": ${e.message}`);
    }
  }
});

// Handle potential readline errors
rl.on('error', (err) => {
  console.error('Readline error:', err);
});$harness$,
  test_cases   = '[{"input": "set name=Aragorn, class=Ranger", "description": "Set character basics", "expected_output": "Character Aragorn (Ranger) initialized"}, {"input": "set name=Aragorn, class=Ranger\nset strength=18, dexterity=16, intelligence=12", "description": "Set character stats", "expected_output": "Character Aragorn (Ranger) initialized\nStats set: STR 18, DEX 16, INT 12"}, {"input": "set name=Aragorn, class=Ranger\nset strength=18, dexterity=16, intelligence=12\nadd skill=Archery, level=5", "description": "Add character skill", "expected_output": "Character Aragorn (Ranger) initialized\nStats set: STR 18, DEX 16, INT 12\nSkill Archery (level 5) added"}, {"input": "set name=Aragorn, class=Ranger\nset strength=18, dexterity=16, intelligence=12\nadd skill=Archery, level=5\nbuild_sheet", "description": "Build final character sheet", "expected_output": "Character Aragorn (Ranger) initialized\nStats set: STR 18, DEX 16, INT 12\nSkill Archery (level 5) added\nCharacter sheet built: Aragorn, Ranger, STR 18, DEX 16, INT 12, Skills: Archery"}, {"input": "set name=Legolas, class=Elf\nbuild_sheet", "description": "Build sheet with only name and class set (default stats expected)", "expected_output": "Character Legolas (Elf) initialized\nCharacter sheet built: Legolas, Elf, STR 0, DEX 0, INT 0"}, {"input": "set name=Gandalf, class=Wizard\nadd skill=Magic, level=10\nadd skill=Swordplay, level=5\nadd skill=Magic, level=12\nbuild_sheet", "description": "Add multiple skills and verify skill overwrite and final sheet output", "expected_output": "Character Gandalf (Wizard) initialized\nSkill Magic (level 10) added\nSkill Swordplay (level 5) added\nSkill Magic (level 12) added\nCharacter sheet built: Gandalf, Wizard, STR 0, DEX 0, INT 0, Skills: Magic, Swordplay"}, {"input": "set name=Bob, class=Warrior\nset name=Alice, class=Rogue\nbuild_sheet", "description": "Overwrite character name and class and build sheet", "expected_output": "Character Bob (Warrior) initialized\nCharacter Alice (Rogue) initialized\nCharacter sheet built: Alice, Rogue, STR 0, DEX 0, INT 0"}, {"input": "set name=Gimli, class=Dwarf\nset strength=20, dexterity=10, intelligence=8\nset strength=19, dexterity=9, intelligence=7\nbuild_sheet", "description": "Overwrite character stats and build sheet", "expected_output": "Character Gimli (Dwarf) initialized\nStats set: STR 20, DEX 10, INT 8\nStats set: STR 19, DEX 9, INT 7\nCharacter sheet built: Gimli, Dwarf, STR 19, DEX 9, INT 7"}, {"input": "unknown_command param=value", "description": "Handle unknown command gracefully", "expected_output": "Error: Unknown command \"unknown_command\""}, {"input": "set name=Frodo", "description": "Handle malformed set command gracefully", "expected_output": "Error: Unknown ''set'' command type or format: set name=Frodo"}]'::jsonb
