-- dp_053: Middleware Stack Decorator
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // The harness expects the user to implement the `Strategy` interface and `Context` / `ConcreteStrategy` classes.
  // The `Strategy` interface is expected to be augmented by the user to include `next` for middleware chains:
  // `interface Strategy { execute(data: unknown, next?: (data: unknown) => void): void; }`
  // The `ConcreteStrategy` class is expected to have:
  // - A constructor that accepts `name: string` and an optional `message?: string`.
  // - An `execute` method that adheres to the augmented `Strategy` interface.
  // - An optional `configure(key: string, value: string)` method for dynamic configuration.
  // The `Context` class is expected to have:
  // - A constructor that takes no arguments initially.
  // - A `setHandler(handler: Strategy)` method to set the final request handler.
  // - An `addMiddleware(middleware: Strategy, position?: number)` method to add middleware to the stack.
  // - An `execute(data: unknown)` method that orchestrates the middleware chain and the final handler.

  // Harness wrapper for user's Strategy instances. This class implements the `Strategy` interface
  // and acts as the actual Strategy objects that the user's `Context` will interact with.
  // It allows the harness to configure and control behavior (like blocking a request) while
  // delegating the actual processing logic to the user's `ConcreteStrategy` instance.
  class HarnessStrategyWrapper implements Strategy {
    public name: string;
    private config: Map<string, string> = new Map();
    private shouldBlock: boolean = false;
    private isHandler: boolean = false; // True if this wrapper represents the final handler
    private userConcreteStrategy: ConcreteStrategy; // The actual user-implemented Strategy instance

    /**
     * Creates a wrapper for a user's ConcreteStrategy instance.
     * Assumes ConcreteStrategy constructor takes (name: string, message?: string).
     * @param name The identifying name for this strategy.
     * @param defaultMessage An optional message for the user's strategy to use.
     * @param isHandler True if this wrapper represents the final handler, false for middleware.
     */
    constructor(name: string, defaultMessage?: string, isHandler: boolean = false) {
      this.name = name;
      this.isHandler = isHandler;
      // Instantiate the user's ConcreteStrategy class. This relies on the user defining it.
      // We pass the name and message for the user's strategy to initialize itself.
      this.userConcreteStrategy = new ConcreteStrategy(name, defaultMessage);
    }

    /**
     * Configures the behavior of this wrapper (e.g., blocking) and passes relevant config
     * to the underlying user's ConcreteStrategy instance if it supports a `configure` method.
     * @param key The configuration key (e.g., "blocksRequest").
     * @param value The configuration value (e.g., "true").
     */
    configure(key: string, value: string): void {
      this.config.set(key, value);
      if (key === "blocksRequest") {
        this.shouldBlock = (value === "true");
      }
      // If the user's ConcreteStrategy also has a `configure` method, call it.
      // This allows the user's strategy to handle its own specific configurations.
      if (typeof (this.userConcreteStrategy as any).configure === 'function') {
        (this.userConcreteStrategy as any).configure(key, value);
      }
    }

    /**
     * Executes the strategy logic. This is the method the user's Context will call
     * for each Strategy in its chain. It applies harness-specific logic (like blocking)
     * then delegates to the user's ConcreteStrategy's `execute` method.
     * @param data The request data being processed.
     * @param next The callback function to call the next strategy in the chain.
     */
    execute(data: unknown, next?: (data: unknown) => void): void {
      if (this.isHandler) {
        // If this is the final handler, directly execute the user's handler logic.
        // The user's handler is expected to produce the final output for the request
        // and should not call `next`.
        (this.userConcreteStrategy as any).execute(data);
        return;
      }

      // Logic for middleware:
      if (this.shouldBlock) {
        console.log(`${this.name} middleware blocked request: 401`);
        return; // Stop the chain here by not calling next
      }

      // Log the execution flow for middleware (e.g., "auth -> ").
      // The user's ConcreteStrategy is expected to process the data and then call `next(data)`
      // if the chain should continue.
      console.log(`${this.name} -> `);
      (this.userConcreteStrategy as any).execute(data, next);
    }
  }

  // --- Harness state and main logic --- 
  let currentContext: Context | null = null;
  // Stores HarnessStrategyWrapper instances by their names. These are the objects
  // that implement `Strategy` and are passed to the user's `Context`.
  const knownStrategies: Map<string, HarnessStrategyWrapper> = new Map();

  for (const line of lines) {
    const parts = line.split(' ');
    const command = parts[0];

    try {
      if (command === "CREATE_HANDLER") {
        // Command: CREATE_HANDLER <handlerName> [message]
        const handlerName = parts[1];
        const defaultMessage = parts.length > 2 ? parts.slice(2).join(' ') : undefined;
        const wrapper = new HarnessStrategyWrapper(handlerName, defaultMessage, true); // Mark as handler
        knownStrategies.set(handlerName, wrapper);
      } else if (command === "CREATE_MIDDLEWARE") {
        // Command: CREATE_MIDDLEWARE <middlewareName> [message]
        const middlewareName = parts[1];
        const defaultMessage = parts.length > 2 ? parts.slice(2).join(' ') : undefined;
        const wrapper = new HarnessStrategyWrapper(middlewareName, defaultMessage, false); // Mark as middleware
        knownStrategies.set(middlewareName, wrapper);
      } else if (command === "BUILD_STACK") {
        // Command: BUILD_STACK <handlerName> [middleware1,middleware2,...]
        const handlerName = parts[1];
        const middlewareNames = parts[2] ? parts[2].split(',') : [];

        const handlerWrapper = knownStrategies.get(handlerName);
        if (!handlerWrapper) {
          console.log(`Error: Handler '${handlerName}' not found.`);
          continue;
        }

        // Instantiate the user's Context class.
        // Assumes Context has a constructor that takes no arguments initially.
        currentContext = new Context();
        // Set the handler in the user's Context. Assumes `setHandler` method exists.
        (currentContext as any).setHandler(handlerWrapper);

        for (const mwName of middlewareNames) {
          const mwWrapper = knownStrategies.get(mwName);
          if (!mwWrapper) {
            console.log(`Error: Middleware '${mwName}' not found.`);
            currentContext = null; // Invalidate context if building fails
            break;
          }
          // Add middleware to the user's Context. Assumes `addMiddleware` method exists.
          (currentContext as any).addMiddleware(mwWrapper);
        }

      } else if (command === "ADD_MIDDLEWARE") {
        // Command: ADD_MIDDLEWARE <middlewareName> [at position=<index>]
        if (!currentContext) {
          console.log("Error: Context not built yet. Use BUILD_STACK first.");
          continue;
        }
        const middlewareName = parts[1];
        const atPositionMatch = line.match(/at position=(\d+)/);
        const position = atPositionMatch ? parseInt(atPositionMatch[1], 10) : undefined;

        const mwWrapper = knownStrategies.get(middlewareName);
        if (!mwWrapper) {
          console.log(`Error: Middleware '${middlewareName}' not found.`);
          continue;
        }
        // Add middleware to the user's Context. Assumes `addMiddleware` method exists.
        (currentContext as any).addMiddleware(mwWrapper, position);
        if (position !== undefined) {
          console.log(`${middlewareName} added at position ${position} in stack`);
        } else {
          console.log(`${middlewareName} added to stack`);
        }

      } else if (command === "CONFIGURE_STRATEGY") {
        // Command: CONFIGURE_STRATEGY <strategyName> <key>=<value>
        const strategyName = parts[1];
        const configPair = parts[2].split('=');
        const key = configPair[0];
        const value = configPair[1];

        const wrapper = knownStrategies.get(strategyName);
        if (!wrapper) {
          console.log(`Error: Strategy '${strategyName}' not found.`);
          continue;
        }
        wrapper.configure(key, value);

      } else if (command === "RUN_REQUEST") {
        // Command: RUN_REQUEST <requestData>
        if (!currentContext) {
          console.log("Error: Context not built yet. Use BUILD_STACK first.");
          continue;
        }
        const requestData = parts.slice(1).join(' ');
        currentContext.execute(requestData);
      } else {
        console.log(`Unknown command: ${command}`);
      }
    } catch (e: any) {
      console.log(`Harness error processing command '\u001b[31m${line}\u001b[0m': ${e.message}`);
      // console.error(e); // Uncomment for local harness debugging
    }
  }
});$harness$,
  test_cases   = '[{"input": "CREATE_HANDLER handler \"handler executed\"\nCREATE_MIDDLEWARE auth\nCREATE_MIDDLEWARE logging\nCREATE_MIDDLEWARE cors\nBUILD_STACK handler auth,logging,cors\nRUN_REQUEST GET /api", "description": "Middleware chain execution", "expected_output": "auth -> \nlogging -> \ncors -> \nhandler executed"}, {"input": "CREATE_HANDLER handler \"handler executed\"\nCREATE_MIDDLEWARE auth\nCREATE_MIDDLEWARE logging\nBUILD_STACK handler auth,logging\nCONFIGURE_STRATEGY auth blocksRequest=true\nRUN_REQUEST GET /api", "description": "Auth middleware blocks request", "expected_output": "auth middleware blocked request: 401"}, {"input": "CREATE_HANDLER handler \"handler executed\"\nCREATE_MIDDLEWARE auth\nCREATE_MIDDLEWARE logging\nCREATE_MIDDLEWARE cors\nBUILD_STACK handler auth,logging,cors\nCREATE_MIDDLEWARE rate_limiter\nADD_MIDDLEWARE rate_limiter at position=1\nRUN_REQUEST GET /api", "description": "Add middleware to stack", "expected_output": "rate_limiter added at position 1 in stack\nauth -> \nrate_limiter -> \nlogging -> \ncors -> \nhandler executed"}, {"input": "CREATE_HANDLER handler \"Request passed directly to handler\"\nBUILD_STACK handler\nRUN_REQUEST GET /api", "description": "Empty middleware stack", "expected_output": "Request passed directly to handler"}, {"input": "CREATE_HANDLER final_response \"Final response: OK\"\nCREATE_MIDDLEWARE mw1\nCREATE_MIDDLEWARE mw2\nCREATE_MIDDLEWARE mw3\nBUILD_STACK final_response mw1,mw2,mw3\nCONFIGURE_STRATEGY mw2 blocksRequest=true\nRUN_REQUEST POST /data", "description": "Middleware in middle blocks request", "expected_output": "mw1 -> \nmw2 middleware blocked request: 401"}, {"input": "CREATE_HANDLER final_handler \"Request handled\"\nCREATE_MIDDLEWARE logging\nCREATE_MIDDLEWARE auth\nBUILD_STACK final_handler\nADD_MIDDLEWARE logging\nADD_MIDDLEWARE auth at position=0\nRUN_REQUEST /status", "description": "Dynamically add middleware to an empty stack", "expected_output": "logging added to stack\nauth added at position 0 in stack\nauth -> \nlogging -> \nRequest handled"}, {"input": "CREATE_HANDLER default_handler \"Default handler ran\"\nCREATE_MIDDLEWARE validator\nCREATE_MIDDLEWARE sanitizer\nCREATE_MIDDLEWARE cache\nBUILD_STACK default_handler validator,sanitizer\nADD_MIDDLEWARE cache at position=1\nRUN_REQUEST /item/123", "description": "Verify middleware order after insertion", "expected_output": "cache added at position 1 in stack\nvalidator -> \ncache -> \nsanitizer -> \nDefault handler ran"}]'::jsonb
