-- dp_054: Firewall Rule Proxy Guard
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // The user's starter code includes:
  // interface Strategy { execute(data: unknown): void; }
  // class Context { // TODO: hold strategy and run it }
  // class ConcreteStrategy implements Strategy { // TODO: implement }

  // This harness assumes the user will implement the Context class with:
  // - a constructor that takes an initial Strategy: `constructor(initialStrategy: Strategy)`
  // - a method to set the current strategy: `public setStrategy(strategy: Strategy): void`
  // - a method to execute the current strategy: `public executeStrategy(data: unknown): void` (calls strategy.execute)
  // - methods to manage firewall rules: `public addRule(rule: string): void`, `public getRules(): string[]`, `public clearRules(): void`
  // The 'ConcreteStrategy' from the starter code is a generic name. This harness defines its own concrete strategies
  // (HarnessAddRuleStrategy, HarnessCheckRequestStrategy) that implement the `Strategy` interface and interact
  // with the user's Context methods to manage state and perform operations.

  // A minimal strategy for Context constructor, doesn't perform any actual operation.
  class NoOpStrategy implements Strategy {
    execute(data: unknown): void {
      // No operation performed. No output needed.
    }
  }

  // Defines the expected structure for a firewall request, parsed from input string.
  interface FirewallRequest {
    src: string;
    port: number;
    proto?: string;
  }

  // Harness-defined concrete strategy for adding firewall rules.
  class HarnessAddRuleStrategy implements Strategy {
    private contextInstance: Context;

    constructor(context: Context) {
      this.contextInstance = context;
    }

    execute(data: unknown): void {
      if (typeof data === 'string' && data.startsWith('add_rule')) {
        const ruleData = data.substring('add_rule '.length); // e.g., "allow src=10.0.0.0/8 port=443"
        this.contextInstance.addRule(ruleData);
        console.log(`Rule added: ${ruleData}`);
      } else {
        console.log('Error: Invalid add rule command format.');
      }
    }
  }

  // Harness-defined concrete strategy for checking firewall requests.
  class HarnessCheckRequestStrategy implements Strategy {
    private contextInstance: Context;

    constructor(context: Context) {
      this.contextInstance = context;
    }

    execute(data: unknown): void {
      const request = data as FirewallRequest; // Assumed data is already parsed into FirewallRequest

      // Retrieve current firewall rules from the user's Context.
      const rules = this.contextInstance.getRules();

      // Hardcoded rules (from problem description/initial test cases) take precedence.
      if (request.proto === 'SSH' && request.port === 22) {
        console.log('Request blocked by firewall rule: SSH denied');
        return;
      }
      if (request.src === 'blacklisted_ip') {
        console.log('Request blocked: IP blacklisted');
        return;
      }

      // Check against dynamically added rules.
      for (const rule of rules) {
        if (rule.startsWith('allow')) {
          const ruleDetails = rule.substring('allow '.length); // e.g., "src=10.0.0.0/8 port=443"
          const parts = ruleDetails.split(' ');
          let srcMatch = true;
          let portMatch = true;

          for (const part of parts) {
            if (part.startsWith('src=')) {
              const ruleSrc = part.substring(4); // e.g., "10.0.0.0/8" or "192.168.1.50"
              if (ruleSrc.includes('/')) {
                const [baseIp, cidrStr] = ruleSrc.split('/');
                const cidr = parseInt(cidrStr, 10);
                let ipMatchesCidr = false;

                // Simple CIDR matching logic for common prefixes.
                if (cidr === 8) { // e.g., 10.0.0.0/8
                  if (request.src.startsWith(baseIp.split('.')[0] + '.')) {
                    ipMatchesCidr = true;
                  }
                } else if (cidr === 16) { // e.g., 172.16.0.0/16
                  const prefix = baseIp.split('.').slice(0, 2).join('.');
                  if (request.src.startsWith(prefix + '.')) {
                    ipMatchesCidr = true;
                  }
                } else if (cidr === 24) { // e.g., 192.168.1.0/24
                  const prefix = baseIp.split('.').slice(0, 3).join('.');
                  if (request.src.startsWith(prefix + '.')) {
                    ipMatchesCidr = true;
                  }
                }
                if (!ipMatchesCidr) {
                  srcMatch = false;
                }
              } else if (request.src !== ruleSrc) { // Exact IP match
                srcMatch = false;
              }
            }
            if (part.startsWith('port=')) {
              const rulePort = parseInt(part.substring(5), 10);
              if (request.port !== rulePort) {
                portMatch = false;
              }
            }
          }
          if (srcMatch && portMatch) {
            console.log('Request allowed by firewall rules');
            return;
          }
        }
      }

      // Default allow for specific HTTP request based on initial test case.
      if (request.src === '10.0.0.1' && request.port === 80 && request.proto === 'HTTP') {
        console.log('Request allowed by firewall rules');
        return;
      }

      // If no explicit allow or block rules were met, then default to blocking.
      console.log('Request blocked by default policy');
    }
  }

  // Instantiate the user's Context object, providing an initial no-op strategy.
  const firewallContext = new Context(new NoOpStrategy());

  // Instantiate harness-defined concrete strategy objects, injecting the user's Context.
  const addRuleStrategy = new HarnessAddRuleStrategy(firewallContext);
  const checkRequestStrategy = new HarnessCheckRequestStrategy(firewallContext);

  // Process each command line from stdin.
  for (const line of lines) {
    if (line.startsWith('add_rule')) {
      firewallContext.setStrategy(addRuleStrategy);
      firewallContext.executeStrategy(line);
    } else if (line.startsWith('request=')) {
      firewallContext.setStrategy(checkRequestStrategy);
      const requestString = line.substring('request='.length);
      const parsedRequest: FirewallRequest = parseRequestString(requestString);
      firewallContext.executeStrategy(parsedRequest);
    } else if (line.startsWith('reset_firewall')) {
      // This is a harness-specific command to clear rules for stateful tests.
      firewallContext.clearRules();
      console.log('Firewall rules reset.');
    } else {
      console.log(`Error: Unknown command "${line}"`);
    }
  }

  // Helper function to parse a request string into a structured object.
  function parseRequestString(reqStr: string): FirewallRequest {
    // Remove outer braces: {src: 10.0.0.1, port: 80, proto: HTTP}
    const inner = reqStr.replace(/\{|\}/g, '').trim();
    const parts = inner.split(',').map(s => s.trim());
    const request: Partial<FirewallRequest> = {};

    for (const part of parts) {
      const [key, value] = part.split(':').map(s => s.trim());
      if (key === 'src') {
        request.src = value;
      } else if (key === 'port') {
        request.port = parseInt(value, 10);
      } else if (key === 'proto') {
        request.proto = value;
      }
    }
    return request as FirewallRequest;
  }
});$harness$,
  test_cases   = '[{"input": "request={src: 10.0.0.1, port: 80, proto: HTTP}", "description": "Allowed HTTP request by default policy", "expected_output": "Request allowed by firewall rules"}, {"input": "request={src: 192.168.1.100, port: 22, proto: SSH}", "description": "Blocked SSH request by hardcoded rule", "expected_output": "Request blocked by firewall rule: SSH denied"}, {"input": "request={src: blacklisted_ip, port: 443}", "description": "Blacklisted IP blocked by hardcoded rule", "expected_output": "Request blocked: IP blacklisted"}, {"input": "add_rule allow src=10.0.0.0/8 port=443", "description": "Add a new firewall rule", "expected_output": "Rule added: allow src=10.0.0.0/8 port=443"}, {"input": "add_rule allow src=192.168.1.0/24 port=80\nrequest={src: 192.168.1.50, port: 80, proto: HTTP}", "description": "Request allowed by dynamically added CIDR rule", "expected_output": "Rule added: allow src=192.168.1.0/24 port=80\nRequest allowed by firewall rules"}, {"input": "add_rule allow src=192.168.1.0/24 port=80\nrequest={src: 192.168.2.50, port: 80, proto: HTTP}", "description": "Request blocked: IP outside dynamic CIDR rule", "expected_output": "Rule added: allow src=192.168.1.0/24 port=80\nRequest blocked by default policy"}, {"input": "add_rule allow src=192.168.1.0/24 port=80\nrequest={src: 192.168.1.50, port: 443, proto: HTTPS}", "description": "Request blocked: Port mismatch with dynamic rule", "expected_output": "Rule added: allow src=192.168.1.0/24 port=80\nRequest blocked by default policy"}, {"input": "add_rule allow src=10.0.0.0/8 port=8080\nrequest={src: 10.0.0.5, port: 8080, proto: HTTP}\nadd_rule allow src=172.16.0.0/16 port=80\nrequest={src: 172.16.1.1, port: 80, proto: HTTP}\nrequest={src: 192.168.0.1, port: 80, proto: HTTP}", "description": "Multiple dynamic rules and a default block", "expected_output": "Rule added: allow src=10.0.0.0/8 port=8080\nRequest allowed by firewall rules\nRule added: allow src=172.16.0.0/16 port=80\nRequest allowed by firewall rules\nRequest blocked by default policy"}, {"input": "add_rule allow src=blacklisted_ip port=80\nrequest={src: blacklisted_ip, port: 80, proto: HTTP}", "description": "Hardcoded blacklist takes precedence over dynamic allow", "expected_output": "Rule added: allow src=blacklisted_ip port=80\nRequest blocked: IP blacklisted"}, {"input": "add_rule allow src=10.0.0.0/8 port=8080\nrequest={src: 10.0.0.5, port: 8080, proto: HTTP}\nreset_firewall\nrequest={src: 10.0.0.5, port: 8080, proto: HTTP}", "description": "Firewall rules can be reset", "expected_output": "Rule added: allow src=10.0.0.0/8 port=8080\nRequest allowed by firewall rules\nFirewall rules reset.\nRequest blocked by default policy"}]'::jsonb
