-- dp_055: Feature Flag Singleton Store
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin
});

const lines: string[] = [];
rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', () => {
  // The singleton instance of the user's FeatureFlagStore
  let store: any = null; 

  for (const line of lines) {
    if (line === '') continue; // Skip empty lines

    if (line === 'get_instance') {
      // Ensure FeatureFlagStore class and its static getInstance method exist
      if (typeof (global as any).FeatureFlagStore !== 'function' || typeof (global as any).FeatureFlagStore.getInstance !== 'function') {
        console.log("Error: User's FeatureFlagStore class or its static getInstance() method not found. Ensure it's globally accessible and implements a static getInstance().");
        continue;
      }
      store = (global as any).FeatureFlagStore.getInstance();
    } else if (line.startsWith('set_flag')) {
      const commandArgs = line.substring('set_flag '.length).split(', ');
      let featureName: string | undefined;
      let enabledStr: string | undefined;

      for (const arg of commandArgs) {
        if (arg.startsWith('feature=')) {
          featureName = arg.substring('feature='.length);
        } else if (arg.startsWith('enabled=')) {
          enabledStr = arg.substring('enabled='.length);
        }
      }

      if (!store) {
        console.log("Error: Feature flag store not initialized. Call 'get_instance' first to create/retrieve the singleton.");
      } else if (featureName && enabledStr !== undefined) {
        const enabled = enabledStr === 'true';
        // Ensure the store instance has a setFlag method
        if (typeof store.setFlag !== 'function') {
            console.log("Error: setFlag() method not found on the FeatureFlagStore instance.");
            continue;
        }
        store.setFlag(featureName, enabled);
      } else {
        console.log("Error: Invalid 'set_flag' command format. Expected 'set_flag feature=<name>, enabled=<true|false>'.");
      }
    } else if (line.startsWith('get_flag')) {
      const commandArgs = line.substring('get_flag '.length).split('=');
      if (commandArgs.length === 2 && commandArgs[0] === 'feature') {
        const featureName = commandArgs[1];
        if (!store) {
          console.log("Error: Feature flag store not initialized. Call 'get_instance' first to create/retrieve the singleton.");
        } else {
            // Ensure the store instance has a getFlag method
            if (typeof store.getFlag !== 'function') {
                console.log("Error: getFlag() method not found on the FeatureFlagStore instance.");
                continue;
            }
            // The user's getFlag method is expected to print the result to stdout.
            store.getFlag(featureName);
        }
      } else {
        console.log("Error: Invalid 'get_flag' command format. Expected 'get_flag feature=<name>'.");
      }
    } else {
      console.log(`Unknown command: ${line}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "get_instance", "description": "Get singleton instance for the first time, ensuring creation message", "expected_output": "Feature flag store singleton created"}, {"input": "get_instance\nget_instance", "description": "Ensure the same singleton instance is returned on subsequent calls", "expected_output": "Feature flag store singleton created\nReturning existing singleton store"}, {"input": "get_instance\nset_flag feature=dark_mode, enabled=true", "description": "Enable a feature flag and check its set message", "expected_output": "Feature flag store singleton created\nFeature flag dark_mode set to true"}, {"input": "get_instance\nset_flag feature=dark_mode, enabled=true\nget_flag feature=dark_mode", "description": "Set and then get an enabled feature flag", "expected_output": "Feature flag store singleton created\nFeature flag dark_mode set to true\ndark_mode: enabled"}, {"input": "get_instance\nset_flag feature=beta_features, enabled=false", "description": "Disable a feature flag and check its set message", "expected_output": "Feature flag store singleton created\nFeature flag beta_features set to false"}, {"input": "get_instance\nset_flag feature=beta_features, enabled=false\nget_flag feature=beta_features", "description": "Set and then get a disabled feature flag", "expected_output": "Feature flag store singleton created\nFeature flag beta_features set to false\nbeta_features: disabled"}, {"input": "get_instance\nget_flag feature=non_existent_flag", "description": "Attempt to get a feature flag that has not been set", "expected_output": "Feature flag store singleton created\nnon_existent_flag: not found"}, {"input": "get_instance\nset_flag feature=admin_panel, enabled=true\nset_flag feature=admin_panel, enabled=false\nget_flag feature=admin_panel", "description": "Update a feature flag''s state and then get its new state", "expected_output": "Feature flag store singleton created\nFeature flag admin_panel set to true\nFeature flag admin_panel set to false\nadmin_panel: disabled"}]'::jsonb
