-- dp_056: Undo Redo Command Processor
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

const lines: string[] = [];
rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', () => {
  // Cr4ck's internal TextEditor (Receiver) for user's commands
  // This class is provided by the test harness and available to user code.
  class Cr4ckTextEditor {
      private content: string = "";
      private boldedSelections: Set<string> = new Set(); // Tracks what's currently bolded

      /**
       * Appends text to the editor's content.
       * @param text The string to type.
       * @returns A log message describing the action.
       */
      type(text: string): string {
          this.content += text;
          return `Typed: ${text}`;
      }

      /**
       * Removes the last occurrence of the given text from the editor's content.
       * Used primarily for undoing 'type' commands.
       * @param text The string to remove.
       * @returns A log message describing the action.
       */
      removeLastTyped(text: string): string {
          if (this.content.endsWith(text)) {
              this.content = this.content.slice(0, -text.length);
              return `Undone: ${text} removed`;
          }
          // This case should ideally not happen if undo history is managed correctly.
          return `Error: Text "${text}" not found to undo. Current content: "${this.content}"`;
      }

      /**
       * Marks a selection as bold.
       * @param selection The text selection to bold.
       * @returns A log message describing the action.
       */
      bold(selection: string): string {
          if (!this.boldedSelections.has(selection)) {
              this.boldedSelections.add(selection);
              return `Selection ${selection} made bold`;
          }
          return `Selection ${selection} was already bold`;
      }

      /**
       * Unmarks a selection as bold.
       * Used primarily for undoing 'bold' commands.
       * @param selection The text selection to unbold.
       * @returns A log message describing the action.
       */
      unbold(selection: string): string {
          if (this.boldedSelections.delete(selection)) {
              return `Selection ${selection} unbolded`;
          }
          return `Selection ${selection} was not bold`;
      }
  }

  // Initialize the Cr4ckTextEditor (Receiver) which the user's commands will operate on.
  const editor = new Cr4ckTextEditor();

  // Initialize the user's Context class (Invoker/Command Processor).
  // Assumes the user's Context constructor accepts an editor instance.
  // The user is expected to implement Context with methods like runCommand, undo, and redo.
  const context = new Context(editor);

  // Process each line of input from stdin.
  for (const line of lines) {
    let output: string = "";

    if (line.startsWith("execute command=")) {
      // Parse commands like "execute command=type Hello" or "execute command=bold selection=Hello"
      const commandPart = line.substring("execute command=".length);
      const parts = commandPart.split(/\s+(?=(?:[^"']*"[^"']*")*[^"']*$)/); // Robust split for potential quoted strings
      const commandType = parts[0];

      if (commandType === "type") {
        const textToType = parts[1];
        // Assumes user defines 'TypeCommand' implementing 'Strategy' interface.
        // The user's TypeCommand should take the editor and text as constructor arguments.
        const command = new TypeCommand(editor, textToType);
        // Assumes Context has a 'runCommand' method that accepts a Strategy instance.
        output = context.runCommand(command);
      } else if (commandType === "bold") {
        const selectionMatch = commandPart.match(/selection=(\S+)/); // Extract selection value
        if (selectionMatch) {
            const selection = selectionMatch[1];
            // Assumes user defines 'BoldCommand' implementing 'Strategy' interface.
            // The user's BoldCommand should take the editor and selection as constructor arguments.
            const command = new BoldCommand(editor, selection);
            output = context.runCommand(command);
        } else {
            output = `Error: Missing selection for bold command: ${line}`;
        }
      } else {
          output = `Error: Unknown command type \"${commandType}\" in line: ${line}`;
      }
    } else if (line === "undo") {
      // Assumes Context has an 'undo' method.
      output = context.undo();
    } else if (line === "redo") {
      // Assumes Context has a 'redo' method.
      output = context.redo();
    } else {
      output = `Error: Unrecognized input format: ${line}`;
    }

    // Print the output of each meaningful command to stdout.
    if (output) {
      console.log(output);
    }
  }
});$harness$,
  test_cases   = '[{"input": "execute command=type Hello\nundo", "description": "Execute type command and then undo it", "expected_output": "Typed: Hello\nUndone: Hello removed"}, {"input": "execute command=type Hello\nundo\nexecute command=bold selection=Hello\nredo", "description": "Execute type, undo it, execute bold, then redo the type command", "expected_output": "Typed: Hello\nUndone: Hello removed\nSelection Hello made bold\nRedone: Hello removed... then re-added"}, {"input": "undo\nredo", "description": "Attempt undo/redo on empty history", "expected_output": "Nothing to undo.\nNothing to redo."}, {"input": "execute command=type Hello\nexecute command=type World\nundo\nundo\nredo\nredo", "description": "Multi-step type, undo, and redo operations", "expected_output": "Typed: Hello\nTyped: World\nUndone: World removed\nUndone: Hello removed\nRedone: Hello removed... then re-added\nRedone: World removed... then re-added"}, {"input": "execute command=bold selection=Foo\nundo\nredo", "description": "Execute bold, undo it, then redo the bold command", "expected_output": "Selection Foo made bold\nSelection Foo unbolded\nSelection Foo made bold"}]'::jsonb
WHERE id = 'dp_056';
-- dp_057: Pagination Cursor Iterator
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

interface PaginationResult {
  items: string[];
  nextCursor: string | null;
}

// The harness expects the user's `Context` class to have the following public methods:
// - `constructor(strategy: Strategy)`: Initializes the context with a strategy.
// - `setPaginationData(itemsCount: number, pageSize: number): void`: Sets up the overall data source for pagination.
// - `paginate(currentCursor: string | null): PaginationResult`: Returns a page of items and the next cursor.
// - `hasNextPage(currentCursor: string | null): boolean`: Checks if there are more pages available.
//
// Internally, these `Context` methods are expected to use `this.strategy.execute()`,
// passing a suitable `data` object (e.g., `{ fullItemsList, pageSize, currentCursor, command }`)
// and casting the `unknown` return type of `Strategy.execute` to `PaginationResult` or `boolean` respectively.

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // Instantiate the user's ConcreteStrategy and Context
  // Assuming Context takes Strategy in its constructor
  const concreteStrategy = new ConcreteStrategy();
  const context = new Context(concreteStrategy);

  let currentItemsCount: number | null = null;
  let currentPagesize: number | null = null;

  for (const line of lines) {
    let output: string | null = null;

    // Command: set_pagination_data items=1000, page_size=10
    const setDataMatch = line.match(/^set_pagination_data items=(\d+), page_size=(\d+)$/);
    if (setDataMatch) {
      const itemsCount = parseInt(setDataMatch[1], 10);
      const pageSize = parseInt(setDataMatch[2], 10);
      try {
        context.setPaginationData(itemsCount, pageSize);
        currentItemsCount = itemsCount;
        currentPagesize = pageSize;
      } catch (e: any) {
        console.log(`Error setting pagination data: ${e.message}`);
      }
      // Setup commands do not produce explicit output for this harness
      continue; // Move to the next line
    }

    // Command: paginate cursor=item_10 OR paginate cursor=null
    const paginateMatch = line.match(/^paginate cursor=(.+)$/);
    if (paginateMatch) {
      const cursor = paginateMatch[1] === 'null' ? null : paginateMatch[1];

      if (currentItemsCount === null || currentPagesize === null) {
          console.log("Error: Pagination data not set. Use 'set_pagination_data' first.");
          continue;
      }

      let result: PaginationResult;
      try {
        result = context.paginate(cursor);
      } catch (e: any) {
        console.log(`Error during pagination: ${e.message}`);
        continue;
      }

      const startItemNum = result.items.length > 0
        ? parseInt(result.items[0].split('_')[1], 10)
        : 0;
      const endItemNum = result.items.length > 0
        ? parseInt(result.items[result.items.length - 1].split('_')[1], 10)
        : 0;

      let pageIndicator = '';
      // Determine page number / last page status based on cursor and results
      if (cursor === null) {
        pageIndicator = 'Page 1: ';
      } else if (result.nextCursor === null) {
        // If there's no next cursor, it's the last page (even if current page is empty)
        pageIndicator = 'Last page: ';
      } else if (startItemNum > 0 && currentPagesize > 0) {
        // Calculate page number based on the first item of the current page
        const currentPage = Math.ceil(startItemNum / currentPagesize);
        pageIndicator = `Page ${currentPage}: `;
      }

      const itemsRange = startItemNum > 0 && endItemNum > 0
        ? `items ${startItemNum}-${endItemNum}`
        : (result.items.length === 0 ? 'no items' : 'malformed items'); // Handles empty page or unexpected item format

      output = `${pageIndicator}${itemsRange}, next_cursor=${result.nextCursor}`;
    }

    // Command: has_next cursor=item_10 OR has_next cursor=null
    const hasNextMatch = line.match(/^has_next cursor=(.+)$/);
    if (hasNextMatch) {
      const cursor = hasNextMatch[1] === 'null' ? null : hasNextMatch[1];

      if (currentItemsCount === null || currentPagesize === null) {
        console.log("Error: Pagination data not set. Use 'set_pagination_data' first.");
        continue;
      }

      let result: boolean;
      try {
        result = context.hasNextPage(cursor);
      } catch (e: any) {
        console.log(`Error during hasNextPage: ${e.message}`);
        continue;
      }

      output = String(result);
    }

    if (output !== null) {
      console.log(output);
    } else if (!setDataMatch) { // Only log error if it wasn't a setData command
      console.log(`Error: Unknown command or invalid format - ${line}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "set_pagination_data items=1000, page_size=10\npaginate cursor=null", "description": "First page", "expected_output": "Page 1: items 1-10, next_cursor=item_10"}, {"input": "set_pagination_data items=1000, page_size=10\npaginate cursor=item_10", "description": "Second page", "expected_output": "Page 2: items 11-20, next_cursor=item_20"}, {"input": "set_pagination_data items=1000, page_size=10\npaginate cursor=item_990", "description": "Last page", "expected_output": "Last page: items 991-1000, next_cursor=null"}, {"input": "set_pagination_data items=1000, page_size=10\nhas_next cursor=item_1000", "description": "No next page", "expected_output": "false"}]'::jsonb
WHERE id = 'dp_057';
-- dp_058: Organization Chart Composite
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {
  // The user's `Context` class is expected to manage the organization chart state.
  // Strategies will be instantiated by the harness and given a reference to this `Context` instance,
  // allowing them to interact with the shared organizational chart.
  const orgChartContext = new Context();

  interface ParsedCommand {
    type: string;
    args: { [key: string]: string | null };
  }

  function parseCommand(commandLine: string): ParsedCommand {
    const parts = commandLine.split(' ');
    const type = parts[0];
    const args: { [key: string]: string | null } = {};
    if (parts.length > 1) {
      const argString = parts[1];
      argString.split(',').forEach(arg => {
        const [key, value] = arg.split('=').map(s => s.trim());
        args[key] = value === 'null' ? null : value; // Handle 'null' string as actual null
      });
    }
    return { type, args };
  }

  // Process each line of input
  for (const line of lines) {
    const { type, args } = parseCommand(line);
    let currentStrategy: Strategy | undefined;

    try {
      switch (type) {
        case 'add_employee':
          // Assumes the user has implemented `AddEmployeeStrategy` which takes Context in its constructor
          currentStrategy = new AddEmployeeStrategy(orgChartContext);
          orgChartContext.setStrategy(currentStrategy);
          orgChartContext.execute({ name: args.name, parent: args.parent });
          break;
        case 'get_subordinates':
          // Assumes the user has implemented `GetSubordinatesStrategy` which takes Context in its constructor
          currentStrategy = new GetSubordinatesStrategy(orgChartContext);
          orgChartContext.setStrategy(currentStrategy);
          orgChartContext.execute({ manager: args.manager });
          break;
        case 'get_depth':
          // Assumes the user has implemented `GetDepthStrategy` which takes Context in its constructor
          currentStrategy = new GetDepthStrategy(orgChartContext);
          orgChartContext.setStrategy(currentStrategy);
          orgChartContext.execute({ employee: args.employee });
          break;
        default:
          console.log(`Error: Unknown command type '${type}'.`);
          break;
      }
    } catch (error: any) {
      // This catch block handles unexpected runtime errors (e.g., TypeError, ReferenceError).
      // Expected functional errors (e.g., 'parent not found') should be caught and printed
      // by the user's strategy/context methods directly to match expected_output.
      console.log(`Runtime Error processing command '${line}': ${error.message || error}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "add_employee name=CEO, parent=null", "description": "Add root employee", "expected_output": "CEO added as root node"}, {"input": "add_employee name=CEO, parent=null\nadd_employee name=CTO, parent=CEO", "description": "Add direct report to existing employee", "expected_output": "CEO added as root node\nCTO added under CEO"}, {"input": "add_employee name=CEO, parent=null\nadd_employee name=CTO, parent=CEO\nadd_employee name=Engineer1, parent=CTO\nadd_employee name=Engineer2, parent=CTO\nadd_employee name=CFO, parent=CEO\nget_subordinates manager=CTO", "description": "Get subordinates of a manager (CTO)", "expected_output": "CEO added as root node\nCTO added under CEO\nEngineer1 added under CTO\nEngineer2 added under CTO\nCFO added under CEO\nCTO subordinates: [Engineer1, Engineer2]"}, {"input": "add_employee name=CEO, parent=null\nadd_employee name=CTO, parent=CEO\nadd_employee name=Engineer1, parent=CTO\nadd_employee name=Engineer2, parent=CTO\nadd_employee name=CFO, parent=CEO\nget_depth employee=Engineer1", "description": "Get depth of an employee (Engineer1)", "expected_output": "CEO added as root node\nCTO added under CEO\nEngineer1 added under CTO\nEngineer2 added under CTO\nCFO added under CEO\nEngineer1 depth: 3"}, {"input": "add_employee name=CEO, parent=null\nadd_employee name=CTO, parent=CEO\nadd_employee name=Engineer1, parent=CTO\nadd_employee name=Engineer2, parent=CTO\nadd_employee name=CFO, parent=CEO\nget_depth employee=CEO", "description": "Get depth of the root employee (CEO)", "expected_output": "CEO added as root node\nCTO added under CEO\nEngineer1 added under CTO\nEngineer2 added under CTO\nCFO added under CEO\nCEO depth: 1"}, {"input": "add_employee name=CEO, parent=null\nadd_employee name=CTO, parent=CEO\nadd_employee name=Engineer1, parent=CTO\nadd_employee name=Engineer2, parent=CTO\nadd_employee name=CFO, parent=CEO\nget_subordinates manager=CEO", "description": "Get subordinates of the root employee (CEO)", "expected_output": "CEO added as root node\nCTO added under CEO\nEngineer1 added under CTO\nEngineer2 added under CTO\nCFO added under CEO\nCEO subordinates: [CFO, CTO]"}, {"input": "add_employee name=CEO, parent=null\nadd_employee name=NonExistentChild, parent=NoOne", "description": "Attempt to add employee with a non-existent parent", "expected_output": "CEO added as root node\nError: Parent ''NoOne'' not found."}, {"input": "add_employee name=CEO, parent=null\nget_depth employee=NonExistent", "description": "Attempt to get depth of a non-existent employee", "expected_output": "CEO added as root node\nError: Employee ''NonExistent'' not found."}, {"input": "add_employee name=CEO, parent=null\nget_subordinates manager=NonExistentManager", "description": "Attempt to get subordinates of a non-existent manager", "expected_output": "CEO added as root node\nError: Employee ''NonExistentManager'' not found."}, {"input": "add_employee name=CEO, parent=null\nadd_employee name=NewCEO, parent=null", "description": "Attempt to add a second root employee", "expected_output": "CEO added as root node\nError: Root employee already exists. Cannot add ''NewCEO'' as root."}, {"input": "add_employee name=CEO, parent=null\nadd_employee name=CTO, parent=CEO\nadd_employee name=CEO, parent=CTO", "description": "Attempt to add an employee with an existing name", "expected_output": "CEO added as root node\nCTO added under CEO\nError: Employee ''CEO'' already exists."}]'::jsonb
WHERE id = 'dp_058';
-- dp_059: Home Automation Facade Hub
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // The user is expected to implement a HomeAutomationFacade class
  // and potentially its constituent subsystem classes (Lights, Thermostat, Security).
  // The harness will instantiate and interact with the HomeAutomationFacade.
  const facade = new HomeAutomationFacade(); // Assumes user's class name

  for (const line of lines) {
    if (!line) {
      // Allow empty lines in input without error, just skip them.
      continue;
    }

    const parts = line.split('=');
    if (parts.length !== 2 || parts[0] !== 'command') {
      // Log an error for malformed commands, but continue processing other commands.
      console.log(`Error: Invalid command format: '${line}'. Expected 'command=<action>'.`);
      continue;
    }

    const commandAction = parts[1];
    let result: string | undefined;

    try {
      switch (commandAction) {
        case 'turn_on_all':
          result = facade.turnOnAll();
          break;
        case 'night_mode':
          result = facade.nightMode();
          break;
        case 'away_mode':
          result = facade.awayMode();
          break;
        case 'query_status':
          result = facade.queryStatus();
          break;
        default:
          result = `Error: Unknown command action: '${commandAction}'`;
          break;
      }
    } catch (e: any) {
      // Catch any runtime errors from user's code
      result = `Error executing command \'${commandAction}\': ${e.message || e}`;
    }

    if (result !== undefined) {
      console.log(result);
    }
  }
});$harness$,
  test_cases   = '[{"input": "command=turn_on_all", "description": "Turn on all devices", "expected_output": "Lights ON, Thermostat ON, Security ON via facade"}, {"input": "command=night_mode", "description": "Activate night mode", "expected_output": "Lights dim to 20%, Thermostat set 18C, Locks engaged"}, {"input": "command=away_mode", "description": "Activate away mode", "expected_output": "All lights OFF, Thermostat eco mode, Alarm armed"}, {"input": "command=turn_on_all\ncommand=query_status", "description": "Query home status", "expected_output": "Lights ON, Thermostat ON, Security ON via facade\nLights: ON, Thermostat: 22C, Security: armed"}]'::jsonb
WHERE id = 'dp_059';
-- dp_060: Third-Party Payment Adapter
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

// The LegacyOldPayCoProvider class serves as the 'Adaptee' for the user's solution.
// It simulates a third-party payment system with specific, non-standard interfaces.
// Users are expected to create an Adapter (their ConcreteStrategy) to work with this.
class LegacyOldPayCoProvider {
  private balance: number = 250.00; // Initial balance for testing

  /**
   * Simulates processing a payment through the legacy system.
   * @param amount The amount to charge.
   * @param currency The currency of the charge.
   * @returns A string describing the legacy processing result.
   */
  public processPayment(amount: number, currency: string): string {
    if (amount > 0) {
      this.balance -= amount;
    }
    return `Legacy OldPayCo processed charge of $${amount.toFixed(2)} ${currency}. Current balance: $${this.balance.toFixed(2)}`;
  }

  /**
   * Simulates reversing a payment (refund) through the legacy system.
   * @param amount The amount to refund.
   * @returns A string describing the legacy refund result.
   */
  public reversePayment(amount: number): string {
    if (amount > 0) {
      this.balance += amount;
    }
    return `Legacy OldPayCo processed refund of $${amount.toFixed(2)}. Current balance: $${this.balance.toFixed(2)}`;
  }

  /**
   * Retrieves the current account balance from the legacy system.
   * @returns The current balance as a number.
   */
  public getAccountBalance(): number {
    return this.balance;
  }
}

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // Instantiate the Adaptee and the Context (Client) for the test session.
  // This ensures state persists across commands within a single test run.
  const legacyProvider = new LegacyOldPayCoProvider();
  const context = new Context();

  for (const line of lines) {
    const parts = line.split(', ').map(p => p.trim());
    const commandParams: Record<string, string> = {};
    parts.forEach(p => {
      const [key, value] = p.split('=');
      commandParams[key] = value;
    });

    try {
      if (commandParams['legacy_provider'] === 'OldPayCo') {
        if (commandParams['charge']) {
          const amount = parseFloat(commandParams['charge']);
          const currency = commandParams['currency'] || 'USD';
          // Create an adapter (ConcreteStrategy) for the 'charge' operation and set it in the context.
          const strategy = new ConcreteStrategy(legacyProvider, 'charge');
          context.setStrategy(strategy);
          // Perform the operation via the context, which delegates to the adapter.
          const result = context.performOperation({ charge: amount, currency: currency });
          console.log(result);
        } else if (commandParams['refund']) {
          const amount = parseFloat(commandParams['refund']);
          // Create an adapter (ConcreteStrategy) for the 'refund' operation and set it in the context.
          const strategy = new ConcreteStrategy(legacyProvider, 'refund');
          context.setStrategy(strategy);
          // Perform the operation via the context, which delegates to the adapter.
          const result = context.performOperation({ refund: amount });
          console.log(result);
        } else if (commandParams['get_balance'] !== undefined) { // Check for existence as it has no explicit value
          // Create an adapter (ConcreteStrategy) for the 'getBalance' operation and set it in the context.
          const strategy = new ConcreteStrategy(legacyProvider, 'getBalance');
          context.setStrategy(strategy);
          // Perform the operation via the context, which delegates to the adapter.
          const result = context.performOperation({}); // No specific data needed for getBalance
          console.log(result);
        } else {
          console.error(`Error: Unrecognized legacy_provider command: ${line}`);
        }
      } else if (commandParams['modern_interface'] && commandParams['legacy_method']) {
        // Handle interface mapping directly through the Context. The Context itself
        // is expected to output the mapping result based on the test description.
        context.registerInterfaceMapping(commandParams['modern_interface'], commandParams['legacy_method']);
      } else {
        console.error(`Error: Unknown command format: ${line}`);
      }
    } catch (e: any) {
      console.error(`Runtime Error: ${e.message}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "legacy_provider=OldPayCo, charge=100, currency=USD", "description": "Charge via legacy adapter", "expected_output": "Adapted OldPayCo charge: $100.00 USD"}, {"input": "legacy_provider=OldPayCo, refund=50", "description": "Refund via legacy adapter", "expected_output": "Adapted OldPayCo refund: $50.00"}, {"input": "legacy_provider=OldPayCo, get_balance", "description": "Get initial balance via adapter", "expected_output": "Adapted balance: $250.00"}, {"input": "legacy_provider=OldPayCo, charge=100, currency=USD\nlegacy_provider=OldPayCo, refund=50\nlegacy_provider=OldPayCo, get_balance", "description": "Sequential operations: charge, then refund, then get balance", "expected_output": "Adapted OldPayCo charge: $100.00 USD\nAdapted OldPayCo refund: $50.00\nAdapted balance: $200.00"}, {"input": "modern_interface=charge, legacy_method=processPayment", "description": "Interface mapping (modern method to legacy method)", "expected_output": "Modern charge() mapped to legacy processPayment()"}]'::jsonb
WHERE id = 'dp_060';
-- dp_061: CI Pipeline Step Template
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin
});

const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // Instantiate the user's Context class. It's assumed to be available globally.
  const pipelineContext = new Context();

  // Instantiate concrete strategies expected from the user's implementation.
  // The user is expected to define classes like CheckoutStrategy, TestStrategy, etc.,
  // implementing the `Strategy` interface.
  try {
    const checkoutStrategy = new (global as any).CheckoutStrategy();
    const testStrategy = new (global as any).TestStrategy();
    const buildStrategy = new (global as any).BuildStrategy();
    const deployStrategy = new (global as any).DeployStrategy();
    const customBuildStrategy = new (global as any).CustomBuildStrategy();
    const lintStrategy = new (global as any).LintStrategy();
    const typecheckStrategy = new (global as any).TypecheckStrategy();

    // The ParallelStepsStrategy is a composite strategy that needs access to the main context
    // to execute its sub-strategies dynamically.
    const parallelStepsStrategy = new (global as any).ParallelStepsStrategy(pipelineContext);

    // Register default strategies with the user's Context instance
    pipelineContext.setStrategy("checkout", checkoutStrategy);
    pipelineContext.setStrategy("test", testStrategy);
    pipelineContext.setStrategy("build", buildStrategy);
    pipelineContext.setStrategy("deploy", deployStrategy);
    pipelineContext.setStrategy("custom_build", customBuildStrategy); // Register custom_build as a named strategy
    pipelineContext.setStrategy("lint", lintStrategy);
    pipelineContext.setStrategy("typecheck", typecheckStrategy);
    pipelineContext.setStrategy("parallel_steps", parallelStepsStrategy); // Register the parallel composite strategy
  } catch (e: any) {
      console.log(`Error: Failed to instantiate a required Strategy class. Please ensure all ConcreteStrategy classes (e.g., CheckoutStrategy, TestStrategy, BuildStrategy, DeployStrategy, CustomBuildStrategy, LintStrategy, TypecheckStrategy, ParallelStepsStrategy) are defined and implement the Strategy interface. Details: ${e.message}`);
      return;
  }

  for (const line of lines) {
    let output: string | null = null;

    if (line.startsWith("RUN_PIPELINE ")) {
      const pipelineMatch = line.match(/pipeline=\[(.*?)\]/);
      // Regex to find all config_key=value pairs
      const configMatches = Array.from(line.matchAll(/config_([a-zA-Z0-9_]+)=([a-zA-Z0-9,]+)/g));

      if (pipelineMatch && pipelineMatch[1]) {
        const stepNames = pipelineMatch[1].split(',').map(s => s.trim());
        // Initialize step configurations with just their names
        const stepConfigs: Array<{name: string, config?: any}> = stepNames.map(name => ({ name }));

        // Apply additional configurations from the command line to specific steps
        for (const match of configMatches) {
          const configKey = match[1]; // e.g., 'test_testStatus', 'parallel_steps'
          const configValue = match[2]; // e.g., 'fail', 'lint,typecheck'

          if (configKey.startsWith("parallel_steps")) {
              // This config applies to the 'parallel_steps' strategy itself, providing its sub-steps
              const targetStepName = "parallel_steps";
              const stepIndex = stepConfigs.findIndex(sc => sc.name === targetStepName);
              if (stepIndex !== -1) {
                  if (!stepConfigs[stepIndex].config) stepConfigs[stepIndex].config = {};
                  stepConfigs[stepIndex].config.steps = configValue.split(',').map(s => s.trim());
              }
          } else {
              // This config applies to a single regular step, e.g., 'test' from 'test_testStatus'
              const parts = configKey.split('_');
              if (parts.length >= 2) {
                const targetStepName = parts[0]; // e.g., 'test'
                const actualConfigKey = parts.slice(1).join('_'); // e.g., 'testStatus'
                const stepIndex = stepConfigs.findIndex(sc => sc.name === targetStepName);
                if (stepIndex !== -1) {
                    if (!stepConfigs[stepIndex].config) stepConfigs[stepIndex].config = {};
                    stepConfigs[stepIndex].config[actualConfigKey] = configValue;
                }
              }
          }
        }
        output = pipelineContext.runPipeline(stepConfigs);
      } else {
        output = "Error: Invalid RUN_PIPELINE command format.";
      }
    } else if (line.startsWith("OVERRIDE_STEP ")) {
      const match = line.match(/OVERRIDE_STEP (\w+) with (\w+)/);
      if (match) {
        const originalName = match[1]; // e.g., 'build'
        const newStrategyName = match[2]; // e.g., 'custom_build'

        let newStrategyInstance: Strategy | undefined;
        // Instantiate the correct user-defined strategy based on `newStrategyName`
        try {
          switch (newStrategyName) {
            case "checkout": newStrategyInstance = new (global as any).CheckoutStrategy(); break;
            case "test": newStrategyInstance = new (global as any).TestStrategy(); break;
            case "build": newStrategyInstance = new (global as any).BuildStrategy(); break;
            case "deploy": newStrategyInstance = new (global as any).DeployStrategy(); break;
            case "custom_build": newStrategyInstance = new (global as any).CustomBuildStrategy(); break;
            case "lint": newStrategyInstance = new (global as any).LintStrategy(); break;
            case "typecheck": newStrategyInstance = new (global as any).TypecheckStrategy(); break;
            case "parallel_steps": newStrategyInstance = new (global as any).ParallelStepsStrategy(pipelineContext); break;
            default: output = `Error: Unknown new strategy '${newStrategyName}'.`; break;
          }
        } catch (e: any) {
          output = `Error: Failed to instantiate strategy '${newStrategyName}' for override. Details: ${e.message}`;
        }

        if (newStrategyInstance && !output) {
          output = pipelineContext.overrideStep(originalName, newStrategyInstance);
        }
      } else {
        output = "Error: Invalid OVERRIDE_STEP command format.";
      }
    } else {
        output = `Error: Unknown command: '${line}'`;
    }

    if (output !== null) {
      console.log(output);
    }
  }
});$harness$,
  test_cases   = '[{"input": "RUN_PIPELINE pipeline=[checkout,test,build,deploy]", "description": "Full pipeline execution", "expected_output": "Pipeline started: checkout -> test -> build -> deploy"}, {"input": "RUN_PIPELINE pipeline=[checkout,test,build] config_test_testStatus=fail", "description": "Pipeline stops on failure", "expected_output": "Pipeline stopped at test step: FAILED"}, {"input": "OVERRIDE_STEP build with custom_build\nRUN_PIPELINE pipeline=[checkout,build,deploy]", "description": "Override pipeline step", "expected_output": "build step overridden with custom_build\nPipeline started: checkout -> custom_build -> deploy"}, {"input": "RUN_PIPELINE pipeline=[checkout,parallel_steps,deploy] config_parallel_steps=lint,typecheck", "description": "Parallel step execution", "expected_output": "Pipeline started: checkout -> lint and typecheck running in parallel -> deploy"}]'::jsonb
