-- dp_062: Expense Approval Chain
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout,
  terminal: false
});

const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', () => {
  // Assumed user-defined interfaces/classes (from starter code and expected implementation)
  interface ExpenseRequest {
    amount: number;
  }

  // User's Strategy interface as provided
  // interface Strategy {
  //   execute(data: unknown): void;
  // }

  // User's Context class as provided
  // class Context {
  //   // TODO: hold strategy and run it
  // }

  // User's ConcreteStrategy class as provided
  // class ConcreteStrategy implements Strategy {
  //   // TODO: implement
  // }

  let contextInstance: Context | null = null;

  for (const line of lines) {
    const parts = line.split(' ');
    const command = parts[0];

    switch (command) {
      case 'SETUP_CHAIN':
        if (parts.length === 4) {
          const managerLimit = parseInt(parts[1]);
          const directorLimit = parseInt(parts[2]);
          const vpLimit = parseInt(parts[3]);

          // Instantiate user's approver classes
          // Assuming user has ManagerApprover, DirectorApprover, VPApprover, BoardApprover
          // extending ConcreteStrategy and implementing Strategy.
          // They must have a constructor taking a limit and a setNext method.
          // They also must have a 'name' property (likely on ConcreteStrategy base).
          const manager = new ManagerApprover(managerLimit);
          const director = new DirectorApprover(directorLimit);
          const vp = new VPApprover(vpLimit);
          const board = new BoardApprover(); // Board typically approves anything reaching it

          // Build the chain
          manager.setNext(director);
          director.setNext(vp);
          vp.setNext(board);

          // Instantiate user's Context with the head of the chain
          contextInstance = new Context(manager);
        } else {
          console.error('Invalid SETUP_CHAIN command format. Expected: SETUP_CHAIN <manager_limit> <director_limit> <vp_limit>');
        }
        break;
      case 'PROCESS_EXPENSE':
        if (contextInstance && parts.length === 2) {
          const amount = parseInt(parts[1]);
          const request: ExpenseRequest = { amount: amount };
          // Call the method on the user's Context to start the approval process
          (contextInstance as any).processRequest(request); // Assuming user's Context has a processRequest method
        } else if (!contextInstance) {
          console.error('Chain not set up. Please use SETUP_CHAIN first.');
        } else {
          console.error('Invalid PROCESS_EXPENSE command format. Expected: PROCESS_EXPENSE <amount>');
        }
        break;
      default:
        console.error(`Unknown command: ${command}`);
        break;
    }
  }
});$harness$,
  test_cases   = '[{"input": "SETUP_CHAIN 1000 5000 50000\nPROCESS_EXPENSE 200", "description": "Manager approves small expense", "expected_output": "Manager approved $200 expense"}, {"input": "SETUP_CHAIN 1000 5000 50000\nPROCESS_EXPENSE 2000", "description": "Expense escalated to director", "expected_output": "Manager escalated $2000 to Director\nDirector approved $2000"}, {"input": "SETUP_CHAIN 1000 5000 50000\nPROCESS_EXPENSE 10000", "description": "VP approves large expense", "expected_output": "Manager escalated $10000 to Director\nDirector escalated $10000 to VP\nVP approved $10000"}, {"input": "SETUP_CHAIN 1000 5000 50000\nPROCESS_EXPENSE 500000", "description": "Board approves very large expense", "expected_output": "Manager escalated $500000 to Director\nDirector escalated $500000 to VP\nVP escalated $500000 to Board\nBoard approved"}]'::jsonb
