  // All user-defined classes (e.g., AuctionMediator, Bidder, AuctionItem) are available here.

  // Assume the user implements a class named 'AuctionMediator' with methods
  // matching the expected interactions for an auction system based on the Mediator pattern.
  // This class should handle the core Mediator logic.
  // Expected methods for the harness to interact with:
  // class AuctionMediator {
  //   registerBidderForItem(bidderName: string, itemName: string): string; // Registers a bidder for an item, returns confirmation message.
  //   placeBid(bidderName: string, amount: number): string;               // Places a bid, returns notification message.
  //   closeAuction(itemName: string): string;                           // Closes an auction, returns outcome message.
  // }

  // Create the main stateful object (the Mediator instance)
  const auctionMediator = new AuctionMediator();

  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    const parts = line.split(' ');
    const command = parts[0];
    const argsString = parts.slice(1).join(' '); // Rejoin for easier parsing of key=value pairs

    let output: string | undefined;

    try {
      if (command === 'register') {
        const { bidder, item } = parseArgs(argsString, ['bidder', 'item']);
        if (bidder && item) {
          output = auctionMediator.registerBidderForItem(bidder, item);
        } else {
          output = `Error: 'register' command requires 'bidder' and 'item' arguments.`;
        }
      } else if (command === 'place_bid') {
        const { bidder, amount } = parseArgs(argsString, ['bidder', 'amount']);
        if (bidder && amount) {
          const amountNum = parseInt(amount);
          if (!isNaN(amountNum)) {
            output = auctionMediator.placeBid(bidder, amountNum);
          } else {
            output = `Error: 'amount' for 'place_bid' must be a valid number. Got: '${amount}'.`;
          }
        } else {
          output = `Error: 'place_bid' command requires 'bidder' and 'amount' arguments.`;
        }
      } else if (command === 'close_auction') {
        const { item } = parseArgs(argsString, ['item']);
        if (item) {
          output = auctionMediator.closeAuction(item);
        } else {
          output = `Error: 'close_auction' command requires 'item' argument.`;
        }
      } else {
        output = `Unknown command: ${command}`;
      }
    } catch (e: any) {
      // Catch errors thrown by the user's implementation methods
      output = e.message || `An unexpected error occurred: ${e}`;
    }

    if (output !== undefined) {
      console.log(output);
    }
  }

  // Helper function for parsing key=value arguments from a string
  function parseArgs(argString: string, expectedKeys: string[]): { [key: string]: string } {
    const result: { [key: string]: string } = {};
    const argPairs = argString.split(',').map(s => s.trim()).filter(s => s.length > 0);
    for (const pair of argPairs) {
      const [key, value] = pair.split('=');
      if (key && value) {
        const trimmedKey = key.trim();
        // Only include keys that are explicitly expected by the command
        if (expectedKeys.includes(trimmedKey)) {
          result[trimmedKey] = value.trim();
        }
      }
    }
    return result;
  }
});$harness$,
  test_cases   = '[{"input": "register bidder=alice, item=painting", "description": "Register bidder for an item", "expected_output": "alice registered for painting auction"}, {"input": "register bidder=alice, item=painting\nplace_bid bidder=alice, amount=500", "description": "Place initial bid", "expected_output": "alice registered for painting auction\nalice bid $500, all bidders notified"}, {"input": "register bidder=alice, item=painting\nplace_bid bidder=alice, amount=500\nregister bidder=bob, item=painting\nplace_bid bidder=bob, amount=600", "description": "Place a higher bid by another bidder", "expected_output": "alice registered for painting auction\nalice bid $500, all bidders notified\nbob registered for painting auction\nbob outbid alice at $600, alice notified"}, {"input": "register bidder=alice, item=painting\nplace_bid bidder=alice, amount=500\nregister bidder=bob, item=painting\nplace_bid bidder=bob, amount=600\nclose_auction item=painting", "description": "Close auction with a winner", "expected_output": "alice registered for painting auction\nalice bid $500, all bidders notified\nbob registered for painting auction\nbob outbid alice at $600, alice notified\nAuction closed, winner: bob at $600"}, {"input": "register bidder=charlie, item=sculpture\nclose_auction item=sculpture", "description": "Close auction with no bids", "expected_output": "charlie registered for sculpture auction\nAuction closed for sculpture, no bids."}, {"input": "register bidder=diana, item=vase\nplace_bid bidder=diana, amount=100\nplace_bid bidder=diana, amount=50", "description": "Attempt to place a lower bid than current by same bidder", "expected_output": "diana registered for vase auction\ndiana bid $100, all bidders notified\nBid $50 by diana is not higher than current bid $100 for vase."}, {"input": "register bidder=eve, item=jewelry\nplace_bid bidder=frank, amount=200", "description": "Attempt to place bid by an unregistered bidder for an item", "expected_output": "eve registered for jewelry auction\nBidder frank not found for jewelry auction."}, {"input": "place_bid bidder=grace, amount=100", "description": "Attempt to place bid without any prior registration (bidder not known)", "expected_output": "Bidder grace not found for any auction."}, {"input": "close_auction", "description": "Attempt to close auction without specifying item", "expected_output": "Error: ''close_auction'' command requires ''item'' argument."}, {"input": "register", "description": "Attempt to register without specifying bidder/item", "expected_output": "Error: ''register'' command requires ''bidder'' and ''item'' arguments."}, {"input": "unknown_command arg=value", "description": "Execute an unknown command", "expected_output": "Unknown command: unknown_command"}]'::jsonb
