-- dp_064: Code Editor Snapshot Memento
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {
  // The user's solution is expected to provide the following:
  // - The `Strategy` interface and `Context` class from the starter code, with their TODOs implemented.
  // - Classes for the Memento pattern: `EditorStateMemento`, `Editor`, `SnapshotManager`.
  // - Specific concrete strategy classes for each command: 
  //   `SaveSnapshotStrategy`, `RestoreSnapshotStrategy`, `AutoSaveStrategy`, `CompareSnapshotsStrategy`.
  //   These concrete strategies should implement the `Strategy` interface and accept `Editor` and/or `SnapshotManager`
  //   instances in their constructors as needed by the harness.

  // Initialize stateful objects. These assume user has defined them.
  const editor = new Editor();
  const snapshotManager = new SnapshotManager();
  const context = new Context();

  // Command processing loop
  for (const line of lines) {
    if (!line) continue;

    const [commandPart, ...argsParts] = line.split(' ');
    const command = commandPart.toLowerCase();
    const args: { [key: string]: string } = {};
    argsParts.forEach(arg => {
      const [key, value] = arg.split('=');
      if (key && value) args[key] = value.replace(/_/g, ' '); // Replace underscores in values if any
    });

    let output: string | undefined;
    let strategy: Strategy | null = null;

    try {
      switch (command) {
        case 'set_content':
          // This is a special harness command for setting up the editor's state.
          // It directly interacts with the Editor instance and is not a user-defined strategy.
          editor.setContent(args.content || '');
          output = `Editor content set.`;
          break;

        case 'save_snapshot':
          // User is expected to implement SaveSnapshotStrategy
          strategy = new SaveSnapshotStrategy(editor, snapshotManager);
          break;

        case 'restore_snapshot':
          // User is expected to implement RestoreSnapshotStrategy
          strategy = new RestoreSnapshotStrategy(editor, snapshotManager);
          break;

        case 'auto_save':
          // User is expected to implement AutoSaveStrategy
          // Passing editor for potential future interaction, even if not strictly used for simple print output.
          strategy = new AutoSaveStrategy(editor);
          break;

        case 'compare_snapshots':
          // User is expected to implement CompareSnapshotsStrategy
          strategy = new CompareSnapshotsStrategy(snapshotManager);
          break;

        default:
          output = `Unknown command: ${command}`;
          break;
      }

      if (strategy) {
        context.setStrategy(strategy);
        output = context.executeStrategy(args);
      }
    } catch (e: any) {
      output = `Error processing command '${command}': ${e.message}`;
    }

    if (output !== undefined) {
      console.log(output);
    }
  }
});$harness$,
  test_cases   = '[{"input": "set_content content=This_is_the_initial_editor_content.\nsave_snapshot file=editor_state.json", "description": "Save editor snapshot", "expected_output": "Editor content set.\nSnapshot saved: editor_state.json"}, {"input": "set_content content=Original_content_before_snapshot.\nsave_snapshot file=editor_state.json\nset_content content=Modified_content_after_snapshot.\nrestore_snapshot file=editor_state.json", "description": "Restore from snapshot", "expected_output": "Editor content set.\nSnapshot saved: editor_state.json\nEditor content set.\nEditor restored from snapshot"}, {"input": "auto_save interval=5min", "description": "Enable auto-save", "expected_output": "Auto-save enabled every 5 minutes"}, {"input": "set_content content=First_line.\nSecond_line.\nThird_line.\nsave_snapshot file=snap1\nset_content content=First_line.\nModified_second_line.\nFourth_line_added.\nsave_snapshot file=snap2\ncompare_snapshots snap1 snap2", "description": "Compare snapshots", "expected_output": "Editor content set.\nSnapshot saved: snap1\nEditor content set.\nSnapshot saved: snap2\nSnapshots differ: 2 lines changed"}, {"input": "restore_snapshot file=non_existent.json", "description": "Attempt to restore a non-existent snapshot", "expected_output": "Error: Snapshot ''non_existent.json'' not found."}, {"input": "set_content content=Some_content.\nsave_snapshot file=snap_a\ncompare_snapshots snap_a snap_b", "description": "Attempt to compare with a non-existent snapshot", "expected_output": "Editor content set.\nSnapshot saved: snap_a\nError: One or both snapshots not found for comparison."}]'::jsonb
