-- dp_065: Order Fulfillment State Tracker
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

// The user's provided interfaces and classes are assumed to be concatenated here:
// interface Strategy { execute(data: unknown): void; }
// class Context { // user implements }
// class ConcreteStrategy implements Strategy { // user implements, perhaps a default or base }

// --- Hidden Test Harness Starts Here ---

// The Order class is provided by the harness and will be available to user's Context and Strategy
class Order {
  id: string;
  state: string;
  private _previousState: string | null = null; // Stores state before the last setState call

  constructor(id: string, initialState: string) {
    this.id = id;
    this.state = initialState;
    this._previousState = null; // No previous state on initial creation
  }

  // Strategies will call this method to update the order's state
  setState(newState: string) {
    this._previousState = this.state;
    this.state = newState;
  }

  // The Context can use this to determine transitions
  get previousState(): string | null {
    return this._previousState;
  }
}

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  const orders = new Map<string, Order>();
  const context = new Context(); // Instantiate the user's Context class

  // Helper function to get an instance of the appropriate Strategy
  // The harness expects users to implement specific named strategy classes
  // for each command type/event to demonstrate extensibility of the pattern.
  function getStrategyInstance(commandIdentifier: string): Strategy {
    switch (commandIdentifier) {
      case "INIT_ORDER":
        // Expect user to have a strategy for initial order placement, e.g., InitialOrderPlacementStrategy
        if (typeof InitialOrderPlacementStrategy !== 'undefined') {
          return new InitialOrderPlacementStrategy();
        }
        break;
      case "payment_confirmed":
        if (typeof PaymentConfirmedStrategy !== 'undefined') {
          return new PaymentConfirmedStrategy();
        }
        break;
      case "shipped":
        if (typeof ShippedStrategy !== 'undefined') {
          return new ShippedStrategy();
        }
        break;
      case "delivered":
        if (typeof DeliveredStrategy !== 'undefined') {
          return new DeliveredStrategy();
        }
        break;
    }
    // If a specific strategy class is not found, throw an error.
    // This enforces the implementation of distinct strategies for distinct behaviors.
    throw new Error(`Specific strategy for command '${commandIdentifier}' not found. Please implement ${commandIdentifier === "INIT_ORDER" ? "InitialOrderPlacementStrategy" : commandIdentifier.charAt(0).toUpperCase() + commandIdentifier.slice(1) + "Strategy"}.`);
  }

  for (const line of lines) {
    const parts = line.split(',').map(s => s.trim());
    const commandMap = new Map<string, string>();
    parts.forEach(part => {
      const [key, value] = part.split('=');
      commandMap.set(key, value);
    });

    let output = "Error: Invalid command format"; // Default error output
    let order: Order | undefined;
    let strategyIdentifier: string | undefined; // Used to look up the strategy

    try {
      if (commandMap.has('order') && commandMap.has('state')) {
        // Command to initialize an order's state
        const orderId = commandMap.get('order')!;
        const initialState = commandMap.get('state')!;

        if (orders.has(orderId)) {
          console.log(`Error: Order ${orderId} already exists.`);
          continue;
        }

        order = new Order(orderId, initialState);
        orders.set(orderId, order);
        strategyIdentifier = "INIT_ORDER"; // Special identifier for initial state strategy

        const strategy = getStrategyInstance(strategyIdentifier);
        context.setStrategy(strategy);

        // Context's performAction will execute the strategy and return the output string
        // The data passed to strategy should be an object containing 'order' and any specific event details
        output = context.performAction(order, { initialState: initialState });

      } else if (commandMap.has('event') && commandMap.has('order')) {
        // Command to process an event for an existing order
        const eventType = commandMap.get('event')!;
        const orderId = commandMap.get('order')!;

        order = orders.get(orderId);
        if (!order) {
          console.log(`Error: Order ${orderId} not found.`);
          continue;
        }

        strategyIdentifier = eventType; // Use event type as strategy identifier

        const strategy = getStrategyInstance(strategyIdentifier);
        context.setStrategy(strategy);
        
        // Context's performAction will execute the strategy and return the output string
        // The data passed to strategy should be an object containing 'order' and any specific event details
        output = context.performAction(order, { eventType: eventType });

      } else {
        // If the command format is not recognized
        console.log(output); // Output the default error
        continue;
      }
      console.log(output);

    } catch (e: any) {
      console.log(`Runtime Error: ${e.message}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "order=ORD001, state=PLACED", "description": "Initial order state", "expected_output": "Order ORD001 in PLACED state"}, {"input": "order=ORD001, state=PLACED\nevent=payment_confirmed, order=ORD001", "description": "Payment confirms order", "expected_output": "Order ORD001 in PLACED state\nOrder ORD001 transition: PLACED -> PROCESSING"}, {"input": "order=ORD001, state=PLACED\nevent=payment_confirmed, order=ORD001\nevent=shipped, order=ORD001", "description": "Order shipped", "expected_output": "Order ORD001 in PLACED state\nOrder ORD001 transition: PLACED -> PROCESSING\nOrder ORD001 transition: PROCESSING -> SHIPPED"}, {"input": "order=ORD001, state=PLACED\nevent=payment_confirmed, order=ORD001\nevent=shipped, order=ORD001\nevent=delivered, order=ORD001", "description": "Order delivered", "expected_output": "Order ORD001 in PLACED state\nOrder ORD001 transition: PLACED -> PROCESSING\nOrder ORD001 transition: PROCESSING -> SHIPPED\nOrder ORD001 transition: SHIPPED -> DELIVERED"}]'::jsonb
WHERE id = 'dp_065';
-- dp_066: Insurance Premium Visitor Calculator
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // Define an interface for parsed policy data for strong typing in the harness.
  // This interface helps the harness organize the parsed input but is not part of the user's starter code.
  interface InsurancePolicyData {
    policyType: string;
    age?: number;
    coverage?: number;
    value?: number;
    sum_insured?: number;
    [key: string]: any; // Allow other properties
  }

  // --- Harness specific parsing function ---
  function parseInputLine(line: string): InsurancePolicyData {
    const parts = line.split(', ').map(s => s.trim());
    const data: { [key: string]: any } = {};
    for (const part of parts) {
      const [key, value] = part.split('=');
      if (key === 'policy') {
        data.policyType = value;
      } else if (key === 'visitor') {
        // Ignore visitor=calculator as it's implied by the challenge context
      } else {
        // Attempt to convert to number if possible, otherwise keep as string
        data[key] = isNaN(Number(value)) ? value : Number(value);
      }
    }
    return data as InsurancePolicyData;
  }

  // --- Instantiate stateful objects from user's code ---
  // The user's ConcreteStrategy is expected to act as the PremiumCalculatorVisitor.
  // We assume `ConcreteStrategy` implements `Strategy` and has a public property
  // `premiumCalculationResult: string` to store the formatted output string after execution.
  const premiumCalculatorVisitor: ConcreteStrategy = new ConcreteStrategy();

  // The user's Context is expected to hold and run the strategy.
  // We assume `Context`'s constructor takes the `Strategy` and it has a public method
  // `execute(policyData: unknown)` which internally calls `this.strategy.execute(policyData)`
  // and then retrieves the result from `premiumCalculatorVisitor.premiumCalculationResult` and prints it.
  const context: Context = new Context(premiumCalculatorVisitor);

  // --- Process commands (lines) ---
  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    const policyData = parseInputLine(line);

    // Call the context's execute method to process the policy and print the result.
    // This method is assumed to delegate to the strategy and then print the result.
    context.execute(policyData);
  }
});$harness$,
  test_cases   = '[{"input": "policy=auto, age=30, coverage=100000, visitor=calculator", "description": "Auto insurance premium", "expected_output": "Auto premium: $1200/year for age 30"}, {"input": "policy=home, value=300000, visitor=calculator", "description": "Home insurance premium", "expected_output": "Home premium: $1500/year for $300k home"}, {"input": "policy=life, age=45, sum_insured=500000, visitor=calculator", "description": "Life insurance premium", "expected_output": "Life premium: $3000/year for age 45"}, {"input": "policy=health, age=25, visitor=calculator", "description": "Health insurance premium", "expected_output": "Health premium: $800/year for age 25"}]'::jsonb
