-- dp_067: Map Tile Flyweight Cache
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // The harness assumes the user has implemented a MapTile (the flyweight object)
  // and a MapTileFactory (the flyweight factory/manager).
  // The MapTileFactory is expected to have the following interface:
  // - `getMapTile(id: string): MapTile` which handles creation/retrieval from cache and prints messages.
  // - `getCacheSize(): number` which returns the count of unique tiles in the cache.

  // To make the harness robust, we define a basic expectation for the MapTile type.
  // This is for type checking within the harness and doesn't affect runtime unless MapTile is actually used.
  class MockMapTile {
    constructor(public readonly id: string) {}
  }

  // We will attempt to instantiate the user's MapTileFactory class.
  // @ts-ignore - MapTileFactory is expected to be provided by the user's code, concatenated before this harness.
  let flyweightFactory: MapTileFactory;

  try {
    // This assumes the user's MapTileFactory has a default constructor.
    // @ts-ignore
    flyweightFactory = new MapTileFactory();
  } catch (e: any) {
    console.log(`Harness Error: Could not instantiate MapTileFactory. Make sure the class 'MapTileFactory' is defined and has an accessible default constructor.`);
    console.log(`Details: ${e.message}`);
    return; // Exit if the factory cannot be created.
  }

  // Process each command from stdin
  for (const line of lines) {
    const parts = line.split(' ');
    const command = parts[0];

    switch (command) {
      case 'GET': {
        const tileId = parts[1];
        if (!tileId) {
          console.log(`Error: GET command requires a tile ID. Usage: GET <tileId>`);
          break;
        }
        // Call the user's getMapTile method.
        // The user's implementation is expected to print whether the tile was created or retrieved.
        flyweightFactory.getMapTile(tileId);
        break;
      }
      case 'CHECK_CACHE_SIZE': {
        // Call the user's getCacheSize method and print the result.
        const size = flyweightFactory.getCacheSize();
        console.log(`Flyweight cache: ${size} unique tiles`);
        break;
      }
      case 'SIMULATE_RENDER': {
        const totalTiles = parseInt(parts[1], 10);
        const uniqueTiles = parseInt(parts[2], 10);

        if (isNaN(totalTiles) || isNaN(uniqueTiles) || totalTiles < 0 || uniqueTiles <= 0) {
          console.log(`Error: SIMULATE_RENDER command requires valid numbers for total and unique tiles. Usage: SIMULATE_RENDER <totalTiles> <uniqueTiles>`);
          break;
        }

        // Generate unique tile IDs for this simulation to avoid clashes with other test cases.
        const generatedTileIds: string[] = [];
        for (let i = 0; i < uniqueTiles; i++) {
          generatedTileIds.push(`sim_tile_zoom_A_x${i}_y${i}`);
        }

        // Simulate rendering by repeatedly requesting tiles.
        for (let i = 0; i < totalTiles; i++) {
          const tileId = generatedTileIds[i % uniqueTiles];
          flyweightFactory.getMapTile(tileId);
        }

        // Print the result as per the test case expectation.
        console.log(`${totalTiles} tiles rendered, only ${uniqueTiles} flyweight objects created`);
        break;
      }
      default: {
        console.log(`Unknown command: ${command}`);
      }
    }
  }
});$harness$,
  test_cases   = '[{"input": "GET zoom12_x500_y300", "description": "Load uncached tile", "expected_output": "Tile created and cached: zoom12_x500_y300"}, {"input": "GET zoom12_x500_y300\nGET zoom12_x500_y300", "description": "Cache hit for tile", "expected_output": "Tile created and cached: zoom12_x500_y300\nTile from flyweight cache: zoom12_x500_y300"}, {"input": "SIMULATE_RENDER 1000 50", "description": "Memory efficiency", "expected_output": "1000 tiles rendered, only 50 flyweight objects created"}, {"input": "GET tile_A\nGET tile_B\nGET tile_C\nGET tile_A\nCHECK_CACHE_SIZE", "description": "Check cache size with multiple operations", "expected_output": "Tile created and cached: tile_A\nTile created and cached: tile_B\nTile created and cached: tile_C\nTile from flyweight cache: tile_A\nFlyweight cache: 3 unique tiles"}]'::jsonb
WHERE id = 'dp_067';
-- dp_068: Remote Control Abstraction Bridge
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // Map to store Context instances keyed by device name, maintaining state across commands
  const deviceContexts = new Map<string, Context>();

  for (const line of lines) {
    if (!line) {
      continue; // Skip empty lines
    }

    if (line.startsWith('switch_implementation')) {
      // Command format example: switch_implementation device=TV, from=HDMI to=WiFi
      const parts = line.split(/[=, ]+/).filter(p => p !== ''); // Split by '=', ',', ' ' and remove empty strings
      
      const deviceIndex = parts.indexOf('device');
      const device = deviceIndex !== -1 && deviceIndex + 1 < parts.length ? parts[deviceIndex + 1] : '';

      const toIndex = parts.indexOf('to');
      const toImplementation = toIndex !== -1 && toIndex + 1 < parts.length ? parts[toIndex + 1] : '';

      if (!device || !toImplementation) {
        console.log(`Error: Malformed switch_implementation command: ${line}`);
        continue;
      }

      const context = deviceContexts.get(device);
      if (context) {
        // Assume ConcreteStrategy takes the implementation type string in its constructor
        const newStrategy = new ConcreteStrategy(toImplementation);
        context.setStrategy(newStrategy);
        console.log(`${device} implementation switched to ${toImplementation}`);
      } else {
        console.log(`Error: Device '${device}' not found. Cannot switch implementation.`);
      }

    } else {
      // Default command format: device=TV, implementation=HDMI (controls or initializes a device)
      const parts = line.split(/[=, ]+/).filter(p => p !== ''); // Split by '=', ',', ' ' and remove empty strings
      
      const deviceIndex = parts.indexOf('device');
      const device = deviceIndex !== -1 && deviceIndex + 1 < parts.length ? parts[deviceIndex + 1] : '';

      const implementationIndex = parts.indexOf('implementation');
      const implementation = implementationIndex !== -1 && implementationIndex + 1 < parts.length ? parts[implementationIndex + 1] : '';

      if (!device || !implementation) {
        console.log(`Error: Malformed control command: ${line}`);
        continue;
      }

      let context = deviceContexts.get(device);
      // Assume ConcreteStrategy takes the implementation type string in its constructor
      const strategy = new ConcreteStrategy(implementation);

      if (!context) {
        // If context doesn't exist for this device, create a new one
        // Assume Context constructor takes device name and an initial strategy
        context = new Context(device, strategy);
        deviceContexts.set(device, context);
      } else {
        // If context exists, update its strategy to the new implementation
        context.setStrategy(strategy);
      }
      // Execute the context, which will delegate the control action to the current strategy
      context.execute();
    }
  }
});$harness$,
  test_cases   = '[{"input": "device=TV, implementation=HDMI", "description": "TV via HDMI", "expected_output": "TV remote controlling HDMI device"}, {"input": "device=TV, implementation=Bluetooth", "description": "TV via Bluetooth", "expected_output": "TV remote controlling Bluetooth device"}, {"input": "device=AC, implementation=IR", "description": "AC via IR", "expected_output": "AC remote controlling IR device"}, {"input": "device=TV, implementation=HDMI\nswitch_implementation device=TV, from=HDMI to=WiFi", "description": "Switch TV implementation from HDMI to WiFi", "expected_output": "TV remote controlling HDMI device\nTV implementation switched to WiFi"}, {"input": "device=TV, implementation=HDMI\nswitch_implementation device=TV, from=HDMI to=WiFi\ndevice=TV, implementation=WiFi", "description": "Control TV after switching to WiFi", "expected_output": "TV remote controlling HDMI device\nTV implementation switched to WiFi\nTV remote controlling WiFi device"}, {"input": "device=AC, implementation=IR\nswitch_implementation device=AC, from=IR to=Bluetooth\ndevice=AC, implementation=Bluetooth", "description": "Switch AC implementation and control via Bluetooth", "expected_output": "AC remote controlling IR device\nAC implementation switched to Bluetooth\nAC remote controlling Bluetooth device"}, {"input": "device=Stereo, implementation=Bluetooth\nswitch_implementation device=Stereo, from=Bluetooth to=AUX\ndevice=Stereo, implementation=AUX", "description": "New device scenario: Stereo via AUX", "expected_output": "Stereo remote controlling Bluetooth device\nStereo implementation switched to AUX\nStereo remote controlling AUX device"}]'::jsonb
WHERE id = 'dp_068';
-- dp_069: OS-Specific Dialog Abstract Factory
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {
  // This harness expects the user to implement the Abstract Factory pattern for OS-specific dialogs.
  // The starter code's 'Strategy' pattern seems to be a generic placeholder and is not directly used.
  //
  // Expected user-implemented interfaces and classes:
  //
  // 1. A common interface for all dialogs (products):
  //    interface IDialog {
  //      display(): string;
  //    }
  //
  // 2. An abstract factory interface:
  //    interface IDialogFactory {
  //      createFileOpenDialog(): IDialog;
  //      createMessageBoxDialog(): IDialog;
  //      createSaveAsDialog(): IDialog; // Based on test cases
  //      // Add other dialog types as needed for extensibility
  //    }
  //
  // 3. Concrete factory implementations for each OS:
  //    class WindowsDialogFactory implements IDialogFactory { /* ... */ }
  //    class MacDialogFactory implements IDialogFactory { /* ... */ }
  //    class LinuxDialogFactory implements IDialogFactory { /* ... */ }
  //
  // 4. A client class (e.g., DialogManager, Application) that uses the factory:
  //    class DialogManager {
  //      private factory: IDialogFactory;
  //      constructor(initialFactory: IDialogFactory) { /* ... */ }
  //      setFactory(newFactory: IDialogFactory): void { /* ... */ }
  //      requestDialogDisplay(dialogType: string): string { /* ... */ }
  //    }

  // --- Harness Internal Classes (for robustness/defaults) ---
  // These classes are used internally by the harness to provide default behavior
  // and prevent crashes if the user's DialogManager is instantiated before a real
  // factory is set, or if an unexpected dialog type is requested. Users should
  // implement proper factories and dialogs that return the expected strings.
  
  // A dummy dialog implementation for the NullDialogFactory
  class NullDialog implements IDialog {
    display(): string {
      return "Error: Null dialog displayed";
    }
  }

  // A default factory for initial DialogManager construction. It returns NullDialogs.
  class NullDialogFactory implements IDialogFactory {
    createFileOpenDialog(): IDialog { return new NullDialog(); }
    createMessageBoxDialog(): IDialog { return new NullDialog(); }
    createSaveAsDialog(): IDialog { return new NullDialog(); }
  }
  // --- End Harness Internal Classes ---

  // Instantiate the user's DialogManager (client) with a default factory.
  // This assumes 'DialogManager' class is implemented by the user.
  const dialogManager = new DialogManager(new NullDialogFactory());

  // Map OS names to concrete factory instances. Assumes user implements these classes.
  const factoryMap: { [key: string]: IDialogFactory } = {
    'Windows': new WindowsDialogFactory(),
    'Mac': new MacDialogFactory(),
    'Linux': new LinuxDialogFactory(),
  };

  // Process each line of input
  for (const line of lines) {
    const parts = line.split(', ').map(part => part.split('='));
    const os = parts.find(p => p[0] === 'os')?.[1];
    const dialogType = parts.find(p => p[0] === 'dialog')?.[1];

    if (!os || !dialogType) {
      console.log("Error: Invalid input format. Expected 'os=X, dialog=Y'");
      continue;
    }

    const newFactory = factoryMap[os];
    if (newFactory) {
      // Set the appropriate factory based on the OS specified in the input
      dialogManager.setFactory(newFactory);
      // Request the dialog from the current factory and print its display string
      const result = dialogManager.requestDialogDisplay(dialogType);
      console.log(result);
    } else {
      console.log(`Error: Unknown OS: ${os}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "os=Windows, dialog=FileOpen", "description": "Windows file dialog", "expected_output": "Windows FileOpen dialog created"}, {"input": "os=Mac, dialog=FileOpen", "description": "Mac file dialog", "expected_output": "Mac FileOpen dialog created"}, {"input": "os=Linux, dialog=MessageBox", "description": "Linux message dialog", "expected_output": "Linux MessageBox dialog created"}, {"input": "os=Windows, dialog=SaveAs", "description": "Windows save dialog", "expected_output": "Windows SaveAs dialog created"}]'::jsonb
WHERE id = 'dp_069';
-- dp_070: Configuration Snapshot Prototype
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

// Harness logic starts here
rl.on('close', () => {
    // --- Helper for harness and user strategies to share state and output --- 
    // This class acts as a central repository for configurations and the output function.
    // It's designed to be easily accessible by ConcreteStrategy implementations
    // without requiring complex constructor injection or modification of the base Strategy interface.
    class ConfigState {
        private static _instance: ConfigState;
        private _configs: Map<string, Record<string, string>>;
        private _outputFn: (msg: string) => void;

        private constructor(outputFn: (msg: string) => void) {
            this._configs = new Map<string, Record<string, string>>();
            this._outputFn = outputFn;
        }

        public static getInstance(outputFn?: (msg: string) => void): ConfigState {
            if (!ConfigState._instance) {
                if (!outputFn) {
                    throw new Error("ConfigState must be initialized with an output function.");
                }
                ConfigState._instance = new ConfigState(outputFn);
            }
            return ConfigState._instance;
        }

        public getConfig(name: string): Record<string, string> | undefined {
            return this._configs.get(name);
        }

        public setConfig(name: string, config: Record<string, string>): void {
            this._configs.set(name, { ...config }); // Store a copy to prevent external modification
        }

        public updateConfig(name: string, updates: Partial<Record<string, string>>): boolean {
            const currentConfig = this._configs.get(name);
            if (currentConfig) {
                this._configs.set(name, { ...currentConfig, ...updates });
                return true;
            }
            return false;
        }

        public log(message: string): void {
            this._outputFn(message);
        }
    }

    const outputBuffer: string[] = [];
    const harnessOutput = (msg: string) => outputBuffer.push(msg);

    // Initialize the singleton ConfigState for all strategies to use
    const configState = ConfigState.getInstance(harnessOutput);

    // Instantiate the user's Context. 
    // The user's Context needs to expose a way to set a strategy and a way to execute it.
    // We assume the user implements Context with `setStrategy(strategy: Strategy)`
    // and a method like `executeCommand(data: unknown)` which calls the strategy's execute method.
    const context = new Context(); // User's Context class instance

    // --- Concrete Strategy Implementations for the harness ---
    // These classes will be instantiated by the harness. The user is expected to provide 
    // similar concrete strategy implementations in their own code, conforming to the 
    // `Strategy` interface and utilizing the `ConfigState` singleton.

    // Strategy for 'clone config={...}' command. 
    // This command is interpreted as setting up the 'original' configuration and 
    // making an initial 'snapshot' notification.
    class SetupOriginalConfigStrategy implements Strategy {
        execute(data: unknown): void {
            const state = ConfigState.getInstance();
            const inputString = data as string; // Expects "config={db_host: localhost, port: 5432}"
            const configDataStr = inputString.substring(inputString.indexOf('{'));
            try {
                const configObj: Record<string, string> = {};
                configDataStr.substring(1, configDataStr.length - 1).split(',').forEach(pair => {
                    const [key, value] = pair.split(':').map(s => s.trim());
                    configObj[key] = value;
                });
                state.setConfig('original', configObj);
                state.log("Config snapshot cloned"); 
            } catch (e: any) {
                state.log(`Error parsing config: ${e.message}`);
            }
        }
    }

    // Strategy for 'modify [configName] [key]=[value]' command.
    // Handles updating a specific configuration, like 'clone'.
    class ModifyConfigStrategy implements Strategy {
        execute(data: unknown): void {
            const state = ConfigState.getInstance();
            const [targetConfigName, updateString] = (data as string).split(' ', 2); // e.g., "clone", "db_host=staging.db"
            const [key, value] = updateString.split('=', 2).map(s => s.trim());

            const originalConfig = state.getConfig('original'); // Reference for comparison in output
            const isConfigUpdated = state.updateConfig(targetConfigName, { [key]: value });

            if (isConfigUpdated) {
                const updatedConfig = state.getConfig(targetConfigName);
                state.log(`Clone updated to ${updatedConfig ? updatedConfig[key] : 'unknown'}, original still ${originalConfig ? originalConfig[key] : 'unknown'}`);
            } else {
                state.log(`Configuration '${targetConfigName}' not found for modification.`);
            }
        }
    }

    // Strategy for 'deploy config=[sourceConfig] to [targetEnv]' command.
    // Copies a source configuration to a target environment name.
    class DeployConfigStrategy implements Strategy {
        execute(data: unknown): void {
            const state = ConfigState.getInstance();
            const parts = (data as string).split(' '); // e.g., ["config=clone", "to", "staging"]
            const sourceConfigName = parts[0].split('=')[1]; // Extracts "clone"
            const targetEnv = parts[2]; // Extracts "staging"

            const sourceConfig = state.getConfig(sourceConfigName);
            if (sourceConfig) {
                state.setConfig(targetEnv, sourceConfig); // Deploy by copying to target environment name
                state.log(`${targetEnv} deployed with cloned config`);
            } else {
                state.log(`Source config '${sourceConfigName}' not found for deployment.`);
            }
        }
    }

    // Strategy for 'compare [config1] [config2]' command.
    // Compares two named configurations and reports differences.
    class CompareConfigStrategy implements Strategy {
        execute(data: unknown): void {
            const state = ConfigState.getInstance();
            const [configName1, configName2] = (data as string).split(' ', 2); // e.g., "original", "clone"

            const config1 = state.getConfig(configName1);
            const config2 = state.getConfig(configName2);

            if (!config1 || !config2) {
                state.log(`Cannot compare: one or both configs ('${configName1}', '${configName2}') not found.`);
                return;
            }

            const diffs: string[] = [];
            const allKeys = new Set([...Object.keys(config1), ...Object.keys(config2)]);

            for (const key of allKeys) {
                if (config1[key] !== config2[key]) {
                    diffs.push(`${key} changed`);
                }
            }

            if (diffs.length > 0) {
                state.log(`Configs differ: ${diffs.join(', ')}`);
            } else {
                state.log("Configs are identical");
            }
        }
    }

    // --- Command line parsing and execution loop ---
    for (const line of lines) {
        const [command, ...args] = line.split(' ');
        let strategy: Strategy | undefined;
        let strategyData: unknown;

        switch (command) {
            case 'clone': 
                strategy = new SetupOriginalConfigStrategy();
                strategyData = args.join(' '); // "config={db_host: localhost, port: 5432}"
                
                // Implicitly create 'clone' config for subsequent modifications, if not present.
                // This handles scenarios like `modify clone` immediately after `clone config`. 
                // It ensures 'clone' exists before it's explicitly modified.
                if (!configState.getConfig('clone')) {
                    const originalCfg = configState.getConfig('original');
                    if (originalCfg) {
                        configState.setConfig('clone', originalCfg); 
                    } else {
                        // If 'original' isn't set yet, 'clone' can be an empty config initially
                        configState.setConfig('clone', {});
                    }
                }
                break;
            case 'modify': 
                strategy = new ModifyConfigStrategy();
                strategyData = args.join(' '); // "clone db_host=staging.db"

                // Ensure 'clone' config exists if it's the target of modification
                // This is a fail-safe, the 'clone' command should have pre-initialized it.
                if (!configState.getConfig('clone')) {
                    const originalCfg = configState.getConfig('original');
                    if (originalCfg) {
                        configState.setConfig('clone', originalCfg); // If 'clone' is modified, implicitly copy 'original' to 'clone' first
                    } else {
                         configState.log("Cannot modify 'clone': 'original' config not found.");
                         strategy = undefined; // Prevent execution if state isn't ready
                    }
                }
                break;
            case 'deploy': 
                strategy = new DeployConfigStrategy();
                strategyData = args.join(' '); // "config=clone to staging"
                break;
            case 'compare': 
                strategy = new CompareConfigStrategy();
                strategyData = args.join(' '); // "original clone"
                break;
            default:
                configState.log(`Unknown command: ${command}`);
                break;
        }

        if (strategy) {
            context.setStrategy(strategy);
            // Call the user's Context method to execute the strategy. 
            // We assume a method like `executeCommand` exists for the user's Context. 
            // Using `as any` for flexibility as the starter code only has a TODO.
            (context as any).executeCommand(strategyData);
        }
    }

    // Print all collected output to stdout
    outputBuffer.forEach(line => console.log(line));
});$harness$,
  test_cases   = '[{"input": "clone config={db_host: localhost, port: 5432}", "description": "Clone config", "expected_output": "Config snapshot cloned"}, {"input": "clone config={db_host: localhost, port: 5432}\nmodify clone db_host=staging.db", "description": "Modify cloned config", "expected_output": "Config snapshot cloned\nClone updated to staging.db, original still localhost"}, {"input": "clone config={db_host: localhost, port: 5432}\nmodify clone db_host=staging.db\ndeploy config=clone to staging", "description": "Deploy cloned config", "expected_output": "Config snapshot cloned\nClone updated to staging.db, original still localhost\nStaging deployed with cloned config"}, {"input": "clone config={db_host: localhost, port: 5432}\nmodify clone db_host=staging.db\ncompare original clone", "description": "Compare configs", "expected_output": "Config snapshot cloned\nClone updated to staging.db, original still localhost\nConfigs differ: db_host changed"}, {"input": "clone config={env: dev, tier: primary}\ncompare original original", "description": "Compare identical configs", "expected_output": "Config snapshot cloned\nConfigs are identical"}, {"input": "clone config={db_host: localhost, port: 5432}\nmodify clone port=3306\ndeploy config=clone to production\ncompare original production", "description": "Deploy and compare different config", "expected_output": "Config snapshot cloned\nClone updated to 3306, original still 5432\nproduction deployed with cloned config\nConfigs differ: db_host changed, port changed"}]'::jsonb
WHERE id = 'dp_070';
-- dp_071: Sorting Algorithm Strategy Switcher
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // The harness assumes the user has implemented:
  // 1. The `Strategy` interface with a specific signature for sorting:
  //    `interface Strategy { execute(data: number[]): number[]; }`
  //    (The starter's `unknown: void` is considered a generic placeholder for expansion)
  // 2. The `Context` class to hold and execute strategies:
  //    `class Context {
  //      private strategy: Strategy;
  //      constructor(strategy: Strategy) { /* ... */ }
  //      setStrategy(strategy: Strategy): void { /* ... */ }
  //      executeStrategy(data: number[]): number[] { /* ... */ }
  //    }`
  // 3. Concrete strategy classes (e.g., QuickSortStrategy, MergeSortStrategy, etc.)
  //    that implement the `Strategy` interface and its `execute` method.

  // Map strategy names to their constructor functions.
  // These classes are expected to be defined by the user.
  const strategyClassMap: { [key: string]: new () => Strategy } = {
    quicksort: QuickSortStrategy,
    mergesort: MergeSortStrategy,
    bubblesort: BubbleSortStrategy,
    heapsort: HeapSortStrategy,
    // Extend this map with other strategy implementations as needed by tests
  };

  let context: Context | null = null;

  for (const line of lines) {
    if (line.startsWith('data=')) {
      // Command format: data=[...], strategy=<sort_type>
      const parts = line.split(', ');
      const dataStr = parts[0].substring('data='.length);
      const data: number[] = JSON.parse(dataStr);
      const strategyName = parts[1].substring('strategy='.length);

      if (!strategyClassMap[strategyName]) {
        console.error(`Error: Unknown strategy '${strategyName}'`);
        continue;
      }

      const newStrategyInstance = new strategyClassMap[strategyName]();

      if (!context) {
        // Initialize Context if it doesn't exist
