      } catch (e: any) {
        console.error(`Error executing strategy '${strategyName}': ${e.message}`);
      }

    } else if (line.startsWith('switch_strategy')) {
      // Command format: switch_strategy from=<old_strategy> to=<new_strategy>
      const parts = line.split(' '); // e.g., ['switch_strategy', 'from=quicksort', 'to=heapsort']
      const newStrategyName = parts[2].substring('to='.length); // Extract 'heapsort'

      if (!strategyClassMap[newStrategyName]) {
        console.error(`Error: Unknown strategy '${newStrategyName}'`);
        continue;
      }

      const newStrategyInstance = new strategyClassMap[newStrategyName]();

      if (!context) {
        // Initialize Context if it doesn't exist, with the new strategy
        context = new Context(newStrategyInstance);
      } else {
        context.setStrategy(newStrategyInstance);
      }
