UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // Application state, managed by the harness, passed to strategies for modification.
  // This simulates an external 'SensorNetworkManager' that ConcreteStrategies interact with.
  const sensorSubscriptions = new Map<string, Set<string>>(); // Maps sensor_id -> Set<display_id>
  const sensorReadings = new Map<string, number>();           // Maps sensor_id -> latest_value

  // Instantiate the user's Context.
  // In this setup, the Context just holds the current strategy and delegates execution.
  // It does not directly manage the application state; strategies operate on the state provided to them.
  const context = new Context();

  // Helper function for strategies to log output, ensuring all output goes through console.log
  const logOutput = (message: string) => {
    console.log(message);
  };

  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    // Parse command: "command_type param1=value1, param2=value2, ..."
    const parts = line.split(' ');
    const commandType = parts[0];
    const argsString = parts.slice(1).join(' ').trim();
    const commandArgs: Record<string, string> = {};

    argsString.split(',').forEach(arg => {
      const [key, value] = arg.split('=').map(s => s.trim());
      if (key && value) {
        commandArgs[key] = value;
      }
    });

    let strategy: Strategy | null = null;

    // The harness dynamically selects and instantiates the appropriate concrete strategy
    // based on the command type. This assumes the user has implemented specific
    // strategy classes (e.g., SubscribeCommandStrategy, UpdateCommandStrategy) that
    // implement the `Strategy` interface.
    try {
      switch (commandType) {
        case 'subscribe':
          // Assuming user provides 'SubscribeCommandStrategy'
          strategy = new (global as any).SubscribeCommandStrategy();
          break;
        case 'update':
          // Assuming user provides 'UpdateCommandStrategy'
          strategy = new (global as any).UpdateCommandStrategy();
          break;
        case 'sensor_alert':
          // Assuming user provides 'SensorAlertCommandStrategy'
          strategy = new (global as any).SensorAlertCommandStrategy();
          break;
        case 'unsubscribe':
          // Assuming user provides 'UnsubscribeCommandStrategy'
          strategy = new (global as any).UnsubscribeCommandStrategy();
          break;
        default:
          logOutput(`Error: Unknown command type '${commandType}'`);
          continue;
      }
    } catch (e: any) {
      logOutput(`Error instantiating strategy for command '${commandType}': ${e.message}`);
      continue;
    }

    if (strategy) {
      // Set the selected strategy on the context
      context.setStrategy(strategy);
      
      // Execute the strategy, passing all necessary data:
      // - The command arguments for the strategy to process.
      // - References to the shared application state (subscriptions, readings).
      // - A logging function to capture output consistently.
      context.execute({
        commandArgs,          // Arguments specific to the current command
        sensorSubscriptions,  // Reference to the map of subscriptions
        sensorReadings,       // Reference to the map of sensor values
        log: logOutput,       // Function for strategies to use for output
      });
    }
  }
});$harness$,
  test_cases   = '[{"input": "subscribe display=dashboard, sensor=temp_sensor_1", "description": "Subscribe to sensor", "expected_output": "Dashboard subscribed to temp_sensor_1"}, {"input": "subscribe display=dashboard, sensor=temp_sensor_1\nupdate sensor=temp_sensor_1, value=28.5", "description": "Sensor reading update", "expected_output": "Dashboard subscribed to temp_sensor_1\nDashboard notified: temp_sensor_1 = 28.5C"}, {"input": "subscribe display=dashboard, sensor=temp_sensor_1\nupdate sensor=temp_sensor_1, value=25\nsensor_alert sensor=temp_sensor_1, threshold=30C", "description": "Threshold alert", "expected_output": "Dashboard subscribed to temp_sensor_1\nDashboard notified: temp_sensor_1 = 25C\nAlert: temp_sensor_1 exceeded 30C"}, {"input": "subscribe display=dashboard, sensor=temp_sensor_1\nunsubscribe display=dashboard, sensor=temp_sensor_1", "description": "Unsubscribe from sensor", "expected_output": "Dashboard subscribed to temp_sensor_1\nDashboard unsubscribed from temp_sensor_1"}, {"input": "subscribe display=dashboard, sensor=temp_sensor_A\nsubscribe display=monitor, sensor=temp_sensor_A\nupdate sensor=temp_sensor_A, value=22.1", "description": "Multiple displays subscribed to one sensor are notified", "expected_output": "Dashboard subscribed to temp_sensor_A\nMonitor subscribed to temp_sensor_A\nDashboard notified: temp_sensor_A = 22.1C\nMonitor notified: temp_sensor_A = 22.1C"}, {"input": "subscribe display=dashboard, sensor=temp_sensor_B\nsubscribe display=monitor, sensor=temp_sensor_B\nunsubscribe display=monitor, sensor=temp_sensor_B\nupdate sensor=temp_sensor_B, value=19.0", "description": "One display unsubscribes, others remain subscribed", "expected_output": "Dashboard subscribed to temp_sensor_B\nMonitor subscribed to temp_sensor_B\nMonitor unsubscribed from temp_sensor_B\nDashboard notified: temp_sensor_B = 19.0C"}, {"input": "update sensor=pressure_sensor_1, value=100.5\nsensor_alert sensor=pressure_sensor_1, threshold=120", "description": "Updating a sensor with no active subscribers and then alerting", "expected_output": "Alert: pressure_sensor_1 exceeded 120"}]'::jsonb
