UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

const lines: string[] = [];
rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', () => {
  // Access user-defined classes from the global scope.
  // We assume the user implements a Context class with a `setStrategy` method
  // and a `dispatch` method, and concrete strategy classes like CarStrategy, etc.
  // The starter code provides 'interface Strategy' and 'class Context',
  // and 'class ConcreteStrategy'. For the Strategy pattern, the user is expected
  // to implement specific vehicle strategies (e.g., CarStrategy, VanStrategy)
  // instead of just one generic ConcreteStrategy.

  // Dynamically get user-defined classes/interfaces
  const UserStrategy: (new (...args: any[]) => any) | undefined = (global as any).Strategy;
  const UserContext: (new (...args: any[]) => any) | undefined = (global as any).Context;

  if (!UserContext || !UserStrategy) {
    console.log("Harness Error: User's Context class or Strategy interface not found. Ensure they are defined correctly.");
    return;
  }

  const context = new UserContext();

  // Instantiate strategy objects based on expected factory types from test cases.
  // We assume the user creates concrete strategy classes named CarStrategy, VanStrategy, etc.
  const availableStrategies: Record<string, any> = {};

  try {
    if ((global as any).CarStrategy) availableStrategies['car'] = new (global as any).CarStrategy();
    if ((global as any).VanStrategy) availableStrategies['van'] = new (global as any).VanStrategy();
    if ((global as any).MotorcycleStrategy) availableStrategies['motorcycle'] = new (global as any).MotorcycleStrategy();
    if ((global as any).TruckStrategy) availableStrategies['truck'] = new (global as any).TruckStrategy();
  } catch (e: any) {
    console.log(`Harness Error: Could not instantiate one or more strategy classes. Ensure classes like CarStrategy, VanStrategy, MotorcycleStrategy, and TruckStrategy are correctly implemented and extend the Strategy interface. Error: ${e.message}`);
    return;
  }

  for (const line of lines) {
    if (!line) continue;

    const parts = line.split(' ');
    const command = parts[0];
    const args = parts.slice(1).join(' ');

    try {
      if (command === 'SET_FACTORY') {
        const factoryType = args.toLowerCase();
        const strategyInstance = availableStrategies[factoryType];
        if (strategyInstance) {
          // The user's Context class must have a setStrategy method.
          context.setStrategy(strategyInstance);
          // No output for state change commands typically
        } else {
          console.log(`Harness Error: Unknown factory type '${factoryType}'. Make sure a corresponding strategy class (e.g., ${factoryType.charAt(0).toUpperCase() + factoryType.slice(1)}Strategy) is implemented and available.`);
        }
      } else if (command === 'DISPATCH') {
        const vehicleType = args;
        // The user's Context class must have a dispatch method that uses the currently set strategy.
        // The strategy's execute method should then print the output using console.log().
        context.dispatch(vehicleType);
      } else {
        console.log(`Harness Error: Unknown command '${command}'.`);
      }
    } catch (e: any) {
      console.log(`Harness Error during command '${line}': ${e.message}`);
    }
  }
});$harness$,
