-- dp_074: Meal Plan Builder Nutritionist
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {
    // --- START Harness Logic ---

    // Define internal data for nutrition calculations
    const mealNutrientData = {
        'oats': { calories: 150, protein: 5 },
        'milk': { calories: 100, protein: 8 },
        'banana': { calories: 200, protein: 2 },
        'chicken': { calories: 300, protein: 50 },
        'rice': { calories: 250, protein: 5 },
        'vegetables': { calories: 100, protein: 10 },
        'egg': { calories: 80, protein: 6 },
        'bread': { calories: 120, protein: 4 },
        'apple': { calories: 90, protein: 0 },
        'yogurt': { calories: 150, protein: 15 },
        'fish': { calories: 250, protein: 45 },
        'quinoa': { calories: 200, protein: 8 },
        'lentils': { calories: 200, protein: 15 }
    };

    // State variables maintained across commands
    let currentNutritionGoals = { calories: 0, protein: 0 };
    const mealsRecord: { [key: string]: { items: string[]; calories: number; protein: number } } = {};

    // Internal Strategy implementations (these fulfill the `Strategy` interface from user code)
    // and encapsulate the logic for each command type.
    class HarnessSetGoalStrategy implements Strategy {
        constructor(private goals: typeof currentNutritionGoals) {}

        execute(data: unknown): void {
            const params = data as { calories: number; protein: number };
            this.goals.calories = params.calories;
            this.goals.protein = params.protein;
            console.log(`Nutrition goal set: ${this.goals.calories} cal, ${this.goals.protein}g protein`);
        }
    }

    class HarnessAddMealStrategy implements Strategy {
        constructor(private mealsRecord: typeof mealsRecord, private nutrientData: typeof mealNutrientData) {}

        execute(data: unknown): void {
            const params = data as { mealType: string; items: string[] };
            let totalCalories = 0;
            let totalProtein = 0;

            for (const item of params.items) {
                const nutrients = this.nutrientData[item.toLowerCase()];
                if (nutrients) {
                    totalCalories += nutrients.calories;
                    totalProtein += nutrients.protein;
                } else {
                    // If an item is not found, assume 0 nutrition for simplicity in this challenge
                }
            }
            this.mealsRecord[params.mealType] = { items: params.items, calories: totalCalories, protein: totalProtein };
            // Capitalize meal type for output consistency (e.g., 'breakfast' -> 'Breakfast')
            const mealTypeOutput = params.mealType.charAt(0).toUpperCase() + params.mealType.slice(1);
            console.log(`${mealTypeOutput} added: ${totalCalories} cal, ${totalProtein}g protein`);
        }
    }

    class HarnessBuildPlanStrategy implements Strategy {
        constructor(private goals: typeof currentNutritionGoals, private mealsRecord: typeof mealsRecord) {}

        execute(data: unknown): void {
            let totalPlannedCalories = 0;
            // let totalPlannedProtein = 0; // Not used in the current output string, but could be extended.
            for (const mealType in this.mealsRecord) {
                totalPlannedCalories += this.mealsRecord[mealType].calories;
                // totalPlannedProtein += this.mealsRecord[mealType].protein;
            }

            const calorieStatus = totalPlannedCalories >= this.goals.calories ? "target met" : "target not met";
            // Simple heuristic for days planned: if any meals are recorded, assume 7 days.
            const daysPlanned = Object.keys(this.mealsRecord).length > 0 ? 7 : 0;

            console.log(`Meal plan built: ${this.goals.calories} cal ${calorieStatus}, meals planned for ${daysPlanned} days`);
        }
    }

    // Instantiate user's Context class and our harness-specific strategy implementations.
    // These instances are stateful and persist throughout the challenge execution.
    const context = new Context();
    const setGoalStrategy = new HarnessSetGoalStrategy(currentNutritionGoals);
    const addMealStrategy = new HarnessAddMealStrategy(mealsRecord, mealNutrientData);
    const buildPlanStrategy = new HarnessBuildPlanStrategy(currentNutritionGoals, mealsRecord);

    // Process each command line from stdin
    for (const line of lines) {
        if (!line) continue; // Skip empty lines

        if (line.startsWith('set_goal')) {
            const parts = line.substring('set_goal '.length).split(',').map(s => s.trim());
            let calories = 0;
            let protein = 0;
            for (const part of parts) {
                if (part.startsWith('calories=')) {
                    calories = parseInt(part.substring('calories='.length), 10);
                } else if (part.startsWith('protein=')) {
                    protein = parseInt(part.substring('protein='.length).replace('g', ''), 10);
                }
            }
            context.setStrategy(setGoalStrategy);
            context.executeStrategy({ calories, protein });
        } else if (line.startsWith('add_meal')) {
            const parts = line.substring('add_meal '.length).split('=').map(s => s.trim());
            const mealType = parts[0]; // e.g., 'breakfast'
            // Extract items from inside [] and split by comma
            const itemsString = parts[1].substring(1, parts[1].length - 1); // Remove leading/trailing brackets
            const items = itemsString.split(',').map(item => item.trim()); // Split by comma and trim each item

            context.setStrategy(addMealStrategy);
            context.executeStrategy({ mealType, items });
        } else if (line.startsWith('build_plan')) {
            context.setStrategy(buildPlanStrategy);
            context.executeStrategy({}); // No specific data needed for build_plan in this setup
        } else {
            // If an unknown command is encountered, log an error. This will typically fail the test.
            console.error(`Error: Unknown command encountered: ${line}`);
        }
    }
    // --- END Harness Logic ---
});$harness$,
  test_cases   = '[{"input": "set_goal calories=2000, protein=150g", "description": "Set nutrition goals", "expected_output": "Nutrition goal set: 2000 cal, 150g protein"}, {"input": "set_goal calories=2000, protein=150g\nadd_meal breakfast=[oats, milk, banana]", "description": "Add breakfast", "expected_output": "Nutrition goal set: 2000 cal, 150g protein\nBreakfast added: 450 cal, 15g protein"}, {"input": "set_goal calories=2000, protein=150g\nadd_meal breakfast=[oats, milk, banana]\nadd_meal lunch=[chicken, rice, vegetables]", "description": "Add lunch", "expected_output": "Nutrition goal set: 2000 cal, 150g protein\nBreakfast added: 450 cal, 15g protein\nLunch added: 650 cal, 65g protein"}, {"input": "set_goal calories=2000, protein=150g\nadd_meal breakfast=[oats, milk, banana]\nadd_meal lunch=[chicken, rice, vegetables]\nbuild_plan", "description": "Build full meal plan", "expected_output": "Nutrition goal set: 2000 cal, 150g protein\nBreakfast added: 450 cal, 15g protein\nLunch added: 650 cal, 65g protein\nMeal plan built: 2000 cal target not met, meals planned for 7 days"}]'::jsonb
WHERE id = 'dp_074';
