// DUMMY implementations for harness to compile and illustrate expected interaction.
// These will be overridden by the user's actual code during testing.
// The harness relies on user implementing specific class names for decorators.
// The `if (typeof ... === 'undefined')` checks ensure that these dummy classes are only
// defined if the user hasn't defined them, making the harness robust to user's class definitions.

// Redefine Strategy interface for harness's internal use with a more specific type
// This will be compatible with the user's `unknown` type in their `Strategy` interface.
interface Strategy {
  execute(data: Record<string, any>): void;
}

// Dummy Context implementation, expected API for user's Context:
// - constructor()
// - addStrategy(name: string, strategy: Strategy)
// - decorateEvent(eventName: string, decoratorNames: string[]): Record<string, any>
// - flushEvents(): number
// This class will be replaced by the user's actual Context class.
if (typeof Context === 'undefined') {
  class Context {
    private strategies: Map<string, Strategy>;
    private storedEvents: Array<Record<string, any>>;

    constructor() {
      this.strategies = new Map();
      this.storedEvents = [];
    }

    public addStrategy(name: string, strategy: Strategy): void {
      this.strategies.set(name, strategy);
    }

    public decorateEvent(eventName: string, decoratorNames: string[]): Record<string, any> {
      const eventData: Record<string, any> = { event: eventName };
      for (const name of decoratorNames) {
        const strategy = this.strategies.get(name);
        if (strategy) {
          strategy.execute(eventData);
        } // In a real scenario, an unknown strategy might throw or log an error.
      }
      this.storedEvents.push(eventData);
      return eventData;
    }

    public flushEvents(): number {
      const count = this.storedEvents.length;
      this.storedEvents = []; // Clear events after flushing
      return count;
    }
  }
}

// Dummy Strategy implementations for the harness to instantiate and use.
// These classes will be replaced by user's concrete strategy classes.
// The harness expects the user to create classes named as below and implement `Strategy` interface.
if (typeof TimestampDecorator === 'undefined') {
