      data.user_id = 'u123';
    }
  }
}
if (typeof SessionIdDecorator === 'undefined') {
  class SessionIdDecorator implements Strategy {
    execute(data: Record<string, any>): void {
      data.session_id = 's456';
    }
  }
}
if (typeof GeoLocationDecorator === 'undefined') {
  class GeoLocationDecorator implements Strategy {
    execute(data: Record<string, any>): void {
      data.geo = 'US/New York';
    }
  }
}


const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout,
});

const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // Instantiate specific strategy implementations as per expected decorator names.
  const timestampStrategy = new TimestampDecorator();
  const userIdStrategy = new UserIdDecorator();
  const sessionIdStrategy = new SessionIdDecorator();
  const geoLocationStrategy = new GeoLocationDecorator();

  // Instantiate the user's Context class.
  const context = new Context();

  // Register strategies with the context, assuming Context has an `addStrategy` method.
  context.addStrategy('timestamp', timestampStrategy);
  context.addStrategy('user_id', userIdStrategy);
  context.addStrategy('session_id', sessionIdStrategy);
  context.addStrategy('geo_location', geoLocationStrategy);

  for (const line of lines) {
    if (line.startsWith('event=')) {
      const parts = line.split(',').map(p => p.trim());
      const eventName = parts[0].split('=')[1];
      const decoratorsPart = parts[1];
      let decoratorNames: string[] = [];

      if (decoratorsPart.startsWith('decorator=')) {
        decoratorNames = [decoratorsPart.split('=')[1]];
      } else if (decoratorsPart.startsWith('decorators=[')) {
        decoratorNames = decoratorsPart
          .substring('decorators=['.length, decoratorsPart.length - 1)
