      }

      // Call the user's Context to decorate the event.
      const decoratedEvent = context.decorateEvent(eventName, decoratorNames);

      // Format and print the decorated event.
      let output = `Event: ${decoratedEvent.event}`;
      if (decoratedEvent.timestamp) output += ` | timestamp: ${decoratedEvent.timestamp}`;
      if (decoratedEvent.user_id) output += ` | user_id: ${decoratedEvent.user_id}`;
      if (decoratedEvent.session_id) output += ` | session_id: ${decoratedEvent.session_id}`;
      if (decoratedEvent.geo) output += ` | geo: ${decoratedEvent.geo}`;

      console.log(output);

    } else if (line === 'flush events to analytics') {
      // Call the user's Context to flush events.
      const flushedCount = context.flushEvents();
      console.log(`${flushedCount} decorated events flushed to analytics`);

