rl.on('close', () => {
  // The user's `Context` class is expected to implement the Image Lazy-Load Proxy functionality.
  // It should expose the following public methods for the harness to interact with:
  // - `fetchImage(path: string): void`: Simulates a request to fetch an an image.
  //    Expected to print one of:
  //      "Proxy: image not loaded, returning placeholder"
  //      "Proxy: loading image from origin"
  //      "Proxy: returning cached image"
  // - `notifyInViewport(path: string): void`: Informs the proxy that a specific image has entered the viewport.
  //    This typically updates internal state but does not print output directly.
  // - `reset(): void`: Clears all internal image states and caches.
  //    This typically does not print output directly.
  // - `processBatch(totalImages: number, viewportImages: number): void`: Simulates managing a batch of images.
  //    Expected to print a single summary line: "Only <viewportImages> images loaded, <deferredCount> deferred"

  // Instantiate the user's Context class, which acts as the ImageLazyLoadProxy.
  const proxy = new Context();

  for (const line of lines) {
    if (line === '') continue; // Skip empty lines

    if (line.startsWith('fetch ')) {
      const path = line.substring('fetch '.length);
      proxy.fetchImage(path);
    } else if (line.startsWith('view ')) {
      const path = line.substring('view '.length);
      proxy.notifyInViewport(path);
    } else if (line === 'reset') {
      proxy.reset();
    } else if (line.startsWith('batch ')) {
      const parts = line.substring('batch '.length).split(',');
      const total = parseInt(parts[0], 10);
      const viewport = parseInt(parts[1], 10);
      if (isNaN(total) || isNaN(viewport) || parts.length !== 2) {
        console.log(`Error: Invalid batch command format: ${line}. Expected 'batch <total>,<viewport>'`);
      } else {
        proxy.processBatch(total, viewport);
      }
    } else {
      console.log(`Error: Unknown command: ${line}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "reset\nfetch /assets/hero.jpg", "description": "Lazy load returns placeholder", "expected_output": "Proxy: image not loaded, returning placeholder"}, {"input": "reset\nview /assets/hero.jpg\nfetch /assets/hero.jpg", "description": "Image loaded when in viewport", "expected_output": "Proxy: loading image from origin"}, {"input": "reset\nview /assets/hero.jpg\nfetch /assets/hero.jpg\nfetch /assets/hero.jpg", "description": "Cached image returned", "expected_output": "Proxy: loading image from origin\nProxy: returning cached image"}, {"input": "reset\nbatch 100,5", "description": "Lazy loading defers off-screen images", "expected_output": "Only 5 images loaded, 95 deferred"}]'::jsonb
WHERE id = 'dp_076';
