-- dp_078: Macro Recorder Command Replay
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {
  // Instantiate the user's Context class. The harness expects this class
  // to implement the macro recording/replaying logic with specific methods.
  // The user's Context is expected to have the following public methods
  // that return specific string messages:
  // - startRecording(): string
  // - addCommandsToRecording(commands: string[]): string
  // - stopRecording(macroName: string): string
  // - replayMacro(macroName: string): string
  const macroRecorder = new Context();

  for (const line of lines) {
    let output: string;

    if (line === 'start_recording') {
      output = macroRecorder.startRecording();
    } else if (line.startsWith('record commands=[')) {
      const commandsStr = line.substring('record commands=['.length, line.length - 1);
      const commands = commandsStr.split(', ').map(cmd => cmd.trim());
      output = macroRecorder.addCommandsToRecording(commands);
    } else if (line.startsWith('stop_recording, save as=')) {
      const macroName = line.substring('stop_recording, save as='.length);
      output = macroRecorder.stopRecording(macroName);
    } else if (line.startsWith('replay macro=')) {
      const macroName = line.substring('replay macro='.length);
      output = macroRecorder.replayMacro(macroName);
    } else {
      output = `Unknown command: ${line}`;
    }
    console.log(output);
  }
});$harness$,
  test_cases   = '[{"input": "start_recording\nrecord commands=[open_file, bold_text, save_file]\nstop_recording, save as=format_doc\nreplay macro=format_doc", "description": "Record and replay a simple macro", "expected_output": "Recording started, capturing commands\nMacro recorded: 3 commands\nMacro format_doc saved with 3 commands\nReplaying: open_file -> bold_text -> save_file"}, {"input": "start_recording\nrecord commands=[cut, copy, paste]\nstop_recording, save as=clipboard_ops\nstart_recording\nrecord commands=[find, replace_all]\nstop_recording, save as=text_edit\nreplay macro=clipboard_ops\nreplay macro=text_edit", "description": "Record and replay multiple distinct macros", "expected_output": "Recording started, capturing commands\nMacro recorded: 3 commands\nMacro clipboard_ops saved with 3 commands\nRecording started, capturing commands\nMacro recorded: 2 commands\nMacro text_edit saved with 2 commands\nReplaying: cut -> copy -> paste\nReplaying: find -> replace_all"}, {"input": "replay macro=non_existent", "description": "Attempt to replay a non-existent macro", "expected_output": "Error: Macro non_existent not found or empty."}, {"input": "start_recording\nstop_recording, save as=empty_macro\nreplay macro=empty_macro", "description": "Record and replay an empty macro", "expected_output": "Recording started, capturing commands\nMacro empty_macro saved with 0 commands\nError: Macro empty_macro not found or empty."}, {"input": "start_recording\nrecord commands=[old_command_a, old_command_b]\nstop_recording, save as=my_macro\nreplay macro=my_macro\nstart_recording\nrecord commands=[new_command_x, new_command_y, new_command_z]\nstop_recording, save as=my_macro\nreplay macro=my_macro", "description": "Overwrite an existing macro and replay the new version", "expected_output": "Recording started, capturing commands\nMacro recorded: 2 commands\nMacro my_macro saved with 2 commands\nReplaying: old_command_a -> old_command_b\nRecording started, capturing commands\nMacro recorded: 3 commands\nMacro my_macro saved with 3 commands\nReplaying: new_command_x -> new_command_y -> new_command_z"}, {"input": "record commands=[bad_command]\nstop_recording, save as=bad_macro\nstart_recording\nstart_recording\nstop_recording, save as=another_bad_macro\nstop_recording, save as=yet_another_bad_macro", "description": "Handle various recording/stopping error states", "expected_output": "Error: Not currently recording. Cannot record commands.\nError: Not currently recording.\nRecording started, capturing commands\nError: Already recording.\nMacro another_bad_macro saved with 0 commands\nError: Not currently recording."}]'::jsonb
WHERE id = 'dp_078';
-- dp_079: Graph DFS Iterator Explorer
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  let concreteStrategyInstance: ConcreteStrategy | undefined;
  let contextInstance: Context | undefined;

  // Helper function to parse graph input strings
  function parseGraphInput(inputStr: string): { graph: Map<string, string[]>, startNode: string } {
    let graph: Map<string, string[]> = new Map();
    let startNode: string = '';

    const parts = inputStr.split(', ').map(p => p.trim());

    if (inputStr.startsWith('graph=')) {
      const graphPart = parts.find(p => p.startsWith('graph='));
      const startPart = parts.find(p => p.startsWith('start='));

      if (graphPart) {
        const graphStr = graphPart.replace(/^graph=/, '');
        // Example: {A:[B,C], B:[D], C:[D], D:[]}
        const cleanedGraphStr = graphStr.substring(1, graphStr.length - 1); // Remove outer {} if present
        if (cleanedGraphStr) { // Check if there are any nodes defined
          const nodePairs = cleanedGraphStr.split('],').map(p => p.trim() + ']'); // Split by '],' and re-add ']' to each part

          for (const pair of nodePairs) {
            const [nodeKey, neighborsStr] = pair.split(':[');
            if (nodeKey && neighborsStr !== undefined) {
              const neighbors = neighborsStr.substring(0, neighborsStr.length - 1); // Remove trailing ']'
              graph.set(nodeKey.trim(), neighbors ? neighbors.split(',').map(n => n.trim()) : []);
            }
          }
        }
      }
      if (startPart) {
        startNode = startPart.replace('start=', '');
      }
    } else if (inputStr.startsWith('empty graph')) {
      startNode = parts[1].replace('start=', '');
      graph = new Map(); // Explicitly an empty graph (no nodes, no edges)
    }
    return { graph, startNode };
  }

  // Process each command line
  for (const line of lines) {
    try {
      if (line === 'INIT') {
        // Initialize ConcreteStrategy and Context instances
        concreteStrategyInstance = new ConcreteStrategy();
        contextInstance = new Context(concreteStrategyInstance);
      } else if (line.startsWith('RUN_DFS')) {
        if (!contextInstance || !concreteStrategyInstance) {
          console.log('Error: Harness not initialized. Use INIT first.');
          continue;
        }
        const inputStr = line.substring('RUN_DFS '.length);
        const { graph, startNode } = parseGraphInput(inputStr);

        // Execute the DFS strategy using the Context
        // The Strategy interface's execute method is `execute(data: unknown): void;`
        // The harness passes `data` as an object `{ graph, startNode }`
        contextInstance.executeStrategy({ graph, startNode });

        // After execution, assume ConcreteStrategy has a method to retrieve the full DFS traversal result as a string
        const dfsResult = (concreteStrategyInstance as any).getDFSResultString();
        console.log(`DFS from ${startNode}: ${dfsResult}`);

      } else if (line === 'CURRENT') {
        if (!concreteStrategyInstance) {
          console.log('Error: Strategy not initialized. Use INIT first.');
          continue;
        }
        // Assume ConcreteStrategy has a 'current' method for iterator functionality
        const currentNode = (concreteStrategyInstance as any).current();
        console.log(currentNode !== undefined ? currentNode : 'undefined');
      } else if (line === 'NEXT') {
        if (!concreteStrategyInstance) {
          console.log('Error: Strategy not initialized. Use INIT first.');
          continue;
        }
        // Assume ConcreteStrategy has a 'next' method for iterator functionality
        // It should advance the iterator and return the element it advanced to, or undefined if exhausted.
        const nextNode = (concreteStrategyInstance as any).next();
        console.log(nextNode !== undefined ? nextNode : 'undefined');
      } else if (line === 'HAS_NEXT') {
        if (!concreteStrategyInstance) {
          console.log('Error: Strategy not initialized. Use INIT first.');
          continue;
        }
        // Assume ConcreteStrategy has a 'hasNext' method for iterator functionality
        const hasNext = (concreteStrategyInstance as any).hasNext();
        console.log(hasNext ? 'true' : 'false');
      } else {
        console.log(`Unknown command: ${line}`);
      }
    } catch (e: any) {
      console.log(`Error processing command "${line}": ${e.message}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "INIT\nRUN_DFS graph={A:[B,C], B:[D], C:[D], D:[]}, start=A", "description": "Basic DFS traversal", "expected_output": "DFS from A: A, B, D, C"}, {"input": "INIT\nRUN_DFS graph={A:[B,C], B:[D], C:[D], D:[]}, start=A\nCURRENT\nNEXT\nCURRENT\nNEXT\nCURRENT\nHAS_NEXT\nNEXT\nCURRENT\nHAS_NEXT\nNEXT\nCURRENT", "description": "Full traversal iteration and hasNext checks", "expected_output": "DFS from A: A, B, D, C\nA\nB\nB\nD\nD\ntrue\nC\nC\nfalse\nundefined\nundefined"}, {"input": "INIT\nRUN_DFS graph={A:[B], B:[C], C:[A]}, start=A", "description": "DFS with cycle detection", "expected_output": "DFS from A: A, B, C (cycle detected)"}, {"input": "INIT\nRUN_DFS empty graph, start=A", "description": "DFS on single node graph (empty graph but start node specified)", "expected_output": "DFS from A: A only"}, {"input": "INIT\nRUN_DFS graph={A:[B], B:[C], C:[D], D:[E], E:[]}, start=A\nCURRENT\nNEXT\nNEXT\nNEXT\nNEXT\nNEXT\nHAS_NEXT\nCURRENT", "description": "Long linear graph traversal and iteration end", "expected_output": "DFS from A: A, B, C, D, E\nA\nB\nC\nD\nE\nfalse\nundefined"}, {"input": "INIT\nRUN_DFS graph={A:[], B:[C], C:[]}, start=B\nCURRENT\nHAS_NEXT\nNEXT\nCURRENT\nHAS_NEXT\nNEXT\nCURRENT", "description": "DFS from disconnected component and iteration", "expected_output": "DFS from B: B, C\nB\ntrue\nC\nC\nfalse\nundefined\nundefined"}]'::jsonb
WHERE id = 'dp_079';
-- dp_080: Menu Item Composite Builder
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // The user is expected to implement the Composite pattern
  // and provide a top-level manager class, e.g., 'MenuSystem',
  // which interacts with 'MenuItem' (leaf) and 'SubMenu' (composite) classes.
  // The provided 'Strategy' and 'Context' classes in the starter code are not
  // directly used by these specific test cases, but are available to the user.
  
  // Expecting a user-defined class named 'MenuSystem' to manage the menu structure.
  // It should have methods: addItem, addSubmenu, render.
  const menuSystem = new MenuSystem(); 

  for (const line of lines) {
    if (line.startsWith('add_item')) {
      const match = line.match(/^add_item parent=(?<parent>[a-zA-Z0-9 ]+), child=(?<child>[a-zA-Z0-9 ]+)$/);
      if (match && match.groups) {
        const { parent, child } = match.groups;
        console.log(menuSystem.addItem(parent, child));
      } else {
        console.log(`Error: Invalid add_item command format: ${line}`);
      }
    } else if (line.startsWith('add_submenu')) {
      const match = line.match(/^add_submenu parent=(?<parent>[a-zA-Z0-9 ]+), name=(?<name>[a-zA-Z0-9 ]+)$/);
      if (match && match.groups) {
        const { parent, name } = match.groups;
        console.log(menuSystem.addSubmenu(parent, name));
      } else {
        console.log(`Error: Invalid add_submenu command format: ${line}`);
      }
    } else if (line === 'render menu') {
      console.log(menuSystem.render());
    } else {
      console.log(`Error: Unknown command: ${line}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "add_item parent=File, child=New\nadd_item parent=File, child=Save\nadd_submenu parent=Edit, name=Find\nadd_item parent=Find, child=Find Next\nadd_item parent=Find, child=Find Prev\nrender menu", "description": "Builds a menu structure with items and submenus, then renders the complete tree. Top-level menus should be ordered by their insertion, and children within a submenu should be sorted alphabetically.", "expected_output": "New added under File menu\nSave added under File menu\nFind submenu added under Edit\nFind Next added under Find menu\nFind Prev added under Find menu\nFile(New, Save), Edit(Find(Find Next, Find Prev))"}, {"input": "add_item parent=Options, child=Settings\nadd_submenu parent=Tools, name=Macros\nadd_item parent=Macros, child=Record Macro\nadd_item parent=Tools, child=Customize\nrender menu", "description": "Builds a more complex menu structure to test ordering and nesting.", "expected_output": "Settings added under Options menu\nMacros submenu added under Tools\nRecord Macro added under Macros menu\nCustomize added under Tools menu\nOptions(Settings), Tools(Customize, Macros(Record Macro))"}, {"input": "add_submenu parent=View, name=Zoom\nadd_item parent=Zoom, child=Zoom In\nadd_item parent=Zoom, child=Zoom Out\nadd_item parent=View, child=Status Bar\nrender menu", "description": "Tests adding to an existing parent and nested structure.", "expected_output": "Zoom submenu added under View\nZoom In added under Zoom menu\nZoom Out added under Zoom menu\nStatus Bar added under View menu\nView(Status Bar, Zoom(Zoom In, Zoom Out))"}, {"input": "render menu", "description": "Renders an empty menu system.", "expected_output": ""}, {"input": "add_item parent=Help, child=About\nrender menu", "description": "Adds a single item and renders.", "expected_output": "About added under Help menu\nHelp(About)"}, {"input": "add_submenu parent=File, name=New\nadd_item parent=New, child=Document\nadd_item parent=New, child=Spreadsheet\nrender menu", "description": "Tests a submenu named ''New'' containing items.", "expected_output": "New submenu added under File\nDocument added under New menu\nSpreadsheet added under New menu\nFile(New(Document, Spreadsheet))"}]'::jsonb
WHERE id = 'dp_080';
