-- dp_082: XML-to-JSON Adapter Converter
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // User's code (interface Strategy, class Context, class ConcreteStrategy) is available here.
  // The harness assumes the user has updated the Strategy interface to:
  //   interface Strategy { execute(xmlString: string): string; }
  // and implemented Context to hold and execute the strategy:
  //   class Context { private strategy: Strategy; constructor(strategy: Strategy); public convert(xmlString: string): string; }
  // and ConcreteStrategy to perform the XML-to-JSON conversion:
  //   class ConcreteStrategy implements Strategy { execute(xmlString: string): string; }

  let context: Context;
  try {
    // Instantiate the concrete strategy (user's implementation of ConcreteStrategy)
    const concreteStrategy = new ConcreteStrategy();

    // Instantiate the context with the strategy (user's implementation of Context)
    // The Context constructor is expected to accept a Strategy instance.
    context = new Context(concreteStrategy);
  } catch (e: any) {
    // Catch errors during instantiation (e.g., if user code throws in constructor)
    console.log(`Error during initialization: ${e.message}`);
    return;
  }

  // Process each line read from stdin as a command
  for (const line of lines) {
    // Each line is expected to be in the format "command=value"
    const parts = line.split('=');
    if (parts.length < 2) {
      console.log(`Error: Invalid command format "${line}". Expected "command=value".`);
      continue;
    }

    const command = parts[0];
    // Rejoin the rest of the parts in case the value itself contains an '=' character
    const value = parts.slice(1).join('='); 

    if (command === 'xml') {
      try {
        // Call the Context's method to perform the conversion.
        // The method is assumed to be 'convert', accepting an XML string and returning a JSON string.
        const jsonOutput = context.convert(value);
        console.log(jsonOutput);
      } catch (error: any) {
        // If the strategy or context throws an error (e.g., due to malformed XML),
        // catch it and print its message as specified in the test cases.
        console.log(`Error: ${error.message}`);
      }
    } else {
