-- dp_083: Contract Clause Template Engine
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // The user's Context class is expected to manage strategies and shared resources.
  // It should expose methods like `setStrategy`, `registerTemplate`, `getTemplate`, and `execute`.
  const userContext = new Context();

  for (const line of lines) {
    if (line.length === 0) continue; // Skip empty lines

    const parts = line.split(' ');
    const command = parts[0];
    const args = parts.slice(1).join(' ');

    try {
      switch (command) {
        case 'CREATE_TEMPLATE': {
          // Command: CREATE_TEMPLATE <name> <content>
          // Example: CREATE_TEMPLATE NDA This NDA is between {party1} and {party2}.
          // Parses the first word as the template name, and the rest as its content.
          const match = args.match(/^(\S+)\s+(.*)$/s); 
          if (!match) {
            console.log(`Error: CREATE_TEMPLATE requires a template name and content.`);
            continue;
          }
          const name = match[1];
          const content = match[2];
          userContext.registerTemplate(name, content);
          break;
        }
        case 'SET_STRATEGY': {
          // Command: SET_STRATEGY <StrategyClassName>
          // Example: SET_STRATEGY TemplateGenerationStrategy
          // The harness dynamically instantiates the user's strategy class.
          // User is expected to have defined classes like TemplateGenerationStrategy, ExportStrategy in global scope.
          // The user's strategy constructor is expected to accept the `Context` instance as an argument
          // to allow strategies to access shared state (e.g., templates managed by Context).
          const [strategyClassName] = args.split(' ');
          if (!strategyClassName) {
            console.log(`Error: SET_STRATEGY requires a strategy class name.`);
            continue;
          }

          const StrategyClass = (globalThis as any)[strategyClassName];
          if (typeof StrategyClass !== 'function') {
            console.log(`Error: Strategy class '${strategyClassName}' not found.`);
            continue;
          }
          const strategyInstance: Strategy = new StrategyClass(userContext);
          userContext.setStrategy(strategyInstance);
          break;
        }
        case 'EXECUTE': {
          // Command: EXECUTE <data_string>
          // The entire 'args' string is passed as data to the currently set strategy's execute method.
          userContext.execute(args);
          break;
        }
        default:
          console.log(`Error: Unknown command '${command}'`);
      }
    } catch (error: any) {
      console.log(`Error: ${error.message}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "CREATE_TEMPLATE NDA This Non-Disclosure Agreement is between {party1} and {party2}.\nSET_STRATEGY TemplateGenerationStrategy\nEXECUTE template=NDA, vars={party1: Acme, party2: Widget Co}", "description": "Generate NDA from template", "expected_output": "NDA generated with Acme and Widget Co"}, {"input": "CREATE_TEMPLATE employment_contract This Employment Contract for {employee} specifies a salary of ${salary}.\nSET_STRATEGY TemplateGenerationStrategy\nEXECUTE template=employment_contract, vars={employee: Alice, salary: 100000}", "description": "Generate employment contract", "expected_output": "Employment contract generated for Alice at $100,000"}, {"input": "CREATE_TEMPLATE NDA This Non-Disclosure Agreement is between {party1} and {party2}.\nSET_STRATEGY TemplateGenerationStrategy\nEXECUTE template=NDA, vars={party1: Acme}", "description": "Missing variable error", "expected_output": "Error: missing required variable party2"}, {"input": "SET_STRATEGY ExportStrategy\nEXECUTE format=pdf", "description": "Export contract as PDF", "expected_output": "Contract exported as PDF"}, {"input": "SET_STRATEGY NonExistentStrategy\nEXECUTE some_data", "description": "Attempt to set a non-existent strategy", "expected_output": "Error: Strategy class ''NonExistentStrategy'' not found."}, {"input": "EXECUTE some_data", "description": "Execute without setting strategy", "expected_output": "Error: No strategy set. Use SET_STRATEGY first."}, {"input": "CREATE_TEMPLATE Invoice No {invoiceId} for {customer}.\nSET_STRATEGY TemplateGenerationStrategy\nEXECUTE template=Invoice, vars={invoiceId: 123, customer: Global Corp}\nSET_STRATEGY ExportStrategy\nEXECUTE format=excel", "description": "Generate invoice then export", "expected_output": "Invoice generated for Global Corp (ID: 123)\nContract exported as Excel"}]'::jsonb
WHERE id = 'dp_083';
-- dp_084: Purchase Order Chain Approver
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

const lines: string[] = [];
rl.on('line', (line) => {
    lines.push(line.trim());
});

rl.on('close', () => {
    // Define a type for the purchase order request for clarity within the harness.
    // User's `Strategy.execute` method will receive this type (as `unknown`) and should cast it.
    interface PurchaseOrderRequest {
      orderId: string;
      amount: number;
    }

    // --- Expected User Implementation Assumptions --- 
    // 1. The `Strategy` interface has been augmented by the user to include:
    //    - `execute(data: PurchaseOrderRequest): string;` (returns log string)
    //    - `setNext(nextApprover: Strategy | null): void;` (for building the chain)
    //    - `getName(): string;` (for logging escalation messages)
    // 2. The `ConcreteStrategy` class has been implemented by the user such that:
    //    - It implements the (augmented) `Strategy` interface.
    //    - Its constructor accepts `(name: string, threshold: number)`.
    //    - Its `execute` method processes the request based on the threshold or passes it to the next approver.
    // 3. The `Context` class has been implemented by the user such that:
    //    - Its constructor accepts `(initialStrategy: Strategy)` (the head of the chain).
    //    - It has a public method (e.g., `processPurchaseOrder`) that takes a `PurchaseOrderRequest`
    //      and initiates the `execute` method of the initial strategy.

    // --- Build the Chain of Responsibility using user's ConcreteStrategy --- 
    // Thresholds are set to match the expected outputs from the test cases:
    // Supervisor: approves orders up to $1,000
    // Manager: approves orders up to $10,000
    // Director: approves orders up to $100,000
    // CFO: approves all orders above $100,000 (effectively up to max number)
    const supervisor = new ConcreteStrategy("Supervisor", 1000);
    const manager = new ConcreteStrategy("Manager", 10000);
    const director = new ConcreteStrategy("Director", 100000);
    const cfo = new ConcreteStrategy("CFO", Infinity);

    // Link the approvers to form the chain
    supervisor.setNext(manager);
    manager.setNext(director);
    director.setNext(cfo);
    // The CFO is the last in the chain, so its `nextApprover` remains null.

    // Instantiate the Context with the head of the chain
    const context = new Context(supervisor);

    // --- Process commands from stdin ---
    for (const line of lines) {
        if (line.startsWith("PROCESS_ORDER")) {
            const parts = line.split(' ');
            if (parts.length === 3) {
                const orderId = parts[1];
                const amount = parseInt(parts[2], 10);

                if (isNaN(amount)) {
                    console.log(`Error: Invalid amount for order ${orderId}`);
                    continue;
                }

                const poRequest: PurchaseOrderRequest = { orderId, amount };
                
                // Call the context's method to initiate the approval process through the chain.
                const result = context.processPurchaseOrder(poRequest);
                console.log(result);
            } else {
                console.log(`Error: Invalid PROCESS_ORDER command format: ${line}`);
            }
        } else if (line.trim() === '') {
            // Ignore empty lines
            continue;
        }
        else {
            console.log(`Error: Unknown command: ${line}`);
        }
    }
});$harness$,
  test_cases   = '[{"input": "PROCESS_ORDER PO001 500", "description": "Supervisor approves small PO", "expected_output": "Supervisor approved PO001 for $500"}, {"input": "PROCESS_ORDER PO002 5000", "description": "Escalated to manager", "expected_output": "Supervisor escalated PO002 to Manager\nManager approved PO002 for $5000"}, {"input": "PROCESS_ORDER PO003 50000", "description": "Director approves large PO", "expected_output": "Supervisor escalated PO003 to Manager\nManager escalated PO003 to Director\nDirector approved PO003 for $50000"}, {"input": "PROCESS_ORDER PO004 500000", "description": "CFO approves very large PO", "expected_output": "Supervisor escalated PO004 to Manager\nManager escalated PO004 to Director\nDirector escalated PO004 to CFO\nCFO approved PO004 for $500000"}]'::jsonb
WHERE id = 'dp_084';
-- dp_085: Chat Room Mediator Service
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

// The readline setup for reading stdin
const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

const lines: string[] = [];

// Collect all input lines
rl.on('line', (line) => lines.push(line.trim()));

// Process all lines once stdin is closed
rl.on('close', () => {
  // --- Start of logic for processing commands ---

  // Instantiate the main Mediator service
  // We assume the user has implemented a class named ChatRoomMediator
  const mediator = new ChatRoomMediator();

  // Maintain a map of User instances by their name
  // We assume the user has implemented a class named User
  const users: Map<string, User> = new Map();

  /**
   * Helper function to ensure a User instance exists and is registered with the mediator.
   * This centralizes user creation and mediator registration logic.
   * Assumes User constructor takes a 'name' (e.g., `new User(name: string)`).
   * Assumes ChatRoomMediator has a `registerUser(user: User)` method.
   */
  function ensureUser(username: string): User {
    if (!users.has(username)) {
      const newUser = new User(username); // User class likely constructed with just a name
      mediator.registerUser(newUser);    // Mediator manages the registration of colleagues
      users.set(username, newUser);
    }
    return users.get(username)!; // eslint-disable-line @typescript-eslint/no-non-null-assertion
  }

  // Process each command line from stdin
  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    const parts = line.split(' ');
    const commandType = parts[0];
    const args: { [key: string]: string } = {};

    // Parse arguments from "key=value,key2=value2" format
    // Example: "join room=general, user=alice"
    for (let i = 1; i < parts.length; i++) {
      const argPairs = parts[i].split(',');
      for (const argPair of argPairs) {
        const [key, value] = argPair.split('=');
        if (key && value) {
          args[key.trim()] = value.trim();
        }
      }
    }

    let output = '';

    // Execute commands based on parsed input
    switch (commandType) {
      case 'join': {
        const user = ensureUser(args['user']);
        const roomName = args['room'];
        // Assumes mediator has joinRoom(user, roomName) method returning a string
        output = mediator.joinRoom(user, roomName);
        break;
      }
      case 'send': {
        const sender = ensureUser(args['from']);
        const roomName = args['room'];
        const message = args['message'];
        // Assumes mediator has broadcast(sender, roomName, message) method returning a string
        output = mediator.broadcast(sender, roomName, message);
        break;
      }
      case 'leave': {
        const user = ensureUser(args['user']);
        const roomName = args['room'];
        // Assumes mediator has leaveRoom(user, roomName) method returning a string
        output = mediator.leaveRoom(user, roomName);
        break;
      }
      case 'private_message': {
        const sender = ensureUser(args['from']);
        const receiverName = args['to'];
        const message = args['message'];
        // Assumes mediator has directMessage(sender, receiverName, message) method returning a string
        output = mediator.directMessage(sender, receiverName, message);
        break;
      }
      default:
        output = `Error: Unknown command "${commandType}"`;
    }

    // Print the result of the command to stdout
    console.log(output);
  }
  // --- End of logic for processing commands ---
});$harness$,
  test_cases   = '[{"input": "join room=general, user=alice", "description": "User Alice joins a chat room ''general''", "expected_output": "alice joined general, all members notified"}, {"input": "join room=general, user=alice\njoin room=general, user=bob\nsend room=general, from=alice, message=Hello everyone!", "description": "Two users join a room, one sends a broadcast message to all members", "expected_output": "alice joined general, all members notified\nbob joined general, all members notified\nMessage relayed by mediator to all in general"}, {"input": "join room=general, user=alice\njoin room=general, user=bob\nleave room=general, user=alice\nsend room=general, from=bob, message=Bye Alice!", "description": "User leaves a room, then another user sends a message to the remaining members", "expected_output": "alice joined general, all members notified\nbob joined general, all members notified\nalice left general, remaining members notified\nMessage relayed by mediator to all in general"}, {"input": "join room=general, user=alice\njoin room=general, user=bob\nprivate_message from=alice, to=bob, message=Secret message", "description": "Users send a private message to each other", "expected_output": "alice joined general, all members notified\nbob joined general, all members notified\nPrivate message from alice to bob via mediator"}, {"input": "join room=general, user=alice\njoin room=dev, user=bob\nprivate_message from=alice, to=bob, message=Hey Bob, from general", "description": "Private message between users who are in different rooms", "expected_output": "alice joined general, all members notified\nbob joined dev, all members notified\nPrivate message from alice to bob via mediator"}, {"input": "join room=general, user=alice\nprivate_message from=alice, to=charlie, message=Hello non-existent", "description": "Private message to a user who has not registered with the mediator", "expected_output": "alice joined general, all members notified\nError: User charlie not found for private message"}, {"input": "join room=general, user=alice\nleave room=general, user=alice\nsend room=general, from=alice, message=Ghost message", "description": "User attempts to send a broadcast message after leaving the room", "expected_output": "alice joined general, all members notified\nalice left general, remaining members notified\nError: User alice is not in room general to send message"}, {"input": "join room=general, user=alice\njoin room=general, user=bob\njoin room=dev, user=alice\nsend room=general, from=bob, message=General chat\nsend room=dev, from=alice, message=Dev chat", "description": "User is in multiple rooms and sends messages to different rooms", "expected_output": "alice joined general, all members notified\nbob joined general, all members notified\nalice joined dev, all members notified\nMessage relayed by mediator to all in general\nMessage relayed by mediator to all in dev"}, {"input": "join room=general, user=alice\nsend room=private_room, from=alice, message=Wrong room", "description": "User tries to send a message to a room they are not in", "expected_output": "alice joined general, all members notified\nError: User alice is not in room private_room to send message"}]'::jsonb
WHERE id = 'dp_085';
-- dp_086: Form State Memento Restorer
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // The user's Context class is expected to be the Originator, Caretaker, and Strategy Context.
  // It should implement:
  // 1. Memento pattern roles: methods to manage its internal state (e.g., `updateFormState`, `getFormState`),
  //    methods to create mementos (`saveCurrentState`), and methods to restore from mementos (`restoreLastState`).
  //    The Memento objects themselves (FormMemento interface, ConcreteFormMemento class) are also expected to be user-defined.
  // 2. Strategy pattern Context role: a `setStrategy(strategy: Strategy)` method to set the current strategy,
  //    and a `runStrategy(params: Record<string, string>)` method that executes the current strategy.
  //    The `Strategy` interface and its concrete implementations (e.g., `FillFormStrategy`, `SaveStateStrategy`)
  //    are also expected to be user-defined, implementing the `execute` method as `execute(data: { context: Context, params: Record<string, string> }): void`
  //    (casting `unknown` to the expected object shape).

  const formSystemContext = new Context(); // Instantiate the user's Context class

  // Helper to safely get user-defined strategy classes from the global scope.
  // This relies on classes being available after user code concatenation.
  const getStrategyInstance = (name: string): Strategy => {
    try {
      const StrategyClass = eval(name); // Dynamically get the constructor function
      if (typeof StrategyClass === 'function' && typeof StrategyClass.prototype.execute === 'function') {
        return new StrategyClass();
      }
      throw new Error(`Strategy class '${name}' found but does not appear to be a valid Strategy.`);
    } catch (e: any) {
      console.error(`Error loading strategy '${name}': ${e.message}`);
      // Provide a fallback 'do-nothing' strategy for robustness in testing
      return { execute: () => console.log(`Error: Strategy '${name}' failed to load.`) };
    }
  };

  // Map command names to instances of user-defined concrete Strategy classes.
  const strategyMap: Map<string, Strategy> = new Map();
  strategyMap.set('fill_form', getStrategyInstance('FillFormStrategy'));
  strategyMap.set('modify_form', getStrategyInstance('ModifyFormStrategy'));
  strategyMap.set('save_state', getStrategyInstance('SaveStateStrategy'));
  strategyMap.set('restore_state', getStrategyInstance('RestoreStateStrategy'));

  for (const line of lines) {
    const parts = line.split(' ');
    const command = parts[0];
    let params: Record<string, string> = {};

    if (parts.length > 1) {
      const paramsString = parts.slice(1).join(' ');
      if (paramsString.startsWith('fields={') && paramsString.endsWith('}')) {
        const fieldsContent = paramsString.substring('fields={'.length, paramsString.length - 1);
        fieldsContent.split(', ').forEach(pair => {
          const [key, value] = pair.split(': ');
          if (key && value) { params[key.trim()] = value.trim(); }
        });
      } else { // Assume key=value format for simple modifications, space-separated
        paramsString.split(' ').forEach(param => {
          const [key, value] = param.split('=');
          if (key && value) { params[key.trim()] = value.trim(); }
        });
      }
    }

    const strategy = strategyMap.get(command);
    if (strategy) {
      formSystemContext.setStrategy(strategy);
      formSystemContext.runStrategy(params);
    } else {
      console.log(`Error: Unknown command or strategy not registered for: ${command}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "fill_form fields={name: Alice, email: alice@example.com}", "description": "Fill form fields", "expected_output": "Form filled: name=Alice, email=alice@example.com"}, {"input": "fill_form fields={name: Bob, phone: 123-4567}\nsave_state", "description": "Save form state", "expected_output": "Form filled: name=Bob, phone=123-4567\nForm state saved as memento"}, {"input": "fill_form fields={name: Carol}\nmodify_form name=Carla", "description": "Modify form", "expected_output": "Form filled: name=Carol\nForm name updated to Carla"}, {"input": "fill_form fields={name: Alice, email: alice@example.com}\nsave_state\nmodify_form email=new@example.com\nrestore_state", "description": "Restore saved form state", "expected_output": "Form filled: name=Alice, email=alice@example.com\nForm state saved as memento\nForm email updated to new@example.com\nForm restored: name=Alice, email=alice@example.com"}, {"input": "fill_form fields={product: A, price: 10}\nsave_state\nmodify_form price=12\nsave_state\nmodify_form quantity=3\nrestore_state\nrestore_state", "description": "Multiple saves and restores (LIFO)", "expected_output": "Form filled: product=A, price=10\nForm state saved as memento\nForm price updated to 12\nForm state saved as memento\nForm quantity updated to 3\nForm restored: product=A, price=12\nForm restored: product=A, price=10"}, {"input": "restore_state", "description": "Restore with no saved state", "expected_output": "No state to restore."}, {"input": "fill_form fields={user: John, id: 101}\nsave_state\nmodify_form id=102 status=active\nrestore_state\nsave_state\nrestore_state", "description": "Complex save and restore scenario", "expected_output": "Form filled: user=John, id=101\nForm state saved as memento\nForm id updated to 102\nForm status updated to active\nForm restored: user=John, id=101\nForm state saved as memento\nForm restored: user=John, id=101"}]'::jsonb
WHERE id = 'dp_086';
-- dp_087: Elevator State Controller
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // Assume Context and ConcreteStrategy are defined by the user.
  // We expect the user's Context class to manage the elevator's state and
  // provide methods for the harness to interact with it.
  // Expected Context methods:
  //   constructor()
  //   setStrategy(strategy: Strategy): void
  //   runEvent(eventData: unknown): void // This method should delegate to the current strategy
  //   getCurrentState(): string        // Used by strategies to read current state
  //   setCurrentState(newState: string): void // Used by strategies to update state

  // We expect the user's ConcreteStrategy to implement the Strategy interface
  // and its 'execute' method to handle elevator state transitions and print messages.
  // The 'data' passed to execute will be an object like: { context: Context, event: { type: string, [key: string]: any } }
  
  // Create an instance of the user's ConcreteStrategy
  const elevatorStrategy: Strategy = new ConcreteStrategy();

  // Create an instance of the user's Context (which will manage the elevator state)
  const elevatorContext: Context = new Context();
  
  // Set the strategy on the context. We assume Context has a public 'setStrategy' method.
  (elevatorContext as any).setStrategy(elevatorStrategy);

  for (const line of lines) {
    if (!line) continue;

    const parts = line.split(' ');
    const command = parts[0];
    const args = parts.slice(1).join(' ');

    switch (command) {
      case 'SET_STATE':
        // Set the current state of the elevator context. We assume a public 'setCurrentState' method.
        (elevatorContext as any).setCurrentState(args); 
        break;
      case 'EVENT':
        // Trigger an event. The Context will delegate this to its currently set strategy.
        // The strategy will then perform logic based on the event and current state,
        // potentially updating the context's state and printing output.
        (elevatorContext as any).runEvent({ type: args }); 
        break;
      default:
        console.log(`Unknown command: ${command}`);
    }
  }
});$harness$,
