WHERE id = 'dp_087';
-- dp_088: AST Node Visitor Evaluator
UPDATE challenges SET
  test_harness = $harness$abstract class BaseASTNode {
    abstract type: string;
}

class BinaryOp extends BaseASTNode {
    type: string = "BinaryOp";
    constructor(public op: string, public left: BaseASTNode, public right: BaseASTNode) { super(); }
}

class Identifier extends BaseASTNode {
    type: string = "Identifier";
    constructor(public name: string) { super(); }
}

class IfStmt extends BaseASTNode {
    type: string = "IfStmt";
    constructor() { super(); }
}

class Literal extends BaseASTNode {
    type: string = "Literal";
    constructor(public value: number | string) { super(); }
}

// Helper functions for parsing commands
function parseLiteralValue(str: string): number | string {
    if (!isNaN(Number(str)) && !isNaN(parseFloat(str))) {
        return Number(str);
    }
    if ((str.startsWith("'') && str.endsWith("'")) || (str.startsWith('"') && str.endsWith('"'))) {
        return str.substring(1, str.length - 1);
    }
    return str;
}

function parseArgument(arg: string, namedNodes: Map<string, BaseASTNode>): BaseASTNode {
    arg = arg.trim();
    if (namedNodes.has(arg)) {
        return namedNodes.get(arg)!;
    }
    // Check if it's a literal number or string
    if (!isNaN(Number(arg)) && !isNaN(parseFloat(arg))) {
        return new Literal(Number(arg));
    }
    if ( (arg.startsWith('"') && arg.endsWith('"')) || (arg.startsWith("'') && arg.endsWith("'")) ) {
        return new Literal(arg.substring(1, arg.length - 1));
    }
    // Check if it's another node definition (recursive call)
    if (arg.includes('(') && arg.includes(')')) {
        return parseNodeDefinitionRecursive(arg, namedNodes);
    }
    // Default to Identifier if it's a simple string that hasn't been resolved as a named node or literal.
    return new Identifier(arg);
}

function parseNodeDefinitionRecursive(def: string, namedNodes: Map<string, BaseASTNode>): BaseASTNode {
    const match = def.match(/^(\w+)\((.*)\)$/);
    if (!match) {
        throw new Error(`Invalid node definition format: ${def}`);
    }
    const nodeType = match[1];
    const argsString = match[2];

    switch (nodeType) {
        case "BinaryOp": {
            const args: string[] = [];
            let balance = 0;
            let currentArg = '';
            for (let i = 0; i < argsString.length; i++) {
                const char = argsString[i];
                if (char === '(') balance++;
                else if (char === ')') balance--;

                if (char === ',' && balance === 0) {
                    args.push(currentArg.trim());
                    currentArg = '';
                } else {
                    currentArg += char;
                }
            }
            args.push(currentArg.trim());

            if (args.length !== 3) throw new Error(`BinaryOp expects 3 arguments, got ${args.length}: ${def}`);
            const op = args[0];
            const left = parseArgument(args[1], namedNodes);
            const right = parseArgument(args[2], namedNodes);
            return new BinaryOp(op, left, right);
        }
        case "Identifier": {
            if (argsString === '') throw new Error(`Identifier expects a name: ${def}`);
            return new Identifier(argsString);
        }
        case "IfStmt": {
            if (argsString !== '') throw new Error(`IfStmt expects no arguments: ${def}`);
            return new IfStmt();
        }
        case "Literal": {
            const value = parseLiteralValue(argsString);
            return new Literal(value);
        }
        default:
            throw new Error(`Unknown AST node type: ${nodeType}`);
    }
}

// Readline setup
import * as readline from 'readline';
const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line: string) => lines.push(line.trim()));

rl.on('close', () => {
    // These maps hold state across commands.
    const namedNodes = new Map<string, BaseASTNode>();
    const symbolTable = new Map<string, any>();
    const cachedStrategies = new Map<string, Strategy>(); // Strategies will be created once and reused.

    let currentContext: Context;
    try {
        // User's Context class is expected to be available globally.
        // Its constructor should not require arguments initially.
        currentContext = new Context();
    } catch (e: any) {
        console.log(`Error: Failed to instantiate Context. Make sure your Context class is correctly defined. Details: ${e.message || e}`);
        return;
    }

    // Helper to dynamically get user's strategy constructors
    const getStrategyConstructor = (name: string): new (symbolTable: Map<string, any>) => Strategy => {
        const className = name.split('_').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join('') + 'Strategy';
        // @ts-ignore - globalThis may not know about user-defined classes without explicit declaration or bundling
        const constructor = globalThis[className];
        if (typeof constructor !== 'function') {
            throw new Error(`Strategy '${name}' (class '${className}') not found. Ensure the class is defined and globally accessible (e.g., via globalThis.${className} = ${className};).`);
        }
        // This assumes the user's Strategy constructor accepts a symbolTable Map.
        // `interface Strategy { execute(data: unknown): void; }` is provided to the user.
        // The user's ConcreteStrategy implementation must implement `execute(data: BaseASTNode): void;`
        // and its constructor should accept `(symbolTable: Map<string, any>)` if it needs symbol table access.
        return constructor as new (symbolTable: Map<string, any>) => Strategy;
    };

    try {
        for (const line of lines) {
            if (line.startsWith("DEFINE_NODE ")) {
                const parts = line.substring("DEFINE_NODE ".length).split(' = ', 2);
                if (parts.length !== 2) throw new Error(`Invalid DEFINE_NODE command: ${line}`);
                const varName = parts[0].trim();
                const nodeDef = parts[1].trim();
                const node = parseNodeDefinitionRecursive(nodeDef, namedNodes);
                namedNodes.set(varName, node);
            } else if (line.startsWith("SET_SYMBOL ")) {
                const parts = line.substring("SET_SYMBOL ".length).split(' = ', 2);
                if (parts.length !== 2) throw new Error(`Invalid SET_SYMBOL command: ${line}`);
                const name = parts[0].trim();
                const valueStr = parts[1].trim();
                let value: any;
                if (!isNaN(Number(valueStr)) && !isNaN(parseFloat(valueStr))) {
                    value = Number(valueStr);
                } else if ((valueStr.startsWith("'') && valueStr.endsWith("'")) || (valueStr.startsWith('"') && valueStr.endsWith('"'))) {
                    value = valueStr.substring(1, valueStr.length - 1);
                } else {
                    value = valueStr;
                }
                symbolTable.set(name, value);
            } else if (line.startsWith("RUN_VISITOR ")) {
                const parts = line.substring("RUN_VISITOR ".length).split(' ', 2);
                if (parts.length !== 2) throw new Error(`Invalid RUN_VISITOR command: ${line}`);
                const nodeVarName = parts[0].trim();
                const visitorName = parts[1].trim();

                const nodeToVisit = namedNodes.get(nodeVarName);
                if (!nodeToVisit) throw new Error(`Node '${nodeVarName}' not found.`);

                let strategyInstance = cachedStrategies.get(visitorName);
                if (!strategyInstance) {
                    const StrategyConstructor = getStrategyConstructor(visitorName);
                    // Instantiate user's Strategy, passing the shared symbol table.
                    strategyInstance = new StrategyConstructor(symbolTable);
                    cachedStrategies.set(visitorName, strategyInstance);
                }

                // Set the strategy on the user's Context object
                currentContext.setStrategy(strategyInstance);
                // Call `run` with `nodeToVisit`. The user's strategy is expected to `console.log` its result.
                currentContext.run(nodeToVisit);
            } else if (line.trim() === '') {
                // Ignore empty lines
            } else {
                console.log(`Error: Unknown command: ${line}`);
            }
        }
    } catch (e: any) {
        console.log(`Error: ${e.message || e}`); // Log all caught errors to stdout for test comparison
    }
});$harness$,
