const rl = readline.createInterface({
    input: process.stdin,
});

const lines: string[] = [];

rl.on('line', (line) => {
    lines.push(line.trim());
});

rl.on('close', () => {
    // Harness logic starts here

    // IMPORTANT ASSUMPTIONS FOR USER CODE:
    // 1. The 'Strategy' interface's 'execute' method should return 'string', not 'void'.
    //    interface Strategy {
    //      execute(data: unknown): string;
    //      getDriverName(): string; // Assumed helper for identifying strategies
    //    }
    // 2. The 'Context' class should hold a Strategy, allow setting a new strategy,
    //    and delegate an operation to the current strategy's 'execute' method.
    //    It should also provide a way to get the current driver's name (e.g., getCurrentDriverName).
    // 3. The 'ConcreteStrategy' class should implement the 'Strategy' interface
    //    and handle different driver types (e.g., AWS, GCP, Azure) via its constructor
    //    or by having multiple concrete strategy classes. The harness assumes
    //    a single `ConcreteStrategy` that takes a `driverType` string in its constructor.

    // Instantiate ConcreteStrategy implementations for different drivers
    const awsStrategy = new ConcreteStrategy("AWS");
    const gcpStrategy = new ConcreteStrategy("GCP");
    const azureStrategy = new ConcreteStrategy("Azure");

    const strategyMap: Record<string, Strategy> = {
        "AWS": awsStrategy,
        "GCP": gcpStrategy,
        "Azure": azureStrategy,
    };

    // Initialize Context with a default strategy (e.g., AWS)
    let currentContext = new Context(strategyMap["AWS"]);

    const outputLines: string[] = [];

    // Helper to parse key-value commands from stdin lines
    function parseCommand(commandString: string): { type: 'operation' | 'switch', data: Record<string, string> } {
        const data: Record<string, string> = {};

        if (commandString.startsWith('switch_driver')) {
            const switchParts = commandString.split(' '); // e.g., ["switch_driver", "from=AWS", "to=Azure"]
            for (let i = 1; i < switchParts.length; i++) {
                const [key, value] = switchParts[i].split('=');
                data[key] = value;
            }
            return { type: 'switch', data: data };
        } else {
            const parts = commandString.split(', ');
            for (const part of parts) {
                const [key, value] = part.split('=');
                data[key] = value;
            }
            return { type: 'operation', data: data };
        }
    }

    for (const line of lines) {
        if (!line) continue; // Skip empty lines

        const parsed = parseCommand(line);

        if (parsed.type === 'switch') {
            const newDriverName = parsed.data['to'];
            if (newDriverName && strategyMap[newDriverName]) {
                currentContext.setStrategy(strategyMap[newDriverName]);
                outputLines.push(`Cloud driver switched to ${newDriverName}`);
            } else {
                outputLines.push(`Error: Unknown driver for switch command: ${newDriverName}`);
            }
        } else if (parsed.type === 'operation') {
            const specifiedDriver = parsed.data['driver'];
            const operation = parsed.data['operation'];

            // If an operation command specifies a driver, ensure the context uses it.
            // This implicitly handles setting the correct driver for a specific operation,
            // even if no explicit 'switch_driver' command was given for that driver.
            if (specifiedDriver && currentContext.getCurrentDriverName() !== specifiedDriver) {
                if (strategyMap[specifiedDriver]) {
                    currentContext.setStrategy(strategyMap[specifiedDriver]);
                    // No output for implicit driver switch, only for explicit 'switch_driver' commands.
                } else {
                    outputLines.push(`Error: Unknown driver specified in operation command: ${specifiedDriver}`);
                    continue; // Skip operation if driver is invalid
                }
            }

            // Prepare data object to pass to strategy.execute(data: unknown)
            // This object will contain all parameters like 'operation', 'file', etc.
            const operationData: Record<string, string> = {};
            for (const key in parsed.data) {
                // 'driver' is handled by the harness for context switching,
                // 'type' is internal to the parser.
                // Other keys are actual data for the strategy.
                if (key !== 'driver' && key !== 'type') {
                    operationData[key] = parsed.data[key];
                }
            }

            try {
                // The Context performs the operation, delegating to the current strategy.
                const result = currentContext.performOperation(operationData);
                outputLines.push(result);
            } catch (error: any) {
                outputLines.push(`Error performing operation: ${error.message || error}`);
            }
        }
    }

    // Print all collected outputs to stdout, separated by newlines
    console.log(outputLines.join('\n'));
});$harness$,
  test_cases   = '[{"input": "driver=AWS, operation=upload, file=data.csv", "description": "Upload via AWS driver", "expected_output": "data.csv uploaded via AWS driver"}, {"input": "switch_driver from=AWS to=GCP\ndriver=GCP, operation=upload, file=data.csv", "description": "Upload via GCP driver", "expected_output": "Cloud driver switched to GCP\ndata.csv uploaded via GCP driver"}, {"input": "switch_driver from=AWS to=Azure", "description": "Switch cloud driver", "expected_output": "Cloud driver switched to Azure"}, {"input": "switch_driver from=AWS to=Azure\ndriver=Azure, operation=list_files", "description": "List files via Azure driver", "expected_output": "Cloud driver switched to Azure\nFiles listed via Azure driver"}, {"input": "driver=AWS, operation=upload, file=report.pdf\nswitch_driver from=AWS to=GCP\ndriver=GCP, operation=list_files", "description": "Perform operation, switch driver, perform another operation", "expected_output": "report.pdf uploaded via AWS driver\nCloud driver switched to GCP\nFiles listed via GCP driver"}]'::jsonb
