  // This method should return the operation's result string or throw an error.

  // Instantiate the user's `Context` class once for statefulness across commands.
  // `globalThis` is used to access user-defined classes assuming they are globally available after concatenation.
  const fileSystemContext = new (globalThis as any).Context();

