      } else if (part.startsWith('file_op=')) {
        fileOp = part.substring(8); // Extract value after 'file_op='
      } else if (part.startsWith('path=')) {
        path = part.substring(5); // Extract value after 'path='. Path can contain '=', so take rest of string.
      }
    }

    // Validate that all required parameters were found in the input line.
    // 'os' and 'fileOp' must be non-empty strings. 'path' must be defined (can be an empty string).
    if (!os || !fileOp || path === undefined) {
      allOutputs.push(`Error: Malformed input line: '${line}'. Ensure 'os', 'file_op', and 'path' are present.`);
      continue;
    }

    try {
      // Call the user's main method on their Context object.
      // This method is expected to handle the OS selection (via Abstract Factory)
      // and execute the specific file operation (via Strategy).
      const result = fileSystemContext.performOperation(os, fileOp, path);
      allOutputs.push(result);
    } catch (error: any) {
      // Capture and report errors thrown by the user's implementation.
      allOutputs.push(`Error: ${error.message}`);
    }
  }

  // Print all collected outputs to stdout, one line per output.
  for (const output of allOutputs) {
    console.log(output);
  }
