-- dp_092: Test Fixture Prototype Duplicator
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {
  // Assumed user-defined interfaces and classes:
  // interface IPrototype {
  //   clone(): IPrototype;
  //   [key: string]: any; // Allows arbitrary properties on the instance
  // }
  //
  // class UserConcretePrototype implements IPrototype {
  //   constructor(initialData: { [key: string]: any } = {}) { /* ... */ }
  //   clone(): IPrototype { /* ... */ }
  //   [key: string]: any;
  // }
  //
  // class PrototypeManager {
  //   constructor() { /* ... */ }
  //   registerPrototype(name: string, prototype: IPrototype): void { /* ... */ }
  //   getPrototype(name: string): IPrototype | undefined { /* ... */ }
  // }

  // Helper function to parse fixture strings like "{key: value, another: 'string'}"
  // This function handles unquoted keys/values, single/double quoted strings, numbers, and booleans.
  function parseFixtureString(fixtureStr: string): { [key: string]: any } {
    const result: { [key: string]: any } = {};
    if (!fixtureStr.startsWith('{') || !fixtureStr.endsWith('}')) {
      throw new Error("Invalid fixture format. Must be like '{key: value}'.");
    }
    const inner = fixtureStr.substring(1, fixtureStr.length - 1).trim(); // Remove braces and trim
    if (!inner) { // Handle empty fixture, e.g., {}
      return result;
    }

    // Split by comma, being careful not to split commas inside quoted strings.
    // This regex splits on commas that are not preceded by an odd number of quotes.
    inner.split(/,(?=(?:(?:[^"']*["'][^"']*["'])*[^"']*)*$)/g).forEach(pair => {
      const parts = pair.split(':').map(p => p.trim());
      if (parts.length === 2) {
        const key = parts[0];
        let valueStr = parts[1];
        let value: any = valueStr;

        // Handle numbers
        if (!isNaN(Number(valueStr)) && !isNaN(parseFloat(valueStr))) {
          value = Number(valueStr);
        }
        // Handle booleans
        else if (valueStr.toLowerCase() === 'true') {
          value = true;
        } else if (valueStr.toLowerCase() === 'false') {
          value = false;
        }
        // Handle strings (remove quotes)
        else if ((valueStr.startsWith("'") && valueStr.endsWith("'")) || (valueStr.startsWith('"') && valueStr.endsWith('"'))) {
          value = valueStr.substring(1, valueStr.length - 1);
        }
        // If it's still a string and potentially unquoted (like 'admin'), keep it as string
        
        result[key] = value;
      } else {
         throw new Error(`Invalid key-value pair in fixture: ${pair}`);
      }
    });
    return result;
  }

  // Instantiate the user's PrototypeManager class
  const manager: any = new (globalThis as any).PrototypeManager(); // Using 'any' for direct access if type not yet defined
  let lastClonedObject: any | undefined = undefined; // Stores the last cloned object for 'modify' commands

  for (const line of lines) {
    if (!line) continue;

    const parts = line.split(' ');
    const command = parts[0];

    try {
      if (command === 'register_prototype') {
        const nameMatch = line.match(/name=(\w+)/);
        const fixtureMatch = line.match(/fixture=({.*?})/);

        if (!nameMatch || !fixtureMatch) {
          console.log('Error: Invalid register_prototype command format. Expected: name=<name>, fixture={<properties>}.');
          continue;
        }

        const name = nameMatch[1];
        const fixtureProperties = parseFixtureString(fixtureMatch[1]);

        // UserConcretePrototype is expected to be defined by the user and implement IPrototype.
        // It should have a constructor that accepts an object of initial properties.
        const prototypeToRegister: any = new (globalThis as any).UserConcretePrototype(fixtureProperties);
        manager.registerPrototype(name, prototypeToRegister);
        console.log(`Prototype ${name} registered`);
        lastClonedObject = undefined; // Registration does not produce a "last cloned" object
      } else if (line.includes('clone')) {
        const prototypeNameMatch = line.match(/prototype=(\w+)/);
        if (!prototypeNameMatch) {
          console.log('Error: Invalid clone command format. Expected: prototype=<name>, [count=<num>].');
          continue;
        }
        const prototypeName = prototypeNameMatch[1];
        const prototype = manager.getPrototype(prototypeName);

        if (!prototype) {
          console.log(`Error: Prototype '${prototypeName}' not found.`);
          continue;
        }

        if (command === 'batch_clone') {
          const countMatch = line.match(/count=(\d+)/);
          if (!countMatch) {
            console.log('Error: Invalid batch_clone command format. Expected: batch_clone prototype=<name>, count=<num>.');
            continue;
          }
          const count = parseInt(countMatch[1], 10);
          for (let i = 0; i < count; i++) {
            prototype.clone(); // Just clone, we don't need to store each individual one.
          }
          console.log(`${count} ${prototypeName} fixtures cloned`);
          lastClonedObject = undefined; // Batch cloning does not result in a single "last cloned" object
        } else { // Single clone command
          const cloned = prototype.clone();
          lastClonedObject = cloned;
          console.log(`Test fixture cloned from ${prototypeName}`);
        }
      } else if (command === 'modify') {
        const targetMatch = line.match(/modify (\w+)/);
        if (!targetMatch) {
            console.log('Error: Invalid modify command format.');
            continue;
        }
        const target = targetMatch[1]; 
        if (target !== 'clone' || !lastClonedObject) {
          console.log('Error: No clone available to modify or invalid target.');
          continue;
        }

        // Extract modifications string: "key1=value1, key2=value2"
        const modificationsStr = line.substring(line.indexOf(target) + target.length).trim();
        const changedProps: string[] = [];

        modificationsStr.split(',').forEach(mod => {
          const parts = mod.split('=').map(p => p.trim());
          if (parts.length === 2) {
            const key = parts[0];
            let valueStr = parts[1];
            let value: any = valueStr;
            // Parse value similar to parseFixtureString
            if (!isNaN(Number(valueStr)) && !isNaN(parseFloat(valueStr))) {
              value = Number(valueStr);
            } else if (valueStr.toLowerCase() === 'true') {
              value = true;
            } else if (valueStr.toLowerCase() === 'false') {
              value = false;
            } else if ((valueStr.startsWith("'") && valueStr.endsWith("'")) || (valueStr.startsWith('"') && valueStr.endsWith('"'))) {
              value = valueStr.substring(1, valueStr.length - 1);
            }
            lastClonedObject![key] = value;
            changedProps.push(`${key}=${JSON.stringify(value)}`); // Use JSON.stringify for consistent output of modified value
          }
        });
        console.log(`Clone ${changedProps.join(', ')} modified.`);

      } else {
        console.log(`Unknown command: ${command}`);
      }
    } catch (e: any) {
      console.log(`Error processing command '${line}': ${e.message}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "register_prototype name=user_fixture, fixture={username: ''initial_user'', email: ''user@example.com''}\nprototype=user_fixture, clone", "description": "Clone test fixture", "expected_output": "Prototype user_fixture registered\nTest fixture cloned from user_fixture"}, {"input": "register_prototype name=user_fixture, fixture={username: ''initial_user'', email: ''user@example.com''}\nprototype=user_fixture, clone\nmodify clone username=''testuser2''", "description": "Modify cloned fixture", "expected_output": "Prototype user_fixture registered\nTest fixture cloned from user_fixture\nClone username=\"testuser2\" modified."}, {"input": "register_prototype name=order_fixture, fixture={id: 123, status: ''pending''}\nbatch_clone prototype=order_fixture, count=10", "description": "Batch clone fixtures", "expected_output": "Prototype order_fixture registered\n10 order_fixture fixtures cloned"}, {"input": "register_prototype name=admin_user, fixture={role: admin, isActive: true}", "description": "Register new prototype", "expected_output": "Prototype admin_user registered"}, {"input": "register_prototype name=user_data, fixture={id: 1, name: ''Alice''}\nprototype=user_data, clone\nmodify clone name=''Bob'', id=2", "description": "Modify multiple properties of clone", "expected_output": "Prototype user_data registered\nTest fixture cloned from user_data\nClone name=\"Bob\", id=2 modified."}, {"input": "register_prototype name=test_user, fixture={id: 1, name: ''Charlie''}\nprototype=test_user, clone\nprototype=test_user, clone", "description": "Clone multiple times, last cloned is stored", "expected_output": "Prototype test_user registered\nTest fixture cloned from test_user\nTest fixture cloned from test_user"}, {"input": "prototype=nonexistent_fixture, clone", "description": "Attempt to clone non-existent fixture", "expected_output": "Error: Prototype ''nonexistent_fixture'' not found."}, {"input": "register_prototype name=empty_fixture, fixture={}\nprototype=empty_fixture, clone", "description": "Clone an empty fixture", "expected_output": "Prototype empty_fixture registered\nTest fixture cloned from empty_fixture"}]'::jsonb
