    // These classes (e.g., CollaborativeFilteringStrategy) are assumed to be defined by the user.
    if (typeof (globalThis as any).CollaborativeFilteringStrategy !== 'undefined') {
      strategyInstances['collaborative'] = new (globalThis as any).CollaborativeFilteringStrategy();
    }
    if (typeof (globalThis as any).ContentBasedStrategy !== 'undefined') {
      strategyInstances['content_based'] = new (globalThis as any).ContentBasedStrategy();
    }
    if (typeof (globalThis as any).PopularItemsStrategy !== 'undefined') {
