    if (typeof (globalThis as any).ConcreteStrategy !== 'undefined') {
      strategyInstances['concrete'] = new (globalThis as any).ConcreteStrategy();
      if (!strategyInstances['default']) { // Assign 'default' only if not already set by a more specific name
        strategyInstances['default'] = strategyInstances['concrete'];
      }
