              initialUserData = JSON.parse(userDataJson);
            } catch (e: any) {
              console.log(`Error parsing user data for init_context: Invalid JSON provided. ${e.message}`);
              break;
            }
          }
          // Assume user's Context class constructor matches 'new Context(Strategy, UserData)'
          context = new (globalThis as any).Context(initialStrategy, initialUserData);
          console.log(`Context initialized with '${initialStrategyName}' strategy.`);
        } else {
          console.log('Error: init_context requires a strategy name and optional user data (JSON format).');
        }
        break;

      case 'set_user_data':
        // Command format: set_user_data <user_data_json_string>
        if (!context) {
          console.log('Error: Context not initialized. Use 'init_context' first.');
          break;
        }
        if (parts.length > 1) {
          try {
            // All subsequent parts form the JSON string for user data
            const userDataJson = parts.slice(1).join(' ');
            const userData = JSON.parse(userDataJson);
