      case 'get_recommendations':
        // Command format: get_recommendations
        if (!context) {
          console.log('Error: Context not initialized. Use 'init_context' first.');
          break;
        }
        // Assume user's Context class has an executeStrategy method,
        // and the currently set strategy's execute method will print its output to stdout.
        context.executeStrategy();
        break;

      default:
        console.log(`Unknown command: '${command}'`);
        break;
    }
  }
