-- dp_094: Price Drop Observer Alert
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {
  // Map to store subscriptions: product name -> (user name -> Context instance).
  // Each Context instance is configured with a ConcreteStrategy to handle specific alerts for that user.
  const subscriptions: Map<string, Map<string, Context>> = new Map();

  // Helper function to parse command arguments from a string like "user=alice, product=laptop"
  const parseArgs = (argString: string): Record<string, string | number> => {
    const parsed: Record<string, string | number> = {};
    argString.split(', ').forEach(arg => {
      const [key, value] = arg.split('=');
      if (key === 'old' || key === 'new') {
        // Parse old and new prices as numbers
        parsed[key] = parseInt(value, 10);
      } else {
        parsed[key] = value;
      }
    });
    return parsed;
  };

  // Process each line of input as a separate command
  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    const parts = line.split(' ');
    const command = parts[0];
    const args = parts.slice(1).join(' ');

    const parsedArgs = parseArgs(args);

    switch (command) {
      case 'subscribe': {
        const user = parsedArgs.user as string;
        const product = parsedArgs.product as string;

        // Ensure a map exists for the product
        if (!subscriptions.has(product)) {
          subscriptions.set(product, new Map());
        }
        
        // Instantiate the user's ConcreteStrategy and Context classes.
        // Assumes Context's constructor accepts a Strategy, and it has a method (e.g., 'request')
        // to delegate to that strategy.
        const concreteStrategy = new ConcreteStrategy();
        const context = new Context(concreteStrategy); 

        // Store the Context instance associated with the user for this product
        subscriptions.get(product)?.set(user, context); 

        console.log(`${user} subscribed to price drops for ${product}`);
        break;
      }

      case 'price_update': {
        const product = parsedArgs.product as string;
        const oldPrice = parsedArgs.old as number;
        const newPrice = parsedArgs.new as number;

        if (newPrice < oldPrice) {
          // Only notify subscribers if there's an actual price drop
          if (subscriptions.has(product)) {
            const productSubscribers = subscriptions.get(product)!;
            // Iterate over each subscriber for the affected product
            productSubscribers.forEach((context, user) => {
              // Trigger the Context's method (e.g., 'request') to execute its associated Strategy.
              // The data passed includes all necessary details for the alert.
              context.request({ user, product, oldPrice, newPrice }); 
            });
          }
          // If there are no subscribers for the product, no output is produced for the price update.
        } else {
          // If price increased or stayed the same, no alert is generated
          console.log("No alert: price increased");
        }
        break;
      }

      case 'unsubscribe': {
        const user = parsedArgs.user as string;
        const product = parsedArgs.product as string;

        if (subscriptions.has(product)) {
          const productSubscribers = subscriptions.get(product)!;
          if (productSubscribers.has(user)) {
            productSubscribers.delete(user);
            // If this product now has no subscribers, clean up by removing the product entry itself
            if (productSubscribers.size === 0) {
              subscriptions.delete(product);
            }
            console.log(`${user} unsubscribed from ${product} price alerts`);
          }
        }
        break;
      }

      default: {
        // Ignore unrecognized commands to prevent unexpected test output
        break;
      }
    }
  }
});$harness$,
  test_cases   = '[{"input": "subscribe user=alice, product=laptop", "description": "Subscribe to price drop", "expected_output": "alice subscribed to price drops for laptop"}, {"input": "subscribe user=alice, product=laptop\nprice_update product=laptop, old=1000, new=850", "description": "Price drop notification", "expected_output": "alice subscribed to price drops for laptop\nalice alerted: laptop dropped from $1000 to $850"}, {"input": "subscribe user=alice, product=laptop\nprice_update product=laptop, old=850, new=900", "description": "No alert on price increase", "expected_output": "alice subscribed to price drops for laptop\nNo alert: price increased"}, {"input": "subscribe user=alice, product=laptop\nunsubscribe user=alice, product=laptop", "description": "Unsubscribe from alerts", "expected_output": "alice subscribed to price drops for laptop\nalice unsubscribed from laptop price alerts"}, {"input": "subscribe user=alice, product=laptop\nsubscribe user=bob, product=laptop\nprice_update product=laptop, old=2000, new=1800", "description": "Multiple users subscribed to the same product are alerted", "expected_output": "alice subscribed to price drops for laptop\nbob subscribed to price drops for laptop\nalice alerted: laptop dropped from $2000 to $1800\nbob alerted: laptop dropped from $2000 to $1800"}, {"input": "price_update product=tablet, old=500, new=450", "description": "Price drop for a product with no active subscriptions yields no alerts", "expected_output": ""}, {"input": "subscribe user=alice, product=laptop\nsubscribe user=alice, product=tablet\nsubscribe user=bob, product=laptop\nprice_update product=laptop, old=1500, new=1400\nprice_update product=tablet, old=700, new=750", "description": "Only relevant subscribers are alerted for specific product price drop, others ignored", "expected_output": "alice subscribed to price drops for laptop\nalice subscribed to price drops for tablet\nbob subscribed to price drops for laptop\nalice alerted: laptop dropped from $1500 to $1400\nbob alerted: laptop dropped from $1500 to $1400\nNo alert: price increased"}, {"input": "subscribe user=charlie, product=monitor\nunsubscribe user=charlie, product=monitor\nprice_update product=monitor, old=300, new=250", "description": "Subscribe then immediately unsubscribe, no alerts", "expected_output": "charlie subscribed to price drops for monitor\ncharlie unsubscribed from monitor price alerts"}]'::jsonb
WHERE id = 'dp_094';
