const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {
  // Map of expected Strategy class names to their constructors.
  // The Cr4ck platform will prepend the user's code, making their classes globally available.
  // We assume the user creates specific strategy classes for different "factories"
  // (e.g., CoffeeStrategy, TeaStrategy, JuiceStrategy), all implementing the `Strategy` interface.
  // The `as any` is used to bypass TypeScript's strict type checking for global class references
  // that are defined in user code and are not known at the harness's compile time.
  const strategyConstructors: { [key: string]: new () => Strategy } = {};

  // Dynamically add available strategy classes to the map.
  // This ensures the harness can create instances of the user-defined strategies.
  // If a class is not defined by the user, we'll log an error later.
  if (typeof CoffeeStrategy !== 'undefined') {
    strategyConstructors['CoffeeStrategy'] = CoffeeStrategy as any;
  }
  if (typeof TeaStrategy !== 'undefined') {
    strategyConstructors['TeaStrategy'] = TeaStrategy as any;
  }
  if (typeof JuiceStrategy !== 'undefined') {
