  }
  // Include the default ConcreteStrategy, in case the user modifies this one for all types
  // (though this is less ideal for a proper Strategy pattern demonstration).
  if (typeof ConcreteStrategy !== 'undefined') {
    strategyConstructors['ConcreteStrategy'] = ConcreteStrategy as any;
  }

  // Initialize the Context instance once. This represents the central factory line.
  // The user's Context class is expected to have a default constructor and a `setStrategy` method,
  // as well as a method to trigger the current strategy's execution (e.g., `makeBeverage`).
  let context: Context = new Context(); 

  for (const line of lines) {
    if (line.startsWith("SET_STRATEGY ")) {
      const strategyClassName = line.substring("SET_STRATEGY ".length);
      if (strategyConstructors[strategyClassName]) {
