      // Assuming the Context's method to trigger strategy execution is named 'makeBeverage'
      // and it takes the specific beverage type as data, which is then passed to the current Strategy's execute method.
      context.makeBeverage(beverageType);
    } else {
      console.log(`Error: Unknown command '${line}'`);
    }
  }
});$harness$,
