-- dp_096: Network Request Builder Chainer
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

/**
 * Internal interface to represent the state of a network request configuration.
 * This type is used by the harness to interact with the user's Context and Strategy,
 * assuming the user's implementation will manage a similar structure.
 */
interface InternalRequestConfig {
  url: string;
  method: string;
  headers: Record<string, string>;
  params: Record<string, string>;
  timeout: number; // in seconds
}

/**
 * The harness assumes the user's `Strategy` interface looks like this,
 * adapting the starter's `execute(data: unknown)` to `execute(config: InternalRequestConfig)`.
 */
interface Strategy {
  execute(config: InternalRequestConfig): void;
}

/**
 * The harness assumes the user's `Context` class has the following public API:
 * - A constructor `new Context()` that initializes an empty request configuration.
 * - A public method `applyStrategy(strategy: Strategy): void` which takes a Strategy object
 *   and executes it, modifying the internal request configuration.
 * - A public method `getRequestConfig(): InternalRequestConfig` that returns a copy
 *   of the current internal request configuration for inspection by the harness.
 *
 * The harness also assumes the user's `ConcreteStrategy` class can be instantiated
 * with an action function, e.g., `new ConcreteStrategy((config: InternalRequestConfig) => { ... })`.
 * This makes `ConcreteStrategy` a flexible command wrapper, as implied by the generic starter class.
 */

/**
 * Helper function to format the request configuration into a consistent string output.
 * This output format is used to generate the `expected_output` for test cases.
 */
function formatConfig(config: InternalRequestConfig): string {
  let output = `${config.method} ${config.url}`;

  const paramsArray = Object.entries(config.params).map(([k, v]) => `${k}=${v}`);
  if (paramsArray.length > 0) {
    output += `?${paramsArray.join('&')}`;
  }

  const parts: string[] = [];
  const headersArray = Object.entries(config.headers).map(([k, v]) => `${k}: ${v}`);
  if (headersArray.length > 0) {
    parts.push(`Headers: {${headersArray.join(', ')}}`);
  }
  if (config.timeout > 0) {
    parts.push(`Timeout: ${config.timeout}s`);
  }

  if (parts.length > 0) {
    return `${output} [${parts.join(', ')}]`;
  } else {
    return output;
  }
}

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  let requestBuilder: Context | undefined; // The user's Context instance

  lines.forEach((line) => {
    if (line.startsWith('build')) {
      const parts = line.substring('build '.length).split(', ').map(p => p.split('='));
      const url = parts.find(p => p[0] === 'url')?.[1] || '';
      const method = parts.find(p => p[0] === 'method')?.[1] || 'GET';
      
      // Initialize a new builder for each 'build' command, effectively resetting state.
      requestBuilder = new Context(); 
      
      // Apply the initial URL and method using a ConcreteStrategy, also clearing other state.
      (requestBuilder as any).applyStrategy(new ConcreteStrategy((config: InternalRequestConfig) => {
        config.url = url;
        config.method = method;
        config.headers = {}; // Clear previous headers
        config.params = {}; // Clear previous params
        config.timeout = 0; // Clear previous timeout
      }));
      
      console.log(formatConfig((requestBuilder as any).getRequestConfig()));
    } else if (line.startsWith('chain .header(')) {
      if (!requestBuilder) { console.log("Error: Builder not initialized. Use 'build' first."); return; }
      const match = line.match(/\.header\(([^\s]+)\s(.+)\)/);
      if (match) {
        const key = match[1];
        const value = match[2];
        (requestBuilder as any).applyStrategy(new ConcreteStrategy((config: InternalRequestConfig) => {
          config.headers[key] = value;
        }));
        console.log(formatConfig((requestBuilder as any).getRequestConfig()));
      } else {
        console.log(`Error: Malformed header command: ${line}`);
      }
    } else if (line.startsWith('chain .param(')) {
      if (!requestBuilder) { console.log("Error: Builder not initialized. Use 'build' first."); return; }
      const match = line.match(/\.param\(([^=]+)=(.+)\)/);
      if (match) {
        const key = match[1];
        const value = match[2];
        (requestBuilder as any).applyStrategy(new ConcreteStrategy((config: InternalRequestConfig) => {
          config.params[key] = value;
        }));
        console.log(formatConfig((requestBuilder as any).getRequestConfig()));
      } else {
        console.log(`Error: Malformed param command: ${line}`);
      }
    } else if (line.startsWith('chain .timeout(')) {
      if (!requestBuilder) { console.log("Error: Builder not initialized. Use 'build' first."); return; }
      const match = line.match(/\.timeout\((\d+)\)/);
      if (match) {
        const seconds = parseInt(match[1], 10);
        (requestBuilder as any).applyStrategy(new ConcreteStrategy((config: InternalRequestConfig) => {
          config.timeout = seconds;
        }));
        console.log(formatConfig((requestBuilder as any).getRequestConfig()));
      } else {
        console.log(`Error: Malformed timeout command: ${line}`);
      }
    } else if (line === 'execute request') {
      if (!requestBuilder) { console.log("Error: Builder not initialized. Use 'build' first."); return; }
      console.log("Request executed, response received");
    } else {
      console.log(`Error: Unknown command: ${line}`);
    }
  });
});$harness$,
  test_cases   = '[{"input": "build url=https://api.example.com/users, method=GET", "description": "Build simple GET request", "expected_output": "GET https://api.example.com/users"}, {"input": "build url=https://api.example.com/users, method=GET\nchain .header(Authorization Bearer token123)\nchain .timeout(30)", "description": "Chain headers and timeout", "expected_output": "GET https://api.example.com/users\nGET https://api.example.com/users [Headers: {Authorization: Bearer token123}]\nGET https://api.example.com/users [Headers: {Authorization: Bearer token123}, Timeout: 30s]"}, {"input": "build url=https://api.example.com/users, method=GET\nchain .param(page=1)\nchain .param(limit=20)", "description": "Chain query parameters", "expected_output": "GET https://api.example.com/users\nGET https://api.example.com/users?page=1\nGET https://api.example.com/users?page=1&limit=20"}, {"input": "build url=https://api.example.com/data, method=POST\nchain .header(Content-Type application/json)\nchain .timeout(10)\nexecute request", "description": "Build a POST request with headers and timeout, then execute", "expected_output": "POST https://api.example.com/data\nPOST https://api.example.com/data [Headers: {Content-Type: application/json}]\nPOST https://api.example.com/data [Headers: {Content-Type: application/json}, Timeout: 10s]\nRequest executed, response received"}, {"input": "build url=https://api.example.com/products, method=GET\nchain .param(category=electronics)\nchain .param(sort=price_asc)\nchain .header(X-Source MobileApp)\nexecute request", "description": "Build a complex GET request with multiple params and header, then execute", "expected_output": "GET https://api.example.com/products\nGET https://api.example.com/products?category=electronics\nGET https://api.example.com/products?category=electronics&sort=price_asc\nGET https://api.example.com/products?category=electronics&sort=price_asc [Headers: {X-Source: MobileApp}]\nRequest executed, response received"}, {"input": "build url=https://api.example.com/auth, method=PUT\nchain .header(X-CSRF-Token some-token-value)\nchain .header(Accept application/xml)\nexecute request", "description": "Build a PUT request with multiple custom headers, then execute", "expected_output": "PUT https://api.example.com/auth\nPUT https://api.example.com/auth [Headers: {X-CSRF-Token: some-token-value}]\nPUT https://api.example.com/auth [Headers: {X-CSRF-Token: some-token-value, Accept: application/xml}]\nRequest executed, response received"}]'::jsonb
