-- dp_097: Cache Invalidation Decorator Layer
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout,
  terminal: false
});

const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', () => {
  // Store the original console.log
  const originalConsoleLog = console.log;
  let capturedLogs: string[] = [];

  // Override console.log to capture output from user's code
  console.log = (...args: unknown[]) => {
    capturedLogs.push(args.map(a => String(a)).join(' '));
  };

  // Mock Date.now for time-based tests
  const originalDateNow = Date.now;
  // Initialize currentMockTime to actual current time, then advance it with SIMULATE_TIME
  let currentMockTime: number = originalDateNow(); 
  Date.now = () => currentMockTime;

  // Default TTL for the cache (can be overridden by SET_TTL command)
  const DEFAULT_TTL = 5000; // 5 seconds
  let currentTTL: number = DEFAULT_TTL;

  // Instantiate the user's ConcreteStrategy (mock DB)
  // The user's `Strategy` interface (from starter code) should be adapted to define:
  //   `fetch(key: string): string;`
  // The user's `ConcreteStrategy` class should implement this `fetch` method.
  // @ts-ignore: We are assuming user implements `fetch` on `ConcreteStrategy`
  const dbStrategy: Strategy = new ConcreteStrategy();

  // Instantiate the user's Context (the caching layer)
  // The user's `Context` constructor (from starter code) should accept:
  //   `constructor(strategy: Strategy, ttl: number)`
  // It should also have public methods:
  //   `getData(key: string): string;`
  //   `invalidate(key: string): void;`
  // @ts-ignore: We are assuming user implements `getData` and `invalidate` on `Context`
  let cacheContext: Context = new Context(dbStrategy, currentTTL);

  // Helper to re-initialize Context when TTL changes
  function resetCacheContext(newTtl: number) {
      currentTTL = newTtl;
      // Re-instantiate Context with the new TTL. This effectively clears the cache.
      // @ts-ignore
      cacheContext = new Context(dbStrategy, currentTTL);
  }

  // Process commands
  for (const line of lines) {
    const parts = line.split(' ');
    const command = parts[0];
    const arg = parts.slice(1).join(' ');

    capturedLogs = []; // Clear logs for *each* command execution (captures user code output)

    try {
      switch (command) {
        case 'SET_TTL':
          const newTtl = parseInt(arg, 10);
          if (isNaN(newTtl) || newTtl <= 0) {
            originalConsoleLog(`Error: Invalid TTL value: ${arg}`);
            continue; // Skip to next command
          }
          resetCacheContext(newTtl);
          // Harness prints its own setup messages directly using originalConsoleLog
          originalConsoleLog(`TTL set to ${newTtl}ms. Cache re-initialized.`);
          break;

        case 'GET':
          // User's Context.getData() is expected to print messages and return data
          // @ts-ignore
          cacheContext.getData(arg);
          break;

        case 'INVALIDATE':
          // User's Context.invalidate() is expected to print messages
          // @ts-ignore
          cacheContext.invalidate(arg);
          break;

        case 'SIMULATE_TIME':
          const timeToAdvance = parseInt(arg, 10);
          if (isNaN(timeToAdvance) || timeToAdvance < 0) {
            originalConsoleLog(`Error: Invalid time to advance: ${arg}`);
            continue;
          }
          currentMockTime += timeToAdvance;
          // This command does not produce output from user code nor from harness directly.
          break;

        default:
          originalConsoleLog(`Unknown command: ${command}`);
          break;
      }
    } catch (error: any) {
      originalConsoleLog(`Error processing command "${line}": ${error.message || error}`);
    }

    // After each command, print any output captured from the user's code.
    // Output from harness-specific commands (SET_TTL, errors) is printed directly.
    if (capturedLogs.length > 0) {
        originalConsoleLog(capturedLogs.join('\n'));
    }
  }

  // Restore original Date.now and console.log
  Date.now = originalDateNow;
  console.log = originalConsoleLog;
});$harness$,
  test_cases   = '[{"input": "GET user_123", "description": "Cache miss fetches from DB", "expected_output": "Cache miss, fetched from DB, cached Data for user_123 from DB"}, {"input": "GET user_123\nGET user_123", "description": "Cache hit returns cached data", "expected_output": "Cache miss, fetched from DB, cached Data for user_123 from DB\nCache hit, returned Data for user_123 from DB from cache"}, {"input": "SET_TTL 100\nGET user_123\nSIMULATE_TIME 150\nGET user_123", "description": "TTL expiry invalidates cache", "expected_output": "TTL set to 100ms. Cache re-initialized.\nCache miss, fetched from DB, cached Data for user_123 from DB\nCache expired, re-fetched and re-cached Data for user_123 from DB"}, {"input": "GET user_123\nINVALIDATE user_123\nGET user_123", "description": "Manual cache invalidation", "expected_output": "Cache miss, fetched from DB, cached Data for user_123 from DB\nCache invalidated for user_123\nCache miss, fetched from DB, cached Data for user_123 from DB"}]'::jsonb
WHERE id = 'dp_097';
-- dp_098: Remote Resource Proxy Loader
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // The user's code is prepended to this harness.
  // We assume the user has adapted the provided 'Strategy', 'Context', and 'ConcreteStrategy' classes
  // to implement the Proxy pattern. Specifically:
  //
  // 1. The 'Strategy' interface is expected to define the operation performed by the RealSubject.
  //    Its 'execute' method signature is assumed to be `(resourceName: string, options?: any): string`.
  //
  // 2. 'ConcreteStrategy' acts as the RealSubject, implementing the `Strategy` interface and
  //    containing the actual resource loading logic (e.g., simulating a real fetch or unavailability).
  //
  // 3. 'Context' acts as the Proxy. It's expected to:
  //    - Take an instance of `Strategy` (the RealSubject) in its constructor.
  //    - Have a public method (e.g., 'run', as hinted by the starter code's TODO "run it")
  //      that takes `resourceName: string` and an `options` object, and returns a `string`.
  //      This method will implement the proxy's behaviors (caching, lazy loading, remote fetching, fallback).

  // Instantiate the real subject (ConcreteStrategy).
  // Since user code is prepended, `ConcreteStrategy` should be globally available.
  const realSubject: Strategy = new ConcreteStrategy();

  // Instantiate the proxy (Context), injecting the real subject.
  // `Context` is expected to be globally available and its constructor takes a `Strategy` instance.
  const proxy: Context = new Context(realSubject);

  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    // Parse input line. Commands are like "resource=name, key=value".
    // We split by space or comma, then parse key=value pairs.
    const parts = line.split(/[ ,]+/).filter(Boolean); // Split by space or comma, filter empty strings
    let resourceName: string | undefined;
    const options: { [key: string]: string } = {};

    for (const part of parts) {
      if (part.includes('=')) {
        const [key, value] = part.split('=');
        if (key === "resource") {
          resourceName = value;
        } else {
          options[key] = value;
        }
      }
      // Non-key=value parts (like the implicit "fetch" command) are ignored.
    }

    if (!resourceName) {
      console.log(`Error: Resource name not specified in input: ${line}`);
      continue;
    }

    try {
      // Call the proxy's primary method. We assume a 'run' method based on the Context's TODO.
      // We cast to `any` to allow calling `run` if it's not explicitly defined on `Context` interface for the harness.
      if (typeof (proxy as any).run === 'function') {
        const result = (proxy as any).run(resourceName, options);
        console.log(result);
      } else {
        console.log(`Error: Proxy 'Context' class does not have a public 'run' method.`);
      }
    } catch (error: any) {
      console.log(`Error processing command for resource '${resourceName}' with options ${JSON.stringify(options)}: ${error.message}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "resource=remote_config, cache=empty", "description": "Initial remote resource fetch (explicitly ignoring cache).", "expected_output": "Proxy: fetching remote_config from origin"}, {"input": "resource=remote_config, cache=empty\nresource=remote_config", "description": "Fetch a resource, then retrieve it from cache.", "expected_output": "Proxy: fetching remote_config from origin\nProxy: returning cached remote_config"}, {"input": "resource=heavy_dataset size=100MB", "description": "Initial request for a large resource, triggering lazy loading.", "expected_output": "Proxy: loading heavy_dataset lazily"}, {"input": "resource=heavy_dataset size=100MB\nresource=heavy_dataset size=100MB", "description": "Subsequent request for a lazily loaded resource should still report lazy loading initiated unless actual data is fetched.", "expected_output": "Proxy: loading heavy_dataset lazily\nProxy: loading heavy_dataset lazily"}, {"input": "resource=offline_resource", "description": "Request for an unavailable resource, triggering a fallback.", "expected_output": "Proxy: resource unavailable, returning fallback"}, {"input": "resource=another_config, cache=empty\nresource=another_config\nresource=another_config, cache=empty", "description": "Mixed operations: initial fetch, then cached access, then forced re-fetch ignoring cache.", "expected_output": "Proxy: fetching another_config from origin\nProxy: returning cached another_config\nProxy: fetching another_config from origin"}]'::jsonb
WHERE id = 'dp_098';
-- dp_099: Connection Pool Singleton Manager
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', async () => {
    let connectionPoolManager: any = null; // Will hold the user's singleton instance
    const output: string[] = [];
    
    // Map to hold references to Connection objects acquired by the harness.
    // This is crucial because the user's acquireConnection is expected to return a Connection object
    // which then needs to be passed back to releaseConnection.
    // The key is the connection's ID, and the value is the actual Connection object.
    const acquiredConnections: Map<number, any> = new Map(); 

    // Helper to format pool status for output based on assumed getStatus() method
    // Assumes user's getStatus() returns { used: number, total: number }
    const printStatus = () => {
        if (connectionPoolManager) {
            const status = connectionPoolManager.getStatus();
            return `(${status.used}/${status.total} used)`;
        }
        return '';
    };

    for (const line of lines) {
        const parts = line.split(' ');
        const command = parts[0];

        switch (command) {
            case 'INIT_POOL': {
                const size = parseInt(parts[1], 10);
                if (isNaN(size) || size <= 0) {
                    output.push(`Error: Invalid pool size '${parts[1]}'.`);
                    continue;
                }

                if (!connectionPoolManager) {
                    try {
                        // Assume ConnectionPoolManager.getInstance is a static method that takes size as an initial argument
                        // The user's ConnectionPoolManager class should be globally available due to concatenation.
                        connectionPoolManager = (global as any).ConnectionPoolManager.getInstance(size);
                        output.push(`Connection pool initialized with size ${size}.`);
                    } catch (e: any) {
                        output.push(`Error initializing pool: ${e.message}`);
                    }
                } else {
                    // Pool already exists (Singleton behavior). Check if size is consistent.
                    // Assume getPoolSize() method exists on the user's ConnectionPoolManager to verify state.
                    const currentPoolSize = connectionPoolManager.getPoolSize(); 
                    if (currentPoolSize !== size) {
                        output.push(`Attempted to re-initialize pool with size ${size}, but instance already exists with size ${currentPoolSize}.`);
                    } else {
                        output.push(`Connection pool already initialized with size ${size}.`);
                    }
                }
                break;
            }

            case 'GET_CONNECTION': {
                if (!connectionPoolManager) {
                    output.push('Error: Connection pool not initialized. Use INIT_POOL first.');
                    continue;
                }
                try {
                    // Assume acquireConnection returns a Connection object (with an 'id' property) or null if exhausted.
                    const connection = connectionPoolManager.acquireConnection();
                    if (connection) {
                        // Store the acquired connection object reference in the harness's map.
                        // Assumes the connection object has an 'id' property.
                        acquiredConnections.set(connection.id, connection);
                        output.push(`Connection ${connection.id} acquired ${printStatus()}.`);
                    } else {
                        // If null or undefined, indicates no connection available immediately (pool exhausted).
                        output.push('Pool exhausted, waiting for available connection.');
                    }
                } catch (e: any) {
                    output.push(`Error acquiring connection: ${e.message}`);
                }
                break;
            }

            case 'RELEASE_CONNECTION': {
                if (!connectionPoolManager) {
                    output.push('Error: Connection pool not initialized. Use INIT_POOL first.');
                    continue;
                }
                const connId = parseInt(parts[1], 10);
                if (isNaN(connId)) {
                    output.push(`Error: Invalid connection ID '${parts[1]}'.`);
                    continue;
                }

                const connectionToRelease = acquiredConnections.get(connId);
                if (!connectionToRelease) {
                    output.push(`Error: Connection ${connId} not found in acquired list (might be already released or never acquired by harness).`);
                    continue;
                }
                
                try {
                    // Assume releaseConnection takes the Connection object and returns boolean success.
                    const success = connectionPoolManager.releaseConnection(connectionToRelease);
                    if (success) {
                        acquiredConnections.delete(connId); // Remove from harness's tracking
                        output.push(`Connection ${connId} returned to pool ${printStatus()}.`);
                    } else {
                        output.push(`Error: Failed to return connection ${connId} to pool (user's release method returned false).`);
                    }
                } catch (e: any) {
                    output.push(`Error releasing connection ${connId}: ${e.message}`);
                }
                break;
            }

            case 'GET_POOL_STATUS': { // For debugging or explicit status checks of the pool
                if (!connectionPoolManager) {
                    output.push('Connection pool not initialized.');
                } else {
                    const status = connectionPoolManager.getStatus();
                    output.push(`Current pool status: ${status.used}/${status.total} used.`);
                }
                break;
            }

            default:
                output.push(`Unknown command: ${command}`);
        }
    }

    output.forEach(line => console.log(line));
});$harness$,
  test_cases   = '[{"input": "INIT_POOL 10\nGET_CONNECTION", "description": "Acquire connection from pool", "expected_output": "Connection pool initialized with size 10.\nConnection 1 acquired (1/10 used)."}, {"input": "INIT_POOL 1\nGET_CONNECTION\nGET_CONNECTION", "description": "Pool exhausted waits", "expected_output": "Connection pool initialized with size 1.\nConnection 1 acquired (1/1 used).\nPool exhausted, waiting for available connection."}, {"input": "INIT_POOL 10\nGET_CONNECTION\nRELEASE_CONNECTION 1", "description": "Release connection", "expected_output": "Connection pool initialized with size 10.\nConnection 1 acquired (1/10 used).\nConnection 1 returned to pool (0/10 used)."}, {"input": "INIT_POOL 5\nGET_CONNECTION\nINIT_POOL 10\nGET_CONNECTION", "description": "Get singleton pool instance and verify state retention (cannot re-initialize size)", "expected_output": "Connection pool initialized with size 5.\nConnection 1 acquired (1/5 used).\nAttempted to re-initialize pool with size 10, but instance already exists with size 5.\nConnection 2 acquired (2/5 used)."}, {"input": "INIT_POOL 3\nGET_CONNECTION\nGET_CONNECTION\nRELEASE_CONNECTION 1\nGET_CONNECTION\nGET_POOL_STATUS", "description": "Complex scenario: init, acquire multiple, release one, acquire again, check status", "expected_output": "Connection pool initialized with size 3.\nConnection 1 acquired (1/3 used).\nConnection 2 acquired (2/3 used).\nConnection 1 returned to pool (1/3 used).\nConnection 3 acquired (2/3 used).\nCurrent pool status: 2/3 used."}]'::jsonb
WHERE id = 'dp_099';
-- dp_100: Workflow Step Command Executor
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout,
  terminal: false
});

const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', () => {
  // These ConcreteStrategy classes implement the `Strategy` interface
  // and are expected to be provided by the user's solution.
  // They interact with the `Context` instance passed via the `data` object.

  class InitializeWorkflowStrategy implements Strategy {
    execute(data: unknown): void {
      const { context, steps } = data as { context: Context; steps: string[] };
      context.setWorkflow(steps);
      console.log(`Workflow initialized with: ${steps.join(', ')}`);
    }
  }

  class ExecuteWorkflowStrategy implements Strategy {
    execute(data: unknown): void {
      const { context } = data as { context: Context };
      const workflow = context.getWorkflow();
      let currentIdx = context.getCurrentStepIndex();
      let outputSegments: string[] = [];
      let anyActualExecution = false;
      let lastProcessedIndex = currentIdx;

      if (currentIdx + 1 >= workflow.length) {
        console.log("No steps to execute.");
        return;
      }

      for (let i = currentIdx + 1; i < workflow.length; i++) {
        const step = workflow[i];
        if (context.isStepSkipped(step)) {
          outputSegments.push(`${step} skipped`);
        } else {
          outputSegments.push(step); // Just the step name
          anyActualExecution = true;
        }
        lastProcessedIndex = i; // Advance index for all steps processed in this run
      }

      if (outputSegments.length > 0) {
        let finalOutput = outputSegments.join(', '); // Use ', ' for consistency
        if (anyActualExecution) {
          finalOutput += ' executed';
        }
        console.log(finalOutput);
        context.setCurrentStepIndex(lastProcessedIndex); // Update context's current step
      } else {
        console.log("No steps to execute.");
      }
    }
  }

  class SkipStepStrategy implements Strategy {
    execute(data: unknown): void {
      const { context, step: stepToSkip } = data as { context: Context; step: string };
      if (context.getWorkflow().includes(stepToSkip)) {
        context.addSkippedStep(stepToSkip);
        console.log(`${stepToSkip} marked for skipping.`);
      } else {
        console.log(`Error: Step '${stepToSkip}' not found in workflow.`);
      }
    }
  }

  class AddStepStrategy implements Strategy {
    execute(data: unknown): void {
      const { context, after, new_step } = data as { context: Context; after: string; new_step: string };
      if (context.insertStep(after, new_step)) {
        console.log(`${new_step} added after ${after}`);
      } else {
        console.log(`Error: Step '${after}' not found to add after.`);
      }
    }
  }

  class UndoStepStrategy implements Strategy {
    execute(data: unknown): void {
      const { context, step: targetStep } = data as { context: Context; step: string };
      const workflow = context.getWorkflow();
      const currentIdx = context.getCurrentStepIndex();

      if (currentIdx >= 0) {
        const lastProcessedStep = workflow[currentIdx];
        if (lastProcessedStep === targetStep) {
          context.setCurrentStepIndex(currentIdx - 1);
          const newCurrentStep = workflow[context.getCurrentStepIndex()];
          console.log(`${targetStep} undone, workflow at ${newCurrentStep || 'start'}`);
        } else {
          console.log(`Error: Cannot undo '${targetStep}'. Last processed step was '${lastProcessedStep}'.`);
        }
      } else {
        console.log("No steps to undo.");
      }
    }
  }

  // Instantiate the stateful Context object (provided by user's code)
  const workflowContext = new Context();

  // Process each line as a command
  lines.forEach(line => {
    if (!line) return; // Skip empty lines

    const parts = line.split(' ');
    const command = parts[0];
    const args: Record<string, any> = {};

    parts.slice(1).forEach(part => {
      const [key, value] = part.split('=');
      if (key && value) {
        if (key === 'steps') { // Special handling for comma-separated steps
          args[key] = value.split(',');
        } else {
          args[key] = value;
        }
      }
    });

    // Set strategy and run it, passing additional arguments.
    // The Context object itself is automatically injected into the data for the strategy.
    let strategy: Strategy | null = null;
    switch (command) {
      case 'init_workflow':
        strategy = new InitializeWorkflowStrategy();
        break;
      case 'execute_workflow':
        strategy = new ExecuteWorkflowStrategy();
        break;
      case 'skip_step':
        strategy = new SkipStepStrategy();
        break;
      case 'add_step':
        strategy = new AddStepStrategy();
        break;
      case 'undo_step':
        strategy = new UndoStepStrategy();
        break;
      default:
        console.log(`Unknown command: ${command}`);
        return;
    }

    if (strategy) {
      workflowContext.setStrategy(strategy);
      workflowContext.runStrategy(args); // Pass args, Context will add itself to it.
    }
  });
});$harness$,
  test_cases   = '[{"input": "init_workflow steps=step1,step2,step3\nexecute_workflow", "description": "Execute workflow steps", "expected_output": "Workflow initialized with: step1, step2, step3\nstep1, step2, step3 executed"}, {"input": "init_workflow steps=step1,step2,step3\nskip_step step=step2\nexecute_workflow", "description": "Skip step in workflow", "expected_output": "Workflow initialized with: step1, step2, step3\nstep2 marked for skipping.\nstep1, step2 skipped, step3 executed"}, {"input": "init_workflow steps=step1,step2,step3\nexecute_workflow\nundo_step step=step3", "description": "Undo step", "expected_output": "Workflow initialized with: step1, step2, step3\nstep1, step2, step3 executed\nstep3 undone, workflow at step2"}, {"input": "init_workflow steps=step1,step2,step3\nadd_step after=step2 new_step=step2b\nexecute_workflow", "description": "Add step to workflow", "expected_output": "Workflow initialized with: step1, step2, step3\nstep2b added after step2\nstep1, step2, step2b, step3 executed"}]'::jsonb
WHERE id = 'dp_100';
-- oop_001: Library System
UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.HashMap;
import java.util.Map;

class Main {
    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        Library library = new Library();
        Map<String, Book> bookInstances = new HashMap<>();
        Map<String, User> userInstances = new HashMap<>();

        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }
            String[] parts = line.split(" ");
            String command = parts[0];
            String bookName = parts.length > 1 ? parts[1] : null;
            String userName = parts.length > 2 ? parts[2] : null;

            Book book = null;
            if (bookName != null) {
                book = bookInstances.computeIfAbsent(bookName, name -> new Book(name));
            }

            User user = null;
            if (userName != null) {
                user = userInstances.computeIfAbsent(userName, name -> new User(name));
            }

            String result = "";
            switch (command) {
                case "add": // Command to add a book to the library's general inventory
                    if (book == null) {
                        result = "Error: Book name required for 'add' command.";
                    } else {
                        // The user's Library class must implement addBook(Book book)
                        result = library.addBook(book);
                    }
                    break;
                case "borrow":
                    if (book == null || user == null) {
                        result = "Error: Book and User names required for 'borrow' command.";
                    } else {
                        // The user's Library class must implement borrowBook(Book book, User user)
                        result = library.borrowBook(book, user);
                    }
                    break;
                case "return":
                    if (book == null || user == null) {
                        result = "Error: Book and User names required for 'return' command.";
                    } else {
                        // The user's Library class must implement returnBook(Book book, User user)
                        result = library.returnBook(book, user);
                    }
                    break;
                default:
                    result = "Unknown command: " + command;
                    break;
            }
            if (!result.isEmpty()) {
                System.out.println(result);
            }
        }
        sc.close();
    }
}$harness$,
