-- oop_002: E-Commerce Cart
UPDATE challenges SET
  test_harness = $harness$import sys

# User's Cart, DiscountStrategy, PercentageDiscount, and FixedDiscount classes
# are expected to be available in the global scope when this harness runs.
# DiscountStrategy is expected to be an abstract base class.
# PercentageDiscount and FixedDiscount are expected to inherit from DiscountStrategy.

def run_harness():
    cart = Cart() # Initialize the user's Cart object

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        parts = line.split(maxsplit=1)
        command = parts[0]
        args = parts[1] if len(parts) > 1 else ""

        try:
            if command == "add":
                # Expects: add <item_name> <price> <quantity>
                item_parts = args.split()
                if len(item_parts) != 3:
                    print(f"Error: Invalid 'add' command format: {line}")
                    continue
                item_name = item_parts[0]
                price = float(item_parts[1])
                quantity = int(item_parts[2])
                cart.add_item(item_name, price, quantity)
                print(f"Added {quantity} x {item_name} at {price:.2f} each.")

            elif command == "remove":
                # Expects: remove <item_name> [quantity]
                item_parts = args.split()
                item_name = item_parts[0]
                quantity_to_remove = int(item_parts[1]) if len(item_parts) > 1 else None # None means remove all
                
                removed_qty = cart.remove_item(item_name, quantity_to_remove)
                if removed_qty > 0:
                    print(f"Removed {removed_qty} x {item_name}.")
                else:
                    print(f"Item '{item_name}' not found or no quantity removed.")

            elif command == "apply_discount":
                # Expects: apply_discount <type> <value> <code_name>
                discount_parts = args.split(maxsplit=2) # type, value, code_name
                if len(discount_parts) != 3:
                    print(f"Error: Invalid 'apply_discount' command format: {line}")
                    continue
                discount_type = discount_parts[0]
                value = float(discount_parts[1])
                code_name = discount_parts[2]

                discount_strategy = None
                if discount_type == "percentage":
                    discount_strategy = PercentageDiscount(value, code_name)
                elif discount_type == "fixed":
                    # User is expected to implement FixedDiscount class
                    discount_strategy = FixedDiscount(value, code_name)
                else:
                    print(f"Error: Unknown discount type '{discount_type}'.")
                    continue

                cart.apply_discount(discount_strategy)
                print(f"Applied {discount_type.capitalize()} discount '{code_name}'.")

            elif command == "remove_discount":
                # Expects: remove_discount <code_name>
                code_name = args.strip()
                if cart.remove_discount(code_name):
                    print(f"Removed discount '{code_name}'.")
                else:
                    print(f"Discount '{code_name}' not found.")

            elif command == "set_tax":
                # Expects: set_tax <rate>
                tax_rate = float(args.strip())
                cart.set_tax_rate(tax_rate)
                print(f"Tax rate set to {tax_rate:.2f}.")

            elif command == "calculate_total":
                subtotal = cart.calculate_subtotal()
                total_discount = cart.calculate_discount_amount()
                tax_amount = cart.calculate_tax_amount()
                final_total = cart.calculate_final_total()

                print(f"Subtotal: {subtotal:.2f}")
                # Discounts are typically reductions, so print with a minus sign
                print(f"Discount: {-total_discount:.2f}")
                print(f"Tax: {tax_amount:.2f}")
                print(f"Total: {final_total:.2f}")

            else:
                print(f"Error: Unknown command '{command}'.")

        except ValueError as e:
            print(f"Error parsing arguments: {e} in command: {line}")
        except AttributeError as e:
            # This can happen if user's class methods are not implemented or named incorrectly
            print(f"Error: Method missing or invalid operation for Cart/DiscountStrategy: {e} in command: {line}")
        except TypeError as e:
             # This can happen if DiscountStrategy is not an ABC or its abstract methods
             # are not implemented correctly by concrete classes like PercentageDiscount/FixedDiscount.
             print(f"Error: Type mismatch or unimplemented method in user's classes: {e} in command: {line}")
        except Exception as e:
            print(f"An unexpected error occurred: {e} in command: {line}")

# Call the harness function at module level
run_harness()$harness$,
  test_cases   = '[{"input": "add Book 10.00 2\ncalculate_total", "description": "Basic cart total calculation with single item", "expected_output": "Added 2 x Book at 10.00 each.\nSubtotal: 20.00\nDiscount: 0.00\nTax: 0.00\nTotal: 20.00"}, {"input": "add Shirt 30.00 1\napply_discount percentage 10 STUDENT10\ncalculate_total", "description": "Percentage discount applied", "expected_output": "Added 1 x Shirt at 30.00 each.\nApplied Percentage discount ''STUDENT10''.\nSubtotal: 30.00\nDiscount: -3.00\nTax: 0.00\nTotal: 27.00"}, {"input": "add Laptop 1000.00 1\nadd Mouse 25.00 2\napply_discount percentage 10 BLACKFRIDAY\napply_discount fixed 50 VETERAN50\nset_tax 0.05\ncalculate_total", "description": "Multiple items, multiple discounts (percentage and fixed), and tax applied", "expected_output": "Added 1 x Laptop at 1000.00 each.\nAdded 2 x Mouse at 25.00 each.\nApplied Percentage discount ''BLACKFRIDAY''.\nApplied Fixed discount ''VETERAN50''.\nTax rate set to 0.05.\nSubtotal: 1050.00\nDiscount: -155.00\nTax: 44.75\nTotal: 939.75"}, {"input": "add ItemX 10.00 3\nremove ItemX 1\ncalculate_total", "description": "Remove a specific quantity of an item", "expected_output": "Added 3 x ItemX at 10.00 each.\nRemoved 1 x ItemX.\nSubtotal: 20.00\nDiscount: 0.00\nTax: 0.00\nTotal: 20.00"}, {"input": "add ItemY 5.00 2\nremove ItemY\ncalculate_total", "description": "Remove all quantity of an item", "expected_output": "Added 2 x ItemY at 5.00 each.\nRemoved 2 x ItemY.\nSubtotal: 0.00\nDiscount: 0.00\nTax: 0.00\nTotal: 0.00"}, {"input": "add ProductZ 100.00 1\napply_discount percentage 15 SUMMER15\nremove_discount SUMMER15\ncalculate_total", "description": "Apply and then remove a discount", "expected_output": "Added 1 x ProductZ at 100.00 each.\nApplied Percentage discount ''SUMMER15''.\nRemoved discount ''SUMMER15''.\nSubtotal: 100.00\nDiscount: 0.00\nTax: 0.00\nTotal: 100.00"}, {"input": "remove NonExistentItem\ncalculate_total", "description": "Attempt to remove a non-existent item", "expected_output": "Item ''NonExistentItem'' not found or no quantity removed.\nSubtotal: 0.00\nDiscount: 0.00\nTax: 0.00\nTotal: 0.00"}, {"input": "remove_discount NONEXISTENT\ncalculate_total", "description": "Attempt to remove a non-existent discount", "expected_output": "Discount ''NONEXISTENT'' not found.\nSubtotal: 0.00\nDiscount: 0.00\nTax: 0.00\nTotal: 0.00"}, {"input": "calculate_total", "description": "Calculate total for an empty cart", "expected_output": "Subtotal: 0.00\nDiscount: 0.00\nTax: 0.00\nTotal: 0.00"}]'::jsonb
WHERE id = 'oop_002';
