UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.HashMap;
import java.util.Map;
import java.util.List;
import java.util.ArrayList;
import java.util.Collections;
import java.util.Comparator;

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner scanner = new Scanner(System.in);
        // The user's Enrollment class is expected to have a no-arg constructor
        Enrollment enrollmentSystem = new Enrollment();

        while (scanner.hasNextLine()) {
            String line = scanner.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String[] parts = line.split(" ", 3); // Max 3 parts for most commands (e.g., COMMAND arg1 arg2)
            String command = parts[0];
            String result = "";

            try {
                switch (command) {
                    case "ADD_STUDENT":
                        if (parts.length < 2) {
                            result = "Error: ADD_STUDENT requires a name.";
                        } else {
                            result = enrollmentSystem.addStudent(parts[1]);
                        }
                        break;
                    case "ADD_COURSE":
                        if (parts.length < 3) {
                            result = "Error: ADD_COURSE requires a name and capacity.";
                        } else {
                            String courseName = parts[1];
                            int capacity = Integer.parseInt(parts[2]);
                            result = enrollmentSystem.addCourse(courseName, capacity);
                        }
                        break;
                    case "ENROLL":
                        if (parts.length < 3) {
                            result = "Error: ENROLL requires student name and course name.";
                        }
                         else {
                            result = enrollmentSystem.enrollStudentInCourse(parts[1], parts[2]);
                        }
                        break;
                    case "DROP":
                        if (parts.length < 3) {
                            result = "Error: DROP requires student name and course name.";
                        }
                         else {
                            result = enrollmentSystem.dropStudentFromCourse(parts[1], parts[2]);
                        }
                        break;
                    case "TRANSCRIPT":
                        if (parts.length < 2) {
                            result = "Error: TRANSCRIPT requires a student name.";
                        }
                         else {
                            result = enrollmentSystem.getTranscript(parts[1]);
                        }
                        break;
                    default:
                        result = "Error: Unknown command '" + command + "'";
                        break;
                }
            } catch (NumberFormatException e) {
                result = "Error: Invalid number format for capacity. " + e.getMessage();
            } catch (Exception e) { // Catch any unexpected exceptions from user code
                result = "Runtime Error: " + e.getClass().getSimpleName() + ": " + e.getMessage();
                // For debugging, you might uncomment the line below:
                // e.printStackTrace();
            }
            System.out.println(result);
        }
        scanner.close();
    }
