-- oop_004: Bank Account Hierarchy
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {
    const accounts: {
        savings?: SavingsAccount;
        checking?: CheckingAccount;
        investment?: InvestmentAccount;
    } = {};

    // Helper functions for precise monetary value handling with BigInt
    function parseAmount(amountStr: string): bigint {
        const parts = amountStr.split('.');
        let integerPart = BigInt(parts[0]);
        let fractionalPart = BigInt(0);
        if (parts.length > 1) {
            let fracStr = parts[1];
            if (fracStr.length > 2) { // Truncate extra decimals
                fracStr = fracStr.substring(0, 2);
            } else if (fracStr.length < 2) { // Pad missing decimals
                fracStr = fracStr.padEnd(2, '0');
            }
            fractionalPart = BigInt(fracStr);
        }
        return integerPart * 100n + fractionalPart;
    }

    function formatAmount(amount: bigint): string {
        const sign = amount < 0n ? "-" : "";
        const absAmount = amount < 0n ? -amount : amount;
        const dollars = absAmount / 100n;
        const cents = absAmount % 100n;
        return `${sign}${dollars}.${cents.toString().padStart(2, '0')}`;
    }

    for (const line of lines) {
        const parts = line.split(' ');
        const accountType = parts[0];
        const command = parts[1];
        const args = parts.slice(2);
        let output: string | undefined;

        // Initialize accounts if they don't exist
        if (accountType === 'savings' && !accounts.savings) accounts.savings = new SavingsAccount();
        if (accountType === 'checking' && !accounts.checking) accounts.checking = new CheckingAccount();
        if (accountType === 'investment' && !accounts.investment) accounts.investment = new InvestmentAccount();

        try {
            switch (accountType) {
                case 'savings': {
                    const account = accounts.savings!;
                    switch (command) {
                        case 'deposit': {
                            const amount = parseAmount(args[0]);
                            account.deposit(amount);
                            output = `Balance: ${formatAmount(account.getBalance())}`;
                            break;
                        }
                        case 'withdraw': {
                            const amount = parseAmount(args[0]);
                            account.withdraw(amount);
                            output = `Balance: ${formatAmount(account.getBalance())}`;
                            break;
                        }
                        case 'applyInterest': {
                            const rate = parseFloat(args[0]); // User code is expected to handle precision for rate
                            account.applyInterest(rate);
                            output = `Balance: ${formatAmount(account.getBalance())}`;
                            break;
                        }
                        case 'setWithdrawalLimit': {
                            const limit = parseInt(args[0], 10);
                            account.setWithdrawalLimit(limit);
                            break; // No explicit output for setting limits
                        }
                        case 'resetWithdrawalCount': {
                            account.resetWithdrawalCount();
                            break; // No explicit output
                        }
                        case 'getBalance': {
                            output = `Balance: ${formatAmount(account.getBalance())}`;
                            break;
                        }
                        default:
                            output = `Unknown command for SavingsAccount: ${command}`;
                    }
                    break;
                }
                case 'checking': {
                    const account = accounts.checking!;
                    switch (command) {
                        case 'deposit': {
                            const amount = parseAmount(args[0]);
                            account.deposit(amount);
                            output = `Balance: ${formatAmount(account.getBalance())}`;
                            break;
                        }
                        case 'withdraw': {
                            const amount = parseAmount(args[0]);
                            account.withdraw(amount);
                            output = `Balance: ${formatAmount(account.getBalance())}`;
                            break;
                        }
                        case 'setOverdraftLimit': {
                            const limit = parseAmount(args[0]);
                            account.setOverdraftLimit(limit);
                            break; // No explicit output
                        }
                        case 'getBalance': {
                            output = `Balance: ${formatAmount(account.getBalance())}`;
                            break;
                        }
                        default:
                            output = `Unknown command for CheckingAccount: ${command}`;
                    }
                    break;
                }
                case 'investment': {
                    const account = accounts.investment!;
                    switch (command) {
                        case 'deposit': {
                            const amount = parseAmount(args[0]);
                            account.deposit(amount);
                            output = `Balance: ${formatAmount(account.getBalance())}`;
                            break;
                        }
                        case 'withdraw': {
                            const amount = parseAmount(args[0]);
                            account.withdraw(amount);
                            output = `Balance: ${formatAmount(account.getBalance())}`;
                            break;
                        }
                        case 'buyAsset': {
                            const assetId = args[0];
                            const quantity = parseInt(args[1], 10);
                            const price = parseAmount(args[2]);
                            account.buyAsset(assetId, quantity, price);
                            output = `Balance: ${formatAmount(account.getBalance())}, Portfolio: ${formatAmount(account.getPortfolioValue())}`;
                            break;
                        }
                        case 'sellAsset': {
                            const assetId = args[0];
                            const quantity = parseInt(args[1], 10);
                            const price = parseAmount(args[2]);
                            account.sellAsset(assetId, quantity, price);
                            output = `Balance: ${formatAmount(account.getBalance())}, Portfolio: ${formatAmount(account.getPortfolioValue())}`;
                            break;
                        }
                        case 'getBalance': {
                            output = `Balance: ${formatAmount(account.getBalance())}`;
                            break;
                        }
                        case 'getPortfolioValue': {
                            output = `Portfolio: ${formatAmount(account.getPortfolioValue())}`;
                            break;
                        }
                        default:
                            output = `Unknown command for InvestmentAccount: ${command}`;
                    }
                    break;
                }
                default:
                    output = `Unknown account type: ${accountType}`;
            }
            if (output !== undefined) {
                console.log(output);
            }
        } catch (e: any) {
            console.log(e.message);
        }
    }
});$harness$,
  test_cases   = '[{"input": "savings deposit 500.00", "description": "Deposit into savings account", "expected_output": "Balance: 500.00"}, {"input": "savings deposit 500.00\nsavings withdraw 100.00", "description": "Withdraw from savings account", "expected_output": "Balance: 500.00\nBalance: 400.00"}, {"input": "checking deposit 100.00\nchecking setOverdraftLimit 150.00\nchecking withdraw 200.00", "description": "Checking account uses overdraft protection", "expected_output": "Balance: 100.00\nBalance: -100.00"}, {"input": "checking deposit 100.00\nchecking setOverdraftLimit 150.00\nchecking withdraw 300.00", "description": "Withdrawal beyond overdraft limit rejected", "expected_output": "Balance: 100.00\nOverdraft limit exceeded"}, {"input": "savings deposit 1000.00\nsavings applyInterest 0.05", "description": "Savings account earns interest", "expected_output": "Balance: 1000.00\nBalance: 1050.00"}, {"input": "savings deposit 500.00\nsavings setWithdrawalLimit 2\nsavings withdraw 100.00\nsavings withdraw 50.00\nsavings withdraw 20.00", "description": "Savings account limited withdrawals per month", "expected_output": "Balance: 500.00\nBalance: 400.00\nBalance: 350.00\nMonthly withdrawal limit exceeded"}, {"input": "savings deposit 500.00\nsavings setWithdrawalLimit 1\nsavings withdraw 100.00\nsavings withdraw 50.00\nsavings resetWithdrawalCount\nsavings withdraw 20.00", "description": "Savings account withdrawal limit resets", "expected_output": "Balance: 500.00\nBalance: 400.00\nMonthly withdrawal limit exceeded\nBalance: 380.00"}, {"input": "investment deposit 10000.00\ninvestment buy AAPL 10 150.00\ninvestment buy GOOG 5 200.00\ninvestment sell AAPL 5 160.00\ninvestment getBalance\ninvestment getPortfolioValue", "description": "Investment account buys and sells assets, tracks portfolio value", "expected_output": "Balance: 10000.00\nBalance: 8500.00, Portfolio: 1500.00\nBalance: 7500.00, Portfolio: 2500.00\nBalance: 8300.00, Portfolio: 1750.00\nBalance: 8300.00\nPortfolio: 1750.00"}, {"input": "savings deposit 123.45\nsavings withdraw 23.45\nsavings getBalance", "description": "Savings account handles precise monetary values", "expected_output": "Balance: 123.45\nBalance: 100.00\nBalance: 100.00"}, {"input": "checking deposit 50.00\nchecking withdraw 100.00\nchecking setOverdraftLimit 50.00\nchecking withdraw 10.00\nchecking getBalance", "description": "Checking account dynamically adjusts overdraft limit", "expected_output": "Balance: 50.00\nInsufficient funds\nBalance: 40.00\nBalance: 40.00"}]'::jsonb
