-- oop_005: Hospital Patient Management
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  const hospitalService = new Service(); // User's Service class

  for (const line of lines) {
    let result: string | undefined;

    if (line.startsWith('admit patient=')) {
      const patientDataStr = line.substring('admit patient='.length);
      const patientMatch = patientDataStr.match(/\{name: (.*?), age: (\d+), condition: (.*?)\}/);
      if (patientMatch) {
        const name = patientMatch[1];
        const age = parseInt(patientMatch[2]);
        const condition = patientMatch[3];
        result = hospitalService.admitPatient(name, age, condition);
      } else {
        result = `Invalid patient data format: ${patientDataStr}`;
      }
    } else if (line.startsWith('assign doctor=')) {
      const parts = line.substring('assign doctor='.length).split(', patient=');
      if (parts.length === 2) {
        const doctorName = parts[0].trim();
        const patientId = parts[1].trim();
        result = hospitalService.assignDoctorToPatient(doctorName, patientId);
      } else {
        result = `Invalid assign doctor command format: ${line}`;
      }
    } else if (line.startsWith('discharge patient=')) {
      const patientId = line.substring('discharge patient='.length).trim();
      result = hospitalService.dischargePatient(patientId);
    } else if (line.startsWith('get_patient_record id=')) {
