UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.HashMap;
import java.util.Map;

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        Service service = new Service(); // The user's Service class

        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String result = "";
            try {
                if (line.startsWith("add driver")) {
                    // Command format: add driver id=D001, name=Alice, location=10,10
                    Map<String, String> params = parseParams(line.substring("add driver".length()).trim());
                    String id = params.get("id");
                    String name = params.get("name");
                    String location = params.get("location");
                    result = service.addDriver(id, name, location);
                } else if (line.startsWith("add rider")) {
                    // Command format: add rider id=R001, name=Bob, location=12,12
                    Map<String, String> params = parseParams(line.substring("add rider".length()).trim());
                    String id = params.get("id");
                    String name = params.get("name");
                    String location = params.get("location");
                    result = service.addRider(id, name, location);
                } else if (line.startsWith("request ride")) {
                    // Command format: request ride ride=R001, from=Times Square, to=JFK, rider=R001
                    Map<String, String> params = parseParams(line.substring("request ride".length()).trim());
                    String rideId = params.get("ride");
                    String from = params.get("from");
                    String to = params.get("to");
                    String riderId = params.get("rider");
                    result = service.requestRide(rideId, riderId, from, to);
                } else if (line.contains("accept ride=")) {
                    // Command format: driver=D001 accept ride=R001
                    String[] parts = line.split(" accept ride=");
                    String driverPart = parts[0]; // e.g., driver=D001
                    String ridePart = parts[1];   // e.g., R001
                    String driverId = driverPart.substring("driver=".length());
                    String rideId = ridePart;
                    result = service.acceptRide(driverId, rideId);
                } else if (line.contains("complete, fare=")) {
                    // Command format: ride=R001 complete, fare=45.00
                    String[] parts = line.split(" complete, fare=");
                    String ridePart = parts[0]; // e.g., ride=R001
                    String farePart = parts[1]; // e.g., 45.00
                    String rideId = ridePart.substring("ride=".length());
                    double fare = Double.parseDouble(farePart);
                    result = service.completeRide(rideId, fare);
                } else if (line.startsWith("rate driver=")) {
                    // Command format: rate driver=D001, rating=5
                    String[] parts = line.split(", rating=");
                    String driverPart = parts[0]; // e.g., rate driver=D001
                    String ratingPart = parts[1]; // e.g., 5
                    String driverId = driverPart.substring("rate driver=".length());
                    int rating = Integer.parseInt(ratingPart);
                    result = service.rateDriver(driverId, rating);
                } else {
                    result = "Unknown command: " + line;
                }
            } catch (Exception e) {
                // In case of any error, print an error message
                result = "Error processing command '" + line + "': " + e.getMessage();
                // For debugging purposes, uncomment to print stack trace:
                // e.printStackTrace();
            }
            System.out.println(result);
        }
        sc.close();
    }

    /**
     * Helper method to parse "key=value, key2=value2" strings into a Map.
     * Assumes parameters are separated by ", " and key-value pairs by "=".
     */
    private static Map<String, String> parseParams(String paramString) {
        Map<String, String> params = new HashMap<>();
        if (paramString == null || paramString.isEmpty()) {
            return params;
        }
        // Split by ", " to handle multiple key=value pairs
        String[] pairs = paramString.split(", ");
        for (String pair : pairs) {
            // Split each pair by "=" to separate key and value
            String[] keyValue = pair.split("=", 2);
            if (keyValue.length == 2) { // Ensure it's a valid key=value pair
                params.put(keyValue[0].trim(), keyValue[1].trim());
            }
        }
        return params;
    }
