def run_harness():
    # The user's Service class will be instantiated to manage inventory.
    inventory_service = Service()

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        parts = line.split(' ', 1)
        command = parts[0]
        args_str = parts[1] if len(parts) > 1 else ''

        args = {}
        if args_str:
            for arg_pair in args_str.split(', '):
                if '=' in arg_pair:
                    key, value = arg_pair.split('=', 1)
                    args[key.strip()] = value.strip()
                # Assuming well-formed input as per challenge constraints.

        result = ""
        try:
            if command == "add_item":
                sku = args.get('sku')
                qty = args.get('qty')
                location = args.get('location')
                if not all([sku, qty, location]):
                    result = "Error: Missing arguments for add_item (sku, qty, location)."
                else:
                    # Expecting Service.add_item(sku: str, qty_str: str, location: str) -> str
                    result = inventory_service.add_item(sku, qty, location)
            elif command == "remove_item":
                sku = args.get('sku')
                qty = args.get('qty')
                if not all([sku, qty]):
                    result = "Error: Missing arguments for remove_item (sku, qty)."
                else:
                    # Expecting Service.remove_item(sku: str, qty_str: str) -> str
                    result = inventory_service.remove_item(sku, qty)
            elif command == "low_stock":
                threshold = args.get('threshold')
                if not threshold:
                    result = "Error: Missing threshold for low_stock."
                else:
                    # Expecting Service.low_stock_alerts(threshold_str: str) -> str
                    result = inventory_service.low_stock_alerts(threshold)
            elif command == "find_item":
                sku = args.get('sku')
                if not sku:
                    result = "Error: Missing sku for find_item."
                else:
                    # Expecting Service.find_item(sku: str) -> str
                    result = inventory_service.find_item(sku)
            else:
                result = f"Error: Unknown command '{command}'"
        except AttributeError as e:
            # Catches errors for missing methods if user hasn't implemented them yet
            result = f"Runtime Error: Method not found or accessible: {e}"
        except Exception as e:
            # Catch any other unexpected errors from the user's implementation
            result = f"Runtime Error: {type(e).__name__}: {e}"

        print(result)

# Call the harness function at module level as required
