const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // The user is expected to implement classes like Flight, Passenger, Booking, FlightService, BookingService,
  // and PassengerService, all inheriting from the provided Entity and Service base classes.
  // This harness relies on specific methods and properties being present in the user's implementation.

  // Initialize services. These will maintain the state of the system.
  const flightService = new FlightService();
  const passengerService = new PassengerService();
  const bookingService = new BookingService(flightService, passengerService);

  // Add initial flights to the system for testing purposes.
  // These flights are available for 'search' and 'book' commands.
  flightService.addFlight(new Flight("AA101", "NYC", "LAX", "2024-06-15", 150, 200));
  flightService.addFlight(new Flight("UA202", "NYC", "LAX", "2024-06-15", 100, 220));
  flightService.addFlight(new Flight("DL303", "NYC", "LAX", "2024-06-15", 120, 190));
  // Add a different flight that won't match the primary search criteria
  flightService.addFlight(new Flight("WN404", "LAX", "SFO", "2024-06-16", 80, 100));

  // Process each command line from stdin
  for (const line of lines) {
    const rawParts = line.split(' ');
    let command = rawParts[0];
    let paramsArray: string[] = [];

    // Special handling for multi-word commands like 'search flights'
    if (command === 'search' && rawParts.length > 1 && rawParts[1] === 'flights') {
      command = 'search flights';
      paramsArray = rawParts.slice(2); // Parameters start after 'search flights'
    } else {
      paramsArray = rawParts.slice(1); // Parameters start after the single-word command
    }

    const args: { [key: string]: string } = {};
    // Parse parameters, splitting by ',' first, then by '='
    paramsArray.forEach(paramToken => {
      // Split by comma to handle cases like 'to=LAX, date=...' or 'param1=val1,param2=val2'
      paramToken.split(',').forEach(subToken => {
        const trimmedToken = subToken.trim();
        if (trimmedToken) { // Ensure not an empty string from a trailing comma
          const [key, value] = trimmedToken.split('=').map(s => s.trim());
          if (key && value) {
            args[key] = value;
          }
        }
      });
    });

    switch (command) {
      case 'search flights':
        const from = args['from'];
        const to = args['to'];
        const date = args['date'];
        if (from && to && date) {
          const foundFlights = flightService.searchFlights(from, to, date);
          if (foundFlights.length > 0) {
            console.log(`${foundFlights.length} flights found: ${foundFlights.map(f => f.getId()).join(', ')}`);
          } else {
            console.log("No flights found.");
          }
        } else {
          console.log("Error: Missing 'from', 'to', or 'date' parameters for search flights.");
        }
        break;

      case 'book':
        const flightIdToBook = args['flight'];
        const passengerName = args['passenger'];
        const seatNumber = args['seat'];
        if (flightIdToBook && passengerName && seatNumber) {
          const booking = bookingService.bookFlight(flightIdToBook, passengerName, seatNumber);
          if (booking) {
            // Expected output includes the generated booking ID (e.g., BK001)
            console.log(`Booking ${booking.getId()} confirmed: ${booking.getFlightId()} seat ${booking.getSeatNumber()} for ${passengerName}`);
          } else {
            console.log(`Booking failed for flight ${flightIdToBook}, passenger ${passengerName}, seat ${seatNumber}.`);
          }
        } else {
          console.log("Error: Missing 'flight', 'passenger', or 'seat' parameters for book command.");
        }
        break;

      case 'cancel':
        const bookingIdToCancel = args['booking'];
        if (bookingIdToCancel) {
          const cancelled = bookingService.cancelBooking(bookingIdToCancel);
          if (cancelled) {
            console.log(`Booking ${bookingIdToCancel} cancelled, refund processed`);
          } else {
            console.log(`Failed to cancel booking ${bookingIdToCancel}. It might be already cancelled or not found.`);
          }
        } else {
          console.log("Error: Missing 'booking' ID for cancel command.");
        }
        break;

      case 'get_booking':
        const bookingIdToGet = args['id'];
        if (bookingIdToGet) {
          const booking = bookingService.getBooking(bookingIdToGet);
          if (booking) {
            console.log(`Booking ${booking.getId()}: ${booking.getStatus()}`);
          } else {
            console.log(`Booking ${bookingIdToGet} not found.`);
          }
        } else {
          console.log("Error: Missing 'id' for get_booking command.");
        }
        break;

      default:
        console.log(`Unknown command: ${line}`);
        break;
    }
  }
});$harness$,
