UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.Map;
import java.util.HashMap;
import java.time.LocalDate;
import java.time.format.DateTimeParseException;

public class Main {

    public static void main(String[] args) throws Exception {
        Scanner scanner = new Scanner(System.in);
        Service hotelService = new Service(); // Instantiate the user's Service class

        while (scanner.hasNextLine()) {
            String line = scanner.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            // Parse command and arguments
            String[] parts = line.split(" ", 2);
            String command = parts[0];
            Map<String, String> params = new HashMap<>();
            if (parts.length > 1) {
                String[] paramPairs = parts[1].split(", ");
                for (String pair : paramPairs) {
                    String[] kv = pair.split("=", 2);
                    if (kv.length == 2) {
                        params.put(kv[0].trim(), kv[1].trim());
                    }
                }
            }

            String result = "";
            try {
                switch (command) {
                    case "add_hotel":
                        String hotelName = params.get("name");
                        if (hotelName != null) {
                            result = hotelService.addHotel(hotelName);
                        } else {
                            result = "Error: Missing hotel name for add_hotel command.";
                        }
                        break;

                    case "add_room":
                        hotelName = params.get("hotel");
                        String roomType = params.get("type");
                        String roomNumber = params.get("number");
                        String rateStr = params.get("rate");
                        if (hotelName != null && roomType != null && roomNumber != null && rateStr != null) {
                             double rate = Double.parseDouble(rateStr);
                             result = hotelService.addRoom(hotelName, roomType, roomNumber, rate);
                        } else {
                            result = "Error: Missing room details (hotel, type, number, or rate) for add_room command.";
                        }
                        break;

                    case "check_availability":
                        hotelName = params.get("hotel");
                        String checkInStr = params.get("check_in");
                        String checkOutStr = params.get("check_out");
                        roomType = params.get("type");
                        if (hotelName != null && checkInStr != null && checkOutStr != null && roomType != null) {
                            result = hotelService.checkAvailability(hotelName, checkInStr, checkOutStr, roomType);
                        } else {
                            result = "Error: Missing availability details (hotel, check_in, check_out, or type) for check_availability command.";
                        }
                        break;

                    case "book":
                        hotelName = params.get("hotel");
                        roomType = params.get("room_type"); 
                        String guestName = params.get("guest");
                        checkInStr = params.get("check_in");
                        checkOutStr = params.get("check_out");

                        if (hotelName != null && roomType != null && guestName != null && checkInStr != null && checkOutStr != null) {
                             result = hotelService.bookRoom(hotelName, roomType, guestName, checkInStr, checkOutStr);
                        } else {
                            result = "Error: Missing booking details (hotel, room_type, guest, check_in, or check_out) for book command.";
                        }
                        break;

                    case "cancel":
                        String bookingId = params.get("booking");
                        if (bookingId != null) {
                            result = hotelService.cancelBooking(bookingId);
                        } else {
                            result = "Error: Missing booking ID for cancel command.";
                        }
                        break;

                    case "get_bill":
                        bookingId = params.get("booking");
                        if (bookingId != null) {
                            result = hotelService.getBill(bookingId);
                        } else {
                            result = "Error: Missing booking ID for get_bill command.";
                        }
                        break;

                    default:
                        result = "Unknown command: " + command;
                        break;
                }
            } catch (NumberFormatException e) {
                result = "Error: Invalid number format in command - " + e.getMessage();
            } catch (DateTimeParseException e) {
                result = "Error: Invalid date format in command - " + e.getMessage();
            } catch (Exception e) {
                result = "An unexpected error occurred: " + e.getClass().getSimpleName() + ": " + e.getMessage();
                // For debugging during development, uncomment below:
                // e.printStackTrace();
            }
            System.out.println(result);
        }
        scanner.close();
