UPDATE challenges SET
  test_harness = $harness$import sys

def run_harness():
    # Instantiate the user's Service class once to maintain state
    auction_service = Service()

    # Helper function to parse arguments from the command string
    def parse_args(args_str):
        args = {}
        if args_str:
            # Split by comma and space, then by the first '=' to handle potential values with '='
            pairs = args_str.split(', ')
            for pair in pairs:
                if '=' in pair:
                    key, value = pair.split('=', 1)
                    args[key.strip()] = value.strip()
        return args

    # Read commands from stdin line by line
    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue # Skip empty lines

        # Parse the command and its arguments
        parts = line.split(' ', 1)
        command = parts[0]
        args_str = parts[1] if len(parts) > 1 else ''
        args = parse_args(args_str)

        output = ""
        try:
            # Execute commands based on the parsed input
            if command == "create_auction":
                item = args.get('item')
                start_price = int(args.get('start_price'))
                output = auction_service.create_auction(item, start_price)
            elif command == "place_bid":
                user = args.get('user')
                amount = int(args.get('amount'))
                output = auction_service.place_bid(user, amount)
            elif command == "close_auction":
                output = auction_service.close_auction()
            else:
                output = f"Error: Unknown command '{command}'"
        except Exception as e:
            # Catch any exceptions from user's code and report them
            output = f"Error executing command '{command}': {e}"
        
        # Print the result of each command to stdout
        print(output)

