  lines.push(line.trim());
});

rl.on('close', () => {
  // The user is expected to define a 'PrescriptionManager' class
  // that extends 'Service' and handles the core logic.
  // This manager should internally handle patient, drug, and prescription entities,
  // including generating sequential IDs (e.g., RX001, P001, D001).
  const manager: PrescriptionManager = new PrescriptionManager();

  for (const line of lines) {
    if (!line) continue;

    const parts = line.split(' ');
    const command = parts[0];
    const params: { [key: string]: string } = {};

    if (parts.length > 1) {
      parts[1].split(',').forEach(p => {
        const [key, value] = p.trim().split('=');
        if (key && value) {
          params[key.trim()] = value.trim();
        }
      });
    }

    let output: string = '';

    switch (command) {
      case 'add_prescription': {
        const patientName = params['patient'];
        const drugName = params['drug'];
        const dosage = params['dosage'];
        output = manager.addPrescription(patientName, drugName, dosage);
        break;
      }
      case 'dispense': {
        const prescriptionId = params['prescription'];
        output = manager.dispensePrescription(prescriptionId);
        break;
      }
      case 'check_interactions': {
        const drug1 = params['drug1'];
        const drug2 = params['drug2'];
        output = manager.checkInteractions(drug1, drug2);
        break;
      }
      case 'refill': {
        const prescriptionId = params['prescription'];
        output = manager.refillPrescription(prescriptionId);
        break;
      }
      // Add more cases here if more commands are introduced later
      default:
        output = `Error: Unknown command - ${command}`;
        break;
    }
    console.log(output);
  }
