UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.Map;
import java.util.HashMap;

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        // Assuming 'Service' is the main class for business logic
        Service gymService = new Service(); 

        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String[] parts = line.split(" ", 2);
            String command = parts[0];
            Map<String, String> params = new HashMap<>();

            if (parts.length > 1) {
                String argString = parts[1];
                String[] argPairs = argString.split(", ");

                for (String pair : argPairs) {
                    String[] kv = pair.split("=", 2);
                    if (kv.length == 2) {
                        String key = kv[0].trim();
                        String value = kv[1].trim();

                        // Special handling for the 'register' command's member={...} structure
                        // This extracts name and plan directly into the params map
                        if (key.equals("member") && value.startsWith("{") && value.endsWith("}")) {
                            String innerContent = value.substring(1, value.length() - 1); // remove {} brackets
                            String[] innerPairs = innerContent.split(", ");
                            for (String innerPair : innerPairs) {
                                String[] innerKv = innerPair.split(": ", 2);
                                if (innerKv.length == 2) {
                                    params.put(innerKv[0].trim(), innerKv[1].trim());
                                }
                            }
                        } else {
                            params.put(key, value);
                        }
                    }
                }
            }

            String result = "";
            switch (command) {
                case "register":
                    String name = params.get("name");
                    String plan = params.get("plan");
                    if (name != null && plan != null) {
                        // Assumes the Service class has a method: public String registerMember(String name, String plan)
                        result = gymService.registerMember(name, plan);
                    } else {
                        result = "Error: Missing name or plan for register command.";
                    }
                    break;
                case "check_in":
                    String memberIdCheckIn = params.get("member");
                    if (memberIdCheckIn != null) {
                        // Assumes the Service class has a method: public String checkInMember(String memberId)
                        result = gymService.checkInMember(memberIdCheckIn);
                    } else {
                        result = "Error: Missing member ID for check_in command.";
                    }
                    break;
                case "upgrade_plan":
                    String memberIdUpgrade = params.get("member");
                    String newPlan = params.get("plan");
                    if (memberIdUpgrade != null && newPlan != null) {
                        // Assumes the Service class has a method: public String upgradePlan(String memberId, String newPlan)
                        result = gymService.upgradePlan(memberIdUpgrade, newPlan);
                    } else {
                        result = "Error: Missing member ID or plan for upgrade_plan command.";
                    }
                    break;
                case "cancel_membership":
                    String memberIdCancel = params.get("member");
                    if (memberIdCancel != null) {
                        // Assumes the Service class has a method: public String cancelMembership(String memberId)
                        result = gymService.cancelMembership(memberIdCancel);
                    } else {
                        result = "Error: Missing member ID for cancel_membership command.";
                    }
                    break;
                default:
                    result = "Error: Unknown command '" + command + "'";
                    break;
            }
            System.out.println(result);
        }
        sc.close();
    }
