-- oop_013: Restaurant Order Management
UPDATE challenges SET
  test_harness = $harness$import sys

# Global state for the harness
restaurant_service = None
order_id_registry = {} # Maps symbolic ID (e.g., "O001") to actual ID returned by service
next_symbolic_order_num = 1

def parse_args(args_str):
    args = {}
    if not args_str:
        return args
    for part in args_str.split(', '):
        key, value = part.split('=', 1)
        if key == 'items':
            # Parse [item1, item2, ...]
            items_list_str = value.strip('[]')
            if items_list_str:
                args[key] = [item.strip() for item in items_list_str.split(',')]
            else:
                args[key] = []
        elif key in ['table']:
            args[key] = int(value)
        else: # 'order' ID, other strings
            args[key] = value.strip() # Remove any leading/trailing whitespace
    return args

def run_harness():
    global restaurant_service, next_symbolic_order_num

    restaurant_service = Service() # Instantiate the user's Service class

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        command_parts = line.split(' ', 1)
        command_name = command_parts[0]
        args_str = command_parts[1] if len(command_parts) > 1 else ''
        args = parse_args(args_str)

        output_to_print = None

        try:
            if command_name == 'place_order':
                table = args.get('table')
                items = args.get('items', [])
                if table is None:
                    raise ValueError("Table number missing for place_order")

                # The place_order method is expected to return a tuple:
                # (display_string, actual_order_id_object_or_string)
                # The user's Service implementation should return a string for printing
                # and an actual ID/object for internal tracking.
                result = restaurant_service.place_order(table, items)
                if not isinstance(result, tuple) or len(result) != 2:
                    raise TypeError("place_order method must return a tuple (display_string, actual_order_id)")

                display_string, actual_order_id = result

                symbolic_id = f"O{next_symbolic_order_num:03d}"
                order_id_registry[symbolic_id] = actual_order_id
                next_symbolic_order_num += 1
                output_to_print = display_string

            elif command_name == 'mark_ready':
                symbolic_order_id = args.get('order')
                if symbolic_order_id not in order_id_registry:
                    raise ValueError(f"Unknown order ID: {symbolic_order_id}")
                actual_order_id = order_id_registry[symbolic_order_id]

                # mark_ready is expected to return the display string directly
                output_to_print = restaurant_service.mark_ready(actual_order_id)

            elif command_name == 'deliver':
                symbolic_order_id = args.get('order')
                table = args.get('table')
                if symbolic_order_id not in order_id_registry:
                    raise ValueError(f"Unknown order ID: {symbolic_order_id}")
                if table is None:
                    raise ValueError("Table number missing for deliver")
                actual_order_id = order_id_registry[symbolic_order_id]

                # deliver is expected to return the display string directly
                output_to_print = restaurant_service.deliver(actual_order_id, table)

            elif command_name == 'get_bill':
                table = args.get('table')
                if table is None:
                    raise ValueError("Table number missing for get_bill")

                # get_bill is expected to return the display string directly
                output_to_print = restaurant_service.get_bill(table)

            else:
                output_to_print = f"Error: Unknown command '{command_name}'"

        except Exception as e:
            # Catch any exception from user code or harness logic
            output_to_print = f"Error: {e}"

        if output_to_print is not None:
            print(output_to_print)

# Call the harness function at module level
