UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin
});

const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', () => {
  // The user's 'Service' class is expected to be available in scope.
  // We assume the user will define a Service class with the expected methods.
  const fleetService = new Service(); 

  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    const parts = line.split(' ');
    const command = parts[0];
    const argsString = parts.slice(1).join(' ');

    const args: { [key: string]: string } = {};
    // Split by comma first, then by equals. Handle potential multiple spaces.
    argsString.split(',').forEach(argPair => {
      const trimmedArgPair = argPair.trim();
      if (trimmedArgPair) {
        const [key, value] = trimmedArgPair.split('=');
        if (key && value !== undefined) {
          args[key.trim()] = value.trim();
        }
      }
    });

    let output: string | undefined;

    try {
      switch (command) {
        case 'add_vehicle':
          // Expected: fleetService.addVehicle(id: string, type: string, driver: string) => string
          if ('addVehicle' in fleetService && typeof fleetService.addVehicle === 'function') {
            output = fleetService.addVehicle(args.id, args.type, args.driver);
          } else {
            output = `Error: 'addVehicle' method not found or not a function on Service.`;
          }
          break;
        case 'update_location':
          // Expected: fleetService.updateVehicleLocation(vehicleId: string, lat: number, lon: number) => string
          if ('updateVehicleLocation' in fleetService && typeof fleetService.updateVehicleLocation === 'function') {
            const lat = parseFloat(args.lat);
            const lon = parseFloat(args.lon);
            if (!isNaN(lat) && !isNaN(lon)) {
              output = fleetService.updateVehicleLocation(args.vehicle, lat, lon);
            } else {
              output = `Error: Invalid lat/lon provided for update_location.`;
            }
          } else {
            output = `Error: 'updateVehicleLocation' method not found or not a function on Service.`;
          }
          break;
        case 'get_fleet_status':
          // Expected: fleetService.getFleetStatus(): string
          if ('getFleetStatus' in fleetService && typeof fleetService.getFleetStatus === 'function') {
            output = fleetService.getFleetStatus();
          } else {
            output = `Error: 'getFleetStatus' method not found or not a function on Service.`;
          }
          break;
        case 'assign_job':
          // Expected: fleetService.assignJob(vehicleId: string, destination: string) => string
          if ('assignJob' in fleetService && typeof fleetService.assignJob === 'function') {
            output = fleetService.assignJob(args.vehicle, args.destination);
          } else {
            output = `Error: 'assignJob' method not found or not a function on Service.`;
          }
          break;
        default:
          output = `Unknown command: ${command}`;
          break;
      }
    } catch (e: any) {
      // Catch potential errors in user's implementation to provide clearer feedback
      output = `Runtime Error: ${e.message || e}`;
    }
    
    if (output !== undefined) {
      console.log(output);
    }
