UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.Map;
import java.util.HashMap;

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner scanner = new Scanner(System.in);
        // The user's Service class is expected to contain the business logic
        Service gradeBookService = new Service(); 

        while (scanner.hasNextLine()) {
            String line = scanner.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }
            processCommand(gradeBookService, line);
        }
        scanner.close();
    }

    private static void processCommand(Service service, String commandLine) {
        String[] parts = commandLine.split(" ", 2);
        String command = parts[0];
        Map<String, String> params = new HashMap<>();

        if (parts.length > 1) {
            String[] paramPairs = parts[1].split(", ");
            for (String pair : paramPairs) {
                String[] keyValue = pair.split("=", 2);
                if (keyValue.length == 2) {
                    params.put(keyValue[0].trim(), keyValue[1].trim());
                }
            }
        }

        String result = "";
        try {
            switch (command) {
                case "add_student":
                    String name = params.get("name");
                    int grade = Integer.parseInt(params.get("grade"));
                    result = service.addStudent(name, grade);
                    break;
                case "record_score":
                    String studentName = params.get("student");
                    String subjectName = params.get("subject");
                    double score = Double.parseDouble(params.get("score"));
                    result = service.recordScore(studentName, subjectName, score);
                    break;
                case "get_gpa":
                    String gpaStudentName = params.get("student");
                    result = service.getGPA(gpaStudentName);
                    break;
                case "get_class_average":
                    String avgSubjectName = params.get("subject");
                    result = service.getClassAverage(avgSubjectName);
                    break;
                default:
                    result = "Unknown command: " + command;
                    break;
            }
        } catch (NumberFormatException e) {
            result = "Error: Invalid number format for a parameter in command '" + command + "'. Details: " + e.getMessage();
        } catch (NullPointerException e) {
            result = "Error: Missing expected parameter for command '" + command + "'. Details: " + e.getMessage();
        } catch (Exception e) {
            // Catch any other unexpected exceptions from user's code
            result = "An unexpected error occurred during command '" + command + "': " + e.getMessage();
        }
        System.out.println(result);
    }
}$harness$,
