UPDATE challenges SET
  test_harness = $harness$import sys

def run_harness():
    # Instantiate the user's Service class once to maintain state
    cr4ck_service = Service()
    post_id_counter = 0 # Counter for generating unique post IDs like P001, P002

    # Read commands from stdin line by line
    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        # Parse command and arguments
        parts = line.split(' ', 1)
        command = parts[0]
        args_str = parts[1] if len(parts) > 1 else ""

        args = {}
        # Parse arguments like "key=value, key2=value2"
        for arg_pair in args_str.split(', '):
            if '=' in arg_pair:
                key, value = arg_pair.split('=', 1)
                args[key.strip()] = value.strip()

        output = ""
        try:
            if command == "post":
                post_id_counter += 1
                post_id = f"P{post_id_counter:03d}" # Format as P001, P002, etc.
                author = args.get('author')
                content = args.get('content')
                if author is None or content is None:
                    output = "Error: 'post' command requires 'author' and 'content'."
                else:
                    # Assuming Service.create_post method exists and returns the formatted string
                    output = cr4ck_service.create_post(post_id, author, content)
            elif command == "follow":
                user_to_follow = args.get('user')
                follower = args.get('follower')
                if user_to_follow is None or follower is None:
                    output = "Error: 'follow' command requires 'user' and 'follower'."
                else:
                    # Assuming Service.follow method exists and returns the formatted string
                    output = cr4ck_service.follow(user_to_follow, follower)
            elif command == "get_feed":
                user = args.get('user')
                if user is None:
                    output = "Error: 'get_feed' command requires 'user'."
                else:
                    # Assuming Service.get_feed method exists and returns the formatted string
                    output = cr4ck_service.get_feed(user)
            elif command == "like":
                post_id = args.get('post')
                user = args.get('user')
                if post_id is None or user is None:
                    output = "Error: 'like' command requires 'post' and 'user'."
                else:
                    # Assuming Service.like_post method exists and returns the formatted string
                    output = cr4ck_service.like_post(post_id, user)
            else:
                output = f"Unknown command: {command}"
        except Exception as e:
            # Catch any exceptions from user code for robust testing
            output = f"Runtime Error processing command '{line}': {e}"

        # Print the result of each command
        print(output)

# Call the harness function at module level
