  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {
    // The user's classes (Entity, Service, and their concrete implementations like
    // Property, Agent, ListingService) are available in this scope.

    // Initialize the main service instance.
    // It's assumed the user implements a class named 'ListingService' that
    // extends 'Service' and has the expected methods.
    let listingService: any; // Use 'any' to avoid strict type checking on user's undefined classes
    try {
        // This 'new ListingService()' assumes the user has defined a class named ListingService
        // and it's a valid class that can be instantiated.
        // If the user's solution does not have a class named ListingService, this will fail.
        listingService = new (global as any).ListingService(); 
    } catch (e: any) {
        console.error(`Error initializing ListingService: ${e.message}. Ensure 'ListingService' class is defined and extends 'Service'.`);
        return;
    }

    // Helper to parse key=value arguments from command strings
    const parseArgs = (argString: string): Record<string, string> => {
        const args: Record<string, string> = {};
        argString.split(',').forEach(part => {
            const [key, value] = part.split('=').map(s => s.trim());
            if (key && value) {
                args[key] = value;
            }
        });
        return args;
    };

    for (const line of lines) {
        if (!line) continue;

        const parts = line.split(' ');
        const command = parts[0];
        const argString = parts.slice(1).join(' '); // The rest is the argument string

        let output = '';

        try {
            switch (command) {
                case 'list_property': {
                    const args = parseArgs(argString);
                    const address = args['address'];
                    const priceStr = args['price'];
                    const type = args['type'];

                    if (!address || !priceStr || !type) {
                        output = `Error: Missing arguments for list_property. Expected: address, price, type.`;
                        break;
                    }
                    const price = parseFloat(priceStr);
                    if (isNaN(price)) {
                         output = `Error: Invalid price for list_property. Price must be a number.`;
                         break;
                    }

                    // Assumed method signature: listProperty(address: string, price: number, type: string): Property
                    // Assumed Property object has .address, .price, .type properties for display
                    const listedProperty = listingService.listProperty(address, price, type);
                    output = `Property listed: ${listedProperty.address}, $${listedProperty.price.toLocaleString()} ${listedProperty.type}`;
                    break;
                }
                case 'search': {
                    const args = parseArgs(argString);
                    const type = args['type'];
                    const maxPriceStr = args['max_price'];
                    let maxPrice: number | undefined = undefined;

                    if (maxPriceStr !== undefined) {
                        maxPrice = parseFloat(maxPriceStr);
                        if (isNaN(maxPrice)) {
                            output = `Error: Invalid max_price for search. Max price must be a number.`;
                            break;
                        }
                    }

                    // Assumed method signature: searchProperties(criteria: { type?: string, maxPrice?: number }): Property[]
                    // Property objects are assumed to have .address and .price for display
                    const results = listingService.searchProperties({ type, maxPrice });

                    if (results.length === 0) {
                        output = "0 results.";
                    } else {
                        const formattedResults = results
                            .map((p: any) => `${p.address}, $${p.price.toLocaleString()}`)
                            .join(', ');
                        const resultWord = results.length === 1 ? 'result' : 'results';
                        output = `${results.length} ${resultWord}: ${formattedResults}`;
                    }
                    break;
                }
                case 'contact': {
                    const args = parseArgs(argString);
                    const agentId = args['agent'];
                    const propertyId = args['property']; // This is assumed to be the property's address
                    if (!agentId || !propertyId) {
                        output = `Error: Missing arguments for contact. Expected: agent, property.`;
                        break;
                    }
                    // Assumed method signature: contactAgent(agentId: string, propertyId: string): string
                    // Method should return the confirmation string for output
                    output = listingService.contactAgent(agentId, propertyId);
                    break;
                }
                case 'mark_sold': {
                    const args = parseArgs(argString);
                    const propertyId = args['property']; // This is assumed to be the property's address
                    if (!propertyId) {
                        output = `Error: Missing arguments for mark_sold. Expected: property.`;
                        break;
                    }
                    // Assumed method signature: markPropertySold(propertyId: string): string
                    // Method should return the confirmation string for output
                    output = listingService.markPropertySold(propertyId);
                    break;
                }
                default:
                    output = `Error: Unknown command '${command}'`;
                    break;
            }
        } catch (e: any) {
            // Catch errors thrown by the user's implementation methods
            output = `Error executing command '${command}': ${e.message}`;
        }
        console.log(output);
    }
});$harness$,
