  test_harness = $harness$import java.util.Scanner;
import java.util.HashMap;
import java.util.Map;

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        Service musicCatalogService = new Service(); // User's main service class

        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String[] parts = line.split(" ", 2);
            String command = parts[0];
            String argsStr = parts.length > 1 ? parts[1] : "";

            Map<String, String> params = new HashMap<>();
            if (!argsStr.isEmpty()) {
                String[] argPairs = argsStr.split(", ");
                for (String pair : argPairs) {
                    String[] kv = pair.split("=", 2);
                    if (kv.length == 2) {
                        params.put(kv[0].trim(), kv[1].trim());
                    }
                }
            }

            String result = "";
            try {
                switch (command) {
                    case "add_artist":
                        result = musicCatalogService.addArtist(params.get("name"));
                        break;
                    case "add_album":
                        result = musicCatalogService.addAlbum(params.get("title"), params.get("artist"), Integer.parseInt(params.get("year")));
                        break;
                    case "add_song":
                        result = musicCatalogService.addSong(params.get("title"), params.get("artist"), params.get("album"), Integer.parseInt(params.get("duration")));
                        break;
                    case "create_playlist":
                        result = musicCatalogService.createPlaylist(params.get("name"));
                        break;
                    case "search":
                        String searchType = "";
                        String searchQuery = "";
                        if (params.containsKey("artist")) {
                            searchType = "artist";
                            searchQuery = params.get("artist");
                        } else if (params.containsKey("song")) {
                            searchType = "song";
                            searchQuery = params.get("song");
                        } else if (params.containsKey("album")) {
                            searchType = "album";
                            searchQuery = params.get("album");
                        } else {
                            // Default or error handling if no specific type is given, to prevent NPE in user's method
                            searchType = "";
                            searchQuery = "";
                        }
                        result = musicCatalogService.search(searchType, searchQuery);
                        break;
                    case "play":
                        result = musicCatalogService.playSong(params.get("song"));
                        break;
                    case "add_to_playlist":
                        result = musicCatalogService.addToPlaylist(params.get("song"), params.get("playlist"));
                        break;
                    case "get_recommendations":
                        String recommendationType = "";
                        String recommendationQuery = "";
                        String basedOnParam = params.get("based_on");
                        if (basedOnParam != null) {
                            String[] basedOnParts = basedOnParam.split("=", 2);
                            if (basedOnParts.length == 2) {
                                recommendationType = basedOnParts[0].trim();
                                recommendationQuery = basedOnParts[1].trim();
                            } else {
                                // Default to 'song' if only a value is provided (e.g., 'Come Together')
                                recommendationType = "song"; 
                                recommendationQuery = basedOnParam;
                            }
                        }
                        result = musicCatalogService.getRecommendations(recommendationType, recommendationQuery);
                        break;
                    default:
                        result = "Error: Unknown command: " + command;
                }
            } catch (Exception e) {
                // Catch any exceptions from user's methods for better error reporting
                result = "Error executing command '" + command + "': " + e.getMessage();
            }
            
            if (result != null && !result.isEmpty()) {
                System.out.println(result);
            }
        }
        sc.close();
    }
