-- oop_019: Insurance Policy Manager
UPDATE challenges SET
  test_harness = $harness$import sys

class Cr4ckHarness:
    def __init__(self):
        # The user's Service class is expected to be defined
        # above this harness code and will be instantiated here.
        self.service = Service()

    def parse_command(self, line):
        line = line.strip()
        if not line:
            return None, {}

        parts = line.split(' ', 1)
        command = parts[0]
        args = {}

        if len(parts) > 1:
            arg_str = parts[1]
            # Split by comma for multiple arguments, then by equals for key-value
            for arg_pair in arg_str.split(','):
                arg_pair = arg_pair.strip()
                if '=' in arg_pair:
                    key, value = arg_pair.split('=', 1)
                    args[key.strip()] = value.strip()
        return command, args

    def execute_command(self, command, args):
        result = None
        try:
            if command == "create_policy":
                policy_type = args.get('type')
                holder = args.get('holder')
                premium = int(args.get('premium'))
                # Assumes Service has a create_policy method
                result = self.service.create_policy(policy_type, holder, premium)
            elif command == "file_claim":
                policy_id = args.get('policy')
                amount = int(args.get('amount'))
                # Assumes Service has a file_claim method
                result = self.service.file_claim(policy_id, amount)
            elif command == "approve_claim":
                claim_id = args.get('claim')
                # Assumes Service has an approve_claim method
                result = self.service.approve_claim(claim_id)
            elif command == "renew_policy":
                policy_id = args.get('policy')
                # Assumes Service has a renew_policy method
                result = self.service.renew_policy(policy_id)
            # Extend with more commands as the challenge requires
        except Exception as e:
            # Print a consistent error message if user's code fails
            result = f"Error executing command '{command}': {e}"
        return result

def run_harness():
    harness = Cr4ckHarness()
    for line in sys.stdin:
        command, args = harness.parse_command(line)
        if command: # Only execute if a valid command was parsed
            output = harness.execute_command(command, args)
            if output is not None:
                print(output)

# Call the harness function at module level as required
run_harness()$harness$,
  test_cases   = '[{"input": "create_policy type=auto, holder=Alice, premium=1200", "description": "Create a basic auto policy", "expected_output": "Auto policy created for Alice at $1200/year"}, {"input": "create_policy type=home, holder=Bob, premium=2500", "description": "Create a basic home policy (polymorphism test, assumes different policy types)", "expected_output": "Home policy created for Bob at $2500/year"}, {"input": "create_policy type=auto, holder=Alice, premium=1200\nfile_claim policy=POL001, amount=500", "description": "File a claim on an existing policy (POL001)", "expected_output": "Auto policy created for Alice at $1200/year\nClaim filed on POL001 for $500"}, {"input": "create_policy type=auto, holder=Alice, premium=1200\nfile_claim policy=POL001, amount=500\napprove_claim claim=CLM001", "description": "Approve an existing claim (CLM001)", "expected_output": "Auto policy created for Alice at $1200/year\nClaim filed on POL001 for $500\nClaim CLM001 approved, payout $500"}, {"input": "create_policy type=auto, holder=Alice, premium=1200\nrenew_policy policy=POL001", "description": "Renew an existing policy (POL001)", "expected_output": "Auto policy created for Alice at $1200/year\nPolicy POL001 renewed for another year"}, {"input": "create_policy type=auto, holder=Alice, premium=1200\ncreate_policy type=home, holder=Bob, premium=2500\nfile_claim policy=POL001, amount=750\nfile_claim policy=POL002, amount=1500\napprove_claim claim=CLM001\napprove_claim claim=CLM002\nrenew_policy policy=POL001\nrenew_policy policy=POL002", "description": "Complex scenario with multiple policies, claims, approvals, and renewals", "expected_output": "Auto policy created for Alice at $1200/year\nHome policy created for Bob at $2500/year\nClaim filed on POL001 for $750\nClaim filed on POL002 for $1500\nClaim CLM001 approved, payout $750\nClaim CLM002 approved, payout $1500\nPolicy POL001 renewed for another year\nPolicy POL002 renewed for another year"}, {"input": "create_policy type=auto, holder=Charlie, premium=900\nfile_claim policy=POL003, amount=300\napprove_claim claim=CLM003", "description": "Another sequence of create, file, approve (ensuring ID generation continues)", "expected_output": "Auto policy created for Charlie at $900/year\nClaim filed on POL003 for $300\nClaim CLM003 approved, payout $300"}]'::jsonb
