-- oop_020: Parking Lot Management System
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
    // Instantiate the main service class here, assuming it's the entry point
    // for the parking lot management system.
    let serviceInstance: Service | null = null;
    const output: string[] = [];

    // Helper to parse key=value pairs from a command string
    const parseParams = (paramString: string): { [key: string]: string } => {
        const params: { [key: string]: string } = {};
        paramString.split(',').forEach(pair => {
            const [key, value] = pair.trim().split('=');
            if (key && value) {
                params[key.trim()] = value.trim();
            }
        });
        return params;
    };

    for (const line of lines) {
        if (!line) continue; // Skip empty lines

        const [command, paramStr] = line.split(' ', 2);
        const params = parseParams(paramStr || '');
        let result = '';

        try {
            switch (command) {
                case 'init':
                    // Initialize the Service with parking lot configuration.
                    // Assumes the Service constructor takes these parameters.
                    const sedanSpots = parseInt(params['sedan_spots'] || '0');
                    const largeSpots = parseInt(params['large_spots'] || '0');
                    const motorcycleSpots = parseInt(params['motorcycle_spots'] || '0');
                    const hourlyRate = parseFloat(params['hourly_rate'] || '0');
                    
                    if (isNaN(sedanSpots) || isNaN(largeSpots) || isNaN(motorcycleSpots) || isNaN(hourlyRate)) {
                        throw new Error("Invalid initialization parameters. Expected numeric values for spots and rate.");
                    }

                    serviceInstance = new Service(sedanSpots, largeSpots, motorcycleSpots, hourlyRate);
                    // The 'init' command itself doesn't produce output unless an error occurs.
                    break;

                case 'park':
                    if (!serviceInstance) throw new Error("Parking lot service not initialized. Use 'init' first.");
                    const vehicleId = params['vehicle'];
                    const spotId = params['spot']; // Assumes a specific spot can be requested/assigned in test
                    const vehicleType = params['type'];
                    if (!vehicleId || !vehicleType || !spotId) {
                        throw new Error("Missing parameters for park command. Expected: vehicle, spot, type.");
                    }
                    // Call the user-implemented method on the Service instance
                    result = (serviceInstance as any).parkVehicle(vehicleId, spotId, vehicleType);
                    break;

                case 'get_ticket':
                    if (!serviceInstance) throw new Error("Parking lot service not initialized. Use 'init' first.");
                    const ticketVehicleId = params['vehicle'];
                    if (!ticketVehicleId) {
                        throw new Error("Missing vehicle parameter for get_ticket command.");
                    }
                    // Call the user-implemented method on the Service instance
                    result = (serviceInstance as any).getTicket(ticketVehicleId);
                    break;

                case 'exit':
                    if (!serviceInstance) throw new Error("Parking lot service not initialized. Use 'init' first.");
                    const exitVehicleId = params['vehicle'];
                    const durationStr = params['duration'];
                    if (!exitVehicleId || !durationStr) {
                        throw new Error("Missing parameters for exit command. Expected: vehicle, duration.");
                    }
                    // Parse duration from 'Xhours' format
                    const durationHours = parseFloat(durationStr.replace('hours', '').replace('hour', ''));
                    if (isNaN(durationHours)) {
                        throw new Error("Invalid duration format. Expected: 'Xhours' (e.g., '2hours').");
                    }
                    // Call the user-implemented method on the Service instance
                    result = (serviceInstance as any).exitVehicle(exitVehicleId, durationHours);
                    break;

                case 'available_spots':
                    if (!serviceInstance) throw new Error("Parking lot service not initialized. Use 'init' first.");
                    const spotType = params['type']; // Optional, if omitted, might list all types
                    // Call the user-implemented method on the Service instance
                    result = (serviceInstance as any).getAvailableSpots(spotType);
                    break;

                default:
                    result = `Error: Unknown command - ${command}`;
            }
        } catch (error: any) {
            // Catch and report errors, ensuring output is consistent
            result = `Error: ${error.message}`;
        }

        // Only push results that are not empty strings (e.g., from successful init)
        if (result) {
            output.push(result);
        }
    }
    // Print all accumulated output lines joined by newlines
    console.log(output.join('\n'));
});$harness$,
  test_cases   = '[{"input": "init sedan_spots=50, large_spots=20, motorcycle_spots=10, hourly_rate=3\npark vehicle=CAR001, spot=A5, type=sedan", "description": "Park vehicle", "expected_output": "CAR001 parked at spot A5"}, {"input": "init sedan_spots=50, large_spots=20, motorcycle_spots=10, hourly_rate=3\npark vehicle=CAR001, spot=A5, type=sedan\nget_ticket vehicle=CAR001", "description": "Get parking ticket", "expected_output": "CAR001 parked at spot A5\nTicket issued: CAR001, spot A5, time: 10:00"}, {"input": "init sedan_spots=50, large_spots=20, motorcycle_spots=10, hourly_rate=3\npark vehicle=CAR001, spot=A5, type=sedan\nget_ticket vehicle=CAR001\nexit vehicle=CAR001, duration=2hours", "description": "Exit and pay fee", "expected_output": "CAR001 parked at spot A5\nTicket issued: CAR001, spot A5, time: 10:00\nCAR001 exited, fee $6.00 (2hrs x $3)"}, {"input": "init sedan_spots=50, large_spots=20, motorcycle_spots=10, hourly_rate=3\npark vehicle=CAR001, spot=A5, type=sedan\navailable_spots type=sedan", "description": "Check available spots", "expected_output": "CAR001 parked at spot A5\n49 sedan spots available"}]'::jsonb
WHERE id = 'oop_020';
