  test_harness = $harness$import java.util.Scanner;
import java.util.Map;
import java.util.HashMap;

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        Service service = new Service(); // Instantiate the user's Service class

        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String[] parts = line.split(" ", 2); // Split command from parameters
            String command = parts[0];
            Map<String, String> params = new HashMap<>();

            if (parts.length > 1) {
                String[] paramPairs = parts[1].split(", "); // Split param pairs like 'key=value'
                for (String pair : paramPairs) {
                    String[] kv = pair.split("=", 2);
                    if (kv.length == 2) {
                        params.put(kv[0].trim(), kv[1].trim());
                    } else {
                        // Handle malformed key=value pairs if necessary, or ignore
                    }
                }
            }

            // Process commands
            switch (command) {
                case "add_source":
                    String name = params.get("name");
                    String url = params.get("url");
                    String category = params.get("category");
                    if (name != null && url != null && category != null) {
                        // Assuming Service.addSource returns the formatted confirmation string
                        String result = service.addSource(name, url, category);
                        System.out.println(result);
                    } else {
                        System.out.println("Error: Missing parameters for add_source (name, url, category).");
                    }
                    break;

                case "fetch_feed":
                    String sourceName = params.get("source");
                    if (sourceName != null) {
                        // Assuming Service.fetchFeed returns the count of fetched articles
                        int articleCount = service.fetchFeed(sourceName);
                        System.out.println("Fetched " + articleCount + " articles from " + sourceName);
                    } else {
                        System.out.println("Error: Missing source parameter for fetch_feed.");
                    }
                    break;

                case "filter":
                    String filterCategory = params.get("category");
                    if (filterCategory != null) {
                        // Assuming Service.filterFeed returns the count of articles matching the filter
                        int filteredCount = service.filterFeed(filterCategory);
                        System.out.println("Filtered feed: " + filteredCount + " " + filterCategory + " articles");
                    } else {
                        System.out.println("Error: Missing category parameter for filter.");
                    }
                    break;

                case "get_top_stories":
                    String countStr = params.get("count");
                    if (countStr != null) {
                        try {
                            int count = Integer.parseInt(countStr);
                            // Assuming Service.getTopStories returns the count of top stories available/returned
                            int topStoriesCount = service.getTopStories(count);
                            System.out.println("Top " + topStoriesCount + " stories returned");
                        } catch (NumberFormatException e) {
                            System.out.println("Error: Invalid count parameter for get_top_stories. Must be an integer.");
                        }
                    } else {
                        System.out.println("Error: Missing count parameter for get_top_stories.");
                    }
                    break;

                default:
                    System.out.println("Unknown command: " + command);
            }
        }
        sc.close();
    }
}$harness$,
  test_cases   = '[{"input": "add_source name=TechNews, url=technews.com, category=technology", "description": "Add news source", "expected_output": "Source TechNews added"}, {"input": "add_source name=TechNews, url=technews.com, category=technology\nfetch_feed source=TechNews", "description": "Fetch news feed", "expected_output": "Source TechNews added\nFetched 10 articles from TechNews"}, {"input": "add_source name=TechNews, url=technews.com, category=technology\nfetch_feed source=TechNews\nfilter category=technology", "description": "Filter by category", "expected_output": "Source TechNews added\nFetched 10 articles from TechNews\nFiltered feed: 10 technology articles"}, {"input": "add_source name=TechNews, url=technews.com, category=technology\nfetch_feed source=TechNews\nfilter category=technology\nget_top_stories count=5", "description": "Get top stories", "expected_output": "Source TechNews added\nFetched 10 articles from TechNews\nFiltered feed: 10 technology articles\nTop 5 stories returned"}]'::jsonb
