-- oop_022: Job Application Tracker
UPDATE challenges SET
  test_harness = $harness$import sys

# The user's code with classes Entity, Service, Application, ApplicationTrackerService
# will be prepended to this harness.

def parse_args(arg_string):
    """
    Parses a string of key=value pairs separated by ', '.
    Example: "job=SWE at Google, status=applied"
    """
    args = {}
    if not arg_string:
        return args
    
    pairs = arg_string.split(', ')
    for pair in pairs:
        if '=' in pair:
            key, value = pair.split('=', 1) # Split only on the first '='
            args[key.strip()] = value.strip()
    return args

def run_harness():
    """
    The main test harness function. Reads commands from stdin,
    interacts with the user's ApplicationTrackerService, and prints results to stdout.
    """
    # Instantiate the main service class once.
    # We assume the user has implemented ApplicationTrackerService
    # inheriting from the provided Service class.
    tracker_service = ApplicationTrackerService()

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        parts = line.split(' ', 1)
        command = parts[0]
        arg_string = parts[1] if len(parts) > 1 else ''
        
        args = parse_args(arg_string)

        output = None
        try:
            if command == "add_application":
                job_full = args.get('job', '')
                status = args.get('status', 'unknown') # Default status to 'unknown' if not provided
                
                # Parse "job title at company" format, e.g., "SWE at Google"
                job_parts = job_full.rsplit(' at ', 1)
                if len(job_parts) == 2:
                    job_title, company = job_parts
                else:
                    job_title = job_parts[0] if job_parts else ''
                    company = "Unknown Company" # Default company if ' at ' separator is not found
                
                output = tracker_service.add_application(job_title=job_title, company=company, status=status)
            
            elif command == "update_status":
                job_full = args.get('job', '')
                new_status = args.get('status', 'unknown')
                
                # Parse "job title at company" format
                job_parts = job_full.rsplit(' at ', 1)
                if len(job_parts) == 2:
                    job_title, company = job_parts
                else:
                    job_title = job_parts[0] if job_parts else ''
                    company = "Unknown Company"
                
                output = tracker_service.update_status(job_title=job_title, company=company, new_status=new_status)
            
            elif command == "get_pipeline":
                output = tracker_service.get_pipeline()
            
            elif command == "add_note":
                job_full = args.get('job', '')
                note_text = args.get('note', '')
                
                # Parse "job title at company" format
                job_parts = job_full.rsplit(' at ', 1)
                if len(job_parts) == 2:
                    job_title, company = job_parts
                else:
                    job_title = job_parts[0] if job_parts else ''
                    company = "Unknown Company"
                
                output = tracker_service.add_note(job_title=job_title, company=company, note_text=note_text)
            
            else:
                output = f"Error: Unknown command '{command}'"
        
        except AttributeError as ae:
            # Catches errors if tracker_service methods are not implemented or misspelled
            output = f"Error: Service method for command '{command}' not found or incorrectly implemented. Details: {ae}"
        except Exception as e:
            # Catch any other unexpected errors from user's code
            output = f"Error executing command '{command}': {e}"
        
        if output is not None:
            print(output)

# Call the harness function to start execution
run_harness()$harness$,
  test_cases   = '[{"input": "add_application job=SWE at Google, status=applied", "description": "Add a single application", "expected_output": "Application added: SWE at Google (applied)"}, {"input": "add_application job=SWE at Google, status=applied\nadd_application job=Data Scientist at Microsoft, status=interview\nadd_application job=Product Manager at Amazon, status=offer\nget_pipeline", "description": "Add multiple applications and get pipeline summary", "expected_output": "Application added: SWE at Google (applied)\nApplication added: Data Scientist at Microsoft (interview)\nApplication added: Product Manager at Amazon (offer)\nPipeline: 1 applied, 1 interview, 1 offers"}, {"input": "add_application job=SWE at Google, status=applied\nupdate_status job=SWE at Google, status=interview\nget_pipeline", "description": "Update application status and verify pipeline change", "expected_output": "Application added: SWE at Google (applied)\nApplication updated to interview stage\nPipeline: 0 applied, 1 interview, 0 offers"}, {"input": "add_application job=SWE at Google, status=applied\nadd_note job=SWE at Google, note=System design interview on Monday", "description": "Add a note to an existing application", "expected_output": "Application added: SWE at Google (applied)\nNote added to SWE at Google application"}, {"input": "add_application job=Frontend Dev at Meta, status=applied\nadd_application job=Backend Eng at Netflix, status=applied\nadd_application job=Data Analyst at Spotify, status=interview\nupdate_status job=Frontend Dev at Meta, status=interview\nadd_note job=Frontend Dev at Meta, note=Recruiter call scheduled\nupdate_status job=Backend Eng at Netflix, status=rejected\nget_pipeline", "description": "Complex scenario with multiple operations and final pipeline check", "expected_output": "Application added: Frontend Dev at Meta (applied)\nApplication added: Backend Eng at Netflix (applied)\nApplication added: Data Analyst at Spotify (interview)\nApplication updated to interview stage\nNote added to Frontend Dev at Meta application\nApplication updated to rejected stage\nPipeline: 0 applied, 2 interview, 0 offers"}]'::jsonb
