-- oop_023: Package Delivery Tracking
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
    input: process.stdin
});

const lines: string[] = [];

rl.on('line', (line) => {
    lines.push(line.trim());
});

rl.on('close', () => {
    // Helper function to parse commands
    function parseCommand(line: string): { command: string, args: { [key: string]: string } } {
        const parts = line.split(' ');
        const command = parts[0];
        const args: { [key: string]: string } = {};
        if (parts.length > 1) {
            const paramString = parts.slice(1).join(' ');
            paramString.split(',').forEach(param => {
                const [key, value] = param.split('=').map(s => s.trim());
                if (key && value !== undefined) {
                    args[key] = value;
                }
            });
        }
        return { command, args };
    }

    // Instantiate the main service. Assumes user implements `TrackingService`.
    // This object maintains state across commands.
    const trackingService = new TrackingService();

    for (const line of lines) {
        if (!line) {
            continue; // Skip empty lines
        }

        const { command, args } = parseCommand(line);
        let output: string = '';

        try {
            switch (command) {
                case 'create_shipment':
                    // Expects args: id, origin, destination
                    // User's TrackingService.createShipment() should return the formatted string.
                    output = trackingService.createShipment(args.id, args.origin, args.destination);
                    break;
                case 'update_status':
                    // Expects args: shipment (id), status, location
                    // User's TrackingService.updateShipmentStatus() should return the formatted string.
                    output = trackingService.updateShipmentStatus(args.shipment, args.status, args.location);
                    break;
                case 'track':
                    // Expects args: shipment (id)
                    // User's TrackingService.trackShipment() should return the formatted string.
                    output = trackingService.trackShipment(args.shipment);
                    break;
                case 'deliver':
                    // Expects args: shipment (id)
