// Assume the user has defined Loan and LoanService classes
// which extend the provided Entity and Service base classes.
// Example (user's expected implementation structure):
// class Loan extends Entity {
//   constructor(public amount: number, public termYears: number, public annualRate: number) { super(); }
// }
//
// class LoanService extends Service {
//   // ... methods for calculations
//   calculateMonthlyPayment(loan: Loan): number { /* ... */ }
//   calculateTotalInterest(loan: Loan): number { /* ... */ }
//   calculatePayoffAcceleration(loan: Loan, extraMonthlyPayment: number): number { /* ... */ }
//   getAmortizationEntry(loan: Loan, month: number, extraMonthlyPayment: number = 0): { payment: number, principal: number, interest: number } { /* ... */ }
// }

const rl = readline.createInterface({
    input: process.stdin
});

const lines: string[] = [];

rl.on('line', (line) => {
    lines.push(line.trim());
});

rl.on('close', () => {
    // State variables for the hidden test harness
    let currentLoan: Loan | null = null;
    let extraPaymentAmount: number = 0;
    
    // Instantiate the LoanService. Assumes LoanService has a default constructor.
    // The user's LoanService class should extend the provided 'Service' class.
    const loanService: LoanService = new LoanService(); 

    // Helper function for currency formatting
    function formatCurrency(amount: number): string {
        return `$${amount.toFixed(2)}`;
    }

    // Process each command line
    for (const line of lines) {
        const parts = line.split(' ');
        const command = parts[0];

        switch (command) {
            case 'SET_LOAN':
                try {
                    const amount = parseFloat(parts[1]);
                    const termYears = parseInt(parts[2], 10);
                    const annualRatePercent = parseFloat(parts[3]); // e.g., "5" for 5%
                    
                    if (isNaN(amount) || isNaN(termYears) || isNaN(annualRatePercent) || amount <= 0 || termYears <= 0 || annualRatePercent < 0) {
                        console.log('Error: Invalid SET_LOAN parameters. Usage: SET_LOAN <amount> <termYears> <annualRatePercent>');
                        continue;
                    }
                    // The user's Loan class should extend the provided 'Entity' class.
                    currentLoan = new Loan(amount, termYears, annualRatePercent / 100); // Convert percentage to decimal
                } catch (e: any) {
                    console.log(`Error processing SET_LOAN: ${e.message}`);
                }
                break;

            case 'SET_EXTRA_PAYMENT':
                try {
                    const amount = parseFloat(parts[1]);
                    if (isNaN(amount) || amount < 0) {
                        console.log('Error: Invalid SET_EXTRA_PAYMENT amount. Usage: SET_EXTRA_PAYMENT <amount>');
                        continue;
                    }
                    extraPaymentAmount = amount;
                } catch (e: any) {
                    console.log(`Error processing SET_EXTRA_PAYMENT: ${e.message}`);
                }
                break;

            case 'CALCULATE_MONTHLY_PAYMENT':
                if (!currentLoan) {
                    console.log('Error: Loan not set. Use SET_LOAN first.');
                    continue;
                }
                try {
                    const payment = loanService.calculateMonthlyPayment(currentLoan);
                    console.log(`Monthly payment: ${formatCurrency(payment)}`);
                } catch (e: any) {
                    console.log(`Error calculating monthly payment: ${e.message}`);
                }
                break;

            case 'CALCULATE_TOTAL_INTEREST':
                if (!currentLoan) {
                    console.log('Error: Loan not set. Use SET_LOAN first.');
                    continue;
                }
                try {
                    const totalInterest = loanService.calculateTotalInterest(currentLoan);
                    console.log(`Total interest: ${formatCurrency(totalInterest)}`);
                } catch (e: any) {
                    console.log(`Error calculating total interest: ${e.message}`);
                }
                break;

            case 'CALCULATE_PAYOFF_ACCELERATION':
                if (!currentLoan) {
                    console.log('Error: Loan not set. Use SET_LOAN first.');
                    continue;
                }
                try {
                    const acceleratedMonths = loanService.calculatePayoffAcceleration(currentLoan, extraPaymentAmount);
                    // Round to nearest whole month as payoff acceleration is typically reported as an integer.
                    console.log(`Payoff accelerated by ${Math.round(acceleratedMonths)} months`);
                } catch (e: any) {
                    console.log(`Error calculating payoff acceleration: ${e.message}`);
                }
                break;

            case 'GET_AMORTIZATION_ENTRY':
                if (!currentLoan) {
                    console.log('Error: Loan not set. Use SET_LOAN first.');
                    continue;
                }
                try {
                    const monthNumber = parseInt(parts[1], 10);
                    if (isNaN(monthNumber) || monthNumber <= 0) {
                        console.log('Error: Invalid month number for amortization entry. Usage: GET_AMORTIZATION_ENTRY <month>');
                        continue;
                    }
                    const entry = loanService.getAmortizationEntry(currentLoan, monthNumber, extraPaymentAmount);
                    console.log(`Month ${monthNumber}: payment ${formatCurrency(entry.payment)}, principal ${formatCurrency(entry.principal)}, interest ${formatCurrency(entry.interest)}`);
                } catch (e: any) {
                    console.log(`Error getting amortization entry: ${e.message}`);
                }
                break;

            default:
                console.log(`Error: Unknown command "${command}"`);
                break;
        }
    }
});$harness$,
