-- oop_028: Food Delivery Order Router
UPDATE challenges SET
  test_harness = $harness$import sys
import re

def run_harness():
    # Instantiate the main service object.
    # Assume the user implements the main logic directly within the Service class
    # or a class derived from Service, named 'Service' itself by convention for the harness.
    router = Service()

    # Regex to parse key=value arguments, handling lists like items=[item1, item2]
    # It captures the key and then the value. Value can be a simple string or a [list].
    arg_pattern = re.compile(r'(\w+)=([^,\[\]]+(?:\\[[^\]]*\\])?)')

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        parts = line.split(' ', 1)
        command = parts[0]
        args_str = parts[1] if len(parts) > 1 else ''

        args = {}
        # Iterate over all matches in the argument string
        for match in arg_pattern.finditer(args_str):
            key = match.group(1)
            value = match.group(2)
            # Handle list parsing for values like "[item1, item2]"
            if value.startswith('[') and value.endswith(']') and len(value) > 1:
                # Split by comma, remove leading/trailing whitespace for each item
                # Filter out empty strings in case of trailing comma or empty list elements
                value = [item.strip() for item in value[1:-1].split(',') if item.strip()]
            args[key] = value

        result = None
        try:
            if command == "place_order":
                customer = args['customer']
                items = args['items'] # This should be parsed as a list by regex
                address = args['address']
                result = router.place_order(customer, items, address)
            elif command == "assign_driver":
                order_id = args['order']
                driver_id = args['driver']
                result = router.assign_driver(order_id, driver_id)
            elif command == "update_eta":
                order_id = args['order']
                eta = args['eta']
                result = router.update_eta(order_id, eta)
            elif command == "deliver":
                order_id = args['order']
                result = router.deliver_order(order_id)
            elif command == "register_restaurant":
                name = args['name']
                address = args['address']
                cuisine = args['cuisine'] # This should be parsed as a list by regex
                result = router.register_restaurant(name, address, cuisine)
            elif command == "register_driver":
                driver_id = args['id']
                name = args['name']
                vehicle = args['vehicle']
                result = router.register_driver(driver_id, name, vehicle)
            else:
                result = f"Error: Unknown command '{command}'"

            if result is not None:
                print(result)

        except AttributeError as e:
            # This handles cases where the user has not implemented a required method on the Service object.
            print(f"Error: Method not implemented or incorrect call for command '{command}' - {e}")
        except KeyError as e:
            # This handles cases where a required argument is missing from the input command.
            print(f"Error: Missing argument for command '{command}': {e}")
        except Exception as e:
            # Catch any other unexpected errors during command execution.
            print(f"An unexpected error occurred during command '{command}': {e}")

