-- oop_029: Subscription Billing Manager
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // Assume the user defines a class named 'SubscriptionManager' as the main entry point
  // which handles all subscription logic and methods.
  const manager = new SubscriptionManager(); // Stateful object

  // Helper function to parse command strings
  function parseCommand(commandLine: string): any {
    const parts = commandLine.split(' ');
    const command = parts[0];
    const params: { [key: string]: string } = {};
    if (parts.length > 1) {
      parts[1].split(', ').forEach(param => {
        const [key, value] = param.split('=');
        params[key.trim()] = value.trim();
      });
    }
    return { command, ...params };
  }

  for (const line of lines) {
    const cmd = parseCommand(line);
    let output: string | undefined;

    switch (cmd.command) {
      case 'subscribe':
        // Expect manager.subscribe(user: string, plan: string, billingCycle: string) to return string
        output = manager.subscribe(cmd.user, cmd.plan, cmd.billing);
        break;
      case 'process_billing':
        // Expect manager.processBilling(user: string) to return string
        output = manager.processBilling(cmd.user);
        break;
      case 'upgrade':
        // Expect manager.upgrade(user: string, newPlan: string) to return string
        output = manager.upgrade(cmd.user, cmd.plan);
        break;
      case 'cancel':
        // Expect manager.cancel(user: string, effective: string) to return string
        output = manager.cancel(cmd.user, cmd.effective);
        break;
      default:
        output = `Unknown command: ${cmd.command}`;
        break;
    }
    if (output !== undefined) {
      console.log(output);
    }
  }
});$harness$,
  test_cases   = '[{"input": "subscribe user=alice, plan=premium, billing=monthly", "description": "Create subscription", "expected_output": "Alice subscribed to premium monthly at $9.99"}, {"input": "subscribe user=alice, plan=premium, billing=monthly\nprocess_billing user=alice", "description": "Process billing", "expected_output": "Alice subscribed to premium monthly at $9.99\nBilled alice $9.99 for premium monthly"}, {"input": "subscribe user=alice, plan=premium, billing=monthly\nupgrade user=alice, plan=enterprise", "description": "Upgrade subscription", "expected_output": "Alice subscribed to premium monthly at $9.99\nAlice upgraded to enterprise, prorated charge applied"}, {"input": "subscribe user=alice, plan=premium, billing=monthly\ncancel user=alice, effective=end_of_period", "description": "Cancel subscription", "expected_output": "Alice subscribed to premium monthly at $9.99\nAlice subscription cancelled at end of billing period"}]'::jsonb
WHERE id = 'oop_029';
-- oop_030: Tournament Bracket Organizer
UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.Map;
import java.util.HashMap;
import java.util.Arrays;
import java.util.List;
import java.util.stream.Collectors;

public class Main {

    // Helper method to parse command parameters from the input string
    private static Map<String, String> parseParams(String paramsString) {
        Map<String, String> params = new HashMap<>();
        if (paramsString == null || paramsString.trim().isEmpty()) {
            return params;
        }
        // Split by comma, then trim and split by '='
        String[] pairs = paramsString.split(",\s*");
        for (String pair : pairs) {
            String[] parts = pair.split("=", 2);
            if (parts.length == 2) {
                params.put(parts[0].trim(), parts[1].trim());
            } else {
                // Handle malformed parameters if necessary, or ignore
                // For this challenge, assume well-formed inputs.
            }
        }
        return params;
    }

    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        Service service = new Service(); // Instantiate the user's Service class

        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) {
                continue; // Skip empty lines
            }

            // Split the command from its parameters
            String[] commandParts = line.split(" ", 2);
            String command = commandParts[0];
            String paramsString = commandParts.length > 1 ? commandParts[1] : "";
            Map<String, String> params = parseParams(paramsString);

            String result = "";
            try {
                switch (command) {
                    case "create_tournament":
                        String name = params.get("name");
                        int participants = Integer.parseInt(params.get("participants"));
                        result = service.createTournament(name, participants);
                        break;
                    case "record_result":
                        String matchId = params.get("match");
                        String winner = params.get("winner");
                        String loser = params.get("loser");
                        result = service.recordResult(matchId, winner, loser);
                        break;
                    case "get_bracket":
                        // Assuming get_bracket operates on the 'current' or 'last created' tournament
                        // as no tournament name parameter is provided in the original test case.
                        result = service.getBracket();
                        break;
                    case "get_champion":
                        String tournamentName = params.get("tournament");
                        result = service.getChampion(tournamentName);
                        break;
                    default:
                        result = "Unknown command: " + command;
                        break;
                }
            } catch (Exception e) {
                // Catch any exceptions from user's code to prevent harness crash
                result = "Error processing command '" + command + "': " + e.getMessage();
                // Optionally print stack trace for debugging during development:
                // e.printStackTrace(); 
            }
            System.out.println(result);
        }
        sc.close();
    }
}$harness$,
