-- oop_031: Classroom Seating Planner
UPDATE challenges SET
  test_harness = $harness$import sys

def run_harness():
    # Instantiate the user's Service class once for stateful operations
    # The user is expected to implement the Service class with methods
    # like initialize_classroom, assign_student, move_student,
    # get_seating_chart, and get_available_seats_count.
    service = Service() 

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue # Skip empty lines

        output_message = None # Store the message to print

        if line.startswith("classroom seats="):
            try:
                num_seats = int(line.split('=')[1])
                output_message = service.initialize_classroom(num_seats)
            except (IndexError, ValueError):
                output_message = f"Error: Invalid 'classroom seats' command format: {line}"
            except AttributeError:
                output_message = f"Error: 'Service' object has no 'initialize_classroom' method."
        elif line.startswith("assign student="):
            try:
                parts = line.split(', ')
                student_name = parts[0].split('=')[1]
                seat_id = parts[1].split('=')[1]
                output_message = service.assign_student(student_name, seat_id)
            except (IndexError, AttributeError):
                output_message = f"Error: Invalid 'assign student' command format or missing method: {line}"
        elif line.startswith("move student="):
            try:
                parts = line.split(', ')
                student_name = parts[0].split('=')[1]
                # Extract new_seat_id. Assuming 'to=' is always present and unique in valid commands.
                new_seat_id_part = next(p for p in parts if p.startswith("to="))
                new_seat_id = new_seat_id_part.split('=')[1]
                output_message = service.move_student(student_name, new_seat_id)
            except (IndexError, AttributeError, StopIteration): # StopIteration if 'to=' part is missing
                output_message = f"Error: Invalid 'move student' command format or missing method: {line}"
        elif line == "get_seating_chart":
            try:
                output_message = service.get_seating_chart()
            except AttributeError:
                output_message = f"Error: 'Service' object has no 'get_seating_chart' method."
        elif line == "available_seats":
            try:
                output_message = service.get_available_seats_count()
            except AttributeError:
                output_message = f"Error: 'Service' object has no 'get_available_seats_count' method."
        else:
            output_message = f"Error: Unknown command '{line}'"

        # Print the output for the command if it's not None
        if output_message is not None:
            print(output_message)

run_harness()$harness$,
  test_cases   = '[{"input": "classroom seats=30\nassign student=Alice, seat=A1", "description": "Assign student seat", "expected_output": "Classroom created with 30 seats\nAlice assigned to seat A1"}, {"input": "classroom seats=30\nassign student=Alice, seat=A1\nmove student=Alice, from=A1, to=B3", "description": "Move student seat", "expected_output": "Classroom created with 30 seats\nAlice assigned to seat A1\nAlice moved to seat B3"}, {"input": "classroom seats=30\nassign student=Alice, seat=A1\nmove student=Alice, from=A1, to=B3\nget_seating_chart", "description": "Get seating chart", "expected_output": "Classroom created with 30 seats\nAlice assigned to seat A1\nAlice moved to seat B3\nSeating chart: Alice at B3, 29 empty seats"}, {"input": "classroom seats=30\nassign student=Alice, seat=A1\nmove student=Alice, from=A1, to=B3\navailable_seats", "description": "Count available seats", "expected_output": "Classroom created with 30 seats\nAlice assigned to seat A1\nAlice moved to seat B3\n29 seats available"}]'::jsonb
