const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {
  // Instantiate the user's main Service class.
  // This assumes the user implements the core logic directly within or on a class named 'Service'.
  const dealershipService = new Service();

  for (const line of lines) {
    if (!line) continue;

    const parts = line.split(' ');
    const command = parts[0];
    const paramsStr = parts.slice(1).join(' ');

    const params: { [key: string]: any } = {};
    paramsStr.split(',').forEach(paramPair => {
      const [key, val] = paramPair.split('=').map(s => s.trim());
      if (key && val !== undefined) {
        // Convert 'price' to a number
        if (key === 'price') {
          params[key] = parseFloat(val);
        } else {
          params[key] = val;
        }
      }
    });

    let output: string | undefined;

    try {
      switch (command) {
        case 'add_car':
          // Expects a method like `addCar(vin: string, make: string, model: string, price: number)`
          if ('vin' in params && 'make' in params && 'model' in params && 'price' in params) {
            output = (dealershipService as any).addCar(params.vin, params.make, params.model, params.price);
          } else {
            output = `Error: Missing parameters for add_car command. Expected: vin, make, model, price.`;
          }
          break;

        case 'search':
          // Expects a method like `searchCars(criteria: { make?: string; model?: string; vin?: string; })`
          // and returns an array of car-like objects with `make`, `model`, `vin`, `price`.
          if (Object.keys(params).length > 0) {
            const results = (dealershipService as any).searchCars(params);
            if (Array.isArray(results)) {
              if (results.length > 0) {
                output = `Found ${results.length}: ` + results.map((car: any) => `${car.make} ${car.model} ${car.vin}, $${car.price}`).join('; ');
              } else {
                output = `Found 0 cars matching criteria.`;
              }
            } else {
              output = `Error: search method did not return an array.`;
            }
          } else {
            output = `Error: Missing search criteria for search command.`;
          }
          break;

        case 'sell':
          // Expects a method like `sellCar(vin: string, buyer: string)`
          if ('car' in params && 'buyer' in params) {
            // The 'car' parameter is assumed to be the VIN.
            output = (dealershipService as any).sellCar(params.car, params.buyer);
          } else {
            output = `Error: Missing parameters for sell command. Expected: car (VIN), buyer.`;
          }
          break;

        case 'get_inventory':
          // Expects a method like `getInventorySummary()`
          output = (dealershipService as any).getInventorySummary();
          break;

        default:
          output = `Unknown command: ${command}`;
          break;
      }
    } catch (e: any) {
      // Catch potential runtime errors from user's code and report them.
      output = `Runtime Error: ${e.message || e}`;
    }

    if (output !== undefined) {
      console.log(output);
    }
  }
});$harness$,
