-- oop_033: Recipe Management System
UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.List;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Map;
import java.util.HashMap;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner scanner = new Scanner(System.in);
        // The user's Service class will manage the recipe system
        Service recipeService = new Service(); 

        while (scanner.hasNextLine()) {
            String line = scanner.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String commandName;
            Map<String, String> params = new HashMap<>();

            int firstSpace = line.indexOf(' ');
            if (firstSpace == -1) {
                commandName = line;
            } else {
                commandName = line.substring(0, firstSpace);
                String paramsString = line.substring(firstSpace + 1);

                // Split parameters by comma, but not inside square brackets for list values like 'ingredients'
                String[] rawParams = paramsString.split(",\s*(?![^\[]*\])");
                for (String param : rawParams) {
                    int eqIndex = param.indexOf('=');
                    if (eqIndex != -1) {
                        String key = param.substring(0, eqIndex).trim();
                        String value = param.substring(eqIndex + 1).trim();
                        params.put(key, value);
                    }
                }
            }

            String result = "";
            try {
                switch (commandName) {
                    case "add_recipe":
                        String recipeName = params.get("name");
                        String ingredientsStr = params.get("ingredients"); // e.g., "[pasta, sauce, cheese]"
                        List<String> ingredients = new ArrayList<>();
                        if (ingredientsStr != null && ingredientsStr.startsWith("[") && ingredientsStr.endsWith("]")) {
                            ingredientsStr = ingredientsStr.substring(1, ingredientsStr.length() - 1); // Remove brackets
                            if (!ingredientsStr.isEmpty()) {
                                ingredients = Arrays.asList(ingredientsStr.split(",\s*"));
                            }
                        }
                        // Assumes user's Service class has a method: String addRecipe(String name, List<String> ingredients)
                        result = recipeService.addRecipe(recipeName, ingredients);
                        break;
                    case "search":
                        String ingredient = params.get("ingredient");
                        // Assumes user's Service class has a method: String searchByIngredient(String ingredient)
                        result = recipeService.searchByIngredient(ingredient);
                        break;
                    case "scale_recipe":
                        String scaleRecipeName = params.get("name");
                        String servingsStr = params.get("servings"); // e.g., "4 to 8"
                        int fromServings = 0;
                        int toServings = 0;
                        if (servingsStr != null) {
                            String[] parts = servingsStr.split(" to ");
                            if (parts.length == 2) {
                                fromServings = Integer.parseInt(parts[0].trim());
                                toServings = Integer.parseInt(parts[1].trim());
                            }
                        }
                        // Assumes user's Service class has a method: String scaleRecipe(String name, int fromServings, int toServings)
                        result = recipeService.scaleRecipe(scaleRecipeName, fromServings, toServings);
                        break;
                    case "get_nutrition":
                        String nutritionRecipeName = params.get("recipe");
                        // Assumes user's Service class has a method: String getNutrition(String recipeName)
                        result = recipeService.getNutrition(nutritionRecipeName);
                        break;
                    default:
                        result = "Unknown command: " + commandName;
                        break;
                }
            } catch (Exception e) {
                // Catches exceptions from user's code and prints an error message
                result = "Error processing command '" + commandName + "': " + e.getMessage();
                // For debugging during development, you might want to uncomment: e.printStackTrace();
            }
            System.out.println(result);
        }
        scanner.close();
    }
}$harness$,
  test_cases   = '[{"input": "add_recipe name=Pasta, ingredients=[pasta, sauce, cheese]", "description": "Add recipe", "expected_output": "Recipe Pasta added with 3 ingredients"}, {"input": "add_recipe name=Pasta, ingredients=[pasta, sauce, cheese]\nsearch ingredient=pasta", "description": "Search by ingredient", "expected_output": "Recipe Pasta added with 3 ingredients\nRecipes with pasta: [Pasta]"}, {"input": "add_recipe name=Pasta, ingredients=[pasta, sauce, cheese]\nscale_recipe name=Pasta, servings=4 to 8", "description": "Scale recipe servings", "expected_output": "Recipe Pasta added with 3 ingredients\nPasta recipe scaled: doubled all ingredients"}, {"input": "add_recipe name=Pasta, ingredients=[pasta, sauce, cheese]\nget_nutrition recipe=Pasta", "description": "Get recipe nutrition", "expected_output": "Recipe Pasta added with 3 ingredients\nPasta: 650 cal, 28g protein, 85g carbs"}]'::jsonb
WHERE id = 'oop_033';
