-- oop_035: Loyalty Rewards Program
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', () => {
  // Assume the user's 'Service' class is the main entry point for loyalty program operations
  // This object will maintain state across commands.
  const loyaltyService = new Service(); 

  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    const parts = line.split(' ');
    const command = parts[0];
    // Rejoin the rest of the parts in case argument values contain spaces
    // and then split by comma to parse individual key=value pairs.
    const argsString = parts.slice(1).join(' '); 

    const argMap = new Map<string, string>();
    argsString.split(',').forEach(argPair => {
      const trimmedArg = argPair.trim();
      if (trimmedArg) {
        const [key, value] = trimmedArg.split('=');
        if (key && value !== undefined) { // Value can be empty string, but not undefined
          argMap.set(key.trim(), value.trim());
        }
      }
    });

    let output: string | undefined;

    try {
      switch (command) {
        case 'earn_points': {
          const user = argMap.get('user');
          const amountStr = argMap.get('amount');
          const transaction = argMap.get('transaction');
          const amount = parseInt(amountStr || '0', 10); // Default to 0 if not provided or invalid

          if (user && amountStr !== undefined && !isNaN(amount) && amount >= 0 && transaction !== undefined) {
            output = loyaltyService.earnPoints(user, amount, transaction);
          } else {
            output = `Error: Invalid or missing arguments for earn_points. Expected: user, amount, transaction. Received: ${line}`;
          }
          break;
        }
        case 'redeem': {
          const user = argMap.get('user');
          const pointsStr = argMap.get('points');
          const reward = argMap.get('reward');
          const points = parseInt(pointsStr || '0', 10); // Default to 0 if not provided or invalid

          if (user && pointsStr !== undefined && !isNaN(points) && points >= 0 && reward !== undefined) {
            output = loyaltyService.redeemPoints(user, points, reward);
          } else {
            output = `Error: Invalid or missing arguments for redeem. Expected: user, points, reward. Received: ${line}`;
          }
          break;
        }
        case 'get_balance': {
          const user = argMap.get('user');
          if (user !== undefined) {
            output = loyaltyService.getUserBalance(user);
          } else {
            output = `Error: Missing 'user' argument for get_balance. Received: ${line}`;
          }
          break;
        }
        case 'tier_status': {
          const user = argMap.get('user');
          if (user !== undefined) {
            output = loyaltyService.getUserTierStatus(user);
          } else {
            output = `Error: Missing 'user' argument for tier_status. Received: ${line}`;
          }
          break;
        }
        default:
          output = `Error: Unknown command: ${command}. Received: ${line}`;
          break;
      }
    } catch (e: any) {
      // Catch any unhandled errors from the user's implementation
      output = `Runtime Error processing command '${command}': ${e.message || e}`;
    }

    if (output !== undefined) {
      console.log(output);
    }
  }
});$harness$,
  test_cases   = '[{"input": "earn_points user=alice, amount=100, transaction=purchase\nget_balance user=alice", "description": "Earn reward points and verify balance", "expected_output": "alice earned 100 points (total: 100)\nalice points balance: 100"}, {"input": "earn_points user=bob, amount=200, transaction=signup\nredeem user=bob, points=50, reward=discount\nget_balance user=bob", "description": "Earn and redeem points, then verify remaining balance", "expected_output": "bob earned 200 points (total: 200)\nbob redeemed 50 points for $5 discount\nbob points balance: 150"}, {"input": "earn_points user=charlie, amount=100, transaction=welcome\ntier_status user=charlie", "description": "Check tier status after initial points earning", "expected_output": "charlie earned 100 points (total: 100)\ncharlie tier: Silver (100 points earned)"}, {"input": "earn_points user=diana, amount=50, transaction=purchase1\ntier_status user=diana\nearn_points user=diana, amount=150, transaction=purchase2\ntier_status user=diana\nearn_points user=diana, amount=300, transaction=purchase3\ntier_status user=diana\nearn_points user=diana, amount=10, transaction=purchase4\ntier_status user=diana", "description": "Verify tier progression with multiple earning transactions", "expected_output": "diana earned 50 points (total: 50)\ndiana tier: Bronze (50 points earned)\ndiana earned 150 points (total: 200)\ndiana tier: Silver (200 points earned)\ndiana earned 300 points (total: 500)\ndiana tier: Gold (500 points earned)\ndiana earned 10 points (total: 510)\ndiana tier: Gold (510 points earned)"}, {"input": "earn_points user=eve, amount=40, transaction=small_purchase\nredeem user=eve, points=50, reward=free_coffee\nget_balance user=eve", "description": "Attempt to redeem more points than available", "expected_output": "eve earned 40 points (total: 40)\nError: eve does not have enough points to redeem 50 points for free_coffee\neve points balance: 40"}, {"input": "get_balance user=frank\ntier_status user=george", "description": "Check balance and tier for non-existent users", "expected_output": "Error: User frank not found.\nError: User george not found."}]'::jsonb
