-- oop_036: Airport Baggage Handler
UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.HashMap;

// User classes will be concatenated here:
// class Entity { ... }
// class Service { ... }

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner scanner = new Scanner(System.in);
        Service airportService = new Service(); // Assume a default constructor for Service

        while (scanner.hasNextLine()) {
            String line = scanner.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            // Parse the command
            String[] parts = line.split(" ", 2); // Split into command and arguments
            String command = parts[0];
            String argsStr = parts.length > 1 ? parts[1] : "";

            // Helper to parse arguments into a map
            HashMap<String, String> params = new HashMap<>();
            String[] argPairs = argsStr.split(", ");
            for (String pair : argPairs) {
                String[] keyValue = pair.split("=", 2);
                if (keyValue.length == 2) {
                    params.put(keyValue[0].trim(), keyValue[1].trim());
                }
            }

            String result = "";
            switch (command) {
                case "check_in":
                    String bagIdCheckIn = params.get("bag");
                    String flightIdCheckIn = params.get("flight");
                    String weightStr = params.get("weight");
                    result = airportService.checkInBag(bagIdCheckIn, flightIdCheckIn, weightStr);
                    break;
                case "scan":
                    String bagIdScan = params.get("bag");
                    String locationScan = params.get("location");
                    result = airportService.scanBag(bagIdScan, locationScan);
                    break;
                case "track":
                    String bagIdTrack = params.get("bag");
                    result = airportService.trackBag(bagIdTrack);
                    break;
                case "flag":
                    String bagIdFlag = params.get("bag");
                    String reasonFlag = params.get("reason");
                    result = airportService.flagBag(bagIdFlag, reasonFlag);
                    break;
                default:
                    result = "Unknown command: " + command;
                    break;
            }
            System.out.println(result);
        }
        scanner.close();
    }
