-- oop_037: Legal Case Management
UPDATE challenges SET
  test_harness = $harness$import sys

def run_harness():
    # Instantiate the main service object. This object will maintain state
    # across multiple commands read from stdin. It is expected to be named 'Service'.
    try:
        system = Service() 
    except NameError:
        print("Error: 'Service' class not found. Please ensure your main class for legal case management is named 'Service'.")
        sys.exit(1)

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        try:
            command_parts = line.split(" ", 1)
            command = command_parts[0]
            args_str = command_parts[1] if len(command_parts) > 1 else ""

            args = {}
            if args_str:
                # Parse arguments in 'key=value, key2=value2' format
                for arg_pair in args_str.split(", "):
                    key_value = arg_pair.split("=", 1)
                    if len(key_value) == 2:
                        key, value = key_value
                        args[key.strip()] = value.strip()
                    else:
                        # Handle cases like 'key=' or just 'key' without an explicit value
                        args[key_value[0].strip()] = ""

            result = None
            # Dispatch commands to the appropriate method of the 'system' object
            if command == "open_case":
                result = system.open_case(
                    client=args.get("client"),
                    type=args.get("type"),
                    description=args.get("description")
                )
            elif command == "add_document":
                result = system.add_document(
                    case_id=args.get("case"),
                    document_name=args.get("doc")
                )
            elif command == "schedule_hearing":
                result = system.schedule_hearing(
                    case_id=args.get("case"),
                    date=args.get("date")
                )
            elif command == "close_case":
                result = system.close_case(
                    case_id=args.get("case"),
                    outcome=args.get("outcome")
                )
            else:
                result = f"Error: Unknown command '{command}'"

            if result is not None:
                print(result)

        except Exception as e:
            # Catch any exceptions raised by the user's code or harness processing errors
            print(f"Error processing command '{line}': {e}")

