const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout // Added output for consistency, though console.log is used.
});

const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // Assume user has implemented PetClinic and other necessary classes.
  // e.g., class Entity { ... }
  // class Service { ... }
  // class PetClinic { ... } // This is what we instantiate.

  // Instantiate the main service object. If PetClinic is not defined by the user,
  // this line will cause a runtime error, which is expected for a hidden test harness.
  const clinic = new PetClinic();

  // Helper function to parse key=value parameters from a command string.
  const parseParams = (paramString: string): Record<string, string> => {
    const params: Record<string, string> = {};
    paramString.split(',').forEach(param => {
      const [key, value] = param.trim().split('=');
      if (key && value) {
        params[key.trim()] = value.trim();
      }
    });
    return params;
  };

  // Process each command line from stdin.
  for (const line of lines) {
    let output = '';
    const commandParts = line.split(' ');
    const firstWord = commandParts[0];

    try {
      if (line.startsWith('book appointment')) {
        const paramString = line.substring('book appointment '.length);
        const params = parseParams(paramString);
        if (params.pet && params.type && params.date) {
          // Assuming bookAppointment returns the full formatted string as per expected_output.
          output = clinic.bookAppointment(params.pet, params.type, params.date);
        } else {
          output = `Error: Missing parameters for book appointment. Command: "${line}"`;
        }
      } else if (firstWord === 'cancel') {
        const paramString = line.substring('cancel '.length);
        const params = parseParams(paramString);
        if (params.appointment) {
          // Assuming cancelAppointment returns the full formatted string as per expected_output.
          output = clinic.cancelAppointment(params.appointment);
        } else {
          output = `Error: Missing appointment ID for cancel. Command: "${line}"`;
        }
      } else if (firstWord === 'reschedule') {
        const paramString = line.substring('reschedule '.length);
        const params = parseParams(paramString);
        if (params.appointment && params.new_date) {
          // Assuming rescheduleAppointment returns the full formatted string as per expected_output.
          output = clinic.rescheduleAppointment(params.appointment, params.new_date);
        } else {
          output = `Error: Missing parameters for reschedule. Command: "${line}"`;
        }
      } else if (firstWord === 'get_upcoming') {
        const paramString = line.substring('get_upcoming '.length);
        const params = parseParams(paramString);
        if (params.vet) {
          // Assuming getUpcomingAppointments returns the full formatted string as per expected_output.
          output = clinic.getUpcomingAppointments(params.vet);
        } else {
          output = `Error: Missing vet name for get_upcoming. Command: "${line}"`;
        }
      } else {
        output = `Error: Unknown command: "${line}"`;
      }
    } catch (e: any) {
      // Catch and report any runtime errors from the user's code.
      output = `Runtime Error processing command "${line}": ${e.message || e}`; 
    }
    console.log(output);
  }
});$harness$,
