import java.util.Map;
import java.util.HashMap;

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner scanner = new Scanner(System.in);
        Service bookingService = new Service(); // User's Service class

        while (scanner.hasNextLine()) {
            String line = scanner.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String[] parts = line.split(" ", 2); // Split into command and optional arguments
            String command = parts[0];
            Map<String, String> params = new HashMap<>();

            if (parts.length > 1) {
                String[] argPairs = parts[1].split(", ");
                for (String argPair : argPairs) {
                    String[] kv = argPair.split("=", 2);
                    if (kv.length == 2) {
                        params.put(kv[0].trim(), kv[1].trim());
                    }
                }
            }

            String result = "";
            try {
                switch (command) {
                    case "book":
                        String roomNameBook = params.get("room");
                        String userNameBook = params.get("user");
                        String dateStrBook = params.get("date");
                        String timeRangeBook = params.get("time");
                        
                        if (roomNameBook == null || userNameBook == null || dateStrBook == null || timeRangeBook == null) {
                            result = "Error: Missing parameters for book command. Required: room, user, date, time.";
                        } else {
                            result = bookingService.bookRoom(roomNameBook, userNameBook, dateStrBook, timeRangeBook);
                        }
                        break;

                    case "cancel":
                        String bookingIdToCancel = params.get("booking");
                        if (bookingIdToCancel == null) {
                            result = "Error: Missing booking ID for cancel command. Required: booking.";
                        } else {
                            result = bookingService.cancelBooking(bookingIdToCancel);
                        }
                        break;

                    case "get_availability":
                        String roomNameAvail = params.get("room");
                        String dateStrAvail = params.get("date");
                        if (roomNameAvail == null || dateStrAvail == null) {
                            result = "Error: Missing parameters for get_availability command. Required: room, date.";
                        } else {
                            result = bookingService.getAvailability(roomNameAvail, dateStrAvail);
                        }
                        break;

                    default:
                        result = "Unknown command: " + command;
                        break;
                }
            } catch (Exception e) {
                // Catch any exceptions from the user's code to prevent crash and provide feedback
                result = "Error processing command '" + command + "': " + e.getClass().getSimpleName() + ": " + e.getMessage();
            }
            System.out.println(result);
        }
        scanner.close();
    }
