-- oop_040: Supply Chain Shipment Tracker
UPDATE challenges SET
  test_harness = $harness$import sys

def run_harness():
    # Instantiate the user's Service class once.
    # This class is expected to manage shipments and expose the required methods.
    tracker_service = Service()

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        parts = line.split(" ", 1)
        command = parts[0]
        args_str = parts[1] if len(parts) > 1 else ""

        # Parse arguments into a dictionary
        args = {}
        # Arguments are separated by ", "
        # Each argument is key=value
        for arg_pair in args_str.split(", "):
            if "=" in arg_pair:
                key, value = arg_pair.split("=", 1)
                args[key] = value

        result = None # Initialize result to None for each command

        try:
            if command == "create_shipment":
                # Expected arguments: id, origin, destination
                shipment_id = args["id"]
                origin = args["origin"]
                destination = args["destination"]
                result = tracker_service.create_shipment(shipment_id, origin, destination)
            elif command == "update_milestone":
                # Expected arguments: shipment, milestone
                shipment_id = args["shipment"]
                milestone = args["milestone"]
                result = tracker_service.update_milestone(shipment_id, milestone)
            elif command == "get_status":
                # Expected arguments: shipment
                shipment_id = args["shipment"]
                result = tracker_service.get_status(shipment_id)
            elif command == "alert":
                # The specific test case `alert delay=SHP001, days=3` implies
                # 'delay' is a key in args, and its value is the shipment ID.
                # 'days' is another key.
                if "delay" in args and "days" in args:
                    shipment_id = args["delay"]
                    days = int(args["days"]) # days should be an integer
                    result = tracker_service.alert_delay(shipment_id, days)
                else:
                    result = "Error: Invalid alert command format. Expected 'alert delay=<id>, days=<num>'."
            else:
                result = f"Error: Unknown command '{command}'."
        except KeyError as e:
            # Catch cases where required arguments are missing
            result = f"Error: Missing argument {e} for command '{command}'."
        except ValueError as e:
            # Catch cases like invalid integer conversion for 'days'
            result = f"Error: Invalid value for an argument: {e}."
        except AttributeError as e:
            # Catch if the user's Service class doesn't have the expected method
            result = f"Error: Service class method not found or incorrect signature: {e}. Did you implement all required methods (create_shipment, update_milestone, get_status, alert_delay)?"
        except Exception as e:
            # Catch any other unexpected errors
            result = f"An unexpected error occurred during command '{command}': {e}"

        # Print the result if one was generated (i.e., not None)
        if result is not None:
            print(result)

# Call the harness function at module level
run_harness()$harness$,
