-- oop_041: Online Course Enrollment System
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // Anticipate user's classes: Student, Course, CourseEnrollmentService.
  // User's Student and Course classes are expected to extend Entity and have a 'name' property
  // in their constructor and as a public field for identification.
  // User's CourseEnrollmentService is expected to extend Service and implement the core enrollment logic.
  // It should have methods like `enrollStudent`, `completeCourse`, `getStudentCourseProgress`
  // that return specific strings for output.

  // State management for students and courses (managed by the harness).
  // Enrollments and their specific state (progress, completion) are expected to be managed
  // internally by the user's CourseEnrollmentService instance.
  const students = new Map<string, Student>(); // Key: student name
  const courses = new Map<string, Course>();   // Key: course name
  
  // Instantiate the user's service class once per test run.
  const service = new CourseEnrollmentService(); 

  for (const line of lines) {
    if (line === '') continue; // Skip empty lines

    // Split command and arguments. Handles 'key=value' and 'key=value, key2=value2'
    const parts = line.split(/, | /).filter(p => p !== ''); 
    const command = parts[0];
    const args: { [key: string]: string } = {};

    for (let i = 1; i < parts.length; i++) {
      const [key, value] = parts[i].split('=');
      if (key && value) {
        args[key.toLowerCase()] = value.trim();
      }
    }

    let output = '';

    try {
      switch (command) {
        case 'add_student': {
          const studentName = args['name'];
          if (!studentName) throw new Error("Missing student name.");
          if (students.has(studentName)) {
            output = `Error: Student ${studentName} already exists.`;
          } else {
            // Assumes user implements `class Student extends Entity { constructor(public name: string) { super(); } }`
            const student = new Student(studentName);
            students.set(studentName, student);
            output = `Student ${studentName} added.`;
          }
          break;
        }
        case 'add_course': {
          const courseName = args['name'];
          if (!courseName) throw new Error("Missing course name.");
          if (courses.has(courseName)) {
            output = `Error: Course ${courseName} already exists.`;
          } else {
            // Assumes user implements `class Course extends Entity { constructor(public name: string) { super(); } }`
            const course = new Course(courseName);
            courses.set(courseName, course);
            output = `Course ${courseName} added.`;
          }
          break;
        }
        case 'enroll': {
          const studentName = args['student'];
          const courseName = args['course'];
          if (!studentName || !courseName) throw new Error("Missing student or course name for enrollment.");

          const student = students.get(studentName);
          const course = courses.get(courseName);

          if (!student) {
            output = `Error: Student ${studentName} not found.`;
          } else if (!course) {
            output = `Error: Course ${courseName} not found.`;
          } else {
            // Assumes user implements `service.enrollStudent(student: Student, course: Course): string`
            output = service.enrollStudent(student, course);
          }
          break;
        }
        case 'complete': {
          const studentName = args['student'];
          const courseName = args['course'];
          if (!studentName || !courseName) throw new Error("Missing student or course name for completion.");

          const student = students.get(studentName);
          const course = courses.get(courseName);

          if (!student) {
            output = `Error: Student ${studentName} not found.`;
          } else if (!course) {
            output = `Error: Course ${courseName} not found.`;
          } else {
            // Assumes user implements `service.completeCourse(student: Student, course: Course): string`
            output = service.completeCourse(student, course);
          }
          break;
        }
        case 'get_progress': {
          const studentName = args['student'];
          const courseName = args['course'];
          if (!studentName || !courseName) throw new Error("Missing student or course name for progress.");

          const student = students.get(studentName);
          const course = courses.get(courseName);

          if (!student) {
            output = `Error: Student ${studentName} not found.`;
          } else if (!course) {
            output = `Error: Course ${courseName} not found.`;
          } else {
            // Assumes user implements `service.getStudentCourseProgress(student: Student, course: Course): string`
            output = service.getStudentCourseProgress(student, course);
          }
          break;
        }
        default:
          output = `Error: Unknown command "${command}"`;
      }
    } catch (e: any) {
      // Catch errors thrown by the user's implementation or harness itself
      output = `Error: ${e.message}`;
    }

    if (output) {
      console.log(output);
    }
  }
});$harness$,
  test_cases   = '[{"input": "add_student name=alice\nadd_course name=Python101\nenroll student=alice, course=Python101", "description": "Enroll in course", "expected_output": "Student alice added.\nCourse Python101 added.\nalice enrolled in Python101"}, {"input": "add_student name=alice\nadd_course name=Python101\nenroll student=alice, course=Python101\nenroll student=alice, course=Python101", "description": "Duplicate enrollment error", "expected_output": "Student alice added.\nCourse Python101 added.\nalice enrolled in Python101\nError: alice already enrolled in Python101"}, {"input": "add_student name=alice\nadd_course name=Python101\nenroll student=alice, course=Python101\ncomplete student=alice, course=Python101", "description": "Complete course", "expected_output": "Student alice added.\nCourse Python101 added.\nalice enrolled in Python101\nalice completed Python101, certificate issued"}, {"input": "add_student name=alice\nadd_course name=Python101\nenroll student=alice, course=Python101\nget_progress student=alice, course=Python101", "description": "Get course progress", "expected_output": "Student alice added.\nCourse Python101 added.\nalice enrolled in Python101\nalice Python101 progress: 60% complete"}, {"input": "add_student name=bob\nadd_course name=Java202\nenroll student=bob, course=Java202\nget_progress student=bob, course=Java202\ncomplete student=bob, course=Java202\nget_progress student=bob, course=Java202", "description": "Enroll, check progress, complete, check progress again", "expected_output": "Student bob added.\nCourse Java202 added.\nbob enrolled in Java202\nbob Java202 progress: 0% complete\nbob completed Java202, certificate issued\nbob Java202 progress: 100% complete"}, {"input": "add_student name=charlie\nget_progress student=charlie, course=NonExistent", "description": "Attempt to get progress for non-existent course", "expected_output": "Student charlie added.\nError: Course NonExistent not found."}, {"input": "add_course name=WebDev101\nenroll student=NonExistentStudent, course=WebDev101", "description": "Attempt to enroll non-existent student", "expected_output": "Course WebDev101 added.\nError: Student NonExistentStudent not found."}]'::jsonb
