-- oop_042: Library Fine Calculator
UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.HashMap;
import java.util.Map;

// The user's Entity and Service classes will be concatenated here.
// They are assumed to exist when this Main class is compiled.

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        // Instantiate the user's Service class.
        // Assuming the user implements all library fine calculation logic within this class.
        Service libraryService = new Service(); 

        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String[] parts = line.split(" ", 2); // Split command from arguments
            String command = parts[0];
            Map<String, String> argsMap = new HashMap<>();

            if (parts.length > 1) {
                // Split arguments by ", " then by "="
                String[] params = parts[1].split(", ");
                for (String param : params) {
                    String[] kv = param.split("=", 2);
                    if (kv.length == 2) {
                        argsMap.put(kv[0], kv[1]);
                    }
                }
            }

            String result = "";
            try {
                switch (command) {
                    case "checkout":
                        String checkoutBook = argsMap.get("book");
                        String checkoutUser = argsMap.get("user");
                        String checkoutDue = argsMap.get("due");
                        // Call the user's service method
                        result = libraryService.checkoutBook(checkoutBook, checkoutUser, checkoutDue);
                        break;
                    case "return":
                        String returnBook = argsMap.get("book");
                        String returnUser = argsMap.get("user");
                        String returnedDate = argsMap.get("returned");
                        // Call the user's service method
                        result = libraryService.returnBook(returnBook, returnUser, returnedDate);
                        break;
                    case "get_fines":
                        String finesUser = argsMap.get("user");
                        // Call the user's service method
                        result = libraryService.getFines(finesUser);
                        break;
                    case "pay_fine":
                        String payUser = argsMap.get("user");
                        // Ensure amount is parsed correctly, handles "3.00"
                        double payAmount = Double.parseDouble(argsMap.get("amount"));
                        // Call the user's service method
                        result = libraryService.payFine(payUser, payAmount);
                        break;
                    default:
                        result = "Unknown command: " + command;
                        break;
                }
            } catch (Exception e) {
                // Catch any exceptions from user's code and report them
                result = "Error processing command '" + command + "': " + e.getMessage();
            }
            System.out.println(result);
        }
        sc.close();
    }
}$harness$,
  test_cases   = '[{"input": "checkout book=Design Patterns, user=alice, due=2024-07-30", "description": "Checkout book", "expected_output": "Book checked out: Design Patterns for alice, due 2024-07-30"}, {"input": "checkout book=Design Patterns, user=alice, due=2024-07-30\nreturn book=Design Patterns, user=alice, returned=2024-08-05", "description": "Late return fine", "expected_output": "Book checked out: Design Patterns for alice, due 2024-07-30\nBook returned 6 days late, fine: $3.00"}, {"input": "checkout book=Design Patterns, user=alice, due=2024-07-30\nreturn book=Design Patterns, user=alice, returned=2024-08-05\nget_fines user=alice", "description": "Get user fines", "expected_output": "Book checked out: Design Patterns for alice, due 2024-07-30\nBook returned 6 days late, fine: $3.00\nalice outstanding fines: $3.00"}, {"input": "checkout book=Design Patterns, user=alice, due=2024-07-30\nreturn book=Design Patterns, user=alice, returned=2024-08-05\npay_fine user=alice, amount=3.00", "description": "Pay library fine", "expected_output": "Book checked out: Design Patterns for alice, due 2024-07-30\nBook returned 6 days late, fine: $3.00\nFine paid: $3.00. alice balance: $0.00"}, {"input": "checkout book=Clean Code, user=bob, due=2024-08-01\nreturn book=Clean Code, user=bob, returned=2024-08-01\nget_fines user=bob", "description": "On-time return no fine, get fines check", "expected_output": "Book checked out: Clean Code for bob, due 2024-08-01\nBook returned on time, fine: $0.00\nbob outstanding fines: $0.00"}, {"input": "checkout book=The Pragmatic Programmer, user=charlie, due=2024-08-10\nreturn book=The Pragmatic Programmer, user=charlie, returned=2024-08-05\nget_fines user=charlie", "description": "Early return no fine, get fines check", "expected_output": "Book checked out: The Pragmatic Programmer for charlie, due 2024-08-10\nBook returned on time, fine: $0.00\ncharlie outstanding fines: $0.00"}]'::jsonb
