-- oop_044: Theater Seat Reservation
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

const lines: string[] = [];

rl.on('line', (line) => {
    lines.push(line.trim());
});

rl.on('close', () => {
    // Instantiate the user's service class.
    // We assume the user creates a class named 'TheaterService' which extends 'Service'.
    const theaterService = new TheaterService();

    for (const line of lines) {
        if (!line) continue; // Skip empty lines

        // Split the line into command and argument string
        const parts = line.split(' ');
        const command = parts[0];
        const argsString = parts.slice(1).join(' '); // All parts after the command

        const params: { [key: string]: string } = {};
        // Parse key=value pairs from the argsString
        argsString.split(',').forEach(arg => {
            const trimmedArg = arg.trim();
            const eqIndex = trimmedArg.indexOf('=');
            if (eqIndex > -1) {
                const key = trimmedArg.substring(0, eqIndex).trim();
                const value = trimmedArg.substring(eqIndex + 1).trim();
                if (key) {
                    params[key] = value;
                }
            }
        });

        let result: string | null = null;

        try {
            switch (command) {
                case 'add_show':
                    if (params.name && params.capacity) {
                        result = theaterService.addShow(params.name, parseInt(params.capacity, 10));
                    } else {
                        result = `Error: Missing name or capacity for add_show command.`;
                    }
                    break;
                case 'reserve':
                    if (params.seat && params.user && params.show) {
                        result = theaterService.reserveSeat(params.seat, params.user, params.show);
                    } else {
                        result = `Error: Missing seat, user, or show for reserve command.`;
                    }
                    break;
                case 'cancel_reservation':
                    if (params.seat && params.show) {
                        result = theaterService.cancelReservation(params.seat, params.show);
                    } else {
                        result = `Error: Missing seat or show for cancel_reservation command.`;
                    }
                    break;
                case 'get_available_seats':
                    if (params.show) {
                        result = theaterService.getAvailableSeats(params.show);
                    } else {
                        result = `Error: Missing show for get_available_seats command.`;
                    }
                    break;
                default:
                    result = `Unknown command: ${command}`;
                    break;
            }
        } catch (e: any) {
            result = `Error executing command '${command}': ${e.message}`;
