        line = line.strip()
        if not line:
            continue

        parts = line.split(' ', 1)
        command_type = parts[0]
        args_str = parts[1] if len(parts) > 1 else ""

        args = {}
        # Parse arguments in 'key=value, key2=value2' format
        for arg_pair in args_str.split(','):
            arg_pair = arg_pair.strip()
            if '=' in arg_pair:
                key, value = arg_pair.split('=', 1)
                args[key.strip()] = value.strip()

        result = None
        try:
            if command_type == "register":
                device_name = args.get('device')
                room_name = args.get('room')
                if device_name and room_name:
                    # User's Service.register_device is expected to create and store the appropriate Entity subclass
                    result = controller.register_device(device_name, room_name)
                else:
                    result = "Error: 'register' command requires 'device' and 'room'."

            elif command_type == "command":
                device_name = args.get('device')
                action = args.get('action')
                if device_name and action:
                    # Pass other args (like 'value' for brightness) as keyword arguments
                    command_kwargs = {k: v for k, v in args.items() if k not in ['device', 'action']}
                    result = controller.command_device(device_name, action, **command_kwargs)
                else:
                    result = "Error: 'command' requires 'device' and 'action'."

            elif command_type == "scene":
                activate_scene_name = args.get('activate')
                if activate_scene_name:
                    # User's Service.activate_scene is expected to perform scene actions
                    # and return a summary string.
                    result = controller.activate_scene(activate_scene_name)
                else:
                    result = "Error: 'scene' command requires 'activate'."

            elif command_type == "get_status":
                device_name = args.get('device')
                if device_name:
                    # User's Service.get_status is expected to query the device's state.
                    result = controller.get_status(device_name)
                else:
                    result = "Error: 'get_status' command requires 'device'."

            else:
                result = f"Unknown command: {command_type}"

        except Exception as e:
            # Catch any exceptions from user's code for robust execution
            result = f"Error processing command '{line}': {type(e).__name__}: {e}"

        # Print the result of each command
        if result is not None:
            print(result)

