        case 'get_project_progress': {
          const projectName = paramMap.get('project');
          if (projectName) {
            result = system.getProjectProgress(projectName);
          } else {
            result = "Error: Missing parameters for get_project_progress (project).";
          }
          break;
        }
        default:
          result = `Unknown command: ${command}`;
      }
    } catch (e: any) {
      // Catch any unhandled errors from user's implementation for better feedback
      result = `Error processing command '${command}': ${e.message}`;
    }

    // Print the result of each meaningful command.
    if (result !== undefined) {
      console.log(result);
    }
  });
