-- oop_051: Tax Filing System
UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.HashMap;
import java.util.Map;

public class Main {

    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        Service taxService = new Service(); // User's Service class instance

        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) continue;

            String[] parts = line.split(" ", 2);
            String command = parts[0];
            String argsString = parts.length > 1 ? parts[1] : "";

            Map<String, String> params = parseArgs(argsString);
            String userName;
            Entity taxpayer;

            try {
                switch (command) {
                    case "file_taxes":
                        userName = params.get("user");
                        double income = Double.parseDouble(params.get("income"));
                        double initialDeductions = Double.parseDouble(params.get("deductions"));
                        
                        taxpayer = taxService.getOrCreateEntity(userName);
                        taxService.processTaxFiling(taxpayer, income, initialDeductions);
                        
                        System.out.println("Taxable income: $" + (int) taxpayer.getTaxableIncome() + ", tax owed: $" + (int) taxpayer.getTaxOwed());
                        break;

                    case "apply_deduction":
                        userName = params.get("user"); // Assuming user is now a required parameter
                        String deductionType = params.get("type"); 
                        double deductionAmount = Double.parseDouble(params.get("amount"));
                        
                        taxpayer = taxService.getOrCreateEntity(userName);
                        taxpayer.addDeduction(deductionAmount); // Entity method to add deduction
                        taxService.updateTaxCalculation(taxpayer); // Recalculate tax after new deduction
                        
                        System.out.println("Deduction applied: $" + (int) deductionAmount + " " + deductionType);
                        break;

                    case "get_refund":
                        userName = params.get("user");
                        double withheld = Double.parseDouble(params.get("withheld"));
                        
                        taxpayer = taxService.getOrCreateEntity(userName);
                        double refund = taxService.calculateRefund(taxpayer, withheld);
                        
                        System.out.println("Refund: $" + (int) refund + " (withheld $" + (int) withheld + ", owed $" + (int) taxpayer.getTaxOwed() + ")");
                        break;

                    case "submit":
                        String returnId = params.get("return");
                        String[] returnParts = returnId.split("_");
                        userName = returnParts[0];
                        String year = returnParts.length > 1 ? returnParts[1] : "";
                        
                        taxpayer = taxService.getOrCreateEntity(userName);
                        taxpayer.setSubmitted(true); // Entity method to set submission status
                        
                        System.out.println("Tax return submitted for " + userName + (year.isEmpty() ? "" : " (" + year + ")"));
                        break;

                    default:
                        System.out.println("Unknown command: " + command);
                }
            } catch (NumberFormatException e) {
                System.out.println("Error: Invalid number format for command '" + command + "'. Details: " + e.getMessage());
            } catch (Exception e) {
                System.out.println("Error processing command '" + command + "': " + e.getMessage());
                // e.printStackTrace(); // For debugging in a real scenario
            }
        }
        sc.close();
    }

    // Helper method to parse arguments from command line
    private static Map<String, String> parseArgs(String argsString) {
        Map<String, String> params = new HashMap<>();
        if (argsString == null || argsString.isEmpty()) {
            return params;
        }
        String[] argPairs = argsString.split(", ");
        for (String pair : argPairs) {
            String[] keyValue = pair.split("=", 2);
            if (keyValue.length == 2) {
                params.put(keyValue[0].trim(), keyValue[1].trim());
            }
        }
        return params;
    }
}

// Minimal expected Entity class structure for the harness to interact with.
// User must implement this based on the challenge description.
class Entity {
    private String name;
    private double income;
    private double currentDeductions; // All deductions combined
    private double taxOwed;
    private boolean submitted;

    public Entity(String name) {
        this.name = name;
        this.income = 0;
        this.currentDeductions = 0;
        this.taxOwed = 0;
        this.submitted = false;
    }

    public String getName() { return name; }
    public double getIncome() { return income; }
    public void setIncome(double income) { this.income = income; }
    
    // Method to set all deductions for a new filing. Clears previous.
    public void setDeductions(double deductions) { this.currentDeductions = deductions; }
    // Method to add to existing deductions.
    public void addDeduction(double amount) { this.currentDeductions += amount; }
    public double getTotalDeductions() { return currentDeductions; }
    
    public double getTaxableIncome() { return income - currentDeductions; }
    public double getTaxOwed() { return taxOwed; }
    public void setTaxOwed(double taxOwed) { this.taxOwed = taxOwed; }
    public boolean isSubmitted() { return submitted; }
    public void setSubmitted(boolean submitted) { this.submitted = submitted; }
}

// Minimal expected Service class structure for the harness to interact with.
// User must implement this based on the challenge description.
import java.util.HashMap;
import java.util.Map;

class Service {
    private Map<String, Entity> entities;
    private static final double TAX_RATE = 0.15; // Derived from 9450 / 63000 in test case

    public Service() {
        this.entities = new HashMap<>();
    }

    public Entity getOrCreateEntity(String name) {
        return entities.computeIfAbsent(name, Entity::new);
    }

    // Handles the initial filing data and calculates tax
    public void processTaxFiling(Entity entity, double income, double initialDeductions) {
        entity.setIncome(income);
        entity.setDeductions(initialDeductions); // Sets the initial deductions, effectively clearing any prior ones for this filing context
        updateTaxCalculation(entity); // Calculate tax based on new income/deductions
    }

    // Recalculates tax based on current entity state (e.g., after adding a new deduction)
    public void updateTaxCalculation(Entity entity) {
        double taxableIncome = entity.getTaxableIncome();
        // Ensure taxable income doesn't go negative for tax calculation purposes.
        taxableIncome = Math.max(0, taxableIncome); 
        double taxOwed = taxableIncome * TAX_RATE;
        entity.setTaxOwed(taxOwed);
    }

    // Calculates refund based on tax owed and withheld amount
    public double calculateRefund(Entity entity, double withheldAmount) {
        return withheldAmount - entity.getTaxOwed();
    }
