# This function will parse a command line and extract the command and its arguments.
def parse_command_line(line):
    line = line.strip()
    if not line:
        return None, {}

    parts = line.split(' ', 1)
    command = parts[0]
    args_str = parts[1] if len(parts) > 1 else ""

    args = {}
    # Split arguments by comma. This assumes no commas within simple string values,
    # only within list elements (handled by value[1:-1].split(',')).
    arg_pairs = [arg.strip() for arg in args_str.split(',')] 

    for arg_pair in arg_pairs:
        if '=' in arg_pair:
            key, value = arg_pair.split('=', 1)
            key = key.strip()
            value = value.strip()

            if value.startswith('[') and value.endswith(']'):
                # For list values like stops=[Stop1, Stop2]
                # Handle empty list case: stops=[]
                if value[1:-1].strip() == '':
                    args[key] = []
                else:
                    items = [item.strip() for item in value[1:-1].split(',')]
                    args[key] = items
            elif key == 'minutes' and value.isdigit():
                args[key] = int(value)
            else:
                args[key] = value
    return command, args

def run_harness():
    # Instantiate the main scheduler object from the user's code.
    # This object will maintain the state across commands.
    try:
        scheduler = BusRouteScheduler()
    except NameError:
        print("Error: BusRouteScheduler class not found. Make sure you've defined it.")
        sys.exit(1)
    except Exception as e:
        print(f"Error initializing BusRouteScheduler: {e}")
        sys.exit(1)

    for line in sys.stdin:
        command, args = parse_command_line(line)
        result = None

        if not command:
            continue # Skip empty lines

        try:
            if command == "schedule":
                route_id = args.get("route")
                departure = args.get("departure")
                stops = args.get("stops") # Can be an empty list, so check for `is not None`
                if route_id and departure and stops is not None:
                    result = scheduler.schedule_route(route_id, departure, stops)
                else:
                    result = f"Error: Missing or invalid arguments for schedule command: {line.strip()}"
            elif command == "get_next_bus":
                stop_id = args.get("stop")
                route_id = args.get("route")
                if stop_id and route_id:
                    result = scheduler.get_next_bus(stop_id, route_id)
                else:
                    result = f"Error: Missing or invalid arguments for get_next_bus command: {line.strip()}"
            elif command == "delay":
                route_id = args.get("route")
                minutes = args.get("minutes")
                if route_id and minutes is not None:
                    result = scheduler.delay_route(route_id, minutes)
                else:
                    result = f"Error: Missing or invalid arguments for delay command: {line.strip()}"
            elif command == "get_route_status":
                route_id = args.get("route")
                if route_id:
                    result = scheduler.get_route_status(route_id)
                else:
                    result = f"Error: Missing or invalid arguments for get_route_status command: {line.strip()}"
            else:
                result = f"Error: Unknown command '{command}'"
        except AttributeError as e:
            result = f"Error: Method call failed - {e}. Ensure BusRouteScheduler has the required methods and they are callable."
        except Exception as e:
            result = f"An unexpected error occurred during command '{command}': {e}"
        
        if result is not None:
            print(result)

