d_output": "Route R10 scheduled: 0 stops, departs 10:00\nError: Stop Stop1 not on Route R10."}, {"input": "schedule route=R5, departure=08:00, stops=[Stop1, Stop2, Stop3]\nget_next_bus stop=NonExistent, route=R5", "description": "Attempt to get bus for a non-existent stop on an existing route", "expected_output": "Route R5 scheduled: 3 stops, departs 08:00\nError: Stop NonExistent not on Route R5."}, {"input": "delay route=R99, minutes=5", "description": "Attempt to delay a non-existent route", "expected_output": "Error: Route R99 not found."}, {"input": "get_route_status route=R999", "description": "Attempt to get status for a non-existent route", "expected_output": "Error: Route R999 not found."}, {"input": "schedule route=R_dup, departure=11:00, stops=[S1]\nschedule route=R_dup, departure=12:00, stops=[S2]", "description": "Attempt to schedule the same route twice", "expected_output": "Route R_dup scheduled: 1 stops, departs 11:00\nError: Route R_dup already scheduled."}]'::jsonb
