  posTerminal.addProduct("SKU003", "Generic Item C", 3.00);
  posTerminal.addProduct("SKU004", "Keyboard", 75.00);
  posTerminal.addProduct("SKU005", "Monitor", 300.00);

  // Seed discounts into the terminal's registry.
  // User's `Service` must implement `addPercentageDiscount` and `addFixedAmountDiscount` methods.
  // The description provided here will be the expected output string for `apply_discount` command.
  posTerminal.addPercentageDiscount("SAVE10", 0.10, "10% discount applied");
  posTerminal.addFixedAmountDiscount("FLAT5", 5.00, "$5 off coupon applied");

  for (const line of lines) {
    if (!line) continue; // Skip empty lines
