    paramsArr.forEach(p => {
      const [key, value] = p.split('=');
      if (key && value) {
        // Treat specific keys as strings, others as numbers if possible.
        params[key] = (key === 'method' || key === 'coupon' || key === 'item') ? value : Number(value);
      }
    });

    let output = '';
    try {
      switch (command) {
        case 'scan':
          // Assuming `posTerminal.scanItem(itemSku: string, quantity: number): string`
          // Expected output: "SKU<N> added to cart: $X.YY" where $X.YY is `product.price * quantity`
          if (typeof params.item === 'string' && typeof params.qty === 'number') {
            output = posTerminal.scanItem(params.item, params.qty);
          } else {
