        case 'apply_discount':
          // Assuming `posTerminal.applyDiscount(couponCode: string): string`
          // Expected output: The discount description provided during seeding (e.g., "10% discount applied")
          if (typeof params.coupon === 'string') {
            output = posTerminal.applyDiscount(params.coupon);
          } else {
            output = `Error: Invalid 'apply_discount' parameters. Expected 'coupon=<CODE>'`;
          }
          break;
        case 'process_payment':
          // Assuming `posTerminal.processPayment(method: string, amount: number): string`
          // Expected output: "Payment processed: $X.YY via <method>"
          if (typeof params.method === 'string' && typeof params.amount === 'number') {
            output = posTerminal.processPayment(params.method, params.amount);
          } else {
            output = `Error: Invalid 'process_payment' parameters. Expected 'method=<string>, amount=<number>'`;
          }
          break;
        case 'print_receipt':
          // Assuming `posTerminal.printReceipt(): string`
          // Expected output: "Receipt printed: X items, subtotal $Y.YY, discount -$Z.ZZ, total $W.WW"
          output = posTerminal.printReceipt();
          break;
        default:
          output = `Error: Unknown command "${command}"`;
      }
    } catch (e: any) {
      // Catch and log any errors thrown by the user's implementation
      output = `Runtime Error: ${e.message}`;
    }
    console.log(output);
  }
