-- oop_055: Appointment Booking Calendar
UPDATE challenges SET
  test_harness = $harness$import sys
import datetime

# Helper function to parse arguments from command line
def parse_args(arg_string):
    args = {}
    if arg_string:
        # Split by comma and then by the first equals sign
        for item in arg_string.split(', '):
            if '=' in item:
                key, value = item.split('=', 1)
                args[key.strip()] = value.strip()
    return args

def run_harness():
    try:
        # The user is expected to implement a CalendarManager class
        # This class will be responsible for managing appointments, providers, and users.
        booking_system = CalendarManager()
    except NameError:
        print("Error: User must define a 'CalendarManager' class.")
        sys.exit(1)
    except Exception as e:
        print(f"Error initializing CalendarManager: {type(e).__name__}: {str(e)}")
        sys.exit(1)

    # Map command prefixes to the corresponding handler methods on the booking_system object
    command_handlers = {
        "book appointment": booking_system.book_appointment,
        "cancel appointment": booking_system.cancel_appointment,
        "get_availability": booking_system.get_availability,
        "reschedule appointment": booking_system.reschedule_appointment,
    }

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        executed = False
        # Iterate over command keys, matching longer prefixes first to avoid partial matches
        for cmd_key_prefix in sorted(command_handlers.keys(), key=len, reverse=True):
            if line.startswith(cmd_key_prefix):
                # Extract arguments string after the command prefix
                args_str = line[len(cmd_key_prefix):].strip()
                args = parse_args(args_str)
                handler = command_handlers[cmd_key_prefix]

                result = None
                try:
                    # Dispatch to the appropriate method based on the command key
                    if cmd_key_prefix == "book appointment":
                        provider_name = args.get("provider")
                        user_name = args.get("user")
                        date_time_str = args.get("date")
                        if not all([provider_name, user_name, date_time_str]):
                            result = "Error: Missing arguments for book appointment. Required: provider, user, date."
                        else:
                            result = handler(provider_name, user_name, date_time_str)
                    elif cmd_key_prefix == "cancel appointment":
                        apt_id = args.get("appointment")
                        if not apt_id:
                            result = "Error: Missing appointment ID for cancel appointment. Required: appointment."
                        else:
                            result = handler(apt_id)
                    elif cmd_key_prefix == "get_availability":
                        provider_name = args.get("provider")
                        date_str = args.get("date")
                        if not all([provider_name, date_str]):
                            result = "Error: Missing arguments for get_availability. Required: provider, date."
                        else:
                            result = handler(provider_name, date_str)
                    elif cmd_key_prefix == "reschedule appointment":
                        apt_id = args.get("appointment")
                        new_time_str = args.get("new_time")
                        if not all([apt_id, new_time_str]):
                            result = "Error: Missing arguments for reschedule appointment. Required: appointment, new_time."
                        else:
                            result = handler(apt_id, new_time_str)
                    # No 'else' for unknown command here, as it's handled outside this block

                except Exception as e:
                    # Catch exceptions from user's code and report them clearly
                    result = f"Error executing command '{cmd_key_prefix}' with args {args}: {type(e).__name__}: {str(e)}"

                if result is not None:
                    print(result)
                executed = True
                break # Command handled, move to the next line from stdin

        if not executed:
            print(f"Error: Unknown command or invalid format for line: '{line}'")

# Call the harness function at module level as required
