const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {
  // Assuming the user implements a NewsletterService class that extends Service.
  // All user-defined classes (Entity, Service, and likely NewsletterService, NewsletterList, Subscriber) 
  // are available in this scope.
  const newsletterService = new NewsletterService();

  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    const parts = line.split(' ');
    const command = parts[0].toLowerCase();
    const args: { [key: string]: string } = {};

    // Parse arguments from the rest of the line
    if (parts.length > 1) {
      parts.slice(1).join(' ').split(',').forEach(arg => {
        const [key, value] = arg.split('=');
        if (key && value) {
          args[key.trim()] = value.trim();
        }
      });
    }

    let output: string | null = null;

    try {
      switch (command) {
        case 'subscribe':
          if (args.email && args.list) {
            output = newsletterService.subscribe(args.email, args.list);
          } else {
            output = 'Error: Missing email or list for subscribe command.';
          }
          break;
        case 'unsubscribe':
          if (args.email && args.list) {
            output = newsletterService.unsubscribe(args.email, args.list);
          } else {
            output = 'Error: Missing email or list for unsubscribe command.';
          }
          break;
        case 'send':
          // Prioritize 'list' as the target for sending, 'newsletter' seems to be content name if separate
          // Assuming sendNewsletter takes the list name to target subscribers.
          if (args.list) {
            output = newsletterService.sendNewsletter(args.list);
          } else {
            output = 'Error: Missing list for send command.';
          }
          break;
        case 'get_subscriber_count':
          if (args.list) {
            output = newsletterService.getSubscriberCount(args.list);
          } else {
            output = 'Error: Missing list for get_subscriber_count command.';
          }
          break;
        default:
          output = `Error: Unknown command "${command}"`;
      }
    } catch (e: any) {
      output = `Error executing command '${command}': ${e.message || e}`;
    }

    if (output !== null) {
      console.log(output);
    }
  }
