-- oop_058: Mortgage Application Processor
UPDATE challenges SET
  test_harness = $harness$import sys
import re

class Harness:
    def __init__(self):
        # Instantiate the user's main service class
        # We assume the user implements a class named MortgageApplicationService
        # inheriting from Service (or a similar top-level service).
        try:
            self.service = MortgageApplicationService()
        except NameError:
            print("Error: MortgageApplicationService class not found. Ensure it's defined and inherits from Service.", file=sys.stderr)
            sys.exit(1)

    def _parse_command(self, line):
        parts = line.strip().split(' ', 1)
        command = parts[0]
        args = {}
        if len(parts) > 1:
            arg_str = parts[1]
            for item in arg_str.split(','):
                if '=' in item:
                    key, value = item.split('=', 1)
                    args[key.strip()] = value.strip()
        return command, args

    def run(self):
        for line in sys.stdin:
            command, args = self._parse_command(line)
            output = ""

            try:
                if command == "apply":
                    loan = float(args['loan'])
                    term = int(args['term'].replace('years', ''))
                    rate = float(args['rate'].replace('%', ''))
                    income = float(args['income'])
                    
                    # Call user's service method. Assume it returns app_id and dti_ratio.
                    # The user's service is expected to generate app_id sequentially (e.g., MORT001, MORT002).
                    app_id, dti_ratio = self.service.submit_application(loan, term, rate, income)
                    output = f"Application submitted, DTI ratio: {dti_ratio:.0f}%. Application ID: {app_id}"

                elif command == "approve":
                    app_id = args['application']
                    loan_amount, annual_rate = self.service.approve_application(app_id)
                    output = f"Mortgage {app_id} approved: ${loan_amount:,.0f} at {annual_rate:.1f}%"

                elif command == "deny":
                    app_id = args['application']
                    reason = args['reason']
                    denial_reason = self.service.deny_application(app_id, reason)
                    output = f"Mortgage {app_id} denied: {denial_reason.replace('_', ' ')}"

                elif command == "get_monthly_payment":
                    loan = float(args['loan'])
                    rate = float(args['rate'].replace('%', ''))
                    term = int(args['term'])
                    monthly_payment = self.service.get_monthly_payment(loan, rate, term)
                    output = f"Monthly payment: ${monthly_payment:,.2f}"

                else:
                    output = f"Unknown command: {command}"

            except KeyError as e:
                output = f"Error: Missing required argument for '{command}' command: {e}"
            except ValueError as e:
                output = f"Error: Invalid value or format for '{command}' command: {e}"
            except AttributeError as e:
                output = f"Error: Method not found or invalid attribute access on service for '{command}': {e}"
            except Exception as e:
                # Catch any other unexpected errors from user's code
                output = f"Error processing command '{command}': {e}"
            
            print(output)

def run_harness():
    harness = Harness()
