const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // The user's Service class is expected to be defined and available.
  // It should have methods like:
  // addItem(sku: string, qty: number, reorderPoint: number): string;
  // updateQuantity(sku: string, newQty: number): string;
  // getReorderList(): string;
  // acknowledgeAlert(sku: string): string;
  const inventoryService = new Service();

  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    const parts = line.split(' ');
    const command = parts[0];
    const args = parts.slice(1).join(' '); // Rejoin the rest to simplify argument parsing

    let output: string | undefined;

    try {
      switch (command) {
        case 'add_item': {
          const skuMatch = args.match(/sku=([^,]+)/);
          const qtyMatch = args.match(/qty=(\d+)/);
          const reorderMatch = args.match(/reorder_point=(\d+)/);

          if (skuMatch && qtyMatch && reorderMatch) {
            const sku = skuMatch[1];
            const qty = parseInt(qtyMatch[1], 10);
            const reorderPoint = parseInt(reorderMatch[1], 10);
            output = inventoryService.addItem(sku, qty, reorderPoint);
          } else {
            output = `Error: Invalid add_item command format: ${line}`;
          }
          break;
        }
        case 'update_qty': {
          const skuMatch = args.match(/sku=([^,]+)/);
          const qtyMatch = args.match(/qty=(\d+)/);

          if (skuMatch && qtyMatch) {
            const sku = skuMatch[1];
            const qty = parseInt(qtyMatch[1], 10);
            output = inventoryService.updateQuantity(sku, qty);
          } else {
            output = `Error: Invalid update_qty command format: ${line}`;
          }
          break;
        }
        case 'get_reorder_list': {
          output = inventoryService.getReorderList();
          break;
        }
        case 'acknowledge_alert': {
          const skuMatch = args.match(/sku=([^,]+)/);

          if (skuMatch) {
            const sku = skuMatch[1];
            output = inventoryService.acknowledgeAlert(sku);
          } else {
            output = `Error: Invalid acknowledge_alert command format: ${line}`;
          }
          break;
        }
        default:
          output = `Error: Unknown command: ${command}`;
          break;
      }
    } catch (e: any) {
      output = `Error processing command '${command}': ${e.message}`;
    }

    if (output !== undefined) {
      console.log(output);
    }
  }
