-- oop_060: Customer Support Ticket Desk
UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.Map;
import java.util.HashMap;

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner scanner = new Scanner(System.in);
        // Create a single instance of the Service class
        Service service = new Service();

        while (scanner.hasNextLine()) {
            String line = scanner.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            // Split command name and parameters
            String[] parts = line.split(" ", 2);
            String command = parts[0];
            Map<String, String> params = new HashMap<>();

            if (parts.length > 1) {
                String[] paramPairs = parts[1].split(", ");
                for (String pair : paramPairs) {
                    String[] kv = pair.split("=", 2);
                    if (kv.length == 2) {
                        params.put(kv[0].trim(), kv[1].trim());
                    }
                }
            }

            String result = "";
            try {
                switch (command) {
                    case "create_ticket":
                        String user = params.get("user");
                        String issue = params.get("issue");
                        String priority = params.get("priority");
                        if (user == null || issue == null || priority == null) {
                            result = "Error: Missing parameters for create_ticket.";
                        } else {
                            result = service.createTicket(user, issue, priority);
                        }
                        break;
                    case "assign":
                        String ticketIdAssign = params.get("ticket");
                        String agent = params.get("agent");
                        if (ticketIdAssign == null || agent == null) {
                            result = "Error: Missing parameters for assign.";
                        } else {
                            result = service.assignTicket(ticketIdAssign, agent);
                        }
                        break;
                    case "resolve":
                        String ticketIdResolve = params.get("ticket");
                        String resolution = params.get("resolution");
                        if (ticketIdResolve == null || resolution == null) {
                            result = "Error: Missing parameters for resolve.";
                        } else {
                            result = service.resolveTicket(ticketIdResolve, resolution);
                        }
                        break;
                    case "escalate":
                        String ticketIdEscalate = params.get("ticket");
                        String levelStr = params.get("level");
                        if (ticketIdEscalate == null || levelStr == null) {
                            result = "Error: Missing parameters for escalate.";
                        } else {
                            try {
                                int level = Integer.parseInt(levelStr);
                                result = service.escalateTicket(ticketIdEscalate, level);
                            } catch (NumberFormatException e) {
                                result = "Error: Invalid level format for escalate.";
                            }
                        }
                        break;
                    default:
                        result = "Error: Unknown command '" + command + "'";
                        break;
                }
            } catch (Exception e) {
                result = "Runtime Error: " + e.getClass().getSimpleName() + ": " + e.getMessage();
            }
            System.out.println(result);
        }
        scanner.close();
    }
}$harness$,
  test_cases   = '[{"input": "create_ticket user=alice, issue=Login not working, priority=high", "description": "Create a single support ticket", "expected_output": "Ticket T001 created for alice (high priority)"}, {"input": "create_ticket user=alice, issue=Login not working, priority=high\nassign ticket=T001, agent=Support_Bob", "description": "Create and assign a ticket", "expected_output": "Ticket T001 created for alice (high priority)\nTicket T001 assigned to Support_Bob"}, {"input": "create_ticket user=alice, issue=Login not working, priority=high\nassign ticket=T001, agent=Support_Bob\nresolve ticket=T001, resolution=Password reset completed", "description": "Create, assign, and resolve a ticket", "expected_output": "Ticket T001 created for alice (high priority)\nTicket T001 assigned to Support_Bob\nTicket T001 resolved: Password reset completed"}, {"input": "create_ticket user=alice, issue=Login not working, priority=high\nassign ticket=T001, agent=Support_Bob\nescalate ticket=T001, level=2", "description": "Create, assign, and escalate a ticket", "expected_output": "Ticket T001 created for alice (high priority)\nTicket T001 assigned to Support_Bob\nTicket T001 escalated to level 2 support"}, {"input": "create_ticket user=diana, issue=Broken keyboard, priority=urgent\ncreate_ticket user=eve, issue=Software installation, priority=medium", "description": "Create multiple tickets to test ID generation", "expected_output": "Ticket T001 created for diana (urgent priority)\nTicket T002 created for eve (medium priority)"}, {"input": "assign ticket=T999, agent=ErrorAgent", "description": "Attempt to assign a non-existent ticket (error case)", "expected_output": "Error: Ticket T999 not found."}, {"input": "create_ticket user=frank, issue=Monitor flicker, priority=high\nresolve ticket=T001, resolution=Replaced cable\nescalate ticket=T001, level=3", "description": "Resolve then escalate a ticket", "expected_output": "Ticket T001 created for frank (high priority)\nTicket T001 resolved: Replaced cable\nTicket T001 escalated to level 3 support"}]'::jsonb
