-- oop_061: Movie Theater Showtime Manager
UPDATE challenges SET
  test_harness = $harness$import sys
import re
from datetime import datetime

def parse_params(param_string):
    params = {}
    if param_string:
        for p in param_string.split(', '):
            if '=' in p:
                key, value = p.split('=', 1)
                params[key.strip()] = value.strip()
    return params

def run_harness():
    # Instantiate the user's main Service class once.
    # This assumes the user's primary business logic object is named 'Service'.
    manager = Service() 
    
    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        parts = line.split(' ', 1)
        command = parts[0]
        param_string = parts[1] if len(parts) > 1 else ''
        params = parse_params(param_string)
        
        result = None
        try:
            if command == "add_showtime":
                movie = params.get("movie")
                time_str = params.get("time") # e.g., "2024-07-15 18:00"
                hall = params.get("hall")
                if not all([movie, time_str, hall]):
                    result = "Error: Missing parameters for add_showtime."
                else:
                    result = manager.add_showtime(movie, time_str, hall)
            elif command == "get_showtimes":
                movie = params.get("movie")
                date = params.get("date") # e.g., "2024-07-15"
                if not all([movie, date]):
                    result = "Error: Missing parameters for get_showtimes."
                else:
                    result = manager.get_showtimes(movie, date)
            elif command == "book":
                seat = params.get("seat")
                showtime_str = params.get("showtime") # e.g., "Inception 18:00"
                user = params.get("user")
                if not all([seat, showtime_str, user]):
                    result = "Error: Missing parameters for book."
                else:
                    # showtime_str needs to be split into movie and time
                    # Assuming format: "Movie Title HH:MM"
                    match = re.match(r"^(.*?)\s(\d{2}:\d{2})$", showtime_str)
                    if match:
                        movie_title_for_booking = match.group(1).strip()
                        time_for_booking = match.group(2).strip()
                        result = manager.book_seat(seat, movie_title_for_booking, time_for_booking, user)
                    else:
                        result = "Error: Invalid showtime format for booking."
            elif command == "cancel":
                booking_id = params.get("booking")
                if not booking_id:
                    result = "Error: Missing booking ID for cancel."
                else:
                    result = manager.cancel_booking(booking_id)
            else:
                result = f"Error: Unknown command '{command}'"
        except AttributeError as ae:
             # Catch specific AttributeError for better debug if user forgets methods
             result = f"Error: Method or attribute not found. Did you implement the required methods? Details: {ae}"
        except Exception as e:
            result = f"Error executing command '{command}': {e}"
        
        if result is not None:
            print(result)

# Call the harness function at the module level
