-- oop_062: Portfolio Risk Analyzer
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', async () => {
  function parseCommand(line: string): { command: string, args: Record<string, string> } {
    const parts = line.split(' ');
    const command = parts[0];
    const args: Record<string, string> = {};

    if (parts.length > 1) {
      const argString = parts.slice(1).join(' ').trim();
      argString.split(',').forEach(argPair => {
        const [key, value] = argPair.split('=').map(s => s.trim());
        if (key && value) {
          args[key] = value;
        }
      });
    }
    return { command, args };
  }

  // Instantiate the user's Service class. This will maintain state across commands.
  const portfolioService = new Service();

  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    const { command, args } = parseCommand(line);
    let result: string | null = null;

    try {
      switch (command) {
        case 'add_asset':
          if (!args['portfolio'] || !args['type'] || !args['ticker'] || !args['value'] || !args['risk']) {
            result = `Error: Missing arguments for add_asset command. Expected: portfolio, type, ticker, value, risk. Received: ${line}`;
            break;
          }
          const assetValue = parseInt(args['value']);
          if (isNaN(assetValue)) {
            result = `Error: Invalid value for asset value: ${args['value']}`;
            break;
          }
          result = portfolioService.addAsset(args['portfolio'], args['type'], args['ticker'], assetValue, args['risk']);
          break;

        case 'calculate_var':
          if (!args['portfolio'] || !args['confidence']) {
            result = `Error: Missing arguments for calculate_var command. Expected: portfolio, confidence. Received: ${line}`;
            break;
          }
          const confidence = parseInt(args['confidence'].replace('%', ''));
          if (isNaN(confidence)) {
            result = `Error: Invalid value for confidence: ${args['confidence']}`;
            break;
          }
          result = portfolioService.calculateVaR(args['portfolio'], confidence);
          break;

        case 'get_diversification':
          if (!args['portfolio']) {
            result = `Error: Missing portfolio argument for get_diversification command. Expected: portfolio. Received: ${line}`;
            break;
          }
          result = portfolioService.getDiversification(args['portfolio']);
          break;

        case 'stress_test':
          if (!args['portfolio'] || !args['scenario']) {
            result = `Error: Missing arguments for stress_test command. Expected: portfolio, scenario. Received: ${line}`;
            break;
          }
          result = portfolioService.stressTest(args['portfolio'], args['scenario']);
          break;

        default:
          result = `Error: Unknown command "${command}"`;
          break;
      }
    } catch (e: any) {
      result = `Error executing command "${command}": ${e.message || e}`;
    }

    if (result !== null) {
      console.log(result);
    }
  }
});$harness$,
  test_cases   = '[{"input": "add_asset portfolio=P001, type=stock, ticker=AAPL, value=10000, risk=medium", "description": "Add single asset to portfolio", "expected_output": "AAPL added to portfolio P001: $10,000 medium risk"}, {"input": "add_asset portfolio=P001, type=stock, ticker=AAPL, value=6000, risk=medium\nadd_asset portfolio=P001, type=bond, ticker=GOVT, value=3000, risk=low\nadd_asset portfolio=P001, type=cash, ticker=CASH, value=1000, risk=very_low\ncalculate_var portfolio=P001, confidence=95%", "description": "Calculate Value at Risk for a diversified portfolio", "expected_output": "AAPL added to portfolio P001: $6,000 medium risk\nGOVT added to portfolio P001: $3,000 low risk\nCASH added to portfolio P001: $1,000 very_low risk\nVaR at 95%: $850 (portfolio $10,000)"}, {"input": "add_asset portfolio=P001, type=stock, ticker=AAPL, value=6000, risk=medium\nadd_asset portfolio=P001, type=bond, ticker=GOVT, value=3000, risk=low\nadd_asset portfolio=P001, type=cash, ticker=CASH, value=1000, risk=very_low\nget_diversification portfolio=P001", "description": "Check diversification for a portfolio", "expected_output": "AAPL added to portfolio P001: $6,000 medium risk\nGOVT added to portfolio P001: $3,000 low risk\nCASH added to portfolio P001: $1,000 very_low risk\nPortfolio P001 diversification: 60% stocks, 30% bonds, 10% cash"}, {"input": "add_asset portfolio=P001, type=stock, ticker=AAPL, value=6000, risk=medium\nadd_asset portfolio=P001, type=bond, ticker=GOVT, value=3000, risk=low\nadd_asset portfolio=P001, type=cash, ticker=CASH, value=1000, risk=very_low\nstress_test portfolio=P001, scenario=2008_crash", "description": "Stress test a portfolio under a specific scenario", "expected_output": "AAPL added to portfolio P001: $6,000 medium risk\nGOVT added to portfolio P001: $3,000 low risk\nCASH added to portfolio P001: $1,000 very_low risk\nStress test P001: portfolio loses 35% in 2008 scenario"}]'::jsonb
