        } else {
          output = "Error: Missing product ID for get_average_rating.";
        }
        break;

      case 'filter_reviews':
        const filterProductId = params['product'];
        const minRating = parseInt(params['min_rating']);
        if (filterProductId && !isNaN(minRating)) {
          output = reviewService.filterReviews(filterProductId, minRating);
        } else {
          output = "Error: Missing or invalid parameters for filter_reviews.";
        }
        break;

      case 'flag_review':
        // The reviewId (e.g., 'R001') is expected to be managed and understood by the user's ReviewService.
        const reviewId = params['review']; 
        const reason = params['reason'];
        if (reviewId && reason) {
          output = reviewService.flagReview(reviewId, reason);
        } else {
          output = "Error: Missing or invalid parameters for flag_review.";
        }
        break;

      default:
        output = `Unknown command: ${command}`;
        break;
    }

    if (output !== null) {
      console.log(output);
    }
  }
