        # If `Service` requires constructor arguments, or if the user uses a different
        # main class name, this would need adjustment. For this challenge, assuming
        # Service() without args is the most common and robust approach given the starter.
        portal_system = Service() 
    except TypeError as e:
        print(f"Error: Could not instantiate Service class. It might be an Abstract Base Class (ABC) or require specific constructor arguments. Details: {e}")
        return
    except Exception as e:
        print(f"Error during system initialization: {e}")
        return

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        try:
            # Parse command and parameters
            parts = line.split(" ", 1)
            command_name = parts[0]
            params_str = parts[1] if len(parts) > 1 else ""

            params = {}
            if params_str:
                for param_pair in params_str.split(", "):
                    key_value = param_pair.split("=", 1)
                    if len(key_value) == 2:
                        key = key_value[0].strip()
                        value = key_value[1].strip()
                        params[key] = value
            
            result = ""
            # Dispatch commands to the portal_system object
            if command_name == "create_account":
                user = params["user"]
                utility = params["utility"]
                result = portal_system.create_account(user, utility)
            elif command_name == "generate_bill":
                user = params["user"]
                usage = params["usage"] # e.g., "350kWh"
                result = portal_system.generate_bill(user, usage)
            elif command_name == "process_payment":
                user = params["user"]
                amount = float(params["amount"]) # Amounts are typically floats
                result = portal_system.process_payment(user, amount)
            elif command_name == "get_usage_history":
                user = params["user"]
                result = portal_system.get_usage_history(user)
            else:
                result = f"Error: Unknown command '{command_name}'"
            
            print(result)

        except KeyError as e:
            print(f"Error: Missing parameter for command '{command_name}'. Required: {e}. Full command: '{line}'")
        except ValueError as e:
            print(f"Error: Invalid value format for a parameter in command '{command_name}'. Details: {e}. Full command: '{line}'")
        except AttributeError:
            # This handles cases where methods like create_account are not found on portal_system
            print(f"Error: Method '{command_name}' not found or not callable on the system object. Please ensure your 'Service' class (or its relevant subclass) implements this method correctly. Full command: '{line}'")
        except Exception as e:
            print(f"An unexpected error occurred while processing command '{line}': {type(e).__name__}: {e}")

