-- oop_068: Software License Manager
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // Assume the user's primary license management class is named 'Service'
  // and instances of this class handle all license operations.
  const manager = new Service();

  for (const line of lines) {
    if (line === '') continue; // Skip empty lines

    const parts = line.split(' ');
    const command = parts[0];
    const params: { [key: string]: string } = {};

    // Parse command parameters (e.g., 'key=LIC001, product=DesignTool')
    if (parts.length > 1) {
      parts[1].split(',').forEach(param => {
        const [key, value] = param.split('=').map(s => s.trim());
        if (key && value) {
          params[key] = value;
        }
      });
    }

    let result: string | undefined;

    try {
      switch (command) {
        case 'issue_license':
          {
            const { key, product, user, type } = params;
            // Expected user method signature: issueLicense(key: string, product: string, user: string, type: string): boolean;
            // Returns `true` on successful issuance, `false` otherwise (e.g., duplicate key).
            const success = (manager as any).issueLicense(key, product, user, type);
            if (success) {
              result = `License issued: ${user} ${product} ${type}`;
            } else {
              result = `Failed to issue license for ${product} to ${user}`;
            }
          }
          break;

        case 'validate_license':
          {
            const { key } = params;
            // Expected user method signature: validateLicense(key: string): { isValid: boolean; type?: 'annual' | 'perpetual' | 'monthly'; expires?: string; };
            // For annual licenses, 'expires' should be '2024-12-31' for consistency with tests.
            // For perpetual licenses, 'type' should be 'perpetual'.
            const validationResult = (manager as any).validateLicense(key);
            if (validationResult && validationResult.isValid) {
              if (validationResult.type === 'perpetual') {
                result = `License ${key} valid, perpetual`;
              } else if (validationResult.expires) {
                result = `License ${key} valid, expires ${validationResult.expires}`;
              } else {
                // Fallback for valid licenses if type/expires info is missing
                result = `License ${key} valid`;
              }
            } else {
              result = `License ${key} invalid`;
            }
          }
          break;

        case 'expire_license':
          {
            const { key } = params;
            // Expected user method signature: expireLicense(key: string): boolean;
            // Returns `true` on successful expiration, `false` if license not found or already expired.
            const success = (manager as any).expireLicense(key);
            if (success) {
              result = `License ${key} expired`;
            } else {
              result = `Failed to expire license: ${key}`;
            }
          }
          break;

        case 'transfer_license':
          {
            const { key, from, to } = params;
            // Expected user method signature: transferLicense(key: string, fromUser: string, toUser: string): boolean;
            // Returns `true` on successful transfer, `false` if license not found or transfer conditions not met.
            const success = (manager as any).transferLicense(key, from, to);
            if (success) {
              result = `License ${key} transferred from ${from} to ${to}`;
            } else {
              result = `Failed to transfer license: ${key}`;
            }
          }
          break;

        default:
          result = `Unknown command: ${command}`;
      }
    } catch (e: any) {
      // Catch any unhandled errors from user's implementation
      result = `Error processing command '${command}': ${e.message}`;
    }

    if (result !== undefined) {
      console.log(result);
    }
  }
});$harness$,
  test_cases   = '[{"input": "issue_license key=LIC001, product=DesignTool, user=alice, type=annual\nvalidate_license key=LIC001", "description": "Issue and validate an annual software license", "expected_output": "License issued: alice DesignTool annual\nLicense LIC001 valid, expires 2024-12-31"}, {"input": "issue_license key=LIC002, product=AnotherTool, user=bob, type=perpetual\nvalidate_license key=LIC002", "description": "Issue and validate a perpetual software license", "expected_output": "License issued: bob AnotherTool perpetual\nLicense LIC002 valid, perpetual"}, {"input": "issue_license key=LIC003, product=DevSuite, user=charlie, type=annual\nexpire_license key=LIC003\nvalidate_license key=LIC003", "description": "Expire a license and then validate its status", "expected_output": "License issued: charlie DevSuite annual\nLicense LIC003 expired\nLicense LIC003 invalid"}, {"input": "issue_license key=LIC004, product=OfficeApp, user=david, type=annual\ntransfer_license key=LIC004, from=david, to=eve\nvalidate_license key=LIC004", "description": "Transfer a license to a new user and then validate it", "expected_output": "License issued: david OfficeApp annual\nLicense LIC004 transferred from david to eve\nLicense LIC004 valid, expires 2024-12-31"}, {"input": "validate_license key=NONEXISTENT", "description": "Attempt to validate a non-existent license", "expected_output": "License NONEXISTENT invalid"}, {"input": "expire_license key=NONEXISTENT", "description": "Attempt to expire a non-existent license", "expected_output": "Failed to expire license: NONEXISTENT"}, {"input": "transfer_license key=NONEXISTENT, from=x, to=y", "description": "Attempt to transfer a non-existent license", "expected_output": "Failed to transfer license: NONEXISTENT"}, {"input": "issue_license key=LIC005, product=ToolX, user=frank, type=annual\nissue_license key=LIC005, product=ToolY, user=grace, type=perpetual", "description": "Attempt to issue a license with a duplicate key (should fail second attempt)", "expected_output": "License issued: frank ToolX annual\nFailed to issue license for ToolY to grace"}]'::jsonb
