            try {
                switch (command) {
                    case "add_donation":
                        // blood_type=O+, units=2, donor=Alice
                        String addBloodType = params.get("blood_type");
                        int addUnits = Integer.parseInt(params.get("units"));
                        String donorName = params.get("donor");
                        result = bloodBankService.addDonation(addBloodType, addUnits, donorName);
                        break;
                    case "request":
                        // blood_type=AB-, units=1, hospital=Memorial
                        String reqBloodType = params.get("blood_type");
                        int reqUnits = Integer.parseInt(params.get("units"));
                        String hospitalName = params.get("hospital");
                        result = bloodBankService.requestBlood(reqBloodType, reqUnits, hospitalName);
                        break;
                    case "get_inventory":
                        // blood_type=O+
                        String invBloodType = params.get("blood_type");
                        result = bloodBankService.getInventory(invBloodType);
                        break;
                    case "low_inventory":
                        // threshold=5
                        int threshold = Integer.parseInt(params.get("threshold"));
                        result = bloodBankService.getLowInventory(threshold);
                        break;
                    case "initialize_inventory": // Custom command for testing setup
                        // inventory_data=O+=10,A+=5,B-=2
                        String inventoryData = params.get("inventory_data");
                        result = bloodBankService.initializeInventory(inventoryData != null ? inventoryData : "");
                        break;
                    default:
                        result = "Unknown command: " + command;
                        break;
                }
            } catch (NumberFormatException e) {
                result = "Error: Invalid number format for units or threshold: " + e.getMessage();
            } catch (IllegalArgumentException e) {
                result = "Error: " + e.getMessage();
            } catch (Exception e) {
                result = "An unexpected error occurred: " + e.getClass().getSimpleName() + ": " + e.getMessage();
            }
            System.out.println(result);
        }
        sc.close();
    }
