-- oop_070: Parking Fine Processor
UPDATE challenges SET
  test_harness = $harness$import sys

# User's classes (Entity, Service, ParkingFineService, Fine, Vehicle etc.) will be appended here.

# It's assumed the user implements a ParkingFineService class that inherits from Service,
# and other entity classes like Fine that inherit from Entity.
# Expected methods on ParkingFineService:
# - __init__(self)
# - issue_fine(self, fine_id: str, vehicle_id: str, violation: str, amount: float) -> str
# - pay_fine(self, fine_id: str, vehicle_id: str) -> str
# - get_outstanding_fines(self, vehicle_id: str) -> str
# - appeal_fine(self, fine_id: str, reason: str) -> str

class Cr4ckHarness:
    def __init__(self):
        self.fine_counter = 0
        # Assuming the user implements a class named ParkingFineService
        # that inherits from the provided Service base class.
        self.parking_service = ParkingFineService()

    def _parse_params(self, param_str):
        params = {}
        if param_str:
            for part in param_str.split(', '):
                key, value = part.split('=', 1)
                params[key.strip()] = value.strip()
        return params

    def run(self):
        for line in sys.stdin:
            line = line.strip()
            if not line:
                continue

            parts = line.split(' ', 1)
            command = parts[0]
            param_str = parts[1] if len(parts) > 1 else ""
            params = self._parse_params(param_str)

            output = ""
            if command == "issue_fine":
                self.fine_counter += 1
                # Generate sequential fine IDs for the harness to manage
                # This ID will be passed to the user's service and used in subsequent commands
                fine_id = f"FINE{self.fine_counter:03d}"
                vehicle_id = params['vehicle']
                violation = params['violation']
                amount = float(params['amount'])
                output = self.parking_service.issue_fine(fine_id, vehicle_id, violation, amount)
            elif command == "pay_fine":
                fine_id = params['fine']
                vehicle_id = params['vehicle']
                output = self.parking_service.pay_fine(fine_id, vehicle_id)
            elif command == "get_outstanding":
                vehicle_id = params['vehicle']
                output = self.parking_service.get_outstanding_fines(vehicle_id)
            elif command == "appeal":
                fine_id = params['fine']
                reason = params['reason']
                output = self.parking_service.appeal_fine(fine_id, reason)
            else:
                output = f"Unknown command: {command}"
            
            print(output)

# Module-level function to run the harness
def run_harness():
    harness = Cr4ckHarness()
    harness.run()

# Call the harness function at module level
run_harness()$harness$,
