UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
    // Instantiate the user's Service class.
    // The user's Service class is expected to have methods corresponding to the commands
    // and manage its internal state (e.g., a collection of ReturnRequest objects).
    const service = new Service();

    for (const line of lines) {
        if (!line) continue;

        const parts = line.split(' ');
        const command = parts[0];
        const argsString = parts.slice(1).join(' ');

        const params: { [key: string]: string | number } = {};
        argsString.split(',').forEach(arg => {
            const [key, value] = arg.trim().split('=');
            if (key && value !== undefined) { // Ensure key and value are present
                // Heuristic to determine if a value should be a string or a number:
                // If it starts with an alphabetic character, treat as string (e.g., IDs, item names, reasons).
                // Otherwise, attempt conversion to number (e.g., amounts).
                params[key] = (typeof value === 'string' && value.match(/^[a-zA-Z]/)) ? value : (isNaN(Number(value)) ? value : Number(value));
            }
        });

        let output = '';
        try {
            switch (command) {
                case 'initiate_return':
                    // Expected parameters: order (string), item (string), reason (string)
                    const orderId = params['order'];
                    const itemName = params['item'];
                    const reason = params['reason'];
                    if (typeof orderId === 'string' && typeof itemName === 'string' && typeof reason === 'string') {
                        // User's Service.initiateReturn is expected to return a string like "Return initiated for ... with ID RET00X"
                        output = service.initiateReturn(orderId, itemName, reason);
                    } else {
                        output = `Error: Missing or invalid parameters for initiate_return. Got: ${JSON.stringify(params)}`;
                    }
                    break;
                case 'inspect':
                    // Expected parameters: return (string, e.g., RET001), condition (string)
                    const returnIdInspect = params['return'];
                    const condition = params['condition'];
                    if (typeof returnIdInspect === 'string' && typeof condition === 'string') {
                        output = service.inspectReturn(returnIdInspect, condition);
                    } else {
                        output = `Error: Missing or invalid parameters for inspect. Got: ${JSON.stringify(params)}`;
                    }
                    break;
                case 'process_refund':
                    // Expected parameters: return (string, e.g., RET001), amount (number)
                    const returnIdRefund = params['return'];
                    const amount = params['amount'];
                    if (typeof returnIdRefund === 'string' && typeof amount === 'number') {
                        output = service.processRefund(returnIdRefund, amount);
                    } else {
                        output = `Error: Missing or invalid parameters for process_refund. Got: ${JSON.stringify(params)}`;
                    }
                    break;
                case 'exchange':
                    // Expected parameters: return (string, e.g., RET001), new_item (string)
                    const returnIdExchange = params['return'];
                    const newItemName = params['new_item'];
                    if (typeof returnIdExchange === 'string' && typeof newItemName === 'string') {
                        // User's Service.processExchange is expected to return a string like "Exchange processed: oldItem -> newItem"
                        output = service.processExchange(returnIdExchange, newItemName);
                    } else {
                        output = `Error: Missing or invalid parameters for exchange. Got: ${JSON.stringify(params)}`;
                    }
                    break;
                default:
                    output = `Error: Unknown command "${command}"`;
                    break;
            }
        } catch (e: any) {
            // Catch any unhandled exceptions from the user's Service methods
            output = `Error processing command '${command}': ${e.message || 'An unknown error occurred.'}`; 
        }
        console.log(output);
    }
});$harness$,
