-- oop_072: Research Paper Repository
UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.HashMap;
import java.util.Map;

public class Main {

    // Helper to parse key=value pairs from command arguments
    private static Map<String, String> parseArgs(String argsString) {
        Map<String, String> args = new HashMap<>();
        String[] parts = argsString.split(", ");
        for (String part : parts) {
            String[] kv = part.split("=", 2);
            if (kv.length == 2) {
                args.put(kv[0].trim(), kv[1].trim());
            }
        }
        return args;
    }

    public static void main(String[] args) throws Exception {
        Scanner scanner = new Scanner(System.in);
        // Instantiate the user's Service class.
        // The user is expected to implement methods like submitPaper, searchPapers, etc.
        // on their 'Service' class, adhering to the contract below.
        Service repository = new Service();

        while (scanner.hasNextLine()) {
            String line = scanner.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            if (line.startsWith("submit paper")) {
                String argString = line.substring("submit paper ".length());
                Map<String, String> parsedArgs = parseArgs(argString);
                String title = parsedArgs.get("title");
                String author = parsedArgs.get("author");
                String journal = parsedArgs.get("journal");

                // Assumed method signature:
                // public String submitPaper(String title, String author, String journal)
                //   - Should generate a unique ID (e.g., PAP001) and return it.
                String paperId = repository.submitPaper(title, author, journal);
                System.out.println("Paper " + paperId + " submitted: " + title + " by " + author + " to " + journal);

            } else if (line.startsWith("search keyword=")) {
                String keyword = line.substring("search keyword=".length());
                // Assumed method signature:
                // public int searchPapers(String keyword)
                //   - Should return the count of papers matching the keyword (case-insensitive substring match).
                int count = repository.searchPapers(keyword);
                System.out.println("Found " + count + " papers matching " + keyword);

            } else if (line.startsWith("cite paper=")) {
                // Command format: cite paper=CITED_PAPER_ID in paper=CITING_PAPER_ID
                String argString = line.substring("cite paper=".length());
                String[] parts = argString.split(" in paper=", 2);
                if (parts.length == 2) {
                    String citedPaperId = parts[0].trim(); // The paper being cited
                    String citingPaperId = parts[1].trim(); // The paper that references the cited paper
                    // Assumed method signature:
                    // public void citePaper(String citingPaperId, String citedPaperId)
                    //   - Should register that 'citingPaperId' refers to 'citedPaperId'.
                    repository.citePaper(citingPaperId, citedPaperId);
                    System.out.println(citedPaperId + " cited in " + citingPaperId);
                } else {
                    System.out.println("Error: Malformed cite command: " + line);
                }

            } else if (line.startsWith("get_citations paper=")) {
                String paperId = line.substring("get_citations paper=".length());
                // Assumed method signature:
                // public int getCitationCount(String paperId)
                //   - Should return the number of other papers that cite this 'paperId'.
                int count = repository.getCitationCount(paperId);
                System.out.println(paperId + " citations: " + count);

            } else {
                System.out.println("Unknown command: " + line);
            }
        }
        scanner.close();
    }
