-- oop_073: Emergency Dispatch Console
UPDATE challenges SET
  test_harness = $harness$import sys
import re
import itertools

# The harness assumes the user's solution provides at least the following classes and methods:
#
# class Entity:
#     # Base class, might have ID generation or common attributes
#     pass
#
# class Service:
#     def __init__(self):
#         # Initializes internal state, e.g., dictionaries for incidents and units.
#         pass
#
#     def create_incident(self, incident_type: str, location: str, severity: str) -> str:
#         # Creates an incident and returns its unique ID (e.g., "INC001").
#         pass
#
#     def register_unit(self, unit_id: str, unit_type: str):
#         # Registers a dispatch unit (e.g., FD001, PD001) of a given type (fire, police, medical).
#         pass
#
#     def dispatch_unit(self, unit_id: str, incident_id: str) -> str:
#         # Dispatches a unit to an incident. Returns a descriptive string (e.g., "Fire unit FD001 dispatched to INC001")
#         # or an error message if the unit/incident is invalid/unavailable.
#         pass
#
#     def update_incident_status(self, incident_id: str, new_status: str) -> str:
#         # Updates an incident's status. Returns a descriptive string (e.g., "INC001 status: contained, units on scene").
#         pass
#
#     def close_incident(self, incident_id: str, outcome: str) -> str:
#         # Closes an incident. Returns a descriptive string (e.g., "Incident INC001 closed: resolved").
#         pass


class HarnessState:
    def __init__(self):
        # Instantiate the user's Service class, which is expected to manage all operations.
        self.dispatch_service = Service()
        # Track active incidents and units for harness validation (e.g., preventing dispatch to non-existent incidents).
        # The actual objects are managed by the user's Service.
        self.active_incidents = {}
        self.active_units = {}

    def _parse_args(self, arg_string):
        args = {}
        for item in arg_string.split(', '):
            if '=' in item:
                key, value = item.split('=', 1)
                args[key.strip()] = value.strip()
        return args

    def handle_command(self, command_line):
        command_parts = command_line.split(' ', 1)
        command_name = command_parts[0]
        args_str = command_parts[1] if len(command_parts) > 1 else ""
        args = self._parse_args(args_str)
        
        output_lines = []

        try:
            if command_name == "create_incident":
                # Expects `create_incident type=fire, location=Building A, severity=high`
                # User's Service.create_incident should return the generated incident ID (e.g., "INC001").
                incident_type = args['type']
                location = args['location']
                severity = args['severity']
                
                incident_id = self.dispatch_service.create_incident(incident_type, location, severity)
                
                if not isinstance(incident_id, str) or not re.match(r"INC\d{3}", incident_id):
                    raise ValueError(f"create_incident did not return a valid incident ID (expected INCxxx, got {incident_id})")
                
                self.active_incidents[incident_id] = True
                output_lines.append(f"Incident created: {incident_type} at {location} ({severity}) - ID: {incident_id}")

            elif command_name == "register_unit":
                # Expects `register_unit id=FD001, type=fire`
                unit_id = args['id']
                unit_type = args['type']
                
                self.dispatch_service.register_unit(unit_id, unit_type)
                
                self.active_units[unit_id] = unit_type # Store type for message consistency
                output_lines.append(f"{unit_type.capitalize()} unit {unit_id} registered.")

            elif command_name == "dispatch":
                # Expects `dispatch unit=FD001, incident=INC001`
                unit_id = args['unit']
                incident_id = args['incident']

                if unit_id not in self.active_units:
                    output_lines.append(f"Error: Unit {unit_id} not registered.")
                elif incident_id not in self.active_incidents:
                    output_lines.append(f"Error: Incident {incident_id} not created or closed.")
                else:
                    message = self.dispatch_service.dispatch_unit(unit_id, incident_id)
                    output_lines.append(message)

            elif command_name == "update_status":
                # Expects `update_status incident=INC001, status=contained`
                incident_id = args['incident']
                status = args['status']

                if incident_id not in self.active_incidents:
                    output_lines.append(f"Error: Incident {incident_id} not created or closed.")
                else:
                    message = self.dispatch_service.update_incident_status(incident_id, status)
                    output_lines.append(message)

            elif command_name == "close_incident":
                # Expects `close_incident id=INC001, outcome=resolved`
                incident_id = args['id']
                outcome = args['outcome']

                if incident_id not in self.active_incidents:
                    output_lines.append(f"Error: Incident {incident_id} not created or already closed.")
                else:
                    message = self.dispatch_service.close_incident(incident_id, outcome)
                    output_lines.append(message)
                    del self.active_incidents[incident_id] # Mark incident as no longer active

            else:
                output_lines.append(f"Unknown command: {command_name}")

        except KeyError as e:
            output_lines.append(f"Error: Missing argument for command '{command_name}': {e}")
        except AttributeError as e:
            output_lines.append(f"Error: Method '{command_name}' not found or invalid on Service object: {e}")
        except Exception as e:
            output_lines.append(f"An unexpected error occurred during '{command_name}': {e}")
        
        return "\n".join(output_lines)

def run_harness():
    state = HarnessState()
    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue
        result = state.handle_command(line)
        if result: # Only print if there's output
            print(result)

