    try {
        // @ts-ignore: Assume BudgetExpenseTrackerService is globally available from user code
        trackerService = new BudgetExpenseTrackerService();
    } catch (e) {
        console.error(`Error: Could not instantiate BudgetExpenseTrackerService. Make sure your main service class is named 'BudgetExpenseTrackerService' and is properly defined.`);
        return;
    }

    for (const line of lines) {
        if (!line) continue; // Skip empty lines

        const parts = line.split(' ');
        const commandName = parts[0];
        const argsString = parts.slice(1).join(' ');

        const args: { [key: string]: string | number } = {};

        if (argsString) {
            argsString.split(',').forEach(argPair => {
                const [key, value] = argPair.split('=').map(s => s.trim());
                if (key && value) {
                    // Attempt to convert to number if possible
                    args[key] = isNaN(Number(value)) ? value : Number(value);
                }
            });
        }

        let output: string | undefined;

        try {
            switch (commandName) {
                case 'add_expense':
                    if (typeof args.category === 'string' && typeof args.amount === 'number' && typeof args.date === 'string') {
                        output = trackerService.addExpense(args.category, args.amount, args.date);
                    } else {
                        output = `Error: Invalid arguments for add_expense: ${line}`;
                    }
                    break;
                case 'set_budget':
                    if (typeof args.category === 'string' && typeof args.monthly === 'number') {
                        output = trackerService.setBudget(args.category, args.monthly);
                    } else {
                        output = `Error: Invalid arguments for set_budget: ${line}`;
                    }
                    break;
                case 'get_summary':
                    if (typeof args.month === 'string') {
                        output = trackerService.getSummary(args.month);
                    } else {
                        output = `Error: Invalid arguments for get_summary: ${line}`;
                    }
                    break;
                case 'alert':
                    // For 'alert', the harness expects the 'spent' amount as an argument.
                    // The service method should then retrieve the budget limit for the category
                    // and format the alert message.
                    if (typeof args.category === 'string' && typeof args.spent === 'number') {
                        output = trackerService.getBudgetAlert(args.category, args.spent);
                    } else {
                        output = `Error: Invalid arguments for alert: ${line}`;
                    }
                    break;
                default:
                    output = `Error: Unknown command "${commandName}"`;
            }
        } catch (e: any) {
            output = `Error executing command "${commandName}": ${e.message || e}`; 
        }

        if (output !== undefined) {
            console.log(output);
        }
    }
