UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.HashMap;
import java.util.Map;
import java.util.ArrayList;
import java.util.List;

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        Service service = new Service(); // Instantiate the user's Service class

        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String[] parts = line.split(" ", 2);
            String command = parts[0];
            Map<String, String> params = new HashMap<>();

            if (parts.length > 1) {
                String[] paramPairs = parts[1].split(", ");
                for (String pair : paramPairs) {
                    String[] kv = pair.split("=", 2);
                    if (kv.length == 2) {
                        // Remove quotes from values if present
                        params.put(kv[0].trim(), kv[1].trim().replace("\"", ""));
                    }
                }
            }

            String result = "";
            try {
                switch (command) {
                    case "add_station":
                        result = service.addStation(params.get("name"));
                        break;
                    case "add_train":
                        result = service.addTrain(
                            params.get("id"),
                            params.get("name"),
                            Integer.parseInt(params.get("capacity"))
                        );
                        break;
                    case "add_route":
                        result = service.addRoute(
                            params.get("id"),
                            params.get("train"),
                            params.get("origin"),
                            params.get("destination"),
                            params.get("departureTime"),
                            params.get("arrivalTime"),
                            params.get("stops") // May be null if not provided
                        );
                        break;
                    case "add_train_schedule":
                        result = service.addTrainSchedule(
                            params.get("train"),
                            params.get("route"),
                            params.get("date")
                        );
                        break;
                    case "search_route":
                        result = service.searchRoute(
                            params.get("from"),
                            params.get("to"),
                            params.get("date")
                        );
                        break;
                    case "book":
                        result = service.bookSeat(
                            params.get("seat"),
                            params.get("train"),
                            params.get("passenger"),
                            params.get("date")
                        );
                        break;
                    case "delay":
                        result = service.reportDelay(
                            params.get("train"),
                            Integer.parseInt(params.get("minutes")),
                            params.get("date")
                        );
                        break;
                    case "get_schedule":
                        result = service.getStationSchedule(
                            params.get("station"),
                            params.get("date")
                        );
                        break;
                    default:
                        result = "Unknown command: " + command;
                        break;
                }
            } catch (Exception e) {
                // Catch any exceptions from user's Service methods and print an error.
                result = "Error processing command '" + command + "': " + e.getMessage();
                // For debugging, print stack trace to stderr
                // e.printStackTrace(System.err);
            }
            System.out.println(result);
        }
        sc.close();
    }
