  test_harness = $harness$import sys

def parse_command(line):
    parts = line.strip().split(' ', 1)
    command_name = parts[0]
    args = {}
    if len(parts) > 1:
        param_str = parts[1]
        for param_val in param_str.split(', '):
            key, val = param_val.split('=', 1)
            args[key.strip()] = val.strip()
    return command_name, args

def run_harness():
    # The user is expected to implement a class named ChatbotManager, derived from Service.
    # This class should manage bots, conversations, and user interactions.
    try:
        manager = ChatbotManager()
    except NameError:
        print("ERROR: ChatbotManager class not found. Please implement ChatbotManager(Service).")
        return
    except Exception as e:
        print(f"ERROR: Failed to instantiate ChatbotManager: {type(e).__name__}: {e}")
        return

    for line in sys.stdin:
        command_name, args = parse_command(line)
        result = ""
        try:
            if command_name == "create_bot":
                # Expected signature: create_bot(name: str, intent: str) -> str
                result = manager.create_bot(args['name'], args['intent'])
            elif command_name == "message":
                # Expected signature: message(bot_name: str, user_id: str, text: str) -> str
                result = manager.message(args['bot'], args['user'], args['text'])
            elif command_name == "get_history":
                # Expected signature: get_history(bot_name: str, user_id: str) -> str
                result = manager.get_history(args['bot'], args['user'])
            elif command_name == "end_session":
                # Expected signature: end_session(bot_name: str, user_id: str) -> str
                result = manager.end_session(args['bot'], args['user'])
            else:
                result = f"ERROR: Unknown command '{command_name}'"
        except KeyError as e:
            result = f"ERROR: Missing argument for command '{command_name}': {e}"
        except AttributeError as e:
            result = f"ERROR: Method not found or incorrectly implemented in ChatbotManager: {e}"
        except Exception as e:
            # Catch any other exceptions from user code
            result = f"ERROR: {type(e).__name__}: {e}"
        print(result)

