const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
    // Instantiate the main service object.
    // Assuming the user implements a Service class that manages operations.
    const plannerService = new Service(); 

    for (const line of lines) {
        if (!line) continue; // Skip empty lines

        // Parse command and arguments
        const [commandPart, argsPart] = line.split(' ', 2);
        const args: { [key: string]: string } = {};

        if (argsPart) {
            argsPart.split(',').forEach(argPair => {
                const [key, value] = argPair.split('=', 2).map(s => s.trim());
                if (key && value) {
                    args[key] = value;
                }
            });
        }

        let output: string | null = null;

        try {
            switch (commandPart) {
                case 'create_project':
                    if (args.name && args.deadline) {
                        output = plannerService.createProject(args.name, args.deadline);
                    } else {
                        output = "Error: Missing name or deadline for create_project command.";
                    }
                    break;
                case 'add_task':
                    if (args.project && args.name && args.duration) {
                        // Pass optional depends_on parameter for critical path calculation
                        output = plannerService.addTask(args.project, args.name, args.duration, args.depends_on);
                    } else {
                        output = "Error: Missing project, name, or duration for add_task command.";
                    }
                    break;
                case 'assign_crew':
                    // Assuming task names are unique enough or Service can resolve context
                    if (args.task && args.crew) {
                        output = plannerService.assignCrew(args.task, args.crew);
                    } else {
                        output = "Error: Missing task or crew for assign_crew command.";
                    }
                    break;
                case 'get_critical_path':
                    if (args.project) {
                        output = plannerService.getCriticalPath(args.project);
                    } else {
                        output = "Error: Missing project for get_critical_path command.";
                    }
                    break;
                default:
                    output = `Unknown command: ${commandPart}`;
                    break;
            }
        } catch (error: any) {
            output = `Error executing command '${commandPart}': ${error.message || error}`;
        }

        if (output !== null) {
            console.log(output);
        }
    }
