-- oop_079: Scholarship Application System
UPDATE challenges SET
  test_harness = $harness$import sys
import re

# Assume user's classes are defined above this point,
# including ScholarshipApplicationService, which should inherit from Service.
# Example expected API for ScholarshipApplicationService:
# - submit_application(app_id: str, name: str, gpa: float, essay: str) -> str
# - review_application(app_id: str, score: int) -> str
# - award_scholarship(sch_id: str, recipient_name: str, amount: int) -> str
# - reject_application(app_id: str, reason: str) -> str

class Cr4ckHarness:
    def __init__(self):
        try:
            self.service = ScholarshipApplicationService()
        except NameError:
            print("Error: ScholarshipApplicationService class not found. Please implement it.")
            sys.exit(1)

        self.app_id_counter = 0
        self.sch_id_counter = 0
        self.last_generated_app_id = None

    def _generate_app_id(self):
        self.app_id_counter += 1
        return f"APP{self.app_id_counter:03d}"

    def _generate_sch_id(self):
        # Test cases use MERIT001, so this generates MERIT001, MERIT002 etc.
        self.sch_id_counter += 1
        return f"MERIT{self.sch_id_counter:03d}"

    def process_command(self, command_line):
        command_line = command_line.strip()
        if not command_line:
            return

        parts = command_line.split(' ', 1)
        command_type = parts[0]
        args_str = parts[1] if len(parts) > 1 else ""

        args = {}
        # Simple argument parsing: split by comma, then by first equals sign.
        # This assumes no unescaped commas within argument values.
        for arg_pair in args_str.split(','):
            if '=' in arg_pair:
                key, value = arg_pair.split('=', 1)
                args[key.strip()] = value.strip()

        output = None
        try:
            if command_type == "submit" and "application" in args:
                app_id_to_use = self._generate_app_id()
                self.last_generated_app_id = app_id_to_use

                name = args["name"]
                gpa = float(args["gpa"])
                essay = args["essay"]
                
                # User's service method is expected to take the generated ID
                output = self.service.submit_application(app_id_to_use, name, gpa, essay)

            elif command_type == "review" and "application" in args:
                app_id_to_review = args["application"]
                # 'LAST' keyword allows referring to the last submitted application
                if app_id_to_review == "LAST" and self.last_generated_app_id:
                    app_id_to_review = self.last_generated_app_id
                
                score = int(args["score"])
                output = self.service.review_application(app_id_to_review, score)

            elif command_type == "award" and "scholarship" in args:
                # Use the scholarship ID directly from args (e.g., MERIT001).
                # If "scholarship=NEW", generate a new one.
                scholarship_id = args["scholarship"]
                if scholarship_id == "NEW":
                    scholarship_id = self._generate_sch_id()
                
                recipient_name = args["recipient"]
                amount = int(args["amount"])
                
                output = self.service.award_scholarship(scholarship_id, recipient_name, amount)

            elif command_type == "reject" and "application" in args:
                app_id_to_reject = args["application"]
                # 'LAST' keyword allows referring to the last submitted application
                if app_id_to_reject == "LAST" and self.last_generated_app_id:
                    app_id_to_reject = self.last_generated_app_id

                reason = args["reason"]
                output = self.service.reject_application(app_id_to_reject, reason)

            else:
                output = f"Error: Unknown command or invalid arguments: {command_line}"
        except AttributeError as ae:
            # Catches cases where service or its methods are not implemented as expected
            output = f"Error: Required method not found or invalid API usage. Details: {ae}"
        except KeyError as ke:
            # Catches cases where a required argument is missing from the command
            output = f"Error: Missing argument for command '{command_type}': {ke}"
        except ValueError as ve:
            # Catches cases where type conversion (e.g., int(), float()) fails
            output = f"Error: Invalid value format for command '{command_type}': {ve}"
        except Exception as e:
            # Catch any other unexpected exceptions from user code
            output = f"Error processing command '{command_line}': {type(e).__name__}: {e}"
        
        if output is not None:
            print(output)

def run_harness():
    harness = Cr4ckHarness()
    for line in sys.stdin:
        harness.process_command(line)

# Call the harness function at module level
run_harness()$harness$,
  test_cases   = '[{"input": "submit application name=Alice, gpa=3.9, essay=submitted", "description": "Submit a basic application", "expected_output": "Scholarship application submitted for Alice"}, {"input": "submit application name=Bob, gpa=3.5, essay=submitted\nreview application=APP001, score=90", "description": "Submit and then review an application using its generated ID (APP001 for Bob)", "expected_output": "Scholarship application submitted for Bob\nApplication APP001 reviewed, score: 90/100"}, {"input": "award scholarship=MERIT001, recipient=Alice, amount=5000", "description": "Award a specific merit scholarship (predefined ID)", "expected_output": "Merit scholarship $5,000 awarded to Alice"}, {"input": "submit application name=Charlie, gpa=2.5, essay=not_submitted\nreject application=APP002, reason=gpa_below_minimum", "description": "Submit and then reject an application using its generated ID (APP002 for Charlie)", "expected_output": "Scholarship application submitted for Charlie\nApplication APP002 rejected: GPA below minimum"}, {"input": "submit application name=Diana, gpa=4.0, essay=excellent\nreview application=LAST, score=95", "description": "Submit and review the last application using ''LAST'' keyword (APP003 for Diana)", "expected_output": "Scholarship application submitted for Diana\nApplication APP003 reviewed, score: 95/100"}, {"input": "submit application name=Eve, gpa=3.0, essay=poor\nreview application=LAST, score=60\nreject application=LAST, reason=essay_quality", "description": "Submit, review, and reject an application in sequence using ''LAST'' (APP004 for Eve)", "expected_output": "Scholarship application submitted for Eve\nApplication APP004 reviewed, score: 60/100\nApplication APP004 rejected: essay_quality"}, {"input": "award scholarship=NEW, recipient=Frank, amount=1000", "description": "Award a new scholarship using the ''NEW'' keyword (harness generates MERIT001)", "expected_output": "Merit scholarship $1,000 awarded to Frank"}, {"input": "submit application name=Grace, gpa=3.8, essay=good\nreview application=APP001, score=85", "description": "Submit another application (APP005 for Grace) and then re-review a previously submitted one (APP001 for Bob)", "expected_output": "Scholarship application submitted for Grace\nApplication APP001 reviewed, score: 85/100"}]'::jsonb
