        Service surgeService = new Service(); // Instantiate the user's Service class

        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String[] parts = line.split(" ", 2); // Split into command and args
            String command = parts[0];
            Map<String, String> params = new HashMap<>();

            if (parts.length > 1) {
                String[] argPairs = parts[1].split(", "); // Split args like "key=value, key2=value2"
                for (String argPair : argPairs) {
                    String[] kv = argPair.split("=", 2);
                    if (kv.length == 2) {
                        params.put(kv[0].trim(), kv[1].trim());
                    }
                }
            }

            String result = "";
            try {
                switch (command) {
                    case "calculate_surge":
                        String area = params.get("area");
                        String demand = params.get("demand");
                        String supply = params.get("supply");
                        result = surgeService.calculateSurge(area, demand, supply);
                        break;
                    case "fare":
                        double baseFare = Double.parseDouble(params.get("base"));
                        String surgeStr = params.get("surge"); 
                        double surgeMultiplier = Double.parseDouble(surgeStr.substring(0, surgeStr.length() - 1)); // Remove 'x'
                        result = surgeService.applySurgeToFare(baseFare, surgeMultiplier);
                        break;
                    case "cap_surge":
                        String maxStr = params.get("max"); 
                        double maxSurge = Double.parseDouble(maxStr.substring(0, maxStr.length() - 1)); // Remove 'x'
                        String calculatedStr = params.get("calculated"); 
                        double calculatedSurge = Double.parseDouble(calculatedStr.substring(0, calculatedStr.length() - 1)); // Remove 'x'
                        result = surgeService.capSurge(maxSurge, calculatedSurge);
                        break;
                    default:
                        result = "Unknown command: " + command;
                        break;
                }
            } catch (NumberFormatException e) {
                result = "Error parsing number: " + e.getMessage();
            } catch (Exception e) {
                result = "An error occurred: " + e.getMessage();
            }
            System.out.println(result);
        }
        sc.close();
    }
