-- oop_083: Cargo Weight Distribution System
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // The user's 'Service' class is available in the global scope.
  // We assume it has the methods defined for the challenge.
  const service = new Service();

  // Helper function to parse item strings like "{id: ITM001, weight: 2t, x: 0}"
  const parseItemString = (itemStr: string): { id: string; weight: number; x: number } => {
    const item: { id?: string; weight?: number; x?: number } = {};
    // Remove outer curly braces
    const content = itemStr.substring(1, itemStr.length - 1).trim();
    // Split by comma
    const parts = content.split(',').map(p => p.trim());

    for (const part of parts) {
      const [key, valueRaw] = part.split(':', 2).map(s => s.trim());
      if (key === 'id') {
        item.id = valueRaw;
      } else if (key === 'weight') {
        item.weight = parseFloat(valueRaw.replace('t', '')); // Strip 't' and parse
      } else if (key === 'x') {
        item.x = parseInt(valueRaw, 10);
      }
    }
    // Type assertion because we expect these properties to be present in valid input
    return item as { id: string; weight: number; x: number };
  };

  for (const line of lines) {
    if (!line) continue;

    const [commandName, argsString] = line.split(' ', 2);
    const args: { [key: string]: any } = {};

    if (argsString) {
      // This regex splits by comma, but not if the comma is inside square brackets.
      // It handles 'key=value' and 'key=[...]' structures.
      const argPairs = argsString.match(/[^,\[\]]+(?:\[[^\]]*\])?/g)?.map(s => s.trim()) || [];

      for (const pair of argPairs) {
        const [key, valueRaw] = pair.split('=', 2);
        const keyTrimmed = key.trim();
        let value: any = valueRaw.trim();

        if (keyTrimmed === 'items') {
          // Parse the complex items array string
          // value will be like "[{id: ITM001, weight: 2t, x: 0}, ...]"
          const itemsArrayString = value.substring(1, value.length - 1); // Remove outer '[' and ']'
          // Use a regex to find each item object string "{...}"
          const itemStrings = itemsArrayString.match(/\{[^}]+\}/g) || [];
          args.items = itemStrings.map(parseItemString);
        } else if (value.match(/^-?\d+$/)) { // Integer
          args[keyTrimmed] = parseInt(value, 10);
        } else if (value.match(/^-?\d+(\.\d+)?t$/)) { // Weight with 't'
          args[keyTrimmed] = parseFloat(value.replace('t', ''));
        } else { // Assume string
          args[keyTrimmed] = value;
        }
      }
    }

    let result: string | undefined;

    try {
      if (commandName === 'load_cargo') {
        result = service.loadCargo(args.container, args.items);
      } else if (commandName === 'check_balance') {
        result = service.checkBalance(args.container);
      } else if (commandName === 'redistribute') {
        // The item ID is passed directly, e.g., 'ITM002'
        result = service.redistributeCargo(args.container, args.item, args.new_x);
      } else if (commandName === 'get_weight_distribution') {
        result = service.getWeightDistribution(args.container);
      } else {
        result = `Error: Unknown command "${commandName}"`;
      }
    } catch (e: any) {
      // Catch errors thrown by user's implementation
      result = `Error executing command "${commandName}": ${e.message}`;
    }

    if (result !== undefined) {
      console.log(result);
    }
  }
});$harness$,
