UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.Map;
import java.util.HashMap;

public class Main {

    private static Map<String, String> parseArgs(String argsLine) {
        Map<String, String> argsMap = new HashMap<>();
        if (argsLine == null || argsLine.trim().isEmpty()) {
            return argsMap;
        }
        // Split by ", " or "," to handle cases like "key=value,key2=value2" and "key=value, key2=value2"
        // Also handle cases where there's just one argument without a comma: "key=value"
        String[] pairs = argsLine.split(",\\s*"); 
        for (String pair : pairs) {
            String[] keyValue = pair.split("=", 2); // Split only on the first '='
            if (keyValue.length == 2) {
                argsMap.put(keyValue[0].trim(), keyValue[1].trim());
            }
        }
        return argsMap;
    }

    public static void main(String[] args) throws Exception {
        Scanner scanner = new Scanner(System.in);
        Service service = new Service(); // Instantiate the user's Service class

        while (scanner.hasNextLine()) {
            String line = scanner.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String[] parts = line.split(" ", 2);
            String command = parts[0];
