-- oop_089: Alumni Network Platform
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

// Helper function to parse commands and their parameters
function parseCommand(line: string): { command: string, params: Record<string, string> } {
  const parts = line.split(' ');
  const command = parts[0];
  const params: Record<string, string> = {};

  // Extract the rest of the line after the command, trimming leading/trailing spaces
  const restOfLine = line.substring(command.length).trim();

  let typeIdentifier: string | null = null;
  let actualParamString = restOfLine;

  // Special handling for 'register alumni' where 'alumni' is a type identifier, not a key=value pair
  if (command === 'register' && restOfLine.startsWith('alumni')) {
    typeIdentifier = 'alumni';
    // Remove 'alumni' and any subsequent space from the string that will be parsed for key=value pairs
    actualParamString = restOfLine.substring('alumni'.length).trim();
  }

  // Parse key=value pairs from the actual parameter string
  if (actualParamString) {
    actualParamString.split(',').forEach(paramKv => {
      const [key, value] = paramKv.split('=').map(s => s.trim());
      if (key && value) {
        params[key] = value;
      }
    });
  }

  // Add the typeIdentifier as a special internal parameter for easy access in the switch statement
  if (typeIdentifier) {
    params['__type__'] = typeIdentifier;
  }

  return { command, params };
}

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {
  // The user's classes (e.g., AlumniNetworkService) are available in this scope
  // We assume the user implements an AlumniNetworkService class extending the provided Service class
  const alumniNetworkService = new AlumniNetworkService();

  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    const { command, params } = parseCommand(line);
    let output: string | null = null;

    try {
      switch (command) {
        case 'register':
          // Validate that the command is 'register alumni' and all required parameters are present
          if (params.__type__ === 'alumni' && params.name && params.graduation && params.company) {
            output = alumniNetworkService.registerAlumni(params.name, parseInt(params.graduation, 10), params.company);
          } else {
            output = `Error: Invalid or missing parameters for 'register alumni'. Expected format: register alumni name=<name>, graduation=<year>, company=<company>`;
          }
          break;
        case 'connect':
          // Validate required parameters for connecting alumni
          if (params.alumni1 && params.alumni2) {
            output = alumniNetworkService.connectAlumni(params.alumni1, params.alumni2);
          } else {
            output = `Error: Missing parameters for 'connect'. Expected format: connect alumni1=<name1>, alumni2=<name2>`;
          }
          break;
        case 'search':
          // Validate required parameters for searching
          if (params.company) { // Assuming search is primarily by company as per challenge examples
            output = alumniNetworkService.searchAlumniByCompany(params.company);
          } else {
            output = `Error: Missing parameters for 'search'. Expected format: search company=<company>`;
          }
          break;
        case 'post_job':
          // Validate required parameters for posting a job
          if (params.company && params.title) {
            output = alumniNetworkService.postJob(params.company, params.title);
          } else {
            output = `Error: Missing parameters for 'post_job'. Expected format: post_job company=<company>, title=<title>`;
          }
          break;
        default:
          output = `Unknown command: '${command}'.`;
      }
    } catch (e: any) {
      // Catch and report any exceptions thrown by the user's service methods
      output = `Error processing command '${command}': ${e.message || 'An unknown error occurred.'}`;
    }

    // Print the result of each command to stdout
    if (output !== null) {
      console.log(output);
    }
  }
