-- oop_090: Campsite Reservation System
UPDATE challenges SET
  test_harness = $harness$import java.time.LocalDate;
import java.time.format.DateTimeParseException;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Scanner;

// IMPORTANT: These 'dummy' classes (Entity, Service, Campsite, UserEntity, Booking,
// CampsiteReservationService, BookingStatus) are provided within the harness code
// solely for the harness to compile and define the expected API. The actual user
// solution will conceptually replace these classes. The user's solution MUST
// provide classes with the expected names and public methods (e.g.,
// 'CampsiteReservationService' with 'addCampsite', 'searchAvailableCampsites',
// 'bookCampsite', 'cancelBooking', 'checkIn', 'checkOut' methods) that the
// harness can interact with. User classes will have 'public' stripped before
// concatenation, so these dummy classes are also not public.

// Base Entity class as provided to the user. User's entities should extend this.
class Entity {
    // User will add fields and methods here.
}

// Base Service class as provided to the user. User's main service should extend this.
class Service {
    // User will add business logic here.
}

// Dummy concrete Entity representing a Campsite for harness logic.
class Campsite extends Entity {
    String id;
    String name;
    String type; // e.g., "tent", "RV"

    // Simplified internal tracking of bookings for availability checks in dummy service.
    List<Booking> bookings = new ArrayList<>(); 

    Campsite(String id, String name, String type) {
        this.id = id;
        this.name = name;
        this.type = type;
    }

    public String getId() { return id; }
    public String getName() { return name; }
    public String getType() { return type; }

    // Dummy method to check if the campsite is available for a given date range.
    // Assumes active or checked-in bookings make it unavailable.
    public boolean isAvailable(LocalDate start, LocalDate end) {
        for (Booking b : bookings) {
            if (b.getStatus() == BookingStatus.ACTIVE || b.getStatus() == BookingStatus.CHECKED_IN) {
                // Check for overlap: (start1 <= end2) && (end1 >= start2)
                if ((start.isBefore(b.getEndDate()) || start.isEqual(b.getEndDate())) &&
                    (end.isAfter(b.getStartDate()) || end.isEqual(b.getStartDate()))) {
                    return false; // Overlap found, site is not available
                }
            }
        }
        return true;
    }

    // Dummy method to add a booking to this campsite's internal list.
    public void addBooking(Booking booking) {
        this.bookings.add(booking);
    }
}

// Dummy concrete Entity representing a User for harness logic.
class UserEntity extends Entity {
    String username;
    UserEntity(String username) {
        this.username = username;
    }
    public String getUsername() { return username; }
}

// Enum for Booking status.
enum BookingStatus {
    ACTIVE, CANCELLED, CHECKED_IN, CHECKED_OUT
}

// Dummy concrete Entity representing a Booking for harness logic.
class Booking extends Entity {
    String bookingId;
    Campsite campsite;
    UserEntity user;
    LocalDate startDate;
    LocalDate endDate;
    BookingStatus status;

    Booking(String bookingId, Campsite campsite, UserEntity user, LocalDate startDate, LocalDate endDate) {
        this.bookingId = bookingId;
        this.campsite = campsite;
        this.user = user;
        this.startDate = startDate;
        this.endDate = endDate;
        this.status = BookingStatus.ACTIVE; // Default to active upon creation
    }

    public String getBookingId() { return bookingId; }
    public Campsite getCampsite() { return campsite; }
    public UserEntity getUser() { return user; }
    public LocalDate getStartDate() { return startDate; }
    public LocalDate getEndDate() { return endDate; }
    public BookingStatus getStatus() { return status; }

    public void setStatus(BookingStatus status) {
        this.status = status;
    }
}

// Dummy concrete Service for campsite reservations, used by the harness.
// User's implementation of 'Service' should provide similar methods.
class CampsiteReservationService extends Service {
    private Map<String, Campsite> campsites = new HashMap<>();
    private Map<String, UserEntity> users = new HashMap<>();
    private Map<String, Booking> bookings = new HashMap<>();
    private int nextBookingId = 1; // Simple sequential booking ID generator

    // Helper to get or create a user.
    private UserEntity getOrCreateUser(String username) {
        return users.computeIfAbsent(username, UserEntity::new);
    }

    // Adds a new campsite to the system.
    public String addCampsite(String id, String name, String type) {
        if (campsites.containsKey(id)) {
            return "Campsite with ID " + id + " already exists.";
        }
        Campsite newCampsite = new Campsite(id, name, type);
        campsites.put(id, newCampsite);
        return "Campsite " + id + " (" + name + ", " + type + ") added.";
    }

    // Searches for available campsites based on criteria.
    public List<Campsite> searchAvailableCampsites(String siteNameContains, LocalDate startDate, LocalDate endDate, String type) {
        List<Campsite> availableSites = new ArrayList<>();
        for (Campsite site : campsites.values()) {
            boolean nameMatches = siteNameContains == null || site.getName().toLowerCase().contains(siteNameContains.toLowerCase());
            boolean typeMatches = type == null || site.getType().equalsIgnoreCase(type);

            if (nameMatches && typeMatches && site.isAvailable(startDate, endDate)) {
                availableSites.add(site);
            }
        }
        return availableSites;
    }

    // Books a campsite for a user for specified dates.
    public String bookCampsite(String campsiteId, String userName, LocalDate startDate, LocalDate endDate) {
        Campsite campsite = campsites.get(campsiteId);
        if (campsite == null) {
            return "Error: Campsite " + campsiteId + " not found.";
        }
        if (!campsite.isAvailable(startDate, endDate)) {
            return "Error: Campsite " + campsiteId + " is not available from " + startDate + " to " + endDate + ".";
        }

        UserEntity user = getOrCreateUser(userName);
        String bookingId = "CAMP" + String.format("%03d", nextBookingId++); // Generate unique ID
        Booking newBooking = new Booking(bookingId, campsite, user, startDate, endDate);

        campsite.addBooking(newBooking); // Link booking to campsite
        bookings.put(bookingId, newBooking); // Store booking by ID

        return "Booking " + bookingId + " created for " + userName + " at " + campsiteId + " from " + startDate + " to " + endDate;
    }

    // Cancels an existing booking.
    public String cancelBooking(String bookingId) {
        Booking booking = bookings.get(bookingId);
        if (booking == null) {
            return "Error: Booking " + bookingId + " not found.";
        }
        if (booking.getStatus() == BookingStatus.CANCELLED) {
            return "Error: Booking " + bookingId + " is already cancelled.";
        }
        if (booking.getStatus() == BookingStatus.CHECKED_IN) {
            return "Error: Cannot cancel booking " + bookingId + " as it is currently checked in.";
        }

        booking.setStatus(BookingStatus.CANCELLED);
        return "Booking " + bookingId + " cancelled. Site " + booking.getCampsite().getId() + " is now available.";
    }

    // Checks a user into their booking.
    public String checkIn(String bookingId) {
        Booking booking = bookings.get(bookingId);
        if (booking == null) {
            return "Error: Booking " + bookingId + " not found.";
        }
        if (booking.getStatus() != BookingStatus.ACTIVE) {
            return "Error: Booking " + bookingId + " is not in an active state for check-in (Status: " + booking.getStatus() + ").";
        }
        booking.setStatus(BookingStatus.CHECKED_IN);
        return booking.getUser().getUsername() + " checked in to site " + booking.getCampsite().getId() + " for booking " + bookingId + ".";
    }

    // Checks a user out from their booking.
    public String checkOut(String bookingId) {
        Booking booking = bookings.get(bookingId);
        if (booking == null) {
            return "Error: Booking " + bookingId + " not found.";
        }
        if (booking.getStatus() != BookingStatus.CHECKED_IN) {
            return "Error: Booking " + bookingId + " is not checked in for check-out (Status: " + booking.getStatus() + ").";
        }
        booking.setStatus(BookingStatus.CHECKED_OUT);
        return booking.getUser().getUsername() + " checked out from site " + booking.getCampsite().getId() + " for booking " + bookingId + ".";
    }
}

// The main test harness class, entry point for the Cr4ck platform.
public class Main {
    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        // Instantiate the main service class. User's implementation of CampsiteReservationService
        // will be used here.
        CampsiteReservationService service = new CampsiteReservationService();

        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String[] parts = line.split(" ", 2);
            String command = parts[0];
            Map<String, String> params = new HashMap<>();

            if (parts.length > 1) {
                String[] paramPairs = parts[1].split(", ");
                for (String pair : paramPairs) {
                    String[] keyValue = pair.split("=", 2);
                    if (keyValue.length == 2) {
                        params.put(keyValue[0].trim(), keyValue[1].trim());
                    }
                }
            }

            String result = "";
            try {
                switch (command) {
                    case "add_campsite":
                        String id = params.get("id");
                        String name = params.get("name");
                        String type = params.get("type");
                        if (id == null || name == null || type == null) {
                            result = "Error: Missing parameters for add_campsite. Required: id, name, type.";
                        } else {
                            result = service.addCampsite(id, name, type);
                        }
                        break;

                    case "search":
                        String siteNameContains = params.get("site_name_contains");
                        String datesRange = params.get("dates");
                        String searchType = params.get("type");

                        LocalDate startDate = null;
                        LocalDate endDate = null;

                        if (datesRange != null) {
                            String[] dateParts = datesRange.split(" to ");
                            if (dateParts.length == 2) {
                                startDate = LocalDate.parse(dateParts[0]);
                                endDate = LocalDate.parse(dateParts[1]);
                            } else {
                                result = "Error: Invalid date range format. Expected 'YYYY-MM-DD to YYYY-MM-DD'.";
                                break;
                            }
                        } else {
                            result = "Error: Missing dates parameter for search.";
                            break;
                        }

                        List<Campsite> availableSites = service.searchAvailableCampsites(siteNameContains, startDate, endDate, searchType);
                        if (availableSites.isEmpty()) {
                            result = "No sites found matching criteria.";
                        } else {
                            StringBuilder sb = new StringBuilder();
                            for (Campsite site : availableSites) {
                                if (sb.length() > 0) sb.append("\n");
                                sb.append("Campsite ").append(site.getId())
                                  .append(" (").append(site.getName()).append(", ").append(site.getType())
                                  .append(") is available from ").append(startDate).append(" to ").append(endDate);
                            }
                            result = sb.toString();
                        }
                        break;

                    case "book":
                        String bookSiteId = params.get("site_id");
                        String user = params.get("user");
                        String bookDatesRange = params.get("dates");

                        LocalDate bookStartDate = null;
                        LocalDate bookEndDate = null;

                        if (bookDatesRange != null) {
                            String[] dateParts = bookDatesRange.split(" to ");
                            if (dateParts.length == 2) {
                                bookStartDate = LocalDate.parse(dateParts[0]);
                                bookEndDate = LocalDate.parse(dateParts[1]);
                            } else {
                                result = "Error: Invalid date range format. Expected 'YYYY-MM-DD to YYYY-MM-DD'.";
                                break;
                            }
                        } else {
                            result = "Error: Missing dates parameter for book.";
                            break;
                        }

                        if (bookSiteId == null || user == null || bookStartDate == null || bookEndDate == null) {
                            result = "Error: Missing parameters for book. Required: site_id, user, dates.";
                        } else {
                            result = service.bookCampsite(bookSiteId, user, bookStartDate, bookEndDate);
                        }
                        break;

                    case "cancel":
                        String bookingToCancel = params.get("booking");
                        if (bookingToCancel == null) {
                            result = "Error: Missing booking parameter for cancel.";
                        } else {
                            result = service.cancelBooking(bookingToCancel);
                        }
                        break;

                    case "check_in":
                        String bookingToCheckIn = params.get("booking");
                        if (bookingToCheckIn == null) {
                            result = "Error: Missing booking parameter for check_in.";
                        } else {
                            result = service.checkIn(bookingToCheckIn);
                        }
                        break;

                    case "check_out":
                        String bookingToCheckOut = params.get("booking");
                        if (bookingToCheckOut == null) {
                            result = "Error: Missing booking parameter for check_out.";
                        } else {
                            result = service.checkOut(bookingToCheckOut);
                        }
                        break;

                    default:
                        result = "Error: Unknown command '" + command + "'";
                        break;
                }
            } catch (DateTimeParseException e) {
                result = "Error: Invalid date format. Please use YYYY-MM-DD. " + e.getMessage();
            } catch (Exception e) {
                // Catch any other unexpected errors from user's code or harness logic
                result = "Error processing command '" + command + "': " + e.getMessage();
            }
            System.out.println(result);
        }
        sc.close();
    }
