-- oop_091: Franchise Royalty Calculator
UPDATE challenges SET
  test_harness = $harness$import sys
import re

def run_harness():
    royalty_service = Service() # Initialize the main service object once

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        command_parts = line.split(' ', 1)
        command = command_parts[0]
        args = {}
        if len(command_parts) > 1:
            arg_string = command_parts[1]
            # Use re.finditer to parse key=value pairs, handling potential spaces after commas
            for match in re.finditer(r'(\w+)=([^,]+)', arg_string):
                key, value = match.groups()
                args[key] = value.strip()

        output = ""
        try:
            if command == "add_franchise":
                name = args.get("name")
                if name is None:
                    raise ValueError("Missing 'name' argument for add_franchise")
                revenue_str = args.get("revenue")
                if revenue_str is None:
                    raise ValueError("Missing 'revenue' argument for add_franchise")
                revenue = int(revenue_str)
                output = royalty_service.add_franchise(name, revenue)
            elif command == "calculate_royalty":
                franchise_name = args.get("franchise")
                if franchise_name is None:
                    raise ValueError("Missing 'franchise' argument for calculate_royalty")
                rate_str = args.get("rate")
                if rate_str is None:
                    raise ValueError("Missing 'rate' argument for calculate_royalty")
                rate = float(rate_str.replace('%', '')) / 100
                output = royalty_service.calculate_royalty(franchise_name, rate)
            elif command == "process_payment":
                franchise_name = args.get("franchise")
                if franchise_name is None:
                    raise ValueError("Missing 'franchise' argument for process_payment")
                amount_str = args.get("amount")
                if amount_str is None:
                    raise ValueError("Missing 'amount' argument for process_payment")
                amount = int(amount_str)
                month = args.get("month")
                if month is None:
                    raise ValueError("Missing 'month' argument for process_payment")
                # Month format 'YYYY-MM' is expected
                output = royalty_service.process_payment(franchise_name, amount, month)
            elif command == "get_total_royalties":
                month = args.get("month")
                if month is None:
                    raise ValueError("Missing 'month' argument for get_total_royalties")
                output = royalty_service.get_total_royalties(month)
            else:
                output = f"Unknown command: {command}"
        except Exception as e:
            # Catching generic Exception for robustness against user code errors
            output = f"Error processing command '{command}': {e}"

        if output:
            print(output)

# Call the harness function at module level
run_harness()$harness$,
  test_cases   = '[{"input": "add_franchise name=Pizza_Palace, revenue=500000", "description": "Add franchise", "expected_output": "Franchise Pizza_Palace added, revenue $500,000"}, {"input": "add_franchise name=Pizza_Palace, revenue=500000\ncalculate_royalty franchise=Pizza_Palace, rate=6%", "description": "Calculate royalty for an existing franchise", "expected_output": "Franchise Pizza_Palace added, revenue $500,000\nPizza_Palace royalty: $30,000 (6% of $500,000)"}, {"input": "add_franchise name=Pizza_Palace, revenue=500000\nprocess_payment franchise=Pizza_Palace, amount=30000, month=2024-07", "description": "Process a royalty payment for an existing franchise", "expected_output": "Franchise Pizza_Palace added, revenue $500,000\nRoyalty payment of $30,000 received from Pizza_Palace for 2024-07"}, {"input": "add_franchise name=Pizza_Palace, revenue=500000\nprocess_payment franchise=Pizza_Palace, amount=30000, month=2024-07\nadd_franchise name=Burger_Barn, revenue=700000\nprocess_payment franchise=Burger_Barn, amount=35000, month=2024-07\nadd_franchise name=Taco_Tuesday, revenue=400000\nprocess_payment franchise=Taco_Tuesday, amount=20000, month=2024-07\nprocess_payment franchise=Pizza_Palace, amount=5000, month=2024-08\nget_total_royalties month=2024-07", "description": "Get total monthly royalties from multiple franchises", "expected_output": "Franchise Pizza_Palace added, revenue $500,000\nRoyalty payment of $30,000 received from Pizza_Palace for 2024-07\nFranchise Burger_Barn added, revenue $700,000\nRoyalty payment of $35,000 received from Burger_Barn for 2024-07\nFranchise Taco_Tuesday added, revenue $400,000\nRoyalty payment of $20,000 received from Taco_Tuesday for 2024-07\nRoyalty payment of $5,000 received from Pizza_Palace for 2024-08\nJuly total royalties: $85,000 from 3 franchises"}, {"input": "calculate_royalty franchise=Non_Existent, rate=5%", "description": "Attempt to calculate royalty for a non-existent franchise", "expected_output": "Error processing command ''calculate_royalty'': Franchise ''Non_Existent'' not found"}, {"input": "add_franchise name=Coffee_Corner, revenue=100000\ncalculate_royalty franchise=Coffee_Corner, rate=5%\ncalculate_royalty franchise=Coffee_Corner, rate=7.5%", "description": "Calculate royalties with different rates for the same franchise", "expected_output": "Franchise Coffee_Corner added, revenue $100,000\nCoffee_Corner royalty: $5,000 (5% of $100,000)\nCoffee_Corner royalty: $7,500 (7.5% of $100,000)"}, {"input": "process_payment franchise=Non_Existent, amount=1000, month=2024-01", "description": "Attempt to process payment for a non-existent franchise", "expected_output": "Error processing command ''process_payment'': Franchise ''Non_Existent'' not found"}]'::jsonb
