-- oop_092: Microfinance Loan Portfolio
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {
    // Helper to parse commands like "issue_loan borrower=Alice, amount=1000, term=12months, rate=15%"
    const parseCommand = (line: string) => {
        const parts = line.split(' ');
        const command = parts[0];
        const args: { [key: string]: string | number } = {};

        if (parts.length > 1) {
            const argString = parts.slice(1).join(' ');
            argString.split(',').forEach(arg => {
                const [key, value] = arg.trim().split('=');
                if (key && value) {
                    let cleanValue: string | number = value.trim();
                    // Attempt to parse numbers, but be careful not to parse strings like "LOAN001" as numbers.
                    // The check `value.trim() === String(parseFloat(cleanValue))` ensures the original string was purely numeric.
                    if (typeof cleanValue === 'string') {
                        if (cleanValue.endsWith('months')) {
                            cleanValue = parseInt(cleanValue.replace('months', ''), 10);
                        } else if (cleanValue.endsWith('%')) {
                            cleanValue = parseFloat(cleanValue.replace('%', ''));
                        } else if (!isNaN(parseFloat(cleanValue)) && isFinite(parseFloat(cleanValue)) && value.trim() === String(parseFloat(cleanValue))) {
                            cleanValue = parseFloat(cleanValue);
                        }
                    }
                    args[key.trim()] = cleanValue;
                }
            });
        }
        return { command, args };
    };

    // Instantiate the user's main service class.
    // We assume the user creates a concrete class named 'LoanPortfolioService'
    // that extends 'Service' and implements the required methods.
    let loanPortfolioService: any;
    try {
        // Direct instantiation. If LoanPortfolioService is not defined, this will throw.
        loanPortfolioService = new LoanPortfolioService();
    } catch (e: any) {
        console.error(`Error: Could not instantiate LoanPortfolioService. Make sure the class 'LoanPortfolioService' is defined and accessible.`);
        console.error(e.message);
        // Provide a stub for the service to prevent further ReferenceErrors and report issue clearly.
        loanPortfolioService = {
            issueLoan: (...a: any[]) => { throw new Error(`LoanPortfolioService not initialized. Attempted to call issueLoan with: ${a.join(', ')}`); },
            recordPayment: (...a: any[]) => { throw new Error(`LoanPortfolioService not initialized. Attempted to call recordPayment with: ${a.join(', ')}`); },
            markLoanAsDefault: (...a: any[]) => { throw new Error(`LoanPortfolioService not initialized. Attempted to call markLoanAsDefault with: ${a.join(', ')}`); },
            getPortfolioSummary: (...a: any[]) => { throw new Error(`LoanPortfolioService not initialized. Attempted to call getPortfolioSummary.`); }
        };
    }

    for (const line of lines) {
        if (!line) continue; // Skip empty lines

        const { command, args } = parseCommand(line);
        let result: string | null = null;

        try {
            switch (command) {
                case 'issue_loan':
                    // Expecting issueLoan(borrower: string, amount: number, termMonths: number, ratePercent: number)
                    result = loanPortfolioService.issueLoan(
                        args.borrower as string,
                        args.amount as number,
                        args.term as number,
                        args.rate as number
                    );
                    break;
                case 'record_payment':
                    // Expecting recordPayment(loanId: string, amount: number)
                    result = loanPortfolioService.recordPayment(
                        args.loan as string,
                        args.amount as number
                    );
                    break;
                case 'get_portfolio_summary':
                    // Expecting getPortfolioSummary(): string
                    result = loanPortfolioService.getPortfolioSummary();
                    break;
                case 'default':
                    // Expecting markLoanAsDefault(loanId: string)
                    result = loanPortfolioService.markLoanAsDefault(
                        args.loan as string
                    );
                    break;
                default:
                    result = `Error: Unknown command "${command}"`;
            }
        } catch (e: any) {
            result = `Error processing command "${command}": ${e.message || "An unexpected error occurred."}`;
        }

        if (result !== null) {
            console.log(result);
        }
    }
});$harness$,
  test_cases   = '[{"input": "issue_loan borrower=Alice, amount=1000, term=12months, rate=15%", "description": "Issue microfinance loan", "expected_output": "Loan issued to Alice: $1,000 at 15% for 12 months"}, {"input": "issue_loan borrower=Bob, amount=1000, term=12months, rate=15%\nrecord_payment loan=LOAN001, amount=95", "description": "Record loan payment", "expected_output": "Loan issued to Bob: $1,000 at 15% for 12 months\nPayment recorded: LOAN001 $95 (on time)"}, {"input": "issue_loan borrower=Charlie, amount=2000, term=24months, rate=10%\nissue_loan borrower=David, amount=5000, term=36months, rate=12%\ndefault loan=LOAN002", "description": "Mark loan as default", "expected_output": "Loan issued to Charlie: $2,000 at 10% for 24 months\nLoan issued to David: $5,000 at 12% for 36 months\nLoan LOAN002 marked as default, recovery initiated"}, {"input": "issue_loan borrower=Eve, amount=1000, term=12months, rate=10%\nissue_loan borrower=Frank, amount=2000, term=24months, rate=12%\nissue_loan borrower=Grace, amount=500, term=6months, rate=15%\nissue_loan borrower=Heidi, amount=3000, term=36months, rate=8%\nissue_loan borrower=Ivan, amount=1500, term=18months, rate=11%\nrecord_payment loan=LOAN001, amount=100\nrecord_payment loan=LOAN002, amount=200\ndefault loan=LOAN003\nget_portfolio_summary", "description": "Get portfolio summary", "expected_output": "Loan issued to Eve: $1,000 at 10% for 12 months\nLoan issued to Frank: $2,000 at 12% for 24 months\nLoan issued to Grace: $500 at 15% for 6 months\nLoan issued to Heidi: $3,000 at 8% for 36 months\nLoan issued to Ivan: $1,500 at 11% for 18 months\nPayment recorded: LOAN001 $100 (on time)\nPayment recorded: LOAN002 $200 (on time)\nLoan LOAN003 marked as default, recovery initiated\nPortfolio: 4 active loans, $7700 outstanding, 20% default rate"}]'::jsonb
WHERE id = 'oop_092';
-- oop_093: Waste Collection Route Planner
UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.Arrays;
import java.util.List;
import java.util.ArrayList;
import java.util.stream.Collectors;

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        Service service = new Service(); 

        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String[] parts = line.split(" ", 2);
            String command = parts[0];
            String argsStr = parts.length > 1 ? parts[1] : "";

            String result = "";
            try {
                switch (command) {
                    case "add_zone":
                        String id = extractArg(argsStr, "id");
                        String area = extractArg(argsStr, "area");
                        String wasteType = extractArg(argsStr, "waste_type");
                        // The user's service method adds the zone, harness prints the confirmation
                        service.addZone(id, area, wasteType);
                        result = String.format("Zone %s %s (%s) added", id, area, wasteType);
                        break;
                    case "plan_route":
                        List<String> zonesPlan = extractListArg(argsStr, "zones");
                        String startPlan = extractArg(argsStr, "start");
                        // The user's service method calculates and returns the route string
                        result = service.planRoute(zonesPlan, startPlan);
                        break;
                    case "optimize_route":
                        List<String> zonesOptimize = extractListArg(argsStr, "zones");
                        // The user's service method calculates and returns the optimized route string
                        result = service.optimizeRoute(zonesOptimize);
                        break;
                    case "log_collection":
                        String zoneIdLog = extractArg(argsStr, "zone");
                        String weightLog = extractArg(argsStr, "weight");
                        // The user's service method logs collection and returns the confirmation string
                        result = service.logCollection(zoneIdLog, weightLog);
                        break;
                    default:
                        result = "Error: Unknown command: " + command;
                        break;
                }
            } catch (Exception e) {
                result = "Error: " + e.getMessage();
            }
            System.out.println(result);
        }
        sc.close();
    }

    // Helper method to extract arguments like "key=value"
    private static String extractArg(String argsStr, String key) {
        for (String part : argsStr.split(",")) {
            String trimmedPart = part.trim();
            if (trimmedPart.startsWith(key + "=")) {
                return trimmedPart.substring(key.length() + 1).trim();
            }
        }
        return null; // Or throw an IllegalArgumentException if arg is mandatory
    }

    // Helper method to extract list arguments like "key=[item1, item2]"
    private static List<String> extractListArg(String argsStr, String key) {
        String value = extractArg(argsStr, key);
        if (value == null || !value.startsWith("[") || !value.endsWith("]")) {
            return new ArrayList<>(); // Return empty list for missing or malformed list
        }
        String listContent = value.substring(1, value.length() - 1).trim();
        if (listContent.isEmpty()) {
            return new ArrayList<>();
        }
        return Arrays.asList(listContent.split(",")).stream()
                     .map(String::trim)
                     .collect(Collectors.toList());
    }
}$harness$,
  test_cases   = '[{"input": "add_zone id=Z001, area=Downtown, waste_type=recycling", "description": "Add collection zone", "expected_output": "Zone Z001 Downtown (recycling) added"}, {"input": "add_zone id=Z001, area=Downtown, waste_type=recycling\nadd_zone id=Z002, area=Uptown, waste_type=glass\nadd_zone id=Z003, area=Midtown, waste_type=paper\nplan_route zones=[Z001, Z002, Z003], start=depot", "description": "Plan collection route", "expected_output": "Zone Z001 Downtown (recycling) added\nZone Z002 Uptown (glass) added\nZone Z003 Midtown (paper) added\nRoute planned: depot -> Z001 -> Z002 -> Z003 -> depot (45km)"}, {"input": "add_zone id=Z001, area=Downtown, waste_type=recycling\nadd_zone id=Z002, area=Uptown, waste_type=glass\nadd_zone id=Z003, area=Midtown, waste_type=paper\noptimize_route zones=[Z001, Z002, Z003]", "description": "Optimize route", "expected_output": "Zone Z001 Downtown (recycling) added\nZone Z002 Uptown (glass) added\nZone Z003 Midtown (paper) added\nOptimized route: depot -> Z002 -> Z001 -> Z003 (38km)"}, {"input": "add_zone id=Z001, area=Downtown, waste_type=recycling\nlog_collection zone=Z001, weight=2.5t", "description": "Log waste collection", "expected_output": "Zone Z001 Downtown (recycling) added\nCollection logged: Z001 2.5 tonnes recycling"}]'::jsonb
WHERE id = 'oop_093';
-- oop_094: Esports Tournament Bracket
UPDATE challenges SET
  test_harness = $harness$import sys

def run_harness():
    service = Service() # User's Service class will be available here

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        parts = line.split(' ', 1)
        command = parts[0]
        args_str = parts[1] if len(parts) > 1 else ""

        args = {}
        for arg_pair in args_str.split(', '):
            if '=' in arg_pair:
                key, value = arg_pair.split('=', 1)
                args[key.strip()] = value.strip()

        try:
            result = None
            if command == "create_bracket":
                game = args.get("game")
                teams = int(args.get("teams"))
                result = service.create_bracket(game, teams)

            elif command == "record_match":
                tournament_id = args.get("tournament")
                match_id = args.get("match")
                winner = args.get("winner")
                score = args.get("score")
                result = service.record_match_result(tournament_id, match_id, winner, score)

            elif command == "get_bracket":
                tournament_id = args.get("tournament")
                round_name = args.get("round")
                result = service.get_bracket_state(tournament_id, round_name)

            elif command == "get_champion":
                tournament_id = args.get("tournament")
                result = service.get_champion(tournament_id)

            else:
                result = f"Error: Unknown command '{command}'"
            
            if result is not None: # Print if a string (even empty) is returned
                print(result)

        except Exception as e:
            print(f"Error processing command '{line}': {type(e).__name__}: {e}")

run_harness()$harness$,
  test_cases   = '[{"input": "create_bracket game=Valorant_Open, teams=4", "description": "Create esports bracket", "expected_output": "4-team single elimination bracket created"}, {"input": "create_bracket game=Valorant_Open, teams=4\nrecord_match tournament=Valorant_Open, match=SF1, winner=TeamAlpha, score=2-0", "description": "Record first semi-final match result", "expected_output": "4-team single elimination bracket created\nMatch SF1: TeamAlpha wins 2-0, advances"}, {"input": "create_bracket game=Valorant_Open, teams=4\nrecord_match tournament=Valorant_Open, match=SF1, winner=TeamAlpha, score=2-0\nrecord_match tournament=Valorant_Open, match=SF2, winner=TeamBeta, score=2-1\nget_bracket tournament=Valorant_Open, round=Finals", "description": "Check bracket state after semi-finals", "expected_output": "4-team single elimination bracket created\nMatch SF1: TeamAlpha wins 2-0, advances\nMatch SF2: TeamBeta wins 2-1, advances\nFinals: 2 teams remaining"}, {"input": "create_bracket game=Valorant_Open, teams=4\nrecord_match tournament=Valorant_Open, match=SF1, winner=TeamAlpha, score=2-0\nrecord_match tournament=Valorant_Open, match=SF2, winner=TeamBeta, score=2-1\nrecord_match tournament=Valorant_Open, match=FINAL, winner=TeamAlpha, score=3-1\nget_champion tournament=Valorant_Open", "description": "Get final champion", "expected_output": "4-team single elimination bracket created\nMatch SF1: TeamAlpha wins 2-0, advances\nMatch SF2: TeamBeta wins 2-1, advances\nMatch FINAL: TeamAlpha wins 3-1, advances\nChampion: TeamAlpha"}]'::jsonb
