-- oop_095: Telehealth Appointment Platform
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', () => {
    // Helper function to parse arguments from command string
    function parseArgs(argString: string): Record<string, string> {
        const args: Record<string, string> = {};
        // Split by comma, then each part by equals sign
        argString.split(',').forEach(part => {
            const [key, value] = part.split('=').map(s => s.trim());
            if (key && value) {
                args[key] = value;
            }
        });
        return args;
    }

    // Helper to extract HH:MM time string from 'YYYY-MM-DD HH:MM' format
    function extractTime(dateTimeString: string): string {
        try {
            const date = new Date(dateTimeString);
            // Check for invalid date to handle parsing errors gracefully
            if (isNaN(date.getTime())) {
                const parts = dateTimeString.split(' ');
                if (parts.length > 1) {
                    return parts[1]; // Fallback to raw time string if Date object is invalid
                }
                return "Unknown Time";
            }
            const hours = String(date.getHours()).padStart(2, '0');
            const minutes = String(date.getMinutes()).padStart(2, '0');
            return `${hours}:${minutes}`;
        } catch {
            // Generic catch for any unexpected issues during date parsing
            const parts = dateTimeString.split(' ');
            if (parts.length > 1) {
                return parts[1];
            }
            return "Unknown Time";
        }
    }

    // Instantiate the main system object. 
    // This harness assumes the user implements a `TelehealthSystem` class which orchestrates operations.
    // Patient, Doctor, and Appointment are assumed to extend the user's `Entity` class.
    // TelehealthSystem is assumed to extend the user's `Service` class or be a standalone class.
    const system = new TelehealthSystem(); 

    // Maps to store instances of entities managed by the harness, linking names/IDs to actual objects.
    // These maps hold references to the objects created by the user's system methods.
    const patients = new Map<string, Patient>();
    const doctors = new Map<string, Doctor>();
    // Stores Appointment objects by their unique harness-generated ID (e.g., APT001)
    const appointments = new Map<string, Appointment>(); 
    let nextAppointmentHarnessId = 1;

    for (const line of lines) {
        if (!line) continue; // Skip empty lines

        const parts = line.split(' ');
        const command = parts[0];
        // Join remaining parts to form the argument string, handling spaces within argument values
        const argString = parts.slice(1).join(' '); 
        const args = parseArgs(argString);

        let output = '';

        try {
            switch (command) {
                case 'create_patient': {
                    const name = args['name'];
                    if (!name) throw new Error('Missing patient name');
                    // Assumes TelehealthSystem.registerPatient(name: string) returns a Patient object
                    const patient = system.registerPatient(name);
                    patients.set(name, patient); // Store patient object by name for future lookups
                    output = `Patient created: ${name}`;
                    break;
                }
                case 'create_doctor': {
                    const name = args['name'];
                    if (!name) throw new Error('Missing doctor name');
                    // Assumes TelehealthSystem.registerDoctor(name: string) returns a Doctor object
                    const doctor = system.registerDoctor(name);
                    doctors.set(name, doctor); // Store doctor object by name for future lookups
                    output = `Doctor created: ${name}`;
                    break;
                }
                case 'book_appointment': {
                    const patientName = args['patient'];
                    const doctorName = args['doctor'];
                    const type = args['type'];
                    const date = args['date']; // Expected format: "YYYY-MM-DD HH:MM"

                    const patient = patients.get(patientName);
                    const doctor = doctors.get(doctorName);

                    if (!patient) throw new Error(`Patient '${patientName}' not found. Please create them first.`);
                    if (!doctor) throw new Error(`Doctor '${doctorName}' not found. Please create them first.`);
                    if (!type || !date) throw new Error('Missing appointment details (type or date).');

                    // Assumes TelehealthSystem.bookAppointment(patient: Patient, doctor: Doctor, type: string, dateTime: string) 
                    // returns an Appointment object created by the user's system.
                    const appointment = system.bookAppointment(patient, doctor, type, date);
                    // Generate a harness-specific appointment ID to reference this appointment in later commands
                    const harnessAppointmentId = `APT${String(nextAppointmentHarnessId++).padStart(3, '0')}`;
                    appointments.set(harnessAppointmentId, appointment); // Store appointment object by harness ID

                    const appointmentTime = extractTime(date);
                    output = `Telehealth appointment booked: ${patientName} with ${doctorName} at ${appointmentTime}`;
                    break;
                }
                case 'start_session': {
                    const appointmentId = args['appointment']; // Harness-generated ID, e.g., APT001
                    if (!appointmentId) throw new Error('Missing appointment ID.');

                    const appointment = appointments.get(appointmentId);
                    if (!appointment) throw new Error(`Appointment '${appointmentId}' not found. Please book it first.`);

                    // Assumes TelehealthSystem.startSession(appointment: Appointment) returns a string message
                    output = system.startSession(appointment);
                    break;
                }
                case 'prescribe': {
                    const patientName = args['patient'];
                    const drug = args['drug'];
                    const dose = args['dose'];

                    const patient = patients.get(patientName);
                    if (!patient) throw new Error(`Patient '${patientName}' not found. Please create them first.`);
                    if (!drug || !dose) throw new Error('Missing prescription details (drug or dose).');

                    // Assumes TelehealthSystem.prescribe(patient: Patient, drug: string, dose: string) returns a string message
                    output = system.prescribe(patient, drug, dose);
                    break;
                }
                case 'end_session': {
                    const appointmentId = args['appointment']; // Harness-generated ID, e.g., APT001
                    if (!appointmentId) throw new Error('Missing appointment ID.');

                    const appointment = appointments.get(appointmentId);
                    if (!appointment) throw new Error(`Appointment '${appointmentId}' not found.`);

                    // Assumes TelehealthSystem.endSession(appointment: Appointment) returns a string message
                    output = system.endSession(appointment);
                    break;
                }
                default:
                    output = `Unknown command: ${command}`;
            }
        } catch (error: any) {
            // Catch and log any errors during command execution
            output = `Error: ${error.message}`;
        }
        console.log(output);
    }
});$harness$,
  test_cases   = '[{"input": "create_patient name=alice\ncreate_doctor name=Dr. Chen\nbook_appointment patient=alice, doctor=Dr. Chen, type=video, date=2024-07-15 10:00", "description": "Book telehealth appointment", "expected_output": "Patient created: alice\nDoctor created: Dr. Chen\nTelehealth appointment booked: alice with Dr. Chen at 10:00"}, {"input": "create_patient name=alice\ncreate_doctor name=Dr. Chen\nbook_appointment patient=alice, doctor=Dr. Chen, type=video, date=2024-07-15 10:00\nstart_session appointment=APT001", "description": "Start telehealth session", "expected_output": "Patient created: alice\nDoctor created: Dr. Chen\nTelehealth appointment booked: alice with Dr. Chen at 10:00\nVideo session started: alice and Dr. Chen connected"}, {"input": "create_patient name=alice\nprescribe patient=alice, drug=Amoxicillin, dose=500mg", "description": "Send electronic prescription", "expected_output": "Patient created: alice\nPrescription sent: alice Amoxicillin 500mg"}, {"input": "create_patient name=alice\ncreate_doctor name=Dr. Chen\nbook_appointment patient=alice, doctor=Dr. Chen, type=video, date=2024-07-15 10:00\nstart_session appointment=APT001\nend_session appointment=APT001", "description": "End telehealth session", "expected_output": "Patient created: alice\nDoctor created: Dr. Chen\nTelehealth appointment booked: alice with Dr. Chen at 10:00\nVideo session started: alice and Dr. Chen connected\nSession ended, consultation notes saved"}]'::jsonb
WHERE id = 'oop_095';
-- oop_096: Vending Machine Product Manager
UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.HashMap;
import java.util.Map;

class Main {
    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        Service vendingMachine = new Service();

        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String result = processCommand(vendingMachine, line);
            if (result != null) {
                System.out.println(result);
            }
        }
        sc.close();
    }

    private static String processCommand(Service vendingMachine, String command) {
        String[] parts = command.split(" ", 2);
        String cmd = parts[0];
        Map<String, String> params = new HashMap<>();
        if (parts.length > 1) {
            params = parseParams(parts[1]);
        }

        try {
            switch (cmd) {
                case "add_product":
                    String sku = params.get("sku");
                    String name = params.get("name");
                    double price = Double.parseDouble(params.get("price"));
                    int qty = Integer.parseInt(params.get("qty"));
                    return vendingMachine.addProduct(sku, name, price, qty);
                case "dispense":
                    String productNameDispense = params.get("product");
                    double payment = Double.parseDouble(params.get("payment"));
                    return vendingMachine.dispenseProduct(productNameDispense, payment);
                case "restock":
                    String productNameRestock = params.get("product");
                    int restockQty = Integer.parseInt(params.get("qty"));
                    return vendingMachine.restockProduct(productNameRestock, restockQty);
                default:
                    return "Error: Unknown command '" + cmd + "'";
            }
        } catch (NumberFormatException e) {
            return "Error: Invalid number format for a parameter: " + e.getMessage();
        } catch (NullPointerException e) {
             // Catches cases where a required parameter is missing, e.g., sku= or name= in add_product
            return "Error: Missing required parameter for command '" + cmd + "'. " + e.getMessage();
        } catch (Exception e) {
            // Catch any other unexpected exceptions from user code
            return "Error: An unexpected error occurred: " + e.getMessage();
        }
    }

    private static Map<String, String> parseParams(String paramsString) {
        Map<String, String> params = new HashMap<>();
        String[] pairs = paramsString.split(", ");
        for (String pair : pairs) {
            String[] keyValue = pair.split("=", 2);
            if (keyValue.length == 2) {
                params.put(keyValue[0].trim(), keyValue[1].trim());
            } else {
                // Handle malformed key=value pairs, e.g., just 'key' or 'value='
                params.put(keyValue[0].trim(), ""); // or throw an error if strict parsing is needed
            }
        }
        return params;
    }
}$harness$,
