-- oop_097: Satellite Pass Scheduler
UPDATE challenges SET
  test_harness = $harness$import sys

# The user is expected to implement classes like Satellite, GroundStation, and a main
# scheduler class (e.g., SatelliteScheduler) that inherits from Service.
# The harness will instantiate SatelliteScheduler and call its methods.

def run_harness():
    # Instantiate the main service object that the user is expected to provide.
    # This assumes the user defines a class named SatelliteScheduler inheriting from Service.
    # All state will be maintained within this single instance.
    try:
        scheduler = SatelliteScheduler()
    except NameError:
        print("Error: SatelliteScheduler class not found. Please ensure your main scheduler class is named SatelliteScheduler and inherits from Service.")
        return
    except Exception as e:
        print(f"Error initializing SatelliteScheduler: {e}")
        return

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        parts = line.split(" ", 1)
        command_name = parts[0]
        args_str = parts[1] if len(parts) > 1 else ""

        # Parse arguments into a dictionary
        args = {}
        if args_str:
            arg_pairs = args_str.split(", ")
            for pair in arg_pairs:
                key_val = pair.split("=", 1)
                if len(key_val) == 2:
                    args[key_val[0].strip()] = key_val[1].strip()

        result = None
        try:
            if command_name == "add_satellite":
                result = scheduler.add_satellite(
                    id=args.get("id"),
                    orbit=args.get("orbit"),
                    period=args.get("period")
                )
            elif command_name == "schedule_pass":
                result = scheduler.schedule_pass(
                    station=args.get("station"),
                    satellite=args.get("satellite"),
                    date=args.get("date")
                )
            elif command_name == "get_next_pass":
                result = scheduler.get_next_pass(
                    station=args.get("station"),
                    satellite=args.get("satellite")
                )
            elif command_name == "conflict_check":
                result = scheduler.conflict_check(
                    station=args.get("station"),
                    time=args.get("time")
                )
            else:
                result = f"Error: Unknown command '{command_name}'"
        except AttributeError:
            # This can happen if a required method is not implemented by the user
            result = f"Error: Method '{command_name}' not found on SatelliteScheduler. Please implement it."
        except Exception as e:
            result = f"Error executing '{command_name}': {type(e).__name__}: {e}"

        if result is not None:
            print(result)

