-- oop_098: Freight Invoice Generator
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin
});

const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', () => {
  // Assume user defines specific classes based on the challenge description about object-oriented design.
  // For example: `FreightInvoiceService`, `FreightChargeCalculator`, `Invoice`.
  // The harness will try to instantiate these by name and interact with their methods.

  let freightServiceManager: any; // Instance of user's FreightInvoiceService
  let freightChargeCalculator: any; // Instance of user's FreightChargeCalculator

  // To maintain a map of invoices created for the harness's internal logic, 
  // especially for generating consistent Invoice IDs (INV001, INV002 etc.).
  // The user's FreightInvoiceService is expected to manage invoices internally,
  // but the harness needs to pass generated IDs to it.
  const invoiceMap = new Map<string, any>(); // Stores Invoice objects created by the service
  let nextInvoiceIdNum = 1;

  try {
    // Attempt to instantiate user-defined classes. 
    // These names are assumed based on common OOP challenge patterns.
    if (typeof (global as any).FreightInvoiceService !== 'function') {
      throw new Error("User must define a 'FreightInvoiceService' class.");
    }
    if (typeof (global as any).FreightChargeCalculator !== 'function') {
      throw new Error("User must define a 'FreightChargeCalculator' class.");
    }
    freightServiceManager = new (global as any).FreightInvoiceService();
    freightChargeCalculator = new (global as any).FreightChargeCalculator();
  } catch (e: any) {
    console.error(`Initialization Error: ${e.message}`);
    process.exit(1);
  }

  for (const line of lines) {
    const [commandVerb, paramsString] = line.split(' ', 2);
    const params: { [key: string]: any } = {};

    if (paramsString) {
      paramsString.split(', ').forEach(param => {
        const [key, value] = param.split('=');
        if (key && value) {
          if (key === 'items') {
            // items=[cargo_a: 500kg, cargo_b: 300kg]
            const itemsList = value.substring(1, value.length - 1).split(', ').map((item: string) => item.split(': '));
            params[key] = itemsList.reduce((acc: { [key: string]: number }, [name, weightStr]: string[]) => {
              acc[name] = parseInt(weightStr.replace('kg', ''));
              return acc;
            }, {});
          } else if (key === 'weight' || key === 'distance' || key === 'amount') {
            params[key] = parseInt(value.replace('kg', '').replace('km', ''));
          } else {
            params[key] = value;
          }
        }
      });
    }

    let output = '';

    switch (commandVerb) {
      case 'create_invoice':
        const invoiceId = `INV${String(nextInvoiceIdNum++).padStart(3, '0')}`;
        // The service is expected to create and manage the Invoice object internally.
        // We pass the generated ID to ensure consistency with test cases like 'finalize_invoice invoice=INV001'.
        if (typeof freightServiceManager.createInvoice !== 'function') {
            console.error("FreightInvoiceService must implement 'createInvoice(invoiceId, shipmentId, items)' method.");
            process.exit(1);
        }
        const createdInvoice = freightServiceManager.createInvoice(invoiceId, params.shipment, params.items);
        invoiceMap.set(invoiceId, createdInvoice); // Keep a reference in the harness if needed later, though interaction should be via service.

        const totalWeight = Object.values(params.items).reduce((sum: number, weight: any) => sum + weight, 0); 
        output = `Invoice created for ${params.shipment}: ${totalWeight}kg freight`;
        break;

      case 'calculate_charges':
        if (!params.invoice) {
            console.error("Invoice ID is required for 'calculate_charges' to apply them. E.g., invoice=INV001");
            process.exit(1);
        }
        if (!freightChargeCalculator || typeof freightChargeCalculator.calculateCharges !== 'function' || typeof freightChargeCalculator.getDescription !== 'function') {
          console.error("FreightChargeCalculator not properly initialized or missing 'calculateCharges(weight, distance, type)' or 'getDescription(weight, distance, type)' methods.");
          process.exit(1);
        }

        const calculatedAmount = freightChargeCalculator.calculateCharges(
          params.weight,
          params.distance,
          params.type
        );
        const description = freightChargeCalculator.getDescription(
          params.weight,
          params.distance,
          params.type
        );
        output = `Freight charges: $${calculatedAmount} (${description})`;

        // Apply these charges to the specified invoice via the service.
        if (typeof freightServiceManager.applyChargesToInvoice === 'function') {
            freightServiceManager.applyChargesToInvoice(params.invoice, calculatedAmount);
        } else {
            console.error("FreightInvoiceService must implement 'applyChargesToInvoice(invoiceId, amount)' method.");
            process.exit(1);
        }
        break;

      case 'add_surcharge':
        if (!params.invoice) {
            console.error("Invoice ID is required for 'add_surcharge'. E.g., invoice=INV001");
            process.exit(1);
        }
        if (typeof freightServiceManager.addSurchargeToInvoice === 'function') {
            freightServiceManager.addSurchargeToInvoice(params.invoice, params.type, params.amount);
        } else {
            console.error("FreightInvoiceService must implement 'addSurchargeToInvoice(invoiceId, type, amount)' method.");
            process.exit(1);
        }
        output = `${params.type} surcharge $${params.amount} added to invoice`;
        break;

      case 'finalize_invoice':
        if (!params.invoice) {
            console.error("Invoice ID is required for 'finalize_invoice'. E.g., invoice=INV001");
            process.exit(1);
        }
        if (typeof freightServiceManager.finalizeInvoice !== 'function') {
            console.error("FreightInvoiceService must implement 'finalizeInvoice(invoiceId)' method.");
            process.exit(1);
        }
        const finalTotal = freightServiceManager.finalizeInvoice(params.invoice);
        output = `Invoice ${params.invoice} finalized: $${finalTotal} total`;
        break;

      default:
        output = `Unknown command: ${commandVerb}`;
    }
    if (output) {
      console.log(output);
    }
  }
});$harness$,
  test_cases   = '[{"input": "create_invoice shipment=SHP001, items=[cargo_a: 500kg, cargo_b: 300kg]", "description": "Create freight invoice", "expected_output": "Invoice created for SHP001: 800kg freight"}, {"input": "create_invoice shipment=SHP001, items=[cargo_a: 500kg, cargo_b: 300kg]\ncalculate_charges invoice=INV001, weight=800kg, distance=1200km, type=air", "description": "Calculate freight charges", "expected_output": "Invoice created for SHP001: 800kg freight\nFreight charges: $2,400 (800kg air freight 1200km)"}, {"input": "create_invoice shipment=SHP001, items=[cargo_a: 500kg, cargo_b: 300kg]\ncalculate_charges invoice=INV001, weight=800kg, distance=1200km, type=air\nadd_surcharge invoice=INV001, type=fuel, amount=150", "description": "Add surcharge", "expected_output": "Invoice created for SHP001: 800kg freight\nFreight charges: $2,400 (800kg air freight 1200km)\nFuel surcharge $150 added to invoice"}, {"input": "create_invoice shipment=SHP001, items=[cargo_a: 500kg, cargo_b: 300kg]\ncalculate_charges invoice=INV001, weight=800kg, distance=1200km, type=air\nadd_surcharge invoice=INV001, type=fuel, amount=150\nfinalize_invoice invoice=INV001", "description": "Finalize invoice", "expected_output": "Invoice created for SHP001: 800kg freight\nFreight charges: $2,400 (800kg air freight 1200km)\nFuel surcharge $150 added to invoice\nInvoice INV001 finalized: $2,550 total"}]'::jsonb
WHERE id = 'oop_098';
-- oop_099: Digital Newspaper Archive
UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.time.format.DateTimeParseException;
import java.util.HashMap;
import java.util.Map;
import java.util.Objects;

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner scanner = new Scanner(System.in);
        // Instantiate the user's Service class once for stateful operations.
        Service newspaperArchive = new Service(); 

        // Date formatters for parsing input and formatting output
        DateTimeFormatter inputDateFormatter = DateTimeFormatter.ofPattern("yyyy-MM-dd");
        DateTimeFormatter outputDateFormatter = DateTimeFormatter.ofPattern("MMMM d yyyy"); // e.g., "July 15 2024"

        while (scanner.hasNextLine()) {
            String line = scanner.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String[] parts = line.split(" ", 2);
            String command = parts[0];
            Map<String, String> params = new HashMap<>();

            if (parts.length > 1) {
                String[] paramPairs = parts[1].split(", ");
                for (String pair : paramPairs) {
                    String[] kv = pair.split("=", 2);
                    if (kv.length == 2) {
                        params.put(kv[0].trim(), kv[1].trim());
                    }
                }
            }

            String result = "";
            try {
                switch (command) {
                    case "add_article": {
                        String title = Objects.requireNonNull(params.get("title"), "Missing 'title' parameter for add_article.");
                        String dateStr = Objects.requireNonNull(params.get("date"), "Missing 'date' parameter for add_article.");
                        LocalDate date = LocalDate.parse(dateStr, inputDateFormatter);
                        String section = Objects.requireNonNull(params.get("section"), "Missing 'section' parameter for add_article.");
                        
                        // Assumes Service has a method: public void addArticle(String title, LocalDate date, String section)
                        newspaperArchive.addArticle(title, date, section); 
                        result = String.format("Article archived: %s (%s)", title, dateStr);
                        break;
                    }

                    case "search": {
                        String keyword = Objects.requireNonNull(params.get("keyword"), "Missing 'keyword' parameter for search.");
                        String dateRangeStr = params.get("date_range"); // This parameter is optional
                        
                        LocalDate startDate = null;
                        LocalDate endDate = null;

                        if (dateRangeStr != null && !dateRangeStr.isEmpty()) {
                            String[] rangeParts = dateRangeStr.split(" to ");
                            if (rangeParts.length == 2) {
                                startDate = LocalDate.parse(rangeParts[0], inputDateFormatter);
                                endDate = LocalDate.parse(rangeParts[1], inputDateFormatter);
                            } else {
                                throw new IllegalArgumentException("Invalid 'date_range' format. Expected 'YYYY-MM-DD to YYYY-MM-DD'.");
                            }
                        }
                        
                        // Assumes Service has a method: public int searchArticles(String keyword, LocalDate startDate, LocalDate endDate)
                        int count = newspaperArchive.searchArticles(keyword, startDate, endDate); 
                        
                        String dateRangeOutput = "";
                        if (startDate != null && endDate != null) {
                            String startMonth = startDate.format(DateTimeFormatter.ofPattern("MMM"));
                            String endMonth = endDate.format(DateTimeFormatter.ofPattern("MMM"));
                            String year = String.valueOf(startDate.getYear()); 
                            dateRangeOutput = String.format(" from %s-%s %s", startMonth, endMonth, year);
                        }
                        result = String.format("Found %d articles about %s%s", count, keyword, dateRangeOutput);
                        break;
                    }

                    case "get_edition": {
                        String dateStr = Objects.requireNonNull(params.get("date"), "Missing 'date' parameter for get_edition.");
                        LocalDate editionDate = LocalDate.parse(dateStr, inputDateFormatter);
                        
                        // Assumes Service has a method: public Map<String, Integer> getEditionInfo(LocalDate date)
                        // This method is expected to return a map with keys "articles" and "sections".
                        Map<String, Integer> editionInfo = newspaperArchive.getEditionInfo(editionDate); 
                        
                        // Handle potential null or missing keys from user's implementation
                        int numArticles = editionInfo != null ? editionInfo.getOrDefault("articles", 0) : 0;
                        int numSections = editionInfo != null ? editionInfo.getOrDefault("sections", 0) : 0;
                        result = String.format("Edition %s: %d articles, %d sections", dateStr, numArticles, numSections);
                        break;
                    }

                    case "get_article": {
                        String articleTitle = Objects.requireNonNull(params.get("title"), "Missing 'title' parameter for get_article.");
                        
                        // Assumes Service has a method: public Map<String, String> getArticleDetails(String title)
                        // This method is expected to return a map with keys "title", "date", "section" if found, else null.
                        Map<String, String> articleDetails = newspaperArchive.getArticleDetails(articleTitle); 
                        
                        if (articleDetails != null) {
                            String retrievedTitle = Objects.requireNonNull(articleDetails.get("title"), "Article details map missing 'title'.");
                            String articleDateStr = Objects.requireNonNull(articleDetails.get("date"), "Article details map missing 'date'.");
                            LocalDate articleDate = LocalDate.parse(articleDateStr, inputDateFormatter);
                            String articleSection = Objects.requireNonNull(articleDetails.get("section"), "Article details map missing 'section'.");

                            result = String.format("Article: %s, %s, %s section",
                                    retrievedTitle,
                                    articleDate.format(outputDateFormatter), 
                                    articleSection);
                        } else {
                            result = "Article not found: " + articleTitle; 
                        }
                        break;
                    }

                    default:
                        result = "Unknown command: " + command;
                        break;
                }
            } catch (DateTimeParseException e) {
                result = "Error: Invalid date format. Please ensure YYYY-MM-DD is used. Details: " + e.getMessage();
            } catch (IllegalArgumentException e) {
                result = "Error: " + e.getMessage(); // For missing parameters or bad date_range format
            } catch (NullPointerException e) { 
                result = "Error: Required data is missing or object state is invalid. Details: " + e.getMessage();
            } catch (Exception e) {
                // Catch any other exceptions from user's code or unexpected issues
                result = "Runtime Error during command '" + command + "': " + e.getClass().getSimpleName() + " - " + e.getMessage();
            }
            System.out.println(result);
        }
        scanner.close();
    }
