            elif command == "schedule_appointment":
                patient = args.get("patient")
                appt_type = args.get("type")
                date = args.get("date")
                if not all([patient, appt_type, date]):
                    result = "Error: Missing arguments for schedule_appointment: patient, type, date"
                else:
                    result = dental_service.schedule_appointment(patient=patient, type=appt_type, date=date)
            elif command == "record_treatment":
                patient = args.get("patient")
                treatment = args.get("treatment")
                tooth = args.get("tooth")
                # The 'date' argument for record_treatment is optional for the user's method,
                # but provided in test cases for deterministic history output.
                date = args.get("date")
                if not all([patient, treatment, tooth]):
                    result = "Error: Missing arguments for record_treatment: patient, treatment, tooth"
                else:
                    # Pass date=None if not provided in input, user's method should handle.
                    result = dental_service.record_treatment(patient=patient, treatment=treatment, tooth=tooth, date=date)
            elif command == "get_dental_history":
                patient = args.get("patient")
                if not patient:
                    result = "Error: Missing patient for get_dental_history"
                else:
                    result = dental_service.get_dental_history(patient=patient)
            else:
                result = f"Unknown command: {command}"
        except AttributeError as ae:
            # Catches errors if the expected method doesn't exist on dental_service
            result = f"Error: Method for command '{command}' not found or incorrectly implemented on DentalPracticeService. Details: {ae}"
        except Exception as e:
            # Catch any other unexpected errors from user's code
            result = f"An unexpected error occurred during command '{command}': {e}"

        print(result)

