-- sys_001: Rate Limiter
UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.concurrent.TimeUnit;

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        RateLimiter limiter = new RateLimiter(); // Instantiate the user's RateLimiter

        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String[] parts = line.split(" ");
            String command = parts[0].toUpperCase(); // Convert command to uppercase for robustness

            try {
                switch (command) {
                    case "CONFIGURE":
                        if (parts.length != 4) {
                            System.err.println("Error: CONFIGURE expects 3 arguments: userId ratePerSecond burstCapacity");
                            continue;
                        }
                        String userId = parts[1];
                        int ratePerSecond = Integer.parseInt(parts[2]);
                        int burstCapacity = Integer.parseInt(parts[3]);
                        limiter.configure(userId, ratePerSecond, burstCapacity);
                        // No output for CONFIGURE command, it's a setup step
                        break;
                    case "REQUEST":
                        if (parts.length != 2) {
                            System.err.println("Error: REQUEST expects 1 argument: userId");
                            continue;
                        }
                        String requestUserId = parts[1];
                        if (limiter.allowRequest(requestUserId)) {
                            System.out.println("allowed");
                        } else {
                            System.out.println("rate limited");
                        }
                        break;
                    case "WAIT":
                        if (parts.length != 2) {
                            System.err.println("Error: WAIT expects 1 argument: milliseconds");
                            continue;
                        }
                        long milliseconds = Long.parseLong(parts[1]);
                        TimeUnit.MILLISECONDS.sleep(milliseconds);
                        // No output for WAIT command, it's a timing control step
                        break;
                    default:
                        System.err.println("Unknown command: " + command);
                }
            } catch (NumberFormatException e) {
                System.err.println("Error parsing number in command '" + line + "': " + e.getMessage());
            } catch (Exception e) {
                System.err.println("An error occurred processing command '" + line + "': " + e.getMessage());
                e.printStackTrace();
            }
        }
        sc.close();
    }
}$harness$,
  test_cases   = '[{"input": "CONFIGURE alice 5 5\nREQUEST alice", "description": "First request within rate limit is allowed", "expected_output": "allowed"}, {"input": "CONFIGURE alice 2 2\nREQUEST alice\nREQUEST alice\nREQUEST alice", "description": "Third request exceeds rate=2 limit", "expected_output": "allowed\nallowed\nrate limited"}, {"input": "CONFIGURE alice 5 5\nREQUEST alice\nREQUEST alice\nREQUEST alice\nREQUEST alice\nREQUEST alice", "description": "Fifth request exactly at limit is allowed", "expected_output": "allowed\nallowed\nallowed\nallowed\nallowed"}, {"input": "CONFIGURE alice 1 1\nREQUEST alice\nREQUEST alice\nCONFIGURE bob 1 1\nREQUEST bob", "description": "Different user has independent bucket", "expected_output": "allowed\nrate limited\nallowed"}, {"input": "CONFIGURE alice 2 2\nREQUEST alice\nREQUEST alice\nREQUEST alice\nWAIT 1000\nREQUEST alice", "description": "Request allowed after time window resets", "expected_output": "allowed\nallowed\nrate limited\nallowed"}, {"input": "CONFIGURE carol 1 5\nREQUEST carol\nREQUEST carol\nREQUEST carol\nREQUEST carol\nREQUEST carol\nREQUEST carol", "description": "Burst capacity allows multiple initial requests, then rate limits correctly", "expected_output": "allowed\nallowed\nallowed\nallowed\nallowed\nrate limited"}, {"input": "CONFIGURE dave 0 1\nREQUEST dave\nREQUEST dave\nWAIT 1000\nREQUEST dave", "description": "Rate of 0 means no tokens refill after initial burst", "expected_output": "allowed\nrate limited\nrate limited"}, {"input": "CONFIGURE eve 1 1\nREQUEST eve\nREQUEST eve\nCONFIGURE eve 5 5\nREQUEST eve", "description": "Re-configuring a user''s rate limiter resets/updates their bucket", "expected_output": "allowed\nrate limited\nallowed"}]'::jsonb
