-- sys_002: In-Memory Cache
UPDATE challenges SET
  test_harness = $harness$import sys
import time
import re

# Assume LRUCache and CacheEntry are defined by the user

_cache = None # Global cache instance
_DEFAULT_CAPACITY = 100 # A reasonable default if not specified, can be overridden by test case

def run_harness():
    global _cache

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        # Command parsing starts here
        
        # 1. LRUCache initialization (special case, can happen only once ideally per test run)
        if line.startswith("LRUCache capacity="):
            if _cache is not None:
                # This indicates a test scenario where capacity might be re-specified
                # or an issue in test setup. For this challenge, we assume it's set once.
                sys.stderr.write("Warning: LRUCache already initialized. Re-initializing.\n")
            match = re.match(r"LRUCache capacity=(\d+)", line)
            if match:
                capacity = int(match.group(1))
                _cache = LRUCache(capacity)
                continue # Move to the next line
            else:
                sys.stderr.write(f"Error parsing LRUCache capacity command: {line}\n")
                continue

        # If cache hasn't been explicitly initialized, initialize it with default capacity
        # before processing any other command. This handles cases where no 'LRUCache capacity=X' is given.
        if _cache is None:
            _cache = LRUCache(_DEFAULT_CAPACITY)

        # 2. Other commands (require _cache to be initialized)
        if line.startswith("set key="):
            match = re.match(r"set key=(\w+) value=(.*?) ttl=(\d*\.?\d+)", line)
            if match:
                key = match.group(1)
                value_str = match.group(2)
                ttl = float(match.group(3))

                # Attempt to convert value to int/float if possible, otherwise keep as string
                try:
                    value = int(value_str)
                except ValueError:
                    try:
                        value = float(value_str)
                    except ValueError:
                        value = value_str # Keep as string
                _cache.set(key, value, ttl)
            else:
                sys.stderr.write(f"Error parsing set command: {line}\n")
        elif line.startswith("get key="):
            match = re.match(r"get key=(\w+)", line)
            if match:
                key = match.group(1)
                result = _cache.get(key)
                print(result) # Print None or the actual value
            else:
                sys.stderr.write(f"Error parsing get command: {line}\n")
        elif line.startswith("sleep "):
            match = re.match(r"sleep (\d*\.?\d+)", line)
            if match:
                seconds = float(match.group(1))
                time.sleep(seconds)
            else:
                sys.stderr.write(f"Error parsing sleep command: {line}\n")
        elif line == "stats":
            if hasattr(_cache, 'get_stats') and callable(_cache.get_stats):
                stats = _cache.get_stats() # Assume returns {'hits': X, 'misses': Y}
                # Ensure stats has expected keys and is a dictionary
                hits = stats.get('hits', 0) if isinstance(stats, dict) else 0
                misses = stats.get('misses', 0) if isinstance(stats, dict) else 0
                print(f"Hits: {hits}, Misses: {misses}")
            else:
                sys.stderr.write("Error: 'stats' command requires LRUCache to have a 'get_stats()' method that returns a dict with 'hits' and 'misses' keys.\n")
        else:
            sys.stderr.write(f"Unknown command: {line}\n")

run_harness()$harness$,
  test_cases   = '[{"input": "LRUCache capacity=10\nset key=a value=1 ttl=60\nget key=a", "description": "Set and get a cache entry", "expected_output": "1"}, {"input": "LRUCache capacity=10\nget key=missing", "description": "Get missing key returns None", "expected_output": "None"}, {"input": "LRUCache capacity=10\nset key=a value=1 ttl=0.01\nsleep 0.02\nget key=a", "description": "Expired entry returns None", "expected_output": "None"}, {"input": "LRUCache capacity=2\nset key=a value=1 ttl=60\nset key=b value=2 ttl=60\nset key=c value=3 ttl=60\nget key=a", "description": "LRU eviction: oldest key evicted when capacity exceeded", "expected_output": "None"}, {"input": "LRUCache capacity=2\nset key=a value=1 ttl=60\nset key=b value=2 ttl=60\nget key=a\nset key=c value=3 ttl=60\nget key=b", "description": "Recently accessed key stays; unused key evicted", "expected_output": "None"}, {"input": "LRUCache capacity=2\nset key=a value=1 ttl=60\nget key=a\nget key=b\nstats", "description": "Basic hit/miss statistics for cache operations", "expected_output": "1\nNone\nHits: 1, Misses: 1"}, {"input": "LRUCache capacity=2\nset key=a value=1 ttl=0.01\nget key=a\nsleep 0.02\nget key=a\nstats", "description": "Expired entry is a miss and updates stats", "expected_output": "1\nNone\nHits: 1, Misses: 1"}, {"input": "LRUCache capacity=2\nset key=a value=1 ttl=60\nget key=a\nset key=a value=2 ttl=0.01\nget key=a\nsleep 0.02\nget key=a", "description": "Updating an existing key resets its value, TTL, and moves it to MRU", "expected_output": "1\n2\nNone"}, {"input": "LRUCache capacity=1\nset key=a value=1 ttl=60\nset key=b value=2 ttl=60\nget key=a\nget key=b", "description": "Key evicted due to capacity can be re-added", "expected_output": "None\n2"}, {"input": "LRUCache capacity=3\nset key=a value=1 ttl=60\nset key=b value=2 ttl=60\nset key=c value=3 ttl=60\nget key=a\nget key=b\nset key=d value=4 ttl=60\nget key=c", "description": "Multiple gets on different keys correctly update LRU order before eviction", "expected_output": "1\n2\nNone"}]'::jsonb
