-- sys_003: Job Queue
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

// Assume Job, JobQueue, WorkerPool are available from user code
// The global types (JobStatus, Priority, Job interface) are also assumed to be available.

// --- Harness Internal Job Definition ---
// This class acts as the concrete implementation of the 'Job' interface
// that the JobQueue will receive. It simulates the success/failure behavior.
class HarnessJob implements Job {
    id: string;
    priority: Priority;
    status: JobStatus = 'queued'; // JobQueue is expected to update this property
    private executeFailure: boolean;

    constructor(id: string, priority: Priority, executeBehavior: 'ok' | 'fail') {
        this.id = id;
        this.priority = priority;
        this.executeFailure = (executeBehavior === 'fail');
    }

    async execute(): Promise<void> {
        // This log helps in testing priority and concurrent execution order
        console.log(`Executing job ${this.id}`); 
        await new Promise(resolve => setTimeout(resolve, 10)); // Simulate async work duration
        if (this.executeFailure) {
            throw new Error(`Job ${this.id} failed intentionally.`);
        }
        return; // Success
    }
}

// --- Harness Main Logic ---
const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', async () => {
  let jobQueue: JobQueue | undefined;
  // Map to store HarnessJob instances, allowing harness to check their status
  const jobsMap = new Map<string, HarnessJob>();

  for (const line of lines) {
    const parts = line.split(' ');
    const command = parts[0];
    const args = parts.slice(1).reduce((acc, arg) => {
      const [key, value] = arg.split('=');
      acc[key] = value;
      return acc;
    }, {} as Record<string, string>);

    switch (command) {
      case 'init': {
        const maxWorkers = parseInt(args['maxWorkers'] || '3', 10);
        const defaultMaxAttempts = parseInt(args['defaultMaxAttempts'] || '1', 10); // Default max attempts for jobs

        // User's JobQueue constructor is assumed to be `JobQueue(maxConcurrency: number, defaultMaxAttempts: number)`
        jobQueue = new JobQueue(maxWorkers, defaultMaxAttempts);
        console.log(`Initialized JobQueue with maxWorkers=${maxWorkers}, defaultMaxAttempts=${defaultMaxAttempts}`);
        break;
      }
      case 'enqueue': {
        if (!jobQueue) {
          console.error("JobQueue not initialized. Use 'init' first.");
          return; // Stop processing further commands if JobQueue isn't ready
        }
        const id = args['id'];
        const priority: Priority = (args['priority'] as Priority) || 'normal';
        const executeBehavior: 'ok' | 'fail' = (args['execute'] as 'ok' | 'fail') || 'ok';
        // maxAttempts can be overridden per job. If not provided, JobQueue's default will be used.
        const maxAttempts = args['maxAttempts'] ? parseInt(args['maxAttempts'], 10) : undefined;

        const job = new HarnessJob(id, priority, executeBehavior);
        jobsMap.set(id, job);
        
        // User's enqueue method is assumed to be `enqueue(job: Job, maxAttempts?: number)`
        jobQueue.enqueue(job, maxAttempts);
        console.log(`${id} queued`); // Matches expected output format from original test cases
        break;
      }
      case 'startProcessing': {
        if (!jobQueue) {
            console.error("JobQueue not initialized. Use 'init' first.");
            return;
        }
        // User's JobQueue is assumed to have a `startProcessing()` method to begin worker operations
        jobQueue.startProcessing();
        console.log("Job processing started.");
        break;
      }
      case 'waitForIdle': {
        if (!jobQueue) {
            console.error("JobQueue not initialized. Use 'init' first.");
            return;
        }
        // User's JobQueue is assumed to have an async `waitForIdle()` method
        // that resolves when all currently queued and running jobs have reached a terminal state (done/failed).
        try {
          await jobQueue.waitForIdle();
          console.log("Processing cycle completed.");
        } catch (error: any) {
          console.error(`Error waiting for idle: ${error.message || error}`);
        }
        break;
      }
      case 'status': {
        const id = args['id'];
        if (!jobQueue) {
            console.error("JobQueue not initialized. Use 'init' first.");
            return;
        }
        const job = jobsMap.get(id);
        if (job) {
          // The HarnessJob instance's status property should be updated by the JobQueue during processing
          console.log(`${id}: ${job.status}`);
        } else {
          console.log(`${id}: not found`);
        }
        break;
      }
      case 'statusAll': {
        if (!jobQueue) {
            console.error("JobQueue not initialized. Use 'init' first.");
            return;
        }
        const statuses: string[] = [];
        // Iterate through all jobs known to the harness to get their current status
        for (const [id, job] of jobsMap.entries()) {
            statuses.push(`${id}: ${job.status}`);
        }
        statuses.sort(); // Ensure consistent output order for multiple jobs
        console.log(statuses.join('\n'));
        break;
      }
      case 'stopProcessing': { // Optional: A command to explicitly stop the worker pool
        if (!jobQueue) {
            console.error("JobQueue not initialized. Use 'init' first.");
            return;
        }
        // User's JobQueue is assumed to have a `stopProcessing()` method
        jobQueue.stopProcessing();
        console.log("Job processing stopped.");
        break;
      }
      default: {
        console.log(`Unknown command: ${command}`);
      }
    }
    // A small delay between commands to allow for microtask queue to clear and prevent race conditions
    // in cases where job processing might be synchronous or very fast.
    await new Promise(resolve => setTimeout(resolve, 5));
  }
});$harness$,
  test_cases   = '[{"input": "init maxWorkers=1 defaultMaxAttempts=1\nenqueue id=j1 priority=high execute=ok\nstatus id=j1", "description": "Enqueue a high-priority job and check its initial status", "expected_output": "Initialized JobQueue with maxWorkers=1, defaultMaxAttempts=1\nj1 queued\nj1: queued"}, {"input": "init maxWorkers=1 defaultMaxAttempts=1\nenqueue id=j1 priority=low execute=ok\nenqueue id=j2 priority=high execute=ok\nstartProcessing\nwaitForIdle\nstatusAll", "description": "High-priority job processes before low-priority, observable via execution logs", "expected_output": "Initialized JobQueue with maxWorkers=1, defaultMaxAttempts=1\nj1 queued\nj2 queued\nJob processing started.\nExecuting job j2\nExecuting job j1\nProcessing cycle completed.\nj1: done\nj2: done"}, {"input": "init maxWorkers=1 defaultMaxAttempts=1\nenqueue id=j1 priority=normal execute=fail maxAttempts=3\nstartProcessing\nwaitForIdle\nstatus id=j1", "description": "Failed job retries up to maxAttempts (3 attempts total)", "expected_output": "Initialized JobQueue with maxWorkers=1, defaultMaxAttempts=1\nj1 queued\nJob processing started.\nExecuting job j1\nExecuting job j1\nExecuting job j1\nProcessing cycle completed.\nj1: failed"}, {"input": "init maxWorkers=1 defaultMaxAttempts=1\nenqueue id=j1 execute=ok\nstartProcessing\nwaitForIdle\nstatus id=j1", "description": "Successful job status transitions to done", "expected_output": "Initialized JobQueue with maxWorkers=1, defaultMaxAttempts=1\nj1 queued\nJob processing started.\nExecuting job j1\nProcessing cycle completed.\nj1: done"}, {"input": "init maxWorkers=1 defaultMaxAttempts=1\nenqueue id=j1 execute=fail maxAttempts=1\nstartProcessing\nwaitForIdle\nstatus id=j1", "description": "Job exhausting retries (1 attempt) transitions to failed", "expected_output": "Initialized JobQueue with maxWorkers=1, defaultMaxAttempts=1\nj1 queued\nJob processing started.\nExecuting job j1\nProcessing cycle completed.\nj1: failed"}, {"input": "init maxWorkers=1 defaultMaxAttempts=1\nenqueue id=L1 priority=low execute=ok\nenqueue id=H1 priority=high execute=ok\nenqueue id=H2 priority=high execute=ok\nenqueue id=H3 priority=high execute=ok\nenqueue id=H4 priority=high execute=ok\nenqueue id=H5 priority=high execute=ok\nstartProcessing\nwaitForIdle\nstatusAll", "description": "Low-priority job eventually processes, demonstrating no indefinite starvation", "expected_output": "Initialized JobQueue with maxWorkers=1, defaultMaxAttempts=1\nL1 queued\nH1 queued\nH2 queued\nH3 queued\nH4 queued\nH5 queued\nJob processing started.\nExecuting job H1\nExecuting job H2\nExecuting job H3\nExecuting job H4\nExecuting job H5\nExecuting job L1\nProcessing cycle completed.\nH1: done\nH2: done\nH3: done\nH4: done\nH5: done\nL1: done"}, {"input": "init maxWorkers=2 defaultMaxAttempts=1\nenqueue id=j1 priority=low execute=ok\nenqueue id=j2 priority=high execute=ok\nenqueue id=j3 priority=normal execute=ok\nstartProcessing\nwaitForIdle\nstatusAll", "description": "Multiple workers process jobs respecting priority and concurrency", "expected_output": "Initialized JobQueue with maxWorkers=2, defaultMaxAttempts=1\nj1 queued\nj2 queued\nj3 queued\nJob processing started.\nExecuting job j2\nExecuting job j3\nExecuting job j1\nProcessing cycle completed.\nj1: done\nj2: done\nj3: done"}]'::jsonb
