                        System.out.println(lastShortCode);
                        break;
                    case "resolve":
                        String codeToResolve = arg.equals("__LAST_CODE__") ? lastShortCode : arg;
                        if (codeToResolve == null) {
                            System.out.println("Error: No short code available for __LAST_CODE__");
                            break;
                        }
                        String resolvedUrl = shortener.resolve(codeToResolve);
                        System.out.println(resolvedUrl);
                        break;
                    case "get_hits": // Custom command to check hit count
