                        if (codeForHits == null) {
                            System.out.println("Error: No short code available for __LAST_CODE__");
                            break;
                        }
                        // Assuming UrlShortener has a getHitCount method
                        int hits = shortener.getHitCount(codeForHits);
                        System.out.println("hits: " + hits);
                        break;
                    default:
                        System.out.println("Unknown command: " + command);
                        break;
                }
            } catch (Exception e) {
                System.out.println("Error executing command: " + e.getMessage());
            }
        }
        sc.close();
    }
