-- sys_005: Distributed Lock Manager
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', async () => {
  // The user's Scheduler class is available in this scope.
  // We instantiate it here to maintain state across commands.
  const scheduler = new Scheduler();

  for (const line of lines) {
    if (!line) {
      // Allow empty lines in input, just skip them without error
      continue;
    }

    try {
      if (line.startsWith('acquire_lock')) {
        const resourceMatch = line.match(/resource=([\w_]+)/);
        const clientMatch = line.match(/client=([\w_]+)/);
        const ttlMatch = line.match(/ttl=(\d+)s/);

        if (!resourceMatch || !clientMatch || !ttlMatch) {
          console.log(`Error: Invalid acquire_lock command format: ${line}`);
          continue;
        }

        const resource = resourceMatch[1];
        const client = clientMatch[1];
        const ttl = parseInt(ttlMatch[1], 10);

        // Assume Scheduler has an 'acquire' method with signature: (resource: string, client: string, ttl: number) => Promise<string>
        const result = await scheduler.acquire(resource, client, ttl);
        console.log(result);

      } else if (line.startsWith('release_lock')) {
        const resourceMatch = line.match(/resource=([\w_]+)/);
        const clientMatch = line.match(/client=([\w_]+)/);

        if (!resourceMatch || !clientMatch) {
          console.log(`Error: Invalid release_lock command format: ${line}`);
          continue;
        }

        const resource = resourceMatch[1];
        const client = clientMatch[1];

