        Pattern consumePattern = Pattern.compile("consume queue=(?<queue>[^,]+), consumer=(?<consumer>[^,]+)");
        Pattern depthPattern = Pattern.compile("queue_depth queue=(?<queue>.+)");

        while (scanner.hasNextLine()) {
            String commandLine = scanner.nextLine().trim();
