            Matcher consumeMatcher = consumePattern.matcher(commandLine);
            Matcher depthMatcher = depthPattern.matcher(commandLine);

            if (publishMatcher.matches()) {
                String queue = publishMatcher.group("queue");
                String message = publishMatcher.group("message");
                // Call the user's Service.publish method
                result = service.publish(queue, message);
            } else if (consumeMatcher.matches()) {
                String queue = consumeMatcher.group("queue");
                String consumer = consumeMatcher.group("consumer");
