UPDATE challenges SET
  test_harness = $harness$import sys
import re
import time

# Mock time provider for deterministic testing
class TestTime:
    def __init__(self, initial_time=0):
        self._current_time = initial_time

    def time(self):
        return self._current_time

    def advance(self, seconds):
        self._current_time += seconds

# The harness acts as the entry point and manages the user's classes.
# It interacts with user's `Worker` which in turn uses user's `Service`.
def run_harness():
    # Initialize test environment
    test_time_provider = TestTime(initial_time=0) # All time starts at 0 for tests
    worker_instance = Worker(time_provider=test_time_provider)

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        parts = line.split(',')
        command = parts[0].strip()

        params = {}
        for part in parts[1:]:
            if '=' in part:
                key, value = part.split('=', 1)
                params[key.strip()] = value.strip()

        output = ""
        try:
            if command == "configure":
                service_name = params['service']
                threshold = int(params.get('threshold', 3)) # Default threshold
                timeout = int(params.get('timeout', 5)) # Default timeout
                worker_instance.configure_service(service_name, threshold, timeout)
                output = f"Configured {service_name} (threshold={threshold}, timeout={timeout})"

            elif command == "call":
                service_name = params['service']
                # 'failures' param indicates how many times the *backend operation* should fail within this call.
                # If failures=0, backend operation succeeds.
                fail_count = int(params.get('failures', 0))

                # Inject failures into the mock backend before the call
                worker_instance._inject_failure_for_next_n_calls(service_name, fail_count)
                
                # Make the call via the worker, which uses the circuit breaker logic
                output = worker_instance.call(service_name)

            elif command == "advance_time":
                seconds_to_advance = int(params['seconds'])
                test_time_provider.advance(seconds_to_advance)
                output = f"Time advanced by {seconds_to_advance}s. Current time: {test_time_provider.time()}"
            
            # Internal harness command for testing specific CB states directly (optional, but useful for complex scenarios)
            elif command == "set_state_for_testing":
                service_name = params['service']
                state = params['state'] # e.g., "OPEN", "HALF-OPEN", "CLOSED"
                worker_instance._set_service_state_for_testing(service_name, state)
                output = f"Service {service_name} state set to {state} for testing."

            else:
                output = f"Unknown command: {command}"
        except Exception as e:
            output = f"Error processing command '{command}': {e}"
        
        print(output)

# Call the harness function at module level
run_harness()$harness$,
