import java.util.stream.Collectors;

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        Service service = new Service(); // User's Service class

        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) {
                continue; // Skip empty lines
            }

            String result = "";
            if (line.startsWith("write transaction=")) {
                int txnIdStart = line.indexOf("transaction=") + "transaction=".length();
                int txnIdEnd = line.indexOf(",", txnIdStart); // Find comma after transaction ID
                String transactionId = line.substring(txnIdStart, txnIdEnd).trim();

                int dataStart = line.indexOf("data=") + "data=".length();
                String data = line.substring(dataStart).trim();
                
                result = service.write(transactionId, data);
            } else if (line.startsWith("commit transaction=")) {
                int txnIdStart = line.indexOf("transaction=") + "transaction=".length();
                String transactionId = line.substring(txnIdStart).trim();
                
                result = service.commit(transactionId);
            } else if (line.startsWith("crash_recovery wal_entries=")) {
                int entriesStart = line.indexOf("wal_entries=") + "wal_entries=".length();
                String entriesStr = line.substring(entriesStart).trim(); // e.g., "[TXN001, TXN002]" or "[]"

                List<String> walEntries = new ArrayList<>();
                // Only parse if there are actual entries inside the brackets
                if (entriesStr.length() > 2 && entriesStr.startsWith("[") && entriesStr.endsWith("]")) {
                    entriesStr = entriesStr.substring(1, entriesStr.length() - 1); // Remove [ and ]
                    walEntries = Arrays.asList(entriesStr.split(", ")).stream()
                                    .map(String::trim)
                                    .collect(Collectors.toList());
                }
                result = service.recover(walEntries);
            } else if (line.startsWith("checkpoint wal")) {
                result = service.checkpoint();
            } else {
                result = "ERROR: Unknown command '" + line + "'";
            }
            System.out.println(result);
        }
        sc.close();
    }
