UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

// Helper to parse command lines into structured objects
function parseCommand(line: string): { command: string; args: Record<string, string> } {
  const parts = line.split(' ');
  const command = parts[0];
  const args: Record<string, string> = {};
  for (let i = 1; i < parts.length; i++) {
    const [key, value] = parts[i].split('=');
    args[key] = value;
  }
  return { command, args };
}

const rl = readline.createInterface({
  input: process.stdin
});

const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', async () => {
  // The user's `Scheduler` class is expected to implement rate limiting logic.
  // The harness will call methods like `handleRequest` and `resetClientWindow`
  // on an instance of this class. Users must add these methods to their Scheduler.
  const scheduler = new Scheduler();

  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    const { command, args } = parseCommand(line);

    try {
      switch (command) {
        case 'request': {
          const client = args['client'];
          const endpoint = args['endpoint'];
          const windowStr = args['window'];
          const limit = parseInt(args['limit'], 10);

          if (!client || !endpoint || !windowStr || isNaN(limit)) {
            console.error(`Error: Missing or invalid arguments for 'request' command: ${line}`);
            continue;
          }

          const windowSeconds = parseInt(windowStr.slice(0, -1), 10); // Converts "60s" to 60
          // Cast to `any` because the user's `Scheduler` class is initially empty,
          // and they are expected to add these methods.
          const output = await (scheduler as any).handleRequest(client, endpoint, windowSeconds, limit);
          console.log(output);
          break;
        }
        case 'requests': {
          const client = args['client'];
          const count = parseInt(args['count'], 10);
          const windowStr = args['window'];

          // For 'requests' command, default endpoint and limit are assumed
          // based on original test cases if not explicitly provided.
          const endpoint = '/api/data';
          const limit = 100; 

          if (!client || isNaN(count) || !windowStr) {
            console.error(`Error: Missing or invalid arguments for 'requests' command: ${line}`);
            continue;
          }

          const windowSeconds = parseInt(windowStr.slice(0, -1), 10);

          for (let i = 0; i < count; i++) {
            const output = await (scheduler as any).handleRequest(client, endpoint, windowSeconds, limit);
            console.log(output);
          }
          break;
        }
        case 'window_reset': {
          const client = args['client'];

          if (!client) {
            console.error(`Error: Missing client argument for 'window_reset' command: ${line}`);
            continue;
          }

          const output = await (scheduler as any).resetClientWindow(client);
          console.log(output);
          break;
        }
        default:
          console.error(`Unknown command: ${command}`);
          break;
      }
    } catch (e: any) {
      console.error(`Error executing command '${command}' on line '${line}': ${e.message}`);
    }
  }
