-- sys_012: Service Discovery Registry
UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.HashMap;
import java.util.Map;

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        Service registry = new Service(); // Instantiate the user's Service class

        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            // Parse the command and arguments
            String[] parts = line.split(" ", 2); // Split "command args"
            String command = parts[0];
            Map<String, String> params = parseParameters(parts.length > 1 ? parts[1] : "");

            String result = null;
            switch (command) {
                case "register":
                    String regService = params.get("service");
                    String regHost = params.get("host");
                    int regPort = Integer.parseInt(params.get("port"));
                    result = registry.register(regService, regHost, regPort);
                    break;
                case "discover":
                    String discService = params.get("service");
                    result = registry.discover(discService);
                    break;
                case "deregister":
                    String deregService = params.get("service");
                    String deregHost = params.get("host");
                    // Assuming deregister method takes service and host, and implies port from internal state
                    result = registry.deregister(deregService, deregHost);
                    break;
                case "health_check":
                    String hcService = params.get("service");
                    String hcStatus = params.get("status");
                    // Assuming healthCheck method takes service and status, and implies which instance from internal state
                    result = registry.healthCheck(hcService, hcStatus);
                    break;
                default:
                    result = "Unknown command: " + command;
                    break;
            }
            if (result != null) {
                System.out.println(result);
            }
        }
        sc.close();
    }

    // Helper method to parse "key=value, key2=value2" strings
    private static Map<String, String> parseParameters(String paramString) {
        Map<String, String> params = new HashMap<>();
        if (paramString == null || paramString.isEmpty()) {
            return params;
        }
        // Split by ", " to get individual key=value pairs, handle potential multiple spaces after comma
        String[] pairs = paramString.split(",\s*");
        for (String pair : pairs) {
            String[] kv = pair.split("=", 2);
            if (kv.length == 2) {
                params.put(kv[0].trim(), kv[1].trim());
            }
        }
        return params;
    }
