-- sys_013: Event Sourcing Store
UPDATE challenges SET
  test_harness = $harness$import sys

# The user's Service and Worker classes will be provided here.
# For the purpose of making this harness self-contained and runnable
# during development, a basic mock implementation is included.
# This mock will be replaced by the user's actual code during testing.

class Service:
    def __init__(self):
        self._stores = {} # Stores events: {aggregate_key: [{'type': '...', 'data': {...}}]}
        self._snapshots = {} # Stores snapshots: {aggregate_key: {version: snapshot_data}}

    def append_event(self, aggregate_type, aggregate_id, event_type, event_data):
        key = f"{aggregate_type}_{aggregate_id}"
        if key not in self._stores:
            self._stores[key] = []
        self._stores[key].append({'type': event_type, 'data': event_data})
        return f"Event appended: {event_type} for {aggregate_type} {aggregate_id}"

    def replay_events(self, aggregate_type, aggregate_id):
        key = f"{aggregate_type}_{aggregate_id}"
        events = self._stores.get(key, [])
        # In a real system, this would iterate events and rebuild an aggregate's state.
        # For the harness, we just need to return the expected string based on event count.
        return f"{aggregate_type.capitalize()}_{aggregate_id} state reconstructed from {len(events)} events"

    def get_events(self, aggregate_type, aggregate_id, from_version=0):
        key = f"{aggregate_type}_{aggregate_id}"
        events = self._stores.get(key, [])
        
        # Ensure 'from_version' is within bounds
        if from_version < 0:
            from_version = 0
        if from_version >= len(events) and events:
            # If from_version is at or beyond the last event, but there are events, return empty list
            return f"Events: []"
        elif not events:
             # No events at all
            return f"Events: []"

        relevant_events = events[from_version:]
        event_types = [e['type'] for e in relevant_events]
        
        # Format as "[Type1, Type2, ...]" without quotes for event names for exact match
        formatted_event_types = ', '.join(event_types)
        return f"Events: [{formatted_event_types}]"

    def snapshot(self, aggregate_type, aggregate_id, version):
        key = f"{aggregate_type}_{aggregate_id}"
        if key not in self._snapshots:
            self._snapshots[key] = {}
        
        # In a real system, a serialized state of the aggregate at 'version' would be saved.
        # For the harness, we just record that a snapshot was requested. 
        # We can simulate saving the state based on events up to that version.
        events_up_to_version = self._stores.get(key, [])[:version] # Assuming version is 1-indexed count
        self._snapshots[key][version] = {'event_count': len(events_up_to_version), 'version': version}

        return f"Snapshot saved for {aggregate_type}_{aggregate_id} at version {version}"

class Worker:
    # Basic mock Worker, as its interaction isn't specified by commands
    def __init__(self):
        pass

# Helper function to parse commands from stdin
def parse_command(line):
    # This parser assumes specific command formats:
    # "append event={key: value, ...}"
    # "replay events aggregate=order_1"
    # "get_events aggregate=order_1, from=0"
    # "snapshot aggregate=order_1 at version=3"

    parts = line.strip().split(' ', 1)
    command = parts[0]
    args_str = ''
    if len(parts) > 1:
        args_str = parts[1]

    args = {}

    if command == 'append':
        if args_str.startswith('event={'):
            # Find the closing brace for the event payload, assuming no nested braces.
            event_payload_start_idx = args_str.find('{')
            event_payload_end_idx = args_str.rfind('}')

            if event_payload_start_idx != -1 and event_payload_end_idx != -1 and event_payload_start_idx < event_payload_end_idx:
                event_data_str = args_str[event_payload_start_idx : event_payload_end_idx + 1]
                event_dict = {}
                inner_content = event_data_str[1:-1].strip()
                if inner_content:
                    for item in inner_content.split(', '):
                        if ': ' in item:
                            k, v = item.split(': ', 1)
                            event_dict[k.strip()] = v.strip()
                args['event'] = event_dict
            # If malformed, 'event' key will simply not be in args
        # No other arguments expected for 'append' based on problem examples.

    elif command == 'replay':
        # Expecting "events aggregate=..."
        if args_str.startswith('events '):
            args_str_rest = args_str[len('events '):] # Remove 'events ' keyword
            for arg_pair in args_str_rest.split(', '):
                if '=' in arg_pair:
                    k, v = arg_pair.split('=', 1)
                    args[k.strip()] = v.strip()
            args['__command_keyword__'] = 'events' # Indicate that 'events' was present

    elif command == 'get_events':
        # Expecting "aggregate=..., from=..."
        for arg_pair in args_str.split(', '):
            if '=' in arg_pair:
                k, v = arg_pair.split('=', 1)
                args[k.strip()] = v.strip()

    elif command == 'snapshot':
        # Expecting "aggregate=... at version=..."
        # Normalize "at version=" to "version=" for easier parsing
        normalized_args_str = args_str.replace('at version=', 'version=')
        for arg_pair in normalized_args_str.split(', '):
            if '=' in arg_pair:
                k, v = arg_pair.split('=', 1)
                args[k.strip()] = v.strip()

    return command, args

def run_harness():
    # Instantiate the user's Service class once for stateful operations
    service = Service()
    # If Worker were directly callable by commands, it would be instantiated here too.
    # worker = Worker() 

    for line in sys.stdin:
        line = line.strip()
        if not line: # Skip empty lines
            continue

        command, args = parse_command(line)
        output = None

        if command == "append":
            event_data = args.get('event')
            if event_data:
                event_type = event_data.get('type')
                # Based on example, 'order_id' inside event data is the specific aggregate ID
                aggregate_id = event_data.get('order_id') 
                # Hardcoded as 'order' based on problem example 'order_1'
                aggregate_type = 'order' 
                
                if event_type and aggregate_id:
                    output = service.append_event(aggregate_type, str(aggregate_id), event_type, event_data)
                else:
                    output = f"Error: Malformed event data in append command: {line}"
            else:
                output = f"Error: Missing event data in append command: {line}"
        
        elif command == "replay":
            if args.get('__command_keyword__') == 'events': # Check if 'events' keyword was present
                aggregate_full_id = args.get('aggregate')
                if aggregate_full_id and '_' in aggregate_full_id: # Expect format like 'order_1'
                    aggregate_type, aggregate_id = aggregate_full_id.split('_', 1)
                    output = service.replay_events(aggregate_type, aggregate_id)
                else:
                    output = f"Error: Malformed replay aggregate ID: {line}"
            else:
                output = f"Error: 'replay' command expects 'events' keyword (e.g., 'replay events aggregate=...'): {line}"

        elif command == "get_events":
            aggregate_full_id = args.get('aggregate')
            from_version_str = args.get('from', '0') # Default to '0' if not provided
            try:
                from_version = int(from_version_str)
            except ValueError:
                output = f"Error: Invalid 'from' version in get_events command: {line}"
                print(output)
                continue # Skip further processing for this command

            if aggregate_full_id and '_' in aggregate_full_id: # Expect format like 'order_1'
                aggregate_type, aggregate_id = aggregate_full_id.split('_', 1)
                output = service.get_events(aggregate_type, aggregate_id, from_version)
            else:
                output = f"Error: Malformed get_events aggregate ID: {line}"

        elif command == "snapshot":
            aggregate_full_id = args.get('aggregate')
            # 'version' key due to normalization from 'at version=' in parse_command
            version_str = args.get('version') 
            if aggregate_full_id and '_' in aggregate_full_id and version_str: # Expect format like 'order_1'
                aggregate_type, aggregate_id = aggregate_full_id.split('_', 1)
                try:
                    version = int(version_str)
                    output = service.snapshot(aggregate_type, aggregate_id, version)
                except ValueError:
                    output = f"Error: Invalid version in snapshot command: {line}"
            else:
                output = f"Error: Malformed snapshot command (missing aggregate or version): {line}"
        else:
