-- sys_014: CQRS Command Dispatcher
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', async () => {
  // The user's Scheduler class is expected to be defined and available here.
  // The harness assumes the user's Scheduler implements 'dispatch' and 'query' methods.
  // Example interface assumed for user's Scheduler:
  // class Scheduler {
  //   async dispatch(commandType: string, payload: Record<string, any>): Promise<string> { /* ... */ }
  //   async query(queryType: string, params: Record<string, any>): Promise<string> { /* ... */ }
  // }

  const scheduler = new Scheduler();

  let expectedRejection: { commandType: string; reason: string } | null = null;
  const outputs: string[] = [];

  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    if (line.startsWith("reject command=")) {
      // This is a special instruction for the harness to expect a rejection for the next command.
      const instruction = line.substring("reject command=".length);
      const parts = instruction.split(", ");
      const commandType = parts[0];
      const reasonMatch = parts.find(p => p.startsWith("reason="));
      if (reasonMatch) {
        const reason = reasonMatch.substring("reason=".length);
        expectedRejection = { commandType: commandType, reason: reason };
      } else {
        outputs.push("Harness Error: Malformed reject command instruction. Missing 'reason=' parameter.");
        expectedRejection = null; // Clear any partial state if instruction is malformed
      }
    } else if (line.startsWith("command=")) {
      const commandString = line.substring("command=".length);
      const parts = commandString.split(", ");
      const commandType = parts[0];
      let payload: Record<string, any> = {};

      const payloadPart = parts.find(p => p.startsWith("payload="));
      if (payloadPart) {
        try {
          // Payload is expected to be a valid JSON string
          payload = JSON.parse(payloadPart.substring("payload=".length));
        } catch (e: any) {
          outputs.push(`Harness Error: Failed to parse payload for command '${commandType}': ${e.message || String(e)}`);
          continue; // Skip this command due to parsing error
        }
      }

      let result: string | null = null;

      if (expectedRejection && expectedRejection.commandType === commandType) {
        try {
          // We expect the user's dispatch method to throw an error here
          await scheduler.dispatch(commandType, payload);
          // If it didn't throw, it's a test failure
          result = `Harness Error: Command '${commandType}' was expected to be rejected but succeeded.`;
        } catch (e: any) {
          // Expected rejection occurred, check the error message
          const actualReason = e.message || String(e);
          if (actualReason.includes(expectedRejection.reason)) {
            // Format the output to match the expected format (e.g., 'validation_error' -> 'validation error')
            result = `Command rejected: ${expectedRejection.reason.replace(/_/g, ' ')} in ${commandType}`;
          } else {
            result = `Harness Error: Command '${commandType}' rejected with unexpected reason: '${actualReason}', expected to contain: '${expectedRejection.reason}'`;
          }
        } finally {
          expectedRejection = null; // Reset rejection state after attempting the command
        }
      } else {
        // No expected rejection, dispatch normally
        try {
          result = await scheduler.dispatch(commandType, payload);
        } catch (e: any) {
          result = `Harness Error: Command '${commandType}' failed unexpectedly: ${e.message || String(e)}`;
        }
      }
      if (result !== null) outputs.push(result);

    } else if (line.startsWith("query=")) {
      const queryString = line.substring("query=".length);
      const parts = queryString.split(", ");
      const queryType = parts[0];
      const params: Record<string, any> = {};

      for (let i = 1; i < parts.length; i++) {
        const [key, value] = parts[i].split("=");
        if (key && value) {
          // Attempt to parse primitive types (number, boolean), otherwise keep as string
          if (!isNaN(Number(value)) && !isNaN(parseFloat(value))) {
            params[key] = Number(value);
          } else if (value === 'true') {
            params[key] = true;
          } else if (value === 'false') {
            params[key] = false;
          } else {
            params[key] = value; // Default to string
          }
        }
      }

      try {
        const result = await scheduler.query(queryType, params);
        outputs.push(result);
      } catch (e: any) {
        outputs.push(`Harness Error: Query '${queryType}' failed unexpectedly: ${e.message || String(e)}`);
      }
    } else {
      outputs.push(`Harness Error: Unknown command format: '${line}'`);
    }
  }

  // Print all collected outputs to stdout
  outputs.forEach(output => console.log(output));
});$harness$,
  test_cases   = '[{"input": "command=CreateOrder, payload={\"user\": \"alice\", \"items\": [\"book\"]}", "description": "Dispatch write command", "expected_output": "CreateOrder command dispatched to OrderService"}, {"input": "query=GetOrder, id=ORD001", "description": "Serve read query from read model", "expected_output": "GetOrder query served from read model"}, {"input": "command=CreateOrder, payload={\"id\": \"ORD001\", \"user\": \"alice\", \"items\": [\"book\"]}\ncommand=CancelOrder, id=ORD001", "description": "Command updates read model", "expected_output": "CreateOrder command dispatched to OrderService\nCancelOrder command dispatched, read model updated"}, {"input": "reject command=CreateOrder, reason=validation_error\ncommand=CreateOrder, payload={\"user\": \"bob\", \"items\": [\"pen\"]}", "description": "Reject invalid command", "expected_output": "Command rejected: validation error in CreateOrder"}]'::jsonb
WHERE id = 'sys_014';
