-- sys_016: Bloom Filter Membership Checker
UPDATE challenges SET
  test_harness = $harness$import sys
import re
import math

def calculate_theoretical_fpr(n, m):
    """Calculates the theoretical false positive rate for a Bloom filter.
    n: expected number of elements
    m: number of bits in the filter
    """
    if n <= 0 or m <= 0:
        # If no elements are expected or no bits are available, FPR is effectively 100%
        return 1.0 
    
    # Optimal number of hash functions k = (m/n) * ln(2)
    k = (m / n) * math.log(2)
    
    # Probability of a bit being 1 after n insertions, with optimal k
    # p_bit_is_one = 1 - e^(-kn/m)
    # With k = (m/n)ln(2), the exponent -kn/m simplifies to -ln(2)
    # So, e^(-kn/m) = e^(-ln(2)) = 1/2
    # Thus, p_bit_is_one = 1 - 1/2 = 1/2
    p_bit_is_one = 0.5
    
    # False positive rate (FPR) = (probability of a bit being 1)^k
    fpr = p_bit_is_one ** k
    
    return fpr

def run_harness():
    # Instantiate the user's Service class once for stateful operations.
    # We assume the Service class can be initialized without arguments
    # and sets up a default Bloom Filter or equivalent mechanism.
    service = Service() # User's Service class

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        # Define regex patterns for commands
        add_match = re.match(r"add element=(.+)", line)
        check_match = re.match(r"check element=(.+)", line)
        fpr_match = re.match(r"false_positive_rate elements=(\d+), bits=(\d+)", line)

        if add_match:
            element = add_match.group(1)
            service.add(element) # Call user's add method
            print(f"{element} added to bloom filter")
        elif check_match:
            element = check_match.group(1)
            is_in_set = service.check(element) # Call user's check method, expects boolean
            # Output format matches specific requirements from original test cases
            if is_in_set:
                print(f"Probably in set: true")
            else:
                print(f"Definitely not in set: false")
        elif fpr_match:
            elements_count = int(fpr_match.group(1))
            bits_count = int(fpr_match.group(2))
            
            # Calculate FPR using the helper function defined in the harness.
            # This calculation is theoretical and does not interact with the 'service' state.
            fpr = calculate_theoretical_fpr(elements_count, bits_count)
            # Format as percentage with one decimal place, matching expected output.
            print(f"Expected false positive rate: {fpr:.1%}")
        else:
            print(f"ERROR: Unknown command '{line}'")

# Call the harness function at module level as required.
run_harness()$harness$,
  test_cases   = '[{"input": "add element=user@example.com", "description": "Add element to bloom filter", "expected_output": "user@example.com added to bloom filter"}, {"input": "add element=user@example.com\ncheck element=user@example.com", "description": "Check existing element", "expected_output": "user@example.com added to bloom filter\nProbably in set: true"}, {"input": "add element=user@example.com\ncheck element=nonexistent@test.com", "description": "Check non-existing element", "expected_output": "user@example.com added to bloom filter\nDefinitely not in set: false"}, {"input": "false_positive_rate elements=1000, bits=10000", "description": "Calculate false positive rate", "expected_output": "Expected false positive rate: 1.2%"}]'::jsonb
