        const parts = line.split(' ');
        // Expected format: start_saga sagaType={...json...}
        if (parts.length < 2) {
          console.error(`Error: Malformed start_saga command: ${line}`);
          continue;
        }
        const commandPayload = parts[1]; // e.g., order={...}
        const payloadParts = commandPayload.split('=', 2);
        if (payloadParts.length < 2) {
          console.error(`Error: Malformed start_saga payload: ${line}`);
          continue;
        }
        const sagaType = payloadParts[0]; // e.g., 'order'
        const rawDetails = payloadParts[1]; // e.g., "{user: \"alice\", ...}"
        const details = JSON.parse(rawDetails);

        // The user's Scheduler class is expected to have an async startSaga method
        const output = await scheduler.startSaga(sagaType, details);
        console.log(output);

      } else if (line.startsWith('step=')) {
        // Expected format: step=step_name, result=success|failure
        const params = line.split(',').map(p => p.trim());
        let stepName: string | null = null;
        let result: 'success' | 'failure' | null = null;

        for (const param of params) {
          if (param.startsWith('step=')) {
            stepName = param.substring('step='.length);
          } else if (param.startsWith('result=')) {
            const res = param.substring('result='.length);
            if (res === 'success' || res === 'failure') {
              result = res;
            } else {
              console.error(`Error: Invalid result for step command: ${res}`);
            }
          }
        }

        if (stepName && result) {
          // The user's Scheduler class is expected to have an async handleStepResult method
          const output = await scheduler.handleStepResult(stepName, result);
          console.log(output);
        } else {
          console.error(`Error: Malformed step command: ${line}`);
        }
      } else if (line === 'saga completed all steps') {
        // The user's Scheduler class is expected to have an async completeSaga method
        const output = await scheduler.completeSaga();
        console.log(output);
      } else {
        console.log(`Unknown command: ${line}`);
      }
    } catch (error: any) {
      console.error(`Error processing command "${line}": ${error.message}`);
    }
  }
