-- sys_023: WebSocket Connection Hub
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
});

const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', async () => {
  // The user's Scheduler class is expected to be available in this scope.
  // We make a reasonable assumption about its interface based on the commands
  // and expected outputs. The methods should return `string` or `Promise<string>`.
  const scheduler: {
    connect(clientId: string): Promise<string> | string;
    broadcast(message: string): Promise<string> | string;
    sendTo(clientId: string, message: string): Promise<string> | string;
    disconnect(clientId: string): Promise<string> | string;
  } = new Scheduler() as any; // Cast to 'any' to avoid TS errors if Scheduler isn't fully defined yet.

  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    const parts = line.split(' ');
    const command = parts[0];
    const argsString = parts.slice(1).join(' ');

    const params: { [key: string]: string } = {};
    if (argsString.length > 0) {
      argsString.split(',').forEach(arg => {
        const [key, value] = arg.split('=').map(s => s.trim());
        if (key && value !== undefined) { // Ensure key exists and value is not undefined (empty string is fine)
          params[key] = value;
        }
      });
    }

    let result: string | undefined;

    try {
      switch (command) {
        case 'connect':
          if (params['client']) {
            result = await Promise.resolve(scheduler.connect(params['client']));
          } else {
            result = 'Error: Missing client for connect command.';
          }
          break;
        case 'broadcast':
          if (params['message']) {
            result = await Promise.resolve(scheduler.broadcast(params['message']));
          } else {
            result = 'Error: Missing message for broadcast command.';
          }
          break;
        case 'send_to':
          if (params['client'] && params['message']) {
            result = await Promise.resolve(scheduler.sendTo(params['client'], params['message']));
          } else {
            result = 'Error: Missing client or message for send_to command.';
          }
          break;
        case 'disconnect':
          if (params['client']) {
            result = await Promise.resolve(scheduler.disconnect(params['client']));
          } else {
            result = 'Error: Missing client for disconnect command.';
          }
          break;
        default:
          result = `Unknown command: ${command}`;
      }
    } catch (e: any) {
      // Catch any unexpected errors from user's Scheduler methods
      result = `Error processing command '${command}': ${e.message || e}`;
    }

    if (result !== undefined) {
      console.log(result);
    }
  }
});$harness$,
  test_cases   = '[{"input": "connect client=ws_client_1", "description": "Client connects", "expected_output": "ws_client_1 connected to WebSocket hub"}, {"input": "connect client=ws_client_1\nconnect client=ws_client_2\nconnect client=ws_client_3\nconnect client=ws_client_4\nconnect client=ws_client_5\nbroadcast message=Hello all, hub", "description": "Broadcast to all clients", "expected_output": "ws_client_1 connected to WebSocket hub\nws_client_2 connected to WebSocket hub\nws_client_3 connected to WebSocket hub\nws_client_4 connected to WebSocket hub\nws_client_5 connected to WebSocket hub\nMessage broadcast to all 5 connected clients"}, {"input": "connect client=ws_client_1\nconnect client=ws_client_2\nsend_to client=ws_client_1, message=Private message to 1\nsend_to client=ws_client_2, message=Private message to 2", "description": "Send to specific client", "expected_output": "ws_client_1 connected to WebSocket hub\nws_client_2 connected to WebSocket hub\nPrivate message to 1 sent to ws_client_1\nPrivate message to 2 sent to ws_client_2"}, {"input": "connect client=ws_client_1\nconnect client=ws_client_2\ndisconnect client=ws_client_1", "description": "Client disconnects", "expected_output": "ws_client_1 connected to WebSocket hub\nws_client_2 connected to WebSocket hub\nws_client_1 disconnected, hub updated"}, {"input": "connect client=ws_client_A\nconnect client=ws_client_B\nconnect client=ws_client_C\ndisconnect client=ws_client_A\nbroadcast message=Update to remaining", "description": "Broadcast to remaining clients after one disconnects", "expected_output": "ws_client_A connected to WebSocket hub\nws_client_B connected to WebSocket hub\nws_client_C connected to WebSocket hub\nws_client_A disconnected, hub updated\nMessage broadcast to all 2 connected clients"}, {"input": "connect client=ws_client_valid\nsend_to client=ws_client_invalid, message=Attempt to send\ndisconnect client=ws_client_valid\nsend_to client=ws_client_valid, message=Attempt to send after disconnect", "description": "Handle send to non-existent or disconnected client", "expected_output": "ws_client_valid connected to WebSocket hub\nClient ws_client_invalid not found or disconnected\nws_client_valid disconnected, hub updated\nClient ws_client_valid not found or disconnected"}]'::jsonb
