UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.concurrent.*;

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner scanner = new Scanner(System.in);
        Service service = new Service(); // Instantiate the user's service class

        while (scanner.hasNextLine()) {
            String line = scanner.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String[] parts = line.split(" ", 2); // Split into command and arguments
            String command = parts[0];
            String argsString = parts.length > 1 ? parts[1] : "";

            String result = "";
            try {
                switch (command) {
                    case "fetch":
                        // Expected format: fetch url=VALUE, edge=VALUE
                        String urlFetch = extractParam(argsString, "url=");
                        String edgeFetch = extractParam(argsString, "edge=");
                        result = service.handleFetch(urlFetch, edgeFetch);
                        break;
                    case "purge":
                        // Expected format: purge url=VALUE
                        String urlPurge = extractParam(argsString, "url=");
                        result = service.handlePurge(urlPurge);
                        break;
                    case "ttl_expired":
                        // Expected format: ttl_expired url=VALUE
                        String urlTtlExpired = extractParam(argsString, "url=");
                        result = service.handleTTLExpired(urlTtlExpired);
                        break;
                    default:
                        result = "UNKNOWN COMMAND: " + command;
                        break;
                }
            } catch (IllegalArgumentException e) {
                result = "ERROR: " + e.getMessage();
            } catch (Exception e) {
                result = "UNEXPECTED ERROR: " + e.getClass().getSimpleName() + " - " + e.getMessage();
            }
            System.out.println(result);
        }
        scanner.close();
    }

    // Helper method to extract parameters like "key=value" from a string
    private static String extractParam(String argsLine, String paramName) {
        // The (cached) suffix from original tests is not expected in the new test cases,
        // but this defensive replacement handles any potential remnants.
        String cleanArgsLine = argsLine.replace(" (cached)", "");

        String[] params = cleanArgsLine.split(", ");
        for (String param : params) {
            if (param.startsWith(paramName)) {
                return param.substring(paramName.length());
            }
        }
        throw new IllegalArgumentException("Missing or malformed parameter: '" + paramName.substring(0, paramName.length() - 1) + "'");
    }
}$harness$,
