-- sys_025: Inverted Index Search Engine
UPDATE challenges SET
  test_harness = $harness$import sys
import re
import time
import random

# User's Service and Worker classes are available here.

class Harness:
    def __init__(self):
        self.service = Service()

    def _parse_index_command(self, line):
        match = re.match(r'INDEX id=(\d+) content="([^"]+)"', line)
        if match:
            doc_id = int(match.group(1))
            content = match.group(2)
            return self.service.index(doc_id, content)
        return None

    def _parse_search_command(self, line):
        match = re.match(r'SEARCH query="([^"]+)"', line)
        if match:
            query = match.group(1)
            return self.service.search(query)
        return None

    def _parse_generate_and_search_command(self, line):
        # This is a special command for the performance test case.
        # The harness generates documents and then calls the user's search method.
        match = re.match(r'GENERATE_AND_SEARCH num_docs=(\d+) common_term="([^"]+)" num_matches=(\d+)', line)
        if match:
            num_docs = int(match.group(1))
            common_term = match.group(2)
            num_matches = int(match.group(3))

            # List of diverse words to create document content for randomized documents
            words = ["apple", "banana", "cherry", "date", "elderberry", "fig", "grape", "honeydew", "kiwi", "lemon", "mango", "nectarine", "orange", "papaya", "quince", "raspberry", "strawberry", "tangerine", "ugli", "vanilla", "watermelon", "xigua", "yam", "zucchini", "azure", "blush", "coral", "denim", "emerald", "fuchsia"]

            # Index documents that contain the common term
            for i in range(num_matches):
                doc_id = i + 1
                # Ensure the common term is present, add other random words
                # Exclude common_term from random words to prevent double counting issues if user code is sensitive
                content_words = [common_term] + random.sample([w for w in words if w != common_term], k=random.randint(2, 5))
                content = ' '.join(content_words)
                self.service.index(doc_id, content)
            
            # Index documents that do NOT contain the common term
            for i in range(num_matches, num_docs):
                doc_id = i + 1
                # Ensure common_term is NOT in these documents
                available_words = [w for w in words if w != common_term]
                if len(available_words) < 3: # Fallback if original word list is too small or common_term too frequent
                    available_words = words # This might lead to common_term appearing if available_words is small, but unlikely with current list

                content_words = random.sample(available_words, k=random.randint(3, 6))
                content = ' '.join(content_words)
                self.service.index(doc_id, content)

            # Perform the search and return its result.
            # The user's search method is expected to return the specific performance string
            # as per the problem description for this particular query and setup.
            return self.service.search(common_term)
        return None

    def process_command(self, line):
        line = line.strip()
        if not line:
            return

        result = self._parse_index_command(line)
        if result is not None:
            print(result)
            return

        result = self._parse_search_command(line)
        if result is not None:
            print(result)
            return

        result = self._parse_generate_and_search_command(line)
        if result is not None:
            print(result)
            return

        # If no command matched, it means an unexpected input was received.
        # For a hidden harness, we typically don't print errors for invalid commands,
        # as all test inputs are controlled.

def run_harness():
    harness = Harness()
    for line in sys.stdin:
        harness.process_command(line)

# Call the harness function at module level as per Cr4ck rules.
run_harness()$harness$,
  test_cases   = '[{"input": "INDEX id=1 content=\"quick brown fox\"", "description": "Index document", "expected_output": "Document 1 indexed: quick, brown, fox"}, {"input": "INDEX id=1 content=\"quick brown fox\"\nSEARCH query=\"brown fox\"", "description": "Search indexed documents", "expected_output": "Document 1 indexed: quick, brown, fox\nResults: [doc 1] (matched: brown, fox)"}, {"input": "INDEX id=1 content=\"quick brown fox\"\nSEARCH query=\"lazy dog\"", "description": "Search returns no results", "expected_output": "Document 1 indexed: quick, brown, fox\nNo results found for: lazy dog"}, {"input": "GENERATE_AND_SEARCH num_docs=1000 common_term=\"common_term\" num_matches=50", "description": "Large index search performance", "expected_output": "Inverted index search: 50 matches in 2ms"}, {"input": "INDEX id=10 content=\"apple banana cherry\"\nINDEX id=11 content=\"banana date cherry\"\nSEARCH query=\"banana cherry\"", "description": "Search multiple documents for multiple terms (intersection)", "expected_output": "Document 10 indexed: apple, banana, cherry\nDocument 11 indexed: banana, cherry, date\nResults: [doc 10, doc 11] (matched: banana, cherry)"}, {"input": "INDEX id=20 content=\"apple\"\nINDEX id=21 content=\"banana\"\nSEARCH query=\"apple banana\"", "description": "Search for terms across non-intersecting documents (no results)", "expected_output": "Document 20 indexed: apple\nDocument 21 indexed: banana\nNo results found for: apple banana"}]'::jsonb
WHERE id = 'sys_025';
-- sys_026: Idempotency Key Deduplicator
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', async () => {
  // Create stateful objects here before processing commands
  const scheduler = new Scheduler();

  for (const line of lines) {
    if (!line) continue;

    const parts = line.split(' ');
    const command = parts[0];
    const idempotencyKey = parts[1];
    // The operation description can be multiple words, so join the rest
    const operation = parts.slice(2).join(' ');

    let result: string | null = null;

    try {
      switch (command) {
        case 'PROCESS':
          // The user's Scheduler is expected to have a method like:
          // async processRequest(idempotencyKey: string, operation: string): Promise<string>
          // This method should internally handle task execution (e.g., simulating work with Promise.resolve/setTimeout)
          // and return the appropriate idempotency message.
          result = await scheduler.processRequest(idempotencyKey, operation);
          break;
        case 'EXPIRE':
          // The user's Scheduler is expected to have a method like:
          // async expireKey(idempotencyKey: string): Promise<string>
          // This method should remove the key from the deduplication cache.
          result = await scheduler.expireKey(idempotencyKey);
          break;
        default:
          result = `Unknown command: ${command}`;
          break;
      }
    } catch (error: any) {
      // Catch any unhandled errors from the user's implementation
      result = `Error processing command '${command}' for key '${idempotencyKey}': ${error.message}`;
    }

    if (result !== null) {
      console.log(result);
    }
