  test_harness = $harness$import sys
import json

def _parse_key_value_args(args_str: str, parse_json_data: bool = False) -> dict:
    """Helper function to parse 'key=value, key2=value2' strings."""
    args = {}
    for arg_pair in args_str.split(', '):
        if not arg_pair:
            continue
        if '=' in arg_pair:
            key, value = arg_pair.split('=', 1)
            if key == 'data' and parse_json_data:
                try:
                    args[key] = json.loads(value)
                except json.JSONDecodeError:
                    return {"_error": f"Error: Invalid JSON for 'data' field: {value}"}
            else:
                args[key] = value
    return args

def run_harness():
    service = Service() # Instantiate the user's Service class

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        parts = line.split(' ', 1)
        command = parts[0]
        args_str = parts[1] if len(parts) > 1 else ""

        result = "" # Initialize result for each command

        if command == "create_tenant":
            args = _parse_key_value_args(args_str)
            if "_error" in args:
                result = args["_error"]
            else:
                tenant_id = args.get('id')
                if tenant_id:
                    result = service.create_tenant(tenant_id)
                else:
                    result = "Error: 'id' argument missing for create_tenant"
        elif command == "write":
            args = _parse_key_value_args(args_str, parse_json_data=True)
            if "_error" in args:
                result = args["_error"]
            else:
                tenant_id = args.get('tenant')
                data = args.get('data')
                if tenant_id and data is not None:
                    result = service.write_data(tenant_id, data)
                else:
                    result = "Error: 'tenant' or 'data' argument missing for write"
        elif command == "read":
            args = _parse_key_value_args(args_str)
            if "_error" in args:
                result = args["_error"]
            else:
                tenant_id = args.get('tenant')
                query = args.get('query')
                if tenant_id and query:
                    result = service.read_data(tenant_id, query)
                else:
                    result = "Error: 'tenant' or 'query' argument missing for read"
        elif command == "cross_tenant_query":
            # Expected format: "cross_tenant_query <source_tenant_id> query <query_string> from <target_tenant_id>"
            sub_parts = args_str.split(' ')
            if len(sub_parts) >= 5 and sub_parts[1] == "query" and sub_parts[3] == "from":
                source_tenant = sub_parts[0]
                query_str = sub_parts[2]
                target_tenant = sub_parts[4]
                result = service.cross_tenant_query(source_tenant, query_str, target_tenant)
            else:
                result = "Error: Invalid cross_tenant_query format. Expected 'cross_tenant_query <source_tenant_id> query <query_string> from <target_tenant_id>'"
        else:
            result = f"Error: Unknown command '{command}'"

        print(result)

