const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', async () => {
  // The user's Scheduler class is expected to be available in the global scope.
  // It should implement methods compatible with the harness's commands.
  // Expected interface for NodeState and Scheduler:
  // interface NodeState {
  //   status: 'ALIVE' | 'FAILED';
  //   knownMembers: string[]; // All nodes this node knows about, including itself, regardless of their status.
  // }
  // 
  // class Scheduler {
  //   addNode(nodeId: string): void; // Adds a new node to the system, initially ALIVE.
  //   setKnownPeers(nodeId: string, initialPeers: string[]): void; // Sets initial 'knownMembers' for a node (excluding itself, which is implicitly added).
  //   triggerGossip(sourceId: string, targetId: string): Promise<void>; // Triggers a direct gossip exchange.
  //   triggerFullGossipRound(): Promise<void>; // Each active node gossips to one random active peer.
  //   markNodeFailed(nodeId: string): void; // Marks a node as FAILED.
  //   getNodeState(nodeId: string): NodeState | undefined;
  //   getAllNodeStates(): Map<string, NodeState>; // Returns states of all nodes in the system.
  // }

  const scheduler = new Scheduler();

  for (const line of lines) {
    if (!line) continue;

    const parts = line.split(' ');
    const command = parts[0];
    const args = parts.slice(1);

    try {
      switch (command) {
        case 'ADD_NODE': {
          const nodeId = args[0];
          scheduler.addNode(nodeId);
          console.log(`Node ${nodeId} added.`);
          break;
        }
        case 'SET_PEERS': {
          const nodeId = args[0];
          const peers = args.slice(1);
          scheduler.setKnownPeers(nodeId, peers);
          console.log(`${nodeId} initially knows members: [${peers.join(', ')}].`);
          break;
        }
        case 'RUN_GOSSIP': {
          const sourceId = args[0];
          const targetId = args[1];
          await scheduler.triggerGossip(sourceId, targetId);
          console.log(`Gossip round from ${sourceId} to ${targetId} completed.`);
          break;
        }
        case 'RUN_GOSSIP_ALL': {
          await scheduler.triggerFullGossipRound();
          console.log(`Global gossip round completed.`);
          break;
        }
        case 'RUN_GOSSIP_ROUNDS': {
            const numRounds = parseInt(args[0], 10);
            if (isNaN(numRounds) || numRounds <= 0) {
                console.log(`Invalid number of rounds: ${args[0]}.`);
                break;
            }
            console.log(`Starting ${numRounds} global gossip rounds.`);
            for (let i = 0; i < numRounds; i++) {
                await scheduler.triggerFullGossipRound();
            }
            console.log(`${numRounds} global gossip rounds completed.`);
            break;
        }
        case 'FAIL_NODE': {
          const nodeId = args[0];
          scheduler.markNodeFailed(nodeId);
          console.log(`Node ${nodeId} marked as FAILED.`);
          break;
        }
        case 'GET_NODE_STATE': {
          const nodeId = args[0];
          const state = scheduler.getNodeState(nodeId);
          if (state) {
            // Sort members for consistent output
            const sortedMembers = [...state.knownMembers].sort().join(', ');
            console.log(`${nodeId} state: ${state.status}, members=[${sortedMembers}].`);
          } else {
            console.log(`Node ${nodeId} not found.`);
          }
          break;
        }
        case 'GET_ALL_STATES': {
            const allStates = scheduler.getAllNodeStates();
            const sortedNodeIds = Array.from(allStates.keys()).sort(); // Sort node IDs for consistent output
            console.log("Current system state:");
            for (const nodeId of sortedNodeIds) {
                const state = allStates.get(nodeId)!;
                // Sort members for consistent output
                const sortedMembers = [...state.knownMembers].sort().join(', ');
                console.log(`  ${nodeId}: ${state.status}, members=[${sortedMembers}].`);
            }
            break;
        }
        default:
          console.log(`Unknown command: ${command}`);
          break;
      }
    } catch (error: any) {
      console.error(`Error executing command '${line}': ${error.message}`);
    }
  }
