import java.util.concurrent.*;

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner scanner = new Scanner(System.in);
        Service service = new Service(); 

        while (scanner.hasNextLine()) {
            String line = scanner.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String[] parts = line.split(" ", 2);
            String command = parts[0];
            String argsStr = parts.length > 1 ? parts[1] : "";

            try {
                switch (command) {
                    case "submit":
                        int recordCount = 0;
                        String processorType = "";
                        String[] submitParams = argsStr.split(", ");
                        for (String param : submitParams) {
                            if (param.startsWith("batch=")) {
                                // Example: batch=[record_1...record_1000]
                                // Extract the number after the last 'record_' within the brackets
                                int bracketStart = param.indexOf('[');
                                int bracketEnd = param.lastIndexOf(']');
                                if (bracketStart != -1 && bracketEnd != -1 && bracketStart < bracketEnd) {
                                    String innerContent = param.substring(bracketStart + 1, bracketEnd);
                                    int lastRecordUnderscore = innerContent.lastIndexOf("record_");
                                    if (lastRecordUnderscore != -1 && lastRecordUnderscore + "record_".length() < innerContent.length()) {
                                        String countStr = innerContent.substring(lastRecordUnderscore + "record_".length());
                                        recordCount = Integer.parseInt(countStr);
                                    } else {
                                        System.err.println("Warning: Could not parse record count from batch string. Defaulting to 0 for: " + param);
                                        recordCount = 0; 
                                    }
                                } else {
                                    System.err.println("Warning: Malformed batch format. Defaulting to 0 for: " + param);
                                    recordCount = 0;
                                }
                            } else if (param.startsWith("processor=")) {
                                processorType = param.substring("processor=".length());
                            }
                        }
                        System.out.println(service.submitBatch(recordCount, processorType));
                        break;

                    case "process":
                        String batchIdProcess = "";
                        int chunkSize = 0;
                        String[] processParams = argsStr.split(", ");
                        for (String param : processParams) {
                            if (param.startsWith("batch_id=")) {
                                batchIdProcess = param.substring("batch_id=".length());
                            } else if (param.startsWith("chunk_size=")) {
                                chunkSize = Integer.parseInt(param.substring("chunk_size=".length()));
                            }
                        }
                        System.out.println(service.processBatch(batchIdProcess, chunkSize));
                        break;

                    case "batch_progress":
                        String batchIdProgress = argsStr.substring("batch=".length());
                        System.out.println(service.getBatchProgress(batchIdProgress));
                        break;

                    case "batch_complete":
                        String batchIdComplete = argsStr.substring("batch=".length());
                        System.out.println(service.completeBatch(batchIdComplete));
                        break;

                    default:
                        System.out.println("Unknown command: " + command);
                }
            } catch (Exception e) {
                System.out.println("Error: " + e.getMessage());
                // For debugging: e.printStackTrace();
            }
        }
        scanner.close();
    }
}

