class HarnessServiceWrapper:
    def __init__(self):
        # Instantiate the user's Service class. The 'Service' class is provided by the user's code.
        self.service = Service()
        # The 'Worker' class is also provided by the user, but not directly used by these specific commands.
        # self.worker = Worker() 

    def _parse_params(self, param_string):
        """Parses a comma-separated string of key=value pairs into a dictionary."""
        params = {}
        if not param_string:
            return params
        for part in param_string.split(', '):
            key, value = part.split('=', 1)
            params[key.strip()] = value.strip()
        return params

    def _parse_duration(self, duration_str):
        """Parses a duration string (e.g., "10ms") into an integer in milliseconds."""
        if duration_str.endswith('ms'):
            return int(duration_str[:-2])
        # Assume it's already an integer if no 'ms' suffix
        return int(duration_str)

    def handle_command(self, command_line):
        """Processes a single command line and returns the result string."""
        parts = command_line.split(' ', 1)
        command_name = parts[0]
        param_string = parts[1] if len(parts) > 1 else ""
        params = self._parse_params(param_string)

        output = ""
        try:
            if command_name == "start_trace":
                request_id = params['request']
                service_name = params['service']
                output = self.service.start_trace(request_id, service_name)
            elif command_name == "add_span":
                trace_id = params['trace']
                service_name = params['service']
                duration_ms = self._parse_duration(params['duration'])
                output = self.service.add_span(trace_id, service_name, duration_ms)
            elif command_name == "get_trace":
                trace_id = params['id']
                output = self.service.get_trace(trace_id)
            else:
                output = f"Error: Unknown command '{command_name}'"
        except KeyError as e:
            output = f"Error: Missing parameter for command '{command_name}': {e}"
        except ValueError as e:
            output = f"Error: Invalid value for command '{command_name}': {e}"
        except Exception as e:
            # Catch any other unexpected errors from user's code for better debugging
            output = f"Error processing command '{command_name}': {e.__class__.__name__}: {e}"
        
        return output

def run_harness():
    """Main entry point for the test harness, reading commands from stdin."""
    harness_manager = HarnessServiceWrapper()
    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue
        result = harness_manager.handle_command(line)
        print(result)

