        _mockParticipantManager.setVote(pId, 'NO'); // Set the specific participant to vote NO
        if ('initiatePrepare' in scheduler && typeof scheduler.initiatePrepare === 'function') {
          // Assume this prepare is specifically for the participant specified.
          await scheduler.initiatePrepare(txnId, [pId]);
