UPDATE challenges SET
  test_harness = $harness$import sys
import json

def run_harness():
    service = Service()

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        try:
            command_parts = line.split(' ', 1)
            command_name = command_parts[0]
            
            kwargs = {}
            if len(command_parts) > 1:
                params_str = command_parts[1]

                param_pairs = []
                current_param = []
                brace_level = 0
                in_json_value = False # To track if we are inside a JSON object value for parameter splitting
                
                for char in params_str:
                    if char == '{':
                        brace_level += 1
                        if brace_level == 1: # First opening brace for a potential JSON value
                            in_json_value = True
                    elif char == '}':
                        brace_level -= 1
                        if brace_level == 0 and in_json_value: # Last closing brace, end of JSON value
                            in_json_value = False

                    # Split by comma only if not inside a JSON value (checked by in_json_value and brace_level)
                    if char == ',' and not in_json_value and brace_level == 0:
                        param_pairs.append("".join(current_param).strip())
                        current_param = []
                    else:
                        current_param.append(char)
                
                if current_param:
                    param_pairs.append("".join(current_param).strip())

                for param_pair in param_pairs:
                    if '=' in param_pair:
                        key, value_str = param_pair.split('=', 1)
                        key = key.strip()
                        value_str = value_str.strip()

                        # Attempt to parse values that look like JSON objects
                        if value_str.startswith('{') and value_str.endswith('}'):
                            try:
                                kwargs[key] = json.loads(value_str)
                            except json.JSONDecodeError:
                                # If it looks like JSON but isn't valid, treat as a string
                                kwargs[key] = value_str 
                        else:
                            kwargs[key] = value_str
                    else:
                        # If a param doesn't have an '=', treat its presence as a boolean flag
                        kwargs[param_pair.strip()] = True 

            method = getattr(service, command_name)
            result = method(**kwargs)
            print(result)

        except AttributeError:
            print(f"Error: Unknown command '{command_name}' or method not found on Service.")
        except TypeError as e:
            print(f"Error: Incorrect parameters for '{command_name}': {e}")
        except json.JSONDecodeError as e:
            print(f"Error parsing JSON message for '{command_name}': {e}")
        except Exception as e:
            print(f"An unexpected error occurred during command '{command_name}': {e}")

