UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin
});

const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  const scheduler = new Scheduler(); // Instantiate the user's Scheduler

  for (const line of lines) {
    let result: string | undefined;

    // --- GET CONFIG ---
    let match = line.match(/^get config=([^,]+), service=(.+)$/);
    if (match) {
      const configName = match[1];
      const serviceName = match[2];
      result = scheduler.getConfig(configName, serviceName);
    }

    // --- UPDATE CONFIG ---
    if (!result) {
      match = line.match(/^update config=([^,]+), (.+)$/);
      if (match) {
        const configName = match[1];
        const paramsString = match[2];
        const updates: Record<string, string | boolean | number> = {};
        paramsString.split(',').forEach(param => {
          const [key, valueStr] = param.trim().split('=');
          if (key && valueStr !== undefined) {
            let value: string | boolean | number = valueStr;
            if (valueStr === 'true') value = true;
            else if (valueStr === 'false') value = false;
            else if (!isNaN(Number(valueStr)) && !isNaN(parseFloat(valueStr))) value = Number(valueStr);
            updates[key] = value;
          }
        });
        result = scheduler.updateConfig(configName, updates);
      }
    }

    // --- HOT RELOAD SERVICE ---
    if (!result) {
      match = line.match(/^hot_reload service=(.+)$/);
      if (match) {
        const serviceName = match[1];
        result = scheduler.hotReloadService(serviceName);
      }
    }

    // --- ROLLBACK CONFIG ---
    if (!result) {
      match = line.match(/^rollback config=([^ ]+) to version=(\d+)$/);
      if (match) {
        const configName = match[1];
        const version = parseInt(match[2], 10);
        result = scheduler.rollbackConfig(configName, version);
      }
    }

    if (result !== undefined) {
      console.log(result);
    } else {
      console.log(`Error: Unknown command or malformed input: ${line}`);
    }
  }
