UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.List;
import java.util.ArrayList;

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner scanner = new Scanner(System.in);
        Service service = new Service(); // Instantiate the user's Service class

        while (scanner.hasNextLine()) {
            String line = scanner.nextLine().trim();
            if (line.isEmpty()) continue;

            try {
                if (line.startsWith("SETUP")) {
                    // Example: SETUP client=C1, bucket_size=10, rate=5/s
                    String[] parts = line.split(", ");
                    String client = parts[0].substring(parts[0].indexOf("client=") + 7);
                    int bucketSize = Integer.parseInt(parts[1].substring(parts[1].indexOf("bucket_size=") + 12));
                    double rate = Double.parseDouble(parts[2].substring(parts[2].indexOf("rate=") + 5, parts[2].indexOf("/s")));
                    service.setupClient(client, bucketSize, rate);
                } else if (line.startsWith("REQUEST")) {
                    // Example: REQUEST client=C1, tokens=1
                    String[] parts = line.split(", ");
                    String client = parts[0].substring(parts[0].indexOf("client=") + 7);
                    int tokens = Integer.parseInt(parts[1].substring(parts[1].indexOf("tokens=") + 7));
                    String result = service.allowRequest(client, tokens);
                    System.out.println(result);
                } else if (line.startsWith("TIME_PASSES")) {
                    // Example: TIME_PASSES 1000ms
                    long milliseconds = Long.parseLong(line.substring(line.indexOf("TIME_PASSES ") + 12, line.indexOf("ms")));
                    List<String> refillMessages = service.passTime(milliseconds);
                    if (refillMessages != null) {
                        for (String msg : refillMessages) {
                            System.out.println(msg);
                        }
                    }
                } else if (line.startsWith("BURST")) {
                    // Example: BURST client=C1, requests=10, tokens_per_request=1
                    String[] parts = line.split(", ");
                    String client = parts[0].substring(parts[0].indexOf("client=") + 7);
                    int requests = Integer.parseInt(parts[1].substring(parts[1].indexOf("requests=") + 9));
                    int tokensPerRequest = Integer.parseInt(parts[2].substring(parts[2].indexOf("tokens_per_request=") + 19));

                    for (int i = 0; i < requests; i++) {
                        String result = service.allowRequest(client, tokensPerRequest);
                        System.out.println(result);
                    }
                } else {
                    System.err.println("Unknown command: " + line);
                }
            } catch (Exception e) {
                System.err.println("Error processing command '" + line + "': " + e.getMessage());
                e.printStackTrace();
            }
        }
        scanner.close();
    }
