                service_match = line[service_start:].strip()
            else:
                service_match = line[service_start:service_end_idx].strip()
            kwargs["service"] = service_match

        # Parse 'dest=' argument
        if "dest=" in line:
            dest_start = line.find("dest=") + len("dest=")
            # Find the end of the destination name: either a comma or end of line
            dest_end_idx = line.find(',', dest_start)
            if dest_end_idx == -1:
                dest_match = line[dest_start:].strip()
            else:
                dest_match = line[dest_start:dest_end_idx].strip()
            kwargs["dest"] = dest_match

        # Parse 'policy=' argument. Assumed to be the last argument if present, 
        # allowing its value to contain spaces.
        if "policy=" in line:
            policy_start = line.find("policy=") + len("policy=")
            policy_match = line[policy_start:].strip()
            kwargs["policy"] = policy_match

        return kwargs

    def process_command(self, line):
        # Parse the command line into a structured dictionary
        parsed = self._parse_command(line)
        verb = parsed.get("verb")
        service_name = parsed.get("service")

        # Route the command to the appropriate method in the Worker class
        if verb == "inject":
            if service_name:
                return self.worker.inject_sidecar(service_name)
            else:
                return "Error: 'inject' command requires 'service' argument."
        elif verb == "request":
            dest_service_name = parsed.get("dest")
            if service_name and dest_service_name:
                return self.worker.request_through_sidecar(service_name, dest_service_name)
            else:
                return "Error: 'request' command requires 'service' and 'dest' arguments."
        elif verb == "configure":
            policy = parsed.get("policy")
            if service_name and policy:
                return self.worker.configure_sidecar(service_name, policy)
            else:
                return "Error: 'configure' command requires 'service' and 'policy' arguments."
        elif verb == "metrics":
            if service_name:
                return self.worker.get_sidecar_metrics(service_name)
            else:
                return "Error: 'metrics' command requires 'service' argument."
        else:
            return f"Unknown command or malformed line: {line}"

def run_harness():
    # Instantiate the test harness once to maintain state across commands
    harness = Cr4ckHarness()

    # Read commands from stdin line by line
    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue # Skip empty lines
        
        # Process each command and print its result to stdout
        result = harness.process_command(line)
        print(result)

