-- sys_040: Tenant Quota Enforcer
UPDATE challenges SET
  test_harness = $harness$import sys

def run_harness():
    # Instantiate stateful objects once.
    # The 'Worker' class is provided, but based on the commands, 
    # the harness directly interacts with 'Service'.
    # If 'Service' needs a 'Worker' instance (e.g., for background tasks),
    # it is expected that the user's implementation of 'Service' will 
    # create/manage 'Worker' instances internally, or that 'Service's 
    # constructor would be adapted by the user to accept one. 
    # For this harness, we assume 'Service' can be instantiated without arguments.
    service = Service()

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        parts = line.split(' ', 1)
        command = parts[0]
        args = {}
        if len(parts) > 1:
            args_str = parts[1]
            # Split by comma, then split each part by equals sign
            for arg_pair in args_str.split(', '):
                if '=' in arg_pair:
                    key, value = arg_pair.split('=', 1)
                    args[key.strip()] = value.strip()

        result = None
        try:
            if command == "set_quota":
                tenant = args.get("tenant")
                resource = args.get("resource")
                limit = args.get("limit")
                if tenant and resource and limit:
                    result = service.set_quota(tenant, resource, limit)
                else:
                    result = f"Error: Missing arguments for set_quota. Required: tenant, resource, limit. Got: {args}"
            elif command == "consume":
                tenant = args.get("tenant")
                resource = args.get("resource")
                amount_str = args.get("amount")
                if tenant and resource and amount_str:
                    try:
                        amount = int(amount_str)
                        result = service.consume(tenant, resource, amount)
                    except ValueError:
                        result = f"Error: Invalid amount '{amount_str}' for consume. Must be an integer."
                else:
                    result = f"Error: Missing arguments for consume. Required: tenant, resource, amount. Got: {args}"
            elif command == "quota_reset":
                tenant = args.get("tenant")
                resource = args.get("resource")
                if tenant and resource:
                    result = service.reset_quota(tenant, resource)
                else:
                    result = f"Error: Missing arguments for quota_reset. Required: tenant, resource. Got: {args}"
            else:
                result = f"Error: Unknown command '{command}'"
        except Exception as e:
            # Catch any exceptions from user code to provide a clearer error message
            result = f"Runtime Error during '{command}' command: {type(e).__name__}: {e}"

        if result is not None:
            print(result)

