-- sys_044: Priority Queue Scheduler
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));
rl.on('close', async () => {
  const scheduler = new Scheduler();

  let dummyTaskId = 0;
  const createDummyTask = (jobName: string): Task => {
    const id = dummyTaskId++;
    return {
      execute: async () => {
        // In a real system, this would perform actual work.
        // For testing, we just simulate asynchronous execution.
        await new Promise(resolve => setTimeout(resolve, 0));
      }
    };
  };

  for (const line of lines) {
    const parts = line.split(',').map(s => s.trim());
    const command = parts[0].split(' ')[0];

    if (command === 'enqueue') {
      const priorityMatch = line.match(/priority=([A-Z]+)/);
      const jobMatch = line.match(/job=(.+)/);

      if (priorityMatch && jobMatch) {
        const priority = priorityMatch[1].toUpperCase() as 'HIGH' | 'MEDIUM' | 'LOW';
        const jobName = jobMatch[1];
        const task = createDummyTask(jobName);
        // We assume the Scheduler's enqueue method takes the Task, priority, and jobName for internal tracking.
        scheduler.enqueue(task, priority, jobName);
        console.log(`${jobName} (${priority}) enqueued`);
      } else {
        console.log(`Error: Invalid enqueue command format: ${line}`);
      }
    } else if (command === 'dequeue') {
      // We assume the Scheduler's dequeue method returns a descriptive string (e.g., 'jobName (PRIORITY)')
      // or null if the queue is empty.
      const dequeuedInfo = await scheduler.dequeue();
      if (dequeuedInfo) {
        console.log(`Dequeued: ${dequeuedInfo}`);
      } else {
        console.log('No tasks to dequeue');
      }
    } else {
      console.log(`Unknown command: ${command}`);
    }
