UPDATE challenges SET
  test_harness = $harness$import java.util.concurrent.*;
import java.util.Scanner;
import java.util.Map;
import java.util.HashMap;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner scanner = new Scanner(System.in);
        Service service = new Service(); // Instantiate the user's Service class

        while (scanner.hasNextLine()) {
            String line = scanner.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String result = processCommand(service, line);
            if (result != null) {
                System.out.println(result);
            }
        }
        scanner.close();
    }

    private static String processCommand(Service service, String commandLine) {
        // Example commandLine: "begin_transaction id=TXN001 isolation=snapshot"
        // Example commandLine: "read TXN001 key=user_1"
        // Example commandLine: "write TXN001 key=user_1 value=some_data"
        // Example commandLine: "commit TXN001"

        String[] parts = commandLine.split(" ", 2); // Split into command and arguments
        String command = parts[0];
        String args = parts.length > 1 ? parts[1] : "";

        try {
            switch (command) {
                case "begin_transaction": {
                    Pattern p = Pattern.compile("id=(\\w+) isolation=(\\w+)");
                    Matcher m = p.matcher(args);
                    if (m.find()) {
                        String txnId = m.group(1);
                        String isolation = m.group(2);
                        return service.beginTransaction(txnId, isolation);
                    }
                    return "Error: Malformed begin_transaction command: " + commandLine;
                }
                case "read": {
                    Pattern p = Pattern.compile("([^ ]+) key=([^ ]+)"); // TXN001 key=user_1
                    Matcher m = p.matcher(args);
                    if (m.find()) {
                        String txnId = m.group(1);
                        String key = m.group(2);
                        return service.read(txnId, key);
                    }
                    return "Error: Malformed read command: " + commandLine;
                }
                case "write": {
                    Pattern p = Pattern.compile("([^ ]+) key=([^ ]+) value=(.*)"); // TXN001 key=user_1 value=some_data
                    Matcher m = p.matcher(args);
                    if (m.find()) {
                        String txnId = m.group(1);
                        String key = m.group(2);
                        String value = m.group(3);
                        return service.write(txnId, key, value);
                    }
                    return "Error: Malformed write command: " + commandLine;
                }
                case "commit": {
                    if (!args.isEmpty()) {
                        return service.commit(args.trim());
                    }
                    return "Error: Malformed commit command: " + commandLine;
                }
                default:
                    return "Error: Unknown command: " + command;
            }
        } catch (Exception e) {
            return "Error processing command '" + commandLine + "': " + e.getMessage();
        }
    }
}$harness$,
