        const delay = delayMatch ? parseInt(delayMatch[1]) : 0; // Default to 0ms delay

        mockWebhookService.setNextResponse(status, delay);
      } else if (command === 'deliver_webhook') {
        const urlMatch = line.match(/url=([^,]+)/);
        const eventMatch = line.match(/event=([^,]+)/);
        const maxRetriesMatch = line.match(/max_retries=(\d+)/);

        const url = urlMatch ? urlMatch[1] : 'https://default.com/hook';
        const event = eventMatch ? eventMatch[1] : 'default_event';
        const maxRetries = maxRetriesMatch ? parseInt(maxRetriesMatch[1]) : 5; // Default max retries if not specified

        await scheduler.deliverWebhook(url, event, maxRetries);
      } else if (command === 'advance_time') {
        const seconds = parseInt(parts[1]);
        if (isNaN(seconds)) {
          console.error(`Invalid time for advance_time: ${parts[1]}`);
          continue;
        }
        await scheduler.advanceTime(seconds);
      } else {
        console.error(`Unknown command: ${line}`);
