-- sys_051: Request Coalescing Proxy
UPDATE challenges SET
  test_harness = $harness$import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.Scanner;
import java.util.*;

// Interface that the Service class is expected to use for its backend dependency.
// User's Service/Worker should implement or take this interface.
interface BackendFetcher {
    CompletableFuture<String> fetch(String resourceId);
}

// Our mock implementation of BackendFetcher
class MockBackendFetcher implements BackendFetcher {
    private final Map<String, Integer> fetchCallCounts = new ConcurrentHashMap<>();
    private final Map<String, ConcurrentLinkedQueue<CompletableFuture<String>>> pendingFetches = new ConcurrentHashMap<>();

    @Override
    public CompletableFuture<String> fetch(String resourceId) {
        fetchCallCounts.merge(resourceId, 1, Integer::sum); // Track how many times fetch is *called*
        CompletableFuture<String> newFetch = new CompletableFuture<>();
        pendingFetches.computeIfAbsent(resourceId, k -> new ConcurrentLinkedQueue<>()).add(newFetch);
        return newFetch; // Return a new future each time, the service must coalesce these.
    }

    /**
     * Completes the next (oldest) pending CompletableFuture for a given resource.
     * This is called by the harness to simulate a backend response.
     * @param resourceId The ID of the resource whose fetch is to be completed.
     * @param data The data to complete the future with.
     * @return true if a future was completed, false if no pending fetch was found.
     */
    public boolean completeNextPendingFetch(String resourceId, String data) {
        ConcurrentLinkedQueue<CompletableFuture<String>> queue = pendingFetches.get(resourceId);
        if (queue != null) {
            CompletableFuture<String> fetchToComplete = queue.poll();
            if (fetchToComplete != null) {
                if (!fetchToComplete.isDone()) { // Only complete if not already done (e.g., cancelled)
                    fetchToComplete.complete(data);
                }
                return true;
            }
        }
        return false;
    }

    public int getFetchCount(String resourceId) {
        return fetchCallCounts.getOrDefault(resourceId, 0);
    }

    public void reset() {
        fetchCallCounts.clear();
        // Cancel any futures that were never completed by the harness
        pendingFetches.forEach((k, v) -> v.forEach(f -> {
            if (!f.isDone()) f.cancel(true);
        }));
        pendingFetches.clear();
    }
}

public class Main {
    private static MockBackendFetcher mockBackend;
    private static Service service; // User's Service class instance
    private static Map<String, CompletableFuture<String>> activeRequests; // User's service.getResource() calls
    private static AtomicInteger requestIdCounter;

    public static void main(String[] args) throws Exception {
        // Initialize mock backend and user service
        mockBackend = new MockBackendFetcher();
        try {
            // This assumes the user's Service class has a constructor that accepts a BackendFetcher.
            // E.g., `public Service(BackendFetcher backend) { ... }`
            service = new Service(mockBackend);
        } catch (Exception e) {
            System.err.println("CRITICAL ERROR: Failed to instantiate Service with MockBackendFetcher. " +
                               "Ensure `Service` has a constructor `Service(BackendFetcher backend)` " +
                               "and handles it correctly. " + e.getMessage());
            throw e; // Propagate exception to fail the test clearly
        }

        activeRequests = new ConcurrentHashMap<>();
        requestIdCounter = new AtomicInteger(0);

        Scanner scanner = new Scanner(System.in);
        while (scanner.hasNextLine()) {
            String line = scanner.nextLine().trim();
            if (line.isEmpty()) continue;

            String[] parts = line.split(" ", 2);
            String command = parts[0];
            String argsStr = parts.length > 1 ? parts[1] : "";

            try {
                switch (command) {
                    case "REQUEST": {
                        String resourceId = argsStr;
                        String requestId = "req_" + requestIdCounter.incrementAndGet();
                        CompletableFuture<String> future = service.getResource(resourceId);
                        activeRequests.put(requestId, future);
                        System.out.println("REQ_SUBMITTED " + requestId + " " + resourceId);
                        break;
                    }
                    case "AWAIT": {
                        String requestId = argsStr;
                        CompletableFuture<String> future = activeRequests.get(requestId);
                        if (future == null) {
                            System.out.println("ERROR: Request ID " + requestId + " not found or already completed/cancelled.");
                            break;
                        }
                        // Use a timeout to prevent tests from hanging indefinitely if future never completes
                        String result = future.get(5, TimeUnit.SECONDS);
                        System.out.println("REQ_COMPLETED " + requestId + " " + result);
                        activeRequests.remove(requestId); // Remove once completed
                        break;
                    }
                    case "BACKEND_RESPOND": {
                        String[] respondArgs = argsStr.split(" ", 2);
                        if (respondArgs.length < 2) {
                            System.out.println("ERROR: BACKEND_RESPOND command requires resourceId and data.");
                            break;
                        }
                        String resourceId = respondArgs[0];
                        String data = respondArgs[1];
                        if (mockBackend.completeNextPendingFetch(resourceId, data)) {
                            System.out.println("BACKEND_RESP_SENT " + resourceId + " " + data);
                        } else {
                            System.out.println("ERROR: No pending backend fetch for resource " + resourceId + " to complete.");
                        }
                        break;
                    }
                    case "GET_FETCH_COUNT": {
                        String resourceId = argsStr;
                        int count = mockBackend.getFetchCount(resourceId);
                        System.out.println("FETCH_COUNT " + resourceId + " " + count);
                        break;
                    }
                    case "SLEEP": {
                        long millis = Long.parseLong(argsStr);
                        Thread.sleep(millis);
                        System.out.println("SLEPT " + millis + "ms");
                        break;
                    }
                    case "RESET_HARNESS": {
                        mockBackend.reset();
                        activeRequests.clear();
                        requestIdCounter.set(0);
                        System.out.println("HARNESS_RESET");
                        break;
                    }
                    default:
                        System.out.println("UNKNOWN_COMMAND: " + line);
                        break;
                }
            } catch (TimeoutException e) {
                System.out.println("ERROR: Request " + (command.equals("AWAIT") ? argsStr : "unknown") + " timed out after 5 seconds. " + e.getMessage());
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt(); // Restore interrupt status
                System.out.println("ERROR: Harness interrupted. " + e.getMessage());
            } catch (Exception e) {
                System.out.println("ERROR_PROCESSING_COMMAND: " + e.getClass().getSimpleName() + ": " + e.getMessage());
                // e.printStackTrace(); // Can uncomment for local debugging if needed
            }
        }
        // Final cleanup for any remaining active requests or backend fetches
        activeRequests.forEach((id, future) -> {
            if (!future.isDone()) {
                future.cancel(true);
            }
        });
        mockBackend.reset();
        scanner.close();
    }
