import collections

def parse_command(line):
    parts = line.strip().split(' ', 1)
    command = parts[0]
    args = {}
    if len(parts) > 1:
        param_str = parts[1]
        for item in param_str.split(', '):
            if '=' in item:
                key, value = item.split('=', 1)
                args[key.strip()] = value.strip()
    return command, args

def run_harness():
    # Instantiate the user's Service class
    service = Service()

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        command, args = parse_command(line)

        output = ""
        try:
            if command == "acquire_semaphore":
                name = args.get("name")
                client = args.get("client")
                # 'max' is an optional parameter, typically used on the first acquire for a semaphore
                max_count = int(args["max"]) if "max" in args else None
                if not name or not client:
                    output = "Error: Missing name or client for acquire_semaphore."
                else:
                    # Call the acquire method on the user's Service instance
                    output = service.acquire(name, client, max_count=max_count)
            elif command == "release_semaphore":
                name = args.get("name")
                client = args.get("client")
                if not name or not client:
                    output = "Error: Missing name or client for release_semaphore."
                else:
                    # Call the release method on the user's Service instance
                    output = service.release(name, client)
            else:
                output = f"Unknown command: {command}"
        except Exception as e:
            output = f"Error processing command '{line}': {e}"
        
        print(output)

