const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout,
  terminal: false
});

const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', async () => {
  // The user's Scheduler class will be available in this scope.
  // It is expected to implement methods like deploy, switchTraffic, rollback, healthCheck.
  const scheduler = new Scheduler();
  const outputs: string[] = [];

  for (const line of lines) {
    if (!line) {
      continue;
    }

    // Split the line into command and arguments
    // Example: "deploy current_deployment=blue new_deployment=green"
    const parts = line.split(' ').map(p => p.trim()).filter(Boolean);
    if (parts.length === 0) {
      continue;
    }

    const command = parts[0];
    const args: Record<string, string> = {};

    // Parse key=value arguments and potential standalone phase argument for health_check
    for (let i = 1; i < parts.length; i++) {
      const argPart = parts[i];
      const eqIndex = argPart.indexOf('=');
      if (eqIndex > -1) {
        const key = argPart.substring(0, eqIndex);
        const value = argPart.substring(eqIndex + 1);
        args[key] = value;
      } else {
        // Handle specific standalone arguments, like 'phase' for 'health_check'
        if (command === 'health_check' && !args['phase']) {
            args['phase'] = argPart;
        }
        // Other standalone arguments for different commands would need specific handling here.
        // For this challenge, 'health_check' is the only one identified.
      }
    }

    let result: string;
    try {
      switch (command) {
        case 'deploy':
          if (args['current_deployment'] && args['new_deployment']) {
            result = await scheduler.deploy(args['current_deployment'], args['new_deployment']);
          } else {
            result = `Error: Missing arguments for deploy command. Expected 'current_deployment' and 'new_deployment'.`;
          }
          break;
        case 'switch_traffic':
          if (args['from'] && args['to']) {
            result = await scheduler.switchTraffic(args['from'], args['to']);
          } else {
            result = `Error: Missing arguments for switch_traffic command. Expected 'from' and 'to'.`;
          }
          break;
        case 'rollback':
          if (args['from'] && args['to']) {
            result = await scheduler.rollback(args['from'], args['to']);
          } else {
            result = `Error: Missing arguments for rollback command. Expected 'from' and 'to'.`;
          }
          break;
        case 'health_check':
          if (args['deployment']) {
            // 'phase' argument is optional for health_check
            result = await scheduler.healthCheck(args['deployment'], args['phase'] || '');
          } else {
            result = `Error: Missing 'deployment' argument for health_check command.`;
          }
          break;
        default:
          result = `Error: Unknown command "${command}"`;
      }
    } catch (e: any) {
      // Catch errors thrown by the user's Scheduler methods
      result = `Error executing command '${command}': ${e.message}`;
    }
    outputs.push(result);
  }

  // Print all collected outputs, each on a new line
  console.log(outputs.join('\n'));
