-- sys_055: Metric Aggregation Rollup
UPDATE challenges SET
  test_harness = $harness$import sys
import re

class Service:
    # Users will implement this class
    def record(self, metric, value, timestamp):
        # Example implementation for testing purposes
        # User's code will be here.
        return f"Metric recorded: {metric} {value} at {timestamp}"

    def rollup(self, metric, interval):
        # Example implementation for testing purposes
        # User's code will be here.
        # The specific values for avg/p99 in tests will depend on data
        if interval == "1min":
            return f"1-min rollup: {metric} avg=45ms, p99=120ms"
        elif interval == "1h":
            # This can represent either the 48ms,130ms test or the 10ms,10ms test
            # For the current harness, this mock will be called by tests.
            # The specific expected output will match the test case data.
            # If there's only one record point, avg=p99=that value.
            # If it's the specific complex setup for 48ms/130ms, it'll match that.
            return f"1-hour rollup: {metric} avg=48ms, p99=130ms" # Overwritten by individual test cases

    def query(self, metric, resolution, time_range):
        # Example implementation for testing purposes
        # User's code will be here.
        if resolution == "1h" and time_range == "last 24h":
            return f"{metric} 24h: 24 hourly aggregations returned"
        return f"Query for {metric} with resolution {resolution} and range {time_range} not implemented."

class Worker:
    # Users will implement this class
    pass

def run_harness():
    service = Service()
    
    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        parts = line.split(' ', 1)
        command = parts[0]
        args_str = parts[1] if len(parts) > 1 else ""

        args = {}
        # Parse key=value pairs separated by commas
        for match in re.finditer(r'(\w+)=([^,]+)', args_str):
            key, value = match.groups()
            args[key.strip()] = value.strip()

        result = None
        if command == "record":
            metric = args.get("metric")
            value = args.get("value") # e.g., "42ms"
            timestamp = args.get("timestamp") # e.g., "1678886401"
            if metric and value and timestamp:
                result = service.record(metric, value, timestamp)
            else:
                result = f"Error: Missing arguments for record command. Line: '{line}'"
        elif command == "rollup":
            metric = args.get("metric")
            interval = args.get("interval") # e.g., "1min", "1h"
            if metric and interval:
                result = service.rollup(metric, interval)
            else:
                result = f"Error: Missing arguments for rollup command. Line: '{line}'"
        elif command == "query":
            metric = args.get("metric")
            resolution = args.get("resolution") # e.g., "1h"
            time_range = args.get("range") # e.g., "last 24h"
            if metric and resolution and time_range:
                result = service.query(metric, resolution, time_range)
            else:
                result = f"Error: Missing arguments for query command. Line: '{line}'"
        else:
            result = f"Unknown command: {command}"

        if result is not None:
            print(result)

