-- sys_056: Adaptive Load Balancer
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', async () => {
  const scheduler = new Scheduler();
  let taskIdCounter = 1;

  // Dummy Task implementation for the harness. The user's Scheduler is expected
  // to interact with Task objects (e.g., receive them via its 'route' method).
  // The actual `execute()` call is not directly simulated by the harness,
  // as its primary role is to observe routing decisions and manage backend state.
  class DummyTask implements Task {
    public readonly id: string;
    constructor(id: string) {
      this.id = id;
    }
    async execute(): Promise<void> {
      // This method would typically contain the actual work. For the harness,
      // it's a placeholder to satisfy the Task interface. The Scheduler is
      // expected to manage connection counts and report completion via `requestCompleted`.
      await new Promise(resolve => setTimeout(resolve, 1)); // Simulate async work
    }
  }

  for (const line of lines) {
    const parts = line.split(' ');
    const command = parts[0];
    const args = parts.slice(1);

    switch (command) {
      case 'ADD_BACKEND': {
        const backendId = args[0];
        if (!backendId) {
          console.error(`Error: ADD_BACKEND requires a backend ID.`);
          break;
        }
        scheduler.addBackend(backendId);
        console.log(`Backend ${backendId} added.`);
        break;
      }
      case 'REMOVE_BACKEND': {
        const backendId = args[0];
        if (!backendId) {
          console.error(`Error: REMOVE_BACKEND requires a backend ID.`);
          break;
        }
        scheduler.removeBackend(backendId);
        console.log(`Backend ${backendId} removed.`);
        break;
      }
      case 'SET_BACKEND_HEALTH': {
        const backendId = args[0];
        const healthStatus = args[1]; // 'HEALTHY' or 'UNHEALTHY'
        if (!backendId || !healthStatus) {
          console.error(`Error: SET_BACKEND_HEALTH requires a backend ID and status.`);
          break;
        }
        const healthy = healthStatus.toUpperCase() === 'HEALTHY';
        scheduler.markBackendHealthy(backendId, healthy);
        console.log(`Backend ${backendId} health set to ${healthStatus}.`);
        break;
      }
      case 'SET_BACKEND_LATENCY': {
        const backendId = args[0];
        const latencyMs = parseInt(args[1], 10);
        if (!backendId || isNaN(latencyMs)) {
          console.error(`Error: SET_BACKEND_LATENCY requires a backend ID and a valid number for latency.`);
          break;
        }
        scheduler.reportLatency(backendId, latencyMs);
        console.log(`Backend ${backendId} latency reported as ${latencyMs}ms.`);
        break;
      }
      case 'SET_BACKEND_CONNECTIONS': {
        const backendId = args[0];
        const connections = parseInt(args[1], 10);
        if (!backendId || isNaN(connections)) {
          console.error(`Error: SET_BACKEND_CONNECTIONS requires a backend ID and a valid number for connections.`);
          break;
        }
        // This is a test-specific method for initial state setup for certain test cases.
        // The user's Scheduler implementation should expose this method for testing purposes.
        scheduler.setBackendConnections(backendId, connections);
        console.log(`Backend ${backendId} connections set to ${connections}.`);
        break;
      }
      case 'PROCESS_REQUEST': {
        const task = new DummyTask(`task_${taskIdCounter++}`);
        try {
          // Assuming the user's Scheduler.route method is async and returns the chosen backend ID.
          const chosenBackendId = await scheduler.route(task);
          if (chosenBackendId) {
            console.log(`Next request routed to ${chosenBackendId}.`);
          } else {
            console.log('No suitable backend available.');
          }
        } catch (error: any) {
          console.log(`Error routing request: ${error.message || error}`);
        }
        break;
      }
      case 'COMPLETE_REQUEST': {
        const backendId = args[0];
        if (!backendId) {
          console.error(`Error: COMPLETE_REQUEST requires a backend ID.`);
          break;
        }
        scheduler.requestCompleted(backendId);
        console.log(`Request completed on ${backendId}.`);
        break;
      }
      default: {
        console.log(`Unknown command: ${line}`);
      }
    }
  }
});$harness$,
