-- sys_057: Binary Protocol Serializer
UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.concurrent.*;
import java.nio.charset.StandardCharsets;

public class Main {

    // Helper to convert hex string to byte array
    private static byte[] hexStringToByteArray(String s) {
        int len = s.length();
        if (len % 2 != 0) {
            throw new IllegalArgumentException("Hex string must have an even length. Provided: " + s);
        }
        byte[] data = new byte[len / 2];
        for (int i = 0; i < len; i += 2) {
            data[i / 2] = (byte) ((Character.digit(s.charAt(i), 16) << 4)
                                 + Character.digit(s.charAt(i+1), 16));
        }
        return data;
    }

    public static void main(String[] args) throws Exception {
        Scanner scanner = new Scanner(System.in);
        Service service = new Service(); // Create the stateful service object
        
        byte[] lastSerializedBytes = null; // State to hold the last serialized binary data

        while (scanner.hasNextLine()) {
            String line = scanner.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            try {
                if (line.startsWith("SERIALIZE ")) {
                    String jsonMessage = line.substring("SERIALIZE ".length());
                    lastSerializedBytes = service.serialize(jsonMessage); // User's serialize returns byte[]
                    String metrics = service.getSerializationMetrics(jsonMessage); // User's method for metrics
                    System.out.println(metrics);
                } else if (line.startsWith("DESERIALIZE LAST")) {
                    if (lastSerializedBytes == null) {
                        System.out.println("Error: No data to deserialize. Please SERIALIZE first.");
                    } else {
                        String deserializedMessage = service.deserialize(lastSerializedBytes); // User's deserialize
                        System.out.println(deserializedMessage);
                    }
                } else if (line.startsWith("DESERIALIZE HEX ")) {
                    String hexString = line.substring("DESERIALIZE HEX ".length());
                    byte[] bytesToDeserialize = hexStringToByteArray(hexString);
                    String deserializedMessage = service.deserialize(bytesToDeserialize); // User's deserialize
                    System.out.println(deserializedMessage);
                } else if (line.startsWith("TEST_BC ")) { 
                    String commandArgs = line.substring("TEST_BC ".length());
                    // Expected format: <message-content> <serializer-version-int> <deserializer-version-int>
                    // Example: {type: LegacyOrder, id: 100} 1 2
                    // This parser assumes the last two space-separated tokens are the versions.
                    
                    String[] tokens = commandArgs.split(" ");
                    if (tokens.length < 3) {
                         System.out.println("Error: Invalid TEST_BC command format. Expected: TEST_BC <message_content> <serializer_version> <deserializer_version>");
                         continue;
                    }
                    
                    int deserializerVer = Integer.parseInt(tokens[tokens.length - 1]);
                    int serializerVer = Integer.parseInt(tokens[tokens.length - 2]);
                    
                    StringBuilder msgBuilder = new StringBuilder();
                    for (int i = 0; i < tokens.length - 2; i++) {
                        msgBuilder.append(tokens[i]);
                        if (i < tokens.length - 3) {
                            msgBuilder.append(" ");
                        }
                    }
                    String msgContent = msgBuilder.toString();

                    String result = service.testBackwardCompatibilityScenario(msgContent, serializerVer, deserializerVer);
                    System.out.println(result);

                } else {
                    System.out.println("Error: Unknown command: " + line);
                }
            } catch (NumberFormatException e) {
                System.out.println("Error: Invalid number format in command: " + e.getMessage());
            } catch (IllegalArgumentException e) {
                // This is caught for deserialize corrupt bytes and hex conversion errors
                System.out.println("Error: " + e.getMessage());
            } catch (Exception e) {
                // Catch any other unexpected exceptions from user's Service methods
                System.out.println("An unexpected error occurred: " + e.getClass().getSimpleName() + ": " + e.getMessage());
            }
        }
        scanner.close();
    }
}

