-- sys_058: Outbox Pattern Relay
UPDATE challenges SET
  test_harness = $harness$import sys
import json
from collections import defaultdict, deque

# --- Mock Dependencies ---
class MockDbClient:
    def __init__(self):
        # Stores events: {id: {type: str, status: 'pending'|'relayed', data: dict|None}}
        self.outbox = {}
        self.transaction_active = False
        self.transaction_buffer = {} # For atomic writes within a transaction

    def begin_transaction(self):
        if self.transaction_active:
            raise RuntimeError("MockDb: Nested transactions not supported.")
        self.transaction_active = True
        self.transaction_buffer = {}

    def commit_transaction(self):
        if not self.transaction_active:
            raise RuntimeError("MockDb: No active transaction to commit.")
        self.outbox.update(self.transaction_buffer)
        self.transaction_active = False
        self.transaction_buffer = {}

    def rollback_transaction(self):
        if not self.transaction_active:
            raise RuntimeError("MockDb: No active transaction to roll back.")
        self.transaction_active = False
        self.transaction_buffer = {}

    def write_outbox_event(self, event_id, event_type, event_data=None):
        event_entry = {"type": event_type, "id": event_id, "status": "pending", "data": event_data}
        if self.transaction_active:
            self.transaction_buffer[event_id] = event_entry
        else:
            # If no transaction is active, we store it directly for simplicity in tests.
            # In a real system, this might typically be an error or auto-committed within a database context.
            self.outbox[event_id] = event_entry
        return True # Indicate success

    def get_pending_outbox_events(self):
        return [
            event for event_id, event in self.outbox.items()
            if event["status"] == "pending"
        ]

    def mark_outbox_event_relayed(self, event_id):
        if event_id in self.outbox:
            self.outbox[event_id]["status"] = "relayed"
            return True
        return False

    def get_event_status(self, event_id):
        return self.outbox.get(event_id, {}).get("status", "not_found")

    def get_outbox_size(self):
        return len(self.get_pending_outbox_events())

class MockMessageBusClient:
    def __init__(self):
        self.sent_events = defaultdict(list) # {event_type: [{id: ..., data: ...}]}}

    def send_event(self, event_type, event_id, event_data=None):
        self.sent_events[event_type].append({"id": event_id, "data": event_data, "type": event_type})
        return True # Indicate success

    def get_sent_events(self, event_type=None):
        if event_type:
            return self.sent_events.get(event_type, [])
        
        all_sent = []
        for events_list in self.sent_events.values():
            all_sent.extend(events_list)
        return all_sent

# --- Harness Logic ---
def run_harness():
    db_client = MockDbClient()
    message_bus_client = MockMessageBusClient()

    try:
        # User's Service and Worker classes are expected to be available in the global scope
        service = Service(db_client) # Assuming Service's __init__ takes a db_client
        worker = Worker(db_client, message_bus_client) # Assuming Worker's __init__ takes db_client and message_bus_client
    except (TypeError, NameError) as e:
        print(f"ERROR: Could not instantiate user classes (Service, Worker). Check their __init__ signatures and existence. {e}")
        sys.exit(1) # Exit on critical setup failure

    for line in sys.stdin:
        command_line = line.strip()
        if not command_line:
            continue

        parts = command_line.split(" ", 1)
        command = parts[0]
        args_str = parts[1] if len(parts) > 1 else ""

        try:
            if command == "SERVICE_WRITE":
                # Command format: SERVICE_WRITE event_type=OrderPlaced event_id=1 [event_data={"k":"v"}]
                args = {}
                for arg in args_str.split(" "):
                    if "=" in arg:
                        k, v = arg.split("=", 1)
                        args[k] = v
                
                event_type = args.get("event_type")
                event_id_str = args.get("event_id")
                event_data_json = args.get("event_data")

                event_id = int(event_id_str) if event_id_str and event_id_str.isdigit() else event_id_str
                event_data = json.loads(event_data_json) if event_data_json else None

                if not event_type or event_id is None:
                    print(f"ERROR: Invalid SERVICE_WRITE command format. Missing event_type or event_id: {command_line}")
                    continue

                # Assuming user's Service class has a method `write_event_to_outbox`
                result = service.write_event_to_outbox(event_type, event_id, event_data)
                print(result)

            elif command == "WORKER_RELAY":
                # Command format: WORKER_RELAY
                # Assuming user's Worker class has a method `relay_outbox_events`
                result = worker.relay_outbox_events()
                print(result)

            elif command == "SERVICE_GET_OUTBOX_SIZE":
                # Command format: SERVICE_GET_OUTBOX_SIZE
                # Assuming user's Service class has a method `get_pending_outbox_event_count`
                size = service.get_pending_outbox_event_count()
                print(f"Service: Outbox has {size} pending events.")

            # --- Internal Harness Debugging/Verification Commands (not direct user methods) ---
            elif command == "MOCKDB_GET_EVENT_STATUS":
                # Command format: MOCKDB_GET_EVENT_STATUS event_id=1
                args = {}
                for arg in args_str.split(" "):
                    if "=" in arg:
                        k, v = arg.split("=", 1)
                        args[k] = v
                event_id_str = args.get("event_id")
                event_id = int(event_id_str) if event_id_str and event_id_str.isdigit() else event_id_str
                if event_id is None:
                    print(f"ERROR: Invalid MOCKDB_GET_EVENT_STATUS command format. Missing event_id: {command_line}")
                    continue
                status = db_client.get_event_status(event_id)
                print(f"MockDB: Event {event_id} status is '{status}'.")

            elif command == "MOCKBUS_GET_SENT_EVENTS":
                # Command format: MOCKBUS_GET_SENT_EVENTS [event_type=OrderPlaced]
                args = {}
                for arg in args_str.split(" "):
                    if "=" in arg:
                        k, v = arg.split("=", 1)
                        args[k] = v
                event_type = args.get("event_type")
                sent_events = message_bus_client.get_sent_events(event_type=event_type)
                
                if sent_events:
                    events_summary = []
                    for event in sent_events:
                        # Use event['type'] if available, otherwise fallback to the queried event_type
                        events_summary.append(f"Type: {event.get('type', event_type)}, ID: {event['id']}")
                    print(f"MockMessageBus: Sent {len(sent_events)} events.\n  - " + "\n  - ".join(events_summary))
                else:
                    print(f"MockMessageBus: No events of type '{event_type}' sent." if event_type else "MockMessageBus: No events sent.")

            else:
                print(f"ERROR: Unknown command: {command}")
        except Exception as e:
            print(f"ERROR processing command '{command_line}': {e}")
            # For debugging purposes on the platform, print full traceback to stdout
            import traceback
            traceback.print_exc(file=sys.stdout)

# Call the harness function at module level as required
run_harness()$harness$,
  test_cases   = '[{"input": "SERVICE_WRITE event_type=OrderPlaced event_id=1", "description": "Write to outbox atomically", "expected_output": "Event OrderPlaced (ID: 1) written to outbox atomically."}, {"input": "SERVICE_WRITE event_type=OrderPlaced event_id=2\nWORKER_RELAY", "description": "Relay outbox to message bus", "expected_output": "Event OrderPlaced (ID: 2) written to outbox atomically.\nWorker: Relayed: OrderPlaced (ID: 2) to message bus."}, {"input": "SERVICE_WRITE event_type=OrderPlaced event_id=3\nWORKER_RELAY\nWORKER_RELAY", "description": "Idempotent relay", "expected_output": "Event OrderPlaced (ID: 3) written to outbox atomically.\nWorker: Relayed: OrderPlaced (ID: 3) to message bus.\nWorker: No pending events to relay."}, {"input": "SERVICE_WRITE event_type=OrderPlaced event_id=4\nWORKER_RELAY\nSERVICE_GET_OUTBOX_SIZE", "description": "Check outbox empty after relay", "expected_output": "Event OrderPlaced (ID: 4) written to outbox atomically.\nWorker: Relayed: OrderPlaced (ID: 4) to message bus.\nService: Outbox has 0 pending events."}, {"input": "SERVICE_WRITE event_type=PaymentProcessed event_id=101 event_data={\"amount\":100, \"currency\":\"USD\"}\nSERVICE_GET_OUTBOX_SIZE\nWORKER_RELAY\nMOCKBUS_GET_SENT_EVENTS event_type=PaymentProcessed\nSERVICE_GET_OUTBOX_SIZE", "description": "Write event with data, verify outbox size, relay, verify sent event, then verify outbox empty", "expected_output": "Event PaymentProcessed (ID: 101) written to outbox atomically.\nService: Outbox has 1 pending events.\nWorker: Relayed: PaymentProcessed (ID: 101) to message bus.\nMockMessageBus: Sent 1 events.\n  - Type: PaymentProcessed, ID: 101\nService: Outbox has 0 pending events."}]'::jsonb
