-- sys_059: Sliding Window Rate Monitor
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', () => {
  // Assumed user-defined class for the Sliding Window Rate Monitor functionality.
  // The harness expects a class named 'RateMonitor' to be globally available
  // (i.e., defined by the user in the provided starter code section, or as a new class).
  // It should have the following methods and properties:
  //
  // class RateMonitor {
  //   constructor(windowSizeMs: number, limit: number);
  //   addRequests(count: number, timestampMs: number): void; // Adds `count` requests to history. Does not check limit for these.
  //   tryRequest(timestampMs: number): boolean; // Attempts to add 1 request. Returns true if allowed and records it, false otherwise.
  //   getCurrentCount(timestampMs: number): number; // Returns the current count of requests within the window at timestampMs.
  //   getLimit(): number; // Returns the configured limit.
  //   getWindowSize(): number; // Returns the configured window size in milliseconds.
  // }
  let monitor: RateMonitor | null = null; // Using 'RateMonitor' as the assumed class name

  for (const line of lines) {
    const parts = line.split(' ');
    const command = parts[0];

    try {
      switch (command) {
        case 'INIT': {
          const windowSizeMs = parseInt(parts[1], 10);
          const limit = parseInt(parts[2], 10);
          monitor = new RateMonitor(windowSizeMs, limit);
          console.log(`RateMonitor initialized: window=${windowSizeMs}ms, limit=${limit}`);
          break;
        }
        case 'ADD_REQUESTS': { // ADD_REQUESTS <count> <timestampMs>
          if (!monitor) {
            console.log("Error: Monitor not initialized.");
            continue;
          }
          const count = parseInt(parts[1], 10);
          const timestampMs = parseInt(parts[2], 10);
          monitor.addRequests(count, timestampMs);
          console.log(`Added ${count} requests at ${timestampMs}`);
          break;
        }
        case 'TRY_REQUEST': { // TRY_REQUEST <timestampMs>
          if (!monitor) {
            console.log("Error: Monitor not initialized.");
            continue;
          }
          const timestampMs = parseInt(parts[1], 10);
          const countBefore = monitor.getCurrentCount(timestampMs); // Get count before this potential request
          const allowed = monitor.tryRequest(timestampMs); // Attempt to add and record
          const limit = monitor.getLimit();
          const windowSizeSec = monitor.getWindowSize() / 1000;

          if (allowed) {
            // If allowed, the request was recorded, so getCurrentCount should now reflect it.
            const countAfter = monitor.getCurrentCount(timestampMs);
            console.log(`${countAfter}/${limit} requests in window, allowed`);
          } else {
            // If not allowed, the request was NOT recorded. The count for the message should be 'countBefore + 1'.
            console.log(`Rate limited: ${countBefore + 1} exceeds ${limit} in ${windowSizeSec}s window`);
          }
          break;
        }
        case 'GET_COUNT': { // GET_COUNT <timestampMs>
          if (!monitor) {
            console.log("Error: Monitor not initialized.");
            continue;
          }
          const timestampMs = parseInt(parts[1], 10);
          const currentCount = monitor.getCurrentCount(timestampMs);
          const windowSizeSec = monitor.getWindowSize() / 1000;
          console.log(`Current requests: ${currentCount} in ${windowSizeSec}s window`);
          break;
        }
        default:
          console.log(`Unknown command: ${command}`);
      }
    } catch (error: any) {
      console.error(`Error processing command '${line}': ${error.message || error}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "INIT 60000 120\nADD_REQUESTS 99 59000\nTRY_REQUEST 60000", "description": "Within sliding window limit", "expected_output": "RateMonitor initialized: window=60000ms, limit=120\nAdded 99 requests at 59000\n100/120 requests in window, allowed"}, {"input": "INIT 60000 120\nADD_REQUESTS 120 59000\nTRY_REQUEST 60000", "description": "Exceeds sliding window limit", "expected_output": "RateMonitor initialized: window=60000ms, limit=120\nAdded 120 requests at 59000\nRate limited: 121 exceeds 120 in 60s window"}, {"input": "INIT 60000 120\nADD_REQUESTS 20 0\nADD_REQUESTS 80 10000\nGET_COUNT 60000\nGET_COUNT 70000", "description": "Window slides and old requests expire", "expected_output": "RateMonitor initialized: window=60000ms, limit=120\nAdded 20 requests at 0\nAdded 80 requests at 10000\nCurrent requests: 100 in 60s window\nCurrent requests: 80 in 60s window"}, {"input": "INIT 60000 120\nADD_REQUESTS 49 59000\nTRY_REQUEST 59001", "description": "Burst within window allowed", "expected_output": "RateMonitor initialized: window=60000ms, limit=120\nAdded 49 requests at 59000\n50/120 requests in window, allowed"}]'::jsonb
WHERE id = 'sys_059';
-- sys_060: Peer-to-Peer DHT Node
UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.*; // User's starter code includes this

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        // Map to hold instances of the user's Service class, acting as individual DHT nodes
        Map<String, Service> nodes = new HashMap<>(); 

        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String result = "";
            try {
                if (line.startsWith("create_node")) {
                    String nodeId = line.substring("create_node ".length()).trim();
                    if (!nodes.containsKey(nodeId)) {
                        // Instantiate user's Service class as a new DHT node
                        nodes.put(nodeId, new Service(nodeId)); 
                        result = nodeId + " created.";
                    } else {
                        result = nodeId + " already exists.";
                    }
                } else if (line.startsWith("join_network")) {
                    // Example: join_network node=N1, bootstrap=N2
                    String argsPart = line.substring("join_network ".length());
                    String[] parts = argsPart.split(", ");
                    String nodeId = parts[0].split("=")[1].trim();
                    String bootstrapId = parts[1].split("=")[1].trim();

                    Service node = nodes.get(nodeId);
                    if (node == null) {
                        // If node isn't created explicitly, create it implicitly
                        node = new Service(nodeId);
                        nodes.put(nodeId, node);
                        // We'll print a message for implicit creation for clarity in tests
                        System.out.println(nodeId + " created implicitly."); 
                    }
                    
                    // The user's Service.join method will perform the actual join logic.
                    // It's expected to return a status string.
                    result = node.join(bootstrapId);

                } else if (line.matches("N\\d+: put key=.*, value=.*") || line.startsWith("put")) { // Added startsWith for robust matching if node prefix isn't always present
                    // Example: N1: put key=file_hash, value=node_location
                    String nodeId;
                    String putCommand;
                    if (line.matches("N\\d+: .*")) {
                        String[] commandParts = line.split(":", 2);
                        nodeId = commandParts[0].trim();
                        putCommand = commandParts[1].trim(); 
                    } else {
                        // If no node prefix, assume N1 for this simple harness
                        nodeId = "N1"; 
                        putCommand = line;
                        if(!nodes.containsKey(nodeId)) { // Create N1 implicitly if not present
                            nodes.put(nodeId, new Service(nodeId));
                            System.out.println(nodeId + " created implicitly for put.");
                        }
                    }

                    String argsStr = putCommand.substring("put ".length());
                    String[] args = argsStr.split(", ");
                    String key = args[0].split("=")[1].trim();
                    String value = args[1].split("=")[1].trim();

                    Service node = nodes.get(nodeId);
                    if (node != null) {
                        result = node.put(key, value);
                    } else {
                        result = "Error: Node " + nodeId + " not found or not active.";
                    }
                } else if (line.matches("N\\d+: get key=.*") || line.startsWith("get")) {
                    // Example: N1: get key=file_hash
                    String nodeId;
                    String getCommand;
                    if (line.matches("N\\d+: .*")) {
                        String[] commandParts = line.split(":", 2);
                        nodeId = commandParts[0].trim();
                        getCommand = commandParts[1].trim();
                    } else {
                        // If no node prefix, assume N1 for this simple harness
                        nodeId = "N1";
                        getCommand = line;
                        if(!nodes.containsKey(nodeId)) { // Create N1 implicitly if not present
                            nodes.put(nodeId, new Service(nodeId));
                            System.out.println(nodeId + " created implicitly for get.");
                        }
                    }

                    String key = getCommand.substring("get key=".length()).trim();

                    Service node = nodes.get(nodeId);
                    if (node != null) {
                        result = node.get(key);
                    } else {
                        result = "Error: Node " + nodeId + " not found or not active.";
                    }
                } else if (line.matches("N\\d+ leaves")) {
                    // Example: N5 leaves
                    String nodeId = line.split(" ")[0].trim();

                    Service node = nodes.get(nodeId);
                    if (node != null) {
                        result = node.leave(); // User's leave method returns status
                        nodes.remove(nodeId); // Remove from our harness's active nodes map
                    } else {
                        result = "Error: Node " + nodeId + " not found or already left.";
                    }
                } else {
                    result = "Unknown command: " + line;
                }
            } catch (Exception e) {
                result = "ERROR processing command '" + line + "': " + e.getMessage();
                // For detailed debugging, print stack trace:
                // e.printStackTrace(System.err);
            }
            System.out.println(result);
        }
        sc.close();
    }
}$harness$,
  test_cases   = '[{"input": "create_node N1\ncreate_node N2\njoin_network node=N1, bootstrap=N2", "expected_output": "N1 created.\nN2 created.\nN1 joined DHT network via N2", "description": "Join DHT network"}, {"input": "create_node N1\ncreate_node N2\ncreate_node N5\ncreate_node N6\njoin_network node=N1, bootstrap=N2\njoin_network node=N5, bootstrap=N1\nN1: put key=file_hash, value=node_location_initial", "expected_output": "N1 created.\nN2 created.\nN5 created.\nN6 created.\nN1 joined DHT network via N2\nN5 joined DHT network via N1\nKey stored in DHT at responsible node", "description": "Store key in DHT"}, {"input": "create_node N1\ncreate_node N2\ncreate_node N5\ncreate_node N6\njoin_network node=N1, bootstrap=N2\njoin_network node=N5, bootstrap=N1\nN1: put key=file_hash, value=node_location_initial\nN1: get key=file_hash", "expected_output": "N1 created.\nN2 created.\nN5 created.\nN6 created.\nN1 joined DHT network via N2\nN5 joined DHT network via N1\nKey stored in DHT at responsible node\nDHT lookup: file_hash found at node N5", "description": "Lookup key in DHT"}, {"input": "create_node N1\ncreate_node N2\ncreate_node N5\ncreate_node N6\njoin_network node=N1, bootstrap=N2\njoin_network node=N5, bootstrap=N1\njoin_network node=N6, bootstrap=N1\nN1: put key=file_hash, value=node_location_initial\nN1: get key=file_hash\nN5 leaves\nN1: get key=file_hash", "expected_output": "N1 created.\nN2 created.\nN5 created.\nN6 created.\nN1 joined DHT network via N2\nN5 joined DHT network via N1\nN6 joined DHT network via N1\nKey stored in DHT at responsible node\nDHT lookup: file_hash found at node N5\nN5 left the network.\nDHT lookup: file_hash found at node N6", "description": "Key migrates on node leave"}]'::jsonb
