-- sys_061: Multi-Region Failover Controller
UPDATE challenges SET
  test_harness = $harness$import sys

# User's Service and Worker classes will be appended here.
# class Service:
#     # TODO: implement
#     pass
#
# class Worker:
#     # TODO: implement
#     pass

class HarnessServiceWrapper:
    def __init__(self):
        # Instantiate the user's Service class.
        # The Worker class might be an internal component or background task
        # managed by the Service, so we primarily interact with Service.
        self.service = Service()
        # If Worker required explicit instantiation and a reference to Service:
        # self.worker = Worker(self.service)

    def process_command(self, command: str) -> str:
        # Split command into parts: those with '=' (key=value) and those without (keywords)
        parts_dict = {}
        keywords_list = []
        for part in command.split(','):
            part = part.strip()
            if '=' in part:
                key, value = part.split('=', 1)
                parts_dict[key.strip()] = value.strip()
            else:
                keywords_list.append(part)
        
        output = ""

        # --- Command Handling Logic ---
        # 1. Initiate failover: primary=us-east, health=failing
        if "primary" in parts_dict and "health" in parts_dict and parts_dict["health"] == "failing":
            # Assumes Service has a method to handle health updates and potentially initiate failover
            output = self.service.handle_health_update(parts_dict["primary"], parts_dict["health"])

        # 2. Failover completes: failover complete, primary=eu-west
        elif "failover complete" in keywords_list and "primary" in parts_dict:
            # Assumes Service has a method to mark failover as complete
            output = self.service.handle_failover_completion(parts_dict["primary"])
        
        # 3. Failback to original region: us-east recovers, failback
        elif "failback" in keywords_list:
            region_recovered = None
            for kw in keywords_list:
                if "recovers" in kw:
                    region_recovered = kw.split(' ')[0] # e.g., "us-east" from "us-east recovers"
                    break
            if region_recovered:
                # Assumes Service has a method to handle region recovery and initiate failback
                output = self.service.handle_region_recovery(region_recovered)

        # 4. RTO/RPO failover test: rto=30s, rpo=5min, failover_test
        elif "rto" in parts_dict and "rpo" in parts_dict and "failover_test" in keywords_list:
            # Assumes Service has a method to run a specific failover test scenario
            output = self.service.run_failover_test(parts_dict["rto"], parts_dict["rpo"])
        
        # If no specific handler matches, do not print anything to avoid unexpected output
