UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout // Added for consistency, though only input is strictly processed
});

const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', async () => {
  // Assume the user has implemented the Scheduler class with the necessary methods
  // (e.g., configureBackend, write, read, switchBackend) as asynchronous operations
  const scheduler = new Scheduler();

  // Helper function to parse 'key=value' arguments, stripping trailing commas
  function parseArg(argString: string): [string, string] | null {
    if (!argString) return null;
    const cleanedArg = argString.replace(/,$/, ''); // Remove trailing comma if present
    const kv = cleanedArg.split('=');
    if (kv.length === 2 && kv[0] && kv[1]) {
      return [kv[0], kv[1]];
    }
    return null;
  }

  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    const parts = line.split(' ');
    const command = parts[0];
    let output: string | undefined;

    try {
      switch (command) {
        case 'configure': {
          const backendArg = parseArg(parts[1]); // Expected format: backend=postgres
          if (backendArg && backendArg[0] === 'backend') {
            output = await scheduler.configureBackend(backendArg[1]);
          } else {
            output = `Error: Malformed configure command: ${line}`;
          }
          break;
        }
        case 'write': {
          const keyArg = parseArg(parts[1]);   // Expected format: key=user_1,
          const valueArg = parseArg(parts[2]); // Expected format: value=Alice
          if (keyArg && keyArg[0] === 'key' && valueArg && valueArg[0] === 'value') {
            output = await scheduler.write(keyArg[1], valueArg[1]);
          } else {
            output = `Error: Malformed write command: ${line}`;
          }
          break;
        }
        case 'switch_backend': {
          const fromArg = parseArg(parts[1]); // Expected format: from=postgres,
          const toArg = parseArg(parts[2]);   // Expected format: to=redis
          if (fromArg && fromArg[0] === 'from' && toArg && toArg[0] === 'to') {
            output = await scheduler.switchBackend(fromArg[1], toArg[1]);
          } else {
            output = `Error: Malformed switch_backend command: ${line}`;
          }
          break;
        }
        case 'read': {
          const keyArg = parseArg(parts[1]); // Expected format: key=user_1
          // The optional 'after switch' part is descriptive and ignored by the harness
          if (keyArg && keyArg[0] === 'key') {
            // The user's read method is expected to return the full output string
            // (e.g., "Read from postgres backend: Alice" or "Read from postgres backend: null")
            output = await scheduler.read(keyArg[1]);
          } else {
            output = `Error: Malformed read command: ${line}`;
          }
          break;
        }
        default: {
          output = `Unknown command: ${command}`;
          break;
        }
      }
    } catch (e: any) {
      // Catch errors thrown by user's scheduler methods
      output = `Runtime Error: ${e.message || e}`;
    }

    if (output !== undefined) {
      console.log(output);
    }
  }
});$harness$,
  test_cases   = '[{"input": "configure backend=postgres", "description": "Configure Postgres backend", "expected_output": "Storage backend configured: postgres"}, {"input": "configure backend=postgres\nwrite key=user_1, value=Alice", "description": "Write data to Postgres", "expected_output": "Storage backend configured: postgres\nWritten to postgres backend"}, {"input": "configure backend=postgres\nwrite key=user_1, value=Alice\nswitch_backend from=postgres, to=redis", "description": "Switch to Redis backend with data migration", "expected_output": "Storage backend configured: postgres\nWritten to postgres backend\nStorage backend switched to redis, data migrated"}, {"input": "configure backend=postgres\nwrite key=user_1, value=Alice\nswitch_backend from=postgres, to=redis\nread key=user_1 after switch", "description": "Read data from new Redis backend after migration", "expected_output": "Storage backend configured: postgres\nWritten to postgres backend\nStorage backend switched to redis, data migrated\nRead from redis backend: Alice"}, {"input": "configure backend=postgres\nread key=non_existent", "description": "Read non-existent key from Postgres", "expected_output": "Storage backend configured: postgres\nRead from postgres backend: null"}, {"input": "configure backend=redis\nwrite key=user_2, value=Bob\nread key=user_2", "description": "Configure and write directly to Redis", "expected_output": "Storage backend configured: redis\nWritten to redis backend\nRead from redis backend: Bob"}, {"input": "configure backend=postgres\nswitch_backend from=postgres, to=postgres", "description": "Attempt to switch backend to currently active backend", "expected_output": "Storage backend configured: postgres\nStorage backend switched to postgres, no migration needed"}, {"input": "configure backend=postgres\nwrite key=user_1, value=Alice\nwrite key=user_1, value=Charlie\nread key=user_1", "description": "Overwrite a key and read its new value", "expected_output": "Storage backend configured: postgres\nWritten to postgres backend\nWritten to postgres backend\nRead from postgres backend: Charlie"}]'::jsonb
