-- sys_063: Distributed Job Scheduler
UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.concurrent.*;

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner scanner = new Scanner(System.in);
        // The Service object maintains the state across multiple commands
        Service service = new Service(); // Assumes a default constructor exists

        while (scanner.hasNextLine()) {
            String line = scanner.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String result = handleCommand(service, line);
            if (result != null) {
                System.out.println(result);
            }
        }
        scanner.close();
    }

    private static String handleCommand(Service service, String command) {
        if (command.startsWith("schedule job=")) {
            // Example: schedule job=daily_report, cron=0 2 * * *, worker=W1
            String[] parts = command.substring("schedule job=".length()).split(", ");
            String jobName = parts[0];
            String cron = parts[1].substring("cron=".length());
            String workerId = parts[2].substring("worker=".length());
            return service.scheduleJob(jobName, cron, workerId);
        }
        else if (command.contains(" trigger at ")) {
            // Example: job=daily_report trigger at 02:00
            String[] parts = command.split(" trigger at ");
            String jobName = parts[0].substring("job=".length());
            String triggerTime = parts[1];
            return service.triggerJob(jobName, triggerTime);
        }
        else if (command.startsWith("worker=") && command.contains(" fails, job=")) {
            // Example: worker=W1 fails, job=daily_report
            String[] parts = command.split(" fails, job=");
            String workerId = parts[0].substring("worker=".length());
            String jobName = parts[1];
            return service.workerFails(workerId, jobName);
        }
        else if (command.startsWith("get_job_status job=")) {
            // Example: get_job_status job=daily_report
            String jobName = command.substring("get_job_status job=".length());
            return service.getJobStatus(jobName);
        }
        // If an unknown command is received, return an error message.
        return "Unknown command: " + command;
    }
}$harness$,
