-- sys_064: gRPC Streaming Gateway
UPDATE challenges SET
  test_harness = $harness$import sys

def run_harness():
    # Instantiate the user's Service class once for stateful operations.
    # The Worker class is available for the user to use within their Service implementation if needed.
    gateway_service = Service()

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        parts = line.split(' ', 1)
        command = parts[0]
        args_str = parts[1] if len(parts) > 1 else ""

        kwargs = {}
        if args_str:
            # Split arguments by ', ' and then by '='
            for arg_pair in args_str.split(', '):
                if '=' in arg_pair:
                    key, value = arg_pair.split('=', 1)
                    kwargs[key.strip()] = value.strip()
                # else: malformed argument, which we assume won't happen in tests

        result = None
        if command == "open_stream":
            client_id = kwargs.get("client")
            target_service = kwargs.get("service")
            if client_id and target_service:
                result = gateway_service.open_stream(client_id=client_id, target_service=target_service)
            else:
                result = "Error: Missing client or service for open_stream"
        elif command == "stream_message":
            client_id = kwargs.get("from") # 'from' is a keyword, but safe as a string key
            data = kwargs.get("data")
            if client_id and data:
                result = gateway_service.stream_message(client_id=client_id, data=data)
            else:
                result = "Error: Missing client or data for stream_message"
        elif command == "backpressure":
            client_id = kwargs.get("on stream") # Note: key 'on stream' with a space
            if client_id:
                result = gateway_service.apply_backpressure(client_id=client_id)
            else:
                result = "Error: Missing stream ID for backpressure"
        elif command == "close_stream":
            client_id = kwargs.get("client")
            if client_id:
                result = gateway_service.close_stream(client_id=client_id)
            else:
                result = "Error: Missing client for close_stream"
        else:
            result = f"Error: Unknown command '{command}'"

        if result is not None:
            print(result)

