      } else {
        output = `ERROR: Invalid add_shard command format: ${line}`;
      }
    } else {
      output = `ERROR: Unknown command: ${line}`;
    }

    // Print the result of each command to stdout
    if (output !== undefined) {
      console.log(output);
    }
  }
