                        break;

                    case "GET_SAGA_STATUS":
                        // GET_SAGA_STATUS <sagaId>
                        if (argsStr.isEmpty()) {
                            System.out.println("ERROR: Invalid GET_SAGA_STATUS format. Expected: GET_SAGA_STATUS <sagaId>");
                            continue;
                        }
                        sagaId = argsStr;
                        String sagaStatus = service.getSagaStatus(sagaId); // Assumed method in user's Service
                        System.out.println("Saga " + sagaId + " status: " + sagaStatus);
                        break;

                    default:
                        System.out.println("ERROR: Unknown command: " + command);
                }
            } catch (NumberFormatException e) {
                System.out.println("ERROR: Invalid number format in command: " + line);
            } catch (Exception e) {
                // Print stack trace for debugging purposes, or just the message
                System.out.println("ERROR during command '" + command + "': " + e.getMessage());
