from typing import Optional

class _HarnessServiceProxy:
    """
    A simple proxy to catch potential errors if Service or its method doesn't exist.
    This also provides a consistent interface for the harness to call.
    """
    def __init__(self):
        self._user_service = None
        try:
            # Attempt to instantiate the user's Service class
            # Will raise NameError if Service is not defined.
            self._user_service = Service()
        except NameError:
            raise RuntimeError("User code error: 'Service' class is not defined. Please implement the 'Service' class.")
        except Exception as e:
            raise RuntimeError(f"User code error: Failed to initialize 'Service' class: {e}")

    def process_request(self, accept_header: str, prefer_header: Optional[str] = None) -> str:
        """
        Calls the user's Service.process_request method.
        Handles checking for method existence and general exceptions.
        """
        if not hasattr(self._user_service, 'process_request'):
            raise NotImplementedError("User code error: 'Service' class does not have a 'process_request' method. Please implement it.")
        
