-- sys_068: Async Task Result Poller
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout,
  terminal: false
});

const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', async () => {
  const scheduler = new Scheduler();

  // Helper to introduce a small delay, allowing the Node.js event loop to process microtasks/timers.
  // This is crucial for user's Scheduler's internal async operations (e.g., setTimeout(0), Promise.resolve()).
  const yieldEventLoop = (ms: number = 5) => new Promise(resolve => setTimeout(resolve, ms));

  for (const line of lines) {
    if (!line) continue;

    const parts = line.split(' ');
    const command = parts[0];
    const args: Record<string, string> = {};

    for (let i = 1; i < parts.length; i++) {
      const [key, value] = parts[i].split('=');
      args[key.replace(/,$/, '')] = value.replace(/,$/, ''); // Clean up trailing commas
    }

    switch (command) {
      case 'submit_task': {
        const jobName = args['job'];
        // The `async=true` is descriptive for the challenge, but not a direct parameter to submitTask.
        // Scheduler is expected to handle tasks asynchronously by nature.
        const taskId = scheduler.submitTask(jobName);
        console.log(`Task submitted, task_id=${taskId} returned immediately`);
        await yieldEventLoop(); // Allow scheduler to start its internal async processes
        break;
      }
      case 'poll': {
        const taskId = args['task_id'];
        const statusResponse = scheduler.getTaskStatus(taskId);
        
        let output = `${taskId} status: ${statusResponse.status}`;

        if (statusResponse.status === 'in_progress' && typeof statusResponse.progress === 'number') {
            output += ` (${statusResponse.progress}% complete)`;
        } else if (statusResponse.status === 'complete') {
            // Check if result is truly available, as per original test case expected output
            const result = scheduler.getTaskResult(taskId);
            if (result !== undefined) {
                output += `, result available`;
            }
        }
        console.log(output);
        await yieldEventLoop(); // Allow event loop to process any pending microtasks/timers
        break;
      }
      case 'get_result': {
        const taskId = args['task_id'];
        const result = scheduler.getTaskResult(taskId);
        if (result === undefined) {
            console.log(`${taskId} result: Not available or task not complete`);
        } else {
            console.log(`${taskId} result: ${result}`);
        }
        await yieldEventLoop(); // Allow event loop to process any pending microtasks/timers
        break;
      }
      case 'advance_time': { // Test-specific command to simulate time passing
        const ms = parseInt(args['ms'], 10);
        if (!isNaN(ms) && ms > 0) {
            await new Promise(resolve => setTimeout(resolve, ms));
        }
        break;
      }
      default: {
        console.log(`Unknown command: ${command}`);
        break;
      }
    }
  }
});$harness$,
  test_cases   = '[{"input": "submit_task job=report_generation, async=true\npoll task_id=TASK001\nadvance_time ms=100\npoll task_id=TASK001\nget_result task_id=TASK001", "description": "Submit async task, poll its in-progress status, advance time, then poll its complete status and retrieve the final result.", "expected_output": "Task submitted, task_id=TASK001 returned immediately\nTASK001 status: in_progress (0% complete)\nTASK001 status: complete, result available\nTASK001 result: report_generation output"}, {"input": "submit_task job=data_export, async=true\npoll task_id=TASK002\nget_result task_id=TASK002\npoll task_id=NONEXISTENT_TASK\nadvance_time ms=150\npoll task_id=TASK002\nget_result task_id=TASK002", "description": "Submit a second async task, attempt to poll/get result while in-progress, poll a non-existent task, then advance time for completion and retrieve result.", "expected_output": "Task submitted, task_id=TASK002 returned immediately\nTASK002 status: in_progress (0% complete)\nTASK002 result: Not available or task not complete\nNONEXISTENT_TASK status: not_found\nTASK002 status: complete, result available\nTASK002 result: data_export output"}, {"input": "submit_task job=image_processing, async=true\nadvance_time ms=50\npoll task_id=TASK003\nadvance_time ms=50\npoll task_id=TASK003", "description": "Submit a task, poll after partial completion, then poll after full completion without getting result.", "expected_output": "Task submitted, task_id=TASK003 returned immediately\nTASK003 status: in_progress (50% complete)\nTASK003 status: complete, result available"}]'::jsonb
