UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.HashMap;
import java.util.List;
import java.util.ArrayList;
import java.util.Collections;
import java.util.Map;

public class Main {

    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        Service service = new Service(); // Instantiate the user's Service class

        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String[] parts = line.split(" ", 2);
            String commandType = parts[0];
            Map<String, String> params = new HashMap<>();

            if (parts.length > 1) {
                String[] paramStrings = parts[1].split(", ");
                for (String paramString : paramStrings) {
                    String[] kv = paramString.split("=", 2);
                    if (kv.length == 2) {
                        params.put(kv[0], kv[1]);
                    }
                }
            }

            String key = params.get("key");
            String prefix = params.get("prefix"); // Used for scan command
            String value = params.get("value");
            String columnFamily = params.get("column_family");

            String output = null;

            switch (commandType) {
                case "put":
                    // User's Service.put method is expected to return a String (e.g., "OK").
                    // The harness formats the final output string based on command parameters.
                    service.put(key, value, columnFamily);
                    output = key + " = " + value + " stored in " + columnFamily + " CF";
                    break;
                case "get":
                    // User's Service.get method is expected to return the value String or null if not found.
                    String retrievedValue = service.get(key, columnFamily);
                    if (retrievedValue == null) {
                        output = key + ": Not Found";
                    } else {
                        output = key + ": " + retrievedValue;
                    }
                    break;
                case "scan":
                    // User's Service.scan method is expected to return List<String> of keys matching the prefix.
                    List<String> scannedKeys = service.scan(prefix, columnFamily);
                    if (scannedKeys == null) {
                        scannedKeys = new ArrayList<>(); // Treat null as an empty list for consistent output
                    }
                    Collections.sort(scannedKeys); // Ensure consistent order for testing
                    
                    StringBuilder sb = new StringBuilder();
                    sb.append(prefix).append(" keys: [");
                    boolean first = true;
                    for (String k : scannedKeys) {
                        if (!first) {
                            sb.append(", ");
                        }
                        sb.append(k);
                        first = false;
                    }
                    sb.append("]");
                    output = sb.toString();
                    break;
                case "delete":
                    // User's Service.delete method is expected to return a String (e.g., "OK").
                    // The harness formats the final output string based on command parameters.
                    service.delete(key, columnFamily);
                    output = key + " deleted from " + columnFamily + " CF";
                    break;
                default:
                    output = "UNKNOWN COMMAND: " + commandType;
                    break;
            }

            if (output != null) {
                System.out.println(output);
            }
        }
        sc.close();
    }
