        elif command == "SET_SERVICE_FAILURE":
            service_name = parts[1]
            fail_count = int(parts[2])
            if service_name not in service_instances:
                print(f"Error: Service '{service_name}' not found.")
            else:
                # Call a method on the user's Service instance to configure its behavior.
                # It is assumed to have a set_failure_count(self, count) method,
                # where 'count' is the number of times the service's 'call' method
                # should return False before returning True.
                service_instances[service_name].set_failure_count(fail_count)

        elif command == "CALL":
            service_name = parts[1]
            # Instruct the Worker to perform the call to the specified service.
            # The Worker is expected to have a perform_operation(self, service_name) method
            # and to print its retry logs directly to stdout in the specified format.
            worker.perform_operation(service_name)

        else:
            print(f"Error: Unknown command '{command}'.")

