-- sys_072: Cache Stampede Preventer
UPDATE challenges SET
  test_harness = $harness$import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.atomic.AtomicLong;
import java.util.Map;
import java.util.HashMap;
import java.util.Scanner;
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

// Interface for the data source that user's Service will interact with
interface DataSource {
    String fetchFromDatabase(String key) throws InterruptedException;
    int getFetchCount();
    void resetFetchCount();
}

// Mock implementation of DataSource for the harness
class MockDataSource implements DataSource {
    private final Map<String, String> db = new ConcurrentHashMap<>();
    private final Map<String, Long> delays = new ConcurrentHashMap<>();
    private final AtomicInteger fetchCount = new AtomicInteger(0);

    public void addData(String key, String value, long delayMs) {
        db.put(key, value);
        delays.put(key, delayMs);
    }

    @Override
    public String fetchFromDatabase(String key) throws InterruptedException {
        fetchCount.incrementAndGet();
        long delay = delays.getOrDefault(key, 0L);
        if (delay > 0) {
            Thread.sleep(delay);
        }
        return db.get(key);
    }

    @Override
    public int getFetchCount() { return fetchCount.get(); }
    @Override
    public void resetFetchCount() { fetchCount.set(0); }
}

// Mock implementation of a clock for time-based tests (TTL, early expiry)
class MockClock {
    private AtomicLong currentTime;

    public MockClock() {
        this.currentTime = new AtomicLong(System.currentTimeMillis());
    }

    public long getTime() { return currentTime.get(); }
    public void advanceTime(long millis) { currentTime.addAndGet(millis); }
}

// Collector for various statistics reported by the user's Service
class StatsCollector {
    final AtomicInteger lockAcquiredCount = new AtomicInteger(0);
    final AtomicInteger waitingOnLockCount = new AtomicInteger(0);
    final AtomicInteger cacheHitCount = new AtomicInteger(0);
    final AtomicInteger cacheMissCount = new AtomicInteger(0);
    final AtomicInteger staleServedCount = new AtomicInteger(0);
    final AtomicInteger earlyRefreshTriggeredCount = new AtomicInteger(0);

    public void incrementLockAcquired() { lockAcquiredCount.incrementAndGet(); }
    public void incrementWaitingOnLock() { waitingOnLockCount.incrementAndGet(); }
    public void incrementCacheHit() { cacheHitCount.incrementAndGet(); }
    public void incrementCacheMiss() { cacheMissCount.incrementAndGet(); }
    public void incrementStaleServed() { staleServedCount.incrementAndGet(); }
    public void incrementEarlyRefreshTriggered() { earlyRefreshTriggeredCount.incrementAndGet(); }

    public void reset() {
        lockAcquiredCount.set(0);
        waitingOnLockCount.set(0);
        cacheHitCount.set(0);
        cacheMissCount.set(0);
        staleServedCount.set(0);
        earlyRefreshTriggeredCount.set(0);
    }

    // Combines stats from collector and mock data source for a comprehensive summary
    public String getSummary(int dataSourceDbFetchCount) {
        return String.format(
            "DB Fetches: %d, Cache Hits: %d, Lock Acquired: %d, Waiting on Lock: %d, Stale Served: %d, Early Refreshes: %d",
            dataSourceDbFetchCount, 
            cacheHitCount.get(),
            lockAcquiredCount.get(),
            waitingOnLockCount.get(),
            staleServedCount.get(),
            earlyRefreshTriggeredCount.get()
        );
    }
}

// The sole entry point for the test harness
public class Main {
    private static Service service; // User's Service implementation
    private static MockDataSource mockDataSource;
    private static MockClock mockClock;
    private static StatsCollector statsCollector;
    private static ExecutorService requestExecutor; // For simulating concurrent requests

    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        mockDataSource = new MockDataSource();
        mockClock = new MockClock();
        statsCollector = new StatsCollector();
        requestExecutor = Executors.newFixedThreadPool(100); // Pool for up to 100 concurrent requests

        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) continue;

            String[] parts = line.split(" ", 2);
            String command = parts[0];
            String argsStr = parts.length > 1 ? parts[1] : "";

            try {
                switch (command) {
                    case "INIT": {
                        String[] initArgs = argsStr.split(" ");
                        long defaultTtlMs = Long.parseLong(initArgs[0]);
                        double beta = Double.parseDouble(initArgs[1]);
                        // User's Service constructor must match this signature:
                        // public Service(DataSource dataSource, MockClock clock, StatsCollector stats, long defaultTtlMs, double beta)
                        service = new Service(mockDataSource, mockClock, statsCollector, defaultTtlMs, beta);
                        System.out.println("Service initialized with TTL=" + defaultTtlMs + ", beta=" + beta);
                        break;
                    }
                    case "SET_DB": {
                        String[] dbArgs = argsStr.split(" ", 3);
                        String key = dbArgs[0];
                        String value = dbArgs[1];
                        long delayMs = Long.parseLong(dbArgs[2]);
                        mockDataSource.addData(key, value, delayMs);
                        System.out.println("DB set: " + key + " -> " + value + " with delay " + delayMs + "ms");
                        break;
                    }
                    case "PUT_CACHE": {
                        if (service == null) throw new IllegalStateException("Service not initialized.");
                        String[] cacheArgs = argsStr.split(" ", 3);
                        String key = cacheArgs[0];
                        String value = cacheArgs[1];
                        long ttlMs = Long.parseLong(cacheArgs[2]);
                        // Assumes user's Service has a method:
                        // public void putToCache(String key, String value, long ttlMs)
                        service.putToCache(key, value, ttlMs);
                        System.out.println("Cache put: " + key + " -> " + value + " with TTL " + ttlMs + "ms");
                        break;
                    }
                    case "FETCH": {
                        if (service == null) throw new IllegalStateException("Service not initialized.");
                        String key = argsStr;
                        String result = service.getData(key); // Assumes user's Service has: public String getData(String key) throws Exception
                        System.out.println("FETCH " + key + " -> " + (result != null ? result : "null"));
                        break;
                    }
                    case "SIMULATE_CONCURRENT_FETCHES": {
                        if (service == null) throw new IllegalStateException("Service not initialized.");
                        String[] fetchArgs = argsStr.split(" ");
                        String key = fetchArgs[0];
                        int numRequests = Integer.parseInt(fetchArgs[1]);
                        long delayBetweenRequestsMs = Long.parseLong(fetchArgs[2]);

                        CountDownLatch latch = new CountDownLatch(numRequests);
                        for (int i = 0; i < numRequests; i++) {
                            final int requestId = i;
                            requestExecutor.submit(() -> {
                                try {
                                    if (delayBetweenRequestsMs > 0 && requestId > 0) {
                                        Thread.sleep(delayBetweenRequestsMs);
                                    }
                                    service.getData(key);
                                } catch (Exception e) {
                                    // Suppress individual request errors to avoid polluting output
                                    // System.err.println("Concurrent fetch request " + requestId + " failed: " + e.getMessage());
                                } finally {
                                    latch.countDown();
                                }
                            });
                        }
                        latch.await(30, TimeUnit.SECONDS); // Wait for all requests to complete with a timeout
                        System.out.println("SIMULATED " + numRequests + " concurrent fetches for " + key);
                        break;
                    }
                    case "ADVANCE_TIME": {
                        long millis = Long.parseLong(argsStr);
                        mockClock.advanceTime(millis);
                        System.out.println("Time advanced by " + millis + "ms.");
                        break;
                    }
                    case "GET_STATS": {
                        System.out.println(statsCollector.getSummary(mockDataSource.getFetchCount()));
                        break;
                    }
                    case "RESET_STATS": {
                        statsCollector.reset();
                        mockDataSource.resetFetchCount();
                        System.out.println("Stats reset.");
                        break;
                    }
                    case "SHUTDOWN": {
                        if (service == null) throw new IllegalStateException("Service not initialized.");
                        // Assumes user's Service has a method:
                        // public void shutdown() to clean up background threads/resources
                        service.shutdown();
                        System.out.println("Service shut down.");
                        break;
                    }
                    default:
                        System.err.println("Unknown command: " + command);
                }
            } catch (Exception e) {
                System.err.println("Error processing command '" + command + "': " + e.getMessage());
                e.printStackTrace(System.err);
            }
        }

        // Ensure all executors are shut down cleanly
        requestExecutor.shutdown();
        if (!requestExecutor.awaitTermination(5, TimeUnit.SECONDS)) {
             requestExecutor.shutdownNow();
        }
        if (service != null) {
            service.shutdown(); // Ensure user service is also shut down
        }
        sc.close();
    }
