-- sys_073: Microservice Health Registry
UPDATE challenges SET
  test_harness = $harness$import sys

def run_harness():
    # Instantiate stateful objects once
    # Service and Worker classes are defined in the user's code, appended before this harness.
    registry = Service()

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        parts = line.split(' ', 1)
        command = parts[0]
        args_str = parts[1] if len(parts) > 1 else ""

        args = {}
        if args_str:
            for arg_pair in args_str.split(', '):
                if '=' in arg_pair:
                    key, value = arg_pair.split('=', 1)
                    args[key.strip()] = value.strip()

        output = ""
        if command == "register":
            service_name = args.get("service")
            endpoint = args.get("endpoint")
            if service_name and endpoint:
                output = registry.register_service(service_name, endpoint)
            else:
                output = "Error: Missing service or endpoint for register command."
        elif command == "health_check":
            service_name = args.get("service")
            response_code = int(args.get("response")) if args.get("response") else None
            if service_name and response_code is not None:
                output = registry.record_health_check(service_name, response_code)
            else:
                output = "Error: Missing service or response for health_check command."
        elif command == "get_system_health":
            output = registry.get_system_health()
        else:
            output = f"Unknown command: {command}"

        if output:
            print(output)

# Call the harness function at module level
run_harness()$harness$,
  test_cases   = '[{"input": "register service=auth-service, endpoint=/health\nhealth_check service=auth-service, response=200", "description": "Register a service and confirm it''s healthy", "expected_output": "auth-service registered in health registry\nauth-service: healthy"}, {"input": "register service=db-service, endpoint=/healthz\nhealth_check service=db-service, response=500", "description": "Register a service and confirm it''s unhealthy with alert", "expected_output": "db-service registered in health registry\ndb-service: unhealthy, alert sent"}, {"input": "register service=auth-service, endpoint=/health\nregister service=db-service, endpoint=/healthz\nregister service=cache-service, endpoint=/status\nhealth_check service=auth-service, response=200\nhealth_check service=db-service, response=500\nhealth_check service=cache-service, response=200\nget_system_health", "description": "Get system health with one service unhealthy", "expected_output": "auth-service registered in health registry\ndb-service registered in health registry\ncache-service registered in health registry\nauth-service: healthy\ndb-service: unhealthy, alert sent\ncache-service: healthy\nSystem health: 2/3 services healthy, db-service down"}, {"input": "register service=db-service, endpoint=/healthz\nhealth_check service=db-service, response=500\nhealth_check service=db-service, response=200\nget_system_health", "description": "An unhealthy service recovers and system health updates", "expected_output": "db-service registered in health registry\ndb-service: unhealthy, alert sent\ndb-service: healthy\nSystem health: 1/1 services healthy"}, {"input": "register service=svc1, endpoint=/h1\nregister service=svc2, endpoint=/h2\nregister service=svc3, endpoint=/h3\nhealth_check service=svc1, response=500\nhealth_check service=svc2, response=500\nhealth_check service=svc3, response=200\nget_system_health", "description": "Get system health with multiple services unhealthy", "expected_output": "svc1 registered in health registry\nsvc2 registered in health registry\nsvc3 registered in health registry\nsvc1: unhealthy, alert sent\nsvc2: unhealthy, alert sent\nsvc3: healthy\nSystem health: 1/3 services healthy, svc1, svc2 down"}]'::jsonb
