-- sys_074: Partition Tolerance Tester
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', async () => {
  const scheduler = new Scheduler();

  for (const line of lines) {
    if (!line) continue;

    const parts = line.split(' ');
    const command = parts[0].toUpperCase();
    let result: string | null = null;

    try {
      switch (command) {
        case 'ADD_NODES': {
          const nodeIds = parts.slice(1).filter(id => id.length > 0); // Filter empty strings if any
          if (nodeIds.length > 0) {
            result = scheduler.addNodes(nodeIds);
          } else {
            result = "Error: ADD_NODES requires node IDs.";
          }
          break;
        }
        case 'PARTITION_NETWORK': {
          const group1Part = parts[1]; // e.g., "group1=n1,n2"
          const group2Part = parts[2]; // e.g., "group2=n3,n4,n5"

          if (group1Part && group2Part && group1Part.startsWith('group1=') && group2Part.startsWith('group2=')) {
            const group1Nodes = group1Part.substring('group1='.length).split(',').filter(id => id.length > 0);
            const group2Nodes = group2Part.substring('group2='.length).split(',').filter(id => id.length > 0);
            if (group1Nodes.length > 0 && group2Nodes.length > 0) {
                result = scheduler.partitionNetwork(group1Nodes, group2Nodes);
            } else {
                result = "Error: PARTITION_NETWORK requires non-empty groups.";
            }
          } else {
            result = "Error: PARTITION_NETWORK requires two groups, e.g., group1=n1,n2 group2=n3,n4,n5";
          }
          break;
        }
        case 'HEAL_PARTITION': {
          result = scheduler.healPartition();
          break;
        }
        case 'SET_PREFERENCE': {
          const preference = parts[1]?.toUpperCase();
          if (preference === 'CP' || preference === 'AP') {
            result = scheduler.setPreference(preference);
          } else {
            result = "Error: SET_PREFERENCE requires 'CP' or 'AP'.";
          }
          break;
        }
        case 'SIMULATE_WRITES': {
          result = scheduler.simulateWrites();
          break;
        }
        default: {
          result = `Unknown command: ${command}`;
          break;
        }
      }
    } catch (e: any) {
      result = `Runtime Error: ${e.message}`;
    }

    if (result !== null) {
      console.log(result);
    }
  }
});$harness$,
  test_cases   = '[{"input": "ADD_NODES n1 n2 n3 n4 n5\nPARTITION_NETWORK group1=n1,n2 group2=n3,n4,n5", "description": "Detect network partition", "expected_output": "Added nodes: n1, n2, n3, n4, n5. Total nodes: 5\nPartition detected: 2/5 nodes isolated"}, {"input": "ADD_NODES n1 n2 n3 n4 n5\nPARTITION_NETWORK group1=n1,n2 group2=n3,n4,n5\nSET_PREFERENCE CP\nSIMULATE_WRITES", "description": "CP system rejects minority writes", "expected_output": "Added nodes: n1, n2, n3, n4, n5. Total nodes: 5\nPartition detected: 2/5 nodes isolated\nPreference set to CP\nWrites rejected on minority side (CP: consistency)"}, {"input": "ADD_NODES n1 n2 n3 n4 n5\nPARTITION_NETWORK group1=n1,n2 group2=n3,n4,n5\nSET_PREFERENCE AP\nSIMULATE_WRITES", "description": "AP system accepts all writes", "expected_output": "Added nodes: n1, n2, n3, n4, n5. Total nodes: 5\nPartition detected: 2/5 nodes isolated\nPreference set to AP\nWrites accepted on both sides (AP: availability)"}, {"input": "ADD_NODES n1 n2 n3 n4 n5\nPARTITION_NETWORK group1=n1,n2 group2=n3,n4,n5\nHEAL_PARTITION", "description": "Partition heals and syncs", "expected_output": "Added nodes: n1, n2, n3, n4, n5. Total nodes: 5\nPartition detected: 2/5 nodes isolated\nPartition healed, nodes re-syncing"}]'::jsonb
WHERE id = 'sys_074';
-- sys_075: Event Stream Replay Engine
UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.concurrent.*;

public class Main {

    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        Service service = new Service(); // User's main service class, 'public' stripped during compilation.

        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String result = handleCommand(service, line);
            if (result != null) {
                System.out.println(result);
            }
        }
        sc.close();
    }

    private static String handleCommand(Service service, String commandLine) {
        if (commandLine.startsWith("store event=")) {
            String eventData = commandLine.substring("store event=".length());
            // Expects the user's Service class to have: public String storeEvent(String eventData)
            return service.storeEvent(eventData);
        } else if (commandLine.startsWith("replay stream")) {
            String argsStr = commandLine.substring("replay stream".length()).trim();
            String fromClause = null;
            String consumerId = null;

            // Split by ", " to handle multiple arguments (e.g., "from=beginning, consumer=audit_service")
            // or single argument (e.g., "from=offset=50")
            String[] parts = argsStr.split(", ");
            for (String part : parts) {
                if (part.startsWith("from=")) {
                    fromClause = part.substring("from=".length());
                } else if (part.startsWith("consumer=")) {
                    consumerId = part.substring("consumer=".length());
                }
            }
            // Expects the user's Service class to have: public String replayStream(String fromClause, String consumerId)
            return service.replayStream(fromClause, consumerId);
        } else if (commandLine.startsWith("consumer_position consumer=")) {
            String consumerId = commandLine.substring("consumer_position consumer=".length());
            // Expects the user's Service class to have: public String getConsumerPosition(String consumerId)
            return service.getConsumerPosition(consumerId);
        } else {
            return "Unknown command: " + commandLine;
        }
    }
