-- sys_076: GraphQL Subscription Manager
UPDATE challenges SET
  test_harness = $harness$import sys
import re

def run_harness():
    service = Service()
    worker = Worker(service) # Assuming Worker takes Service instance for interactions

    subscription_id_counter = 0

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        parts = line.split(' ', 1)
        command = parts[0]
        args_str = parts[1] if len(parts) > 1 else ""

        result = None

        if command == "subscribe":
            match = re.search(r'query=\{topic:\s*(\w+),\s*filter:\s*([^}]+)\}', args_str)
            if match:
                topic = match.group(1)
                filter_str = match.group(2)
                subscription_id_counter += 1
                sub_id = f"SUB{subscription_id_counter:03d}"
                try:
                    service.subscribe(sub_id, topic, filter_str)
                    # Normalize filter_str for output: `status=placed` -> `status placed`
                    output_filter = filter_str.replace("=", " ")
                    result = f"GraphQL subscription created for {topic} {output_filter} (ID: {sub_id})"
                except Exception as e:
                    result = f"Error subscribing: {e}"
            else:
                result = "Invalid subscribe command format"

        elif command == "event":
            # Example: event order_status_changed to placed
            event_match = re.match(r'(\w+)_status_changed to (\w+)', args_str)
            if event_match:
                topic_prefix = event_match.group(1) # e.g., 'order'
                status = event_match.group(2)      # e.g., 'placed'
                try:
                    # Assuming worker.handle_event returns the string expected for event notification
                    # e.g., "Subscription notified: order placed event sent"
                    result = worker.handle_event(topic_prefix, status)
                except Exception as e:
                    result = f"Error processing event: {e}"
            else:
                result = "Invalid event command format"

        elif command == "unsubscribe":
            match = re.search(r'subscription=(\w+)', args_str)
            if match:
                sub_id = match.group(1)
                try:
                    service.unsubscribe(sub_id)
                    result = f"GraphQL subscription {sub_id} cancelled"
                except Exception as e:
                    result = f"Error unsubscribing: {e}"
            else:
                result = "Invalid unsubscribe command format"

        elif command == "subscriber_count":
            match = re.search(r'topic=(\w+)', args_str)
            if match:
                topic = match.group(1)
                try:
                    count = service.get_subscriber_count(topic)
                    result = f"Active subscribers for {topic}: {count}"
                except Exception as e:
                    result = f"Error getting subscriber count: {e}"
            else:
                result = "Invalid subscriber_count command format"
        else:
            result = f"Unknown command: {command}"

        if result is not None:
            print(result)

run_harness()$harness$,
