-- sys_077: Distributed ID Generator
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', async () => {
  // Assume user's Scheduler class is available globally or imported.
  // It is expected to implement:
  // class Scheduler {
  //   constructor();
  //   generateId(nodeId: string): Promise<string>;
  //   setMockTime(timestamp: number): void; // For testing time-based aspects
  //   setMaxSequence(limit: number): void; // For testing sequence overflow
  // }
  const scheduler = new Scheduler();
  const allGeneratedIds: string[] = [];

  for (const line of lines) {
    if (!line) continue;

    const parts = line.split(' ');
    const command = parts[0];
    const args = parts.slice(1);

    try {
      switch (command) {
        case 'SET_TIME': {
          const timestamp = parseInt(args[0], 10);
          if (isNaN(timestamp)) {
            console.error(`Error: Invalid timestamp for SET_TIME: ${args[0]}`);
            continue;
          }
          scheduler.setMockTime(timestamp);
          break;
        }
        case 'SET_MAX_SEQUENCE': {
          const limit = parseInt(args[0], 10);
          if (isNaN(limit)) {
            console.error(`Error: Invalid sequence limit for SET_MAX_SEQUENCE: ${args[0]}`);
            continue;
          }
          scheduler.setMaxSequence(limit);
          break;
        }
        case 'GENERATE': {
          const nodeId = args[0];
          if (!nodeId) {
            console.error('Error: Node ID missing for GENERATE command.');
            continue;
          }
          const id = await scheduler.generateId(nodeId);
          console.log(`Generated ID: ${id}`);
          allGeneratedIds.push(id);
          break;
        }
        case 'BATCH_GENERATE': {
          const count = parseInt(args[0], 10);
          const nodeIdsStr = args[1];
          if (isNaN(count) || count <= 0) {
            console.error(`Error: Invalid count for BATCH_GENERATE: ${args[0]}`);
            continue;
          }
          if (!nodeIdsStr) {
            console.error('Error: Node IDs missing for BATCH_GENERATE command.');
            continue;
          }
          const nodeIds = nodeIdsStr.split(',');
          if (nodeIds.length === 0) {
            console.error('Error: No node IDs provided for BATCH_GENERATE command.');
            continue;
          }

          const promises: Promise<string>[] = [];
          for (let i = 0; i < count; i++) {
            const nodeId = nodeIds[i % nodeIds.length];
            promises.push(scheduler.generateId(nodeId));
          }

          const ids = await Promise.all(promises);
          for (const id of ids) {
             allGeneratedIds.push(id); // Store IDs for later checks, but don't print individual IDs here
          }
          console.log(`Generated ${ids.length} IDs.`); // Print a summary for batch operation
          break;
        }
        case 'CHECK_UNIQUENESS': {
          const uniqueIds = new Set(allGeneratedIds);
          if (uniqueIds.size === allGeneratedIds.length) {
            console.log(`All ${allGeneratedIds.length} IDs are unique.`);
          } else {
            console.log('Collision detected: duplicate IDs found.');
          }
          break;
        }
        case 'PRINT_SORTED_IDS': {
          const sortedIds = [...allGeneratedIds].sort(); // String sort works for ID format `timestamp_node_sequence`
          for (const id of sortedIds) {
            console.log(id);
          }
          break;
        }
        default:
          console.error(`Unknown command: ${command}`);
      }
    } catch (e: any) {
      console.error(`Error executing command '${command}': ${e.message}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "SET_TIME 1703001234567\nGENERATE N1", "description": "Generate a single distributed ID with a specific mock timestamp", "expected_output": "Generated ID: 1703001234567_N1_0001"}, {"input": "SET_TIME 1703001234000\nBATCH_GENERATE 1000 N1,N2,N3\nCHECK_UNIQUENESS", "description": "Generate 1000 IDs concurrently on 3 nodes and verify uniqueness", "expected_output": "Generated 1000 IDs.\nAll 1000 IDs are unique."}, {"input": "SET_MAX_SEQUENCE 2\nSET_TIME 1703001234000\nGENERATE N1\nGENERATE N1\nGENERATE N1", "description": "Sequence overflow handling: timestamp increments when sequence limit is reached", "expected_output": "Generated ID: 1703001234000_N1_0001\nGenerated ID: 1703001234000_N1_0002\nGenerated ID: 1703001234001_N1_0001"}, {"input": "SET_TIME 1703001234000\nGENERATE N1\nSET_TIME 1703001234500\nGENERATE N2\nSET_TIME 1703001234200\nGENERATE N3\nPRINT_SORTED_IDS", "description": "Verify IDs are chronologically sortable by their string representation", "expected_output": "Generated ID: 1703001234000_N1_0001\nGenerated ID: 1703001234500_N2_0001\nGenerated ID: 1703001234200_N3_0001\n1703001234000_N1_0001\n1703001234200_N3_0001\n1703001234500_N2_0001"}]'::jsonb
