-- sys_079: Bulkhead Isolation Boundary
UPDATE challenges SET
  test_harness = $harness$import sys
import re
import threading

# Global counter for unique request IDs to be passed to user's Service.acquire_slot
_GLOBAL_REQUEST_ID_COUNTER = 0
_GLOBAL_REQUEST_ID_LOCK = threading.Lock()

def _generate_request_id(service_name):
    global _GLOBAL_REQUEST_ID_COUNTER
    with _GLOBAL_REQUEST_ID_LOCK:
        _GLOBAL_REQUEST_ID_COUNTER += 1
        return f"{service_name}_req_{_GLOBAL_REQUEST_ID_COUNTER}"

class HarnessServiceManager:
    def __init__(self):
        self.services = {}  # Stores Service instances: {service_name: Service_instance}
        # Stores active request tokens (generated by harness) held by each service:
        # {service_name: [token1, token2, ...]}
        self.active_requests = {}
        # Tracks which services are currently considered saturated by the harness
        # based on previous commands. Used for contextual output.
        self.is_service_saturated = {}

    def run_command(self, line):
        line = line.strip()
        if not line:
            return

        # Command: configure bulkhead service=<name>, pool_size=<size>
        match = re.match(r"configure bulkhead service=(\w+), pool_size=(\d+)", line)
        if match:
            service_name = match.group(1)
            pool_size = int(match.group(2))
            
            if service_name in self.services:
                print(f"Error: Service '{service_name}' already configured.")
                return

            # User's Service class is available. Assumes Service(name, pool_size) constructor.
            try:
                self.services[service_name] = Service(service_name, pool_size)
                self.active_requests[service_name] = []
                self.is_service_saturated[service_name] = False
                print(f"Bulkhead configured: {service_name} isolated pool of {pool_size} threads")
            except Exception as e:
                print(f"Error configuring service '{service_name}': {e}")
            return

        # Command: <service_name>_service saturated=<num> threads
        # This command fills the service's pool to capacity and then attempts one more
        # request to explicitly demonstrate rejection.
        match = re.match(r"(\w+)_service saturated=(\d+) threads", line)
        if match:
            service_name = match.group(1)
            # num_to_saturate_and_test is informational; we fill up to the service's pool_size
            
            service_instance = self.services.get(service_name)
            if not service_instance:
                print(f"Error: Service '{service_name}' not configured.")
                return

            # Assumes Service has get_pool_size(), get_active_count(), acquire_slot(token), release_slot(token)
            try:
                current_pool_size = service_instance.get_pool_size()
                
                # Acquire resources until the service's pool is full
                for _ in range(service_instance.get_active_count(), current_pool_size):
                    token = _generate_request_id(service_name)
                    if service_instance.acquire_slot(token):
                        self.active_requests[service_name].append(token)
                    else:
                        # Should ideally not happen unless pool_size is 0 or acquire_slot has other failure modes
                        print(f"Warning: Could not acquire slot for {service_name} during saturation filling.")
                        break
                
                # Update saturation status for contextual messages in other commands
                self.is_service_saturated[service_name] = (service_instance.get_active_count() >= current_pool_size)

                # Now, attempt one more request to explicitly trigger and print the rejection message.
                token = _generate_request_id(service_name)
                if not service_instance.acquire_slot(token):
                    print(f"{service_name.capitalize()} bulkhead full: requests rejected for {service_name}")
                else:
                    # If it unexpectedly succeeded, release it and report unexpected behavior
                    service_instance.release_slot(token)
                    print(f"Warning: {service_name.capitalize()} service expected to be full but accepted an extra request.")
            except AttributeError as ae:
                print(f"Error: Missing expected method in Service class for '{service_name}': {ae}. Ensure get_pool_size, acquire_slot, release_slot, get_active_count are implemented.")
            except Exception as e:
                print(f"Error saturating service '{service_name}': {e}")
            return

        # Command: request <service_name>_service
        # This command attempts a single request and releases it immediately. 
        # Its output can be contextual (e.g., for isolation tests).
        match = re.match(r"request (\w+)_service", line)
        if match:
            service_name = match.group(1)
            service_instance = self.services.get(service_name)
            if not service_instance:
                print(f"Error: Service '{service_name}' not configured.")
                return
            
            try:
                token = _generate_request_id(service_name)
                if service_instance.acquire_slot(token):
                    service_instance.release_slot(token) # Release immediately after successful acquisition

                    # Determine output message based on known service saturation states.
                    # Specifically, for the 'Bulkhead isolates failure' test, we expect
                    # 'Order service normal: isolated from payment overload' when payment is saturated.
                    if self.is_service_saturated.get("payment", False) and service_name == "order":
                        print(f"Order service normal: isolated from payment overload")
                    else:
                        # Generic success message for requests not directly testing isolation in this way
                        print(f"{service_name.capitalize()} service processed successfully.")
                else:
                    print(f"{service_name.capitalize()} bulkhead full: requests rejected for {service_name}")
            except AttributeError as ae:
                print(f"Error: Missing expected method in Service class for '{service_name}': {ae}. Ensure acquire_slot, release_slot are implemented.")
            except Exception as e:
                print(f"Error processing request for service '{service_name}': {e}")
            return

        # Command: <service_name>_service recovers
        # This command releases all active requests for a service, making its pool available again.
        match = re.match(r"(\w+)_service recovers", line)
        if match:
            service_name = match.group(1)
            service_instance = self.services.get(service_name)
            if not service_instance:
                print(f"Error: Service '{service_name}' not configured.")
                return
            
            try:
                # Release all active requests for this service that the harness is tracking
                # Iterate over a copy to allow modification during iteration
                for token in list(self.active_requests[service_name]): 
                    service_instance.release_slot(token)
                self.active_requests[service_name].clear()
                
                # Update saturation status
                self.is_service_saturated[service_name] = False
                print(f"{service_name.capitalize()} bulkhead pool available again")
            except AttributeError as ae:
                print(f"Error: Missing expected method in Service class for '{service_name}': {ae}. Ensure release_slot is implemented.")
            except Exception as e:
                print(f"Error recovering service '{service_name}': {e}")
            return

        print(f"Unknown command: {line}")

def run_harness():
    manager = HarnessServiceManager()
    for line in sys.stdin:
        manager.run_command(line)

run_harness()$harness$,
  test_cases   = '[{"input": "configure bulkhead service=payment, pool_size=10", "description": "Configure bulkhead", "expected_output": "Bulkhead configured: payment isolated pool of 10 threads"}, {"input": "configure bulkhead service=payment, pool_size=10\npayment_service saturated=10 threads", "description": "Bulkhead rejects overflow", "expected_output": "Bulkhead configured: payment isolated pool of 10 threads\nPayment bulkhead full: requests rejected for payment"}, {"input": "configure bulkhead service=payment, pool_size=10\nconfigure bulkhead service=order, pool_size=5\npayment_service saturated=10 threads\nrequest order_service", "description": "Bulkhead isolates failure", "expected_output": "Bulkhead configured: payment isolated pool of 10 threads\nBulkhead configured: order isolated pool of 5 threads\nPayment bulkhead full: requests rejected for payment\nOrder service normal: isolated from payment overload"}, {"input": "configure bulkhead service=payment, pool_size=10\npayment_service saturated=10 threads\npayment_service recovers", "description": "Bulkhead recovers", "expected_output": "Bulkhead configured: payment isolated pool of 10 threads\nPayment bulkhead full: requests rejected for payment\nPayment bulkhead pool available again"}]'::jsonb
WHERE id = 'sys_079';
-- sys_080: Fan-Out Message Dispatcher
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', async () => {
  const scheduler = new Scheduler();

  // Helper to create mock subscriber callbacks that simulate work and potential failure
  const createMockSubscriberCallback = (name: string, shouldFail: boolean) => {
    return async (event: string): Promise<void> => {
      // Simulate async work with a small, random delay
      await new Promise(resolve => setTimeout(resolve, Math.random() * 5));
      if (shouldFail) {
        throw new Error(`Mock subscriber ${name} failed for event ${event}`);
      }
    };
  };

  for (const line of lines) {
    if (line.startsWith('REGISTER')) {
      const match = line.match(/^REGISTER (\w+)( fails)?(?: topic=(\w+))?$/);
      if (match) {
        const name = match[1];
        const fails = !!match[2]; // Check if ' fails' group exists
        const topic = match[3] || undefined; // Topic is optional
        const callback = createMockSubscriberCallback(name, fails);
        
        // The user's Scheduler must implement registerSubscriber
        scheduler.registerSubscriber(name, callback, topic);
      } else {
        console.log(`ERROR: Invalid REGISTER command format: ${line}`);
      }
    } else if (line.startsWith('PUBLISH')) {
      const match = line.match(/^PUBLISH (\w+) subscribers=\[([\w,]+)\](?: topic=(\w+))?$/);
      if (match) {
        const event = match[1];
        const subscriberNames = match[2].split(',');
        const topic = match[3] || undefined;
        const options = topic ? { topic } : undefined;
        try {
          // The user's Scheduler must implement publish and return a string
          const result = await scheduler.publish(event, subscriberNames, options);
          console.log(result);
        } catch (e: any) {
          console.log(`ERROR: Scheduler publish failed: ${e.message}`);
        }
      } else {
        console.log(`ERROR: Invalid PUBLISH command format: ${line}`);
      }
    } else if (line.trim().length > 0) {
      console.log(`WARN: Unknown command: ${line}`);
    }
  }
});$harness$,
