-- sys_081: Vector Clock Conflict Resolver
UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.Map;
import java.util.HashMap;
import java.util.concurrent.ConcurrentHashMap;
import java.util.ArrayList;
import java.util.Collections;

public class Main {

    // Helper to parse clock string "[N1:1, N2:0]" into Map<String, Integer>
    private static Map<String, Integer> parseClock(String clockStr) {
        Map<String, Integer> clock = new ConcurrentHashMap<>();
        if (clockStr == null || clockStr.isEmpty() || !clockStr.startsWith("[") || !clockStr.endsWith("]")) {
            return clock;
        }
        String inner = clockStr.substring(1, clockStr.length() - 1);
        if (inner.isEmpty()) return clock;
        String[] entries = inner.split(", ");
        for (String entry : entries) {
            String[] parts = entry.split(":");
            if (parts.length == 2) {
                try {
                    clock.put(parts[0].trim(), Integer.parseInt(parts[1].trim()));
                } catch (NumberFormatException e) {
                    System.err.println("Warning: Invalid clock entry format: " + entry);
                }
            }
        }
        return clock;
    }

    // Helper to format Map<String, Integer> into clock string "[N1:1, N2:0]"
    private static String formatClock(Map<String, Integer> clock) {
        StringBuilder sb = new StringBuilder("[");
        boolean first = true;
        
        // Sort keys for consistent output order
        ArrayList<String> sortedNodes = new ArrayList<>(clock.keySet());
        Collections.sort(sortedNodes);

        for (String node : sortedNodes) {
            if (!first) {
                sb.append(", ");
            }
            sb.append(node).append(":").append(clock.get(node));
            first = false;
        }
        sb.append("]");
        return sb.toString();
    }

    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        // Instantiate the user's Service class
        Service service = new Service(); 

        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) continue;

            String[] parts = line.split(" ", 2);
            String command = parts[0].toUpperCase();
            String argsStr = parts.length > 1 ? parts[1] : "";

            try {
                switch (command) {
                    case "INIT_CLOCK": {
                        // INIT_CLOCK N1 [N1:1, N2:0, N3:0]
                        String[] cmdArgs = argsStr.split(" ", 2);
                        String nodeId = cmdArgs[0];
                        Map<String, Integer> clock = parseClock(cmdArgs[1]);
                        service.initClock(nodeId, clock);
                        System.out.println("Clock for " + nodeId + " initialized to: " + formatClock(clock));
                        break;
                    }
                    case "NODE_EVENT": {
                        // NODE_EVENT N1 write
                        String[] cmdArgs = argsStr.split(" ", 2);
                        String nodeId = cmdArgs[0];
                        String eventType = cmdArgs[1];
                        service.processEvent(nodeId, eventType);
                        System.out.println("Event '" + eventType + "' processed for " + nodeId + ".");
                        break;
                    }
                    case "GET_CLOCK": {
                        // GET_CLOCK N1
                        String nodeId = argsStr;
                        Map<String, Integer> clock = service.getClock(nodeId);
                        System.out.println("Clock for " + nodeId + ": " + formatClock(clock));
                        break;
                    }
                    case "SYNC": {
                        // SYNC N1 N2 [N1:1, N2:2, N3:0]
                        String[] cmdArgs = argsStr.split(" ", 3);
                        String targetNodeId = cmdArgs[0];
                        String sourceNodeId = cmdArgs[1];
                        Map<String, Integer> sourceClock = parseClock(cmdArgs[2]);
                        service.syncClocks(targetNodeId, sourceNodeId, sourceClock);
                        System.out.println(targetNodeId + " synced with " + sourceNodeId + "'s clock: " + formatClock(sourceClock));
                        break;
                    }
                    case "PUT": {
                        // PUT N1 x [N1:1, N2:0, N3:0] "val1"
                        int firstBracket = argsStr.indexOf('[');
                        int lastBracket = argsStr.lastIndexOf(']');
                        if (firstBracket == -1 || lastBracket == -1 || lastBracket < firstBracket) {
                            throw new IllegalArgumentException("Invalid PUT command format: missing or malformed clock string.");
                        }

                        String preClock = argsStr.substring(0, firstBracket).trim(); 
                        String clockString = argsStr.substring(firstBracket, lastBracket + 1);
                        String postClock = argsStr.substring(lastBracket + 1).trim(); 

                        String[] preClockParts = preClock.split(" ");
                        if (preClockParts.length != 2) {
                            throw new IllegalArgumentException("Invalid PUT command format: expected <nodeId> <key> before clock.");
                        }
                        String nodeId = preClockParts[0];
                        String key = preClockParts[1];

                        String value = postClock;
                        if (value.startsWith("\"") && value.endsWith("\"")) {
                            value = value.substring(1, value.length() - 1);
                        }

                        Map<String, Integer> clock = parseClock(clockString);
                        service.put(nodeId, key, value, clock);
                        System.out.println("Data for key '" + key + "' stored by " + nodeId + " with clock " + formatClock(clock) + ".");
                        break;
                    }
                    case "CHECK_CONFLICT": {
                        // CHECK_CONFLICT x
                        String key = argsStr;
                        String conflictStatus = service.checkConflict(key);
                        System.out.println("Conflict status for key '" + key + "': " + conflictStatus);
                        break;
                    }
                    case "RESOLVE_CONFLICT": {
                        // RESOLVE_CONFLICT x last_write_wins
                        String[] cmdArgs = argsStr.split(" ", 2);
                        String key = cmdArgs[0];
                        String strategy = cmdArgs[1];
                        String resolutionResult = service.resolveConflict(key, strategy);
                        System.out.println("Conflict for key '" + key + "' resolved using '" + strategy + "': " + resolutionResult);
                        break;
                    }
                    default:
                        System.out.println("Unknown command: " + command);
                        break;
                }
            } catch (Exception e) {
                System.err.println("Error processing command '" + line + "': " + e.getMessage());
                // For debugging, print stack trace. Remove in production if sensitive.
                // e.printStackTrace(System.err);
            }
        }
        sc.close();
    }
}$harness$,
  test_cases   = '[{"input": "INIT_CLOCK N1 [N1:1, N2:0, N3:0]\nNODE_EVENT N1 write\nGET_CLOCK N1", "description": "Increment vector clock on event", "expected_output": "Clock for N1 initialized to: [N1:1, N2:0, N3:0]\nEvent ''write'' processed for N1.\nClock for N1: [N1:2, N2:0, N3:0]"}, {"input": "INIT_CLOCK N1 [N1:2, N2:0, N3:0]\nSYNC N1 N2 [N1:1, N2:2, N3:0]\nGET_CLOCK N1", "description": "Merge vector clocks", "expected_output": "Clock for N1 initialized to: [N1:2, N2:0, N3:0]\nN1 synced with N2''s clock: [N1:1, N2:2, N3:0]\nClock for N1: [N1:2, N2:2, N3:0]"}, {"input": "PUT N1 x [N1:1, N2:0, N3:0] \"value_from_N1\"\nPUT N2 x [N1:0, N2:1, N3:0] \"value_from_N2\"\nCHECK_CONFLICT x", "description": "Detect concurrent write conflict", "expected_output": "Data for key ''x'' stored by N1 with clock [N1:1, N2:0, N3:0].\nData for key ''x'' stored by N2 with clock [N1:0, N2:1, N3:0].\nConflict status for key ''x'': Conflict detected: concurrent writes to x, resolution needed"}, {"input": "PUT N1 x [N1:1, N2:0, N3:0] \"value_from_N1\"\nPUT N2 x [N1:0, N2:1, N3:0] \"value_from_N2\"\nRESOLVE_CONFLICT x last_write_wins", "description": "Resolve conflict", "expected_output": "Data for key ''x'' stored by N1 with clock [N1:1, N2:0, N3:0].\nData for key ''x'' stored by N2 with clock [N1:0, N2:1, N3:0].\nConflict for key ''x'' resolved using ''last_write_wins'': Conflict resolved: later timestamp wins"}]'::jsonb
WHERE id = 'sys_081';
-- sys_082: Zero-Downtime Migration Runner
UPDATE challenges SET
  test_harness = $harness$import sys

def run_harness():
    # Instantiate the main service component once to maintain state across commands.
    # The user's Service class is expected to have a handle_command method.
    service = Service()

    # Read commands from stdin, one line at a time.
    for line in sys.stdin:
        command = line.strip()
        if not command:
            continue

        # Process the command using the service and print its output.
        # The service's handle_command method is expected to return a string.
        result = service.handle_command(command)
        print(result)

# Call the harness function at module level as required.
run_harness()$harness$,
  test_cases   = '[{"input": "create_migration add column=email to users, zero_downtime=true", "description": "Plan zero-downtime migration", "expected_output": "Migration plan: add nullable column, backfill, add constraint"}, {"input": "create_migration add column=email to users, zero_downtime=true\nphase=1 add_nullable_column email to users", "description": "Phase 1 - add nullable column", "expected_output": "Migration plan: add nullable column, backfill, add constraint\nPhase 1 complete: email column added (nullable)"}, {"input": "create_migration add column=email to users, zero_downtime=true\nphase=1 add_nullable_column email to users\nphase=2 backfill email values", "description": "Phase 2 - backfill data", "expected_output": "Migration plan: add nullable column, backfill, add constraint\nPhase 1 complete: email column added (nullable)\nPhase 2 complete: email backfilled for 1M rows"}, {"input": "create_migration add column=email to users, zero_downtime=true\nphase=1 add_nullable_column email to users\nphase=2 backfill email values\nphase=3 add_not_null_constraint email", "description": "Phase 3 - add constraint", "expected_output": "Migration plan: add nullable column, backfill, add constraint\nPhase 1 complete: email column added (nullable)\nPhase 2 complete: email backfilled for 1M rows\nPhase 3 complete: NOT NULL constraint added"}, {"input": "create_migration add column=phone to customers, zero_downtime=true\nphase=1 add_nullable_column phone to customers", "description": "Plan and start a different migration (phone to customers)", "expected_output": "Migration plan: add nullable column, backfill, add constraint\nPhase 1 complete: phone column added (nullable)"}]'::jsonb
WHERE id = 'sys_082';
-- sys_083: Compression Codec Pipeline
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

// These are the concrete Task implementations used by the test harness.
// They simulate the operations and print the expected output to stdout.
// The user's Scheduler class will receive instances of these Task types.
class GzipCompressTask implements Task {
  constructor(private dataId: string) {}
  async execute(): Promise<void> {
    // Simulate GZIP compression work with a delay
    await new Promise(resolve => setTimeout(resolve, 10));
    console.log("Compressed with gzip: 75% size reduction");
  }
}

class SnappyCompressTask implements Task {
  constructor(private dataId: string) {}
  async execute(): Promise<void> {
    // Simulate Snappy compression work (faster, shorter delay)
    await new Promise(resolve => setTimeout(resolve, 5));
    console.log("Compressed with snappy: 60% reduction, faster");
  }
}

class GzipDecompressTask implements Task {
  constructor(private dataId: string) {}
  async execute(): Promise<void> {
    // Simulate GZIP decompression work with a delay
    await new Promise(resolve => setTimeout(resolve, 8));
    console.log("Decompressed successfully");
  }
}

class PipelineTask implements Task {
  constructor(private pipelineSteps: string[]) {}
  async execute(): Promise<void> {
    // Simulate pipeline processing with a delay
    await new Promise(resolve => setTimeout(resolve, 15));
    console.log("Data processed through compression pipeline");
  }
}

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout // Added for completeness, though not strictly required for input reading
});
const lines: string[] = [];
rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', async () => {
  // Initialize the user's Scheduler class instance
  // The user is expected to implement methods like `addTask` and `run` on this class.
  const scheduler = new Scheduler();

  for (const line of lines) {
    if (line.length === 0) continue; // Skip empty lines

    const parts = line.split(' ');
    const command = parts[0];
    const args = parts.slice(1);

    switch (command) {
      case 'ADD_GZIP_COMPRESS':
        // Adds a GZIP compression task to the scheduler
        scheduler.addTask(new GzipCompressTask(args[0]));
        break;
      case 'ADD_SNAPPY_COMPRESS':
        // Adds a Snappy compression task to the scheduler
        scheduler.addTask(new SnappyCompressTask(args[0]));
        break;
      case 'ADD_GZIP_DECOMPRESS':
        // Adds a GZIP decompression task to the scheduler
        scheduler.addTask(new GzipDecompressTask(args[0]));
        break;
      case 'ADD_PIPELINE':
        // Adds a multi-codec pipeline task to the scheduler
        scheduler.addTask(new PipelineTask(args[0].split(',')));
        break;
      case 'EXECUTE_ALL_TASKS':
        // Triggers the scheduler to execute all tasks currently added.
        // This method is expected to be asynchronous and manage concurrency.
        await scheduler.run();
        break;
      default:
        console.error(`Unknown command: ${command}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "ADD_GZIP_COMPRESS large_json\nEXECUTE_ALL_TASKS", "description": "GZIP compression", "expected_output": "Compressed with gzip: 75% size reduction"}, {"input": "ADD_SNAPPY_COMPRESS large_json\nEXECUTE_ALL_TASKS", "description": "Snappy compression (faster)", "expected_output": "Compressed with snappy: 60% reduction, faster"}, {"input": "ADD_GZIP_DECOMPRESS compressed.gz\nEXECUTE_ALL_TASKS", "description": "Decompress data", "expected_output": "Decompressed successfully"}, {"input": "ADD_PIPELINE compress,encrypt,serialize\nEXECUTE_ALL_TASKS", "description": "Multi-codec pipeline", "expected_output": "Data processed through compression pipeline"}, {"input": "ADD_GZIP_COMPRESS data1\nADD_SNAPPY_COMPRESS data2\nADD_GZIP_DECOMPRESS data3\nEXECUTE_ALL_TASKS", "description": "Multiple concurrent tasks", "expected_output": "Compressed with snappy: 60% reduction, faster\nDecompressed successfully\nCompressed with gzip: 75% size reduction"}]'::jsonb
