    public static void main(String[] args) throws Exception {
        Scanner scanner = new Scanner(System.in);

        // The user's Service class is expected to be the central component
        // managing distributed cron logic and interacting with internal Worker instances.
        Service systemService = new Service();

        while (scanner.hasNextLine()) {
            String line = scanner.nextLine().trim();
            if (line.isEmpty()) continue;

            String output = "";

            if (line.startsWith("schedule job=")) {
                // Command format: schedule job=cleanup, cron=0 3 * * *, nodes=[n1, n2, n3]
                
                // Split into "schedule job=JOBNAME" and "cron=CRON_EXP, nodes=[NODE_LIST]"
                String[] jobAndCronNodes = line.split(", cron=");
                String jobName = jobAndCronNodes[0].substring("schedule job=".length());
                
                // Split "CRON_EXP, nodes=[NODE_LIST]" into "CRON_EXP" and "[NODE_LIST]"
                String cronAndNodesPart = jobAndCronNodes[1];
                String[] cronAndNodesSplit = cronAndNodesPart.split(", nodes=");
                String cron = cronAndNodesSplit[0];
                String nodesListStr = cronAndNodesSplit[1]; // e.g., "[n1, n2, n3]"
                
                // Extract node IDs from the bracketed string
                String nodesContent = nodesListStr.substring(1, nodesListStr.length() - 1); // Remove brackets
                List<String> nodeIds = Arrays.stream(nodesContent.split(", "))
                                             .map(String::trim)
                                             .collect(Collectors.toList());
                
                // User's Service class is expected to have this method signature.
                output = systemService.scheduleJob(jobName, cron, nodeIds);

            } else if (line.startsWith("leader elects to run ")) {
                // Command format: leader elects to run cleanup at 03:00
                String jobPart = line.substring("leader elects to run ".length());
                String jobName = jobPart.split(" at ")[0];
                String time = jobPart.split(" at ")[1];
                
                // User's Service class is expected to have this method signature.
                output = systemService.triggerCronExecution(jobName, time);

            } else if (line.startsWith("leader=") && line.contains("crashes during job")) {
                // Command format: leader=n1 crashes during job
                String crashInfo = line.substring("leader=".length());
                String nodeId = crashInfo.split(" ")[0]; // Extracts "n1"
                
                // User's Service class is expected to have this method signature.
                output = systemService.handleLeaderCrash(nodeId);

            } else if (line.equals("prevent duplicate runs in same window")) {
                // This command implies re-attempting a cron execution that should be prevented.
                // We assume it refers to the 'cleanup' job at '03:00' from previous steps.
                // The Service implementation should contain the logic for duplicate prevention.
                output = systemService.triggerCronExecution("cleanup", "03:00"); 

            } else {
                // Fallback for unexpected commands, useful for debugging harness issues
                output = "Unknown command: " + line;
            }
            System.out.println(output);
        }
        scanner.close();
    }
