  const scheduler = new Scheduler(); // Instantiate the user's Scheduler class

  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    try {
      let output: string | null = null;

      if (line.startsWith('simulate partition')) {
        // Example: simulate partition nodes=[n1, n2], isolate=[n3]
        const args = line.substring('simulate partition'.length).trim();
        const parts = args.split(',').map(s => s.trim());
        const nodesPart = parts.find(p => p.startsWith('nodes='));
        const isolatePart = parts.find(p => p.startsWith('isolate='));

        let nodes: string[] = [];
        let isolate: string[] = [];

        if (nodesPart) {
          const nodesStr = nodesPart.substring('nodes='.length).replace('[', '').replace(']', '');
          nodes = nodesStr.split(',').map(n => n.trim()).filter(Boolean);
        }
        if (isolatePart) {
          const isolateStr = isolatePart.substring('isolate='.length).replace('[', '').replace(']', '');
          isolate = isolateStr.split(',').map(n => n.trim()).filter(Boolean);
        }
        output = await scheduler.simulatePartition(nodes, isolate);

      } else if (line === 'test_consistency during partition') {
        // Example: test_consistency during partition
        output = await scheduler.testConsistencyDuringPartition();

      } else if (line === 'heal_partition') {
        // Example: heal_partition
        output = await scheduler.healPartition();

      } else if (line.startsWith('simulate latency')) {
        // Example: simulate latency between n1 and n2, delay=500ms
        const commandArgs = line.substring('simulate latency'.length).trim();
        const parts = commandArgs.split(',').map(s => s.trim());
        
        let node1: string | null = null;
        let node2: string | null = null;
        let delayMs: number | null = null;

        // Parse 'between n1 and n2'
        const betweenMatch = parts[0]?.match(/between (.*) and (.*)/);
        if (betweenMatch) {
          node1 = betweenMatch[1].trim();
          node2 = betweenMatch[2].trim();
        }

        // Parse 'delay=500ms'
        const delayMatch = parts[1]?.match(/delay=(\d+)ms/);
        if (delayMatch) {
          delayMs = parseInt(delayMatch[1], 10);
        }

        if (node1 && node2 && delayMs !== null) {
          output = await scheduler.simulateLatency(node1, node2, delayMs);
        } else {
          output = `Error: Invalid 'simulate latency' command format: ${line}`;
        }

      } else {
        output = `Unknown command: ${line}`;
      }

      if (output !== null) {
        console.log(output);
      }

    } catch (error: any) {
      console.error(`Error executing command "${line}": ${error.message || error}`);
    }
  }
