UPDATE challenges SET
  test_harness = $harness$import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicLong;
import java.util.function.Supplier;
import java.util.Scanner;
import java.util.*;

// --- Cr4ck Harness internal classes --- 

// Cr4ckExecutor: A mock ExecutorService that runs tasks immediately in the calling thread.
// This simplifies virtual time management as tasks complete instantly when 'executed'.
// Actual delays are handled by Cr4ckScheduler.
static class Cr4ckExecutor implements ExecutorService {
    @Override
    public void execute(Runnable command) {
        command.run();
    }

    @Override public void shutdown() {} 
    @Override public List<Runnable> shutdownNow() { return Collections.emptyList(); } 
    @Override public boolean isShutdown() { return false; } 
    @Override public boolean isTerminated() { return false; } 
    @Override public boolean awaitTermination(long timeout, TimeUnit unit) throws InterruptedException { return true; }

    @Override
    public <T> Future<T> submit(Callable<T> task) {
        CompletableFuture<T> future = new CompletableFuture<>();
        try {
            future.complete(task.call());
        } catch (Exception e) {
            future.completeExceptionally(e);
        }
        return future;
    }

    @Override
    public <T> Future<T> submit(Runnable task, T result) {
        CompletableFuture<T> future = new CompletableFuture<>();
        task.run();
        future.complete(result);
        return future;
    }

    @Override
    public Future<?> submit(Runnable task) {
        CompletableFuture<Void> future = new CompletableFuture<>();
        task.run();
        future.complete(null);
        return future;
    }

    // Unsupported methods for this mock
    @Override public <T> List<Future<T>> invokeAll(Collection<? extends Callable<T>> tasks) { throw new UnsupportedOperationException("Not implemented for Cr4ckExecutor"); }
    @Override public <T> List<Future<T>> invokeAll(Collection<? extends Callable<T>> tasks, long timeout, TimeUnit unit) { throw new UnsupportedOperationException("Not implemented for Cr4ckExecutor"); }
    @Override public <T> T invokeAny(Collection<? extends Callable<T>> tasks) { throw new UnsupportedOperationException("Not implemented for Cr4ckExecutor"); }
    @Override public <T> T invokeAny(Collection<? extends Callable<T>> tasks, long timeout, TimeUnit unit) { throw new UnsupportedOperationException("Not implemented for Cr4ckExecutor"); }
}

// Cr4ckScheduler: A mock ScheduledExecutorService that manages tasks based on a virtual clock.
// It does not use real threads for scheduling; instead, tasks are executed when `advanceTime` is called.
static class Cr4ckScheduler extends ScheduledThreadPoolExecutor {
    private long virtualTimeMs = 0;
    private PriorityQueue<ScheduledTask> scheduledTasks = new PriorityQueue<>(Comparator.comparingLong(t -> t.scheduledTimeMs));
    private final Executor directExecutor; // Used to execute tasks when their virtual time arrives

    static class ScheduledTask implements Runnable {
        final long scheduledTimeMs;
        final Runnable command;

        ScheduledTask(long scheduledTimeMs, Runnable command) {
            this.scheduledTimeMs = scheduledTimeMs;
            this.command = command;
        }

        @Override
        public void run() {
            command.run();
        }
    }

    public Cr4ckScheduler(Executor directExecutor) {
        super(1); // Core pool size 1, but we don't use real threads for scheduling.
        this.directExecutor = directExecutor;
    }

    public long getVirtualTime() {
        return virtualTimeMs;
    }

    // Advances the virtual clock and executes any tasks whose scheduled time has arrived.
    public void advanceTime(long millis) {
        virtualTimeMs += millis;
        
        // Collect all tasks to be run *before* running them to avoid ConcurrentModification 
        // if a task itself schedules new tasks (which would add to 'scheduledTasks').
        List<ScheduledTask> tasksToExecute = new ArrayList<>();
        while (!scheduledTasks.isEmpty() && scheduledTasks.peek().scheduledTimeMs <= virtualTimeMs) {
            tasksToExecute.add(scheduledTasks.poll());
        }

        for (ScheduledTask task : tasksToExecute) {
            directExecutor.execute(task.command); // Execute the original command
        }
    }

    @Override
    public ScheduledFuture<?> schedule(Runnable command, long delay, TimeUnit unit) {
        long scheduledTime = virtualTimeMs + unit.toMillis(delay);
        CompletableFuture<Void> future = new CompletableFuture<>();
        ScheduledTask task = new ScheduledTask(scheduledTime, () -> {
            command.run(); // Run the user's command
            future.complete(null); // Complete the internal future
        });
        scheduledTasks.add(task);
        return new CompletableFutureScheduledFuture<>(future, unit.toMillis(delay), scheduledTime);
    }

    @Override
    public <V> ScheduledFuture<V> schedule(Callable<V> callable, long delay, TimeUnit unit) {
        long scheduledTime = virtualTimeMs + unit.toMillis(delay);
        CompletableFuture<V> future = new CompletableFuture<>();
        ScheduledTask task = new ScheduledTask(scheduledTime, () -> {
            try {
                future.complete(callable.call());
            } catch (Exception e) {
                future.completeExceptionally(e);
            }
        });
        scheduledTasks.add(task);
        return new CompletableFutureScheduledFuture<>(future, unit.toMillis(delay), scheduledTime);
    }

    // Custom ScheduledFuture implementation to wrap CompletableFuture, providing necessary interface methods.
    static class CompletableFutureScheduledFuture<V> extends CompletableFuture<V> implements ScheduledFuture<V> {
        private final CompletableFuture<V> wrapped;
        private final long initialDelay;
        private final long scheduledTimestamp;

        public CompletableFutureScheduledFuture(CompletableFuture<V> wrapped, long initialDelay, long scheduledTimestamp) {
            this.wrapped = wrapped;
            this.initialDelay = initialDelay;
            this.scheduledTimestamp = scheduledTimestamp;
        }

        @Override
        public long getDelay(TimeUnit unit) {
            // Simplified: return 0 if virtually past scheduled time, otherwise remaining time. 
            // This implementation is sufficient for common test cases.
            long remaining = scheduledTimestamp - ((Cr4ckScheduler)((ScheduledThreadPoolExecutor)Thread.currentThread().getThreadGroup().getParent().parentThreadGroup().getThreads()[0].getScheduler())).getVirtualTime(); // Hacky way to get virtual time
            return unit.convert(Math.max(0, remaining), TimeUnit.MILLISECONDS);
        }

        @Override
        public int compareTo(Delayed o) {
            long diff = this.getDelay(TimeUnit.MILLISECONDS) - o.getDelay(TimeUnit.MILLISECONDS);
            return diff == 0 ? 0 : (diff < 0 ? -1 : 1);
        }

        @Override public boolean cancel(boolean mayInterruptIfRunning) { return wrapped.cancel(mayInterruptIfRunning); }
        @Override public boolean isCancelled() { return wrapped.isCancelled(); }
        @Override public boolean isDone() { return wrapped.isDone(); }
        @Override public V get() throws InterruptedException, ExecutionException { return wrapped.get(); }
        @Override public V get(long timeout, TimeUnit unit) throws InterruptedException, ExecutionException, TimeoutException { return wrapped.get(timeout, unit); }
    }

    // Unsupported/simplified methods for this mock
    @Override public void shutdown() {} 
    @Override public List<Runnable> shutdownNow() { return Collections.emptyList(); }
}

// ServiceGateway: A mock for external service calls.
// It allows configuring specific delays and responses for primary and secondary calls
// to a named service, using the Cr4ckScheduler for time-based completion.
static class ServiceGateway {
    private final Cr4ckScheduler scheduler;
    private final Map<String, ServiceConfig> serviceConfigs = new ConcurrentHashMap<>();

    static class ServiceConfig {
        long primaryDelayMs;
        String primaryResponse;
        boolean primaryFails;
        String primaryError;

        long secondaryDelayMs;
        String secondaryResponse;
        boolean secondaryFails;
        String secondaryError;

        ServiceConfig(long pDelay, String pResp, long sDelay, String sResp) {
            this.primaryDelayMs = pDelay;
            this.primaryResponse = pResp;
            this.primaryFails = pResp != null && pResp.startsWith("FAILURE:");
            this.primaryError = this.primaryFails ? pResp.substring("FAILURE:".length()) : null;

            this.secondaryDelayMs = sDelay;
            this.secondaryResponse = sResp;
            this.secondaryFails = sResp != null && sResp.startsWith("FAILURE:");
            this.secondaryError = this.secondaryFails ? sResp.substring("FAILURE:".length()) : null;
        }
    }

    public ServiceGateway(Cr4ckScheduler scheduler) {
        this.scheduler = scheduler;
    }

    // Configures the behavior of a named service for primary and secondary calls.
    // `primaryResponse` and `secondaryResponse` can be "SUCCESS:<content>" or "FAILURE:<error_message>".
    public void configureService(String serviceId, long primaryDelay, String primaryResponse, long secondaryDelay, String secondaryResponse) {
        serviceConfigs.put(serviceId, new ServiceConfig(primaryDelay, primaryResponse, secondaryDelay, secondaryResponse));
    }

    // Simulates an external service call, returning a CompletableFuture that completes
    // after the configured delay, based on the Cr4ckScheduler's virtual time.
    public CompletableFuture<String> callService(String serviceId, boolean isPrimaryCall) {
        CompletableFuture<String> future = new CompletableFuture<>();
        ServiceConfig config = serviceConfigs.get(serviceId);

        if (config == null) {
            return CompletableFuture.failedFuture(new RuntimeException("Service " + serviceId + " not configured."));
        }

        long delay = isPrimaryCall ? config.primaryDelayMs : config.secondaryDelayMs;
        String responseContent = isPrimaryCall ? config.primaryResponse : config.secondaryResponse;
        boolean fails = isPrimaryCall ? config.primaryFails : config.secondaryFails;
        String errorContent = isPrimaryCall ? config.primaryError : config.secondaryError;

        if (delay == -1) { // Special value for 'never responds'
            // The future will remain incomplete, simulating a service that never responds.
            return future;
        }

        scheduler.schedule(() -> {
            if (future.isDone()) return; // Already completed or cancelled by another path (e.g., hedging)
            if (fails) {
                future.completeExceptionally(new RuntimeException(errorContent));
            } else {
                future.complete(responseContent.substring("SUCCESS:".length()));
            }
        }, delay, TimeUnit.MILLISECONDS);

        return future;
    }
}

public class Main {
    public static void main(String[] args) throws Exception {
        // Initialize the mock components for the user's Service class
        Cr4ckExecutor executor = new Cr4ckExecutor();
        Cr4ckScheduler scheduler = new Cr4ckScheduler(executor);
        ServiceGateway gateway = new ServiceGateway(scheduler);

        // Instantiate the user's Service class
        // The user's `Service` class is expected to have a constructor like:
        // public Service(ExecutorService executor, ScheduledExecutorService scheduler, ServiceGateway gateway)
        Service service = new Service(executor, scheduler, gateway);

        // Map to hold CompletableFuture results for active `dispatchHedgedRequest` calls.
        Map<String, CompletableFuture<String>> activeRequests = new ConcurrentHashMap<>();
        // A separate executor for the harness to run user's blocking `dispatchHedgedRequest` calls
        // in the background, allowing the main harness loop to process `ADVANCE` commands.
        ExecutorService harnessBackgroundExecutor = Executors.newSingleThreadExecutor(); 

        Scanner sc = new Scanner(System.in);
        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) continue;

            String[] parts = line.split(" ", 2);
            String command = parts[0];
            String argsStr = parts.length > 1 ? parts[1] : "";

            try {
                switch (command) {
                    // Configure a mock external service's primary and secondary call behavior.
                    // Format: CONFIGURE_SERVICE <serviceId> <primaryCallDelayMs> <primaryCallResult> <secondaryCallDelayMs> <secondaryCallResult>
                    // Example: CONFIGURE_SERVICE slow_service 200 SUCCESS:P_OK 95 SUCCESS:S_OK
                    // `primaryCallResult`/`secondaryCallResult` can be "SUCCESS:<content>" or "FAILURE:<error_message>".
                    case "CONFIGURE_SERVICE": {
                        String[] configArgs = argsStr.split(" ", 5);
                        if (configArgs.length != 5) throw new IllegalArgumentException("Invalid CONFIGURE_SERVICE format.");
                        String serviceId = configArgs[0];
                        long primaryDelay = Long.parseLong(configArgs[1]);
                        String primaryResponse = configArgs[2];
                        long secondaryDelay = Long.parseLong(configArgs[3]);
                        String secondaryResponse = configArgs[4];
                        gateway.configureService(serviceId, primaryDelay, primaryResponse, secondaryDelay, secondaryResponse);
                        break;
                    }
                    // Dispatch a hedged request through the user's Service.
                    // Format: DISPATCH <requestId> <serviceId> <hedgeDelayMs>
                    case "DISPATCH": {
                        String[] dispatchArgs = argsStr.split(" ", 3);
                        if (dispatchArgs.length != 3) throw new IllegalArgumentException("Invalid DISPATCH format.");
                        String requestId = dispatchArgs[0];
                        String serviceId = dispatchArgs[1];
                        long hedgeDelay = Long.parseLong(dispatchArgs[2]);

                        CompletableFuture<String> resultFuture = new CompletableFuture<>();
                        activeRequests.put(requestId, resultFuture);

                        // Run the user's `dispatchHedgedRequest` in a background thread.
                        // This allows the main harness thread to continue processing `ADVANCE` commands.
                        harnessBackgroundExecutor.submit(() -> {
                            try {
                                // Assume Service.dispatchHedgedRequest blocks and returns the final status string.
                                String result = service.dispatchHedgedRequest(serviceId, hedgeDelay);
                                resultFuture.complete(result);
                            } catch (Exception e) {
                                resultFuture.completeExceptionally(e);
                            }
                        });
                        System.out.println("DISPATCHED " + requestId);
                        break;
                    }
                    // Advance the virtual clock, triggering any scheduled tasks.
                    // Format: ADVANCE <milliseconds>
                    case "ADVANCE": {
                        long ms = Long.parseLong(argsStr);
                        scheduler.advanceTime(ms);
                        System.out.println("ADVANCED " + ms + "ms");
                        break;
                    }
                    // Retrieve and print the result of a previously dispatched request.
                    // Format: GET_RESULT <requestId>
                    case "GET_RESULT": {
                        String requestId = argsStr;
                        CompletableFuture<String> future = activeRequests.remove(requestId);
                        if (future == null) {
                            System.out.println("ERROR: No active request found for " + requestId);
                            break;
                        }
                        try {
                            // Wait for a reasonable timeout for the result.
                            String result = future.get(5, TimeUnit.SECONDS); 
                            System.out.println("RESULT " + requestId + ": " + result);
                        } catch (CancellationException e) {
                            System.out.println("RESULT " + requestId + ": CANCELED");
                        } catch (TimeoutException e) {
                            System.out.println("RESULT " + requestId + ": TIMEOUT - Not completed within 5 seconds.");
                        } catch (ExecutionException e) {
                            System.out.println("RESULT " + requestId + ": ERROR - " + e.getCause().getMessage());
                        }
                        break;
                    }
                    default:
                        System.out.println("UNKNOWN COMMAND: " + command);
                }
            } catch (Exception e) {
                System.out.println("HARNESS ERROR: " + e.getMessage());
                // For debugging harness issues, uncomment the next line:
                // e.printStackTrace(); 
            }
        }

        // Clean up resources
        harnessBackgroundExecutor.shutdownNow();
        executor.shutdownNow();
        scheduler.shutdownNow();
        sc.close();
    }
}$harness$,
  test_cases   = '[{"input": "CONFIGURE_SERVICE slow_service 1000 SUCCESS:PrimaryValue 95 SUCCESS:SecondaryValue\nDISPATCH req1 slow_service 100\nADVANCE 195\nGET_RESULT req1", "description": "Hedge request fires secondary", "expected_output": "DISPATCHED req1\nADVANCED 195ms\nRESULT req1: Hedged: secondary request fired after 100ms"}, {"input": "CONFIGURE_SERVICE fast_service 80 SUCCESS:PrimaryValue 1000 SUCCESS:SecondaryValue\nDISPATCH req1 fast_service 100\nADVANCE 80\nGET_RESULT req1", "description": "Primary wins, hedge cancelled", "expected_output": "DISPATCHED req1\nADVANCED 80ms\nRESULT req1: Primary responded first (80ms), hedge cancelled"}, {"input": "CONFIGURE_SERVICE mixed_service 200 SUCCESS:PrimaryValue 95 SUCCESS:SecondaryValue\nDISPATCH req1 mixed_service 100\nADVANCE 195\nGET_RESULT req1", "description": "Faster secondary response used", "expected_output": "DISPATCHED req1\nADVANCED 195ms\nRESULT req1: Secondary response used (95ms vs 200ms)"}, {"input": "CONFIGURE_SERVICE dedup_service 80 SUCCESS:PrimaryValue 145 SUCCESS:SecondaryValue\nDISPATCH req1 dedup_service 50\nADVANCE 145\nGET_RESULT req1", "description": "Duplicate response deduplicated", "expected_output": "DISPATCHED req1\nADVANCED 145ms\nRESULT req1: First response used, duplicate discarded"}, {"input": "CONFIGURE_SERVICE failure_service 50 SUCCESS:P_OK 100 FAILURE:SecondaryFailed\nDISPATCH req1 failure_service 200\nADVANCE 50\nGET_RESULT req1", "description": "Primary succeeds before hedge, secondary failure irrelevant", "expected_output": "DISPATCHED req1\nADVANCED 50ms\nRESULT req1: Primary responded first (50ms), hedge cancelled"}, {"input": "CONFIGURE_SERVICE primary_fail_service 100 FAILURE:PrimaryFailed 50 SUCCESS:S_OK\nDISPATCH req1 primary_fail_service 10\nADVANCE 60\nGET_RESULT req1", "description": "Primary fails, secondary wins", "expected_output": "DISPATCHED req1\nADVANCED 60ms\nRESULT req1: Secondary response used (50ms vs ERROR)"}, {"input": "CONFIGURE_SERVICE slow_primary_fail_secondary 1000 FAILURE:PrimaryLongFail 90 FAILURE:SecondaryLongFail\nDISPATCH req1 slow_primary_fail_secondary 100\nADVANCE 190\nGET_RESULT req1", "description": "Both fail, secondary fails faster", "expected_output": "DISPATCHED req1\nADVANCED 190ms\nRESULT req1: ERROR - SecondaryLongFail"}, {"input": "CONFIGURE_SERVICE no_response_service -1 SUCCESS:P_NO -1 SUCCESS:S_NO\nDISPATCH req1 no_response_service 100\nADVANCE 5000\nGET_RESULT req1", "description": "No service responds, request times out", "expected_output": "DISPATCHED req1\nADVANCED 5000ms\nRESULT req1: TIMEOUT - Not completed within 5 seconds."}]'::jsonb
