-- sys_088: Predictive Auto-Scaler
UPDATE challenges SET
  test_harness = $harness$import sys

# The user's Service and Worker classes will be prepended here by the platform.
# For example:
# class Service:
#     # ... user implementation ...
# class Worker:
#     # ... user implementation ...

# Define a function to parse arguments from a command string.
def parse_args(arg_list):
    args = {}
    for arg_pair in arg_list:
        if '=' in arg_pair:
            key, value = arg_pair.split('=', 1)
            args[key] = value
    return args

def run_harness():
    # Instantiate the user's Service class. This object will maintain state across commands.
    service = Service() 

    # Read commands from stdin, one line at a time.
    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        parts = line.split()
        if not parts:
            continue

        command = parts[0]
        args = parse_args(parts[1:])
        
        result_message = None

        try:
            if command == "SET_THRESHOLD":
                # Expects Service.set_threshold(metric_type: str, value: int)
                if 'cpu_up' in args:
                    service.set_threshold("cpu_up", int(args['cpu_up']))
                if 'cpu_down' in args:
                    service.set_threshold("cpu_down", int(args['cpu_down']))
            elif command == "REPORT_CPU":
                # Expects Service.report_cpu_usage(usage: int) -> str
                usage = int(args.get('usage'))
                result_message = service.report_cpu_usage(usage)
            elif command == "PREDICT_SPIKE":
                # Expects Service.predict_spike(event_time_str: str) -> str
                event_time = args.get('time')
                result_message = service.predict_spike(event_time)
            elif command == "SET_COOLDOWN":
                # Expects Service.set_cooldown(seconds: int)
                seconds = int(args.get('seconds'))
                service.set_cooldown(seconds)
            elif command == "ADVANCE_TIME":
                # Expects Service.advance_time_for_testing(seconds: int)
                # This method is crucial for testing time-based logic without actual time.sleep().
                seconds = int(args.get('seconds'))
                service.advance_time_for_testing(seconds)
            else:
                result_message = f"Error: Unknown command '{command}'"
        except Exception as e:
            result_message = f"Error executing command '{command}': {e}"

        # Print any non-empty result messages to stdout.
        if result_message is not None and result_message != "":
            print(result_message)

# Call the harness function at module level.
run_harness()$harness$,
