-- sys_089: Multi-Master Conflict Arbitrator
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', async () => {
  // Instantiate the user's Scheduler class
  const scheduler = new Scheduler(); 

  for (const line of lines) {
    if (line === '') continue;

    const parts = line.split(' ');
    const command = parts[0];
    const params: Record<string, string> = {};

    for (let i = 1; i < parts.length; i++) {
      const [key, value] = parts[i].split('=');
      if (key && value !== undefined) {
        params[key] = value;
      }
    }

    let result: string | Promise<string>;

    try {
      switch (command) {
        case 'DETECT_CONFLICT':
          if (!params.key || !params.master_A_version || !params.master_B_version) {
            result = `Error: Missing parameters for DETECT_CONFLICT. Required: key, master_A_version, master_B_version`;
          } else {
            // Assumes Scheduler has a detectConflict method
            result = scheduler.detectConflict(params.key, params.master_A_version, params.master_B_version);
          }
          break;

        case 'RESOLVE_CONFLICT':
          if (!params.key || !params.strategy) {
            result = `Error: Missing parameters for RESOLVE_CONFLICT. Required: key, strategy`;
          } else {
            // Collect all non-key/strategy params to pass to the method
            const resolveParams: Record<string, string> = {};
            for (const pKey in params) {
                if (pKey !== 'key' && pKey !== 'strategy') {
                    resolveParams[pKey] = params[pKey];
                }
            }
            // Assumes Scheduler has a resolveConflict method
            result = scheduler.resolveConflict(params.key, params.strategy, resolveParams);
          }
          break;

        case 'MANUAL_RESOLVE':
          if (!params.key) {
            result = `Error: Missing 'key' for MANUAL_RESOLVE.`;
          } else {
            // Assumes Scheduler has an applyManualResolution method
            result = scheduler.applyManualResolution(params.key);
          }
          break;
        
        case 'GET_STATUS':
          if (!params.key) {
              result = `Error: Missing 'key' for GET_STATUS.`;
          } else {
              // Assumes Scheduler has a getStatus method
              result = scheduler.getStatus(params.key);
          }
          break;

        default:
          result = `Unknown command: ${command}`;
          break;
      }
      
      // If the method returns a Promise, await it before logging
      if (result instanceof Promise) {
        console.log(await result);
      } else {
        console.log(result);
      }

    } catch (e: any) { 
      // Catch any errors thrown by the user's Scheduler methods
      console.log(`Error executing command '${command}' for '${params.key || 'N/A'}': ${e.message || e}`);
    }
  }
});$harness$,
  test_cases   = '[{"input": "DETECT_CONFLICT key=record_1 master_A_version=v2 master_B_version=v3", "description": "Detect multi-master conflict", "expected_output": "Conflict detected: record_1 has divergent versions"}, {"input": "DETECT_CONFLICT key=record_1 master_A_version=v2 master_B_version=v3\nRESOLVE_CONFLICT key=record_1 strategy=last_write_wins master_A_ts=t5 master_B_ts=t7", "description": "Last-write-wins resolution", "expected_output": "Conflict detected: record_1 has divergent versions\nmaster_B wins: latest timestamp t7"}, {"input": "DETECT_CONFLICT key=record_2 master_A_version=10 master_B_version=20\nRESOLVE_CONFLICT key=record_2 strategy=merge master_A_value=10 master_B_value=20", "description": "Merge resolution strategy", "expected_output": "Conflict detected: record_2 has divergent versions\nMerged: sum of both values applied"}, {"input": "DETECT_CONFLICT key=record_3 master_A_version=v10 master_B_version=v11\nMANUAL_RESOLVE key=record_3", "description": "Manual conflict resolution", "expected_output": "Conflict detected: record_3 has divergent versions\nManual resolution applied to record_3"}, {"input": "DETECT_CONFLICT key=record_4 master_A_version=v1 master_B_version=v2\nRESOLVE_CONFLICT key=record_4 strategy=last_write_wins master_A_ts=t10 master_B_ts=t20\nGET_STATUS key=record_4", "description": "Verify state after conflict resolution", "expected_output": "Conflict detected: record_4 has divergent versions\nmaster_B wins: latest timestamp t20\nStatus for record_4: Resolved by LWW (Master B wins)"}, {"input": "DETECT_CONFLICT key=record_5 master_A_version=a master_B_version=b\nGET_STATUS key=record_5", "description": "Verify state after conflict detection", "expected_output": "Conflict detected: record_5 has divergent versions\nStatus for record_5: Divergent"}]'::jsonb
