-- sys_091: Geofence Alert Broadcaster
UPDATE challenges SET
  test_harness = $harness$import sys
import re

def run_harness():
    # Instantiate user-provided Service and Worker classes
    service = Service()
    worker = Worker(service)
    
    DEVICE_ID = "device" # Assuming a single device named "device" from test cases
    
    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue
        
        output_buffer = []

        # Command: Define geofence and initial device placement/update
        # Example: device lat=40.71, lon=-74.01, geofence=NYC_office radius=500m
        match_init_placement = re.match(r"device lat=([-\d.]+), lon=([-\d.]+), geofence=([a-zA-Z0-9_]+) radius=(\d+)m", line)
        if match_init_placement:
            lat, lon, geofence_id, radius_str = match_init_placement.groups()
            lat, lon = float(lat), float(lon)
            radius = int(radius_str)

            # User's Service should implement define_geofence
            service.define_geofence(geofence_id, lat, lon, radius)
            # User's Service.update_device_location should return raw alerts
            raw_alerts = service.update_device_location(DEVICE_ID, lat, lon)
            
            # For the initial placement command, query the status relative to the specified geofence
            # User's Service should implement get_geofence_status for the harness to query.
            # This status *must* be derived from the user's implementation of geofence logic.
            status = service.get_geofence_status(DEVICE_ID, geofence_id)
            if status in ["inside", "outside"]:
                output_buffer.append(f"Device {status} {geofence_id} geofence")
            
            # User's Worker should process raw alerts from Service
            output_buffer.extend(worker.process_raw_alerts(raw_alerts))

        # Command: Device moves to new location (subsequent updates)
        # Example: device moves to lat=40.72, lon=-74.01
        match_move = re.match(r"device moves to lat=([-\d.]+), lon=([-\d.]+)", line)
        if match_move:
            lat, lon = match_move.groups()
            lat, lon = float(lat), float(lon)
            # User's Service.update_device_location should return raw alerts
            raw_alerts = service.update_device_location(DEVICE_ID, lat, lon)
            # User's Worker should process raw alerts from Service
            output_buffer.extend(worker.process_raw_alerts(raw_alerts))
        
        # Command: Subscribe to alerts
        # Example: subscribe alert=geofence_exit, fence=NYC_office
        match_subscribe = re.match(r"subscribe alert=([a-zA-Z_]+), fence=([a-zA-Z0-9_]+)", line)
        if match_subscribe:
            alert_type, geofence_id = match_subscribe.groups()
            # User's Service.subscribe should return the confirmation string directly
            confirmation_message = service.subscribe(alert_type, geofence_id)
            output_buffer.append(confirmation_message)

        for output_line in output_buffer:
            print(output_line)

run_harness()$harness$,
