-- sys_092: Append-Only Event Journal
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

const lines: string[] = [];

rl.on('line', (line) => {
  lines.push(line.trim());
});

rl.on('close', async () => {
  // Create an instance of the user's Scheduler class
  // It's assumed that the user's Scheduler class will implement
  // methods like append, appendAt, read, and truncate to manage the event journal.
  const scheduler = new Scheduler();

  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    const parts = line.split(' ');
    const command = parts[0];
    let result: string | null = null;

    try {
      switch (command) {
        case 'APPEND': {
          // Usage: APPEND <JSON_string>
          const jsonString = parts.slice(1).join(' ');
          result = await scheduler.append(jsonString);
          break;
        }
        case 'APPEND_AT': {
          // Usage: APPEND_AT <JSON_string> <offset_number>
          const offsetStr = parts[parts.length - 1];
          const offset = parseInt(offsetStr, 10);
          if (isNaN(offset)) {
            result = `Error: Invalid offset provided for APPEND_AT: ${offsetStr}`;
            break;
          }
          // Reconstruct JSON string from parts between command and offset
          const jsonString = parts.slice(1, parts.length - 1).join(' ');
          result = await scheduler.appendAt(jsonString, offset);
          break;
        }
        case 'READ': {
          // Usage: READ <from_offset> <count>
          const fromOffset = parseInt(parts[1], 10);
          const count = parseInt(parts[2], 10);
          if (isNaN(fromOffset) || isNaN(count)) {
            result = `Error: Invalid offset or count for READ. Usage: READ <from_offset> <count>`;
            break;
          }
          result = await scheduler.read(fromOffset, count);
          break;
        }
        case 'TRUNCATE': {
          // Usage: TRUNCATE
          result = await scheduler.truncate();
          break;
        }
        default:
          result = `Error: Unknown command "${command}"`;
          break;
      }
    } catch (e: any) {
      // Catch any errors thrown by the user's Scheduler implementation
      result = `Error: ${e.message || e.toString()}`;
    }

    if (result !== null) {
      console.log(result);
    }
  }
});$harness$,
