UPDATE challenges SET
  test_harness = $harness$import java.util.concurrent.*;
import java.util.Scanner;
import java.util.regex.Matcher;
import java.util.regex.Pattern;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.Collections;

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner scanner = new Scanner(System.in);
        
        // Instantiate user's Worker and Service
        // Assuming Service takes Worker in its constructor
        Worker worker = new Worker();
        Service service = new Service(worker);

        while (scanner.hasNextLine()) {
            String line = scanner.nextLine().trim();
            if (line.isEmpty()) continue;

            String[] parts = line.split(" ", 2);
            String command = parts[0];
            String arg = parts.length > 1 ? parts[1] : "";

            try {
                switch (command) {
                    case "worker_register": {
                        // Format: worker_register TKN001 alice read 3600
                        Pattern p = Pattern.compile("(\S+) (\S+) (\S+) (\d+)");
                        Matcher m = p.matcher(arg);
                        if (m.matches()) {
                            String token = m.group(1);
                            String user = m.group(2);
                            String scope = m.group(3);
                            long expSeconds = Long.parseLong(m.group(4));
                            worker.registerToken(token, user, scope, expSeconds);
                        } else {
                            System.out.println("Error: Invalid worker_register format: " + arg);
                        }
                        break;
                    }
                    case "worker_revoke": {
                        // Format: worker_revoke TKN003
                        worker.revokeToken(arg);
                        break;
                    }
                    case "introspect": {
                        // Format: introspect TKN001
                        String result = service.introspect(arg);
                        System.out.println(result);
                        break;
                    }
                    case "service_set_cache_ttl": {
                        // Format: service_set_cache_ttl 100
                        long ttl = Long.parseLong(arg);
                        service.setCacheTTL(ttl);
                        break;
                    }
                    case "sleep": {
                        // Format: sleep 150
                        long milliseconds = Long.parseLong(arg);
                        Thread.sleep(milliseconds);
                        break;
                    }
                    case "concurrent_introspect": {
                        // Format: concurrent_introspect TKN005 count=5 submit_delay=10
                        // Or: concurrent_introspect TKN006,TKN007 count=2 submit_delay=10
                        Pattern p = Pattern.compile("([\w,]+) count=(\d+) submit_delay=(\d+)");
                        Matcher m = p.matcher(arg);
                        if (m.matches()) {
                            String[] tokens = m.group(1).split(",");
                            int count = Integer.parseInt(m.group(2));
                            long submitDelay = Long.parseLong(m.group(3));

                            ExecutorService executor = Executors.newFixedThreadPool(Math.min(count, 10)); // Limit threads to prevent exhaustion
                            CountDownLatch latch = new CountDownLatch(count);
                            ArrayList<String> results = new ArrayList<>(); // Use ArrayList for controlled sorting
                            Object resultsLock = new Object(); // For synchronizing access to results list

                            for (int i = 0; i < count; i++) {
                                final String tokenToUse = tokens[i % tokens.length]; // Cycle through tokens if multiple provided
                                executor.submit(() -> {
                                    String result = null;
                                    try {
                                        result = service.introspect(tokenToUse);
                                    } catch (Exception e) {
                                        result = "Error during introspection: " + e.getMessage();
                                    } finally {
                                        synchronized (resultsLock) {
                                            results.add(result);
                                        }
                                        latch.countDown();
                                    }
                                });
                                if (i < count - 1) {
                                    Thread.sleep(submitDelay); // Delay between submitting tasks
                                }
                            }
                            latch.await(); // Wait for all tasks to complete
                            executor.shutdown();
                            // It's crucial to await termination or shutdownNow. Using shutdownNow() for quick exit.
                            executor.awaitTermination(1, TimeUnit.SECONDS); // Give it a moment to terminate
                            
                            // Sort and print results for deterministic output
                            Collections.sort(results);
                            for (String res : results) {
                                System.out.println(res);
                            }
                        } else {
                            System.out.println("Error: Invalid concurrent_introspect format: " + arg);
                        }
                        break;
                    }
                    default:
                        System.out.println("Unknown command: " + command);
                }
            } catch (Exception e) {
                System.out.println("Harness error processing command '" + command + "': " + e.getMessage());
                // e.printStackTrace(); // For debugging harness itself
            }
        }
        scanner.close();
    }
}

