class Service {
    private final Worker worker;
    private long cacheTTL = 30000; // Default

    // Simple in-memory cache for demonstration
    private final ConcurrentHashMap<String, CacheEntry> cache = new ConcurrentHashMap<>();

    static class CacheEntry {
        String result;
        long expiryTimeMillis;
        long retrievalTimeMillis;

        public CacheEntry(String result, long ttlMillis) {
            this.result = result;
            this.retrievalTimeMillis = System.currentTimeMillis();
            this.expiryTimeMillis = this.retrievalTimeMillis + ttlMillis;
        }

