        } else if (workerResult.equals("token expired")) {
            return String.format("Cache TTL expired for %s, re-introspected: token expired", token);
        } else if (workerResult.equals("token invalid")) {
            return "Token invalid: not found or malformed";
        } else {
            return "Unexpected worker result: " + workerResult; 
        }
    }
}
