-- sys_094: Shadow Traffic Mirrorer
UPDATE challenges SET
  test_harness = $harness$import sys
import json

# User's Service and Worker classes will be provided above this harness.
# For example:
# class Service:
#     # TODO: implement
#     pass
# class Worker:
#     # TODO: implement
#     pass


class Cr4ckHarness:
    def __init__(self):
        # Instantiate the user's Service class. 
        # Assume the Service class handles all primary operations
        # and internally manages Worker instances if needed for concurrency.
        self.service = Service()

    def process_command(self, command_line: str):
        parts = command_line.strip().split(' ', 1)
        cmd = parts[0]
        args = parts[1] if len(parts) > 1 else ""

        if cmd == "MIRROR":
            method, path = args.split(' ', 1)
            self.service.mirror_request(method, path)
            print(f"Request mirrored for {method} {path}")
        elif cmd == "SET_PROD_RESPONSE":
            method, path_and_rest = args.split(' ', 1)
            path, status_data = path_and_rest.split(' ', 1)
            status_code_str, response_data = status_data.split(' ', 1)
            status_code = int(status_code_str)
            self.service.set_production_response(method, path, status_code, response_data)
            print(f"Production response set for {method} {path}")
        elif cmd == "SET_SHADOW_RESPONSE":
            method, path_and_rest = args.split(' ', 1)
            path, status_data = path_and_rest.split(' ', 1)
            status_code_str, response_data = status_data.split(' ', 1)
            status_code = int(status_code_str)
            self.service.set_shadow_response(method, path, status_code, response_data)
            print(f"Shadow response set for {method} {path}")
        elif cmd == "COMPARE":
            method, path = args.split(' ', 1)
            print(f"Comparing responses for {method} {path}...")
            # The service's compare_responses method should update its internal divergence state
            # and return True if responses match (no divergence), False otherwise.
            if self.service.compare_responses(method, path):
                print(f"Shadow response matches production: no divergence for {method} {path}")
            else:
                print(f"Divergence detected: shadow returned different data for {method} {path}")
        elif cmd == "GET_DIVERGENCE":
            method, path = args.split(' ', 1)
            status = self.service.get_divergence_status(method, path)
            print(f"Divergence status for {method} {path}: {status}")
        elif cmd == "GET_ERROR_RATE":
            shadow_rate, prod_rate = self.service.get_error_rate()
            # Format to one decimal place as per example
            print(f"Shadow error rate: {shadow_rate:.1f}% (vs production {prod_rate:.1f}%)")
        else:
            print(f"Unknown command: {command_line}")

def run_harness():
    harness = Cr4ckHarness()
    for line in sys.stdin:
        if line.strip():  # Ignore empty lines
            harness.process_command(line.strip())

