-- sys_095: Lease-Based Resource Allocator
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

// The interface for the user's Scheduler class methods that the harness will call.
// These methods should handle the business logic for lease management.
// Methods are expected to return a string representing the outcome, or a Promise resolving to a string.
// The harness will await all method calls for consistency.
declare class Scheduler {
  acquireLease(resource: string, leaseholder: string, ttlSeconds: number): Promise<string> | string;
  renewLease(resource: string, leaseholder: string): Promise<string> | string;
  releaseLease(resource: string, leaseholder: string): Promise<string> | string;
}

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', async () => {
  const scheduler = new Scheduler();

  // Helper function to parse key-value arguments from a command line.
  // It extracts the first group captured by the provided regex pattern.
  const parseArg = (pattern: RegExp, input: string): string | undefined => {
    const match = input.match(pattern);
    return match ? match[1] : undefined;
  };

  for (const line of lines) {
    if (!line) continue; // Skip empty lines

    const commandParts = line.split(' ');
    const command = commandParts[0];

    let resource: string | undefined;
    let leaseholder: string | undefined;
    let ttl: number | undefined;

    // Extract 'resource' argument (e.g., 'resource=primary_db')
    resource = parseArg(/resource=([^, ]+)/, line);
    // Extract 'leaseholder' or 'client' argument (e.g., 'leaseholder=node_1', 'client=node_2')
    leaseholder = parseArg(/leaseholder=([^, ]+)/, line) || parseArg(/client=([^, ]+)/, line);
    // Extract 'ttl' argument (e.g., 'ttl=30s') and convert to number
    const ttlStr = parseArg(/ttl=(\d+)s/, line);
    if (ttlStr) {
      ttl = parseInt(ttlStr, 10);
    }

    // Special parsing for the 'lease_expires' command to extract the leaseholder
    // from a phrase like 'node_1 dies'.
    if (command === 'lease_expires') {
      const diesMatch = line.match(/(\w+)\s+dies/);
      if (diesMatch) {
        leaseholder = diesMatch[1]; // Capture 'node_1' from 'node_1 dies'
      }
    }

    let output = '';

    try {
      if (command === 'acquire_lease') {
        if (!resource || !leaseholder || ttl === undefined) {
          throw new Error(`Invalid or missing arguments for acquire_lease: ${line}`);
        }
        output = await Promise.resolve(scheduler.acquireLease(resource, leaseholder, ttl));
      } else if (command === 'renew_lease') {
        if (!resource || !leaseholder) {
          throw new Error(`Invalid or missing arguments for renew_lease: ${line}`);
        }
        output = await Promise.resolve(scheduler.renewLease(resource, leaseholder));
      } else if (command === 'lease_expires') {
        if (!resource || !leaseholder) {
          throw new Error(`Invalid or missing arguments for lease_expires: ${line}`);
        }
        // The 'lease_expires' command implies a release operation due to some event (e.g., node failure).
        output = await Promise.resolve(scheduler.releaseLease(resource, leaseholder));
      } else {
        console.error(`Unknown command: ${command}`);
        process.exit(1);
      }
      console.log(output);
    } catch (e: any) {
      console.error(`Error processing command "${line}": ${e.message}`);
      process.exit(1);
    }
  }
});$harness$,
  test_cases   = '[{"input": "acquire_lease resource=primary_db, leaseholder=node_1, ttl=30s", "description": "Acquire resource lease", "expected_output": "Lease granted: node_1 holds primary_db for 30s"}, {"input": "acquire_lease resource=primary_db, leaseholder=node_1, ttl=30s\nrenew_lease resource=primary_db, leaseholder=node_1", "description": "Renew lease", "expected_output": "Lease granted: node_1 holds primary_db for 30s\nLease renewed: node_1 primary_db for another 30s"}, {"input": "acquire_lease resource=primary_db, leaseholder=node_1, ttl=30s\nlease_expires resource=primary_db, node_1 dies", "description": "Expired lease released on failure", "expected_output": "Lease granted: node_1 holds primary_db for 30s\nLease expired for node_1, primary_db is now available"}, {"input": "acquire_lease resource=primary_db, leaseholder=node_1, ttl=30s\nlease_expires resource=primary_db, node_1 dies\nacquire_lease resource=primary_db, client=node_2, ttl=30s", "description": "New lease after expiry", "expected_output": "Lease granted: node_1 holds primary_db for 30s\nLease expired for node_1, primary_db is now available\nLease granted: node_2 holds primary_db for 30s"}]'::jsonb
WHERE id = 'sys_095';
-- sys_096: Streaming Aggregation Window
UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;

public class Main {
    private static Service service = null;

    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        while (sc.hasNextLine()) {
            String line = sc.nextLine();
            String[] parts = line.trim().split(" ");

            if (parts.length == 0 || parts[0].isEmpty()) {
                continue; // Skip empty lines
            }

            String command = parts[0];

            try {
                switch (command) {
                    case "INIT":
                        // INIT <window_type> <window_size_ms> <slide_size_ms> <allowed_lateness_ms> <aggregation_type>
                        if (parts.length != 6) {
                            System.out.println("Error: INIT command requires 5 arguments.");
                            break;
                        }
                        String windowType = parts[1];
                        long windowSizeMs = Long.parseLong(parts[2]);
                        long slideSizeMs = Long.parseLong(parts[3]);
                        long allowedLatenessMs = Long.parseLong(parts[4]);
                        String aggregationType = parts[5];
                        service = new Service(windowType, windowSizeMs, slideSizeMs, allowedLatenessMs, aggregationType);
                        System.out.println("Service initialized.");
                        break;
                    case "INGEST":
                        // INGEST <timestamp_ms> <event_type> <value>
                        if (parts.length != 4) {
                            System.out.println("Error: INGEST command requires 3 arguments.");
                            break;
                        }
                        long timestamp = Long.parseLong(parts[1]);
                        String eventType = parts[2];
                        int value = Integer.parseInt(parts[3]);
                        if (service != null) {
                            service.processEvent(timestamp, eventType, value);
                        } else {
                            System.out.println("Error: Service not initialized. Use INIT first.");
                        }
                        break;
                    case "ADVANCE_WATERMARK":
                        // ADVANCE_WATERMARK <timestamp_ms>
                        if (parts.length != 2) {
                            System.out.println("Error: ADVANCE_WATERMARK command requires 1 argument.");
                            break;
                        }
                        long watermarkTime = Long.parseLong(parts[1]);
                        if (service != null) {
                            service.advanceWatermark(watermarkTime);
                        } else {
                            System.out.println("Error: Service not initialized. Use INIT first.");
                        }
                        break;
                    default:
                        System.out.println("Unknown command: " + command);
                        break;
                }
            } catch (NumberFormatException e) {
                System.out.println("Error: Invalid number format in command '" + line + "': " + e.getMessage());
            } catch (ArrayIndexOutOfBoundsException e) {
                System.out.println("Error: Missing arguments for command '" + line + "'.");
            } catch (Exception e) {
                System.out.println("Error processing command '" + line + "': " + e.getClass().getSimpleName() + ": " + e.getMessage());
            }
        }
        sc.close();
    }
