-- sys_097: Cross-Service Correlation Tracer
UPDATE challenges SET
  test_harness = $harness$import sys

# Assume Service and Worker classes are defined by the user above this.

def run_harness():
    # Instantiate the user's Worker class, which acts as the central tracer.
    # It should have methods like generate_trace_id, record_span, get_full_trace.
    tracer = Worker() 
    services = {} # Dictionary to hold instances of user's Service class

    # Define a helper function to get a service instance by name.
    # This allows a Service object to simulate calling another Service object.
    def get_service_instance(service_name):
        return services.get(service_name)

    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue

        parts = line.split()
        command = parts[0]

        try:
            if command == "INIT_SERVICE":
                service_name = parts[1]
                if service_name not in services:
                    # Pass the `get_service_instance` callable to the Service constructor.
                    # User's Service constructor is expected to be:
                    # Service(service_name, tracer_instance, get_service_instance_callable)
                    services[service_name] = Service(service_name, tracer, get_service_instance)
                    print(f"Initialized service: {service_name}")
                else:
                    print(f"Service {service_name} already initialized.")

            elif command == "REQUEST_ENTER":
                service_name = parts[1]
                trace_id = parts[2] if len(parts) > 2 else None # Optional trace_id
                
                if service_name not in services:
                    print(f"Error: Service {service_name} not initialized.")
                    continue
                
                # Call user's Service.handle_incoming_request.
                # Expected return: (actual_trace_id: str, message_string: str)
                actual_trace_id, message = services[service_name].handle_incoming_request(trace_id)
                
                # Special handling for "New trace_id generated" to append the actual ID.
                if "New trace_id generated" in message and trace_id is None:
                    print(f"{message}: {actual_trace_id}") 
                else:
                    print(message)

            elif command == "CALL_SERVICE":
                from_service_name = parts[1]
                to_service_name = parts[2]
                trace_id = parts[3]

                if from_service_name not in services:
                    print(f"Error: Service {from_service_name} not initialized.")
                    continue
                
                # Call user's Service.call_service.
                # Expected return: message_string
                message = services[from_service_name].call_service(to_service_name, trace_id)
                print(message)

            elif command == "GET_TRACE":
                trace_id = parts[1]
                # Call user's Worker.get_full_trace.
                # Expected return: formatted_trace_string
                trace_output = tracer.get_full_trace(trace_id)
                print(trace_output)
            else:
                print(f"Unknown command: {command}")
        except IndexError:
            print(f"Error: Missing arguments for command '{command}' in line: {line}")
        except AttributeError as ae:
            print(f"Error: Method missing or invalid call for command '{command}' in line: {line}. Details: {ae}")
            print("Please ensure your Service and Worker classes implement the expected methods:")
            print("  - Worker(): constructor")
            print("  - Worker.generate_trace_id(): returns str (a unique ID)")
            print("  - Worker.record_span(trace_id: str, span_data: str): None (records an event in a trace)")
            print("  - Worker.get_full_trace(trace_id: str): returns str (a formatted trace history)")
            print("  - Service(service_name: str, tracer_instance: Worker, get_service_instance_callable: Callable[[str], Service]): constructor")
            print("  - Service.handle_incoming_request(trace_id: Optional[str] = None): returns (actual_trace_id: str, message_str: str)")
            print("  - Service.call_service(target_service_name: str, current_trace_id: str): returns message_str")
        except Exception as e:
            print(f"An unexpected error occurred for command '{command}' in line: {line}: {e}")

# Call the harness function at module level as the sole entry point.
run_harness()$harness$,
  test_cases   = '[{"input": "INIT_SERVICE service_A\nREQUEST_ENTER service_A TRACE001", "description": "Propagate correlation ID", "expected_output": "Initialized service: service_A\nCorrelation header propagated: X-Trace-ID: TRACE001"}, {"input": "INIT_SERVICE service_A\nINIT_SERVICE service_B\nREQUEST_ENTER service_A TRACE001\nCALL_SERVICE service_A service_B TRACE001", "description": "Correlation ID carried across services", "expected_output": "Initialized service: service_A\nInitialized service: service_B\nCorrelation header propagated: X-Trace-ID: TRACE001\nservice_B logs with TRACE001 correlation ID"}, {"input": "INIT_SERVICE service_A\nINIT_SERVICE service_B\nREQUEST_ENTER service_A TRACE001\nCALL_SERVICE service_A service_B TRACE001\nGET_TRACE TRACE001", "description": "Retrieve full correlated trace", "expected_output": "Initialized service: service_A\nInitialized service: service_B\nCorrelation header propagated: X-Trace-ID: TRACE001\nservice_B logs with TRACE001 correlation ID\nTRACE001: service_A -> service_B -> db (all correlated)"}, {"input": "INIT_SERVICE service_C\nREQUEST_ENTER service_C", "description": "Generate trace ID when missing", "expected_output": "Initialized service: service_C\nNew trace_id generated for uncorrelated request: GENERATED_TRACE_ID_1"}]'::jsonb
WHERE id = 'sys_097';
-- sys_098: Adaptive Circuit Probe
UPDATE challenges SET
  test_harness = $harness$import * as readline from 'readline';

const rl = readline.createInterface({ input: process.stdin });
const lines: string[] = [];

rl.on('line', (line) => lines.push(line.trim()));

rl.on('close', async () => {
  // Instantiate the user's Scheduler class, which is expected to implement the circuit breaker logic.
  const scheduler = new Scheduler();

  for (const line of lines) {
    const parts = line.split(' ');
    const command = parts[0];
    const args = parts.slice(1);

    switch (command) {
      case 'INIT_CIRCUIT':
        // Assumes the Scheduler has an initialization method to set up the circuit breaker's initial state (e.g., OPEN).
        // 'await' is used in case the user's method is asynchronous.
        if (typeof scheduler.initCircuitBreaker === 'function') {
          await scheduler.initCircuitBreaker();
        } else {
          console.error('Scheduler.initCircuitBreaker() method not found. Ensure your Scheduler class has this method.');
        }
        break;
      case 'SIMULATE_TIMEOUT':
        // Simulates the circuit remaining in the OPEN state for its timeout period,
        // which typically triggers a probe attempt to check service health.
        if (typeof scheduler.simulateCircuitOpenTimeout === 'function') {
          await scheduler.simulateCircuitOpenTimeout();
        } else {
          console.error('Scheduler.simulateCircuitOpenTimeout() method not found. Ensure your Scheduler class has this method.');
        }
        break;
      case 'SIMULATE_PROBE_RESPONSE':
        const status = parseInt(args[0], 10);
        if (isNaN(status)) {
          console.error(`Invalid status for SIMULATE_PROBE_RESPONSE: ${args[0]}`);
          continue;
        }
        // Handles the result of the probe, determining if the circuit should move to HALF-OPEN or remain OPEN.
        if (typeof scheduler.handleProbeResponse === 'function') {
          await scheduler.handleProbeResponse(status);
        } else {
          console.error('Scheduler.handleProbeResponse() method not found. Ensure your Scheduler class has this method.');
        }
        break;
      case 'SIMULATE_TRIAL':
        const outcome = args[0]; // Expected: 'SUCCESS' or 'FAILURE'
        if (outcome !== 'SUCCESS' && outcome !== 'FAILURE') {
          console.error(`Invalid outcome for SIMULATE_TRIAL: ${args[0]}`);
          continue;
        }
        // Records the result of a single trial request when the circuit is in the HALF-OPEN state.
        // Based on cumulative results, the circuit might close or reopen.
        if (typeof scheduler.recordTrialResult === 'function') {
          await scheduler.recordTrialResult(outcome === 'SUCCESS');
        } else {
          console.error('Scheduler.recordTrialResult() method not found. Ensure your Scheduler class has this method.');
        }
        break;
      default:
        console.error(`Unknown command: ${command}`);
        break;
    }
  }
});$harness$,
  test_cases   = '[{"input": "INIT_CIRCUIT\nSIMULATE_TIMEOUT", "description": "Probe sent after circuit open timeout", "expected_output": "Adaptive probe sent to payment service"}, {"input": "INIT_CIRCUIT\nSIMULATE_TIMEOUT\nSIMULATE_PROBE_RESPONSE 200", "description": "Successful probe enables trial", "expected_output": "Adaptive probe sent to payment service\nCircuit moving to HALF-OPEN, allowing trial requests"}, {"input": "INIT_CIRCUIT\nSIMULATE_TIMEOUT\nSIMULATE_PROBE_RESPONSE 200\nSIMULATE_TRIAL SUCCESS\nSIMULATE_TRIAL SUCCESS\nSIMULATE_TRIAL SUCCESS\nSIMULATE_TRIAL SUCCESS\nSIMULATE_TRIAL SUCCESS\nSIMULATE_TRIAL SUCCESS\nSIMULATE_TRIAL SUCCESS\nSIMULATE_TRIAL SUCCESS\nSIMULATE_TRIAL SUCCESS\nSIMULATE_TRIAL SUCCESS", "description": "Circuit closes on successful trials", "expected_output": "Adaptive probe sent to payment service\nCircuit moving to HALF-OPEN, allowing trial requests\nCircuit CLOSED: service recovered"}, {"input": "INIT_CIRCUIT\nSIMULATE_TIMEOUT\nSIMULATE_PROBE_RESPONSE 200\nSIMULATE_TRIAL SUCCESS\nSIMULATE_TRIAL SUCCESS\nSIMULATE_TRIAL FAILURE\nSIMULATE_TRIAL SUCCESS\nSIMULATE_TRIAL FAILURE\nSIMULATE_TRIAL SUCCESS\nSIMULATE_TRIAL SUCCESS\nSIMULATE_TRIAL SUCCESS\nSIMULATE_TRIAL FAILURE\nSIMULATE_TRIAL SUCCESS", "description": "Circuit reopens on high trial failure rate", "expected_output": "Adaptive probe sent to payment service\nCircuit moving to HALF-OPEN, allowing trial requests\nCircuit reopens: trial failure rate too high"}]'::jsonb
WHERE id = 'sys_098';
-- sys_099: Hierarchical Namespace Router
UPDATE challenges SET
  test_harness = $harness$import java.util.Scanner;
import java.util.concurrent.*;

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        Service routerService = new Service(); // User's Service class

        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }

            String[] parts = line.split(" ", 2);
            String command = parts[0];
            String arg = parts.length > 1 ? parts[1] : "";

            String result = "";
            try {
                switch (command) {
                    case "ADD_NAMESPACE":
                        result = routerService.addNamespace(arg);
                        break;
                    case "ADD_WILDCARD":
                        result = routerService.addWildcard(arg);
                        break;
                    case "ROUTE":
                        result = routerService.route(arg);
                        break;
                    case "LIST_NAMESPACES":
                        result = routerService.listNamespaces();
                        break;
                    case "LIST_WILDCARDS":
                        result = routerService.listWildcards();
                        break;
                    case "REMOVE_NAMESPACE":
                        result = routerService.removeNamespace(arg);
                        break;
                    case "REMOVE_WILDCARD":
                        result = routerService.removeWildcard(arg);
                        break;
                    default:
                        result = "Error: Unknown command: " + command;
                        break;
                }
            } catch (Exception e) {
                result = "Error processing command '" + command + "' with arg '" + arg + "': " + e.getMessage();
                // For debugging, consider e.printStackTrace(System.err);
            }
            System.out.println(result);
        }
        sc.close();
    }
}$harness$,
  test_cases   = '[{"input": "ADD_NAMESPACE /api\nADD_NAMESPACE /api/v1\nADD_NAMESPACE /api/v1/users\nADD_NAMESPACE /api/v1/users/123\nROUTE /api/v1/users/123", "description": "Route in hierarchical namespace", "expected_output": "Namespace /api added.\nNamespace /api/v1 added.\nNamespace /api/v1/users added.\nNamespace /api/v1/users/123 added.\nRouted (specific): /api -> /v1 -> /users -> /123"}, {"input": "ADD_WILDCARD /api/v1/*/profile\nROUTE /api/v1/alice/profile", "description": "Wildcard namespace routing", "expected_output": "Wildcard pattern /api/v1/*/profile added.\nRouted (wildcard): /api/v1/alice/profile via /api/v1/*/profile"}, {"input": "ADD_NAMESPACE /api/v1\nADD_WILDCARD /api/*\nROUTE /api/v1", "description": "Specific route wins over wildcard", "expected_output": "Namespace /api/v1 added.\nWildcard pattern /api/* added.\nRouted (specific): /api -> /v1"}, {"input": "ADD_NAMESPACE /api/v2", "description": "Add new namespace to hierarchy", "expected_output": "Namespace /api/v2 added."}, {"input": "ROUTE /non/existent/path", "description": "Attempt to route a non-existent path", "expected_output": "Error: No route found for /non/existent/path"}, {"input": "ADD_NAMESPACE /temp/path\nREMOVE_NAMESPACE /temp/path\nROUTE /temp/path", "description": "Remove an existing namespace", "expected_output": "Namespace /temp/path added.\nNamespace /temp/path removed.\nError: No route found for /temp/path"}, {"input": "ADD_NAMESPACE /duplicate/path\nADD_NAMESPACE /duplicate/path", "description": "Attempt to add duplicate namespace", "expected_output": "Namespace /duplicate/path added.\nError: Namespace /duplicate/path already exists."}]'::jsonb
WHERE id = 'sys_099';
-- sys_100: Chaos Injection Fault Manager
UPDATE challenges SET
  test_harness = $harness$import sys

class Harness:
    def __init__(self):
        # Instantiate the user's Service and Worker classes
        # Assuming the main interaction is with the Service
        # The user's Service and Worker classes will be available in the same scope
        self.chaos_manager = Service() 

    def parse_command(self, command_line):
        parts = command_line.split(' ', 1)
        cmd_name = parts[0].strip()
        args_str = parts[1].strip() if len(parts) > 1 else ""

        args = {}
        if args_str:
            # Split by comma, then each part by equals sign
            for arg_pair in args_str.split(','):
                arg_pair = arg_pair.strip()
                if '=' in arg_pair:
                    key, value = arg_pair.split('=', 1)
                    args[key.strip()] = value.strip()
                # Assuming all arguments are in key=value format for this challenge
                # If a non-key=value argument is given, it will be ignored, 
                # or handled by a KeyError if expected by a specific command.

        return cmd_name, args

    def run(self):
        for line in sys.stdin:
            line = line.strip()
            if not line:
                continue

            cmd_name, args = self.parse_command(line)
            result = ""

            try:
                if cmd_name == "inject":
                    fault_type = args.pop("fault", None)
                    service_name = args.pop("service", None)
                    if fault_type is None or service_name is None:
                        raise KeyError("Missing 'fault' or 'service' argument for 'inject' command.")
                    # Pass remaining args as kwargs to the inject_fault method
                    result = self.chaos_manager.inject_fault(fault_type, service_name, **args)
                elif cmd_name == "stop_chaos":
                    service_name = args.pop("service", None)
                    if service_name is None:
                        raise KeyError("Missing 'service' argument for 'stop_chaos' command.")
                    result = self.chaos_manager.stop_chaos(service_name)
                elif cmd_name == "chaos_report":
                    if args: # According to problem description, chaos_report takes no arguments
                        raise ValueError(f"Unexpected arguments for 'chaos_report': {args}")
                    result = self.chaos_manager.get_chaos_report()
                else:
                    result = f"Error: Unknown command '{cmd_name}'"
            except (AttributeError, TypeError) as e:
                # AttributeError: method missing. TypeError: wrong number/type of args.
                result = f"Error: Failed to execute command '{cmd_name}'. Check method signature or existence: {e}"
            except KeyError as e:
                result = f"Error: Missing required argument: {e} for command '{cmd_name}'"
            except ValueError as e:
                result = f"Error: Invalid command format or arguments: {e}"
            except Exception as e:
                result = f"Error: An unexpected error occurred during command '{cmd_name}': {e}"

            print(result)

def run_harness():
    harness = Harness()
    harness.run()

# Call the harness at module level
run_harness()$harness$,
  test_cases   = '[{"input": "inject fault=latency, service=payment, delay=500ms, rate=10%", "description": "Inject latency fault", "expected_output": "Chaos: 10% of payment requests delayed 500ms"}, {"input": "inject fault=error, service=db, error_rate=5%", "description": "Inject error fault", "expected_output": "Chaos: 5% of DB requests return error"}, {"input": "inject fault=latency, service=payment, delay=500ms, rate=10%\nstop_chaos service=payment", "description": "Stop chaos injection after latency fault", "expected_output": "Chaos: 10% of payment requests delayed 500ms\nChaos stopped for payment service, normal operation"}, {"input": "inject fault=latency, service=payment, delay=500ms, rate=10%\nstop_chaos service=payment\nchaos_report", "description": "Report chaos experiment results for a completed latency fault", "expected_output": "Chaos: 10% of payment requests delayed 500ms\nChaos stopped for payment service, normal operation\nChaos report: system survived 500ms payment latency, SLO met"}, {"input": "inject fault=error, service=db, error_rate=10%\ninject fault=latency, service=auth, delay=200ms, rate=5%\nchaos_report", "description": "Report with multiple active faults (expecting a default report if no specific reporting is implemented)", "expected_output": "Chaos: 10% of DB requests return error\nChaos: 5% of auth requests delayed 200ms\nChaos report: system survived 500ms payment latency, SLO met"}]'::jsonb
WHERE id = 'sys_100';
